
// ═══ [SECTION] Mission 2.A — Anti-clonage IA & scraping (v2.7.2 — anti-page-blanche) ═══
// CORRECTION CRITIQUE : ne JAMAIS vider document.body — cause de page blanche
// chez utilisateurs légitimes (mobile lent, anciennes versions, etc.)
(function(){
  try {
    // 1. Anti-clickjacking — redirection top si iframe cross-origin (SANS vider le body)
    if(window.top !== window.self){
      try {
        // Si on peut accéder à top, c'est même origin → OK, ne rien faire
        var topHref = window.top.location.href;
      } catch(e){
        // Cross-origin iframe → tenter de break-out (mais sans casser la page si fail)
        try { window.top.location.href = window.location.href; } catch(e2){}
      }
    }

    // 2. (Assaini v1.2.3) Clic droit + sélection de texte RÉACTIVÉS.
    //    Le blocage global (contextmenu/selectstart sur #APP/#VISITOR) dégradait
    //    l'UX et l'accessibilité (impossible de copier un nom, sélectionner du texte)
    //    sans rien protéger — le code reste lisible côté client de toute façon.
    //    La détection bot passive (ci-dessous) + le filigrane des exports suffisent.
    //    La protection des médias payants reste au niveau de chaque lecteur
    //    (oncontextmenu / controlsList="nodownload" sur les <video>/<embed>/<img>).

    // 3. Détection bot LIGHT (passive, log uniquement, ne bloque pas)
    try {
      var sus = 0;
      if(navigator.webdriver === true) sus += 10;
      var ua = navigator.userAgent || '';
      if(/headless|puppeteer|selenium|playwright|phantomjs|scrapy/i.test(ua)) sus += 20;
      // 'GPTBot|ChatGPT|Claude|anthropic|CCBot|Google-Extended' déjà bloqués par robots.txt + .htaccess
      if(sus >= 15 && navigator.sendBeacon){
        try {
          var data = new Blob([JSON.stringify({ts:Date.now(),sus:sus,ua:ua.substring(0,200)})], {type:'application/json'});
          navigator.sendBeacon('/api/_bot_log.php', data);
        } catch(_){}
      }
    } catch(_){}

    // 4. Watermark invisible (signature copyright)
    try {
      var c = document.createComment(' © 2026 Mythe Errant · Jacques Miterand TAKOU · VÉRITAS Academy · Tous droits réservés · Watermark: VRT-'+Date.now().toString(36)+' · Toute reproduction ou utilisation pour entraînement IA est interdite (CPI L335-2/L335-3). ');
      if(document.documentElement) document.documentElement.appendChild(c);
    } catch(_){}
  } catch(e){
    console.warn('[VÉRITAS anti-clone] init ignored:', e);
    // FAIL-SAFE : ne JAMAIS vider le body — toujours laisser la page se charger
  }
})();

