function visitorOrderProduct(title,price){
  const overlay=document.createElement('div');overlay.className='mov';
  if(overlay)overlay.innerHTML='<div class="modal"><div class="mhd"><div><div class="mtt">🛒 Commander: '+title+'</div><div class="mst">'+fmt(price)+' FCFA</div></div><button class="mc" onclick="this.closest(\'.mov\').remove()">✕</button></div><div class="mb"><div class="fg2"><div class="fg"><span class="fl">Nom complet *</span><input class="fi" id="vpNom" placeholder="Nom et prénom"></div><div class="fg"><span class="fl">Téléphone WhatsApp *</span><input class="fi" id="vpTel" type="tel" placeholder="+237 6 XX XX XX XX"></div></div><div class="fg mt8"><span class="fl">Code promo (optionnel)</span><input class="fi" id="vpPromo" placeholder="ELEVE10" style="text-transform:uppercase"></div></div><div class="mf"><button class="btn bo" onclick="this.closest(\'.mov\').remove()">Annuler</button><button class="btn bi" onclick="confirmProductOrder(\'' + title.replace(/'/g,"") + '\','+price+')">✓ Commander</button></div></div>';
  document.body.appendChild(overlay);
}
function confirmProductOrder(title,price){
  var nom=(document.getElementById('vpNom')?.value||'').trim();
  var tel=(document.getElementById('vpTel')?.value||'').trim();
  if(!nom||!tel){toast('Nom et téléphone requis','warn');return;}
  var promo=(document.getElementById('vpPromo')?.value||'').trim().toUpperCase();
  var finalPrice=price;
  if(promo){var pc=(DB.promoCodes||[]).find(function(p){return p.code===promo&&p.actif;});if(pc){if(pc.type==='percent')finalPrice=Math.round(price*(100-pc.reduction)/100);else finalPrice=Math.max(0,price-pc.reduction);}}
  if(!DB.visitorOrders)DB.visitorOrders=[];
  DB.visitorOrders.push({id:gid(),bookTitle:title,nom:nom,tel:tel,date:today(),statut:'En attente',prix:finalPrice,promo:promo});
  save();
  var mov=document.querySelector('.mov');if(mov)mov.remove();
  // v1.0 : ouvrir le modal de paiement unifié
  setTimeout(function(){
    if(typeof openPaymentModal === 'function' && finalPrice > 0){
      // ── v1.2 : metadata pour activation automatique ──
      var lastOrder = DB.visitorOrders[DB.visitorOrders.length-1];
      openPaymentModal({
        montant: finalPrice,
        label: '🛒 '+title,
        refPrefix: 'SHOP',
        intent: 'product',
        targetId: lastOrder?lastOrder.id:null,
        customerNom: nom, customerTel: tel
      });
    } else {
      toast('✓ Commande envoyée !');
    }
  }, 100);
}

