function confirmVisitorOrder(bid){
  const b=DB.books.find(x=>x.id===bid);if(!b)return;
  const nom=(document.getElementById('voNom')?.value||'').trim();
  const tel=(document.getElementById('voTel')?.value||'').trim();
  const adresse=(document.getElementById('voAdresse')?.value||'').trim();
  if(!nom||!tel){toast('Nom et téléphone requis','warn');return;}
  if(!adresse){toast('Adresse de livraison requise','warn');return;}
  if(!DB.visitorOrders)DB.visitorOrders=[];
  const promoCode=(document.getElementById('voPromo')?.value||'').trim().toUpperCase();
  let finalPrix=b.prix;let promoUsed='';
  if(promoCode){const promo=(DB.promoCodes||[]).find(p=>p.code===promoCode&&p.actif);
    if(promo){if(promo.type==='percent')finalPrix=Math.round(b.prix*(100-promo.reduction)/100);else finalPrix=Math.max(0,b.prix-promo.reduction);promoUsed=promoCode;promo.usage=(promo.usage||0)+1;}}
  DB.visitorOrders.push({id:gid(),bid,bookTitle:b.titre,nom,tel,adresse,
    email:document.getElementById('voEmail')?.value||'',
    cls:document.getElementById('voCls')?.value||'',
    msg:document.getElementById('voMsg')?.value||'',
    promo:promoUsed,prixOriginal:b.prix,
    date:today(),statut:'En attente',prix:finalPrix});
  // ── PROGRAMME PARTENARIAT v1 : tracking commission si code parrainage utilisé ──
  if(promoCode && typeof applyPartnerCode==='function'){
    try {
      applyPartnerCode(promoCode, {
        refType:'book', refId:bid, refLabel:b.titre,
        saleAmount: finalPrix, qty:1
      });
    } catch(e){ /* fail silent — la vente reste enregistrée même si commission KO */ }
  }
  save();
  const mov=document.querySelector('.mov');if(mov)mov.remove();
  // v1.0 : ouvrir le modal de paiement unifié
  setTimeout(function(){
    if(typeof openPaymentModal === 'function' && finalPrix > 0){
      // ── v1.2 : metadata pour activation automatique ──
      openPaymentModal({
        montant: finalPrix,
        label: '📚 '+b.titre,
        refPrefix: 'BOOK',
        intent: 'book',
        targetId: bid,
        customerNom: nom,
        customerTel: tel,
        customerAdresse: adresse,
        customerEmail: document.getElementById('voEmail')?.value||''
      });
    } else {
      toast('✓ Commande enregistrée ! Nous vous contacterons au '+tel);
    }
  }, 100);
}

function addBookContent(bid){
  const b=DB.books.find(x=>x.id===bid);if(!b)return;
  let previewHtml='<span class="xs2 mut">Aucune image</span>';
  if(b.previewImages&&b.previewImages.length){
    previewHtml=b.previewImages.map(function(img,i){
      return '<div style="position:relative;width:80px;height:100px;border:1px solid var(--bg3);border-radius:4px;overflow:hidden"><img src="'+img+'" style="width:100%;height:100%;object-fit:cover"><div style="position:absolute;top:2px;right:2px;background:var(--re);color:#fff;border:none;border-radius:50%;width:16px;height:16px;font-size:13px;cursor:pointer;display:flex;align-items:center;justify-content:center" onclick="removeBookPreview('+String.fromCharCode(39)+bid+String.fromCharCode(39)+','+i+')">×</div></div>';
    }).join('');
  }
  let coverHtml=b.coverImg?'<img src="'+_esc(b.coverImg)+'" style="width:60px;height:80px;object-fit:cover;border-radius:4px;border:1px solid var(--bg3)" onerror="this.outerHTML=\'<span class=\\\'xs2 mut\\\'>Image indisponible</span>\'">':'<span class="xs2 mut">Aucune couverture</span>';
  var _pdfStat=(b.previewPdfUrl||b.previewPdfKey)
    ?'<span class="bg bgg">✅ '+_esc(b.previewPdfName||'apercu.pdf')+'</span> '
      +(b.previewPdfUrl?'<span class="xs2" style="color:var(--gr)">☁️ Disponible sur tous les appareils</span> ':'<span class="xs2 mut">📱 Local uniquement</span> ')
      +'<button class="btn bo xs" onclick="removeBookPdfPreview(\''+bid+'\')" style="font-size:10px;padding:2px 8px">🗑 Supprimer</button>'
    :'<span class="xs2 mut">Aucun aperçu PDF chargé</span>';
  M('📖 Gérer le contenu — '+b.titre,'Extraits et chapitres consultables par les visiteurs',
  '<div class="ib ibt mb14"><span>📝</span><span>Ajoutez des extraits que les visiteurs pourront lire avant d\'acheter.</span></div>'+
  '<div class="fg mb12"><span class="fl">📄 Aperçu PDF / Word (avant achat)</span>'+
  '<div class="fl2 fic g8 mt6" id="bkPdfStatus">'+_pdfStat+'</div>'+
  '<div class="ib" style="background:var(--blb);border:1px solid var(--bld);color:var(--bl);border-radius:var(--r);padding:7px 11px;font-size:12px;margin:5px 0">💡 Chargez 2-3 pages PDF/Word — les visiteurs les liront avant d\'acheter.</div>'+
  '<input type="file" class="fi mt4" id="bkPdfFile" accept=".pdf,.doc,.docx" style="font-size:12px"></div>'+
  '<div class="fg mb12"><span class="fl">Extrait principal (texte)</span><textarea class="fi" id="bkExtrait" rows="6" placeholder="Collez ici un extrait du livre (10-20 pages)...">'+(b.extrait||'')+'</textarea></div>'+
  '<div class="fg mb12"><span class="fl">Chapitres (un par ligne)</span><textarea class="fi" id="bkChaps" rows="4" placeholder="Chapitre 1 — Algèbre">'+(b.chaps||[]).join('\n')+'</textarea></div>'+
  '<div class="fg mb12"><span class="fl">📸 Images / Captures de pages</span>'+
  '<div class="fl2 g8 fw mt8" id="bkPreviews">'+previewHtml+'</div>'+
  '<button class="btn bo sm mt8" onclick="uploadBookPreview('+String.fromCharCode(39)+bid+String.fromCharCode(39)+')">＋ Ajouter des captures</button></div>'+
  '<div class="fg"><span class="fl">📸 Image de couverture</span>'+
  '<div class="fl2 fic g8 mt8">'+coverHtml+'<button class="btn bo sm" onclick="uploadBookCover('+String.fromCharCode(39)+bid+String.fromCharCode(39)+')">📷 Changer couverture</button></div></div>',
  '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveBookContent('+String.fromCharCode(39)+bid+String.fromCharCode(39)+')">✓ Enregistrer</button>',true);
}

function saveBookContent(bid){
  var b=DB.books.find(function(x){return x.id===bid;});if(!b)return;
  b.extrait=document.getElementById('bkExtrait')?.value||'';
  var chapsText=document.getElementById('bkChaps')?.value||'';
  b.chaps=chapsText.split('\n').map(function(x){return x.trim();}).filter(function(x){return x;});
  var pdfInput=document.getElementById('bkPdfFile');
  var pdfFile=pdfInput&&pdfInput.files&&pdfInput.files[0];
  if(pdfFile){
    var cloudCfg=_effectiveCloudConfig();
    if(cloudCfg&&cloudCfg.url&&cloudCfg.secret){
      // ── Upload direct vers le cloud pour accessibilité multi-appareils ──
      toast('⬆️ Upload PDF en cours…','info');
      var fd=new FormData();
      fd.append('file',pdfFile,pdfFile.name);
      fd.append('type','book');
      fd.append('ref_id',bid);
      var ctrl=typeof AbortController!=='undefined'?new AbortController():null;
      var tmt=ctrl?setTimeout(function(){ctrl.abort();},120000):null;
      var baseUrl=cloudCfg.url.replace(/\/+$/,'');
      // FIX WAF LWS 2026 : Authorization header au lieu de _secret= dans URL/FormData
      fetch(baseUrl+'/upload_file.php',{
        method:'POST',
        headers:{'Authorization':'Bearer '+cloudCfg.secret},
        body:fd,
        signal:ctrl?ctrl.signal:undefined
      }).then(function(r){
        if(tmt)clearTimeout(tmt);
        return r.json();
      }).then(function(j){
        if(j&&j.url){
          b.previewPdfUrl=j.url;
          b.previewPdfName=pdfFile.name;
          b.previewPdfKey=''; // plus besoin du stockage local
          save();cm();re();toast('✓ PDF disponible sur tous les appareils ☁️');
        } else {
          throw new Error(j&&j.error?j.error:'Réponse invalide');
        }
      }).catch(function(e){
        if(tmt)clearTimeout(tmt);
        // Fallback : stocker en IDB local
        toast('⚠️ Upload cloud échoué, enregistrement local…','warn');
        var pdfReader=new FileReader();
        pdfReader.onload=function(ev){
          var pdfKey='bkprev_'+bid;
          idbSave(pdfKey,ev.target.result,pdfFile.name,pdfFile.type||'application/pdf',function(){
            b.previewPdfKey=pdfKey;b.previewPdfName=pdfFile.name;
            save();cm();re();toast('✓ PDF enregistré localement (cloud indisponible)','warn');
          });
        };
        pdfReader.onerror=function(){save();cm();re();toast('✓ Contenu enregistré (erreur lecture PDF)','warn');};
        pdfReader.readAsDataURL(pdfFile);
      });
    } else {
      // ── Pas de cloud configuré : stockage IDB local ──
      var pdfReader=new FileReader();
      pdfReader.onload=function(ev){
        var pdfKey='bkprev_'+bid;
        idbSave(pdfKey,ev.target.result,pdfFile.name,pdfFile.type||'application/pdf',function(){
          b.previewPdfKey=pdfKey;b.previewPdfName=pdfFile.name;
          save();cm();re();toast('✓ Contenu + aperçu PDF enregistrés');
        });
      };
      pdfReader.onerror=function(){save();cm();re();toast('✓ Contenu enregistré (erreur lecture PDF)','warn');};
      pdfReader.readAsDataURL(pdfFile);
    }
  } else {
    save();cm();re();toast('✓ Contenu du livre mis à jour');
  }
}

function removeBookPdfPreview(bid){
  var b=DB.books.find(function(x){return x.id===bid;});if(!b)return;
  if(b.previewPdfKey){
    var _idbReq=indexedDB.open('veritasDB',1);
    _idbReq.onsuccess=function(e){
      try{e.target.result.transaction('files','readwrite').objectStore('files').delete(b.previewPdfKey);}catch(ex){}
    };
  }
  b.previewPdfKey='';b.previewPdfName='';b.previewPdfUrl='';
  save();addBookContent(bid);toast('✓ Aperçu PDF supprimé');
}
function removeBookPreview(bid,idx){
  const b=DB.books.find(x=>x.id===bid);if(!b||!b.previewImages)return;
  b.previewImages.splice(idx,1);save();toast('Image supprimée');
  addBookContent(bid);
}

