        +'<button class="btn bo" style="border:none;cursor:pointer;font-size:13px;padding:10px 18px;margin:4px" onclick="var w=window.open(window[\'_bookGvUrl_'+bid+'\'],\'_blank\');if(!w)alert(\'Autorisez les pop-ups\');">🔍 Voir aperçu</button>'
