function _heroActuTab(cat,btn){
  _heroCurCat=cat;
  ['education','minesec','grandes_ecoles','bourses'].forEach(function(id){
    var b=document.getElementById('hat_'+id);
    if(!b)return;
    var active=id===cat;
    if(active){
      b.style.border='1.5px solid '+(_heroCatColors[id]||'#3B82F6');
      b.style.background=(_heroCatBg[id]||'#EFF6FF');
      b.style.color=(_heroCatText[id]||'#1D4ED8');
      b.style.boxShadow='none';
    }else{
      b.style.border='1.5px solid #E5E7EB';
      b.style.background='#F9FAFB';
      b.style.color='#6B7280';
      b.style.boxShadow='none';
    }
  });
  _heroActuLoad(cat);
}

function _hexToRgb(hex){
  var r=parseInt(hex.slice(1,3),16),g=parseInt(hex.slice(3,5),16),b=parseInt(hex.slice(5,7),16);
  return r+','+g+','+b;
}

function _heroActuLoad(cat){
  var list=document.getElementById('vHeroNewsList');
  if(!list)return;
  var now=Date.now();
  // Utiliser le cache si disponible
  if(_actuCache[cat]&&(now-_actuCache[cat].ts)<1800000){
    _heroActuRender(_actuCache[cat].items,cat);
    return;
  }
  list.innerHTML='<div style="display:flex;align-items:center;justify-content:center;height:80px;color:#94A3B8;font-size:12px">⏳ Chargement...</div>';
  var base=(DB.cloudConfig&&DB.cloudConfig.url||'https://veritas-school.com/api').replace(/\/+$/,'');
  fetch(base+'/news_proxy.php?cat='+encodeURIComponent(cat))
    .then(function(r){return r.json();})
    .then(function(data){
      if(data.items&&data.items.length){
        _actuCache[cat]={items:data.items,ts:now};
        _heroActuRender(data.items,cat);
      }else{
        list.innerHTML='<div style="color:#94A3B8;font-size:12px;padding:16px;text-align:center">Aucun article disponible</div>';
      }
    })
    .catch(function(){
      list.innerHTML='<div style="color:#EF4444;font-size:12px;padding:16px;text-align:center">⚠️ Actualités indisponibles</div>';
    });
}

function _heroActuRender(items,cat){
  var list=document.getElementById('vHeroNewsList');
  if(!list)return;
  var col=_heroCatColors[cat]||'#3B82F6';
  var bg=_heroCatBg[cat]||'#EFF6FF';
  var textCol=_heroCatText[cat]||'#1D4ED8';
  // Injection animation une seule fois
  if(!document.getElementById('_heroActuStyle')){
    var s=document.createElement('style');
    s.id='_heroActuStyle';
    s.textContent='@keyframes heroFadeIn{from{opacity:0;transform:translateX(14px)}to{opacity:1;transform:translateX(0)}}';
    document.head.appendChild(s);
  }
  var html='';
  items.forEach(function(it,i){
    var delay=(i*0.06).toFixed(2);
    html+='<a href="'+it.link+'" target="_blank" rel="noopener" style="text-decoration:none;display:block;margin-bottom:5px">'
      +'<div style="'
        +'padding:10px 12px 9px;'
        +'border-radius:10px;'
        +'background:#FAFBFF;'
        +'border:1px solid #EEF2FB;'
        +'cursor:pointer;'
        +'transition:all .22s ease;'
        +'animation:heroFadeIn .4s ease both;'
        +'animation-delay:'+delay+'s;'
      +'" '
      +'onmouseover="this.style.background=\''+bg+'\';this.style.borderColor=\''+col+'\';this.style.transform=\'translateX(4px)\'" '
      +'onmouseout="this.style.background=\'#FAFBFF\';this.style.borderColor=\'#EEF2FB\';this.style.transform=\'\'">'
        +'<div style="display:flex;align-items:flex-start;gap:10px">'
          // Point coloré
          +'<div style="width:8px;height:8px;min-width:8px;border-radius:50%;background:'+col+';margin-top:5px"></div>'
          +'<div style="flex:1;min-width:0">'
            // Titre
            +'<div style="font-size:12.5px;font-weight:600;color:#1E293B;line-height:1.45;margin-bottom:6px;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden">'+it.title+'</div>'
            // Méta
            +'<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap">'
              +(it.source?'<span style="font-size:9.5px;color:'+textCol+';font-weight:700;background:'+bg+';border:1px solid '+col+'33;padding:1px 8px;border-radius:8px">'+it.source+'</span>':'')
              +'<span style="font-size:9px;color:#94A3B8">'+it.date+'</span>'
              +'<span style="margin-left:auto;font-size:11px;color:'+col+';font-weight:800;transition:transform .15s" onmouseover="this.style.transform=\'translateX(2px)\'" onmouseout="this.style.transform=\'\'">↗</span>'
            +'</div>'
          +'</div>'
        +'</div>'
      +'</div>'
    +'</a>';
  });
  list.innerHTML=html;
}

// ── ACTUALITÉS ÉDUCATIVES (page dédiée) ──────────────────────────────────────
var _actuCat='education';
var _actuCache={};

function showActualites(container){
  var c=container||document.getElementById('vContent');
  if(!c)return;
  var cats=[
    {id:'education',     label:'📰 Éducation',     color:'#3C8DFF'},
    {id:'minesec',       label:'🏛️ MINESEC',        color:'#059669'},
    {id:'grandes_ecoles',label:'🎓 Grandes Écoles', color:'#7C3AED'},
    {id:'bourses',       label:'💼 Bourses',         color:'#f59e0b'},
  ];
  var tabsHtml=cats.map(function(ct){
    var active=ct.id===_actuCat;
    return '<button onclick="_actuTab(\''+ct.id+'\')" id="actutab_'+ct.id+'" style="'
      +'padding:8px 16px;border-radius:6px;border:1.5px solid '+(active?ct.color:'var(--bg3)')+';'
      +'background:'+(active?ct.color+'18':'transparent')+';color:'+(active?ct.color:'var(--ink3)')+';'
      +'font-family:Montserrat,sans-serif;font-size:12px;font-weight:700;cursor:pointer;white-space:nowrap;transition:all .2s">'+ct.label+'</button>';
  }).join('');

  c.innerHTML='<div class="vsec">'
    +'<div class="vsec-title">📡 Actualités Éducatives</div>'
    +'<div class="vsec-sub">Restez informé — éducation Cameroun, MINESEC, grandes écoles et bourses</div>'
    +'<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:20px;padding-bottom:12px;border-bottom:var(--br)">'
      +tabsHtml
      +'<button onclick="_actuRefresh()" title="Actualiser" style="margin-left:auto;padding:8px 14px;border-radius:6px;border:1px solid var(--bg3);background:var(--sur);color:var(--ink3);cursor:pointer;font-size:13px">🔄</button>'
    +'</div>'
    +'<div id="actu-feed" style="min-height:200px"></div>'
    +'<div class="vsec-sub" style="margin-top:20px;font-size:11px">Sources : Google News · Auto-actualisation toutes les 15 min · Bouton 🔄 = force refresh</div>'
    +'</div>';

  _actuLoad(_actuCat);
  _actuStartAutoRefresh(); // lance le timer 15 min
}

function _actuTab(cat){
  _actuCat=cat;
  var cats=['education','minesec','grandes_ecoles','bourses'];
  var colors={education:'#3C8DFF',minesec:'#059669',grandes_ecoles:'#7C3AED',bourses:'#f59e0b'};
  cats.forEach(function(id){
    var btn=document.getElementById('actutab_'+id);
    if(!btn)return;
    var active=id===cat;
    var col=colors[id];
    btn.style.border='2px solid '+(active?col:'transparent');
    btn.style.background=active?col+'22':'transparent';
    btn.style.color=active?col:'var(--ink3)';
  });
  _actuLoad(cat);
}

function _actuRefresh(){
  // Force-refresh : vide le cache MÉMOIRE + envoie nocache=1 au proxy PHP
  delete _actuCache[_actuCat];
  _actuLoad(_actuCat, true);
}

function _actuLoad(cat, forceRefresh){
  var feed=document.getElementById('actu-feed');
  if(!feed)return;

  // Utiliser le cache mémoire si < 10 min ET pas de force refresh
  var now=Date.now();
  if(!forceRefresh && _actuCache[cat]&&(now-_actuCache[cat].ts)<600000){
    _actuRender(_actuCache[cat].items,cat,_actuCache[cat].fetched_at);
    return;
  }

  feed.innerHTML='<div style="text-align:center;padding:40px;color:var(--ink4)">'
    +'<div style="font-size:32px;margin-bottom:10px;animation:spin 1s linear infinite;display:inline-block">⏳</div>'
    +'<div style="font-size:13px">'+(forceRefresh?'Force refresh en cours...':'Chargement des actualités...')+'</div></div>';

  var base=(DB.cloudConfig&&DB.cloudConfig.url||'https://veritas-school.com/api').replace(/\/+$/,'');
  // t= invalide le cache navigateur ; nocache=1 force le proxy à re-fetch Google News
  var url=base+'/news_proxy.php?cat='+encodeURIComponent(cat)+'&t='+now+(forceRefresh?'&nocache=1':'');

  fetch(url,{cache:forceRefresh?'no-store':'default'})
    .then(function(r){return r.json();})
    .then(function(data){
      if(data.items&&data.items.length){
        _actuCache[cat]={items:data.items,ts:now,fetched_at:data.fetched_at||null};
        _actuRender(data.items,cat,data.fetched_at);
      }else{
        feed.innerHTML='<div class="ib ibt"><span>📭</span><span>Aucun article disponible pour le moment — réessayez dans quelques minutes.</span></div>';
      }
    })
    .catch(function(){
      feed.innerHTML='<div class="ib ibw"><span>⚠️</span><span>Impossible de charger les actualités. Vérifiez votre connexion.</span></div>';
    });
}

// Auto-refresh toutes les 15 min quand la page actualités est visible
window._actuAutoTimer=null;
function _actuStartAutoRefresh(){
  if(window._actuAutoTimer)clearInterval(window._actuAutoTimer);
  window._actuAutoTimer=setInterval(function(){
    if(window._vCurrentSec==='actualites'&&document.visibilityState==='visible'){
      _actuRefresh();
    }
  },15*60*1000);
}

function _actuRender(items,cat,fetchedAt){
  var feed=document.getElementById('actu-feed');
  if(!feed)return;
  var colors={education:'#3C8DFF',minesec:'#059669',grandes_ecoles:'#7C3AED',bourses:'#f59e0b'};
  var col=colors[cat]||'#3C8DFF';
  // Indicateur de fraîcheur en haut
  var freshHtml='';
  if(fetchedAt){
    var fetchDate=new Date(fetchedAt);
    var diffMin=Math.floor((Date.now()-fetchDate.getTime())/60000);
    freshHtml='<div style="font-size:11px;color:var(--ink4);margin-bottom:8px;display:flex;align-items:center;gap:6px">'
      +'<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:'+(diffMin<5?'#16A34A':diffMin<30?'#D97706':'#94A3B8')+'"></span>'
      +'Mis à jour il y a '+(diffMin<1?'moins d\'1 min':diffMin+' min')+' · '+items.length+' article(s)'
      +'</div>';
  }
  var html=freshHtml+'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:14px">';
  items.forEach(function(it){
    html+='<a href="'+it.link+'" target="_blank" rel="noopener" style="text-decoration:none">'
      +'<div style="background:var(--sur);border:1px solid var(--bg3);border-left:3px solid '+col+';border-radius:var(--r2);padding:14px;transition:all .2s;cursor:pointer" '
        +'onmouseover="this.style.boxShadow=\'0 4px 16px rgba(0,0,0,.08)\';this.style.transform=\'translateY(-2px)\'" '
        +'onmouseout="this.style.boxShadow=\'\';this.style.transform=\'\'">'
        +'<div style="font-family:Montserrat,sans-serif;font-size:13px;font-weight:700;color:var(--ink1);line-height:1.4;margin-bottom:8px">'+it.title+'</div>'
        +'<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">'
          +(it.source?'<span style="font-size:10px;color:'+col+';font-weight:700;background:'+col+'15;padding:2px 8px;border-radius:10px">'+it.source+'</span>':'')
          +'<span style="font-size:10px;color:var(--ink4)">📅 '+it.date+'</span>'
          +'<span style="margin-left:auto;font-size:11px;color:'+col+';font-weight:700">Lire →</span>'
        +'</div>'
      +'</div>'
    +'</a>';
  });
  html+='</div>';
  feed.innerHTML=html;
}

function _vRevealInit(){
  if(_vRevealObs)_vRevealObs.disconnect();
  _vRevealObs=new IntersectionObserver(function(entries){
    entries.forEach(function(e){if(e.isIntersecting){e.target.classList.add('visible');_vRevealObs.unobserve(e.target);}});
  },{threshold:0.12,rootMargin:'0px 0px -40px 0px'});
  var vis=document.getElementById('VISITOR');
  if(!vis)return;
  vis.querySelectorAll('.v-reveal,.v-reveal-left,.v-reveal-right,.v-reveal-scale,.v-stagger').forEach(function(el){_vRevealObs.observe(el);});
}

