// ═══════════════════════════════════════════════
// NOTIFICATIONS
// ═══════════════════════════════════════════════
function _notifUid(){return SES?.id||SES?.user||'';}
function _notifList(){
  var uid=_notifUid();
  return (DB.notifications||[])
    .filter(function(n){return n.to==='all'||n.to===uid||n.to===SES?.type;})
    .sort(function(a,b){return (b.date||'').localeCompare(a.date||'');});
}
function showNotifications(){
  _renderNotifModal();
}
function _renderNotifModal(){
  var notifs=_notifList();
  var uid=_notifUid();
  var unread=notifs.filter(function(n){return !(n.read||[]).includes(uid);}).length;
  var html='';
  if(notifs.length){
    html='<div style="max-height:420px;overflow-y:auto">';
    notifs.forEach(function(n){
      var isRead=(n.read||[]).includes(uid);
      var ico=n.type==='warn'?'⚠️':n.type==='success'?'✅':'ℹ️';
      var bg=isRead?'transparent':'rgba(59,130,246,.07)';
      var border=isRead?'1px solid var(--bg2)':'1px solid rgba(59,130,246,.18)';
      html+='<div style="padding:12px 14px;border-bottom:1px solid var(--bg2);background:'+bg+';border-left:'+border+';cursor:pointer;transition:background .2s" '
        +'onmouseenter="this.style.background=\'rgba(59,130,246,.05)\'" '
        +'onmouseleave="this.style.background=\''+bg+'\'" '
        +'onclick="_notifMarkAndRefresh(\''+n.id+'\')">'
        +'<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px">'
        +'<div style="display:flex;align-items:center;gap:6px;flex:1;min-width:0">'
        +(isRead?'':'<span style="width:7px;height:7px;border-radius:50%;background:#3B82F6;flex-shrink:0;margin-top:3px;display:inline-block"></span>')
        +'<span style="font-size:16px">'+ico+'</span>'
        +'<span style="font-family:Montserrat,sans-serif;font-size:13px;font-weight:'+(isRead?'600':'800')+';color:var(--ink1)">'+_esc(n.titre)+'</span>'
        +'</div>'
        +'<div style="display:flex;align-items:center;gap:6px;flex-shrink:0">'
        +'<span style="font-size:11px;color:var(--ink4)">'+_esc(n.date||'')+'</span>'
        +(iA()?'<button onclick="event.stopPropagation();_delNotif(\''+n.id+'\')" style="background:none;border:none;cursor:pointer;font-size:14px;opacity:.4;padding:0 2px" title="Supprimer">🗑</button>':'')
        +'</div>'
        +'</div>'
        +'<div style="font-size:12.5px;color:var(--ink2);margin-top:5px;margin-left:'+(isRead?'22px':'29px')+';line-height:1.55">'+_esc(n.msg)+'</div>'
        +'</div>';
    });
    html+='</div>';
  } else {
    html='<div class="empty"><div class="empty-ico">🔔</div><div>Aucune notification pour le moment</div></div>';
  }
  var footer='<button class="btn bo" onclick="cm()">Fermer</button>';
  if(unread>0) footer+='<button class="btn bgr2" onclick="_markAllNotifsRead()">✓ Tout marquer lu</button>';
  if(iA()) footer='<button class="btn bi sm" onclick="cm();mNewNotification()">＋ Nouvelle</button>'+footer;
  var titre=unread>0?'🔔 Notifications <span style="background:#EF4444;color:#fff;font-size:11px;font-weight:700;padding:2px 7px;border-radius:10px;margin-left:6px">'+unread+' non lu'+(unread>1?'es':'')+'</span>':'🔔 Notifications';
  M(titre,notifs.length+' notification'+(notifs.length>1?'s':''),html,footer);
}
function _notifMarkAndRefresh(nid){
  var n=(DB.notifications||[]).find(function(x){return x.id===nid;});
  if(n){var uid=_notifUid();if(!n.read)n.read=[];if(!n.read.includes(uid))n.read.push(uid);save();topUI();}
  _renderNotifModal();
}
function markNotifRead(nid){_notifMarkAndRefresh(nid);}
function _markAllNotifsRead(){
  var uid=_notifUid();
  (DB.notifications||[]).forEach(function(n){
    if(n.to==='all'||n.to===uid||n.to===SES?.type){
      if(!n.read)n.read=[];
      if(!n.read.includes(uid))n.read.push(uid);
    }
  });
  save();topUI();_renderNotifModal();toast('✓ Toutes les notifications marquées comme lues');
}
function _delNotif(nid){
  DB.notifications=(DB.notifications||[]).filter(function(x){return x.id!==nid;});
  save();topUI();_renderNotifModal();toast('Notification supprimée');
}
function mNewNotification(){
  M('📤 Nouvelle notification','Envoyer un message aux utilisateurs',
  '<div class="fg2">'
  +'<div class="fg full"><span class="fl">Titre *</span><input class="fi" id="nfTitre" placeholder="Ex: Résultats des épreuves blanches disponibles"></div>'
  +'<div class="fg"><span class="fl">Type</span><select class="fi" id="nfType"><option value="info">ℹ️ Information</option><option value="success">✅ Bonne nouvelle</option><option value="warn">⚠️ Alerte / Urgent</option></select></div>'
  +'<div class="fg"><span class="fl">Destinataires</span><select class="fi" id="nfTo"><option value="all">👥 Tout le monde</option><option value="eleve">🎓 Élèves uniquement</option><option value="enseignant">👨‍🏫 Enseignants uniquement</option></select></div>'
  +'<div class="fg full"><span class="fl">Message *</span><textarea class="fi" id="nfMsg" rows="4" placeholder="Rédigez votre message ici…"></textarea></div>'
  +'</div>',
  '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="sendNotification()">📤 Envoyer</button>');
}
function autoNotify(titre,msg,to){
  if(!DB.notifications)DB.notifications=[];
  DB.notifications.push({id:gid(),to:to||'all',titre:titre,msg:msg,
    date:new Date().toISOString().split('T')[0],read:[],type:'info'});
  save();topUI();
}
function sendNotification(){
  var titre=(document.getElementById('nfTitre')?.value||'').trim();
  var msg=(document.getElementById('nfMsg')?.value||'').trim();
  if(!titre||!msg){toast('Titre et message requis','warn');return;}
  if(!DB.notifications)DB.notifications=[];
  DB.notifications.push({id:gid(),
    to:document.getElementById('nfTo')?.value||'all',
    titre:titre,msg:msg,
    date:new Date().toISOString().split('T')[0],
    read:[],
    type:document.getElementById('nfType')?.value||'info'});
  save();topUI();cm();toast('✓ Notification envoyée');
}

// ═══════════════════════════════════════════════
// SÉCURITÉ RENFORCÉE v1.0
// ═══════════════════════════════════════════════

// ── Hachage SHA-256 avec sel unique par utilisateur ──
// DEPRECATED : fallback XOR conservé uniquement pour vérifier les anciens hashes H$...
// Ne jamais utiliser pour de nouveaux hashes — _hashSync produit ~4 milliards de valeurs (cassable en secondes).
function _hashSync(pwd,salt){
  var s=pwd+(salt||'_VERITAS_2026');var h=0;
  for(var i=0;i<s.length;i++){h=((h<<5)-h)+s.charCodeAt(i);h|=0;}
  return 'H$'+Math.abs(h).toString(36)+'$'+s.length;
}
async function hashPassword(pwd,salt){
  if(typeof crypto!=='undefined'&&crypto.subtle){
    try{
      var enc=new TextEncoder();var data=enc.encode(pwd+'$'+(salt||'VERITAS')+'$2026');
      var hash=await crypto.subtle.digest('SHA-256',data);
      return 'S256$'+Array.from(new Uint8Array(hash)).map(function(b){return b.toString(16).padStart(2,'0');}).join('');
    }catch(e){console.warn('[security] crypto.subtle a échoué, fallback faible:',e);}
  }
  // Fallback uniquement pour navigateurs anciens — produit H$ (XOR faible)
  console.warn('[security] AVERTISSEMENT : utilisation du hash XOR faible (navigateur ancien)');
  return _hashSync(pwd,salt);
}
function isHashed(p){return p&&(p.indexOf('S256$')===0||p.indexOf('H$')===0);}
async function verifyPassword(plain,hashed,salt,recordRef){
  if(isHashed(hashed)){
    try{
      var h=await hashPassword(plain,salt);
      var ok=(h===hashed);
      // Si compte ancien (H$ XOR faible) et auth réussie → upgrader vers S256$
      if(ok && hashed.indexOf('H$')===0 && recordRef){
        try{recordRef.pwd=h;if(typeof save==='function')setTimeout(save,100);}catch(eU){}
      }
      return ok;
    }catch(e){console.warn('[security] hash fail, fallback plain:',e);return false;}
  }
  // Legacy plaintext : autoriser UNE fois pour ne pas brick les comptes seed, mais upgrader immédiatement
  if(plain===hashed){
    if(recordRef){
      try{
        recordRef.pwd=await hashPassword(plain,salt);
        if(typeof save==='function')setTimeout(save,100);
      }catch(eU2){console.warn('[security] upgrade fail:',eU2);}
    }
    return true;
  }
  return false;
}

// ── Migration automatique : hasher tous les mots de passe en clair ──
async function _migratePasswords(){
  var changed=false;
  // Super admin
  if(DB.superAdmin&&DB.superAdmin.pwd&&!isHashed(DB.superAdmin.pwd)){
    DB.superAdmin.pwd=await hashPassword(DB.superAdmin.pwd,DB.superAdmin.user);changed=true;
  }
  // Admins
  if(DB.admins){for(var i=0;i<DB.admins.length;i++){
    if(DB.admins[i].pwd&&!isHashed(DB.admins[i].pwd)){
      DB.admins[i].pwd=await hashPassword(DB.admins[i].pwd,DB.admins[i].user);changed=true;
    }
  }}
  // Student accounts
  if(DB.studentAccounts){for(var j=0;j<DB.studentAccounts.length;j++){
    if(DB.studentAccounts[j].pwd&&!isHashed(DB.studentAccounts[j].pwd)){
      DB.studentAccounts[j].pwd=await hashPassword(DB.studentAccounts[j].pwd,DB.studentAccounts[j].user);changed=true;
    }
  }}
  // Teacher passwords
  if(DB.tpwd){for(var k in DB.tpwd){
    if(DB.tpwd[k]&&!isHashed(DB.tpwd[k])){
      DB.tpwd[k]=await hashPassword(DB.tpwd[k],k);changed=true;
    }
  }}
  // Visitor accounts
  if(DB.visitorAccounts){for(var v=0;v<DB.visitorAccounts.length;v++){
    if(DB.visitorAccounts[v].pwd&&!isHashed(DB.visitorAccounts[v].pwd)){
      DB.visitorAccounts[v].pwd=await hashPassword(DB.visitorAccounts[v].pwd,DB.visitorAccounts[v].user);changed=true;
    }
  }}
  // Author accounts
  if(DB.authorAccounts){for(var a=0;a<DB.authorAccounts.length;a++){
    if(DB.authorAccounts[a].pwd&&!isHashed(DB.authorAccounts[a].pwd)){
      DB.authorAccounts[a].pwd=await hashPassword(DB.authorAccounts[a].pwd,DB.authorAccounts[a].user);changed=true;
    }
  }}
  if(changed)save();
}

// ── Anti brute-force : verrouillage temporaire ──
var _loginLock={};
function _checkLoginLock(user){
  var k=user.toLowerCase();var l=_loginLock[k];
  if(!l)return{locked:false,remaining:0};
  if(l.locked&&Date.now()<l.until){return{locked:true,remaining:Math.ceil((l.until-Date.now())/1000)};}
  if(l.locked&&Date.now()>=l.until){_loginLock[k]={attempts:0,locked:false,until:0};}
  return{locked:false,remaining:0};
}
function _recordLoginFail(user){
  var k=user.toLowerCase();
  if(!_loginLock[k])_loginLock[k]={attempts:0,locked:false,until:0};
  _loginLock[k].attempts++;
  // 3 échecs → verrouillage 30s, 6 → 2min, 9 → 5min, 12+ → 15min
  var a=_loginLock[k].attempts;
  if(a>=12){_loginLock[k].locked=true;_loginLock[k].until=Date.now()+15*60000;}
  else if(a>=9){_loginLock[k].locked=true;_loginLock[k].until=Date.now()+5*60000;}
  else if(a>=6){_loginLock[k].locked=true;_loginLock[k].until=Date.now()+2*60000;}
  else if(a>=3){_loginLock[k].locked=true;_loginLock[k].until=Date.now()+30000;}
  // Log failed attempt
  if(!DB.loginLog)DB.loginLog=[];
  DB.loginLog.push({user:user,role:'echec',date:today(),time:new Date().toLocaleTimeString('fr-FR'),ip:'local'});
  if(DB.loginLog.length>200)DB.loginLog=DB.loginLog.slice(-200);
  save();
}
function _recordLoginSuccess(user){
  var k=user.toLowerCase();_loginLock[k]={attempts:0,locked:false,until:0};
}

// ── Session sécurisée ──
function sanitizeInput(str){if(!str)return'';return String(str).replace(/[<>"'&]/g,function(c){return({'<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;','&':'&amp;'})[c]||c;});}
function generateSessionToken(){return gid()+'-'+Date.now()+'-'+Math.random().toString(36).substr(2);}
var SESSION_TOKEN=null;
var SESSION_EXPIRY=0;
var SESSION_DURATION=4*60*60*1000; // 4 heures
function _createSession(data){
  SESSION_TOKEN=generateSessionToken();
  SESSION_EXPIRY=Date.now()+SESSION_DURATION;
  SES=data;SES._token=SESSION_TOKEN;SES._exp=SESSION_EXPIRY;
  sessionStorage.setItem('VERITAS_SES',JSON.stringify(SES));
}
function _checkSession(){
  if(!SES||!SES._token||!SES._exp)return false;
  if(Date.now()>SES._exp){_destroySession();toast('Session expirée — reconnectez-vous','warn');return false;}
  return true;
}
function _destroySession(){
  SES=null;SESSION_TOKEN=null;SESSION_EXPIRY=0;
  sessionStorage.removeItem('VERITAS_SES');
}

// ═══════════════════════════════════════════════
// QR CODE GENERATION — SVG natif (pas de CDN requis)
// Mini QR encoder (Mode Byte, ECC-L, Version 1-6 auto)
// ═══════════════════════════════════════════════
var _qrSvg=(function(){
  // Galois field GF(256) tables
  var EXP=new Uint8Array(512),LOG=new Uint8Array(256);
  (function(){var x=1;for(var i=0;i<255;i++){EXP[i]=x;LOG[x]=i;x<<=1;if(x&256)x^=285;}for(var i=255;i<512;i++)EXP[i]=EXP[i-255];})();
  function gfMul(a,b){return a&&b?EXP[LOG[a]+LOG[b]]:0;}
  function polyMul(p,q){var r=new Uint8Array(p.length+q.length-1);for(var i=0;i<p.length;i++)for(var j=0;j<q.length;j++)r[i+j]^=gfMul(p[i],q[j]);return r;}
  function genPoly(n){var g=new Uint8Array([1]);for(var i=0;i<n;i++)g=polyMul(g,new Uint8Array([1,EXP[i]]));return g;}
  function eccEncode(data,eccLen){var gen=genPoly(eccLen);var msg=new Uint8Array(data.length+eccLen);msg.set(data);for(var i=0;i<data.length;i++){var coef=msg[i];if(coef)for(var j=0;j<gen.length;j++)msg[i+j]^=gfMul(gen[j],coef);}return msg.slice(data.length);}

  // Version params: [totalCodewords, eccCodewords, dataCodewords]
  var VERS=[null,[26,7,19],[44,10,34],[70,15,55],[100,20,80],[134,26,108],[172,36,136]];
  function pickVer(len){for(var v=1;v<=6;v++){var dw=VERS[v][2]-2;if(len<=dw)return v;}return 6;}
  function sz(v){return 17+v*4;}

  function encode(text){
    var bytes=[];for(var i=0;i<text.length;i++){var c=text.charCodeAt(i);if(c<128)bytes.push(c);else if(c<2048){bytes.push(192|(c>>6),128|(c&63));}else{bytes.push(224|(c>>12),128|((c>>6)&63),128|(c&63));}}
    var ver=pickVer(bytes.length);var p=VERS[ver];var dcw=p[2];var ecw=p[1];
    // Build data codewords
    var bits=[];function addBits(val,len){for(var i=len-1;i>=0;i--)bits.push((val>>i)&1);}
    addBits(4,4);// Mode: byte
    addBits(bytes.length,ver<=9?8:16);
    for(var i=0;i<bytes.length;i++)addBits(bytes[i],8);
    addBits(0,Math.min(4,dcw*8-bits.length));
    while(bits.length%8)bits.push(0);
    while(bits.length<dcw*8){bits.push(1,1,1,0,1,1,0,0);if(bits.length<dcw*8)bits.push(0,0,0,1,0,0,0,1);}
    var data=new Uint8Array(dcw);for(var i=0;i<dcw;i++){var b=0;for(var j=0;j<8;j++)b=(b<<1)|bits[i*8+j];data[i]=b;}
    var ecc=eccEncode(data,ecw);
    // Interleave (single block for v1-6 ECC-L)
    var payload=new Uint8Array(dcw+ecw);payload.set(data);payload.set(ecc,dcw);

    // Build matrix
    var n=sz(ver);var grid=[];var reserved=[];
    for(var r=0;r<n;r++){grid[r]=new Uint8Array(n);reserved[r]=new Uint8Array(n);}
    function setMod(r,c,v){if(r>=0&&r<n&&c>=0&&c<n){grid[r][c]=v?1:0;reserved[r][c]=1;}}
    // Finder patterns
    function finder(row,col){for(var dr=-1;dr<=7;dr++)for(var dc=-1;dc<=7;dc++){var r=row+dr,c=col+dc;if(r<0||r>=n||c<0||c>=n)continue;var v=(dr>=0&&dr<=6&&(dc===0||dc===6))||(dc>=0&&dc<=6&&(dr===0||dr===6))||(dr>=2&&dr<=4&&dc>=2&&dc<=4);setMod(r,c,v);}}
    finder(0,0);finder(0,n-7);finder(n-7,0);
    // Timing
    for(var i=8;i<n-8;i++){setMod(6,i,i%2===0);setMod(i,6,i%2===0);}
    // Dark module + reserved format
    setMod(n-8,8,1);
    for(var i=0;i<15;i++){if(i<6)reserved[8][i]=1;else if(i<8)reserved[8][i+1]=1;else reserved[14-i][8]=1;
    if(i<8)reserved[n-1-i][8]=1;else if(i<9)reserved[8][n-15+i]=1;else reserved[8][n-15+i]=1;}
    for(var i=0;i<8;i++){reserved[8][i]=1;reserved[8][n-8+i]=1;reserved[i][8]=1;reserved[n-8+i][8]=1;}
    reserved[8][8]=1;reserved[8][7]=1;reserved[7][8]=1;

    // Alignment (v2+)
    if(ver>=2){var pos=[6,n-7];for(var ri=0;ri<pos.length;ri++)for(var ci=0;ci<pos.length;ci++){var cr=pos[ri],cc=pos[ci];if(reserved[cr][cc])continue;for(var dr=-2;dr<=2;dr++)for(var dc=-2;dc<=2;dc++)setMod(cr+dr,cc+dc,Math.abs(dr)===2||Math.abs(dc)===2||(dr===0&&dc===0));}}

    // Place data bits
    var bitIdx=0;var allBits=[];
    for(var i=0;i<payload.length;i++)for(var j=7;j>=0;j--)allBits.push((payload[i]>>j)&1);
    var right=true;for(var col=n-1;col>=1;col-=2){
      if(col===6)col=5;
      for(var cnt=0;cnt<n;cnt++){
        var row=right?(n-1-cnt):cnt;
        for(var dx=0;dx<=1;dx++){
          var c=col-dx;
          if(!reserved[row][c]){grid[row][c]=bitIdx<allBits.length?allBits[bitIdx]:0;bitIdx++;}
        }
      }
      right=!right;
    }

    // Masking (mask 0: (row+col)%2==0)
    for(var r=0;r<n;r++)for(var c=0;c<n;c++)if(!reserved[r][c]&&(r+c)%2===0)grid[r][c]^=1;

    // Format info (ECC L=01, mask 0=000 → 01000 → with BCH)
    var fmtBits=[1,1,1,0,1,1,1,1,1,0,0,0,1,0,0];
    // Place format
    for(var i=0;i<15;i++){
      var bit=fmtBits[i];
      // Around top-left finder
      if(i<6)setMod(8,i,bit);else if(i<8)setMod(8,i+1,bit);else setMod(14-i,8,bit);
      // Around other finders
      if(i<8)setMod(n-1-i,8,bit);else setMod(8,n-15+i,bit);
    }

    return {grid:grid,size:n};
  }

  function toSVG(text,pixelSize){
    pixelSize=pixelSize||3;
    var qr=encode(text);var n=qr.size;var margin=2;
    var total=(n+margin*2)*pixelSize;
    var svg='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 '+total+' '+total+'" width="'+total+'" height="'+total+'">';
    svg+='<rect width="'+total+'" height="'+total+'" fill="#fff"/>';
    for(var r=0;r<n;r++)for(var c=0;c<n;c++){
      if(qr.grid[r][c])svg+='<rect x="'+((c+margin)*pixelSize)+'" y="'+((r+margin)*pixelSize)+'" width="'+pixelSize+'" height="'+pixelSize+'" fill="#000"/>';
    }
    svg+='</svg>';
    return svg;
  }

  return {encode:encode,toSVG:toSVG};
})();

function generateQRData(docType,ref){
  var sc=DB.school||{};
  return (sc.nom||'VERITAS')+'\n'+docType+'\n'+today()+'\nREF:'+ref+'\nTel:'+(sc.tel||'')+'\n'+(sc.ville||'');
}
function addQRToDoc(containerId,docType,docId){
  setTimeout(function(){
    var container=document.getElementById(containerId);
    if(!container)return;
    var ref=docId||gid().substring(0,8).toUpperCase();
    var txt=generateQRData(docType,ref);
    var qrDiv=document.createElement('div');
    qrDiv.className='qr-container';
    qrDiv.innerHTML=_qrSvg.toSVG(txt,3);
    container.appendChild(qrDiv);
  },200);
}

// ═══════════════════════════════════════════════
// IMPORT/EXPORT EXCEL (SheetJS)
// ═══════════════════════════════════════════════
function exportToExcel(data,filename,sheetName){
  if(typeof XLSX==='undefined'){toast('Librairie Excel non chargée','warn');return;}
  const ws=XLSX.utils.json_to_sheet(data);
  const wb=XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb,ws,sheetName||'Données');
  XLSX.writeFile(wb,filename+'.xlsx');
  toast('✓ Fichier Excel exporté: '+filename+'.xlsx');
}

function importTeacherGrades(){
  const t=isEnseignant()?T(SES.tid):null;
  if(!t){toast('Réservé aux enseignants','warn');return;}
  importFromExcel(function(data){
    let count=0;const tri=window._gT||TRS[0];
    data.forEach(function(row){
      const nom=row['Nom']||'';const pre=row['Prénom']||row['Prenom']||'';
      const n1=parseFloat(row['Devoir 1']||row['Note 1']||row.n1);
      const n2=parseFloat(row['Devoir 2']||row['Note 2']||row.n2);
      if(!nom||isNaN(n1)||isNaN(n2)||n1<0||n1>20||n2<0||n2>20)return;
      const student=DB.students.find(function(s){return s.nom.toLowerCase()===nom.toLowerCase()&&s.pre.toLowerCase()===pre.toLowerCase();});
      if(!student)return;
      const sub=t.mat2;const coef=COEFS[sub]||1;
      const existing=DB.grades.find(function(g){return g.eid===student.id&&g.sub===sub&&g.tri===tri;});
      if(existing){existing.n1=n1;existing.n2=n2;}
      else DB.grades.push({id:gid(),eid:student.id,enom:student.pre+' '+student.nom,mat:student.mat,cls:student.cls,sub:sub,n1:n1,n2:n2,coef:coef,tri:tri,ens:t.pre+' '+t.nom});
      count++;
    });
    save();re();toast('✓ '+count+' notes importées en '+t.mat2);
  });
}

function exportTeacherGrades(){
  const t=isEnseignant()?T(SES.tid):null;
  if(!t){exportGrades(window._gC||CLS[0],window._gT||TRS[0]);return;}
  const selC=window._gC||CLS[0];const selT=window._gT||TRS[0];
  const sts=DB.students.filter(function(s){return s.cls===selC;}).sort(function(a,b){return(a.nom+a.pre).localeCompare(b.nom+b.pre);});
  const data=sts.map(function(s){
    const g=DB.grades.find(function(gr){return gr.eid===s.id&&gr.sub===t.mat2&&gr.tri===selT;});
    return{'Nom':s.nom,'Prénom':s.pre,'Matricule':s.mat,'Classe':selC,'Matière':t.mat2,'Trimestre':selT,'Devoir 1':g?g.n1:'','Devoir 2':g?g.n2:'','Moyenne':g?((g.n1+g.n2)/2).toFixed(2):''};
  });
  exportToExcel(data,t.mat2+'_'+selC+'_'+selT,t.mat2);
}

function exportStudentsList(cls){
  const selC=cls||'Toutes';
  const list=selC==='Toutes'?DB.students:DB.students.filter(s=>s.cls===selC);
  const data=list.map((s,i)=>({
    'N°':i+1,'Matricule':s.mat,'Nom':s.nom,'Prénom':s.pre,'Sexe':s.sex,
    'Date naissance':s.dob||'','Classe':s.cls,'Parent':s.parent||'',
    'Tél. Parent':s.ptel||'','Frais':s.frais,'Statut':s.stat
  }));
  exportToExcel(data,'Liste_Eleves_'+(selC==='Toutes'?'Tous':selC),'Élèves');
}

function exportGrades(cls,tri){
  const list=DB.grades.filter(g=>(cls==='Toutes'||g.cls===cls)&&g.tri===tri);
  const data=list.map(g=>({
    'Matricule':g.mat,'Élève':g.enom,'Classe':g.cls,'Matière':g.sub,
    'Devoir 1':g.n1,'Devoir 2':g.n2,'Coef':g.coef,'Moyenne':((g.n1+g.n2)/2).toFixed(2),
    'Trimestre':g.tri,'Enseignant':g.ens||''
  }));
  exportToExcel(data,'Notes_'+cls+'_'+tri,'Notes');
}

function exportTeacherHours(tid){
  const t=T(tid);if(!t)return;
  const hours=DB.teacherHours.filter(h=>h.tid===tid);
  const data=hours.map(h=>({
    'Date':h.date,'Classe':h.cls,'Matière':h.matiere,
    'Heures':h.heures,'Description':h.desc||'',
    'Montant (FCFA)':h.heures*(DB.tauxHoraire||2000)
  }));
  exportToExcel(data,'Heures_'+t.pre+'_'+t.nom,'Heures');
}

function importFromExcel(callback){
  const input=document.createElement('input');
  input.type='file';input.accept='.xlsx,.xls,.csv';
  input.onchange=function(e){
    const file=e.target.files[0];if(!file)return;
    const reader=new FileReader();
    reader.onload=function(evt){
      try{
        const wb=XLSX.read(evt.target.result,{type:'binary'});
        const ws=wb.Sheets[wb.SheetNames[0]];
        const data=XLSX.utils.sheet_to_json(ws);
        if(callback)callback(data);
        toast('✓ '+data.length+' lignes importées');
      }catch(err){toast('Erreur d\'import: '+err.message,'warn');}
    };
    reader.readAsBinaryString(file);
  };
  input.click();
}

function importStudents(){
  importFromExcel(function(data){
    let count=0;
    data.forEach(row=>{
      const nom=row['Nom']||row.nom;const pre=row['Prénom']||row.pre||row.prenom;
      if(!nom||!pre)return;
      const existing=DB.students.find(s=>s.nom===nom&&s.pre===pre);
      if(!existing){
        const n=String(DB.students.length+1).padStart(3,'0');
        DB.students.push({id:gid(),mat:row['Matricule']||'VRT-'+n,nom,pre,sex:row['Sexe']||row.sex||'M',
          dob:row['Date naissance']||row.dob||'',cls:row['Classe']||row.cls||CLS[0],
          tel:row['Tél']||row.tel||'',parent:row['Parent']||row.parent||'',
          ptel:row['Tél. Parent']||row.ptel||'',frais:parseInt(row['Frais']||row.frais)||25000,
          ins:today(),stat:row['Statut']||row.stat||'En attente',photo:''});
        count++;
      }
    });
    save();re();toast('✓ '+count+' élèves importés');
  });
}

