function uploadStudentPhoto(sid){
  const input=document.createElement('input');
  input.type='file';input.accept='image/*';
  input.onchange=function(e){
    const file=e.target.files[0];if(!file)return;
    if(file.size>500000){toast('Photo trop lourde (max 500Ko)','warn');return;}
    const reader=new FileReader();
    reader.onload=function(evt){
      const s=S(sid);if(s){s.photo=evt.target.result;save();re();toast('✓ Photo mise à jour');}
    };
    reader.readAsDataURL(file);
  };
  input.click();
}

function getStudentPhoto(s){
  if(s&&s.photo)return'<img src="'+s.photo+'" class="stu-photo" alt="">';
  return'<div class="av" style="width:40px;height:40px;background:'+(s&&s.sex==='F'?'var(--pub)':'var(--blb)')+';color:'+(s&&s.sex==='F'?'var(--pu)':'var(--bl)')+';border:1.5px solid '+(s&&s.sex==='F'?'var(--pud)':'var(--bld)')+';font-size:13px">'+(s?s.pre[0]:'?')+'</div>';
}

