// GALERIE PHOTOS ACCUEIL
// ═══════════════════════════════════════════════
function uploadGalleryPhoto(){
  var input=document.createElement('input');
  input.type='file';input.accept='image/*';input.multiple=true;
  input.style.display='none';document.body.appendChild(input);
  input.onchange=function(e){
    var files=Array.from(e.target.files);
    var total=files.filter(function(f){return f.size<=5000000;}).length;
    var processed=0;
    files.forEach(function(file){
      if(file.size>5000000){toast('Image '+file.name+' trop lourde (max 5Mo)','warn');return;}
      var titre=prompt('Titre de la photo :',file.name.replace(/\.[^.]+$/,''));
      if(!titre)return;
      // MOD-3.6 : upload via LWS_API.upload (remplace cloudConfig + upload_file.php)
      showUploadProgress(0,'Upload en cours…');
      uploadToLWS(file,'galerie',function(pct){
        showUploadProgress(pct,file.name+' — '+pct+'%');
      }).then(function(res){
        showUploadProgress(100);
        if(!DB.galleryImages)DB.galleryImages=[];
        DB.galleryImages.push({id:gid(),src:res.url,serverSrc:res.url,titre:titre,desc:'',date:today()});
        processed++;save();
        if(processed===total){
          if(iA()&&typeof re==='function'){re();}
          else{vShowSec('photos',document.querySelector('.vnav-btn[onclick*="photos"]')||document.querySelectorAll('.vnav-btn')[2]);}
          toast('✓ '+processed+' photo(s) uploadée(s) sur LWS');
        }
      }).catch(function(){
        showUploadProgress(100);
        _galleryFallback(file,titre,total,function(){
          processed++;
          if(processed===total){
            save();
            if(iA()&&typeof re==='function'){re();}
            else{vShowSec('photos',document.querySelector('.vnav-btn[onclick*="photos"]')||document.querySelectorAll('.vnav-btn')[2]);}
            toast('✓ Photo ajoutée (stockage local — cloud KO)','warn');
          }
        });
      });
    });
    input.remove();
  };
  setTimeout(function(){input.click();},100);
}
function _galleryFallback(file,titre,total,done){
  var reader=new FileReader();
  reader.onload=function(evt){
    if(!DB.galleryImages)DB.galleryImages=[];
    DB.galleryImages.push({id:gid(),src:evt.target.result,titre:titre,desc:'',date:today()});
    save();done();
  };
  reader.readAsDataURL(file);
}

function _galleryLightbox(encodedSrc, titre){
  var src=decodeURIComponent(encodedSrc);
  M('','',
    '<div style="text-align:center;padding:4px 0">'
    +'<img src="'+src+'" alt="'+_esc(titre)+'" loading="lazy" '
    +'style="max-width:100%;max-height:75vh;border-radius:10px;display:block;margin:0 auto;box-shadow:0 8px 32px rgba(0,0,0,.25)">'
    +(titre?'<div style="margin-top:12px;font-family:Libre Baskerville,serif;font-size:16px;font-weight:700;color:var(--bl)">'+_esc(titre)+'</div>':'')
    +'</div>',
    '<button class="btn bo" onclick="cm()">✕ Fermer</button>',
    true
  );
}
function deleteGalleryPhoto(pid){
  if(!confirm('Supprimer cette photo ?'))return;
  DB.galleryImages=(DB.galleryImages||[]).filter(function(p){return p.id!==pid;});
  DB.photos=(DB.photos||[]).filter(function(p){return p.id!==pid;});
  save();
  // Push immédiat vers le cloud pour que la suppression ne revienne pas au prochain poll
  if(typeof _triggerAutoSync==='function')setTimeout(_triggerAutoSync,300);
  // Rester dans le panneau actif (admin ou visiteur) sans redirection
  if(iA()&&typeof re==='function'){re();}
  else if(typeof initVisitor==='function'){initVisitor();}
  toast('✓ Photo supprimée');
}

