// ══════════════════════════════════════════════════════════════════
// ── MODULE CLOUD SYNC — veritas-school.com API ──────────────────
// ══════════════════════════════════════════════════════════════════

function _cloudHeaders(withContentType){
  // FIX WAF LWS 2026 : utiliser Authorization header (CORS preflight le permet maintenant)
  // Le WAF LWS Anubis bloque _secret= en URL/FormData → on bascule sur Authorization Bearer
  var h={};
  if(withContentType)h['Content-Type']='application/json';
  var secret=DB.cloudConfig&&DB.cloudConfig.secret;
  if(secret)h['Authorization']='Bearer '+secret;
  return h;
}
function _cloudUrl(endpoint){
  var base=(DB.cloudConfig?.url||'https://veritas-school.com/api').replace(/\/$/,'');
  // FIX WAF LWS 2026 : plus de _secret= dans l'URL (bloqué par WAF) — utiliser _cloudHeaders à la place
  return base+'/'+endpoint;
}

// ── Déduire la catégorie d'upload à partir du type MIME ou de l'extension ──
function _uploadCat(file){
  var mime=(file.type||'').toLowerCase();
  var name=(file.name||'').toLowerCase();
  if(mime.indexOf('image/')===0)return 'image';
  if(mime.indexOf('video/')===0)return 'video';
  if(mime.indexOf('audio/')===0)return 'audio';
  if(mime.indexOf('pdf')>=0||name.endsWith('.pdf'))return 'epreuve';
  if(name.match(/\.(html?|htm)$/))return 'ressource';
  if(name.match(/\.(zip|docx|pptx|xlsx|odt|ods)$/))return 'ressource';
  return 'ressource';
}

// ── Upload d'un fichier vers le serveur cloud ────────────────────────
// cb(url, errMsg) — url=null si échec
function _uploadToServer(file,type,refId,cb){
  var secret=DB.cloudConfig&&DB.cloudConfig.secret;
  var baseUrl=DB.cloudConfig&&DB.cloudConfig.url;
  if(!secret||!baseUrl){cb(null,'Aucune configuration cloud');return;}
  var fd=new FormData();
  fd.append('file',file);
  fd.append('type',type||'resource');
  fd.append('ref_id',refId||'x');
  toast('⬆️ Upload vers le serveur...');
  // FIX WAF LWS 2026 : Authorization header (le WAF bloque _secret= en URL/body)
  fetch(baseUrl.replace(/\/+$/,'')+'/upload_file.php',{
    method:'POST',
    headers:{'Authorization':'Bearer '+secret},
    body:fd
  })
  .then(function(r){return r.json();})
  .then(function(j){
    if(j.success&&j.url){cb(j.url,null);}
    else{cb(null,j.error||'Erreur upload serveur');}
  })
  .catch(function(err){cb(null,'Erreur réseau : '+(err.message||err));});
}

function saveCloudConfig(){
  if(!DB.cloudConfig)DB.cloudConfig={};
  var url=(_ge('cloud_url')?.value||'').trim();
  var secret=(_ge('cloud_secret')?.value||'').trim();
  if(!url){toast('⚠️ URL du serveur requise','warn');return;}
  if(!secret){toast('⚠️ Clé API requise','warn');return;}
  DB.cloudConfig.url=url;
  DB.cloudConfig.secret=secret;
  save();
  _saveCloudConfigCache(); // persiste la config pour le polling sans login
  _startBgPoll();           // démarrer le polling immédiatement
  toast('✓ Configuration cloud enregistrée');
}

function cloudTestConnection(){
  var secret=DB.cloudConfig?.secret;
  if(!secret){toast('⚠️ Configurez d\'abord la clé API dans les paramètres Cloud','warn');return;}
  toast('🔌 Test de connexion...');
  _si('cloudSyncStatus','<div class="ib ibt"><span>⏳</span><span>Connexion en cours...</span></div>');
  fetch(_cloudUrl('files.php'),{headers:_cloudHeaders()})
  .then(function(r){
    if(!r.ok)throw new Error('HTTP '+r.status);
    return r.json();
  })
  .then(function(data){
    _si('cloudSyncStatus','<div class="ib ibg"><span>✅</span><span><strong>Connexion réussie !</strong> Le serveur répond correctement. '+
      (Array.isArray(data)?data.length+' fichier(s) en ligne.':'')+'</span></div>');
    toast('✅ Connexion au cloud réussie !');
  })
  .catch(function(e){
    _si('cloudSyncStatus','<div class="ib" style="background:#FEE2E2;border:1px solid #FCA5A5;color:#DC2626"><span>❌</span><span><strong>Échec de connexion :</strong> '+_esc(e.message)+'. Vérifiez l\'URL et la clé API.</span></div>');
    toast('❌ Connexion échouée : '+e.message,'err');
  });
}

function cloudSaveDB(){
  if(!iA()){toast('Accès réservé aux administrateurs','warn');return;}
  var secret=DB.cloudConfig?.secret;
  if(!secret){toast('⚠️ Configurez la clé API dans Paramètres → Cloud','warn');return;}
  if(!confirm('Sauvegarder toutes les données vers le cloud ?\nCela remplacera la dernière sauvegarde en ligne.'))return;
  toast('☁️ Envoi des données vers le cloud...');
  _si('cloudSyncStatus','<div class="ib ibt"><span>⏳</span><span>Sauvegarde en cours... Ne fermez pas cette page.</span></div>');

  var data=JSON.parse(JSON.stringify(DB));
  var stripped=[];

  // ── Filtrer TOUTES les données binaires volumineuses ────────────────
  // 1. Vidéo d'accueil : si data URL locale (peut faire 50-100 Mo), on ne l'envoie pas
  if(data.introVideo&&data.introVideo.src&&data.introVideo.src.startsWith('data:')){
    data.introVideo._hasLocalVideo=true;  // marqueur : à restaurer manuellement
    data.introVideo._mime=data.introVideo.mime||'video/mp4';
    data.introVideo.src='';              // retiré du payload cloud
    stripped.push('vidéo d\'accueil');
  }
  // 2. Logo de l'école en base64
  var _CLOUD_LIMIT=273000; // ~200 Ko — seuil uniforme pour tous les binaires
  if(data.school&&data.school.logo&&data.school.logo.startsWith('data:')&&data.school.logo.length>_CLOUD_LIMIT){
    data.school._hasLocalLogo=true;
    data.school.logo='';
    stripped.push('logo');
  }
  // 3. Fichiers joints dans les contenus e-learning
  if(data.elearning&&data.elearning.contenus){
    data.elearning.contenus.forEach(function(c){
      if(c.fichierData&&c.fichierData.length>_CLOUD_LIMIT){c.fichierData='';if(stripped.indexOf('pièces jointes e-learning')<0)stripped.push('pièces jointes e-learning');}
    });
  }
  // 4. Fichiers dans soumissions élèves
  if(data.elearning&&data.elearning.soumissions){
    data.elearning.soumissions.forEach(function(s){if(s.fichierData&&!s.fichierUrl&&s.fichierData.length>_CLOUD_LIMIT)s.fichierData='';});
  }
  // 5. Devoirs avec fichiers
  if(data.devoirs){data.devoirs.forEach(function(d){if(d.fichierData&&!d.fichierUrl&&d.fichierData.length>_CLOUD_LIMIT)d.fichierData='';});}
  // 6. Partenaires logos
  if(data.partenaires){data.partenaires.forEach(function(p){if(p.logo&&p.logo.startsWith('data:')&&p.logo.length>_CLOUD_LIMIT){p.logo='';if(stripped.indexOf('logos partenaires')<0)stripped.push('logos partenaires');}});}
  // 7. Photos galerie en data URL (stockage local → utiliser upload serveur)
  if(data.galleryImages){data.galleryImages.forEach(function(img){if(img.src&&img.src.startsWith('data:')&&img.src.length>_CLOUD_LIMIT){img.src='';if(stripped.indexOf('photos galerie locales')<0)stripped.push('photos galerie locales');}});}
  // 8. Couvertures livres en data URL + fichiers locaux (non-URL)
  if(data.books){data.books.forEach(function(b){
    if(b.coverImg&&b.coverImg.startsWith('data:')&&b.coverImg.length>_CLOUD_LIMIT){b.coverImg='';if(stripped.indexOf('couvertures livres locales')<0)stripped.push('couvertures livres locales');}
    // Les clés localStorage (fichierKey) et binaires inline ne sont valables que sur cet appareil
    // On les retire du payload cloud ; fichierUrl (URL serveur) reste intact
    if(b.fichierKey){if(b.fichierData)b.fichierData='';b.fichierKey='';if(stripped.indexOf('fichiers manuels locaux')<0)stripped.push('fichiers manuels locaux');}
  });}

  var payload=JSON.stringify(data);
  var sizeKB=Math.round(payload.length/1024);

  // Avertissement si encore trop lourd (> 4 Mo après filtrage)
  if(sizeKB>4000){
    _si('cloudSyncStatus','<div class="ib" style="background:#FEF3C7;border:1px solid #FDE68A;color:#D97706"><span>⚠️</span><span>Données encore volumineuses après filtrage ('+sizeKB+' Ko). La sauvegarde peut échouer.</span></div>');
  }

  // Strip plain pwd avant push Firebase (garder pwdHash bcrypt)
  function _stripPlainPwdSave(o){if(!o)return;if(o.pwd&&!(typeof o.pwd==='string'&&o.pwd.startsWith('$')))delete o.pwd;}
  var _pData=JSON.parse(payload);
  if(_pData.superAdmin)_stripPlainPwdSave(_pData.superAdmin);
  (_pData.admins||[]).forEach(_stripPlainPwdSave);
  (_pData.visitorAccounts||[]).forEach(_stripPlainPwdSave);
  if(_pData.tpwd)_pData.tpwd={};
  payload=JSON.stringify(_pData);

  // FIX: PUT Firebase au lieu de POST sync.php
  _fbFetch(LWS_API.db,{
    method:'PUT',
    headers:{'Content-Type':'application/json'},
    body:payload
  })
  .then(function(r){
    if(r.status===413)throw new Error('Payload trop grand (HTTP 413) — réduisez les données (vidéos, images)');
    if(!r.ok)throw new Error('Erreur serveur HTTP '+r.status+' — Firebase indisponible ?');
    // Firebase retourne l'objet PUT — pas d'enveloppe {saved_at, size_kb}
    return {saved_at:new Date().toLocaleString('fr-FR'),size_kb:sizeKB};
  })
  .then(function(res){
    if(res.error)throw new Error(res.error);
    var dateSync=res.saved_at||new Date().toLocaleString('fr-FR');
    DB.cloudConfig.lastSync=dateSync;
    save();
    var note=stripped.length?' <span style="color:#D97706;font-size:11px">(non inclus : '+stripped.join(', ')+')</span>':'';
    var _sz=(res.size_kb||sizeKB),_dt=dateSync,_nt=note;
    _si('cloudSyncStatus','<div class="ib ibg"><span>✅</span><span><strong>Sauvegarde des données réussie !</strong> '+_sz+' Ko — '+_dt+_nt+'<br><span style="font-size:11px;opacity:.7">🔄 Vérification et upload des fichiers locaux...</span></span></div>');
    toast('✅ Données sauvegardées dans le cloud !');
    _cloudAutoUploadBinaries(function(uploaded,errors){
      var fNote=uploaded>0?' <span style="color:#059669;font-size:11px">+ '+uploaded+' fichier(s) uploadé(s) ✅</span>':'';
      if(errors>0){
        // Récupérer le détail des échecs depuis localStorage
        var failDetail='';
        try{
          var fl=JSON.parse(localStorage.getItem('_vrtUploadErrors')||'[]');
          if(fl.length)failDetail=' <span style="font-size:10px;color:#92400E;cursor:pointer" onclick="var d=JSON.parse(localStorage.getItem(\'_vrtUploadErrors\')||\'[]\');alert(\'Fichiers en échec :\\n\'+d.map(function(x){return \'• \'+x.label+\' : \'+x.reason;}).join(\'\\n\'))">⚠️ '+errors+' échec(s) — cliquez pour détails</span>';
          else failDetail=' <span style="color:#D97706;font-size:11px">⚠️ '+errors+' échec(s)</span>';
        }catch(e){failDetail=' <span style="color:#D97706;font-size:11px">⚠️ '+errors+' échec(s)</span>';}
        fNote+=failDetail;
      }
      var finalMsg=uploaded===0&&errors===0?' <span style="font-size:11px;opacity:.55">(aucun fichier local supplémentaire)</span>':fNote;
      _si('cloudSyncStatus','<div class="ib ibg"><span>✅</span><span><strong>Sauvegarde complète !</strong> '+_sz+' Ko — '+_dt+_nt+finalMsg+'</span></div>');
      if(uploaded>0){
        toast('✅ '+uploaded+' fichier(s) uploadé(s) sur le cloud !');
        // Re-push DB silently : les src des galeries sont maintenant des URLs serveur
        // → le téléphone verra les photos au prochain sync
        setTimeout(function(){_cloudSilentPushDB(function(ok){
          if(ok)_si('cloudSyncStatus','<div class="ib ibg"><span>✅</span><span><strong>Sauvegarde complète !</strong> '+_sz+' Ko — '+_dt+_nt+finalMsg+' <span style="color:#059669;font-size:11px">· DB mise à jour avec les URLs serveur ✅</span></span></div>');
        });},1200);
      }
    });
  })
  .catch(function(e){
    _si('cloudSyncStatus','<div class="ib" style="background:#FEE2E2;border:1px solid #FCA5A5;color:#DC2626"><span>❌</span><span><strong>Échec :</strong> '+_esc(e.message)+'</span></div>');
    toast('❌ Sauvegarde échouée : '+e.message,'err');
  });
}

function cloudRestoreDB(){
  if(!isSA()){toast('Accès réservé au super-administrateur','warn');return;}
  var secret=DB.cloudConfig?.secret;
  if(!secret){toast('⚠️ Configurez la clé API dans Paramètres → Cloud','warn');return;}
  if(!confirm('⚠️ ATTENTION : Cela remplacera TOUTES vos données locales par la dernière sauvegarde cloud.\n\nÊtes-vous sûr ?'))return;
  if(!confirm('Dernière confirmation : les données actuelles seront écrasées. Continuer ?'))return;
  toast('📥 Récupération des données depuis le cloud...');
  _si('cloudSyncStatus','<div class="ib ibt"><span>⏳</span><span>Restauration en cours...</span></div>');
  // FIX: GET Firebase au lieu de sync.php
  _fbFetch(LWS_API.db+'?t='+Date.now())
  .then(function(r){
    if(!r.ok)throw new Error('HTTP '+r.status);
    return r.json();
  })
  .then(function(data){
    if(!data)throw new Error('Cloud vide — aucune sauvegarde à restaurer');
    if(data.error)throw new Error(data.error);
    if(!data.school||!data.students){throw new Error('Format de données invalide');}
    // Save current config before overwriting
    var cloudCfg=DB.cloudConfig;
    DB=data;
    DB.cloudConfig=cloudCfg;
    DB.cloudConfig.lastSync=new Date().toLocaleString('fr-FR')+' (restauré)';
    save();
    _si('cloudSyncStatus','<div class="ib ibg"><span>✅</span><span><strong>Restauration réussie !</strong> '+DB.students.length+' élèves, '+DB.teachers.length+' enseignants, '+DB.grades.length+' notes chargées.</span></div>');
    toast('✅ Données restaurées depuis le cloud !');
    setTimeout(function(){re();},1000);
  })
  .catch(function(e){
    _si('cloudSyncStatus','<div class="ib" style="background:#FEE2E2;border:1px solid #FCA5A5;color:#DC2626"><span>❌</span><span><strong>Erreur :</strong> '+_esc(e.message)+'</span></div>');
    toast('❌ Échec restauration : '+e.message,'err');
  });
}

