  h+='<div class="sc scgr"><div class="sci">💰</div><div class="scl">Revenus totaux</div><div class="scv vgr">'+fmt(totalVentes)+'</div></div>';
  h+='<div class="sc scr"><div class="sci">🤝</div><div class="scl">Part auteurs</div><div class="scv vr">'+fmt(totalAuteurGains)+'</div></div>';
