  var planOptions=['plan1','plan2','plan3','plan4'];
  var planLabels={plan1:'📗 Pack EXAMEN',plan2:'📘 Pack INTERMÉDIAIRE',plan3:'📙 Pack ENSEIGNANT',plan4:'🏆 Pack FAMILLE / ÉCOLE'};
  var plansCheckboxes='<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-top:6px">';
  planOptions.forEach(function(pid){
    var checked=(item.plans||[]).indexOf(pid)>-1;
    plansCheckboxes+='<label style="display:flex;align-items:center;gap:6px;cursor:pointer;padding:6px 10px;background:var(--bg2);border-radius:8px;font-size:12px"><input type="checkbox" id="ecPlan_'+pid+'"'+(checked?' checked':'')+'>'+planLabels[pid]+'</label>';
  });
