function importEvaluationsBAC(){
  if(!iA())return;
  if(!DB.elearning)DB.elearning=defaultDB().elearning;
  if(!DB.elearning.contenus)DB.elearning.contenus=[];
  var added=0,updated=0;
  CATALOGUE_EVALS_BAC.forEach(function(ev){
    var existing=DB.elearning.contenus.find(function(c){return c.id===ev.id;});
    if(existing){
      // Mettre à jour les champs (URL, desc, etc.) sans écraser d'éventuelles modifications manuelles de titre
      existing.externalUrl=ev.externalUrl;
      existing.desc=ev.desc;
      existing.apercu=ev.apercu;
      existing.cat=ev.cat;
      existing.classe=ev.classe;
      existing.matiere=ev.matiere;
      existing.seq=ev.seq;
      existing.gratuit=true;
      updated++;
    } else {
      DB.elearning.contenus.push(Object.assign({},ev,{dateAjout:today()}));
      added++;
    }
  });
  save();re();
  var msg=(added?added+' ajoutée(s). ':'')+(updated?updated+' mise(s) à jour. ':'');
  toast('✅ Évaluations BAC : '+msg.trim(),'ok');
}

