// ── GESTION ACCÈS PAR UTILISATEUR ────────────────────────────────────────
function mGererAccesContenu(itemId){
  if(!iA())return;
  var el=DB.elearning||{contenus:[]};
  var item=(el.contenus||[]).find(function(c){return c.id===itemId;});
  if(!item)return;
  var accs=DB.visitorAccounts||[];
  if(!accs.length){M('👥 Gestion des accès','Aucun compte visiteur enregistré.','<p style="color:var(--ink3);font-size:13px">Aucun compte visiteur inscrit pour le moment.</p>','<button class="btn bo" onclick="cm()">Fermer</button>');return;}
  if(!item.unlockedFor)item.unlockedFor=[];
  if(!item.blockedFor)item.blockedFor=[];
  var rows='';
  accs.forEach(function(acc){
    var isUnlocked=item.unlockedFor.indexOf(acc.id)>=0;
    var isBlocked=item.blockedFor.indexOf(acc.id)>=0;
    var hasPlan=acc.plans&&acc.plans.length&&item.plans&&item.plans.some(function(p){return acc.plans.indexOf(p)>=0;});
    var status=isBlocked?'<span style="background:#FEE2E2;color:#DC2626;font-size:10px;font-weight:700;padding:2px 8px;border-radius:6px">🔒 Bloqué</span>':isUnlocked?'<span style="background:#D1FAE5;color:#059669;font-size:10px;font-weight:700;padding:2px 8px;border-radius:6px">🔓 Débloqué</span>':hasPlan?'<span style="background:#E0EAFF;color:#3C8DFF;font-size:10px;font-weight:700;padding:2px 8px;border-radius:6px">✅ Via plan</span>':'<span style="background:#F3F4F6;color:#6B7280;font-size:10px;font-weight:700;padding:2px 8px;border-radius:6px">— Aucun accès</span>';
    rows+='<tr>'
      +'<td class="semi s">'+_esc(acc.pre)+' '+_esc(acc.nom)+'</td>'
      +'<td class="xs2 mut">'+_esc(acc.email||acc.tel||'')+'</td>'
      +'<td>'+status+'</td>'
      +'<td><div class="fl2 g4">'
      +(isBlocked
        ?'<button class="btn bgg xs" onclick="toggleAccesContenu(\''+itemId+'\',\''+acc.id+'\',\'unblock\')">🔓 Rétablir</button>'
        :isUnlocked
          ?'<button class="btn br2 xs" onclick="toggleAccesContenu(\''+itemId+'\',\''+acc.id+'\',\'block\')">🔒 Bloquer</button>'
            +'<button class="btn bo xs" onclick="toggleAccesContenu(\''+itemId+'\',\''+acc.id+'\',\'remove_unlock\')">✕ Retirer</button>'
          :'<button class="btn bgg xs" onclick="toggleAccesContenu(\''+itemId+'\',\''+acc.id+'\',\'unlock\')">🔓 Débloquer</button>'
            +'<button class="btn br2 xs" onclick="toggleAccesContenu(\''+itemId+'\',\''+acc.id+'\',\'block\')">🔒 Bloquer</button>'
      )
      +'</div></td>'
      +'</tr>';
  });
  M('👥 Accès : '+item.titre,'Gérer l\'accès individuel par utilisateur',
    '<div class="ib ibt mb14"><span>ℹ️</span><span><b>Débloquer</b> = accès sans abonnement. <b>Bloquer</b> = refus même avec un plan actif.</span></div>'
    +'<div class="tw"><table><thead><tr><th>Visiteur</th><th>Contact</th><th>Statut</th><th>Actions</th></tr></thead><tbody>'+rows+'</tbody></table></div>',
    '<button class="btn bo" onclick="cm()">Fermer</button>',true);
}

function toggleAccesContenu(itemId,accId,action){
  var el=DB.elearning||{contenus:[]};
  var item=(el.contenus||[]).find(function(c){return c.id===itemId;});
  if(!item)return;
  if(!item.unlockedFor)item.unlockedFor=[];
  if(!item.blockedFor)item.blockedFor=[];
  if(action==='unlock'){
    if(item.unlockedFor.indexOf(accId)<0)item.unlockedFor.push(accId);
    item.blockedFor=item.blockedFor.filter(function(id){return id!==accId;});
    toast('✅ Accès accordé');
  } else if(action==='block'){
    if(item.blockedFor.indexOf(accId)<0)item.blockedFor.push(accId);
    item.unlockedFor=item.unlockedFor.filter(function(id){return id!==accId;});
    toast('🔒 Accès bloqué');
  } else if(action==='remove_unlock'){
    item.unlockedFor=item.unlockedFor.filter(function(id){return id!==accId;});
    toast('Accès individuel retiré');
  } else if(action==='unblock'){
    item.blockedFor=item.blockedFor.filter(function(id){return id!==accId;});
    toast('🔓 Blocage levé');
  }
  save();
  // Re-ouvrir la modale avec les données à jour
  mGererAccesContenu(itemId);
}

function refuserSoumission(id){
  var sub=(DB.elearning.soumissions||[]).find(function(s){return s.id===id;});
  if(sub){sub.statut='Refusé';save();re();toast('Soumission refusée');}
}

function changeAboPlan(id){
  var abo=(DB.elearning.abonnements||[]).find(function(a){return a.id===id;});
  if(!abo)return;
  var plans=DB.elearning.plans||[];
  M('✏️ Modifier l\'abonnement','Changer le plan de '+abo.nom,
  '<div class="fg"><span class="fl">Plan actuel: <strong>'+abo.plan+'</strong></span></div>'+
  '<div class="fg"><span class="fl">Nouveau plan *</span><select class="fi" id="newPlan">'+plans.map(function(p){return '<option value="'+p.id+'"'+(p.id===abo.plan?' selected':'')+'>'+p.nom+' — '+fmtN(p.prix)+' XAF</option>';}).join('')+'</select></div>'+
  '<div class="fg"><span class="fl">Statut</span><select class="fi" id="newStatut"><option'+(abo.statut==='Activé'?' selected':'')+'>Activé</option><option'+(abo.statut==='En attente'?' selected':'')+'>En attente</option><option>Expiré</option></select></div>',
  '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveAboPlan(\''+id+'\')">✓ Enregistrer</button>');
}
function saveAboPlan(id){
  var abo=(DB.elearning.abonnements||[]).find(function(a){return a.id===id;});
  if(!abo)return;
  abo.plan=document.getElementById('newPlan')?.value||abo.plan;
  abo.statut=document.getElementById('newStatut')?.value||abo.statut;
  save();cm();re();toast('✓ Abonnement mis à jour');
}
function deleteAbo(id){
  if(!confirm('Supprimer cet abonnement ?'))return;
  DB.elearning.abonnements=(DB.elearning.abonnements||[]).filter(function(a){return a.id!==id;});
  save();re();toast('Abonnement supprimé');
}

function activerAbonnement(id){
  var abo=(DB.elearning&&DB.elearning.abonnements||[]).find(function(a){return a.id===id;});
  if(!abo){toast('Abonnement introuvable','warn');return;}
  abo.statut='Activé';
  abo.dateActivation=today();
  // v1.2.2 (bug #3) : paiement validé → confirmer la commission partenaire liée
  try{ if(typeof confirmCommissionsForSale==='function') confirmCommissionsForSale('elearning', abo.plan); }catch(e){}

  // ── Retrouver le compte visiteur lié (via accountId ou normalisation du tel) ──
  var acc=null;
  if(abo.accountId){
    acc=(DB.visitorAccounts||[]).find(function(a){return a.id===abo.accountId;});
  }
  if(!acc&&abo.tel){
    var normT=function(t){return(t||'').replace(/[\s\-\(\)\+]/g,'').replace(/^237/,'');};
    var tAbo=normT(abo.tel);
    acc=(DB.visitorAccounts||[]).find(function(a){return normT(a.tel)===tAbo;});
  }

  // ── Mettre à jour acc.plans pour que _waGroupAccess fonctionne immédiatement ──
  if(acc){
    if(!acc.plans)acc.plans=[];
    if(acc.plans.indexOf(abo.plan)<0)acc.plans.push(abo.plan);
    abo.accountId=acc.id; // rétro-lier si pas encore fait
    acc.statut='actif';
    acc.groupeStatut=acc.groupeStatut||'en_attente';
  }

  save();re();
  toast('✓ Abonnement activé'+(acc?' — compte '+acc.pre+' mis à jour':''));

  // ── Proposer l'invitation WhatsApp immédiatement ──
  if(acc){
    var grp=(DB.whatsappGroupes||[]).find(function(g){
      return g.actif&&(g.niveau===acc.cls||g.niveau==='tous');
    });
    var planObj=(DB.elearning&&DB.elearning.plans||[]).find(function(p){return p.id===abo.plan;});
    var planNom=planObj?planObj.nom:abo.plan;
    M('✅ Abonnement activé','Plan : '+_esc(planNom),
      '<div class="ib ibg mb12"><span>✓</span><span><b>'+_esc(acc.pre+' '+acc.nom)+'</b> · '+_esc(acc.cls)+'<br>Abonnement <b>'+_esc(planNom)+'</b> ajouté au compte.</span></div>'
      +'<div class="fg mb8"><span class="fl">📱 WhatsApp</span><div style="font-size:13px;color:var(--ink2)">'+_esc(acc.tel||'non renseigné')+'</div></div>'
      +(grp
        ? '<div class="ib ibg mb8"><span>📲</span><span>Groupe disponible : <b>'+_esc(grp.nom)+'</b></span></div>'
        : '<div class="ib" style="background:#FEF9C3;border-color:#CA8A04"><span>⚠️</span><span>Aucun groupe WhatsApp actif pour la classe <b>'+_esc(acc.cls)+'</b>. Configurez un groupe dans Gestion → Groupes WhatsApp.</span></div>'),
      '<button class="btn bo" onclick="cm()">Plus tard</button>'
      +(grp&&acc.tel
        ? '<button class="btn bi" onclick="cm();_sendWAGroupInvite(\''+acc.id+'\')">📲 Envoyer invitation WhatsApp</button>'
        : ''));
  }
}

function pgBoutiqueMgmt(){
  if(!iA())return na();
  var prods=DB.products||[];
  var cats=[...new Set(prods.map(function(p){return p.cat||'Autre';}))];
  var h='<div class="fl2 fic fsb mb16 fw g8"><div class="bold" style="font-size:18px">🛍️ Gestion de la Boutique</div>';
  h+='<button class="btn bi" onclick="mAddProduct()">＋ Ajouter un produit</button></div>';
  // Stats
  h+='<div class="sg">';
  h+='<div class="sc scb"><div class="sci">📦</div><div class="scl">Produits actifs</div><div class="scv vb">'+prods.filter(function(p){return p.actif;}).length+'</div></div>';
  h+='<div class="sc scg"><div class="sci">🏷️</div><div class="scl">Catégories</div><div class="scv vg">'+cats.length+'</div></div>';
  h+='<div class="sc scgr"><div class="sci">🛒</div><div class="scl">Commandes</div><div class="scv vgr">'+(DB.visitorOrders||[]).length+'</div></div>';
  h+='</div>';
  // Products table
  h+='<div class="card"><div class="ct">📦 Tous les produits et services</div>';
  h+='<div class="tw"><table><thead><tr><th>Photo</th><th>Produit</th><th>Catégorie</th><th>Ancien prix</th><th>Nouveau prix</th><th>Réduction</th><th>Statut</th><th>Actions</th></tr></thead><tbody>';
  prods.forEach(function(p){
    var pct=p.ancien?Math.round((1-p.prix/p.ancien)*100):0;
    h+='<tr><td>'+(p.photo?'<img src="'+p.photo+'" style="width:40px;height:40px;border-radius:8px;object-fit:cover">':'<span style="font-size:24px">'+p.ico+'</span>')+'</td>';
    h+='<td><div class="semi">'+p.titre+(p.featured?' <span style="background:#FFC93C;color:#142554;padding:1px 6px;border-radius:8px;font-size:10px;font-weight:700;margin-left:4px">⭐ EN AVANT</span>':'')+(p.nouveau?' <span style="background:#DC2626;color:#fff;padding:1px 6px;border-radius:8px;font-size:10px;font-weight:700;margin-left:4px">🆕 NEW</span>':'')+'</div><div class="xs2 mut">'+p.desc.substring(0,50)+'...</div></td>';
    h+='<td><span class="bg bgb">'+(p.cat||'—')+'</span></td>';
    h+='<td class="mono" style="color:var(--re);text-decoration:line-through">'+(p.ancien?fmt(p.ancien):'—')+'</td>';
    h+='<td class="mono bold" style="color:var(--gold)">'+fmt(p.prix)+'</td>';
    h+='<td>'+(pct?'<span class="bg bgr">-'+pct+'%</span>':'—')+'</td>';
    h+='<td><span class="bg '+(p.actif?'bgg':'bgr')+'">'+(p.actif?'Actif':'Inactif')+'</span></td>';
    h+='<td><div class="fl2 g4"><button class="btn bo xs" onclick="mEditProduct(\''+p.id+'\')">✏️</button><button class="btn '+(p.actif?'br2':'bgr2')+' xs" onclick="toggleProduct(\''+p.id+'\')">'+(p.actif?'⏸':'▶')+'</button><button class="btn br2 xs" onclick="deleteProduct(\''+p.id+'\')">🗑</button></div></td></tr>';
  });
  h+='</tbody></table></div></div>';
  return h;
}
