function loadProductPhoto(input){
  if(!input.files||!input.files[0])return;
  var reader=new FileReader();
  reader.onload=function(e){
    document.getElementById('pdPhoto').value=e.target.result;
    _si('pdPreview','<img src="'+e.target.result+'" style="width:80px;height:80px;border-radius:10px;object-fit:cover">');
  };
  reader.readAsDataURL(input.files[0]);
}

