function openPictoPicker(targetInputId){
  var lib=window._PICTO_LIB||[];
  var base='https://em-content.zobj.net/source/microsoft-3D-fluent/406/';
  var tagsSet={}; lib.forEach(function(p){tagsSet[p.tag]=true;});
  var tags=['all'].concat(Object.keys(tagsSet));
  var tagLabels={all:'Tout',education:'🎓 École',books:'📚 Livres',tools:'✏️ Outils',media:'📱 Média',sciences:'🔬 Sciences',awards:'🏆 Récompenses',money:'💳 Argent',fun:'🎮 Jeux',comm:'💬 Comm',top:'🔥 Top',time:'📅 Temps'};

  var tabsHtml='<div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:10px">';
  tags.forEach(function(t){
    tabsHtml+='<button type="button" class="vpicker-tab" data-tag="'+t+'" onclick="_pickerFilter(\''+t+'\')" style="padding:5px 12px;border-radius:14px;border:1px solid #E2E8F0;background:'+(t==='all'?'#142554':'#F8FAFC')+';color:'+(t==='all'?'#fff':'#475569')+';font-size:11px;font-weight:700;cursor:pointer">'+_esc(tagLabels[t]||t)+'</button>';
  });
  tabsHtml+='</div>';

  var gridHtml='<div class="vpicker-grid" id="vpickerGrid">';
  lib.forEach(function(p){
    var url=base+p.file;
    gridHtml+='<div class="vpicker-item" data-tag="'+p.tag+'" data-url="'+url+'" onclick="_pickerSelect(\''+targetInputId+'\',\''+url+'\',this)" title="'+_esc(p.label)+'"><img src="'+url+'" alt="" loading="lazy"></div>';
  });
  gridHtml+='</div>';

  M('🎨 Choisir un picto 3D HD','Cliquez pour sélectionner',
    '<input class="vpicker-search" placeholder="🔍 Rechercher (ex: livre, cœur, fusée...)" oninput="_pickerSearch(this.value)">'+
    tabsHtml+
    gridHtml,
    '<button class="btn bo" onclick="cm()">Annuler</button>',
    true);
}

function _pickerFilter(tag){
  document.querySelectorAll('.vpicker-tab').forEach(function(b){
    var active=b.getAttribute('data-tag')===tag;
    b.style.background=active?'#142554':'#F8FAFC';
    b.style.color=active?'#fff':'#475569';
  });
  document.querySelectorAll('.vpicker-item').forEach(function(i){
    if(tag==='all'||i.getAttribute('data-tag')===tag){i.style.display='flex';}else{i.style.display='none';}
  });
}

function _pickerSearch(q){
  q=(q||'').toLowerCase().trim();
  if(!q){_pickerFilter('all');return;}
  document.querySelectorAll('.vpicker-item').forEach(function(i){
    var title=(i.getAttribute('title')||'').toLowerCase();
    var url=(i.getAttribute('data-url')||'').toLowerCase();
    i.style.display=(title.indexOf(q)>=0||url.indexOf(q)>=0)?'flex':'none';
  });
}

