function updateProduct(pid){
  var p=(DB.products||[]).find(function(x){return x.id===pid;});if(!p)return;
  p.titre=document.getElementById('pdTitre')?.value||p.titre;
  p.prix=parseInt(document.getElementById('pdPrix')?.value)||p.prix;
  p.ancien=parseInt(document.getElementById('pdAncien')?.value)||0;
  p.desc=document.getElementById('pdDesc')?.value||'';
  p.cat=document.getElementById('pdCat')?.value||'Autre';
  p.ico=document.getElementById('pdIco')?.value||p.ico;
  var newPhoto=document.getElementById('pdPhoto')?.value;
  if(newPhoto)p.photo=newPhoto;
  p.pictoUrl=(document.getElementById('pdPictoUrl')?.value||'').trim();
  p.bgColor=(document.getElementById('pdBgColor')?.value||'');
  p.featured=!!document.getElementById('pdFeatured')?.checked;
  p.nouveau=!!document.getElementById('pdNouveau')?.checked;
  save();cm();re();toast('✓ Produit mis à jour');
}
function toggleProduct(pid){var p=(DB.products||[]).find(function(x){return x.id===pid;});if(p){p.actif=!p.actif;save();re();toast(p.actif?'Produit activé':'Produit désactivé');}}
function deleteProduct(pid){
  if(!confirm('Supprimer ce produit ?'))return;
  DB.products=(DB.products||[]).filter(function(x){return x.id!==pid;});
  // FIX : marquer dans tombstone pour eviter resurrection apres sync cloud
  DB.deletedProducts=DB.deletedProducts||[];
  if(DB.deletedProducts.indexOf(pid)<0)DB.deletedProducts.push(pid);
  save();re();
  // Forcer le push cloud immédiat pour que les visiteurs voient la suppression
  if(typeof _triggerAutoSync==='function')_triggerAutoSync();
  toast('✓ Produit supprimé — synchronisation en cours…');
}

// FIX : filtre des produits supprimes a chaque rendu/load
// Appele dans _migrateDB et a chaque acces a DB.products
function _filterDeletedProducts(){
  if(!DB.deletedProducts||!DB.deletedProducts.length)return;
  var tombstones={};
  DB.deletedProducts.forEach(function(id){tombstones[id]=true;});
  DB.products=(DB.products||[]).filter(function(p){return !tombstones[p.id];});
}


// (pgSubmitResource v1 supprimée)


function submitResource(){
  var titre=(document.getElementById('srTitre')?.value||'').trim();
  if(!titre){toast('Titre requis','warn');return;}
  toast('Enregistrement en cours...');
  var t=isEnseignant()?T(SES.tid):null;
  var fileInput=document.getElementById('srFile');
  var fileName='';
  var fileData='';
  if(fileInput&&fileInput.files&&fileInput.files[0]){
    fileName=fileInput.files[0].name;
    var reader=new FileReader();
    reader.onload=function(e){
      fileData=e.target.result;
      doSubmit(titre,fileName,fileData,t);
    };
    reader.readAsDataURL(fileInput.files[0]);
  } else {
    doSubmit(titre,'','',t);
  }
}

function doSubmit(titre,fileName,fileData,t){
  if(!DB.elearning.soumissions) DB.elearning.soumissions=[];
  DB.elearning.soumissions.push({
    id:gid(),titre:titre,
    cat:document.getElementById('srType')?.value||'cat1',
    classe:document.getElementById('srCls')?.value||'',
    matiere:document.getElementById('srMat')?.value||'',
    seq:document.getElementById('srSeq')?.value||'',
    prix:parseInt(document.getElementById('srPrix')?.value)||500,
    desc:document.getElementById('srDesc')?.value||'',
    fichier:fileName,fichierData:fileData,
    enseignant:t?t.id:'',enseignantNom:t?(t.pre+' '+t.nom):'Admin',
    date:today(),statut:'En attente'
  });
  save();re();toast('✓ Ressource soumise pour validation !');
}

