function consulterGratuit(itemId){
  var el=DB.elearning||defaultDB().elearning;
  var item=(el.contenus||[]).find(function(c){return c.id===itemId;});
  if(!item){toast('Ressource introuvable','warn');return;}

  // Ressources pédagogiques interactives (HTML embarqué)
  if(item.resPedago && typeof _RESSOURCES_PEDAGO!=='undefined' && _RESSOURCES_PEDAGO[item.resPedago]){
    lancerRessourcePedago(item.resPedago, false); return;
  }

  // Admin → accès total
  if(iA()){ viewResource(item, 'admin'); return; }

  // Vérifier abonnement visiteur
  var accId=SES&&SES.accountId;
  var visAcc=accId?(DB.visitorAccounts||[]).find(function(a){return a.id===accId;}):null;
  var vPlans=visAcc?visAcc.plans||[]:[];
  var hasPlanAccess=item.plans&&item.plans.length&&item.plans.some(function(p){return vPlans.indexOf(p)>=0;});
  var isFree=item.gratuit||false;

  if(hasPlanAccess){
    // Abonné → accès complet avec filigrane
    viewResource(item,'subscribed'); return;
  }

  if(!isFree){
    // Pas d'abonnement et contenu payant
    toast('&#128274; Abonnement requis pour accéder à ce contenu','warn');
    var elPlans=document.getElementById('elPlans');
    if(elPlans) elPlans.scrollIntoView({behavior:'smooth'});
    return;
  }

  // Contenu gratuit → limite 3 consultations/jour par contenu
  var dlKey='dlg_'+itemId+'_'+new Date().toDateString();
  var used=parseInt(localStorage.getItem(dlKey)||'0');
  var limit=3;
  if(used>=limit){
    toast('Limite de consultations gratuites atteinte ('+limit+'/jour). Abonnez-vous pour un accès illimité !','warn');
    var elPlans2=document.getElementById('elPlans');
    if(elPlans2) elPlans2.scrollIntoView({behavior:'smooth'});
    return;
  }
  localStorage.setItem(dlKey,String(used+1));

  // Contenu HTML embarqué → ouvrir avec filigrane VÉRITAS
  if(item.htmlContent){_openHtmlWithWatermark(item.htmlContent,item.titre,null);return;}
  // Fichier uploadé sur serveur → viewer avec filigrane
  if(item.fichierUrl){
    var isPdfUrl=(item.fichierUrl.toLowerCase().indexOf('.pdf')>-1)||((item.fichierType||'').indexOf('pdf')>-1);
    if(isPdfUrl){_showPDFViewer(item.fichierUrl,item.titre,false);return;}
    _openHtmlWithWatermark(null,item.titre,item.fichierUrl);return;
  }
  if(!item.dlCount) item.dlCount=0;
  item.dlCount++;
  save();
  viewResource(item,'free',used+1,limit);
}

