function viewResource(item, accessMode, dlUsedToday, dlLimitToday){
  var isFree=accessMode==='free'||accessMode===true;
  var isAdmin=accessMode==='admin'||iA();
  var isSubscribed=accessMode==='subscribed';
  var cat=(DB.elearning&&DB.elearning.categories||[]).find(function(c){return c.id===item.cat;})||{ico:'📄',nom:'Autre'};
  var dlKey='dl_'+item.id+'_'+new Date().toDateString();
  var todayCount=parseInt(localStorage.getItem(dlKey)||'0');
  var dlLimit=3;
  
  function buildViewer(dataUrl, fname, ftype){
    var ext=(fname||item.fichier||'').split('.').pop().toLowerCase();
    var isVid=['mp4','mov','avi','mkv','webm','ogg'].includes(ext);
    var isPdf=ext==='pdf';
    var isImg=['jpg','jpeg','png','gif','webp'].includes(ext);
    var isAud=['mp3','m4a','wav'].includes(ext);
    var isWord=['doc','docx'].includes(ext);
    var isPpt=['ppt','pptx'].includes(ext);
    var isXls=['xls','xlsx'].includes(ext);
    var isHtml=ext==='html'||item.fileType==='html';

    var viewer='';
    if(isVid){
      viewer='<div style="background:#000;border-radius:12px;overflow:hidden;margin-bottom:10px">'+
        '<video controls '+(isFree?'':'controlsList="nodownload" disablePictureInPicture')+
        ' style="width:100%;max-height:380px;display:block" oncontextmenu="return false">'+
        '<source src="'+dataUrl+'" type="'+(ftype||'video/mp4')+'"></video></div>';
    } else if(isPdf){
      var _isMobView=/Mobi|Android|iPhone|iPad/i.test(navigator.userAgent||'');
      if(_isMobView){
        // Mobile : <embed> navigue hors du SPA → afficher un bouton blob URL
        var _bvBlobUrl='';
        try{
          if(dataUrl.startsWith('data:')){
            var _bva=dataUrl.split(','),_bvm=(_bva[0].match(/:(.*?);/)||['','application/pdf'])[1];
            var _bvs=atob(_bva[1]),_bvn=_bvs.length,_bvu=new Uint8Array(_bvn);
            while(_bvn--)_bvu[_bvn]=_bvs.charCodeAt(_bvn);
            _bvBlobUrl=URL.createObjectURL(new Blob([_bvu],{type:_bvm}));
            setTimeout(function(){URL.revokeObjectURL(_bvBlobUrl);},60000);
          }else{_bvBlobUrl=dataUrl;}
        }catch(_bve){_bvBlobUrl=dataUrl;}
        viewer='<div style="text-align:center;padding:28px 16px;background:var(--bg2);border-radius:12px;margin-bottom:10px">'
          +'<div style="font-size:56px;margin-bottom:12px">📄</div>'
          +'<div style="font-size:14px;font-weight:700;color:var(--bl);margin-bottom:18px">'+_esc(fname)+'</div>'
          +'<button class="btn bi" style="font-size:15px;padding:14px 28px;width:100%;max-width:280px;cursor:pointer" onclick="window.open(\''+_bvBlobUrl+'\',\'_blank\')">📖 Ouvrir le PDF</button>'
          +'</div>';
      } else {
        viewer='<div style="border-radius:12px;overflow:hidden;border:1px solid var(--bg3);margin-bottom:10px">'+
          '<embed src="'+dataUrl+'#toolbar='+(isFree?'1':'0')+'&navpanes=0&scrollbar=1" type="application/pdf" '+
          'style="width:100%;height:480px;border:none" oncontextmenu="return false"></div>';
      }
    } else if(isImg){
      viewer='<img src="'+dataUrl+'" oncontextmenu="return false" draggable="false" '+
        'style="max-width:100%;max-height:380px;border-radius:12px;display:block;margin:0 auto 10px">';
    } else if(isAud){
      viewer='<audio controls '+(isFree?'':'controlsList="nodownload"')+
        ' style="width:100%;margin:10px 0"><source src="'+dataUrl+'"></audio>';
    } else if(isWord||isPpt||isXls){
      // Embed Office files via Office Online viewer (if URL) or just show download
      viewer='<div style="background:var(--bg2);border-radius:12px;padding:30px;text-align:center;margin-bottom:10px">'+
        '<div style="font-size:48px;margin-bottom:12px">'+(isWord?'📝':isPpt?'📊':'📈')+'</div>'+
        '<div style="font-size:13px;color:var(--ink3);margin-bottom:12px">Fichier '+ext.toUpperCase()+' — '+fname+'</div>'+
        '<div style="font-size:11px;color:var(--ink4)">Téléchargez pour ouvrir dans votre application Office</div></div>';
    } else if(isHtml){
      // HTML interactif : ouvrir dans un nouvel onglet via Blob URL
      if(dataUrl&&dataUrl.indexOf('data:')===0){
        var blob=new Blob([atob(dataUrl.split(',')[1])],{type:'text/html'});
        // Always inject watermark into HTML content
        _openHtmlWithWatermark(atob(dataUrl.split(',')[1]), item.titre, null);
        cm();
        return;
      }
      viewer='<div style="background:var(--bg2);border-radius:12px;padding:30px;text-align:center;margin-bottom:10px">'+
        '<div style="font-size:48px;margin-bottom:12px">🌐</div>'+
        '<div style="font-size:13px;color:var(--ink3)">Contenu HTML interactif — '+_esc(fname)+'</div></div>';
    } else {
      viewer='<div style="background:var(--bg2);border-radius:12px;padding:30px;text-align:center;margin-bottom:10px">'+
        '<div style="font-size:48px;margin-bottom:12px">📄</div>'+
        '<div style="font-size:13px;color:var(--ink3)">'+fname+'</div></div>';
    }

    var apercuHtml=item.apercu?
      '<div style="background:linear-gradient(135deg,#E0EAFF,#EDE9FE);border-radius:10px;padding:12px 14px;margin-bottom:12px;font-family:Georgia,serif;font-size:13px;color:#142554;line-height:1.7">'+
      '<div style="font-size:10px;font-weight:800;color:#7C3AED;text-transform:uppercase;letter-spacing:1px;margin-bottom:6px">📋 Aperçu du contenu</div>'+item.apercu+'</div>':'';

    var counterHtml='';
  var _cnt=dlUsedToday||todayCount;
  var _lim=dlLimitToday||dlLimit;
  if(isFree&&_cnt>0){
    counterHtml='<div style="background:#FEF3C7;border:1px solid #FCD34D;border-radius:8px;padding:7px 12px;font-size:11px;color:#92400E;margin-bottom:10px">&#128202; '+_cnt+' consultation'+(_cnt>1?'s':'')+' sur '+_lim+' gratuites aujourd\'hui</div>';
  } else if(isSubscribed){
    counterHtml='<div style="background:#D1FAE5;border:1px solid #6EE7B7;border-radius:8px;padding:7px 12px;font-size:11px;color:#065F46;margin-bottom:10px">&#9989; Inclus dans votre abonnement</div>';
  }

    var dlBtn='';
    if(isAdmin){
      // Admin : téléchargement direct via data-* (pas de quoting inline)
      dlBtn='<button class="btn bi sm" data-durl="'+encodeURIComponent(dataUrl)+'" data-dfname="'+encodeURIComponent(fname)+'" onclick="_dlFile(this)">&#11015; Télécharger (admin)</button>';
    } else if(isPdf){
      // PDF : pas de téléchargement direct (filigrane non injectable sur binaire)
      dlBtn='<span style="font-size:10px;color:var(--ink4);padding:4px 8px">&#128274; PDF protégé &mdash; consultation uniquement</span>';
    } else if(isWord||isPpt||isXls){
      // Word/PPT/XLS : wrapper HTML filigrane via data-attributes
      dlBtn='<button class="btn bi sm"'
        +' data-durl="'+encodeURIComponent(dataUrl)+'"'
        +' data-dtitle="'+encodeURIComponent(item.titre||'')+'"'
        +' data-dmat="'+encodeURIComponent(item.matiere||'')+'"'
        +' onclick="_dlBtnWord(this)">&#11015; T&eacute;l&eacute;charger (filigrane)</button>';
    } else if(isSubscribed||isFree){
      if(isHtml){
        // HTML interactif : téléchargement avec filigrane injecté
        dlBtn='<button class="btn bi sm"'
          +' data-durl="'+encodeURIComponent(dataUrl)+'"'
          +' data-dtitle="'+encodeURIComponent(item.titre||'')+'"'
          +' onclick="_dlBtnHtml(this)">&#11015; T&eacute;l&eacute;charger (filigrane)</button>';
      } else {
        dlBtn='<button class="btn bi sm" data-durl="'+encodeURIComponent(dataUrl)+'" data-dfname="'+encodeURIComponent(fname)+'" onclick="_dlFile(this)">&#11015; T&eacute;l&eacute;charger</button>';
      }
    }

    M('📖 '+item.titre, cat.ico+' '+cat.nom+(item.classe?' · '+item.classe:''),
      counterHtml+apercuHtml+viewer,
      '<button class="btn bo" onclick="cm()">Fermer</button>'+dlBtn);
  }

  if(item.fichierData&&item.fichierData.length>100){
    buildViewer(item.fichierData, item.fichier||item.titre, item.fileType);
  } else if(item.idbKey){
    idbGetFile(item.idbKey, function(rec){
      if(!rec){toast('Fichier introuvable. Il a peut-être été supprimé.','warn');return;}
      buildViewer(rec.data, rec.name||item.fichier, rec.type||item.fileType);
    });
  } else {
    // No file attached - show description
    M('📖 '+item.titre, cat.ico+' '+cat.nom,
      (item.apercu?'<div style="font-family:Georgia,serif;font-size:13px;line-height:1.8;color:var(--ink2);padding:8px 0">'+item.apercu+'</div>':
       item.desc?'<div style="font-size:13px;line-height:1.8;color:var(--ink3)">'+item.desc+'</div>':
       '<div class="ib ibt">📎 Aucun fichier attaché à cette ressource.</div>'),
      '<button class="btn bo" onclick="cm()">Fermer</button>');
  }
}


function _dlHtmlWatermarked(htmlContent,titre){
  var school=DB.school||{};
  var schoolNom=school.nom||'VÉRITAS Academy';
  var banner='<div style="background:#142554;color:#FFC93C;text-align:center;padding:7px;font-size:11px;font-weight:700;letter-spacing:.5px">&#127891; '+_esc(schoolNom)+' · Usage pédagogique uniquement</div>'
    +'<style>body::after{content:"VÉRITAS";position:fixed;top:50%;left:50%;transform:translate(-50%,-50%) rotate(-40deg);font-size:clamp(50px,12vw,100px);color:rgba(20,37,84,0.07);font-weight:900;pointer-events:none;z-index:2147483646;white-space:nowrap;letter-spacing:14px;font-family:Arial,sans-serif;}</style>';
  var injected=htmlContent||'';
  var bm=/<body([^>]*)>/i.exec(injected);
  if(bm) injected=injected.replace(bm[0],bm[0]+banner);
  else injected='<!DOCTYPE html><html><head><meta charset="utf-8"></head><body>'+banner+injected+'</body></html>';
  var blob=new Blob([injected],{type:'text/html'});
  var a=document.createElement('a');
  a.href=URL.createObjectURL(blob);
  a.download=(titre||'ressource').replace(/[^a-z0-9]/gi,'_')+'_VERITAS.html';
  document.body.appendChild(a);a.click();document.body.removeChild(a);
  toast('&#11015; Fichier téléchargé avec filigrane');
}
function _dlBtnWord(btn){
  // Lit les data-attributes et construit un wrapper Word avec filigrane
  var dataUrl=decodeURIComponent(btn.dataset.durl||'');
  var ep={titre:decodeURIComponent(btn.dataset.dtitle||''),exam:'',serie:'',matiere:decodeURIComponent(btn.dataset.dmat||'')};
  if(!dataUrl){toast('Fichier non disponible','warn');return;}
  _downloadWordWithWatermark(dataUrl,ep);
}
function _dlBtnHtml(btn){
  // Lit les data-attributes et télécharge le HTML avec filigrane injecté
  var dataUrl=decodeURIComponent(btn.dataset.durl||'');
  var titre=decodeURIComponent(btn.dataset.dtitle||'Ressource');
  if(!dataUrl){toast('Fichier non disponible','warn');return;}
  // Si c'est déjà du texte HTML (pas un data URL), télécharger directement
  if(dataUrl.indexOf('data:text/html')===0){
    try{
      var html=atob(dataUrl.split(',')[1]);
      _dlHtmlWatermarked(html,titre);
      return;
    }catch(e){}
  }
  _dlHtmlWatermarked(dataUrl,titre);
}
function _dlFile(btn){
  var url=decodeURIComponent(btn.dataset.durl||'');
  var name=decodeURIComponent(btn.dataset.dfname||'file');
  if(!url){toast('Fichier non disponible','warn');return;}
  var a=document.createElement('a');a.href=url;a.download=name;a.click();
}

function filterElContents(){
  var q=(document.getElementById('elSearch')?.value||'').toLowerCase();
  document.querySelectorAll('.elItem').forEach(function(el){
    if(el)el.style.display=el.getAttribute('data-titre').includes(q)?'':'none';
  });
}

