function validerAbonnement(planId){
  var nom=(document.getElementById('elNom')?.value||'').trim();
  var tel=(document.getElementById('elTel')?.value||'').trim();
  if(!nom||!tel){toast('Nom et WhatsApp requis','warn');return;}
  if(!DB.elearning) DB.elearning={plans:[],categories:[],contenus:[],abonnements:[],commandes:[]};
  if(!DB.elearning.abonnements) DB.elearning.abonnements=[];
  var plan=(DB.elearning.plans||[]).find(function(p){return p.id===planId;});
  var newAbo={
    id:gid(),plan:planId,nom:nom,tel:tel,
    classe:document.getElementById('elClasse')?.value||SES?.cls||'',
    email:document.getElementById('elEmail')?.value||SES?.email||'',
    date:today(),statut:'En attente',
    // Lien vers le compte visiteur si connecté — nécessaire pour activation automatique
    accountId: SES && (SES.type==='visiteur'||SES.type==='visiteur_inscrit') ? (SES.id||SES.accountId||'') : '',
    payRef: '' // sera renseigné lors du paiement
  };
  DB.elearning.abonnements.push(newAbo);
  // ── PROGRAMME PARTENARIAT v1 : tracking commission si code parrainage utilisé ──
  var elPromoCode = (document.getElementById('elPromo')?.value||'').trim().toUpperCase();
  if(elPromoCode && typeof applyPartnerCode==='function'){
    try {
      applyPartnerCode(elPromoCode, {
        refType:'elearning', refId:planId,
        refLabel: plan ? plan.nom : ('Abonnement '+planId),
        saleAmount: plan ? (plan.prix||0) : 0, qty:1
      });
      newAbo.partnerCode = elPromoCode; // trace dans l'abonnement
    } catch(e){ /* fail silent */ }
  }
  // Notification admin
  autoNotify(
    '🔔 Nouvelle souscription E-Learning',
    nom+' a souscrit au pack "'+(plan?plan.nom:planId)+'" ('+newAbo.classe+'). Tél: '+tel+'. En attente de validation.',
    'admin'
  );
  save();cm();
  var montant = plan ? (plan.prix||0) : 0;
  var aboId = newAbo.id; // capture avant le timeout
  setTimeout(function(){
    if(typeof openPaymentModal === 'function' && montant > 0){
      // Générer la ref en avance pour la stocker dans l'abonnement
      var payRef = 'ELRN'+new Date().toISOString().slice(2,10).replace(/-/g,'')+'-'+(Math.random().toString(36).slice(2,6)).toUpperCase();
      // Rétro-lier : stocker la payRef dans l'abonnement pour que mPayAttempts puisse la retrouver
      var aboToLink = (DB.elearning&&DB.elearning.abonnements||[]).find(function(a){return a.id===aboId;});
      if(aboToLink){aboToLink.payRef=payRef;save();}
      openPaymentModal({
        montant: montant,
        label: '🎓 '+(plan ? plan.nom : 'Abonnement E-Learning'),
        refPrefix: 'ELRN',
        ref: payRef,
        // ── v1.2 : metadata pour activation automatique ──
        intent: 'subscription',
        targetId: planId,
        customerAccountId: (SES&&(SES.type==='visiteur'||SES.type==='visiteur_inscrit')?SES.id:null),
        customerNom: nom,
        customerTel: tel
      });
    } else {
      toast('✓ Demande d\'abonnement envoyée ! L\'administration sera contactée.');
      var msg='🔔 *Nouvel abonnement E-Learning VÉRITAS !*\n\n📋 Plan: '+(plan?plan.nom:planId)+'\n👤 Nom: '+nom+'\n📱 Tél: '+tel+'\n📚 Classe: '+newAbo.classe+'\n📅 Date: '+today();
      window.open('https://wa.me/237697637739?text='+encodeURIComponent(msg),'_blank');
    }
  }, 100);
}

