function validerCommandeContenu(itemId){
  var nom=(document.getElementById('cmdNom')?.value||'').trim();
  var tel=(document.getElementById('cmdTel')?.value||'').trim();
  if(!nom||!tel){toast('Nom et WhatsApp requis','warn');return;}
  if(!DB.elearning.commandes) DB.elearning.commandes=[];
  var item=(DB.elearning.contenus||[]).find(function(c){return c.id===itemId;});
  DB.elearning.commandes.push({id:gid(),contenu:itemId,nom:nom,tel:tel,date:today(),statut:'En attente',prix:item?item.prix:0});
  save();cm();
  // v1.0 : ouvrir le modal de paiement unifié
  var montant = item ? (item.prix||0) : 0;
  setTimeout(function(){
    if(typeof openPaymentModal === 'function' && montant > 0){
      openPaymentModal({
        montant: montant,
        label: '📄 '+(item ? item.titre : 'Contenu E-Learning'),
        refPrefix: 'ELRN',
        intent: 'product',
        targetId: itemId,
        customerNom: nom,
        customerTel: tel
      });
    } else {
      toast('✓ Commande envoyée ! Livraison par WhatsApp sous 24h.');
    }
  }, 100);
}

