async function doLogin(){
  // [SEC v1.2] Rate limiting global (bloque après 5 tentatives toutes cibles)
  if(!_checkLoginRateLimit())return;
  var u=($("lu")?.value||"").trim(),p=$("lp")?.value||"";
  $("lerr").style.display="none";
  if(lr==="visiteur"){goToVisitor();return;}
  if(!u||!p){$("lerr").style.display="block";$("lerr").textContent="Veuillez remplir tous les champs.";return;}
  // Anti brute-force par compte
  var lock=_checkLoginLock(u);
  if(lock.locked){$("lerr").style.display="block";$("lerr").innerHTML='<div>Compte temporairement verrouill\u00e9</div><div style="font-size:11px;margin-top:4px;color:#6b7280">R\u00e9essayez dans '+lock.remaining+' secondes</div>';return;}
  if(lr==="eleve"){
    var sa2=null;
    if(DB.studentAccounts){for(var i=0;i<DB.studentAccounts.length;i++){
      var a2=DB.studentAccounts[i];
      if(a2.user.toLowerCase()===u.toLowerCase()){var ok=await verifyPassword(p,a2.pwd,a2.user,a2);if(ok){sa2=a2;break;}}
    }}
    if(sa2){var s=S(sa2.eid);if(s){sa2.lastLogin=today();save();_recordLoginSuccess(u);_loginAttempts.count=0;go2SES({...s,type:'eleve',sid:s.id,accountId:sa2.id,plans:sa2.plans||[]});return;}}
    // Visiteurs inscrits en ligne
    var va2=null;
    if(DB.visitorAccounts){for(var j=0;j<DB.visitorAccounts.length;j++){
      var v2=DB.visitorAccounts[j];
      if(v2.user.toLowerCase()===u.toLowerCase()&&v2.statut!=='suspendu'){var ok2=await verifyPassword(p,v2.pwd,v2.user,v2);if(ok2){va2=v2;break;}}
    }}
    if(va2){va2.lastLogin=today();save();_recordLoginSuccess(u);_loginAttempts.count=0;_createSession({id:va2.id,nom:va2.nom,pre:va2.pre,mat:va2.user,cls:va2.cls,tel:va2.tel,type:'visiteur',accountId:va2.id,plans:va2.plans||[]});hideAll();$('VISITOR').style.display='flex';initVisitor();setTimeout(_updateVisitorHeader,120);return;}
  } else if(lr==="enseignant"){
    var t=DB.teachers.find(function(t2){return t2.user===u;});
    if(t&&DB.tpwd[u]){
      // Wrapper pour permettre l'upgrade DB.tpwd[u] via recordRef.pwd
      var _tpwdRef={get pwd(){return DB.tpwd[u];},set pwd(v){DB.tpwd[u]=v;}};
      var okT=await verifyPassword(p,DB.tpwd[u],u,_tpwdRef);
      if(okT){DB.loginLog.push({user:u,role:'enseignant',date:today()});save();_recordLoginSuccess(u);_loginAttempts.count=0;go2SES({...t,type:'enseignant',tid:t.id});return;}
    }
  } else if(lr==="admin"){
    var foundAdmin=null;
    if(DB.admins){for(var k=0;k<DB.admins.length;k++){
      var ad=DB.admins[k];
      if(ad.user===u){var okA=await verifyPassword(p,ad.pwd,ad.user,ad);if(okA){foundAdmin=ad;break;}}
    }}
    if(foundAdmin){_recordLoginSuccess(u);_loginAttempts.count=0;sendOTP({...foundAdmin,type:'admin'});return;}
  } else if(lr==="superadmin"){
    var sa=DB.superAdmin;
    if(sa&&u===sa.user){var okS=await verifyPassword(p,sa.pwd,sa.user,sa);
      if(okS){_recordLoginSuccess(u);_loginAttempts.count=0;sendOTP({...sa,type:'superadmin',pre:'',role2:'superadmin'});return;}
    }
  }
  _recordLoginFail(u);
  $("lerr").style.display="block";
  if($("lp"))$("lp").value="";
  var lockAfter=_checkLoginLock(u);
  if(lockAfter.locked){
    $("lerr").innerHTML='<div>Identifiants incorrects</div><div style="font-size:11px;margin-top:4px;color:#dc2626">Compte verrouill\u00e9 pour '+lockAfter.remaining+'s apr\u00e8s trop de tentatives</div>';
  } else {
    $("lerr").innerHTML='<div>Identifiants incorrects</div>';
  }
}

function go2SES(acc){
  try{
    SES=acc;
    hideAll();
    $("APP").style.display="flex";
    buildNav();topUI();goTo("dashboard");
    // Afficher l'indicateur de sync cloud pour les admins
    setTimeout(function(){
      if(iA()){
        var dot=document.getElementById('vSyncDot');
        if(dot){
          dot.style.display='inline-flex';
          var lastSync=DB.cloudConfig&&DB.cloudConfig.lastSync;
          _setSyncDot(lastSync?'ok':'pending',lastSync||'');
        }
        // 🔐 v1.2.2 : alerte mot de passe par défaut (admin connecté)
        setTimeout(function(){try{_warnDefaultPasswords();}catch(e){}},2000);
        // Sync intelligente au login : compare lastModified local vs serveur
        // Si serveur plus récent → pull (restaure) ; sinon → push
        var cfg=DB.cloudConfig;
        if(cfg&&cfg.url&&cfg.secret){
          setTimeout(function(){
            if(!iA())return;
            var localTS=DB.lastModified||0;
            // FIX: GET Firebase au lieu de sync.php
            _fbFetch(LWS_API.db+'?t='+Date.now())
            .then(function(r){if(!r.ok)throw new Error('HTTP '+r.status);return r.json();})
            .then(function(serverDB){
              if(!serverDB||!serverDB.school||!serverDB.students){if(!_autoSyncDirty)_cloudAutoSync();return;}
              var serverTS=serverDB.lastModified||0;
              var localScore2=_dbScore(DB),serverScore2=_dbScore(serverDB);
              if(serverTS>localTS||(serverScore2>localScore2+5)){
                // BUG-03 FIX : le polling background ne remplace DB que pour les admins
                if(!iA())return;
                // Serveur plus récent OU plus riche → fusionner
                var cloudCfg=DB.cloudConfig;
                function _mL(la,sa){var m=JSON.parse(JSON.stringify(sa||[]));var si={};m.forEach(function(x){si[x.id||x.mat]=true;});(la||[]).forEach(function(x){var k=x.id||x.mat;if(k&&!si[k])m.push(x);});return m;}
                var lb2=DB.books||[],lg2=DB.galleryImages||[],le2=(DB.elearning&&DB.elearning.contenus)||[];
                DB=serverDB;
                // BUG-09/BUG-03 FIX : re-migration systématique
                _migrateDB();
                DB.books=_mL(lb2,DB.books);
                DB.galleryImages=_mL(lg2,DB.galleryImages);
                if(!DB.elearning)DB.elearning={contenus:[],plans:[],abonnements:[],commandes:[],soumissions:[]};
                DB.elearning.contenus=_mL(le2,DB.elearning.contenus);
                DB.cloudConfig=cloudCfg;
                DB.cloudConfig.lastSync=new Date().toLocaleString('fr-FR')+' (auto-sync ↓)';
                save();
                _setSyncDot('ok',DB.cloudConfig.lastSync);
                toast('🔄 Données synchronisées depuis le cloud','info');
                setTimeout(function(){re();},800);
                // Re-pousser la fusion si admin
                setTimeout(function(){if(iA()){_autoSyncDirty=true;_cloudAutoSync();}},6000);
              } else {
                // Local à jour ou plus récent → pousser vers serveur
                if(!_autoSyncDirty)_cloudAutoSync();
              }
            })
            .catch(function(){
              if(!_autoSyncDirty)_cloudAutoSync();
            });
          },3000);
          // Démarrer le polling arrière-plan (sync automatique toutes les 90s)
          setTimeout(_startBgPoll, 8000);
        } else {
          // 🔐 v1.2.2 : admin connecté mais aucune clé Cloud sur cet appareil → la demander une fois.
          setTimeout(function(){try{_ensureCloudSecret();}catch(e){}},600);
        }
      }
    },300);
  }catch(err){
    // Afficher l'erreur si le chargement du tableau de bord échoue
    $("APP").style.display="none";
    $("LS").style.display="flex";
    $("lerr").style.display="block";
    $("lerr").innerHTML="❌ Erreur chargement: "+err.message+"<br><small style='font-size:10px'>Essayez de <button onclick=\"localStorage.removeItem(\'vrt10\');location.reload()\" style=\"background:#dc2626;color:#fff;border:none;padding:2px 8px;border-radius:4px;cursor:pointer\">réinitialiser</button></small>";
    console.error("go2SES error:",err);
  }
}
