function buildNav(){
  let nav;
  if(isSA())nav=SANAV;
  else if(iA())nav=ANAV;
  else if(isEnseignant())nav=TNAV;
  else if(isEleve())nav=ENAV;
  else nav=ENAV;
  const un=DB.payments.filter(p=>p.stat==='Impayé').length;
  const pendingAbos=(DB.elearning?.abonnements||[]).filter(function(a){return a.statut==='En attente';}).length;
  $("snav").innerHTML=nav.map(s=>`<div class="sbsec"><div class="sbsl">${s.s}</div>${s.i.map(it=>{
    const b=it.k==='payments'&&un>0&&iA()?`<span class="sbbg">${un}</span>`:'';
    const elBadge=it.k==='elearningmgmt'&&pendingAbos>0&&iA()?`<span class="sbbg" style="background:#DC2626">${pendingAbos}</span>`:'';
    return`<div class="sbit${it.k===pg?' on':''}" onclick="goTo('${it.k}')"><span class="sbic">${it.i}</span>${it.l}${b}${elBadge}</div>`;
  }).join("")}</div>`).join("");
  const roleMap={admin:"aa",enseignant:"at",eleve:"ae",superadmin:"asa"};
  const ac=roleMap[SES?.type]||"ae";
  const roleLabel={admin:"Admin",enseignant:"Enseignant",eleve:"Élève",superadmin:"Super Admin"};
  $("sbu").innerHTML=`<div class="sba ${ac}">${SES?.nom?.[0]||'?'}</div><div style="flex:1;min-width:0"><div class="sbun">${SES?.pre?SES.pre+' '+SES.nom:SES?.nom||''}</div><div class="sbur">${roleLabel[SES?.type]||''}</div></div><button class="sblo" onclick="logout()" title="Déconnexion">⏻ Déconnexion</button>`;
  $("sbfi").textContent=`${DB.students.length} élèves · ${DB.teachers.length} enseignants`;
  const lg=getLogo();
  const sl=$("sbLogo");if(sl)sl.src=lg;
  const sn=$("sbSchoolName");if(sn)sn.textContent=DB.school?.nom||'VÉRITAS Academy';
  const ss=$("sbSchoolSlogan");if(ss)ss.textContent=DB.school?.slogan||'Centre d\u0027Excellence Scolaire';
  const sc=$("sbSchoolCity");if(sc)sc.textContent=DB.school?.ville||'Douala, Cameroun';
}
function topUI(){
  const roleTag={admin:'rpa',enseignant:'rpt',eleve:'rpe',superadmin:'rpsa'};
  const roleText={admin:'ADMIN',enseignant:'ENSEIGNANT',eleve:'ÉLÈVE',superadmin:'SUPER ADMIN'};
  $("rtag").className='rp '+(roleTag[SES?.type]||'rpe');
  $("rtag").textContent=roleText[SES?.type]||'ÉLÈVE';
  $("tbd").textContent=today();
  const notifs=(DB.notifications||[]).filter(n=>n.to==='all'||n.to===SES?.id||n.to===SES?.type);
  const unread=notifs.filter(n=>!(n.read||[]).includes(SES?.id||SES?.user||''));
  const bellHtml=unread.length>0?'<div style="position:relative;cursor:pointer" onclick="showNotifications()"><span style="font-size:18px">🔔</span><span style="position:absolute;top:-4px;right:-6px;background:var(--re);color:#fff;font-size:13px;font-weight:700;border-radius:50%;width:14px;height:14px;display:flex;align-items:center;justify-content:center">'+unread.length+'</span></div>':'<span style="cursor:pointer;font-size:18px;opacity:.4" onclick="showNotifications()">🔔</span>';
  const bellEl=document.getElementById('notifBell');if(bellEl)bellEl.innerHTML=bellHtml;
}
function goTo(p){pg=p;buildNav();$("pgt").textContent=PT[p]||p;csb();$("cnt").innerHTML=render(p);$("cnt").scrollTop=0;}
