// ─── MODAL & TOAST ──────────────────────────────
function M(title,sub,body,foot,xl=false){
  // v2 a11y : role=dialog, aria-modal, aria-labelledby, ESC pour fermer, focus trap
  try { window._lastFocusedBeforeModal = document.activeElement; } catch(e){}
  var _mid='m'+Date.now();
  $("MC").innerHTML=`<div class="mov" id="mOvl" onclick="if(event.target.id==='mOvl')cm()" role="presentation"><div class="modal${xl?' mxl':''}" onclick="event.stopPropagation()" role="dialog" aria-modal="true" aria-labelledby="${_mid}-title"><div class="mhd"><div><div class="mtt" id="${_mid}-title">${title}</div>${sub?`<div class="mst">${sub}</div>`:''}</div><button class="mc" onclick="cm()" aria-label="Fermer la fenêtre">✕</button></div><div class="mb">${body}</div><div class="mf">${foot}</div></div></div>`;
  // Auto-focus premier input ou bouton
  setTimeout(function(){
    try {
      var modal=document.querySelector('#mOvl .modal');
      if(!modal) return;
      var first=modal.querySelector('input,select,textarea,button:not(.mc)');
      if(first) first.focus();
    } catch(e){}
  },50);
  // ESC pour fermer
  if(!window._mEscHandler){
    window._mEscHandler=function(e){ if(e.key==='Escape' && document.getElementById('mOvl')) cm(); };
    document.addEventListener('keydown', window._mEscHandler);
  }
}
function cm(){
  $("MC").innerHTML='';
  // v2 a11y : restituer le focus à l'élément qui a ouvert la modale (si possible)
  try { if(window._lastFocusedBeforeModal && document.contains(window._lastFocusedBeforeModal)) window._lastFocusedBeforeModal.focus(); } catch(e){}
}
function toast(msg,t='ok'){const d=document.createElement('div');const c={ok:['var(--gr)','✓'],warn:['var(--or)','⚠'],err:['var(--re)','✕'],info:['#3C8DFF','ℹ']}[t]||['var(--gr)','✓'];d.style.cssText=`position:fixed;bottom:20px;right:20px;display:flex;align-items:center;gap:10px;background:#fff;border:1px solid #E6EAF2;border-left:4px solid ${c[0]};color:#142554;padding:12px 16px;border-radius:12px;font-size:13px;font-weight:600;z-index:9999;box-shadow:0 10px 30px rgba(20,37,84,.16);max-width:360px;animation:su .24s cubic-bezier(.16,1,.3,1);`;d.innerHTML=`<span style="flex-shrink:0;width:22px;height:22px;border-radius:50%;display:flex;align-items:center;justify-content:center;background:${c[0]};color:#fff;font-size:13px;font-weight:800">${c[1]}</span><span>${(''+msg).replace(/</g,'&lt;')}</span>`;document.body.appendChild(d);setTimeout(()=>{d.style.transition='opacity .3s,transform .3s';d.style.opacity='0';d.style.transform='translateY(8px)';setTimeout(()=>d.remove(),300);},3500);}
// Toast enrichi avec bouton d'action — utilisé quand cloud KO et fichiers locaux en attente
function _toastRetrySync(){
  var d=document.createElement('div');
  d.style.cssText='position:fixed;bottom:20px;right:20px;background:var(--orb);border:1px solid var(--ord);color:var(--or);padding:11px 18px;border-radius:var(--r);font-size:13px;font-weight:600;z-index:9999;box-shadow:var(--sh2);max-width:380px;animation:su .22s;display:flex;align-items:center;gap:10px';
  var txt=document.createElement('span');
  txt.textContent='⚠ Cloud KO — fichiers locaux en attente';
  var btn=document.createElement('button');
  btn.textContent='↻ Sync';
  btn.style.cssText='background:var(--or);color:#fff;border:none;border-radius:6px;padding:4px 10px;cursor:pointer;font-size:12px;font-weight:700;white-space:nowrap;flex-shrink:0';
  btn.onclick=function(){d.remove();if(typeof cloudSyncBinaries==='function')cloudSyncBinaries();};
  d.appendChild(txt);d.appendChild(btn);
  document.body.appendChild(d);
  setTimeout(function(){if(d.parentNode)d.remove();},6000);
}

// ═══════════════════════════════════════════════
// MOTEUR DOCUMENTS (conservé de v9)
// ═══════════════════════════════════════════════
var _printOrient='portrait';
function printDoc(html,title,orient){
  _printOrient=orient||'portrait';
  const prev=document.querySelector('.docov');if(prev)prev.remove();
  const wrap=document.createElement('div');wrap.className='docov';
  var wmOverlay=(typeof _watermarkHtml==='function')?_watermarkHtml():'';
  if(wrap)wrap.innerHTML=`<div class="docwin"><div class="docbar"><span class="doctitle">${title}</span><button class="dba dba-pr" onclick="doPrint()">🖨️ Imprimer</button><button class="dba dba-pdf" onclick="doExportPDF('${encodeURIComponent(title)}')">📄 PDF</button><button class="dba dba-img" onclick="doExportImg('${encodeURIComponent(title)}')">🖼️ Image</button><button class="dba dba-cl" onclick="this.closest('.docov').remove()">✕</button></div><div class="docbody"><div id="docContent" style="${_printOrient==='landscape'?'width:1050px':''}position:relative;overflow:hidden">${wmOverlay}${html}</div></div></div>`;
  document.body.appendChild(wrap);
  setTimeout(function(){addQRToCurrentDoc(title);},800);
}
function addQRToCurrentDoc(title){
  var dc=document.getElementById('docContent');
  if(!dc||dc.querySelector('.qr-auth-block'))return;
  // Skip if inline QR already exists (bulletins, certificats)
  if(dc.querySelector('svg[viewBox]'))return;
  var ref=gid().substring(0,8).toUpperCase();
  var txt=generateQRData(title||'Document',ref);
  var wrap=document.createElement('div');
  wrap.className='qr-auth-block';
  wrap.style.cssText='display:flex;flex-direction:column;align-items:center;gap:6px;padding:12px 16px;margin-top:12px';
  var qrHtml='<div style="border:1.5px solid #142554;border-radius:4px;padding:2px;background:#fff;line-height:0">'
    +_qrSvg.toSVG(txt,1)
    +'</div>';
  var infoHtml='<div style="text-align:center;line-height:1.3">'
    +'<div style="font-size:7px;color:#142554;font-weight:800;letter-spacing:1.5px;text-transform:uppercase">Document Authentifié</div>'
    +'<div style="font-size:6px;color:#888;margin-top:1px">'+today()+' · Réf: <strong style="color:#142554;font-family:monospace">'+ref+'</strong></div>'
    +'<div style="font-size:5px;color:#aaa;margin-top:1px">Scannez le QR code pour vérifier</div>'
    +'</div>';
  var sepHtml='<div style="width:100%;height:2px;background:#142554;margin-top:4px"></div>';
  wrap.innerHTML=qrHtml+infoHtml+sepHtml;
  dc.appendChild(wrap);
}
function doPrint(){const c=$("docContent");if(!c){toast('Contenu introuvable','err');return;}var pw=_printOrient==='landscape'?1100:830,ph=_printOrient==='landscape'?830:1100;const w=window.open('','_blank','width='+pw+',height='+ph);if(!w){toast('Autorisez les popups','warn');return;}const fonts=`<link href="https://fonts.googleapis.com/css2?family=Libre+Baskerville:ital,wght@0,400;0,700;1,400&family=Outfit:wght@400;600;700&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet">`;w.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8">${fonts}<style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:'Inter',sans-serif;color:#1c1814;-webkit-print-color-adjust:exact;print-color-adjust:exact}@page{size:A4 ${_printOrient};margin:8mm 10mm}img{max-width:100%}</style></head><body>${c.innerHTML}<scr`+`ipt>window.onload=()=>setTimeout(()=>{document.body.setAttribute('data-print-date',new Date().toLocaleDateString('fr-FR')+' '+new Date().toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'}));window.print();},900);<\/script></body></html>`);w.document.close();}
async function doExportPDF(enc){const c=$("docContent");if(!c)return;const title=decodeURIComponent(enc);toast('⏳ Génération PDF…');try{await document.fonts.ready;await new Promise(r=>setTimeout(r,500));const canvas=await html2canvas(c,{scale:2,useCORS:true,allowTaint:true,backgroundColor:'#fff',logging:false});// [WATERMARK v1.2] Filigrane avant export PDF
applyWatermark(canvas,canvas.getContext('2d'));const{jsPDF}=window.jspdf;const pdf=new jsPDF({orientation:_printOrient||'portrait',unit:'mm',format:'a4'});const pw=pdf.internal.pageSize.getWidth(),ph=pdf.internal.pageSize.getHeight();const img=canvas.toDataURL('image/jpeg',.95);const ih=(canvas.height*pw)/canvas.width;if(ih<=ph){pdf.addImage(img,'JPEG',0,0,pw,ih);}else{let y=0;while(y<ih){if(y>0)pdf.addPage();pdf.addImage(img,'JPEG',0,-y,pw,ih);y+=ph;}}pdf.save(title.replace(/[^\w\sÀ-ÿ\-]/g,'_')+'.pdf');toast('✓ PDF enregistré');}catch(e){console.error(e);toast('Erreur PDF','err');}}
async function doExportImg(enc){const c=$("docContent");if(!c)return;const title=decodeURIComponent(enc);toast('⏳ Génération image…');try{await document.fonts.ready;await new Promise(r=>setTimeout(r,500));const canvas=await html2canvas(c,{scale:2,useCORS:true,allowTaint:true,backgroundColor:'#fff',logging:false});// [WATERMARK v1.2] Filigrane avant export image
applyWatermark(canvas,canvas.getContext('2d'));const link=document.createElement('a');link.download=title.replace(/[^\w\sÀ-ÿ\-]/g,'_')+'.png';link.href=canvas.toDataURL('image/png');link.click();toast('✓ Image téléchargée');}catch(e){console.error(e);toast('Erreur image','err');}}

function docHeader(titre){const sc=DB.school;return`<div style="background:#142554;padding:16px 26px;display:flex;align-items:center;gap:14px"><img src="${getLogo()}" style="width:42px;height:42px;border-radius:50%;background:#fff;padding:2px;object-fit:contain;flex-shrink:0"><div style="flex:1"><div style="font-family:'Libre Baskerville',serif;font-size:16px;color:#FFC93C;letter-spacing:2px">${sc?.nom||'VÉRITAS'}</div><div style="font-size:10px;color:rgba(255,255,255,.5);letter-spacing:1.5px;text-transform:uppercase;margin-top:2px">${sc?.slogan||'La Réussite Assurée'} · ${sc?.ville||'Yaoundé'}</div></div><div style="text-align:right"><div style="font-size:9px;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:1px;margin-bottom:4px">${titre}</div><div style="font-size:8px;font-family:'Fira Code',monospace;color:rgba(255,255,255,.3)">Tél: ${sc?.tel||'—'} · ${sc?.bp||'—'}</div><div style="font-size:8px;color:rgba(255,255,255,.3);margin-top:2px">Année ${sc?.annee||'2024–2025'}</div></div></div>`;}

// ═══════════════════════════════════════════════
// TABLEAU DE BORD (unifié multi-rôles)
// ═══════════════════════════════════════════════
function pgDash(){
  if(isEleve()){
    const s=SES;const gr=DB.grades.filter(g=>g.eid===s.id&&g.tri===TRS[0]);
    const tc=gr.reduce((a,g)=>a+g.coef,0)||1;
    const moy=gr.length?gr.reduce((a,g)=>a+((g.n1+g.n2)/2)*g.coef,0)/tc:null;
    const ap=moy!==null?getAppr(moy):null;
    const absE=DB.absences.filter(a=>a.eid===s.id);
    const totH=absE.reduce((a,b)=>a+b.heures,0);
    const njust=absE.filter(a=>!a.justifie).length;
    const pays=DB.payments.filter(p=>p.eid===s.id);
    const dernier=pays.find(p=>p.stat==='En attente')||pays.find(p=>p.stat==='Impayé');
    const dvsE=DB.devoirs.filter(d=>d.cls===s.cls);
    const subs=DB.submissions.filter(sb=>sb.eid===s.id);
    const dvsPending=dvsE.filter(d=>!subs.find(sb=>sb.dvid===d.id));
    return`<div class="card mb16" style="background:linear-gradient(135deg,#1a6e40,#228844);color:#fff;border:none;padding:22px">
      <div class="fl2 fic g12"><img src="${getLogo()}" alt="" style="width:50px;height:50px;border-radius:50%;background:#fff;padding:3px"><div>
        <div style="font-family:'Libre Baskerville',serif;font-size:20px;color:#edfaf3">${s.pre} ${s.nom}</div>
        <div style="font-size:13px;color:rgba(255,255,255,.6);margin-top:2px">Matricule: <strong style="color:#fff">${s.mat}</strong> · Classe: <strong style="color:#fff">${s.cls}</strong></div>
        <div style="font-size:13px;color:rgba(255,255,255,.4);margin-top:2px">Inscrit le ${s.ins} · ${s.stat}</div>
      </div></div>
    </div>
    <div class="sg" style="grid-template-columns:repeat(4,1fr)">
      <div class="sc scgr" onclick="goTo('mon_bulletin')" style="cursor:pointer"><div class="sci">📄</div><div class="scl">Moyenne T1</div><div class="scv vgr">${moy!==null?moy.toFixed(2):'—'}</div><div class="scs">${ap?.lbl||'—'}</div></div>
      <div class="sc scr" onclick="goTo('mes_absences')" style="cursor:pointer"><div class="sci">✅</div><div class="scl">Absences</div><div class="scv vr">${totH}h</div><div class="scs">${njust} non justifiée${njust>1?'s':''}</div></div>
      <div class="sc ${s.stat==='Payé'?'scgr':'scr'}" onclick="goTo('mon_paiement')" style="cursor:pointer"><div class="sci">💳</div><div class="scl">Paiement</div><div class="scv ${s.stat==='Payé'?'vgr':'vr'}" style="font-size:14px">${s.stat}</div><div class="scs">${fmt(s.frais)}/mois</div></div>
      <div class="sc scb" onclick="goTo('mes_devoirs')" style="cursor:pointer"><div class="sci">📋</div><div class="scl">Devoirs à rendre</div><div class="scv vb">${dvsPending.length}</div><div class="scs">${dvsE.length} au total</div></div>
    </div>
    ${(function(){
      var _wg=(DB.whatsappGroupes||[]).find(function(g){return g.actif&&g.niveau===s.cls;});
      if(!_wg)return '';
      var _a2=typeof _waGroupAccess==='function'?_waGroupAccess(_wg,null,{stat:s.stat,cls:s.cls}):{eligible:true,reason:'Acces libre'};
      var _m=_wg.accessMode||'libre';
      var _bg=_a2.eligible?'linear-gradient(135deg,#25D366,#128C7E)':'linear-gradient(135deg,#94A3B8,#64748B)';
      var _sub=_a2.eligible?'Rejoignez le groupe officiel de votre classe':_a2.reason;
      var _btn='';
      if(_a2.eligible&&_wg.lien){_btn='<a href="'+_wg.lien+'" target="_blank" style="background:#fff;color:#128C7E;font-family:Montserrat,sans-serif;font-size:12px;font-weight:800;padding:8px 18px;border-radius:20px;text-decoration:none;white-space:nowrap;flex-shrink:0">&#128242; Rejoindre</a>';}
      else if(_m==='paiement'){_btn='<span style="background:rgba(255,255,255,.2);color:#fff;font-size:11px;font-weight:700;padding:6px 14px;border-radius:20px">&#128179; Reglez votre scolarite</span>';}
      else if(_m==='abonnement'){_btn='<span style="background:rgba(255,255,255,.2);color:#fff;font-size:11px;font-weight:700;padding:6px 14px;border-radius:20px">&#128230; Abonnement requis</span>';}
      else{_btn='<span style="background:rgba(255,255,255,.2);color:#fff;font-size:11px;font-weight:700;padding:6px 14px;border-radius:20px">Validation admin requise</span>';}
      return '<div style="background:'+_bg+';border-radius:14px;padding:14px 18px;margin-bottom:16px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px"><div style="display:flex;align-items:center;gap:12px"><span style="font-size:26px">&#128241;</span><div><div style="font-family:Montserrat,sans-serif;font-size:13px;font-weight:800;color:#fff">Groupe WA &#8212; '+_esc(_wg.nom)+'</div><div style="font-size:11px;color:rgba(255,255,255,.75);margin-top:2px">'+_sub+'</div></div></div>'+_btn+'</div>';
    })()}
    <div class="g2">
      <div class="card"><div class="ct">📝 Mes dernières notes — ${TRS[0]}</div>
        ${gr.length===0?'<div class="empty"><div class="empty-ico">📋</div>Aucune note disponible</div>':gr.map(g=>{const m=(g.n1+g.n2)/2;const ap2=getAppr(m);return`<div class="fl2 fic fsb" style="padding:8px 0;border-bottom:1px solid var(--bg2)">
          <div><div class="semi s">${g.sub}</div><div class="xs2 mut">Coef. ${g.coef} · ${g.ens}</div></div>
          <div class="fl2 fic g8"><span class="mono xs2">${g.n1}/20 + ${g.n2}/20</span><span class="bg" style="background:${ap2.col}20;color:${ap2.col};border:1px solid ${ap2.col}44">${m.toFixed(1)}</span></div>
        </div>`;}).join("")}
        <button class="btn bgr2 sm mt14" onclick="goTo('mon_bulletin')">📄 Voir bulletin complet →</button>
      </div>
      <div>
        <div class="card mb16"><div class="ct">📋 Prochains devoirs</div>
          ${dvsPending.length===0?'<div class="empty"><div class="empty-ico">✅</div>Tous les devoirs remis !</div>':dvsPending.slice(0,3).map(d=>{const dl=new Date(d.dateLimit);const j=Math.ceil((dl-new Date())/864e5);const cls2=j<0?'dv-late':j<=3?'dv-warn':'dv-ok';return`<div class="dv-card"><div class="fl2 fic fsb mb8"><span class="bg bgb">${d.sub}</span><span class="dv-deadline ${cls2}">${j<0?'En retard':j===0?'Auj.':`dans ${j}j`}</span></div><div class="semi s mb4">${d.titre}</div><div style="font-size:13px;color:var(--ink4)">Limite: ${dl.toLocaleDateString('fr-FR')}</div></div>`;}).join("")}
          <button class="btn bvi sm mt8" onclick="goTo('mes_devoirs')">📋 Tous mes devoirs →</button>
        </div>
        <div class="card"><div class="ct">📣 Annonces récentes</div>
          ${DB.announce.slice(-3).reverse().map(a=>`<div class="fl2 fic g10" style="padding:8px 0;border-bottom:1px solid var(--bg2)"><span class="bg ${EVT[a.type]?.c||'bgt'} xs">${_esc(EVT[a.type]?.l||a.type)}</span><div class="s semi">${_esc(a.titre)}</div></div>`).join("") || '<div class="empty xs2">Aucune annonce</div>'}
          <button class="btn bo sm mt8" onclick="goTo('announce')">Toutes les annonces →</button>
        </div>
      </div>
    </div>`;
  }

  if(isEnseignant()){
    const t=T(SES.tid);
    const mg=DB.grades.filter(g=>g.ens&&g.ens.includes(t?.nom||'@@'));
    const myDvs=DB.devoirs.filter(d=>d.tid===SES.tid);
    const mySubs=DB.submissions.filter(sb=>myDvs.find(d=>d.id===sb.dvid));
    const clsSet=[...new Set(mg.map(g=>g.cls))];
    return`<div class="card mb16" style="background:linear-gradient(135deg,#1a3a8a,#1a50c0);color:#fff;border:none;padding:22px">
      <div class="fl2 fic g12"><img src="${getLogo()}" alt="" style="width:50px;height:50px;border-radius:50%;background:#fff;padding:3px">
      <div><div style="font-family:'Libre Baskerville',serif;font-size:18px;color:#FFC93C">${t?.pre} ${t?.nom}</div>
      <div style="font-size:13px;color:rgba(255,255,255,.5);margin-top:2px">${t?.mat2||t?.mat} · ${t?.grade} · ${t?.mat}</div></div></div>
    </div>
    <div class="sg" style="grid-template-columns:repeat(4,1fr)">
      <div class="sc scg"><div class="sci">📝</div><div class="scl">Notes saisies</div><div class="scv vg">${mg.length}</div></div>
      <div class="sc scb"><div class="sci">📚</div><div class="scl">Matière</div><div style="font-size:13px;font-weight:700;color:var(--bl);margin-top:6px">${t?.mat2||t?.mat||'—'}</div></div>
      <div class="sc scgr"><div class="sci">🎓</div><div class="scl">Élèves suivis</div><div class="scv vgr">${[...new Set(mg.map(g=>g.eid))].length}</div><div class="scs">${clsSet.length} classe${clsSet.length>1?'s':''}</div></div>
      <div class="sc scvi"><div class="sci">📋</div><div class="scl">Mes devoirs</div><div class="scv vvi">${myDvs.length}</div><div class="scs">${mySubs.length} soumission${mySubs.length>1?'s':''}</div></div>
    </div>
    <div class="g2">
      <div class="card"><div class="ct">Mes dernières saisies</div>
        ${mg.length===0?'<div class="empty"><div class="empty-ico">📋</div>Aucune note saisie</div>':`<div class="tw"><table><thead><tr><th>Élève</th><th>Classe</th><th>Dev.1</th><th>Dev.2</th><th>Moy.</th></tr></thead><tbody>
        ${mg.slice(-8).reverse().map(g=>{const m=(g.n1+g.n2)/2;const ap2=getAppr(m);return`<tr><td class="bold s">${g.enom}</td><td><span class="bg bgt">${g.cls}</span></td><td class="mono s">${g.n1}/20</td><td class="mono s">${g.n2}/20</td><td class="mono bold s" style="color:${ap2.col}">${m.toFixed(2)}</td></tr>`;}).join("")}
        </tbody></table></div>`}
        <button class="btn bgr2 sm mt14" onclick="goTo('grades')">📝 Saisir des notes →</button>
      </div>
      <div>
        <div class="card mb16"><div class="ct">📋 Mes devoirs récents</div>
          ${myDvs.length===0?'<div class="empty"><div class="empty-ico">📋</div>Aucun devoir proposé</div>':myDvs.slice(-3).reverse().map(d=>{const nbSub=DB.submissions.filter(sb=>sb.dvid===d.id).length;return`<div class="dv-card"><div class="fl2 fic fsb mb4"><span class="bg bgb">${d.sub} · ${d.cls}</span><span class="bg bgt">${nbSub} soum.</span></div><div class="semi s mb4">${d.titre}</div><div style="font-size:13px;color:var(--ink4)">Limite: ${new Date(d.dateLimit).toLocaleDateString('fr-FR')}</div></div>`;}).join("")}
          <button class="btn bvi sm mt8" onclick="goTo('devoirs_teacher')">📋 Gérer mes devoirs →</button>
        </div>
        <div class="card"><div class="ct">📊 Performance par classe</div>
          ${clsSet.map(cls=>{const clsGr=mg.filter(g=>g.cls===cls);const moysAll=clsGr.reduce((acc,g)=>{if(!acc[g.eid])acc[g.eid]={total:0,coef:0};acc[g.eid].total+=(g.n1+g.n2)/2*g.coef;acc[g.eid].coef+=g.coef;return acc;},{});const moyClasses=Object.values(moysAll).map(x=>x.total/x.coef);const avg=moyClasses.length?moyClasses.reduce((a,b)=>a+b,0)/moyClasses.length:0;return`<div class="fl2 fic fsb mb10"><div><div class="semi s">${cls}</div><div class="xs2 mut">${[...new Set(clsGr.map(g=>g.eid))].length} élèves</div></div><div class="fl2 fic g8"><div class="pb" style="width:100px"><div class="pf pfg" style="width:${Math.round(avg/20*100)}%"></div></div><span class="mono xs2" style="color:var(--gold)">${avg.toFixed(1)}/20</span></div></div>`;}).join("") || '<div class="xs2 mut">Aucune donnée</div>'}
          <button class="btn bo sm mt8" onclick="goTo('perf_teacher')">📊 Analyse complète →</button>
        </div>
      </div>
    </div>`;
  }

  // Admin / Super Admin dashboard
  const paid=DB.payments.filter(p=>p.stat==='Payé').reduce((s,p)=>s+p.mnt,0);
  const imp=DB.payments.filter(p=>p.stat==='Impayé').reduce((s,p)=>s+p.mnt,0);
  const bkr=DB.books.reduce((s,b)=>s+b.vendu*b.prix,0);
  const sal=DB.teachers.reduce((s,t)=>s+t.sal,0);
  const totDep=DB.depenses.reduce((s,d)=>s+d.mnt,0);
  const bnet=paid+bkr-sal-totDep;
  const cd=CLS.map(c=>({c,n:DB.students.filter(s=>s.cls===c).length})).filter(x=>x.n>0);
  const mx=Math.max(...cd.map(x=>x.n),1);
  const tops=DB.students.map(s=>{const gr=DB.grades.filter(g=>g.eid===s.id&&g.tri===TRS[0]);const tc=gr.reduce((a,g)=>a+g.coef,0)||1;const moy=gr.length?gr.reduce((a,g)=>a+((g.n1+g.n2)/2)*g.coef,0)/tc:null;return{...s,moy};}).filter(s=>s.moy!==null).sort((a,b)=>b.moy-a.moy);
  const rp=DB.payments.slice(-5).reverse();
  const ua=DB.announce.filter(a=>new Date(a.date)>=new Date()).sort((a,b)=>new Date(a.date)-new Date(b.date)).slice(0,3);
  const totAbs=DB.absences?.length||0;
  return`
  ${isSA()?'<div class="ib ibg mb16"><span>👑</span><span>Vous êtes connecté en tant que <strong>Super Administrateur</strong>. Vous avez accès à toutes les données sensibles du système.</span></div>':''}
  ${(()=>{var pendingAbos=(DB.elearning?.abonnements||[]).filter(function(a){return a.statut==='En attente';});if(!pendingAbos.length)return'';return'<div class="ib" style="background:#FEE2E2;border:1px solid #FCA5A5;color:#DC2626;cursor:pointer;margin-bottom:16px" onclick="goTo(\'elearningmgmt\')"><span style="font-size:20px">🔔</span><span><strong>'+pendingAbos.length+' abonnement(s) E-Learning en attente de validation !</strong> Cliquez pour gérer → E-Learning Admin</span></div>'})()}
  <div class="sg">
    <div class="sc scg"><div class="sci">🎓</div><div class="scl">Élèves inscrits</div><div class="scv vg">${DB.students.length}</div><div class="scs">${CLS.filter(c=>DB.students.some(s=>s.cls===c)).length} niveaux actifs</div></div>
    <div class="sc scgr"><div class="sci">💰</div><div class="scl">Recettes totales</div><div class="scv vgr" style="font-size:18px">${fmt(paid+bkr)}</div><div class="scs">frais + manuels</div></div>
    <div class="sc scr"><div class="sci">⚠️</div><div class="scl">Impayés</div><div class="scv vr" style="font-size:18px">${fmt(imp)}</div><div class="scs">${DB.payments.filter(p=>p.stat==='Impayé').length} élèves</div></div>
    <div class="sc scb"><div class="sci">👨‍🏫</div><div class="scl">Masse salariale</div><div class="scv vb" style="font-size:18px">${fmt(sal)}</div><div class="scs">${DB.teachers.length} enseignants</div></div>
  </div>
  <div class="sg" style="grid-template-columns:repeat(3,1fr)">
    <div class="sc scvi"><div class="sci">📋</div><div class="scl">Devoirs actifs</div><div class="scv vvi">${DB.devoirs?.length||0}</div><div class="scs">${DB.submissions?.length||0} soumissions</div></div>
    <div class="sc scpu"><div class="sci">✅</div><div class="scl">Absences enreg.</div><div class="scv vpu">${totAbs}</div><div class="scs">cette période</div></div>
    <div class="sc scg"><div class="sci">📚</div><div class="scl">Manuels vendus</div><div class="scv vg">${DB.books.reduce((s,b)=>s+b.vendu,0)}</div><div class="scs">${fmt(bkr)} de recettes</div></div>
  </div>
  <div class="g2">
    <div class="card"><div class="ct">Répartition par classe</div>
      ${cd.map(({c,n})=>`<div class="mb12"><div class="fl2 fic fsb mb6"><span class="semi s">${c}</span><span class="mono xs2 mut">${n} élève${n>1?'s':''}</span></div><div class="pb"><div class="pf pfg" style="width:${Math.round(n/mx*100)}%"></div></div></div>`).join("")}
      <button class="btn bo sm mt14" onclick="goTo('students')">🎓 Voir inscriptions →</button>
    </div>
    <div class="card"><div class="ct">Derniers paiements</div>
      ${rp.map(p=>`<div class="fl2 fic fsb" style="padding:9px 0;border-bottom:1px solid var(--bg2)">
        <div class="fl2 fic g10"><div class="av" style="width:28px;height:28px;background:var(--gp);color:var(--gold);border:1.5px solid var(--gb);font-size:12px">${p.enom[0]}</div>
        <div><div class="semi s">${p.enom}</div><div class="xs2 mut">${p.mo}</div></div></div>
        <div class="fl2 fic g6"><span class="mono s" style="color:var(--gold)">${fmt(p.mnt)}</span><span class="bg ${p.stat==='Payé'?'bgg':p.stat==='Impayé'?'bgr':'bgo'}">${p.stat}</span></div></div>`).join("")}
      <button class="btn bo sm mt14" onclick="goTo('payments')">💳 Tous les paiements →</button>
    </div>
  </div>
  <div class="g2">
    <div class="card"><div class="ct">🏆 Meilleurs élèves — ${TRS[0]}</div>
      ${tops.slice(0,5).map((s,i)=>{const ap2=getAppr(s.moy);return`<div class="fl2 fic fsb" style="padding:8px 0;border-bottom:1px solid var(--bg2)">
        <div class="fl2 fic g10"><div style="width:24px;height:24px;border-radius:50%;background:${i===0?'var(--gp)':'var(--bg3)'};color:${i===0?'var(--gold)':'var(--ink4)'};display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700">${i+1}</div>
        <div><div class="semi s">${s.pre} ${s.nom}</div><div class="xs2 mut">${s.cls}</div></div></div>
        <span class="mono bold" style="color:${ap2.col}">${s.moy.toFixed(2)}</span>
      </div>`;}).join("") || '<div class="empty xs2">Aucune note</div>'}
    </div>
    <div class="card"><div class="ct">Résultat financier</div>
      ${[['＋ Frais scolarité',paid,true],['＋ Vente manuels',bkr,true],['− Masse salariale',sal,false],['− Autres charges',totDep,false]].map(([l,v,pos])=>`<div class="fl2 fic fsb" style="padding:9px 0;border-bottom:1px solid var(--bg2)"><span class="s">${l}</span><span class="mono semi s" style="color:${pos?'var(--gr)':'var(--re)'}">${pos?'+':'−'}${fmt(v)}</span></div>`).join("")}
      <div style="margin-top:12px;padding:14px;background:${bnet>=0?'var(--grb)':'var(--reb)'};border-radius:var(--r2);border:1.5px solid ${bnet>=0?'var(--grd)':'var(--red)'}">
        <div class="xs2 mut">Résultat net</div>
        <div class="mono bold mt8" style="font-size:22px;color:${bnet>=0?'var(--gr)':'var(--re)'}">${bnet>=0?'+':''} ${fmt(bnet)}</div>
      </div>
      <button class="btn bi sm mt14" onclick="goTo('finance')">📈 Bilan détaillé →</button>
    </div>
  </div>
  ${ua.length>0?`<div class="card"><div class="ct">📣 Événements à venir</div><div class="fl2 g12 fw">${ua.map(a=>{const dL=Math.ceil((new Date(a.date)-new Date())/864e5);return`<div style="flex:1;min-width:180px;padding:14px;border-radius:var(--r2);border:var(--br);background:var(--sur2)"><div class="fl2 fic fsb mb8"><span class="bg ${EVT[a.type]?.c||'bgt'}">${EVT[a.type]?.l||a.type}</span><span class="xs2 mut">${dL>0?`dans ${dL}j`:dL===0?'Auj.':`${Math.abs(dL)}j passé`}</span></div><div class="semi s mb4">${a.titre}</div></div>`;}).join("")}</div></div>`:''}`
}

// ═══════════════════════════════════════════════
// ESPACE ÉLÈVE
// ═══════════════════════════════════════════════
function pgMonBulletin(){
  const s=SES;const selT=window._bT||TRS[0];
  const gr=DB.grades.filter(g=>g.eid===s.id&&g.tri===selT);
  const tc=gr.reduce((a,g)=>a+g.coef,0)||1;
  const moy=gr.length?gr.reduce((a,g)=>a+((g.n1+g.n2)/2)*g.coef,0)/tc:null;
  const ap=moy!==null?getAppr(moy):null;
  // Calcul rang
  let rang='—',classEff=DB.students.filter(st=>st.cls===s.cls).length;
  if(moy!==null){
    const allMoy=DB.students.filter(st=>st.cls===s.cls).map(st=>{const gG=DB.grades.filter(g=>g.eid===st.id&&g.tri===selT);const tC=gG.reduce((a,g)=>a+g.coef,0)||1;return gG.length?gG.reduce((a,g)=>a+((g.n1+g.n2)/2)*g.coef,0)/tC:null;}).filter(m=>m!==null).sort((a,b)=>b-a);
    rang=allMoy.findIndex(m=>Math.abs(m-moy)<0.001)+1;
  }
  return`<div class="fl2 fic g8 mb20 fw">
    ${TRS.map(t=>`<button class="tab${t===selT?' on':''}" onclick="window._bT='${t}';re()">${t}</button>`).join("")}
    <button class="btn bi sm" onclick="printBulletin('${s.id}','${selT}')">🖨️ Imprimer bulletin</button>
  </div>
  <div class="card mb16" style="background:linear-gradient(135deg,#142554,#1a3a8a);color:#fff;border:none;padding:22px">
    <div class="fl2 fic fsb fw g12">
      <div class="fl2 fic g12"><img src="${getLogo()}" alt="" style="width:46px;height:46px;border-radius:50%;background:#fff;padding:3px">
        <div><div style="font-family:'Libre Baskerville',serif;font-size:18px;color:#FFC93C">${s.pre} ${s.nom}</div>
        <div style="font-size:13px;color:rgba(255,255,255,.5);margin-top:2px">Matricule: ${s.mat} · Classe: ${s.cls}</div></div>
      </div>
      <div class="fl2 g16 fw">
        <div style="text-align:center"><div style="font-size:9px;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:1px">Moyenne</div><div class="mono bold" style="font-size:28px;color:${ap?.col||'#fff'}">${moy!==null?moy.toFixed(2):'—'}</div><div style="font-size:13px;color:${ap?.col||'rgba(255,255,255,.5)'}">${ap?.lbl||'—'}</div></div>
        <div style="text-align:center"><div style="font-size:9px;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:1px">Rang</div><div class="mono bold" style="font-size:28px;color:#FFC93C">${rang}</div><div style="font-size:13px;color:rgba(255,255,255,.4)">sur ${classEff} élèves</div></div>
      </div>
    </div>
  </div>
  ${gr.length===0?'<div class="empty card"><div class="empty-ico">📄</div>Aucune note pour ce trimestre</div>':
  `<div class="card"><div class="ct">Résultats détaillés — ${selT}</div>
    <div class="tw"><table>
      <thead><tr><th>Matière</th><th>Coef.</th><th>Devoir 1</th><th>Devoir 2</th><th>Moyenne</th><th>Appréc.</th></tr></thead>
      <tbody>${gr.map(g=>{const m=(g.n1+g.n2)/2;const ap2=getAppr(m);return`<tr>
        <td><div class="semi s">${g.sub}</div><div class="xs2 mut">${g.ens||'—'}</div></td>
        <td class="mono xs2">${g.coef}</td>
        <td class="mono s">${g.n1}/20</td>
        <td class="mono s">${g.n2}/20</td>
        <td class="mono bold s" style="color:${ap2.col}">${m.toFixed(2)}/20</td>
        <td><span class="bg" style="background:${ap2.col}20;color:${ap2.col};border:1px solid ${ap2.col}44">${ap2.lbl}</span></td>
      </tr>`;}).join("")}</tbody>
      <tfoot><tr style="background:var(--bg2)"><td colspan="2" class="semi">Moyenne générale</td><td colspan="3" class="mono bold" style="font-size:16px;color:${ap?.col}">${moy!==null?moy.toFixed(2)+'/20':'—'}</td><td><span class="bg bgb">${ap?.lbl||'—'}</span></td></tr></tfoot>
    </table></div>
  </div>`}`;
}

function pgMesAbsences(){
  const s=SES;
  const abs=DB.absences.filter(a=>a.eid===s.id);
  const totH=abs.reduce((a,b)=>a+b.heures,0);
  const njust=abs.filter(a=>!a.justifie).length;
  const jjust=abs.filter(a=>a.justifie).length;
  return`<div class="sg" style="grid-template-columns:repeat(3,1fr)">
    <div class="sc scr"><div class="sci">⏱️</div><div class="scl">Total heures d\'absence</div><div class="scv vr">${totH}h</div></div>
    <div class="sc scr"><div class="sci">❌</div><div class="scl">Non justifiées</div><div class="scv vr">${njust}</div></div>
    <div class="sc scgr"><div class="sci">✅</div><div class="scl">Justifiées</div><div class="scv vgr">${jjust}</div></div>
  </div>
  ${njust>0?`<div class="ib ibr mb14"><span>⚠️</span><span>Vous avez <strong>${njust} absence${njust>1?'s':''} non justifiée${njust>1?'s':''}</strong>. Veuillez fournir un justificatif à l\'administration dès que possible.</span></div>`:''}
  <div class="card">
    <div class="ct">Historique des absences</div>
    ${abs.length===0?'<div class="empty"><div class="empty-ico">✅</div>Aucune absence enregistrée. Félicitations !</div>':
    abs.sort((a,b)=>b.date.localeCompare(a.date)).map(a=>`<div class="abs-item">
      <div class="abs-dot ${a.justifie?'abs-ok':'abs-nok'}"></div>
      <div style="flex:1">
        <div class="fl2 fic fsb"><div class="semi s">${a.date}</div><span class="bg ${a.justifie?'bgg':'bgr'}">${a.justifie?'Justifiée':'Non justifiée'}</span></div>
        <div class="xs2 mut mt4">${a.matiere||'—'} · ${a.heures}h · ${a.motif||'—'}</div>
      </div>
    </div>`).join("")}
  </div>`;
}

function pgMesDevoirs(){
  const s=SES;
  const dvsE=DB.devoirs.filter(d=>d.cls===s.cls).sort((a,b)=>new Date(a.dateLimit)-new Date(b.dateLimit));
  const subs=DB.submissions.filter(sb=>sb.eid===s.id);
  const selF=window._dvF||'Tous';
  const dvsFilt=dvsE.filter(d=>{const submitted=subs.find(sb=>sb.dvid===d.id);if(selF==='À rendre')return!submitted;if(selF==='Rendus')return submitted;return true;});
  return`<div class="fl2 fic g8 mb16 fw">
    <div class="tabs">${['Tous','À rendre','Rendus'].map(f=>`<button class="tab${f===selF?' on':''}" onclick="window._dvF='${f}';re()">${f}</button>`).join("")}</div>
  </div>
  ${dvsFilt.length===0?'<div class="empty card"><div class="empty-ico">📋</div>Aucun devoir dans cette catégorie</div>':
  dvsFilt.map(d=>{const sub=subs.find(sb=>sb.dvid===d.id);const dl=new Date(d.dateLimit);const j=Math.ceil((dl-new Date())/864e5);const cls2=j<0?'dv-late':j<=3?'dv-warn':'dv-ok';
    return`<div class="card mb14">
      <div class="fl2 fic fsb mb12 fw g8">
        <div><div class="fl2 fic g8"><span class="bg bgb">${d.sub}</span><span class="bg bgt">${d.cls}</span>${sub?'<span class="bg bgg">✓ Rendu</span>':''}</div><div class="semi s mt8">${d.titre}</div></div>
        <span class="dv-deadline ${sub?'dv-ok':cls2}">${sub?'Rendu':(j<0?'En retard':(j===0?'Aujourd\'hui':`dans ${j}j`))}</span>
      </div>
      <div style="font-size:13px;color:var(--ink2);line-height:1.7;margin-bottom:12px">${d.desc}</div>
      <div class="fl2 fic fsb xs2 mut">
        <span>📅 Limite: ${dl.toLocaleDateString('fr-FR')}</span>
        ${sub?`<span class="bg bgg">📬 Soumis le ${sub.date||'—'}</span>`:''}
        ${sub?.note?`<span class="mono bold" style="color:var(--gold)">Note: ${sub.note}/20</span>`:''}
      </div>
      ${!sub?`<div style="margin-top:12px;padding-top:12px;border-top:var(--br)">
        <div class="fg mb8"><span class="fl">Ma réponse / commentaire</span><textarea class="fi" id="subText_${d.id}" rows="3" placeholder="Entrez votre réponse ou commentaire..."></textarea></div>
        <button class="btn bgr2 sm" onclick="submitDevoir('${d.id}')">📬 Soumettre</button>
      </div>`:(sub.commentaire?`<div class="ib ibg mt12 mb0"><span>💬</span><span>${sub.commentaire}</span></div>`:'')
      }
    </div>`;}).join("")}`;
}

function submitDevoir(dvid){
  const s=SES;const txt=($(`subText_${dvid}`)?.value||'').trim();
  if(DB.submissions.find(sb=>sb.dvid===dvid&&sb.eid===s.id)){toast('Devoir déjà soumis','warn');return;}
  DB.submissions.push({id:gid(),dvid,eid:s.id,date:today(),contenu:txt,note:null,commentaire:''});
  save();re();toast('✓ Devoir soumis avec succès');
}

function pgMonPaiement(){
  const s=SES;const pays=DB.payments.filter(p=>p.eid===s.id);
  const tpays=pays.filter(p=>p.stat==='Payé').reduce((a,p)=>a+p.mnt,0);
  const purchases=DB.bookPurchases?.filter(bp=>bp.eid===s.id)||[];
  return`<div class="sg" style="grid-template-columns:repeat(3,1fr)">
    <div class="sc ${s.stat==='Payé'?'scgr':'scr'}"><div class="sci">💳</div><div class="scl">Statut actuel</div><div class="scv ${s.stat==='Payé'?'vgr':'vr'}" style="font-size:16px">${s.stat}</div><div class="scs">${fmt(s.frais)}/mois</div></div>
    <div class="sc scgr"><div class="sci">✅</div><div class="scl">Total versé</div><div class="scv vgr" style="font-size:18px">${fmt(tpays)}</div></div>
    <div class="sc scb"><div class="sci">📚</div><div class="scl">Achats manuels</div><div class="scv vb">${purchases.length}</div><div class="scs">${fmt(purchases.reduce((a,b)=>a+b.mnt,0))}</div></div>
  </div>
  ${s.stat!=='Payé'?`<div class="ib ibr mb14"><span>⚠️</span><span>Votre paiement du mois est en attente. Veuillez vous rendre à l\'administration pour régulariser votre situation.</span></div>`:''}
  <div class="card mb16"><div class="ct">Historique des paiements de scolarité</div>
    ${pays.length===0?'<div class="empty">Aucun paiement enregistré</div>':
    `<div class="tw"><table><thead><tr><th>Période</th><th>Montant</th><th>Mode</th><th>Date</th><th>Statut</th><th></th></tr></thead>
    <tbody>${pays.map(p=>`<tr>
      <td class="semi s">${p.mo}</td>
      <td class="mono bold" style="color:var(--gold)">${fmt(p.mnt)}</td>
      <td class="xs2">${p.mode}</td>
      <td class="xs2 mut">${p.dt||'—'}</td>
      <td><span class="bg ${p.stat==='Payé'?'bgg':p.stat==='Impayé'?'bgr':'bgo'}">${p.stat}</span></td>
      <td>${p.stat==='Payé'?`<button class="btn bo xs" onclick="printRec('${p.id}')">🧾 Reçu</button>`:''}</td>
    </tr>`).join("")}</tbody></table></div>`}
  </div>
  ${purchases.length>0?`<div class="card"><div class="ct">Achats de manuels</div>
    <div class="tw"><table><thead><tr><th>Manuel</th><th>Montant</th><th>Date</th><th>Statut</th></tr></thead>
    <tbody>${purchases.map(bp=>{const b=DB.books.find(x=>x.id===bp.bid);return`<tr>
      <td><span style="font-size:18px">${b?.ico||'📚'}</span> <span class="semi s">${b?.titre||'—'}</span></td>
      <td class="mono bold" style="color:var(--gold)">${fmt(bp.mnt)}</td>
      <td class="xs2 mut">${bp.date||'—'}</td>
      <td><span class="bg bgg">${bp.statut}</span></td>
    </tr>`;}).join("")}</tbody></table></div>
  </div>`:''}`;
}

function pgBoutique(){
  const s=SES;const purchases=DB.bookPurchases?.filter(bp=>bp.eid===s.id)||[];
  const purchasedIds=purchases.map(bp=>bp.bid);
  return`<div class="ib ibt mb16"><span>📚</span><span>Achetez vos manuels scolaires directement en ligne. Les manuels achetés seront disponibles auprès de l\'administration pour récupération physique.</span></div>
  <div class="bgrid">
    ${DB.books.map(b=>{const owned=purchasedIds.includes(b.id);return`<div class="bc">
      <div class="bcover" style="background:var(--blb)">${b.ico}</div>
      <div style="padding:12px">
        <div class="semi s mb4">${b.titre}</div>
        <div style="font-size:13px;color:var(--ink4);margin-bottom:6px">${b.cls} · ${b.auteur}</div>
        <div style="font-size:13px;color:var(--ink4);margin-bottom:8px">${b.pages} pages</div>
        <div class="fl2 fic fsb">
          <span class="mono bold s" style="color:var(--gold)">${fmt(b.prix)}</span>
          <span class="bg ${b.stock>0?'bgg':'bgr'}" style="font-size:12px">${b.stock>0?b.stock+' dispo':'Rupture'}</span>
        </div>
        ${owned?'<div class="ib ibg mt8 mb0" style="font-size:12px"><span>✅</span><span>Déjà acheté</span></div>':(b.stock>0?`<button class="btn bi sm mt8" style="width:100%;justify-content:center" onclick="acheterManuel('${b.id}')">🛒 Acheter</button>`:`<button class="btn" style="width:100%;justify-content:center;background:var(--bg3);color:var(--ink4);cursor:not-allowed;padding:5px" disabled>Rupture de stock</button>`)}
      </div>
    </div>`;}).join("")}
  </div>`;
}

function acheterManuel(bid){
  const s=SES;const b=DB.books.find(x=>x.id===bid);if(!b||b.stock<=0){toast('Rupture de stock','warn');return;}
  if(DB.bookPurchases.find(bp=>bp.eid===s.id&&bp.bid===bid)){toast('Vous avez déjà acheté ce manuel','warn');return;}
  M('Acheter ce manuel',b.titre,`<div class="vcard" style="text-align:center;margin-bottom:14px"><div style="font-size:48px;margin-bottom:8px">${b.ico}</div><div class="bold s">${b.titre}</div><div class="xs2 mut">${b.cls} · ${b.auteur} · ${b.pages} pages</div></div>
    <div style="padding:14px;background:var(--gp);border-radius:var(--r2);border:1px solid var(--gb);text-align:center"><div class="mono bold" style="font-size:24px;color:var(--gold)">${fmt(b.prix)}</div><div class="xs2 mut mt4">Prix d\'achat</div></div>
    <div class="ib ibt mt14 mb0"><span>ℹ️</span><span>Votre commande sera enregistrée. Rendez-vous à l\'administration pour récupérer votre manuel et effectuer le paiement.</span></div>`,
  `<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="confirmerAchat('${bid}')">✓ Confirmer la commande</button>`);
}

function confirmerAchat(bid){
  const s=SES;const b=DB.books.find(x=>x.id===bid);if(!b)return;
  b.vendu++;b.stock--;
  const ref='BOOK-'+Math.floor(Math.random()*90000+10000);
  DB.bookPurchases.push({id:gid(),eid:s.id,bid,date:today(),mnt:b.prix,statut:'En attente de paiement',ref});
  save();cm();re();
  // v1.0 : ouvrir directement le modal de paiement au lieu d'un simple toast
  setTimeout(function(){
    if(typeof openPaymentModal === 'function'){
      openPaymentModal({
        montant: b.prix,
        label: '📚 '+b.titre+' ('+b.cls+')',
        ref: ref,
        refPrefix: 'BOOK',
        // ── v1.2 : metadata pour activation automatique ──
        intent: 'book',
        targetId: bid,
        customerAccountId: s?(s.accountId||s.id):null,
        customerNom: s?(s.pre+' '+s.nom):'',
        customerTel: s?s.tel:''
      });
    } else {
      toast('✓ Commande enregistrée ! Passez à l\'administration');
    }
  }, 100);
}

// ═══════════════════════════════════════════════
// ESPACE ENSEIGNANT — DEVOIRS
// ═══════════════════════════════════════════════
function pgDevoirsTeacher(){
  if(!isEnseignant())return na();
  const t=T(SES.tid);
  const myDvs=DB.devoirs.filter(d=>d.tid===SES.tid);
  return`<div class="fl2 fic fsb mb16"><div class="bold">Mes devoirs proposés</div><button class="btn bi" onclick="mAddDevoir()">＋ Nouveau devoir</button></div>
  ${myDvs.length===0?'<div class="card"><div class="empty"><div class="empty-ico">📋</div>Aucun devoir proposé</div></div>':myDvs.map(d=>{const subs=DB.submissions.filter(sb=>sb.dvid===d.id);const dl=new Date(d.dateLimit);const j=Math.ceil((dl-new Date())/864e5);
    return`<div class="card mb14">
      <div class="fl2 fic fsb mb8 fw g8">
        <div class="fl2 fic g8 fw"><span class="bg bgb">${d.sub}</span><span class="bg bgt">${d.cls}</span><span class="bg bgd">${d.tri}</span></div>
        <div class="fl2 g6"><button class="btn bo xs" onclick="viewSubs('${d.id}')">📬 ${subs.length} soum.</button><button class="btn br2 xs" onclick="delDevoir('${d.id}')">🗑</button></div>
      </div>
      <div class="semi s mb4">${d.titre}</div>
      <div style="font-size:13px;color:var(--ink2);margin-bottom:10px">${d.desc}</div>
      <div class="xs2 mut">📅 Limite: ${dl.toLocaleDateString('fr-FR')} · ${j<0?'<span style="color:var(--re)">Délai dépassé</span>':`dans ${j}j`}</div>
    </div>`;}).join("")}`;
}

function mAddDevoir(){
  const t=T(SES.tid);const cls=[...new Set(DB.students.map(s=>s.cls))];
  M('Nouveau devoir',t?.mat2||t?.mat,`<div class="fg2">
    <div class="fg"><span class="fl">Classe *</span><select class="fi" id="dvCls">${cls.map(c=>`<option>${c}</option>`).join("")}</select></div>
    <div class="fg"><span class="fl">Trimestre</span><select class="fi" id="dvTri">${TRS.map(tr=>`<option>${tr}</option>`).join("")}</select></div>
    <div class="fg full"><span class="fl">Titre du devoir *</span><input class="fi" id="dvTitre" placeholder="Ex: Exercices chapitre 5"></div>
    <div class="fg full"><span class="fl">Description / Instructions *</span><textarea class="fi" id="dvDesc" rows="4" placeholder="Décrivez le travail à effectuer..."></textarea></div>
    <div class="fg"><span class="fl">Date limite *</span><input class="fi" id="dvDl" type="date"></div>
  </div>`,
  `<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveDevoir()">✓ Publier le devoir</button>`);
}

function saveDevoir(){
  const t=T(SES.tid);
  const titre=($("dvTitre")?.value||"").trim(),desc=($("dvDesc")?.value||"").trim(),dl=$("dvDl")?.value;
  if(!titre||!desc||!dl){toast('Tous les champs requis','warn');return;}
  DB.devoirs.push({id:gid(),tid:SES.tid,sub:t?.mat2||t?.mat||'—',cls:$("dvCls").value,titre,desc,dateLimit:dl,tri:$("dvTri").value,note:null});
  save();cm();re();toast('✓ Devoir publié avec succès');
}

function delDevoir(dvid){if(!confirm('Supprimer ce devoir ? Les soumissions associées seront aussi supprimées.'))return;DB.devoirs=DB.devoirs.filter(d=>d.id!==dvid);DB.submissions=DB.submissions.filter(sb=>sb.dvid!==dvid);save();re();toast('Devoir supprimé','warn');}

function viewSubs(dvid){
  const dv=DB.devoirs.find(d=>d.id===dvid);if(!dv)return;
  const subs=DB.submissions.filter(sb=>sb.dvid===dvid);
  const cls=DB.students.filter(s=>s.cls===dv.cls);
  M(`Soumissions — ${dv.titre}`,`${dv.cls} · ${dv.sub} · ${subs.length}/${cls.length} soumissions`,
    subs.length===0?`<div class="empty"><div class="empty-ico">📭</div>Aucune soumission reçue</div>`:
    subs.map(sb=>{const st=S(sb.eid);return`<div style="padding:12px;border:var(--br);border-radius:var(--r2);margin-bottom:10px">
      <div class="fl2 fic fsb mb8"><div class="semi s">${_esc(st?.pre||'')} ${_esc(st?.nom||'')}</div><span class="xs2 mut">${_esc(sb.date||'')}</span></div>
      ${sb.contenu?`<div style="font-size:13px;color:var(--ink2);background:var(--bg2);padding:10px;border-radius:var(--r);margin-bottom:8px;white-space:pre-wrap">${_esc(sb.contenu)}</div>`:''}
      <div class="fl2 fic g8">
        <div class="fg" style="flex:1"><input type="number" min="0" max="20" step="0.5" placeholder="Note /20" value="${sb.note||''}" id="note_${sb.id}" style="width:90px;padding:7px;border:1.5px solid var(--bg3);border-radius:6px;outline:none;font-size:13px"></div>
        <div class="fg" style="flex:2"><input type="text" placeholder="Commentaire optionnel" value="${_esc(sb.commentaire||'')}" id="comm_${sb.id}" class="fi"></div>
        <button class="btn bgr2 sm" onclick="saveNote_sb('${sb.id}')">💾 Noter</button>
      </div>
    </div>`;}).join(""),
  `<button class="btn bo" onclick="cm()">Fermer</button>`);
}

function saveNote_sb(sbid){const sb=DB.submissions.find(s=>s.id===sbid);if(!sb)return;const n=parseFloat($(`note_${sbid}`)?.value);if(!isNaN(n)&&n>=0&&n<=20)sb.note=n;sb.commentaire=$(`comm_${sbid}`)?.value||'';save();toast('✓ Note enregistrée');}

// ═══════════════════════════════════════════════
// ESPACE ENSEIGNANT — PERFORMANCES
// ═══════════════════════════════════════════════
function pgPerfTeacher(){
  if(!isEnseignant())return na();
  const t=T(SES.tid);const sub=t?.mat2||t?.mat;
  const selT=window._pT||TRS[0];
  const selC=window._pC||'Toutes';
  const allCls=[...new Set(DB.students.map(s=>s.cls))];
  const myGrades=DB.grades.filter(g=>g.sub===sub&&g.tri===selT&&(selC==='Toutes'||g.cls===selC));
  const stats=myGrades.map(g=>{const m=(g.n1+g.n2)/2;return{...g,moy:m};});
  const avg=stats.length?stats.reduce((a,b)=>a+b.moy,0)/stats.length:null;
  const dist=[{label:'Excellent (≥18)',col:'var(--gr)',fn:m=>m>=18},{label:'Très Bien (16-17)',col:'#228844',fn:m=>m>=16&&m<18},{label:'Bien (14-15)',col:'var(--bl)',fn:m=>m>=14&&m<16},{label:'Assez Bien (12-13)',col:'#3a70d0',fn:m=>m>=12&&m<14},{label:'Passable (10-11)',col:'var(--or)',fn:m=>m>=10&&m<12},{label:'Insuffisant (<10)',col:'var(--re)',fn:m=>m<10}];
  return`<div class="fl2 fic g12 mb20 fw">
    <div class="fg"><span class="fl">Classe</span><select class="fi" onchange="window._pC=this.value;re()">${['Toutes',...allCls].map(c=>`<option${c===selC?' selected':''}>${c}</option>`).join("")}</select></div>
    <div class="fg"><span class="fl">Trimestre</span><select class="fi" onchange="window._pT=this.value;re()">${TRS.map(tr=>`<option${tr===selT?' selected':''}>${tr}</option>`).join("")}</select></div>
  </div>
  <div class="sg" style="grid-template-columns:repeat(3,1fr)">
    <div class="sc scb"><div class="sci">📝</div><div class="scl">Notes saisies</div><div class="scv vb">${stats.length}</div></div>
    <div class="sc scg"><div class="sci">📊</div><div class="scl">Moyenne ${sub}</div><div class="scv vg">${avg!==null?avg.toFixed(2):'—'}</div></div>
    <div class="sc ${avg!==null&&avg>=10?'scgr':'scr'}"><div class="sci">✅</div><div class="scl">Taux de réussite</div><div class="scv ${avg!==null&&avg>=10?'vgr':'vr'}">${stats.length>0?Math.round(stats.filter(g=>g.moy>=10).length/stats.length*100):0}%</div></div>
  </div>
  <div class="g2">
    <div class="card"><div class="ct">Distribution des notes</div>
      ${dist.map(d=>{const n=stats.filter(g=>d.fn(g.moy)).length;const pct=stats.length?Math.round(n/stats.length*100):0;return`<div class="mb12"><div class="fl2 fic fsb mb6"><span class="s">${d.label}</span><span class="mono xs2" style="color:${d.col}">${n} élève${n>1?'s':''} (${pct}%)</span></div><div class="pb"><div class="pf" style="width:${pct}%;background:${d.col}"></div></div></div>`;}).join("")}
    </div>
    <div class="card"><div class="ct">Classement par élève</div>
      ${stats.sort((a,b)=>b.moy-a.moy).slice(0,10).map((g,i)=>{const ap2=getAppr(g.moy);return`<div class="fl2 fic fsb" style="padding:7px 0;border-bottom:1px solid var(--bg2)">
        <div class="fl2 fic g8"><div style="width:22px;height:22px;border-radius:50%;background:${i<3?'var(--gp)':'var(--bg3)'};color:${i<3?'var(--gold)':'var(--ink4)'};display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700">${i+1}</div>
        <div><div class="semi s">${g.enom}</div><div class="xs2 mut">${g.cls}</div></div></div>
        <span class="mono bold" style="color:${ap2.col}">${g.moy.toFixed(2)}/20</span>
      </div>`;}).join("")}
    </div>
  </div>`;
}

// ═══════════════════════════════════════════════
// ADMIN — ABSENCES
// ═══════════════════════════════════════════════
function pgAbsencesAdmin(){
  if(!iA())return na();
  const selCls=window._abCls||'Toutes';const selE=window._abE||'Tous';const allCls=[...new Set(DB.students.map(s=>s.cls))];
  const filtAbs=DB.absences.filter(a=>{const st=S(a.eid);if(selCls!=='Toutes'&&st?.cls!==selCls)return false;if(selE!=='Tous'&&a.eid!==selE)return false;return true;});
  const stFilt=selCls==='Toutes'?DB.students:DB.students.filter(s=>s.cls===selCls);
  return`<div class="fl2 fic fsb mb16 fw g8">
    <div class="fl2 fic g8 fw">
      <div class="fg"><span class="fl">Classe</span><select class="fi" style="min-width:130px" onchange="window._abCls=this.value;window._abE='Tous';re()">${['Toutes',...allCls].map(c=>`<option${c===selCls?' selected':''}>${c}</option>`).join("")}</select></div>
      <div class="fg"><span class="fl">Élève</span><select class="fi" style="min-width:200px" onchange="window._abE=this.value;re()"><option value="Tous">Tous les élèves</option>${stFilt.map(s=>`<option value="${s.id}"${s.id===selE?' selected':''}>${s.pre} ${s.nom}</option>`).join("")}</select></div>
    </div>
    <button class="btn bi" onclick="mAddAbsence()">＋ Saisie individuelle</button>
    <button class="btn bg2" onclick="mBulkAbsence()">📋 Saisie par liste</button>
  </div>
  <div class="sg" style="grid-template-columns:repeat(3,1fr)">
    <div class="sc scr"><div class="sci">⏱️</div><div class="scl">Total heures</div><div class="scv vr">${filtAbs.reduce((a,b)=>a+b.heures,0)}h</div></div>
    <div class="sc scr"><div class="sci">❌</div><div class="scl">Non justifiées</div><div class="scv vr">${filtAbs.filter(a=>!a.justifie).length}</div></div>
    <div class="sc scgr"><div class="sci">✅</div><div class="scl">Justifiées</div><div class="scv vgr">${filtAbs.filter(a=>a.justifie).length}</div></div>
  </div>
  <div class="card">
    <div class="tw"><table>
      <thead><tr><th>Élève</th><th>Classe</th><th>Date</th><th>Matière</th><th>Heures</th><th>Motif</th><th>Statut</th><th></th></tr></thead>
      <tbody>${filtAbs.length===0?`<tr><td colspan="8"><div class="empty">Aucune absence</div></td></tr>`:filtAbs.map(a=>{const st=S(a.eid);return`<tr>
        <td class="semi s">${st?.pre||''} ${st?.nom||''}</td>
        <td><span class="bg bgd">${st?.cls||'—'}</span></td>
        <td class="xs2 mut">${a.date}</td>
        <td class="xs2">${a.matiere||'—'}</td>
        <td class="mono bold" style="color:var(--re)">${a.heures}h</td>
        <td class="xs2">${a.motif||'—'}</td>
        <td><span class="bg ${a.justifie?'bgg':'bgr'}">${a.justifie?'Justifiée':'Non justifiée'}</span></td>
        <td><div class="fl2 g4"><button class="btn bo xs" onclick="toggleJustif('${a.id}')">${a.justifie?'❌ Annuler':'✅ Justifier'}</button><button class="btn br2 xs" onclick="delAbsence('${a.id}')">🗑</button></div></td>
      </tr>`;}).join("")}</tbody>
    </table></div>
  </div>`;
}

function mAddAbsence(){
  const cls=[...new Set(DB.students.map(s=>s.cls))];
  M('Enregistrer une absence','Saisie de présence',`<div class="fg2">
    <div class="fg"><span class="fl">Classe</span><select class="fi" id="abCls" onchange="updateStudentList()">${cls.map(c=>`<option>${c}</option>`).join("")}</select></div>
    <div class="fg"><span class="fl">Élève *</span><select class="fi" id="abEtu"></select></div>
    <div class="fg"><span class="fl">Date *</span><input class="fi" id="abDate" type="date" value="${new Date().toISOString().split('T')[0]}"></div>
    <div class="fg"><span class="fl">Heures *</span><input class="fi" id="abH" type="number" min="1" max="8" value="2"></div>
    <div class="fg"><span class="fl">Matière</span><select class="fi" id="abMat">${SUBS.map(s=>`<option>${s}</option>`).join("")}</select></div>
    <div class="fg"><span class="fl">Motif</span><input class="fi" id="abMotif" placeholder="Ex: Maladie, Voyage..."></div>
    <div class="fg full"><label style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="abJust"> <span class="fl">Absence justifiée</span></label></div>
  </div>`,
  `<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveAbsence()">✓ Enregistrer</button>`);
  setTimeout(()=>updateStudentList(),100);
}

function updateStudentList(){const cls=$("abCls")?.value;const stl=$("abEtu");if(!stl)return;const sts=DB.students.filter(s=>s.cls===cls);stl.innerHTML=sts.map(s=>`<option value="${s.id}">${s.pre} ${s.nom}</option>`).join("");}

function saveAbsence(){
  const eid=$("abEtu")?.value,h=parseInt($("abH")?.value)||2,date=$("abDate")?.value;
  if(!eid||!date){toast('Élève et date requis','warn');return;}
  const dFr=new Date(date).toLocaleDateString('fr-FR');
  DB.absences.push({id:gid(),eid,date:dFr,heures:h,matiere:$("abMat")?.value||'—',motif:$("abMotif")?.value||'—',justifie:$("abJust")?.checked||false});
  save();cm();re();toast('✓ Absence enregistrée');
}
function mBulkAbsence(){
  var cls=window._abCls||[...new Set(DB.students.map(function(s){return s.cls;}))][0];
  var sts=DB.students.filter(function(s){return s.cls===cls;}).sort(function(a,b){return(a.nom+a.pre).localeCompare(b.nom+b.pre);});
  var rows=sts.map(function(s,i){
    return '<tr><td class="xs2 mut">'+(i+1)+'</td><td class="semi">'+s.pre+' '+s.nom+'</td><td><input type="checkbox" class="abCheck" data-sid="'+s.id+'"></td><td><input class="fi" style="padding:4px;width:50px;text-align:center" type="number" min="1" max="8" value="2" data-h="'+s.id+'"></td><td><input class="fi" style="padding:4px;width:120px" placeholder="Motif" data-m="'+s.id+'"></td></tr>';
  }).join('');
  M('📋 Saisie des absences par liste',cls+' — '+today(),
  '<div class="fl2 fic g8 mb13"><div class="fg"><span class="fl">Classe</span><select class="fi" onchange="window._abCls=this.value;cm();mBulkAbsence()">'+CLS.map(function(cl){return '<option'+(cl===cls?' selected':'')+'>'+cl+'</option>';}).join('')+'</select></div><div class="fg"><span class="fl">Matière</span><select class="fi" id="bAbMat">'+SUBS.map(function(s){return '<option>'+s+'</option>';}).join('')+'</select></div><div class="fg"><span class="fl">Date</span><input class="fi" id="bAbDate" type="date" value="'+new Date().toISOString().split('T')[0]+'"></div></div>'+
  '<div class="ib ibt mb13"><span>✅</span><span>Cochez les élèves absents et indiquez le nombre d\'heures.</span></div>'+
  '<div class="tw"><table><thead><tr><th>#</th><th>Élève</th><th>Absent</th><th>Heures</th><th>Motif</th></tr></thead><tbody>'+rows+'</tbody></table></div>',
  '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveBulkAbsence()">✓ Enregistrer les absences</button>',true);
}
function saveBulkAbsence(){
  var checks=document.querySelectorAll('.abCheck:checked');
  var date=document.getElementById('bAbDate')?.value||today();
  var mat=document.getElementById('bAbMat')?.value||'';
  var count=0;
  checks.forEach(function(cb){
    var sid=cb.getAttribute('data-sid');
    var h=parseInt(document.querySelector('[data-h="'+sid+'"]')?.value)||2;
    var m=document.querySelector('[data-m="'+sid+'"]')?.value||'';
    DB.absences.push({id:gid(),eid:sid,date:date,heures:h,matiere:mat,motif:m,justifie:false});
    count++;
  });
  if(count)save();cm();re();toast(count+' absence(s) enregistrée(s)');
}

function toggleJustif(abid){const a=DB.absences.find(x=>x.id===abid);if(a){a.justifie=!a.justifie;save();re();}}
function delAbsence(abid){if(!confirm('Supprimer cette absence ?'))return;DB.absences=DB.absences.filter(a=>a.id!==abid);save();re();}

// ═══════════════════════════════════════════════
// ADMIN — DEVOIRS
// ═══════════════════════════════════════════════
function pgDevoirsAdmin(){
  if(!iA())return na();
  const selT=window._daT||'Tous';const dvsFilt=selT==='Tous'?DB.devoirs:DB.devoirs.filter(d=>d.tri===selT);
  return`<div class="fl2 fic fsb mb16 fw g8">
    <div class="tabs">${['Tous',...TRS].map(t=>`<button class="tab${t===selT?' on':''}" onclick="window._daT='${t}';re()">${t}</button>`).join("")}</div>
  </div>
  <div class="card">
    <div class="tw"><table>
      <thead><tr><th>Enseignant</th><th>Matière</th><th>Classe</th><th>Devoir</th><th>Date limite</th><th>Soumissions</th><th></th></tr></thead>
      <tbody>${dvsFilt.length===0?`<tr><td colspan="7"><div class="empty">Aucun devoir</div></td></tr>`:dvsFilt.map(d=>{const t=T(d.tid);const subs=DB.submissions.filter(sb=>sb.dvid===d.id);const dl=new Date(d.dateLimit);const j=Math.ceil((dl-new Date())/864e5);return`<tr>
        <td class="semi s">${t?.pre||''} ${t?.nom||''}</td>
        <td><span class="bg bgb">${d.sub}</span></td>
        <td><span class="bg bgd">${d.cls}</span></td>
        <td><div class="semi s">${d.titre}</div><div class="xs2 mut">${d.desc.substring(0,60)}${d.desc.length>60?'...':''}...</div></td>
        <td class="xs2 mut">${dl.toLocaleDateString('fr-FR')} ${j<0?'<span style="color:var(--re);font-weight:700"> · Passé</span>':''}  </td>
        <td><span class="bg ${subs.length>0?'bgg':'bgt'}">${subs.length} soum.</span></td>
        <td><button class="btn bo xs" onclick="viewSubs('${d.id}')">📬 Voir</button></td>
      </tr>`;}).join("")}</tbody>
    </table></div>
  </div>`;
}

