function mAddAdmin(){
  M('Créer un administrateur','Nouveau compte admin',
  '<div class="fg2">'+
  '<div class="fg"><span class="fl">Identifiant *</span><input class="fi" id="naUser" placeholder="ex: comptable"></div>'+
  '<div class="fg"><span class="fl">Mot de passe *</span><input class="fi" id="naPwd" type="text" autocomplete="off" placeholder="Mot de passe fort (8+ caractères)"></div>'+
  '<div class="fg"><span class="fl">Nom complet *</span><input class="fi" id="naNom" placeholder="M./Mme ..."></div>'+
  '<div class="fg"><span class="fl">Rôle / Fonction</span><select class="fi" id="naRole"><option>Administrateur</option><option>Secrétaire</option><option>Comptable</option><option>Surveillant</option><option>Censeur</option></select></div>'+
  '</div>',
  '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveNewAdmin()">✓ Créer le compte</button>');
}
async function saveNewAdmin(){
  var user=(document.getElementById('naUser')?.value||'').trim();
  var pwd=document.getElementById('naPwd')?.value||'';
  var nom=(document.getElementById('naNom')?.value||'').trim();
  var role=document.getElementById('naRole')?.value||'Administrateur';
  if(!user||!pwd||!nom){toast('Tous les champs requis','warn');return;}
  if(pwd.length<8){toast('Mot de passe : minimum 8 caractères','warn');return;}
  if(DB.admins.find(function(a){return a.user===user;})){toast('Identifiant déjà utilisé','warn');return;}
  // FIX sécurité : hash AVANT save() pour ne jamais pousser de plain text vers Firebase
  try{
    var hashed=await hashPassword(pwd,user);
    DB.admins.push({id:gid(),user:user,pwd:hashed,nom:nom,role:role,role2:'admin'});
    save();autoNotify('Nouvel administrateur','Un nouveau compte admin a été créé: '+nom+' ('+role+')','all');cm();re();toast('✓ Administrateur '+nom+' créé');
  }catch(e){toast('Erreur hash mot de passe : '+e.message,'warn');}
}
async function promoteToAdmin(tid){
  var t=T(tid);if(!t)return;
  if(DB.admins.find(function(a){return a.user===t.user;})){toast('Déjà administrateur','warn');return;}
  if(!confirm('Promouvoir '+t.pre+' '+t.nom+' au rang d\'administrateur ?'))return;
  // FIX sécurité : si DB.tpwd contient déjà un hash, le réutiliser ; sinon refuser
  var existingPwd=DB.tpwd[t.user];
  if(!existingPwd){toast('Cet enseignant n\'a pas de mot de passe défini','warn');return;}
  // Si plain text, hasher ; si déjà hashé, garder tel quel
  var finalPwd;
  if(isHashed(existingPwd)){finalPwd=existingPwd;}
  else{
    try{finalPwd=await hashPassword(existingPwd,t.user);DB.tpwd[t.user]=finalPwd;}
    catch(e){toast('Erreur hash : '+e.message,'warn');return;}
  }
  DB.admins.push({id:gid(),user:t.user,pwd:finalPwd,nom:t.pre+' '+t.nom,role:'Enseignant-Admin',role2:'admin'});
  save();autoNotify('Promotion admin',t.pre+' '+t.nom+' a été promu administrateur','all');re();toast('✓ '+t.pre+' '+t.nom+' promu administrateur');
}
function revokeAdmin(aid){
  if(!confirm('Révoquer les droits admin de ce compte ?'))return;
  DB.admins=DB.admins.filter(function(a){return a.id!==aid;});
  save();re();toast('Droits admin révoqués');
}

