function editAdminPwd(aid){var a=DB.admins.find(function(x){return x.id===aid;});if(!a)return;M('Modifier mot de passe Admin',_esc(a.nom),'<div class="fg"><span class="fl">Nouveau mot de passe</span><input class="fi" id="naPwd" type="password" placeholder="Nouveau mot de passe"></div><div class="fg mt8"><span class="fl">Confirmer</span><input class="fi" id="naPwd2" type="password" placeholder="Confirmer le mot de passe"></div><div class="ib ibi mt8"><span>\ud83d\udd12</span><span>Le mot de passe sera hash\u00e9 automatiquement (SHA-256)</span></div>','<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="_saveAdminPwd(\''+aid+'\')">✓ Modifier</button>');}
async function _saveAdminPwd(aid){var p1=$('naPwd')?.value||'';var p2=$('naPwd2')?.value||'';if(p1.length<6){toast('Minimum 6 caract\u00e8res','warn');return;}if(p1!==p2){toast('Les mots de passe ne correspondent pas','warn');return;}var a=DB.admins.find(function(x){return x.id===aid;});if(!a)return;a.pwd=await hashPassword(p1,a.user);save();cm();re();toast('\u2713 Mot de passe modifi\u00e9 et hash\u00e9');}
