function mAddAnn(){
  M('Nouvelle annonce','Publication',`<div class="fg2">
    <div class="fg full"><span class="fl">Titre *</span><input class="fi" id="anT" placeholder="Titre de l\'annonce"></div>
    <div class="fg"><span class="fl">Type</span><select class="fi" id="anTy">${Object.entries(EVT).map(([k,v])=>`<option value="${k}">${v.l}</option>`).join('')}</select></div>
    <div class="fg"><span class="fl">Date</span><input class="fi" id="anD" type="date" value="${new Date().toISOString().split('T')[0]}"></div>
    <div class="fg full"><label style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="anU"> <span class="fl">Marquer comme urgent 🚨</span></label></div>
    <div class="fg full"><span class="fl">Description *</span><textarea class="fi" id="anDe" rows="4" placeholder="Contenu de l\'annonce..."></textarea></div>
  </div>`,
  `<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveAnn()">✓ Publier</button>`);
}
function saveAnn(){
  const titre=document.getElementById('anT')?.value.trim(),desc=document.getElementById('anDe')?.value.trim();
  if(!titre||!desc){toast('Titre et description requis','warn');return;}
  DB.announce.push({id:gid(),titre,date:document.getElementById('anD')?.value||new Date().toISOString().split('T')[0],desc,type:document.getElementById('anTy')?.value||'info',urg:document.getElementById('anU')?.checked||false});
  save();cm();re();toast('✓ Annonce publiée');
}
function delAnn(id){if(!confirm('Supprimer cette annonce ?'))return;DB.announce=DB.announce.filter(a=>a.id!==id);save();re();}

