function uploadBookCover(bid){
  var input=document.createElement('input');input.type='file';input.accept='image/*';
  input.style.display='none';document.body.appendChild(input);
  input.onchange=function(e){
    var file=e.target.files[0];if(!file)return;
    if(file.size>5*1024*1024){toast('Image trop lourde (max 5Mo)','warn');return;}
    var cfg=DB.cloudConfig;
    if(cfg&&cfg.url&&cfg.secret){
      toast('⬆️ Upload couverture…','info');
      var fd=new FormData();
      fd.append('file',file);
      fd.append('type','image');          // champ correct pour upload_file.php
      fd.append('ref_id','cover_'+bid);  // champ correct pour upload_file.php
      // Timeout 30s
      var ctrl=typeof AbortController!=='undefined'?new AbortController():null;
      var tmt=ctrl?setTimeout(function(){ctrl.abort();},30000):null;
      // FIX WAF LWS 2026 : Authorization header
      fetch(cfg.url.replace(/\/+$/,'')+'/upload_file.php',{
        method:'POST',
        headers:{'Authorization':'Bearer '+cfg.secret},
        body:fd,
        signal:ctrl?ctrl.signal:undefined
      }).then(function(r){if(tmt)clearTimeout(tmt);return r.json();})
      .then(function(res){
        var b=DB.books.find(function(x){return x.id===bid;});
        if(res.url&&b){b.coverImg=res.url;save();re();toast('✓ Couverture sauvegardée sur le serveur ✅');}
        else{console.warn('[cover upload] Réponse serveur:',res);_bookCoverFallback(file,bid);}
      }).catch(function(err){
        if(tmt)clearTimeout(tmt);
        console.warn('[cover upload] Erreur:',err);
        _bookCoverFallback(file,bid);
      });
    }else{_bookCoverFallback(file,bid);}
    input.remove();
  };
  setTimeout(function(){input.click();},100);
}
function _bookCoverFallback(file,bid){
  var reader=new FileReader();
  reader.onload=function(evt){
    var b=DB.books.find(function(x){return x.id===bid;});
    if(b){b.coverImg=evt.target.result;save();re();toast('✓ Couverture mise à jour (local)');}
  };
  reader.readAsDataURL(file);
}
function uploadBookPreview(bid){
  var input=document.createElement('input');input.type='file';input.accept='image/*';input.multiple=true;
  input.style.display='none';document.body.appendChild(input);
  input.onchange=function(e){
    var files=Array.from(e.target.files);
    var b=DB.books.find(function(x){return x.id===bid;});if(!b)return;
    if(!b.previewImages)b.previewImages=[];
    files.forEach(function(file){
      if(file.size>500000){toast('Image '+file.name+' trop lourde','warn');return;}
      var reader=new FileReader();
      reader.onload=function(evt){
        b.previewImages.push(evt.target.result);
        save();toast('✓ Aperçu ajouté');
      };reader.readAsDataURL(file);
    });input.remove();
  };
  setTimeout(function(){input.click();},100);
}

