// ── MANUELS : UPLOAD FICHIER ADMIN ──────────────────────────────────
function _uploadManuelFichier(bid){
  var b=DB.books.find(function(x){return x.id===bid;});if(!b)return;
  var input=document.createElement('input');
  input.type='file';
  input.accept='.pdf,.doc,.docx,.ppt,.pptx,image/*,video/*,.mp4,.webm';
  input.style.display='none';document.body.appendChild(input);
  input.onchange=function(e){
    var file=e.target.files[0];if(!file)return;
    var maxMo=file.type.startsWith('video')?80:30;
    if(file.size>maxMo*1024*1024){toast('Fichier trop lourd (max '+maxMo+' Mo)','warn');return;}
    // Essayer d'abord le serveur cloud
    _uploadToServer(file,'book',bid,function(url,err){
      if(url){
        b.fichierUrl=url;b.fichierNom=file.name;b.fichierType=file.type;
        delete b.fichierKey;delete b.fichierData;
        save();re();toast('✓ Fichier uploadé sur le serveur : '+file.name);
      } else {
        // Fallback : stockage local
        toast('Serveur non configuré — stockage local','warn');
        var reader=new FileReader();
        reader.onload=function(evt){
          var key='manuel_'+bid;
          try{
            localStorage.setItem(key,evt.target.result);
            b.fichierKey=key;b.fichierNom=file.name;b.fichierType=file.type;
            save();re();toast('✓ Fichier stocké localement : '+file.name);
          }catch(ex){
            b.fichierData=evt.target.result;b.fichierNom=file.name;b.fichierType=file.type;b.fichierKey='inline_'+bid;
            save();re();toast('✓ Fichier stocké (stockage interne)');
          }
        };
        reader.onerror=function(){toast('Erreur de lecture','warn');};
        reader.readAsDataURL(file);
      }
    });
    input.remove();
  };
  setTimeout(function(){input.click();},100);
}

function _getManuelData(b){
  if(!b)return null;
  // URL serveur (cross-device)
  if(b.fichierUrl)return b.fichierUrl;
  // Fichier localStorage
  if(b.fichierKey&&b.fichierKey.startsWith('manuel_')){
    try{return localStorage.getItem(b.fichierKey);}catch(e){return null;}
  }
  return b.fichierData||null;
}

function _previewManuel(bid){
  var b=DB.books.find(function(x){return x.id===bid;});if(!b)return;
  var data=_getManuelData(b);
  if(!data){toast('Aucun fichier disponible','warn');return;}
  var nom=b.fichierNom||'document';
  var type=b.fichierType||'application/pdf';
  var isUrl=data.indexOf('http')===0;
  var isPdf=type.indexOf('pdf')>=0||nom.toLowerCase().endsWith('.pdf');
  var isImg=type.startsWith('image');
  var isVid=type.startsWith('video');
  // URL serveur + PDF → viewer avec filigrane
  if(isUrl&&isPdf){_showPDFViewer(data,nom,iA());return;}
  // URL serveur + autre type → ouvrir dans un onglet
  if(isUrl){window.open(data,'_blank');return;}
  // Données locales (base64) → popup ou modal de secours
  function _showInModal(){
    var inner='';
    var _isMobEmbed=/Mobi|Android|iPhone|iPad/i.test(navigator.userAgent||'');
    if(isPdf){
      if(_isMobEmbed){
        // Mobile : <embed> naviguerait hors du SPA → blob URL + bouton
        var _blobPdf='';
        try{
          var _pa=data.split(','),_pm=(_pa[0].match(/:(.*?);/)||['','application/pdf'])[1];
          var _pb=atob(_pa[1]),_pn=_pb.length,_pu=new Uint8Array(_pn);
          while(_pn--)_pu[_pn]=_pb.charCodeAt(_pn);
          _blobPdf=URL.createObjectURL(new Blob([_pu],{type:_pm}));
        }catch(_pe){_blobPdf=data;}
        inner='<div style="text-align:center;padding:28px 16px">'
          +'<div style="font-size:56px;margin-bottom:12px">📄</div>'
          +'<div style="font-size:14px;font-weight:700;color:var(--bl);margin-bottom:18px">'+_esc(nom)+'</div>'
          +'<button class="btn bi" style="font-size:14px;padding:12px 24px;margin:6px;width:100%;max-width:260px;cursor:pointer" onclick="window.open(\''+_blobPdf+'\',\'_blank\')">📖 Ouvrir le PDF</button>'
          +'</div>';
      } else {
        inner='<div style="border-radius:10px;overflow:hidden;border:1px solid var(--bg3)"><embed src="'+data+'" type="application/pdf" style="width:100%;height:60vh;border:none"></div>';
      }
    }
    else if(isImg){inner='<div style="text-align:center"><img src="'+data+'" style="max-width:100%;max-height:60vh;border-radius:10px;display:inline-block"></div>';}
    else if(isVid){inner='<video src="'+data+'" controls style="width:100%;max-height:55vh;border-radius:10px;display:block;background:#000"></video>';}
    else{inner='<div style="text-align:center;padding:30px"><div style="font-size:42px;margin-bottom:12px">📄</div><div style="font-size:14px;color:var(--ink3);margin-bottom:16px">'+nom+'</div><a href="'+data+'" download="'+nom+'" class="btn bi">⬇️ Télécharger</a></div>';}
    M('📖 '+nom,'',inner,'<button class="btn bo" onclick="cm()">Fermer</button>',true);
  }
  var w=window.open('','_blank','width=900,height=700,resizable=yes,scrollbars=yes');
  if(!w||w.closed){_showInModal();return;}
  try{
    var body='';
    if(isPdf){body='<iframe src="'+data+'" style="width:100%;height:calc(100vh - 44px);border:none"></iframe>';}
    else if(isImg){body='<div style="background:#111;min-height:calc(100vh - 44px);display:flex;align-items:center;justify-content:center"><img src="'+data+'" style="max-width:100%;max-height:calc(100vh - 60px);display:block"></div>';}
    else if(isVid){body='<video src="'+data+'" controls style="width:100%;max-height:calc(100vh - 44px);display:block;background:#000"></video>';}
    else{body='<div style="padding:40px;text-align:center;background:#111;min-height:calc(100vh - 44px)"><p style="font-size:16px;margin-bottom:20px;color:#fff">📄 '+nom+'</p><a href="'+data+'" download="'+nom+'" style="background:#142554;color:#fff;padding:12px 24px;border-radius:10px;text-decoration:none;font-weight:700">⬇️ Télécharger</a></div>';}
    w.document.write('<!DOCTYPE html><html><head><meta charset="UTF-8"><title>'+nom+' — VÉRITAS</title>'
      +'<style>body{margin:0;padding:0;background:#111;color:#fff;height:100vh}'
      +'.bar{background:#142554;padding:10px 18px;display:flex;align-items:center;justify-content:space-between}'
      +'.bar-t{font-family:sans-serif;font-size:14px;font-weight:700;color:#FFC93C}'
      +'.bar-c{font-size:11px;color:rgba(255,255,255,.5)}'
      +'</style></head><body>'
      +'<div class="bar"><span class="bar-t">📖 '+nom+'</span><span class="bar-c">© Mythe Errant 2026 · VÉRITAS</span></div>'
      +body+'</body></html>');
  }catch(e){w.close();_showInModal();}
  w.document.close();
}

function _dlManuel(bid){
  var b=DB.books.find(function(x){return x.id===bid;});if(!b)return;
  var data=_getManuelData(b);
  if(!data){toast('Aucun fichier disponible','warn');return;}
  var nom=b.fichierNom||('manuel_'+b.titre+'.pdf');
  var a=document.createElement('a');
  a.href=data;
  if(data.indexOf('http')===0){a.target='_blank';}else{a.download=nom;}
  a.click();toast('⬇️ Téléchargement lancé : '+nom);
}

// ── Lecture gratuite d'un manuel par un visiteur (URL serveur requis) ──
function _visitorLireManuel(bid){
  var b=DB.books.find(function(x){return x.id===bid;});
  if(!b){toast('Manuel introuvable','warn');return;}
  if(!b.fichierUrl||!b.lireGratuit){toast('Ce manuel n\'est pas disponible en lecture gratuite','warn');return;}
  var isPdf=b.fichierUrl.toLowerCase().indexOf('.pdf')>-1||(b.fichierType||'').indexOf('pdf')>-1;
  if(isPdf){_showPDFViewer(b.fichierUrl,b.titre||'Manuel',false);return;}
  window.open(b.fichierUrl,'_blank');
}

// ── Upload d'un fichier de ressource e-learning sur le serveur ──────
function _uploadElFichier(itemId){
  var item=(DB.elearning.contenus||[]).find(function(c){return c.id===itemId;});
  if(!item){toast('Ressource introuvable','warn');return;}
  var input=document.createElement('input');
  input.type='file';
  input.accept='.pdf,.doc,.docx,.ppt,.pptx,.html,image/*,video/*,.mp4,.webm';
  input.style.display='none';document.body.appendChild(input);
  input.onchange=function(e){
    var file=e.target.files[0];if(!file)return;
    var maxMo=file.type.startsWith('video')?80:30;
    if(file.size>maxMo*1024*1024){toast('Fichier trop lourd (max '+maxMo+' Mo)','warn');return;}
    _uploadToServer(file,'resource',itemId,function(url,err){
      if(url){
        item.fichierUrl=url;item.fichierNom=file.name;item.fichierType=file.type;
        delete item.fichierData;
        save();re();toast('✓ Ressource uploadée sur le serveur : '+file.name);
      } else {
        toast('Serveur non disponible — stockage local','warn');
        var reader=new FileReader();
        reader.onload=function(evt){
          item.fichierData=evt.target.result;item.fichierNom=file.name;item.fichierType=file.type;
          save();re();toast('✓ Ressource stockée localement : '+file.name);
        };
        reader.onerror=function(){toast('Erreur de lecture','warn');};
        reader.readAsDataURL(file);
      }
    });
    input.remove();
  };
  setTimeout(function(){input.click();},100);
}

