function pgVisitorOrders(){
  if(!iA())return na();
  const orders=(DB.visitorOrders||[]).sort((a,b)=>(b.date||'').localeCompare(a.date||''));
  return`<div class="sg" style="grid-template-columns:repeat(3,1fr)">
    <div class="sc scg"><div class="sci">🛒</div><div class="scl">Commandes visiteurs</div><div class="scv vg">${orders.length}</div></div>
    <div class="sc scgr"><div class="sci">⏳</div><div class="scl">En attente</div><div class="scv vgr">${orders.filter(o=>o.statut==='En attente').length}</div></div>
    <div class="sc scb"><div class="sci">💰</div><div class="scl">Revenu potentiel</div><div class="scv vb">${fmt(orders.reduce((s,o)=>s+o.prix,0))}</div></div>
  </div>
  <div class="card">
    <div class="fl2 fic fsb mb16"><div class="ct mb0">Commandes en ligne</div></div>
    ${orders.length===0?'<div class="empty"><div class="empty-ico">🛒</div>Aucune commande visiteur</div>':
    '<div class="tw"><table><thead><tr><th>Date</th><th>Client</th><th>Téléphone</th><th>Manuel</th><th>Classe</th><th>Montant</th><th>Statut</th><th>Actions</th></tr></thead><tbody>'+
    orders.map(o=>
      '<tr><td class="xs2 mut">'+o.date+'</td>'+
      '<td class="semi s">'+o.nom+'</td>'+
      '<td class="mono xs2">'+o.tel+'</td>'+
      '<td class="s">'+o.bookTitle+'</td>'+
      '<td><span class="bg bgd">'+(o.cls||'—')+'</span></td>'+
      '<td class="mono bold" style="color:var(--gold)">'+fmt(o.prix)+'</td>'+
      '<td><span class="bg '+(o.statut==='Confirmé'?'bgg':o.statut==='Annulé'?'bgr':'bgo')+'">'+o.statut+'</span></td>'+
      '<td><div class="fl2 g4">'+
      (o.statut==='En attente'?'<button class="btn bgr2 xs" onclick="confirmVOrder(\''+o.id+'\')">✓</button><button class="btn br2 xs" onclick="cancelVOrder(\''+o.id+'\')">✕</button>':'')+
      (o.statut==='Confirmé'?'<button class="btn bgr2 xs" onclick="sendVisitorReceipt(&apos;'+o.id+'&apos;)">🧾 Reçu WA</button><button class="btn bo xs" onclick="printVisitorReceipt(&apos;'+o.id+'&apos;)">🖨️</button>':'')+
      '<button class="btn bgr2 xs" onclick="sendVisitorReceipt(\''+o.id+'\')">🧾 Reçu</button>'+
      '<a href="https://wa.me/'+o.tel.replace(/[^0-9]/g,'')+'" target="_blank" class="btn bo xs">📲</a>'+
      '</div></td></tr>'
    ).join('')+
    '</tbody></table></div>'}</div>`;
}
function sendVisitorReceipt(oid){
  var o=(DB.visitorOrders||[]).find(function(x){return x.id===oid;});if(!o)return;
  var tel=o.tel.replace(/[^0-9]/g,'');if(tel.length<9){toast('Numéro invalide','warn');return;}
  if(!tel.startsWith('237'))tel='237'+tel;
  var msg='📄 *REÇU — '+( DB.school?.nom||'VÉRITAS Academy')+'*\n\n'+
    '📚 Article: *'+o.bookTitle+'*\n'+
    '💰 Montant: *'+fmt(o.prix)+'*\n'+
    (o.promo?'🎟️ Promo: '+o.promo+'\n':'')+
    '📅 Date: '+o.date+'\n'+
    '📋 Réf: '+o.id.substring(0,8).toUpperCase()+'\n'+
    '✅ Statut: '+o.statut+'\n\n'+
    'Merci pour votre achat ! 🙏\n'+
    (DB.school?.nom||'VÉRITAS Academy')+' — La Réussite Assurée';
  window.open('https://wa.me/'+tel+'?text='+encodeURIComponent(msg),'_blank');
  toast('✓ Reçu envoyé à '+o.tel);
}

function confirmVOrder(oid){const o=(DB.visitorOrders||[]).find(x=>x.id===oid);if(o){o.statut='Confirmé';save();re();autoNotify('Commande confirmée','La commande de '+o.bookTitle+' pour '+o.nom+' a été confirmée.','all');toast('✓ Commande confirmée');}}
function cancelVOrder(oid){const o=(DB.visitorOrders||[]).find(x=>x.id===oid);if(o){o.statut='Annulé';save();re();toast('Commande annulée');}}

function pgBooksale(){
  if(!iA())return na();
  return`<div class="card mb16">
    <div class="fl2 fic fsb mb16"><div class="ct mb0">Vente en caisse</div><button class="btn bi" onclick="mSaleBook()">＋ Nouvelle vente</button></div>
    <div class="tw"><table>
      <thead><tr><th>Date</th><th>Élève</th><th>Manuel</th><th>Montant</th><th>Statut</th><th></th></tr></thead>
      <tbody>${(DB.bookPurchases||[]).sort((a,b)=>(b.date||'').localeCompare(a.date||'')).map(bp=>{const b=DB.books.find(x=>x.id===bp.bid);const st=S(bp.eid);return`<tr>
        <td class="xs2 mut">${bp.date||'—'}</td>
        <td class="semi s">${st?.pre||''} ${st?.nom||''}</td>
        <td><span style="font-size:16px">${b?.ico||'📚'}</span> ${b?.titre||'—'}</td>
        <td class="mono bold" style="color:var(--gold)">${fmt(bp.mnt)}</td>
        <td><span class="bg ${bp.statut==='Payé'?'bgg':'bgo'}">${bp.statut}</span></td>
        <td><div class="fl2 g4">
          ${bp.statut!=='Payé'?`<button class="btn bgr2 xs" onclick="markBPPaid('${bp.id}')">✓ Payé</button>`:''}
          <button class="btn bo xs" onclick="printBookRec('${bp.id}')">🧾</button>
        </div></td>
      </tr>`;}).join('')}
      ${!(DB.bookPurchases?.length)?`<tr><td colspan="6"><div class="empty">Aucune vente enregistrée</div></td></tr>`:''}
      </tbody></table></div>
  </div>`;
}
function mSaleBook(){
  M('Vente de manuel','Enregistrement en caisse',`<div class="fg2">
    <div class="fg full"><span class="fl">Élève</span><select class="fi" id="slEtu">${DB.students.map(s=>`<option value="${s.id}">${s.pre} ${s.nom} (${s.cls})</option>`).join('')}</select></div>
    <div class="fg full"><span class="fl">Manuel *</span><select class="fi" id="slBk" onchange="autoFillSaleP()">${DB.books.filter(b=>b.stock>0).map(b=>`<option value="${b.id}">${b.ico} ${b.titre} (${b.cls}) — ${fmt(b.prix)}</option>`).join('')}</select></div>
    <div class="fg"><span class="fl">Montant</span><input class="fi" id="slMnt" type="number" min="0"></div>
  </div>`,
  `<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveSale()">✓ Enregistrer</button>`);
  setTimeout(()=>autoFillSaleP(),100);
}
function autoFillSaleP(){const bid=document.getElementById('slBk')?.value;const b=DB.books.find(x=>x.id===bid);const m=document.getElementById('slMnt');if(b&&m)m.value=b.prix;}
function saveSale(){
  const eid=document.getElementById('slEtu')?.value;const bid=document.getElementById('slBk')?.value;const mnt=+document.getElementById('slMnt')?.value;
  if(!eid||!bid||!mnt){toast('Tous les champs requis','warn');return;}
  const b=DB.books.find(x=>x.id===bid);if(!b||b.stock<=0){toast('Rupture de stock','warn');return;}
  b.vendu++;b.stock--;
  const ref='BOOK-'+Math.floor(Math.random()*90000+10000);
  if(!DB.bookPurchases)DB.bookPurchases=[];
  DB.bookPurchases.push({id:gid(),eid,bid,date:today(),mnt,statut:'Payé',ref});
  save();cm();re();toast('✓ Vente enregistrée');
}
function markBPPaid(bpid){
  const bp=DB.bookPurchases.find(x=>x.id===bpid);
  if(bp){
    bp.statut='Payé';
    // v1.2.2 (bug #3) : paiement livre validé → confirmer la commission partenaire liée
    try{ if(typeof confirmCommissionsForSale==='function') confirmCommissionsForSale('book', bp.bid); }catch(e){}
    save();re();toast('✓ Paiement confirmé');
    // Notification vers l'acheteur
    if(typeof autoNotify==='function'&&bp.eid){
      var _bk=DB.books&&DB.books.find(x=>x.id===bp.bid);
      autoNotify('📚 Achat confirmé','Votre achat du livre « '+(_bk?_bk.titre:bp.bid)+' » est confirmé. Bonne lecture !',bp.eid);
    }
  }
}
function printBookRec(bpid){
  const bp=DB.bookPurchases.find(x=>x.id===bpid);if(!bp)return;
  const b=DB.books.find(x=>x.id===bp.bid);const st=S(bp.eid);
  printDoc(`<div style="max-width:500px;margin:0 auto;font-family:'Inter',sans-serif">${docHeader('Reçu — Achat Manuel')}
  <div style="padding:16px 26px">
    ${[['Élève',(st?.pre||'')+(st?' ':'')+st?.nom],['Classe',st?.cls||'—'],['Manuel',b?.titre||'—'],['Auteur',b?.auteur||'—'],['Classe manuel',b?.cls||'—'],['Date',bp.date||today()],['Référence',bp.ref]].map(([l,v])=>`<div style="display:flex;justify-content:space-between;padding:7px 0;border-bottom:1px solid #e8e4dc"><span style="color:#6b5e52;font-size:12px">${l}</span><span style="font-weight:700;font-size:12px">${v}</span></div>`).join('')}
    <div style="background:#142554;color:#fff;padding:12px;display:flex;justify-content:space-between;margin-top:10px;border-radius:6px"><span style="font-weight:700">TOTAL</span><span style="font-family:'Fira Code';font-size:20px;font-weight:700;color:#FFC93C">${fmt(bp.mnt)}</span></div>
    <div style="display:flex;justify-content:space-between;margin-top:12px;gap:12px">
      ${['Signature caissier','Cachet direction'].map(l=>`<div style="flex:1;text-align:center"><div style="font-size:13px;color:#a89888;text-transform:uppercase;margin-bottom:22px">${l}</div><div style="border-top:1px solid #c8c0b4;font-size:13px;color:#c8c0b4;padding-top:4px">Signature</div></div>`).join('')}
    </div>
  </div></div>`,`Reçu achat manuel — ${bp.ref}`);
}

