function pgAutreDep(){
  if(!iA())return na();
  const cats=['Loyer','Salaires','Fournitures','Réparations','Électricité','Eau','Communication','Autres'];
  return`<div class="fl2 fic fsb mb16"><div class="bold">Enregistrement des dépenses</div><button class="btn bi" onclick="mAddDep()">＋ Dépense</button></div>
  <div class="card">
    <div class="tw"><table>
      <thead><tr><th>Date</th><th>Catégorie</th><th>Description</th><th>Montant</th><th></th></tr></thead>
      <tbody>${DB.depenses.sort((a,b)=>b.dt.localeCompare(a.dt)).map(d=>`<tr>
        <td class="xs2 mut">${d.dt}</td>
        <td><span class="bg bgo">${d.cat}</span></td>
        <td class="s">${d.desc}</td>
        <td class="mono bold" style="color:var(--re)">${fmt(d.mnt)}</td>
        <td><button class="btn br2 xs" onclick="delDep('${d.id}')">🗑</button></td>
      </tr>`).join('')}
      ${!DB.depenses.length?`<tr><td colspan="5"><div class="empty">Aucune dépense</div></td></tr>`:''}
      </tbody></table></div>
  </div>`;
}
function mAddDep(){
  const cats=['Loyer','Salaires','Fournitures','Réparations','Électricité','Eau','Communication','Autres'];
  M('Nouvelle dépense','Saisie comptable',`<div class="fg2">
    <div class="fg"><span class="fl">Catégorie</span><select class="fi" id="depC">${cats.map(c=>`<option>${c}</option>`).join('')}</select></div>
    <div class="fg"><span class="fl">Montant (FCFA) *</span><input class="fi" id="depM" type="number" min="0"></div>
    <div class="fg full"><span class="fl">Description *</span><input class="fi" id="depD" placeholder="Détail de la dépense"></div>
    <div class="fg"><span class="fl">Date</span><input class="fi" id="depDt" type="date" value="${new Date().toISOString().split('T')[0]}"></div>
  </div>`,
  `<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveDep()">✓ Enregistrer</button>`);
}
function saveDep(){
  const mnt=+document.getElementById('depM')?.value;const desc=document.getElementById('depD')?.value.trim();
  if(!mnt||!desc){toast('Montant et description requis','warn');return;}
  const dtV=document.getElementById('depDt')?.value;
  DB.depenses.push({id:gid(),cat:document.getElementById('depC')?.value,desc,mnt,dt:dtV?new Date(dtV).toLocaleDateString('fr-FR'):today()});
  save();cm();re();toast('✓ Dépense enregistrée');
}
function delDep(id){if(!confirm('Supprimer cette dépense ?'))return;DB.depenses=DB.depenses.filter(d=>d.id!==id);save();re();}

function pgClassStats(){
  if(!iA())return na();
  var tri=window._stTri||TRS[0];
  var clsData=CLS.map(function(cls){
    var sts=DB.students.filter(function(s){return s.cls===cls;});
    var moys=sts.map(function(s){
      var gr=DB.grades.filter(function(g){return g.eid===s.id&&g.tri===tri;});
      var tc=gr.reduce(function(a,g){return a+g.coef;},0)||1;
      return gr.length?gr.reduce(function(a,g){return a+((g.n1+g.n2)/2)*g.coef;},0)/tc:null;
    }).filter(function(m){return m!==null;});
    var avg=moys.length?moys.reduce(function(a,b){return a+b;},0)/moys.length:0;
    var mn=moys.length?Math.min.apply(null,moys):0;
    var mx=moys.length?Math.max.apply(null,moys):0;
    var nb=moys.filter(function(m){return m>=10;}).length;
    var tx=moys.length?Math.round(nb/moys.length*100):0;
    return{cls:cls,eff:sts.length,n:moys.length,avg:avg,mn:mn,mx:mx,tx:tx,nb:nb};
  }).filter(function(d){return d.n>0;});
  var gAvg=clsData.length?clsData.reduce(function(s,d){return s+d.avg;},0)/clsData.length:0;
  var best=clsData.length?clsData.reduce(function(a,b){return a.avg>b.avg?a:b;}):{cls:'-',avg:0};
  var tN=clsData.reduce(function(s,d){return s+d.n;},0);
  var tM=clsData.reduce(function(s,d){return s+d.nb;},0);
  var gTx=tN?Math.round(tM/tN*100):0;
  // Subject data
  var allSubs=[...new Set(DB.grades.filter(function(g){return g.tri===tri;}).map(function(g){return g.sub;}))];
  var subData=allSubs.map(function(sub){
    var gs=DB.grades.filter(function(g){return g.tri===tri&&g.sub===sub;}).map(function(g){return(g.n1+g.n2)/2;});
    var a=gs.length?gs.reduce(function(x,y){return x+y;},0)/gs.length:0;
    var tx=gs.length?Math.round(gs.filter(function(m){return m>=10;}).length/gs.length*100):0;
    return{sub:sub,c:gs.length,avg:a,mn:gs.length?Math.min.apply(null,gs):0,mx:gs.length?Math.max.apply(null,gs):0,tx:tx};
  }).sort(function(a,b){return b.avg-a.avg;});
  var worst=subData.length?subData[subData.length-1]:{sub:'-',avg:0};
  // Build HTML
  var h='<div class="fl2 fic fsb mb16 fw g8">';
  h+='<div class="tabs">'+TRS.map(function(t){return '<button class="tab'+(t===tri?' on':'')+'" onclick="window._stTri=\''+t+'\';re()">'+t+'</button>';}).join('')+'</div>';
  h+='<button class="excel-btn" onclick="exportClassStats()">📊 Exporter</button></div>';
  h+='<div class="sg">';
  h+='<div class="sc scg"><div class="sci">🎓</div><div class="scl">Élèves notés</div><div class="scv vg">'+tN+'</div></div>';
  h+='<div class="sc scb"><div class="sci">📊</div><div class="scl">Moyenne générale</div><div class="scv vb">'+gAvg.toFixed(2)+'</div></div>';
  h+='<div class="sc scgr"><div class="sci">✅</div><div class="scl">Taux réussite</div><div class="scv vgr">'+gTx+'%</div></div>';
  h+='<div class="sc scg"><div class="sci">🏆</div><div class="scl">Meilleure classe</div><div class="scv vg" style="font-size:16px">'+best.cls+'</div><div class="scs">'+best.avg.toFixed(2)+'/20</div></div>';
  h+='</div>';
  // Class comparison
  h+='<div class="g2"><div class="card"><div class="ct">📊 Moyennes par classe — '+tri+'</div>';
  clsData.forEach(function(d){
    var col=d.avg>=14?'var(--gr)':d.avg>=10?'var(--gold)':'var(--re)';
    var pct=Math.round(d.avg/20*100);
    h+='<div class="mb12"><div class="fl2 fic fsb mb6"><span class="semi s">'+d.cls+'</span><span class="mono bold s" style="color:'+col+'">'+d.avg.toFixed(2)+'/20</span></div>';
    h+='<div class="pb"><div class="pf" style="width:'+pct+'%;background:'+col+'"></div></div>';
    h+='<div class="fl2 fic fsb mt4"><span class="xs2 mut">'+d.eff+' él. · Taux: '+d.tx+'%</span><span class="xs2 mut">['+d.mn.toFixed(1)+'-'+d.mx.toFixed(1)+']</span></div></div>';
  });
  h+='</div>';
  // Class ranking
  h+='<div class="card"><div class="ct">🏆 Classement des classes</div><div class="tw"><table><thead><tr><th>#</th><th>Classe</th><th>Moy.</th><th>Taux</th><th>Eff.</th></tr></thead><tbody>';
  clsData.sort(function(a,b){return b.avg-a.avg;}).forEach(function(d,i){
    var col=d.avg>=14?'var(--gr)':d.avg>=10?'var(--gold)':'var(--re)';
    h+='<tr><td class="semi">'+(i+1)+'</td><td class="semi">'+d.cls+'</td>';
    h+='<td class="mono bold" style="color:'+col+'">'+d.avg.toFixed(2)+'</td>';
    h+='<td><span class="bg '+(d.tx>=60?'bgg':d.tx>=40?'bgo':'bgr')+'">'+d.tx+'%</span></td>';
    h+='<td class="xs2 mut">'+d.eff+'</td></tr>';
  });
  h+='</tbody></table></div></div></div>';
  // Subject comparison
  h+='<div class="card mt20"><div class="ct">📚 Performances par Matière — '+tri+'</div><div class="tw"><table>';
  h+='<thead><tr><th>#</th><th>Matière</th><th>Moy.</th><th>Taux ≥10</th><th>Notes</th><th>[Min-Max]</th></tr></thead><tbody>';
  subData.forEach(function(d,i){
    var col=d.avg>=14?'var(--gr)':d.avg>=10?'var(--gold)':'var(--re)';
    h+='<tr><td class="semi">'+(i+1)+'</td><td class="semi">'+d.sub+'</td>';
    h+='<td class="mono bold" style="color:'+col+'">'+d.avg.toFixed(2)+'</td>';
    h+='<td><span class="bg '+(d.tx>=60?'bgg':d.tx>=40?'bgo':'bgr')+'">'+d.tx+'%</span></td>';
    h+='<td class="xs2 mut">'+d.c+'</td><td class="xs2 mut">['+d.mn.toFixed(1)+'-'+d.mx.toFixed(1)+']</td></tr>';
  });
  h+='</tbody></table></div></div>';
  // Subject bars + top 3
  h+='<div class="g2 mt16"><div class="card"><div class="ct">📊 Matières (barres)</div>';
  subData.slice(0,12).forEach(function(d){
    var col=d.avg>=14?'var(--gr)':d.avg>=10?'var(--gold)':'var(--re)';
    h+='<div class="mb10"><div class="fl2 fic fsb mb4"><span class="s">'+d.sub.substring(0,20)+'</span><span class="mono bold xs2" style="color:'+col+'">'+d.avg.toFixed(1)+'</span></div>';
    h+='<div class="pb"><div class="pf" style="width:'+Math.round(d.avg/20*100)+'%;background:'+col+'"></div></div></div>';
  });
  h+='</div><div class="card"><div class="ct">🏅 Top 3 & alerte</div>';
  var medals=['🥇','🥈','🥉'];
  subData.slice(0,3).forEach(function(d,i){
    var bg=i===0?'var(--gp)':i===1?'var(--blb)':'var(--pub)';
    h+='<div style="padding:12px;background:'+bg+';border-radius:var(--r2);margin-bottom:8px"><div class="fl2 fic g10"><span style="font-size:22px">'+medals[i]+'</span><div><div class="semi">'+d.sub+'</div><div class="mono bold" style="color:var(--gold);font-size:16px">'+d.avg.toFixed(2)+'/20</div></div></div></div>';
  });
  if(worst.avg<10)h+='<div class="ib ibr mt8 mb0"><span>⚠️</span><span>Matière la plus faible: <strong>'+worst.sub+'</strong> ('+worst.avg.toFixed(2)+'/20)</span></div>';
  h+='</div></div>';
  return h;
}



function exportClassStats(){
  var tri=window._stTri||TRS[0];
  var data=CLS.map(function(cls){
    var sts=DB.students.filter(function(s){return s.cls===cls;});
    var moyennes=sts.map(function(s){
      var gr=DB.grades.filter(function(g){return g.eid===s.id&&g.tri===tri;});
      var tc=gr.reduce(function(a,g){return a+g.coef;},0)||1;
      return gr.length?gr.reduce(function(a,g){return a+((g.n1+g.n2)/2)*g.coef;},0)/tc:null;
    }).filter(function(m){return m!==null;});
    var avg=moyennes.length?moyennes.reduce(function(a,b){return a+b;},0)/moyennes.length:0;
    return{'Classe':cls,'Effectif':sts.length,'Notes saisies':moyennes.length,
      'Moyenne':avg.toFixed(2),'Min':moyennes.length?Math.min.apply(null,moyennes).toFixed(2):'',
      'Max':moyennes.length?Math.max.apply(null,moyennes).toFixed(2):'',
      'Taux réussite':moyennes.length?Math.round(moyennes.filter(function(m){return m>=10;}).length/moyennes.length*100)+'%':'',
      'Trimestre':tri};
  });
  exportToExcel(data,'Statistiques_Classes_'+tri,'Stats');
}

function pgFinance(){
  if(!iA())return na();
  const tF=DB.payments.filter(p=>p.stat==='Payé').reduce((s,p)=>s+p.mnt,0);
  const tB=DB.books.reduce((s,b)=>s+b.vendu*b.prix,0);
  const tS=DB.teachers.reduce((s,t)=>s+t.sal,0);
  const tD=DB.depenses.reduce((s,d)=>s+d.mnt,0);
  const bNet=tF+tB-tS-tD;
  const catD=DB.depenses.reduce((a,d)=>{a[d.cat]=(a[d.cat]||0)+d.mnt;return a},{});
  return`<div class="sg">
    <div class="sc scgr"><div class="sci">💰</div><div class="scl">Frais scolarité</div><div class="scv vgr" style="font-size:16px">${fmt(tF)}</div></div>
    <div class="sc scb"><div class="sci">📚</div><div class="scl">Ventes manuels</div><div class="scv vb" style="font-size:16px">${fmt(tB)}</div></div>
    <div class="sc scr"><div class="sci">💸</div><div class="scl">Masse salariale</div><div class="scv vr" style="font-size:16px">${fmt(tS)}</div></div>
    <div class="sc scr"><div class="sci">📉</div><div class="scl">Autres charges</div><div class="scv vr" style="font-size:16px">${fmt(tD)}</div></div>
  </div>
  <div class="g2">
    <div class="card" style="background:${bNet>=0?'var(--grb)':'var(--reb)'};border-color:${bNet>=0?'var(--grd)':'var(--red)'}">
      <div class="xs2 mut mb4">RÉSULTAT NET</div>
      <div class="mono bold" style="font-size:32px;color:${bNet>=0?'var(--gr)':'var(--re)'}">${bNet>=0?'+':''} ${fmt(bNet)}</div>
      <div class="xs2 mut mt8">Recettes: ${fmt(tF+tB)} — Charges: ${fmt(tS+tD)}</div>
      <button class="btn bi sm mt14" onclick="printBilan()">🖨️ Imprimer bilan</button>
    </div>
    <div class="card">
      <div class="ct">Répartition des dépenses</div>
      ${Object.entries(catD).sort((a,b)=>b[1]-a[1]).map(([cat,mnt])=>`<div class="mb12">
        <div class="fl2 fic fsb mb6"><span class="semi s">${cat}</span><span class="mono xs2" style="color:var(--re)">${fmt(mnt)} (${Math.round(mnt/(tS+tD)*100)}%)</span></div>
        <div class="pb"><div class="pf pfr" style="width:${Math.round(mnt/(tS+tD)*100)}%"></div></div>
      </div>`).join('') || '<div class="empty xs2">Aucune dépense</div>'}
    </div>
  </div>`;
}
function printBilan(){
  const tF=DB.payments.filter(p=>p.stat==='Payé').reduce((s,p)=>s+p.mnt,0);
  const tB=DB.books.reduce((s,b)=>s+b.vendu*b.prix,0);
  const tS=DB.teachers.reduce((s,t)=>s+t.sal,0);
  const tD=DB.depenses.reduce((s,d)=>s+d.mnt,0);
  const bNet=tF+tB-tS-tD;
  printDoc(`<div style="max-width:660px;margin:0 auto;font-family:'Inter',sans-serif">${docHeader('Bilan Financier')}
  <div style="padding:16px 26px">
    <div style="margin-bottom:14px;padding:10px;background:#edf7f1;border:1px solid #a8d8b8;border-radius:7px"><div style="font-size:13px;text-transform:uppercase;color:#1a6e40">Produits</div></div>
    ${[['Frais de scolarité encaissés',tF,true],['Vente de manuels scolaires',tB,true]].map(([l,v])=>`<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #e8e4dc;font-size:12px"><span>${l}</span><span style="font-family:'Fira Code';color:#1a6e40;font-weight:700">+ ${fmt(v)}</span></div>`).join('')}
    <div style="display:flex;justify-content:space-between;padding:8px;background:#f5f3ef;font-weight:700;font-size:12px"><span>Total Produits</span><span style="font-family:'Fira Code';color:#1a6e40">+ ${fmt(tF+tB)}</span></div>
    <div style="margin:14px 0 10px;padding:10px;background:#fdf0ee;border:1px solid #e8b0a8;border-radius:7px"><div style="font-size:13px;text-transform:uppercase;color:#b82828">Charges</div></div>
    ${[['Masse salariale (enseignants)',tS,false],...DB.depenses.map(d=>[d.desc+' ('+d.cat+')',d.mnt,false])].map(([l,v])=>`<div style="display:flex;justify-content:space-between;padding:7px 0;border-bottom:1px solid #e8e4dc;font-size:12px"><span>${l}</span><span style="font-family:'Fira Code';color:#b82828">- ${fmt(v)}</span></div>`).join('')}
    <div style="display:flex;justify-content:space-between;padding:8px;background:#f5f3ef;font-weight:700;font-size:12px"><span>Total Charges</span><span style="font-family:'Fira Code';color:#b82828">- ${fmt(tS+tD)}</span></div>
    <div style="background:${bNet>=0?'#142554':'#b82828'};color:#fff;padding:14px;display:flex;justify-content:space-between;align-items:center;margin-top:16px;border-radius:7px">
      <span style="font-size:13px;font-weight:700;text-transform:uppercase">RÉSULTAT NET</span>
      <span style="font-family:'Fira Code';font-size:24px;font-weight:700;color:${bNet>=0?'#FFC93C':'#ffccc8'}">${bNet>=0?'+ ':''} ${fmt(bNet)}</span>
    </div>
  </div>
  <div style="background:#f0ede7;border-top:1px solid #ddd8d0;padding:7px 26px;display:flex;justify-content:space-between">
    <span style="font-size:13px;color:#c8c0b4">Établi le ${today()}</span>
    <span style="font-size:13px;color:#c8c0b4">${DB.school?.nom||'VÉRITAS Academy'} · ${DB.school?.ville||''}</span>
  </div></div>`,'Bilan Financier');
}

