function renderPresence(){const cls=window._prCl||CLS[0];const sts=DB.students.filter(s=>s.cls===cls);const pc=document.getElementById('prContent');if(!pc)return;pc.innerHTML=`<div class="tw"><table><thead><tr><th>#</th><th>Élève</th>${Array.from({length:20},(_,i)=>i+1).map(n=>`<th style="text-align:center;min-width:28px">${n}</th>`).join('')}</tr></thead><tbody>${sts.map((s,i)=>`<tr><td class="xs2 mut">${i+1}</td><td class="semi s">${s.pre} ${s.nom}</td>${Array.from({length:20},()=>'<td style="border:1px solid var(--bg3);height:22px"></td>').join('')}</tr>`).join('')}</tbody></table></div>`;}
function printPresence(){const cls=window._prCl||CLS[0];const sts=DB.students.filter(s=>s.cls===cls);printDoc(`<div style="max-width:720px;margin:0 auto;font-family:'Inter',sans-serif">${docHeader('Fiche de Présence')}<div style="padding:10px 16px;background:#f5f3ef;border-bottom:1px solid #ddd8d0"><strong>Classe:</strong> ${cls} — Mois: __________________</div><div style="padding:10px 16px"><table style="width:100%;border-collapse:collapse;font-size:12px"><thead><tr><th style="padding:5px;text-align:left;border:1px solid #ddd">#</th><th style="padding:5px;text-align:left;border:1px solid #ddd;min-width:120px">Élève</th>${Array.from({length:25},(_,i)=>`<th style="padding:4px 2px;text-align:center;border:1px solid #ddd;width:18px">${i+1}</th>`).join('')}</tr></thead><tbody>${sts.map((s,i)=>`<tr><td style="padding:5px;border:1px solid #ddd;font-size:12px">${i+1}</td><td style="padding:5px;border:1px solid #ddd;font-size:13px;font-weight:600">${s.pre} ${s.nom}</td>${Array.from({length:25},()=>'<td style="border:1px solid #ddd;height:18px"></td>').join('')}</tr>`).join('')}</tbody></table></div></div>`,`Présence ${cls}`);}

function pgAttestTravail(){if(!iA())return na();return`<div class="card"><div class="ct">Attestations de travail</div><div class="fg mb14"><span class="fl">Enseignant</span><select class="fi" id="atEns">${DB.teachers.map(t=>`<option value="${t.id}">${t.pre} ${t.nom} — ${t.mat2}</option>`).join('')}</select></div><button class="btn bi" onclick="genAttestTravail()">📄 Générer attestation</button></div>`;}
function genAttestTravail(){
  const t=T(document.getElementById('atEns')?.value);if(!t)return;
  printDoc(`<div style="max-width:600px;margin:0 auto;font-family:'Inter',sans-serif;text-align:center">${docHeader("Attestation de Travail")}<div style="padding:30px 40px"><div style="font-family:'Libre Baskerville',serif;font-size:20px;font-weight:700;color:#142554;margin-bottom:20px">ATTESTATION DE TRAVAIL</div>
  <div style="font-size:13px;line-height:2;text-align:left"><p>Je soussigné(e), <strong>${DB.school?.directeur||'Le Directeur'}</strong>, Directeur du <strong>${DB.school?.nom||'Centre VÉRITAS'}</strong>, atteste que :</p>
  <div style="margin:16px 0;padding:14px;border-left:4px solid #9a7228;background:#f5f3ef"><div style="font-size:18px;font-weight:700;color:#142554">${t.pre.toUpperCase()} ${t.nom.toUpperCase()}</div><div style="font-size:13px;color:#6b5e52;margin-top:4px">Grade: ${t.grade} · Matière: ${t.mat2}</div></div>
  <p>est employé(e) en qualité de <strong>Professeur de ${t.mat2}</strong> au sein de notre établissement depuis la rentrée scolaire <strong>${DB.school?.annee||'2024–2025'}</strong>.</p>
  <p style="margin-top:12px">Cette attestation est délivrée pour servir et valoir ce que de droit.</p></div>
  <div style="display:flex;justify-content:space-between;margin-top:24px"><div><div style="font-size:13px;color:#6b5e52">Fait le: ${today()}</div></div><div style="text-align:right"><div style="font-weight:700">${DB.school?.directeur||'Le Directeur'}</div><div style="margin-top:18px;border-top:1px solid #ccc;width:140px;margin-left:auto;font-size:13px;color:#aaa;padding-top:4px">Signature & Cachet</div></div></div></div></div>`,`Attestation travail — ${t.pre} ${t.nom}`,'landscape');
}

function pgRecuBooks(){return pgBooksale();}

function pgOrientationAdmin(){
  if(!iA())return na();
  const demandes=(DB.orientationDemandes||[]).sort((a,b)=>b.date.localeCompare(a.date));
  const nb=demandes.length;
  const attente=demandes.filter(d=>d.statut==='En attente').length;
  const trait=demandes.filter(d=>d.statut==='En cours').length;
  const clos=demandes.filter(d=>d.statut==='Clôturé').length;
  return`<div class="sg mb16">
    <div class="sc scgr"><div class="sci">📬</div><div class="scl">Total demandes</div><div class="scv vgr">${nb}</div></div>
    <div class="sc scr"><div class="sci">⏳</div><div class="scl">En attente</div><div class="scv vr">${attente}</div></div>
    <div class="sc scb"><div class="sci">🔄</div><div class="scl">En cours</div><div class="scv vb">${trait}</div></div>
    <div class="sc scpu"><div class="sci">✅</div><div class="scl">Clôturés</div><div class="scv vpu">${clos}</div></div>
  </div>
  <div class="card">
    <div class="fl2 fic fsb mb14 fw g8">
      <div class="ct mb0">🧭 Demandes d\'Orientation & Conseil</div>
      <div class="fl2 g8">
        <button class="btn bi sm" onclick="mAddOrientationDemande()">＋ Nouvelle demande</button>
        <button class="btn bg2 sm" onclick="exportOrientationExcel()">📥 Excel</button>
      </div>
    </div>
    ${!nb?'<div class="empty"><div class="empty-ico">🧭</div>Aucune demande pour l\'instant</div>':
    `<div class="tw"><table>
      <thead><tr><th>Date</th><th>Nom</th><th>Téléphone</th><th>Niveau</th><th>Service demandé</th><th>Disponibilité</th><th>Statut</th><th>Actions</th></tr></thead>
      <tbody>${demandes.map(d=>`<tr>
        <td class="xs2 mut">${d.date||'—'}</td>
        <td class="bold s">${d.nom}</td>
        <td class="mono xs2"><a href="https://wa.me/237${(d.tel||'').replace(/[^0-9]/g,'')}" target="_blank" style="color:var(--gr)">📲 ${d.tel}</a></td>
        <td><span class="bg bgd">${d.niveau||'—'}</span></td>
        <td class="s">${d.type||'—'}</td>
        <td class="xs2">${d.dispo||'—'}</td>
        <td><select class="fi" style="padding:3px 6px;font-size:12px;width:110px" onchange="updateOrientStatut('${d.id}',this.value)">
          <option${d.statut==='En attente'?' selected':''}>En attente</option>
          <option${d.statut==='En cours'?' selected':''}>En cours</option>
          <option${d.statut==='Clôturé'?' selected':''}>Clôturé</option>
        </select></td>
        <td><div class="fl2 g4">
          ${d.msg?`<button class="btn bo xs" onclick="viewOrientMsg('${d.id}')">📄 Msg</button>`:''}
          <button class="btn br2 xs" onclick="delOrientDemande('${d.id}')">🗑</button>
        </div></td>
      </tr>`).join('')}</tbody>
    </table></div>`}
  </div>`;
}
function updateOrientStatut(id,statut){
  const d=(DB.orientationDemandes||[]).find(x=>x.id===id);
  if(d){d.statut=statut;save();re();toast('✓ Statut mis à jour');}
}
function delOrientDemande(id){
  if(!confirm('Supprimer cette demande ?'))return;
  DB.orientationDemandes=(DB.orientationDemandes||[]).filter(x=>x.id!==id);
  save();re();toast('Demande supprimée');
}
function viewOrientMsg(id){
  const d=(DB.orientationDemandes||[]).find(x=>x.id===id);
  if(!d)return;
  M('📄 Message de la demande',_esc(d.nom||'')+' — '+_esc(d.date||''),
  `<div style="padding:12px;background:var(--bg2);border-radius:var(--r2);font-size:13px;line-height:1.8;white-space:pre-wrap">${_esc(d.msg||'(Aucun message)')}</div>
   ${d.dispo?`<div class="ib ibt mt12 mb0"><span>📅</span><span>Disponibilité : ${_esc(d.dispo)}</span></div>`:''}`,
  `<button class="btn bo" onclick="cm()">Fermer</button>
   <a href="https://wa.me/237${(d.tel||'').replace(/[^0-9]/g,'')}" target="_blank" class="btn bgr2">📲 WhatsApp</a>`);
}
function mAddOrientationDemande(){
  M('Nouvelle demande','Saisie manuelle',
  `<div class="fg2">
    <div class="fg"><span class="fl">Nom & Prénom *</span><input class="fi" id="aoNom"></div>
    <div class="fg"><span class="fl">Téléphone *</span><input class="fi" id="aoTel" placeholder="6XXXXXXXX"></div>
    <div class="fg"><span class="fl">Niveau</span><select class="fi" id="aoNiveau"><option value="">—</option>${['6ème','5ème','4ème','3ème','2nde','1ère A','1ère C','1ère D','Tle A','Tle C','Tle D','Post-Bac'].map(c=>`<option>${c}</option>`).join('')}</select></div>
    <div class="fg"><span class="fl">Service</span><select class="fi" id="aoType"><option>🎯 Orientation scolaire</option><option>📅 Emploi du temps / cours particuliers</option><option>📝 Astuces pour les examens</option><option>🧠 Psychologie & soutien scolaire</option><option>🏥 Psychiatrie & bien-être</option><option>👨‍👩‍👧 Conseil aux parents</option></select></div>
    <div class="fg full"><span class="fl">Message</span><textarea class="fi" id="aoMsg" rows="2"></textarea></div>
    <div class="fg full"><span class="fl">Disponibilité</span><input class="fi" id="aoDispo"></div>
  </div>`,
  `<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveOrientDemande()">✓ Enregistrer</button>`);
}
function saveOrientDemande(){
  const nom=(document.getElementById('aoNom')?.value||'').trim();
  const tel=(document.getElementById('aoTel')?.value||'').trim();
  if(!nom||!tel){toast('Nom et téléphone requis','warn');return;}
  if(!DB.orientationDemandes)DB.orientationDemandes=[];
  DB.orientationDemandes.push({id:gid(),nom,tel,
    niveau:document.getElementById('aoNiveau')?.value||'—',
    type:document.getElementById('aoType')?.value||'—',
    msg:document.getElementById('aoMsg')?.value||'',
    dispo:document.getElementById('aoDispo')?.value||'',
    date:today(),statut:'En attente'});
  save();cm();re();toast('✓ Demande enregistrée');
}
function exportOrientationExcel(){
  const data=(DB.orientationDemandes||[]).map(d=>({'Date':d.date,'Nom':d.nom,'Téléphone':d.tel,'Niveau':d.niveau||'—','Service':d.type,'Disponibilité':d.dispo||'—','Message':d.msg||'—','Statut':d.statut}));
  exportToExcel(data,'Orientation_Conseil_'+today(),'Demandes');
}
