// v1.2.2 — QUESTION DU JOUR (partage WhatsApp = canal n°1 au Cameroun)
// Une question quotidienne (déterministe selon la date) à partager en statut/
// contact WhatsApp, avec lien vers le site → acquisition virale gratuite.
// ════════════════════════════════════════════════════════════════════
window.QUESTION_JOUR = [
  "Qui est l'auteur de « Ville Cruelle » ? (Indice : un pseudonyme de Mongo Beti)",
  "Quelle est la formule de l'aire d'un trapèze ?",
  "En quelle année le Cameroun a-t-il accédé à l'indépendance ?",
  "Qu'est-ce qu'une métaphore ? Donne un exemple.",
  "Quelle est la capitale économique du Cameroun ?",
  "Résous : 2x + 5 = 17. Que vaut x ?",
  "Cite les 3 états de la matière et un exemple de chacun.",
  "Quel temps exprime une action future : « je mangerai » ?"
];
window._questionDuJour = function(){
  var q=QUESTION_JOUR; if(!q.length) return '';
  var d=new Date(); var idx=(d.getFullYear()*1000 + (d.getMonth()*31+d.getDate())) % q.length;
  return q[idx];
};
window._questionJourHtml = function(){
  var q=_questionDuJour(); if(!q) return '';
  var site='https://veritas-school.com';
  var msg='🎓 QUESTION DU JOUR — Centre VÉRITAS\n\n'+q+'\n\n💡 La réponse avec le Prof. Ambassa (IA gratuite) : '+site;
  var waShare='https://wa.me/?text='+encodeURIComponent(msg); // partage générique (statut/contact)
  return '<div class="v-reveal" style="background:linear-gradient(135deg,#0D9488,#10B981);color:#fff;border-radius:16px;padding:16px 20px;margin:16px 0;box-shadow:0 12px 30px rgba(13,148,136,.22)">'
    +'<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap">'
      +'<div style="flex:1;min-width:220px">'
        +'<div style="font-size:10px;text-transform:uppercase;letter-spacing:2px;color:#A7F3D0;font-weight:800">❓ Question du jour</div>'
        +'<div style="font-family:Montserrat,sans-serif;font-size:15px;font-weight:800;line-height:1.35;margin-top:4px">'+_esc(q)+'</div>'
      +'</div>'
    +'</div>'
    +'<div style="display:flex;gap:8px;margin-top:12px;flex-wrap:wrap">'
      +'<button class="btn" style="background:#fff;color:#0D9488;border:none;border-radius:99px;font-weight:800;padding:9px 18px;cursor:pointer" onclick="(typeof mAgentAmbassa===\'function\'?mAgentAmbassa():(typeof vShowSec===\'function\'?vShowSec(\'elearning\'):0))">🎓 Répondre avec Ambassa</button>'
      +'<a href="'+waShare+'" target="_blank" rel="noopener" class="btn" style="background:#25D366;color:#fff;border:none;border-radius:99px;font-weight:800;padding:9px 18px;text-decoration:none">📲 Partager sur WhatsApp</a>'
    +'</div>'
  +'</div>';
};

window._palmaresHtml = function(){
  var books=DB.books||[];
  var orders=(DB.visitorOrders||[]).concat(DB.bookPurchases||[]);
  var cnt={}; orders.forEach(function(o){ if(o&&o.bid) cnt[o.bid]=(cnt[o.bid]||0)+1; });
  var topBid=null,topN=0; for(var k in cnt){ if(cnt[k]>topN){topN=cnt[k];topBid=k;} }
  var topBook=(topBid&&books.find(function(b){return b.id===topBid;})) || books.find(function(b){return b.featured;}) || books[0] || null;
  var bestRated=null,bestAvg=0;
  if(typeof getBookRating==='function'){ books.forEach(function(b){ var r=getBookRating(b.id); if(r.count>0 && r.avg>bestAvg){bestAvg=r.avg;bestRated=b;} }); }
  var battleN=0; try{ if(DB.battles){ var bs=Array.isArray(DB.battles)?DB.battles:Object.values(DB.battles); battleN=bs.length; } }catch(e){}
  // Champion de la semaine en cours (1er du leaderboard de la battle courante)
  var champ=null; try{ if(DB.battles && typeof _currentWeekKey==='function'){ var _wkb=DB.battles[_currentWeekKey()]; if(_wkb && _wkb.participants){ var _pa=Object.values(_wkb.participants).sort(function(a,b){ return (b.score-a.score) || (a.timeMs-b.timeMs); }); if(_pa.length) champ=_pa[0]; } } }catch(e){}
  var nApp=(DB.students||[]).length+(DB.visitorAccounts||[]).length;
  var tile=function(o){
    return '<div onclick="'+o.click+'" style="display:flex;align-items:center;gap:11px;padding:11px 12px;border-radius:13px;background:#fff;border:1px solid #E6EAF2;border-left:4px solid '+o.color+';cursor:pointer;transition:transform .2s,box-shadow .2s" onmouseover="this.style.transform=\'translateY(-2px)\';this.style.boxShadow=\'0 10px 22px rgba(20,37,84,.10)\'" onmouseout="this.style.transform=\'\';this.style.boxShadow=\'\'">'
      +'<div style="flex-shrink:0;width:40px;height:40px;border-radius:11px;display:flex;align-items:center;justify-content:center;font-size:21px;background:color-mix(in srgb,'+o.color+' 14%,#fff)">'+o.ico+'</div>'
      +'<div style="min-width:0;flex:1">'
        +'<div style="font-size:9.5px;font-weight:800;text-transform:uppercase;letter-spacing:1px;color:color-mix(in srgb,'+o.color+' 60%,#0D1B3E)">'+o.label+'</div>'
        +'<div style="font-size:13.5px;font-weight:800;color:#142554;line-height:1.25;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+o.title+'</div>'
        +(o.sub?'<div style="font-size:10.5px;color:#5B6B85;margin-top:1px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+o.sub+'</div>':'')
      +'</div><div style="color:#C3CCDD;font-size:15px;flex-shrink:0">→</div></div>';
  };
  var tiles='';
  if(topBook){ tiles+=tile({color:'#F59E0B',ico:(topBook.ico||'📘'),label:topN>0?'Manuel le plus commandé':'Manuel à la une',title:_esc(topBook.titre),sub:topN>0?(topN+' commande'+(topN>1?'s':'')+' · '+_esc(topBook.cls)):_esc(topBook.cls),click:"viewBookDetail('"+topBook.id+"')"}); }
  if(bestRated&&bestRated!==topBook){ tiles+=tile({color:'#10B981',ico:'⭐',label:'Le mieux noté',title:_esc(bestRated.titre),sub:'Note '+bestAvg.toFixed(1)+'/5 par les élèves',click:"viewBookDetail('"+bestRated.id+"')"}); }
  var champHtml='';
  if(champ){
    var _cn=_esc(champ.nom||'Anonyme'); var _ci=((_cn.replace(/[^A-Za-zÀ-ÿ]/g,'').trim()[0])||'?').toUpperCase();
    // Récompense du champion (configurable : DB.battleReward) sinon valeur par défaut
    var _reward=_esc((DB.battleReward||champ.reward||'1 mois Premium offert + badge 👑'));
    var _cls=champ.cls?(' · '+_esc(champ.cls)):'';
    champHtml='<div onclick="(typeof mBattles===\'function\'?mBattles():null)" style="cursor:pointer;padding:14px;border-radius:15px;background:linear-gradient(135deg,#FFC93C,#FB923C);box-shadow:0 8px 22px rgba(251,146,60,.28);position:relative;overflow:hidden">'
      +'<div style="position:absolute;top:8px;right:12px;font-size:10px;font-weight:800;color:#7C2D12;letter-spacing:.5px;text-transform:uppercase">👑 Champion</div>'
      +'<div style="display:flex;align-items:center;gap:12px">'
        +'<div style="flex-shrink:0;width:52px;height:52px;border-radius:50%;background:#142554;color:#FFC93C;display:flex;align-items:center;justify-content:center;font-size:22px;font-weight:900;border:2px solid #fff;box-shadow:0 4px 12px rgba(0,0,0,.25)">'+_ci+'</div>'
        +'<div style="min-width:0;flex:1">'
          +'<div style="font-size:9.5px;font-weight:800;text-transform:uppercase;letter-spacing:1px;color:#7C2D12">Battle de la semaine'+_cls+'</div>'
          +'<div style="font-size:16px;font-weight:900;color:#142554;line-height:1.2;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+_cn+'</div>'
          +'<div style="font-size:12px;font-weight:700;color:#7C2D12;margin-top:1px">🏆 '+(champ.score||0)+'/10'+(champ.timeMs?' · '+Math.round(champ.timeMs/1000)+'s':'')+'</div>'
        +'</div>'
      +'</div>'
      +'<div style="margin-top:10px;padding:8px 10px;border-radius:10px;background:rgba(20,37,84,.12);font-size:11px;font-weight:700;color:#142554;display:flex;align-items:center;gap:6px"><span>🎁</span><span style="min-width:0;flex:1">Récompense : '+_reward+'</span></div>'
      +'<button onclick="event.stopPropagation();(typeof mBattles===\'function\'?mBattles():showJeuxEdu())" style="margin-top:8px;width:100%;border:none;cursor:pointer;padding:9px;border-radius:10px;background:#142554;color:#FFC93C;font-weight:800;font-size:12px;letter-spacing:.3px">⚔️ Détrône le champion →</button>'
    +'</div>';
  } else {
    tiles+=tile({color:'#FB923C',ico:'⚔️',label:'Battle de la semaine',title:'10 QCM · Classement national',sub:battleN>0?(battleN+' duel'+(battleN>1?'s':'')+' en cours'):'+50 XP — relevez le défi !',click:"(typeof mBattles===\'function\'?mBattles():showJeuxEdu())"});
  }
  // ── Plan d'abonnement le PLUS souscrit (émulation : « rejoignez les autres ») ──
  var _plans=(DB.elearning&&DB.elearning.plans)||[];
  var _abos=(DB.elearning&&DB.elearning.abonnements)||[];
  var _pcnt={}; _abos.forEach(function(a){ var p=a&&(a.planId||a.plan); if(p)_pcnt[p]=(_pcnt[p]||0)+1; });
  var _topPlanId=null,_topPlanN=0; for(var _pk in _pcnt){ if(_pcnt[_pk]>_topPlanN){_topPlanN=_pcnt[_pk];_topPlanId=_pk;} }
  var _topPlan=(_topPlanId&&_plans.find(function(p){return p.id===_topPlanId;}))
            || _plans.find(function(p){return p.populaire||p.featured;})
            || _plans[0] || null;
  if(_topPlan){
    var _pp=(typeof fmt==='function'&&_topPlan.prix!=null)?fmt(_topPlan.prix):'';
    var _psub=_topPlanN>0
      ? ('🔥 '+_topPlanN+' élève'+(_topPlanN>1?'s ont':' a')+' déjà choisi ce plan — rejoignez-les !')
      : (_pp?('Dès '+_pp+' — débloquez tout le contenu'):'Débloquez tout le contenu premium');
    tiles+=tile({color:'#7C3AED',ico:'🚀',label:'Abonnement le plus choisi',title:_esc(_topPlan.nom||'Plan Premium')+(_pp?(' · '+_pp):''),sub:_psub,click:"(typeof vShowSec===\'function\'?vShowSec(\'elearning\'):(typeof showRegisterForm===\'function\'?showRegisterForm():null))"});
  } else {
    tiles+=tile({color:'#7C3AED',ico:'🔥',label:'Rejoignez le palmarès',title:'XP · Badges · Niveaux',sub:nApp>0?('Déjà '+nApp+' apprenants inscrits — rejoignez-les !'):'Soyez le premier !',click:"(typeof showRegisterForm===\'function\'?showRegisterForm():null)"});
  }
  return '<div style="min-height:300px;height:100%;background:linear-gradient(180deg,#fff,#F7F9FF);border:1px solid #E6EAF2;border-radius:var(--r3,20px);box-shadow:0 4px 24px rgba(20,37,84,.08);display:flex;flex-direction:column;overflow:hidden">'
    +'<div style="padding:14px 16px;background:linear-gradient(135deg,#142554,#1E3A8A);color:#fff;display:flex;align-items:center;gap:10px;flex-shrink:0">'
      +'<span style="font-size:22px">🏆</span>'
      +'<div><div style="font-family:var(--ds-font-display,Montserrat),sans-serif;font-weight:800;font-size:15px;letter-spacing:.3px">Palmarès de la semaine</div>'
      +'<div style="font-size:10px;color:#FFC93C;font-weight:700;letter-spacing:1px;text-transform:uppercase">L\'émulation VÉRITAS</div></div>'
    +'</div>'
    +'<div style="padding:12px;display:flex;flex-direction:column;gap:10px;flex:1;overflow-y:auto">'+champHtml+tiles+'</div>'
  +'</div>';
};

function buildIntroVideoHtml(){
  var v=DB&&DB.introVideo;
  var nom=(DB&&DB.school&&DB.school.nom)||"VÉRITAS";
  var sl=(DB&&DB.publicInfo&&DB.publicInfo.slogan)||"La Réussite Assurée";

  // Overlay commun — bouton son uniquement, sans texte superflu
  function buildOverlay(withSoundBtn){
    if(!withSoundBtn) return '';
    return '<div class="vhero-video-overlay">'
      + '<div class="vhero-vo-top">'
        + '<button class="vhero-sound-btn muted" id="vheroSoundBtn" onclick="_vheroToggleSound(event)" title="Activer le son">🔇 <span>Activer le son</span></button>'
      + '</div>'
    + '</div>';
  }

  // ── 1. Vidéo YouTube configurée par l'admin ──
  if(v&&v.src&&(v.src.indexOf('youtube')>=0||v.src.indexOf('youtu.be')>=0)){
    var vid=v.src;
    vid=vid.replace('watch?v=','embed/');
    vid=vid.replace('youtu.be/','youtube.com/embed/');
    if(vid.indexOf('/embed/')<0){
      var mv=vid.match(/[?&]v=([^&]+)/);
      if(mv)vid='https://www.youtube.com/embed/'+mv[1];
    }
    // Extraire l'ID vidéo pour pouvoir basculer muet/son via postMessage
    var ytId='';
    var mId=vid.match(/\/embed\/([^?&/]+)/);
    if(mId)ytId=mId[1];
    if(vid.indexOf('?')<0)vid+='?'; else vid+='&';
    vid+='autoplay=1&mute=1&loop=1&rel=0&modestbranding=1&controls=1&playsinline=1&enablejsapi=1';
    if(ytId) vid+='&playlist='+ytId; // nécessaire pour le loop YouTube
    return '<div class="vhero-video-wrap" data-vtype="youtube">'
      +'<iframe id="vheroIframe" src="'+vid+'" allow="autoplay;encrypted-media;fullscreen" allowfullscreen loading="lazy"></iframe>'
      +buildOverlay(true)
      +'</div>';
  }

  // ── 2. Vidéo locale dans IndexedDB (grand fichier — src strippé du localStorage) ──
  if(v&&v.idbKey&&!v.src){
    idbGetFile(v.idbKey,function(rec){
      if(rec&&rec.data){
        DB.introVideo.src=rec.data; // restaure en mémoire (non persisté en LS)
        var wrap=document.querySelector('.vhero-video-wrap[data-vtype="idb-loading"]');
        if(wrap){
          wrap.setAttribute('data-vtype','local');
          wrap.innerHTML='<video id="vheroVideo" src="'+rec.data+'" autoplay muted loop playsinline oncontextmenu="return false" controlsList="nodownload"></video>'
            +buildOverlay(true);
        }
      }
    });
    return '<div class="vhero-video-wrap" data-vtype="idb-loading">'
      +'<div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:linear-gradient(-45deg,#0D1B3E,#142554,#1E3A8A,#7C3AED);background-size:400% 400%;animation:vhAnim 8s ease infinite">'
        +'<div style="color:#fff;font-size:14px;opacity:.7;font-family:sans-serif">⏳ Chargement vidéo...</div>'
      +'</div>'
      +'</div>';
  }

  // ── 3. Vidéo URL serveur ou data URL ──
  if(v&&v.src&&(v.src.indexOf('http')===0||v.src.indexOf('data:video')===0)){
    // Pré-check : URL avec /htdocs/ = cassée, basculer directement sur gradient
    if(v.src.indexOf('/htdocs/')>=0){
      setTimeout(function(){_vheroVideoFallback();},50);
    } else {
      // Garde-fou mobile : si après 4s le video.readyState reste 0 (HAVE_NOTHING),
      // fallback vers gradient (certains navigateurs mobiles ne firent pas onerror)
      setTimeout(function(){
        var vid=document.getElementById('vheroVideo');
        if(vid&&vid.readyState===0){
          console.warn('[vhero] timeout 4s — video non chargee, fallback gradient');
          _vheroVideoFallback();
        }
      },4000);
    }
    // PAS de position:absolute sur <video> — flux normal, fonctionne sur tous les mobiles
    return '<div class="vhero-video-wrap" data-vtype="local" style="display:flex;align-items:stretch">'
      +'<video id="vheroVideo"'
      +' src="'+v.src+'"'
      +' autoplay muted loop playsinline'
      +' style="width:100%;height:100%;object-fit:cover;display:block;flex:1"'
      +' oncanplay="this.play().catch(function(){})"'
      +' onerror="_vheroVideoFallback()"'
      +'></video>'
      +'<div id="vheroPlayBtn" style="display:none;position:absolute;inset:0;z-index:10;align-items:center;justify-content:center;background:rgba(0,0,0,.4);cursor:pointer" onclick="_vheroManualPlay()">'
        +'<div style="width:68px;height:68px;border-radius:50%;background:rgba(255,255,255,.92);display:flex;align-items:center;justify-content:center;box-shadow:0 4px 28px rgba(0,0,0,.45)">'
          +'<div style="width:0;height:0;border-style:solid;border-width:13px 0 13px 24px;border-color:transparent transparent transparent #142554;margin-left:5px"></div>'
        +'</div>'
      +'</div>'
      +buildOverlay(true)
      +'</div>';
  }

  // ── 4. Tentative auto : vidéo serveur par défaut (uploadée par l'admin) ──
  // Même si DB.introVideo est vide sur cet appareil, le fichier peut exister sur le serveur.
  // On tente /uploads/video/intro_video.mp4 ; onerror bascule sur le gradient.
  var cfg=DB&&DB.cloudConfig;
  var base=(cfg&&cfg.url||'https://veritas-school.com/api').replace(/\/api\/?$/,'').replace(/\/+$/,'');
  var autoSrc=base+'/uploads/video/intro_video.mp4';
  return '<div class="vhero-video-wrap" data-vtype="auto" style="display:flex;align-items:stretch">'
    +'<video id="vheroVideo"'
    +' src="'+autoSrc+'"'
    +' autoplay muted loop playsinline'
    +' style="width:100%;height:100%;object-fit:cover;display:block;flex:1"'
    +' oncanplay="this.play().catch(function(){})"'
    +' onerror="_vheroShowGradient()"'
    +'></video>'
    +buildOverlay(true)
    +'</div>';
}

// Fallback si autoplay bloqué sur mobile
function _vheroCheckAutoplay(){
  var v=document.getElementById('vheroVideo');
  if(!v)return;
  if(v.paused){
    var btn=document.getElementById('vheroPlayBtn');
    if(btn)btn.style.display='flex';
  }
}
function _vheroVideoFallback(){
  // FIX : si la vidéo a une erreur (URL 404, format invalide), basculer
  // sur le gradient animé au lieu d'un play button inutile qui ne fait rien
  var v=document.getElementById('vheroVideo');
  var wrap=v?v.closest('.vhero-video-wrap'):document.querySelector('.vhero-video-wrap');
  if(wrap){
    wrap.setAttribute('data-vtype','fallback');
    _vheroShowGradient(wrap);
  }
}
// Appelé si la vidéo n'existe pas — remplace par gradient animé
// Accepte un wrap optionnel ; sinon cherche le wrap auto
function _vheroShowGradient(wrap){
  if(!wrap){
    wrap=document.querySelector('.vhero-video-wrap[data-vtype="auto"]')
      ||document.querySelector('.vhero-video-wrap[data-vtype="fallback"]')
      ||document.querySelector('.vhero-video-wrap');
  }
  if(!wrap)return;
  if(wrap.getAttribute('data-vtype')==='gradient-shown')return; // déjà affiché
  wrap.setAttribute('data-vtype','gradient-shown');
  wrap.style.cssText=(wrap.style.cssText||'')
    +';background:linear-gradient(-45deg,#0D1B3E,#142554,#1E3A8A,#7C3AED);background-size:400% 400%;animation:vhAnim 8s ease infinite;display:block;position:relative';
  var nom=(DB&&DB.school&&DB.school.nom)||'VÉRITAS';
  var sl=(DB&&DB.publicInfo&&DB.publicInfo.slogan)||'Centre d\'Excellence Scolaire';
  wrap.innerHTML='<div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:30px 20px;z-index:1">'
    +'<div style="font-size:clamp(56px,12vw,88px);filter:drop-shadow(0 4px 24px rgba(0,0,0,.4));animation:float 6s ease-in-out infinite">🎓</div>'
    +'<div style="font-family:Montserrat,sans-serif;font-size:clamp(20px,4vw,32px);font-weight:900;color:#FFC93C;margin-top:14px;text-shadow:0 2px 14px rgba(0,0,0,.5);letter-spacing:.5px">'+_esc(nom)+'</div>'
    +'<div style="font-family:Georgia,serif;font-size:clamp(12px,2vw,15px);color:rgba(255,255,255,.85);margin-top:8px;font-style:italic;max-width:600px">'+_esc(sl)+'</div>'
    +'</div>';
}
function _vheroManualPlay(){
  var v=document.getElementById('vheroVideo');
  var btn=document.getElementById('vheroPlayBtn');
  if(v){v.muted=true;v.play().then(function(){if(btn)btn.style.display='none';}).catch(function(){});}
}

// Toggle son sur la vidéo héro (seul moyen qui marche avec autoplay navigateur)
function _vheroToggleSound(ev){
  if(ev){ev.stopPropagation();ev.preventDefault();}
  var btn = document.getElementById('vheroSoundBtn');
  if(!btn) return;
  var wrap = btn.closest('.vhero-video-wrap');
  if(!wrap) return;
  var type = wrap.getAttribute('data-vtype');
  var muted; // état cible
  if(type === 'local'){
    var vd = document.getElementById('vheroVideo');
    if(!vd) return;
    vd.muted = !vd.muted;
    muted = vd.muted;
    if(!muted){
      // Essayer de relancer la lecture (au cas où le navigateur l'aurait mise en pause)
      var p = vd.play();
      if(p && p.catch) p.catch(function(){});
    }
  } else if(type === 'youtube'){
    var ifr = document.getElementById('vheroIframe');
    if(!ifr || !ifr.contentWindow) return;
    // Détermine état courant via classe
    var wasMuted = btn.classList.contains('muted');
    muted = !wasMuted;
    var cmd = muted ? 'mute' : 'unMute';
    ifr.contentWindow.postMessage('{"event":"command","func":"'+cmd+'","args":""}','*');
    if(!muted){
      ifr.contentWindow.postMessage('{"event":"command","func":"playVideo","args":""}','*');
    }
  } else {
    return;
  }
  if(muted){
    btn.classList.remove('playing');
    btn.classList.add('muted');
    btn.innerHTML = '🔇 <span>Activer le son</span>';
    btn.title = 'Activer le son';
  } else {
    btn.classList.remove('muted');
    btn.classList.add('playing');
    btn.innerHTML = '🔊 <span>Son activé</span>';
    btn.title = 'Couper le son';
  }
}

