// v2.7 — SYSTÈME DE QUOTAS IA PAR PLAN D'ABONNEMENT
// ════════════════════════════════════════════════════════════════════
// Stratégie freemium :
// - Visiteur anonyme : 2 essais TOTAL (lifetime, localStorage)
// - Visiteur inscrit gratuit : 3 essais / SEMAINE (reset lundi)
// - Plan Starter : 5 / jour
// - Plan Pro : 30 / jour
// - Plan Elite : illimité
// - Enseignant : 50 / jour
// - Admin / Super-admin : illimité

window.AI_QUOTAS = {
  // [type d'action] : { anonyme, gratuit_sem, plan_starter_j, plan_pro_j, plan_elite, enseignant_j, admin }
  default:    { anon:2,  free:3,  starter:5,  pro:30,  elite:-1, teach:50,  admin:-1 },
  ambassa:     { anon:2,  free:3,  starter:5,  pro:30,  elite:-1, teach:50,  admin:-1 },
  devoir:     { anon:2,  free:3,  starter:5,  pro:30,  elite:-1, teach:50,  admin:-1 },
  photo_ia:   { anon:1,  free:2,  starter:3,  pro:15,  elite:-1, teach:20,  admin:-1 },
  orient:     { anon:1,  free:2,  starter:3,  pro:10,  elite:-1, teach:20,  admin:-1 },
  correct:    { anon:2,  free:3,  starter:5,  pro:30,  elite:-1, teach:50,  admin:-1 }
};

// Helper : déterminer le tier de l'utilisateur courant
// v1.2.2 (bug de chaîne #2) : source de vérité unique pour « abonnement actif ».
// Tolère les libellés historiques ('Activé','actif','Payé','confirmed') pour
// éviter qu'un statut divergent prive un payant de ses accès.
window._statutActif = function(statut){
  var s = String(statut||'').toLowerCase();
  return s==='activé' || s==='active' || s==='actif' || s==='payé' || s==='paye' || s==='confirmed';
};
window._aiTier = function(){
  var ses = (typeof SES!=='undefined' && SES) ? SES : null;
  if(!ses || !ses.id) return 'anon';
  // Admin / Super-admin
  if(typeof iA==='function' && iA()) return 'admin';
  // Enseignant
  if(ses.type==='enseignant') return 'teach';
  // Élève / visiteur inscrit : chercher abonnement actif
  var abos = (DB.elearning && DB.elearning.abonnements) || [];
  var a = abos.find(function(x){
    if(!_statutActif(x.statut)) return false;
    // v1.2.2 FIX (bug de chaîne #1) : matcher aussi accountId — c'est le champ
    // réellement stocké par validerAbonnement (userId n'existe pas).
    return (x.accountId && (x.accountId===ses.id || x.accountId===ses.accountId)) ||
      x.userId===ses.id ||
      (ses.pre && x.nom===(ses.pre+' '+ses.nom)) ||
      x.nom===ses.nom ||
      (ses.tel && x.tel===ses.tel);
  });
  if(a){
    // Mapper plan vers tier
    var p = (a.plan||'').toLowerCase();
    if(p.indexOf('elite')>=0 || p==='plan4') return 'elite';
    if(p.indexOf('pro')>=0 || p==='plan3') return 'pro';
    if(p.indexOf('starter')>=0 || p==='plan2') return 'starter';
    if(p.indexOf('plan1')>=0) return 'pro'; // ancien plan1 = pro
  }
  return 'free'; // visiteur inscrit sans abonnement
};

// v1.2.2 — RÉSOLVEUR D'ACCÈS PAR FONCTIONNALITÉ (interconnexion plans ↔ packs)
// Centralise : qui a droit aux labos premium / classes virtuelles selon son plan.
// Le quota IA Ambassa, lui, est géré par AI_QUOTAS + _aiTier (déjà branché).
//   features : 'labos' (expériences premium), 'classes' (classes virtuelles live)
window.PLAN_FEATURES = {
  // tier -> { labos:bool, classes:bool }  (anon/free = découverte limitée)
  anon:    { labos:false, classes:false },
  free:    { labos:false, classes:false },
  starter: { labos:true,  classes:false },  // plan2 INTERMÉDIAIRE
  pro:     { labos:true,  classes:true  },  // plan1 EXAMEN / plan3 ENSEIGNANT
  elite:   { labos:true,  classes:true  },  // plan4 FAMILLE/ÉCOLE (tout inclus)
  teach:   { labos:true,  classes:true  },
  admin:   { labos:true,  classes:true  }
};
window._planAccess = function(feature){
  var tier = (typeof _aiTier==='function') ? _aiTier() : 'anon';
  var f = PLAN_FEATURES[tier] || PLAN_FEATURES.anon;
  return !!f[feature];
};
// Message + redirection abonnement si accès refusé. Retourne true si accès OK.
window._requirePlan = function(feature, labelFeature){
  if(_planAccess(feature)) return true;
  if(typeof iA==='function' && iA()) return true;
  var msg = (labelFeature||'Cette fonctionnalité')+' est réservée aux abonnés. '
    + 'Choisis un plan pour y accéder en illimité.';
  if(typeof M==='function'){
    M('🔒 '+(labelFeature||'Accès premium'),'Réservé aux abonnés VÉRITAS',
      '<div style="padding:14px;text-align:center;line-height:1.6">'+_esc(msg)
      +'<div style="margin-top:10px;font-size:12px;color:#6B7A99">Plans dès <b>3 000 FCFA / an</b>.</div></div>',
      '<button class="btn bo" onclick="cm()">Plus tard</button>'
      +'<button class="btn bi" onclick="cm();(typeof vShowSec===\'function\'?vShowSec(\'elearning\'):0);setTimeout(function(){var p=document.getElementById(\'elPlans\');if(p)p.scrollIntoView({behavior:\'smooth\'});},400)">Voir les plans →</button>');
  } else if(typeof toast==='function'){ toast(msg,'warn'); }
  return false;
};

// Période de comptage selon tier (lifetime, semaine, jour)
window._aiPeriod = function(tier){
  if(tier==='anon') return 'lifetime';
  if(tier==='free') return 'week';
  return 'day';
};

// Clé de stockage selon période
window._aiKey = function(action, tier){
  var p = _aiPeriod(tier);
  if(p === 'lifetime') return '_aiQ_anon_' + action;
  if(p === 'week'){
    // Numéro de semaine ISO
    var d = new Date();
    var firstJan = new Date(d.getFullYear(),0,1);
    var dayOfYear = Math.floor((d - firstJan) / 86400000);
    var week = Math.ceil((dayOfYear + firstJan.getDay() + 1) / 7);
    return '_aiQ_week_' + action + '_' + d.getFullYear() + 'W' + String(week).padStart(2,'0');
  }
  // day
  var d2 = new Date();
  return '_aiQ_day_' + action + '_' + d2.toISOString().slice(0,10);
};

// Récupérer compteur d'usage
window._aiUsed = function(action){
  var tier = _aiTier();
  var key = _aiKey(action, tier);
  try {
    if(tier === 'anon' || tier === 'free' || tier === 'day'){
      // Anon → localStorage (suit le device, pas l'user)
      if(tier === 'anon') return parseInt(localStorage.getItem(key) || '0', 10);
      // Inscrit → DB.userAIUsage par user
      var ses = (typeof SES!=='undefined' && SES) ? SES : null;
      if(ses && ses.id){
        DB.userAIUsage = DB.userAIUsage || {};
        DB.userAIUsage[ses.id] = DB.userAIUsage[ses.id] || {};
        return (DB.userAIUsage[ses.id][key] || 0);
      }
      return parseInt(localStorage.getItem(key) || '0', 10);
    }
    return parseInt(localStorage.getItem(key) || '0', 10);
  } catch(e){ return 0; }
};

// Incrémenter compteur
window._aiInc = function(action){
  var tier = _aiTier();
  var key = _aiKey(action, tier);
  var n = _aiUsed(action) + 1;
  try {
    if(tier === 'anon'){
      localStorage.setItem(key, String(n));
    } else {
      var ses = (typeof SES!=='undefined' && SES) ? SES : null;
      if(ses && ses.id){
        DB.userAIUsage = DB.userAIUsage || {};
        DB.userAIUsage[ses.id] = DB.userAIUsage[ses.id] || {};
        DB.userAIUsage[ses.id][key] = n;
        try { save(); } catch(e){}
      } else {
        localStorage.setItem(key, String(n));
      }
    }
  } catch(e){}
  return n;
};

// Récupérer la limite pour l'action courante
window._aiLimit = function(action){
  var tier = _aiTier();
  var quotas = AI_QUOTAS[action] || AI_QUOTAS.default;
  return quotas[tier] || quotas.free;
};

// Quota check + modal upgrade si dépassé
window._aiGate = function(action){
  action = action || 'default';
  var tier = _aiTier();
  var limit = _aiLimit(action);
  var used = _aiUsed(action);
  // -1 = illimité
  if(limit === -1) return true;
  if(used >= limit){
    _showQuotaExceeded(action, tier, used, limit);
    return false;
  }
  // Incrémenter le compteur (consommation)
  _aiInc(action);
  return true;
};

// Helper public : récupérer status quota (pour affichage badge)
window._aiQuotaStatus = function(action){
  action = action || 'ambassa';
  var tier = _aiTier();
  var limit = _aiLimit(action);
  var used = _aiUsed(action);
  var period = _aiPeriod(tier);
  return {
    tier: tier,
    limit: limit,
    used: used,
    remaining: limit === -1 ? -1 : Math.max(0, limit - used),
    period: period,
    unlimited: limit === -1
  };
};

