function _doAdminLogin(){
  var role = document.getElementById('otpRole')?.value || 'admin';
  var user = (document.getElementById('otpUser')?.value || '').trim();
  var pwd = document.getElementById('otpPwd')?.value || '';
  cm();
  swLR(role);
  // Pre-fill the login form
  setTimeout(function(){
    var lu = document.getElementById('lu');
    var lp = document.getElementById('lp');
    if(lu) lu.value = user;
    if(lp) lp.value = pwd;
    if(user && pwd) doLogin();
  }, 200);
}

// ── Ticker speed fix — vitesse normale ──────────────────────
function initTickerFixed(){
  var bar=document.getElementById('tickerBar');
  var sc=document.getElementById('tkScroll');
  if(!bar||!sc)return;
  var items=(DB&&DB.tickerItems&&DB.tickerItems.length)?DB.tickerItems:_DEFAULT_TICKER;
  bar.style.display='block'; bar.style.visibility='visible';
  var html=items.map(function(it){return'<span class="t-item">'+it.t+'</span><span class="t-dot">●</span>';}).join('');
  sc.innerHTML=html+html; // duplicate pour boucle sans couture
  // Vitesse lente : 5s par item, minimum 40s
  var dur=Math.max(40, items.length*5);
  // Reset animation proprement
  sc.style.animation='none';
  sc.offsetWidth; // force reflow
  sc.style.animation='tkScroll '+dur+'s linear infinite';
}

// Override initTicker
var _origInitTicker = initTicker;
initTicker = initTickerFixed;

