function _saveElContent2(){
  var titre = (document.getElementById('ec2T')?.value||'').trim();
  if(!titre){toast('Titre requis','warn');return;}
  
  var fileInput = document.getElementById('ec2File');
  var btn = document.querySelector('[onclick="_saveElContent2()"]');
  if(btn){btn.disabled=true;btn.textContent='⏳ Enregistrement...';}
  
  function doSave(dataUrl, idbKey, fname, ftype){
    if(!DB.elearning)DB.elearning=defaultDB().elearning;
    if(!DB.elearning.contenus)DB.elearning.contenus=[];
    var prix = parseInt(document.getElementById('ec2P')?.value)||0;
    var isGratuit = document.getElementById('ec2Gr')?.checked || prix===0;
    var selectedCat = document.getElementById('ec2Cat')?.value || (DB.elearning.categories||[{id:'cat1'}])[0]?.id;
    
    var item = {
      id:gid(),cat:selectedCat,
      titre:titre,
      classe:document.getElementById('ec2Cls')?.value||'',
      matiere:document.getElementById('ec2Mat')?.value||'',
      seq:document.getElementById('ec2Seq')?.value||'',
      prix:prix,gratuit:isGratuit,
      apercu:document.getElementById('ec2Ap')?.value||'',
      desc:document.getElementById('ec2De')?.value||'',
      fichier:fname||'',
      fichierData:dataUrl||'',
      idbKey:idbKey||'',
      fileType:ftype||'',
      plans:['plan1','plan2','plan3','plan4'],
      dateAjout:today()
    };
    DB.elearning.contenus.push(item);
    save();cm();re();
    toast('✅ Contenu ajouté au catalogue');
  }
  
  if(fileInput && fileInput.files && fileInput.files[0]){
    _uploadFile(fileInput, {}, function(dataUrl, idbKey, fname, ftype, fsize){
      doSave(dataUrl, idbKey, fname, ftype);
    });
  } else {
    doSave(null, null, '', '');
  }
}

