function uploadLogoFixed(){
  var input=document.createElement('input');input.type='file';input.accept='image/*';
  input.style.display='none';document.body.appendChild(input);
  input.onchange=function(e){
    var file=e.target.files[0];if(!file)return;
    if(file.size>5*1024*1024){toast('Image trop lourde (max 5Mo)','warn');return;}
    // Essayer upload serveur d'abord (cross-device) ; fallback data URL si cloud KO
    var cfg=DB.cloudConfig;
    if(cfg&&cfg.url&&cfg.secret){
      toast('⬆️ Upload logo vers le serveur...','info');
      _uploadToServer(file,_uploadCat(file),'logo_ecole',function(url,err){
        if(url){
          DB.school.logo=url;
          var logos=['loginLogo','sbLogo','vLogo'];
          logos.forEach(function(id){var el=$(id);if(el)el.src=url;});
          save();toast('✓ Logo mis à jour et sauvegardé sur le serveur ☁️');
        } else {
          // Fallback local
          _logoLocalFallback(file);
        }
      });
    } else {
      _logoLocalFallback(file);
    }
    input.remove();
  };
  setTimeout(function(){input.click();},100);
}
function _logoLocalFallback(file){
  var reader=new FileReader();
  reader.onload=function(evt){
    DB.school.logo=evt.target.result;
    var logos=['loginLogo','sbLogo','vLogo'];
    logos.forEach(function(id){var el=$(id);if(el)el.src=evt.target.result;});
    save();toast('✓ Logo mis à jour (stockage local — cloud KO)','warn');
  };reader.readAsDataURL(file);
}

// ── SQL Export ───────────────────────────────────────────────
function exportAllDataSQL(){
  var lines = [];
  lines.push('-- VÉRITAS Database Export');
  lines.push('-- Généré le ' + new Date().toLocaleString('fr-FR'));
  lines.push('');
  
  function esc(v){ return typeof v==='string' ? "'"+v.replace(/'/g,"''")+"'" : (v===null||v===undefined?'NULL':String(v)); }
  
  // Students
  lines.push('-- TABLE: eleves');
  lines.push('DROP TABLE IF EXISTS eleves;');
  lines.push('CREATE TABLE eleves (id TEXT, matricule TEXT, nom TEXT, prenom TEXT, sexe TEXT, dob TEXT, classe TEXT, telephone TEXT, parent TEXT, tel_parent TEXT, frais INTEGER, date_inscription TEXT, statut TEXT);');
  (DB.students||[]).forEach(function(s){
    lines.push('INSERT INTO eleves VALUES('+[s.id,s.mat,s.nom,s.pre,s.sex,s.dob,s.cls,s.tel||'',s.parent||'',s.ptel||'',s.frais||0,s.ins||'',s.stat||''].map(esc).join(',')+');');
  });
  lines.push('');
  
  // Teachers
  lines.push('-- TABLE: enseignants');
  lines.push('DROP TABLE IF EXISTS enseignants;');
  lines.push('CREATE TABLE enseignants (id TEXT, matricule TEXT, nom TEXT, prenom TEXT, matiere TEXT, grade TEXT, login TEXT, telephone TEXT, salaire INTEGER, statut TEXT);');
  (DB.teachers||[]).forEach(function(t){
    lines.push('INSERT INTO enseignants VALUES('+[t.id,t.mat,t.nom,t.pre,t.mat2||'',t.grade||'',t.user||'',t.tel||'',t.sal||0,t.stat||''].map(esc).join(',')+');');
  });
  lines.push('');
  
  // Payments
  lines.push('-- TABLE: paiements');
  lines.push('DROP TABLE IF EXISTS paiements;');
  lines.push('CREATE TABLE paiements (id TEXT, eleve_id TEXT, nom_eleve TEXT, classe TEXT, mois TEXT, montant INTEGER, mode TEXT, date TEXT, statut TEXT, reference TEXT);');
  (DB.payments||[]).forEach(function(p){
    lines.push('INSERT INTO paiements VALUES('+[p.id,p.eid,p.enom||'',p.cls||'',p.mo||'',p.mnt||0,p.mode||'',p.dt||'',p.stat||'',p.ref||''].map(esc).join(',')+');');
  });
  lines.push('');
  
  // Grades
  lines.push('-- TABLE: notes');
  lines.push('DROP TABLE IF EXISTS notes;');
  lines.push('CREATE TABLE notes (id TEXT, eleve_id TEXT, nom_eleve TEXT, matricule TEXT, classe TEXT, matiere TEXT, note1 REAL, note2 REAL, coef INTEGER, trimestre TEXT, enseignant TEXT);');
  (DB.grades||[]).forEach(function(g){
    lines.push('INSERT INTO notes VALUES('+[g.id,g.eid,g.enom||'',g.mat||'',g.cls||'',g.sub||'',g.n1||0,g.n2||0,g.coef||1,g.tri||'',g.ens||''].map(esc).join(',')+');');
  });
  lines.push('');
  
  // Absences
  lines.push('-- TABLE: absences');
  lines.push('DROP TABLE IF EXISTS absences;');
  lines.push('CREATE TABLE absences (id TEXT, eleve_id TEXT, date TEXT, heures INTEGER, matiere TEXT, motif TEXT, justifie INTEGER);');
  (DB.absences||[]).forEach(function(a){
    lines.push('INSERT INTO absences VALUES('+[a.id,a.eid,a.date||'',a.heures||0,a.matiere||'',a.motif||'',a.justifie?1:0].map(esc).join(',')+');');
  });
  
  var sql = lines.join('\n');
  var blob = new Blob([sql], {type:'text/plain'});
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href=url;a.download='VERITAS_export_'+today().replace(/\//g,'-')+'.sql';
  a.click();URL.revokeObjectURL(url);
  toast('✅ Export SQL téléchargé');
}

