// CORRECTION DE DEVOIRS PAR IA (v1.2 OPTIMISATION — Priorité 1 #4)
// Permet à un élève de soumettre un devoir (rédaction, exo maths, dissertation)
// et de recevoir une correction détaillée, note /20, points forts/faibles.
// ═══════════════════════════════════════════════════════════════════════════
window.mDevoirCorrectionIA = function(){
  if(typeof M !== 'function') return;
  // FIX v1.2 : ne pas gater à l'ouverture du modal, seulement à l'exécution
  var u = (typeof _aiUsed==='function')?_aiUsed('devoir'):0;
  var lim = (typeof _aiLimit==='function')?_aiLimit('devoir'):3;
  if(lim!==-1 && u>=lim && typeof _showQuotaExceeded==='function'){ _showQuotaExceeded('devoir', (typeof _aiTier==='function'?_aiTier():'free'), u, lim); return; }
  var rem = Math.max(0, lim-u);
  var badge = lim>=999 ? '∞ Illimité' : rem+' correction'+(rem>1?'s':'')+' aujourd\'hui';

  M('📝 Correction de devoir par IA','Soumets ton devoir, l\'IA te corrige en 30 s',
    '<div class="ib ibt mb12"><span>🎯</span><span>Idéal pour : <b>rédactions, dissertations, commentaires, exercices de maths, problèmes physique-chimie</b>. Tu reçois une note /20, les points forts, les axes d\'amélioration. <b>'+badge+'</b>.</span></div>'+
    '<div class="fg mb10"><span class="fl">Matière *</span>'+
      '<select class="fi" id="dvSub">'+
        ['Français — Rédaction','Français — Dissertation','Français — Commentaire composé','Français — Résumé','Anglais — Essay','Mathématiques','Physique-Chimie','SVT','Histoire-Géographie','Philosophie','Économie','Informatique','Autre']
        .map(function(s){return '<option>'+s+'</option>';}).join('')+
      '</select></div>'+
    '<div class="fg mb10"><span class="fl">Niveau *</span>'+
      '<select class="fi" id="dvLvl">'+
        ['6ème','5ème','4ème','3ème','2nde','1ère A','1ère C','1ère D','Tle A','Tle C','Tle D','Probatoire','BAC blanc','BAC officiel']
        .map(function(s){return '<option>'+s+'</option>';}).join('')+
      '</select></div>'+
    '<div class="fg mb10"><span class="fl">Sujet / Consigne du devoir *</span>'+
      '<textarea class="fi" id="dvConsigne" rows="2" placeholder="Ex: Dissertez sur la phrase de Mongo Beti..."></textarea></div>'+
    '<div class="fg mb10"><span class="fl">Ton travail (texte ou réponse) *</span>'+
      '<textarea class="fi" id="dvTravail" rows="8" placeholder="Colle ici ta rédaction, ta dissertation ou la résolution de ton exercice..." style="font-family:Georgia,serif;font-size:13.5px;line-height:1.6"></textarea></div>'+
    '<div id="dvRes" class="ai-res" style="display:none"></div>',
    '<button class="btn bo" onclick="cm()">Annuler</button>'+
    '<button class="btn bgr2" id="dvBtn" onclick="_runCorrectionIA()">🤖 Corriger ('+rem+' restant'+(rem>1?'s':'')+')</button>',true);
};

window._runCorrectionIA = async function(){
  if(typeof _aiGate==='function' && !_aiGate('devoir')) return;
  var sub = (document.getElementById('dvSub')?.value||'').trim();
  var lvl = (document.getElementById('dvLvl')?.value||'').trim();
  var con = (document.getElementById('dvConsigne')?.value||'').trim();
  var trv = (document.getElementById('dvTravail')?.value||'').trim();
  if(!con){toast('Indique la consigne du devoir','warn');return;}
  if(trv.length<40){toast('Ton travail doit faire au moins 40 caractères','warn');return;}
  var btn=document.getElementById('dvBtn'),res=document.getElementById('dvRes');
  if(btn){btn.disabled=true;btn.innerHTML='⏳ Correction en cours…';}

  var prompt =
    'Tu es un enseignant expert du système éducatif camerounais (MINESEC), bienveillant et exigeant. '+
    'Tu vas corriger le travail d\'un élève de '+lvl+' en '+sub+'. '+
    '\n\n=== CONSIGNE DU DEVOIR ===\n'+con+
    '\n\n=== TRAVAIL DE L\'ÉLÈVE ===\n'+trv+
    '\n\n=== TA CORRECTION (structure obligatoire avec ** pour les titres) ===\n'+
    '**📊 Note proposée : X/20** (sois juste, ni trop sévère ni complaisant)\n\n'+
    '**✅ Points forts** — Liste 2-3 points concrets que l\'élève maîtrise bien.\n\n'+
    '**⚠️ Points à améliorer** — Liste 3-4 erreurs précises (fautes de langue, manques d\'analyse, défauts de structure…) avec des CITATIONS du texte de l\'élève si possible.\n\n'+
    '**💡 Conseils pour progresser** — 3 conseils concrets et actionnables, adaptés au niveau '+lvl+'.\n\n'+
    '**✨ Si je devais réécrire un paragraphe** — Propose une réécriture améliorée d\'un passage faible (max 60 mots).\n\n'+
    'Sois précis, encourageant, et toujours pédagogique. Max 500 mots. En français standard.';

  try{
    var txt = await callClaudeAPI(prompt);
    // FIX v1.2 : _aiGate() a déjà incrémenté le compteur — ne pas appeler _aiInc() une 2ème fois
    var rem2 = (typeof _aiLimit==='function' && typeof _aiUsed==='function')
      ? Math.max(0, _aiLimit('devoir')-_aiUsed('devoir')) : 0;
    if(res){
      res.style.display='block';
      // Formatter le markdown léger ** ** → <strong>
      var html = (typeof _aiMarkdown==='function') ? _aiMarkdown(txt) : _esc(txt).replace(/\n/g,'<br>');
      res.innerHTML = '<div class="ai-md" style="background:linear-gradient(135deg,#FAF5FF,#EDE9FE);border-left:4px solid #7C3AED;border-radius:12px;padding:16px 20px">'+html+'</div>'+
        '<div style="margin-top:12px;font-size:11px;color:#64748B;text-align:right;font-style:italic">Correction générée par IA pédagogique — Centre VÉRITAS</div>';
      res.scrollIntoView({behavior:'smooth',block:'nearest'});
    }
    // Sauvegarder la correction dans l'historique de l'utilisateur
    if(SES && SES.id){
      DB._aiCorrections = DB._aiCorrections || [];
      DB._aiCorrections.unshift({
        id:'corr_'+Date.now(),
        userId: SES.id,
        sub: sub, lvl: lvl, consigne: con,
        date: new Date().toISOString(),
        correction: txt.substring(0,2000) // limite stockage
      });
      if(DB._aiCorrections.length>50) DB._aiCorrections.length=50;
      if(typeof save==='function') save();
    }
    if(btn){btn.disabled=false;btn.innerHTML='🔄 Corriger un autre devoir ('+rem2+' restant'+(rem2>1?'s':'')+')';}
  }catch(e){
    toast('Erreur IA : '+e.message,'err');
    if(btn){btn.disabled=false;btn.innerHTML='🤖 Réessayer';}
  }
};

async function callClaudeAPI(prompt, sysPrompt){
  // v2.9.10 — Avec logs de diagnostic pour identifier où ça échoue côté client
  console.log("[IA] callClaudeAPI appelée — prompt=" + (prompt||'').length + " chars, sys=" + (sysPrompt||'').length + " chars");
  var sys = sysPrompt || "Tu es un assistant pédagogique expert du système éducatif camerounais (MINESEC/MINESUP). Tu connais les programmes BEPC et BAC séries A/C/D, les grandes écoles camerounaises et tu contextualises dans la réalité camerounaise.";

  // ── v1.2.1 : IA routée via le SERVEUR (api/ia_proxy.php) ──────────────────────
  // Pollinations.ai (appel direct navigateur) a été DÉPRÉCIÉ en 2026 : il renvoie un
  // message « legacy text API deprecated » au lieu d'une réponse. On passe donc par
  // notre proxy serveur (clé IA gratuite côté serveur, jamais exposée au client).
  try {
    var _base=(DB&&DB.cloudConfig&&DB.cloudConfig.url|| ((location.origin.indexOf('veritas-school.com')>=0)?location.origin+'/api':'https://veritas-school.com/api')).replace(/\/+$/,'');
    var _ses=(typeof SES!=='undefined'&&SES)?SES:null;
    // v1.2.1 : RAG — chercher des passages d'annales/corpus (rag.php) pour ancrer la réponse.
    // Dégradé proprement (contexte vide) si biblio_index.db n'est pas encore déposé sur le serveur.
    var _ragCtx='';
    try{
      var _rr=await fetch(_base+'/rag.php?limit=4&q='+encodeURIComponent(String(prompt||'').slice(0,180)),{method:'GET'});
      if(_rr.ok){ var _rj=await _rr.json(); if(_rj&&_rj.ok&&_rj.passages&&_rj.passages.length){ _ragCtx=_rj.passages.map(function(p){return '— '+(p.auteur||'?')+', '+(p.titre||'?')+(p.annee?(' ('+p.annee+')'):'')+' : '+p.extrait;}).join('\n'); } }
    }catch(_eRag){}
    var _r=await fetch(_base+'/ia_proxy.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({prompt:String(prompt||''),sysPrompt:sys,ragContext:_ragCtx,userId:_ses&&_ses.id?_ses.id:'',plan:_ses&&_ses.type?_ses.type:'anon'})});
    if(_r.ok){
      var _j=await _r.json();
      if(_j&&_j.text&&!/legacy text API|deprecat|enter\.pollinations/i.test(_j.text)){ console.log('[IA] via ia_proxy ('+(_j.source||'?')+')'); return _j.text; }
      if(_j&&_j.error){ console.warn('[IA] ia_proxy:',_j.error); return "⚠️ "+_j.error; }
    } else { console.warn('[IA] ia_proxy HTTP '+_r.status); }
  } catch(_eP){ console.warn('[IA] ia_proxy injoignable:',_eP.message); }
  return "⚠️ L'assistant IA est momentanément indisponible. Réessayez dans un instant. (Si le problème persiste, l'administrateur doit configurer la clé IA gratuite du serveur — voir api/payment_config.php.)";

  // ── ESSAI 1 : Pollinations.ai en POST (format OpenAI chat-completions, long context OK) ──
  try {
    console.log("[IA] Essai 1 : POST https://text.pollinations.ai/ (body messages JSON)");
    var resp = await fetch("https://text.pollinations.ai/", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        messages: [
          { role: "system", content: sys },
          { role: "user",   content: prompt }
        ],
        model: "openai",
        private: true,
        stream: false
      })
    });
    console.log("[IA] POST → status " + resp.status + " (ok=" + resp.ok + ")");
    if (resp.ok) {
      var txt = await resp.text();
      console.log("[IA] POST réponse : " + txt.length + " chars, début : " + txt.substring(0, 80));
      if (txt && txt.trim().length > 20) {
        try {
          var parsed = JSON.parse(txt);
          if (parsed.choices && parsed.choices[0] && parsed.choices[0].message) {
            console.log("[IA] Format OpenAI détecté, extraction content");
            return parsed.choices[0].message.content;
          }
          if (typeof parsed === "string") return parsed;
        } catch(eParse){ console.log("[IA] Pas du JSON, retour texte brut"); }
        return txt.trim();
      } else {
        console.warn("[IA] POST trop court ou vide → fallback GET");
      }
    } else {
      console.warn("[IA] POST status " + resp.status + " → fallback GET");
    }
  } catch(e1) { console.warn("[IA] POST exception :", e1.message); }

  // ── ESSAI 2 : Pollinations.ai en GET avec system PROMPT TRONQUÉ (fallback courte URL) ──
  try {
    var shortSys = sys.length > 1500 ? (sys.substring(0, 1500) + "\n[...persona tronqué...]") : sys;
    var url = "https://text.pollinations.ai/" + encodeURIComponent(shortSys + "\n\nQuestion: " + prompt + "\n\nRéponds en français:") + "?model=openai";
    console.log("[IA] Essai 2 : GET (URL " + url.length + " chars)");
    if (url.length < 1900) {
      var resp2 = await fetch(url, { method: "GET", headers: { "Accept": "text/plain" } });
      console.log("[IA] GET sys+prompt → status " + resp2.status);
      if (resp2.ok) {
        var txt2 = await resp2.text();
        if (txt2 && txt2.trim().length > 20) return txt2.trim();
      }
    } else {
      console.warn("[IA] URL trop longue (" + url.length + " chars), saut");
    }
  } catch(e2) { console.warn("[IA] GET sys+prompt exception :", e2.message); }

  // ── ESSAI 3 : Pollinations en GET avec UNIQUEMENT le prompt (dernier recours) ──
  try {
    var minimalUrl = "https://text.pollinations.ai/" + encodeURIComponent(prompt);
    console.log("[IA] Essai 3 : GET minimal (URL " + minimalUrl.length + " chars)");
    if (minimalUrl.length < 1900) {
      var resp3 = await fetch(minimalUrl);
      console.log("[IA] GET minimal → status " + resp3.status);
      if (resp3.ok) {
        var txt3 = await resp3.text();
        if (txt3 && txt3.trim().length > 20) return txt3.trim();
      }
    }
  } catch(e3) { console.warn("[IA] GET minimal exception :", e3.message); }

  console.error("[IA] TOUS LES ESSAIS ONT ÉCHOUÉ — retour message d'erreur");
  return "⚠️ Service IA temporairement indisponible. Si le problème persiste, ouvrez la console (F12) et envoyez les messages [IA] à votre administrateur.";
}

