// ── TICKER ADMIN ──────────────────────────────────────────────────
function mManageTickerAdmin(){
  if(!iA())return;
  if(!DB.tickerItems||!DB.tickerItems.length) DB.tickerItems=(_DEFAULT_TICKER||[]).slice();
  var rows=(DB.tickerItems||[]).map(function(it,i){
    var txt=it.t.length>70?it.t.substring(0,70)+"...":it.t;
    return "<tr><td style='padding:5px 8px;font-size:12px'>"+txt+"</td>"
      +"<td style='padding:4px 8px;white-space:nowrap'>"
      +"<button class='btn bo xs' data-ti='"+i+"' onclick='_tkUp(this)'>↑</button> "
      +"<button class='btn br2 xs' data-ti='"+i+"' onclick='_tkDel(this)'>🗑</button>"
      +"</td></tr>";
  }).join("");
  M("📢 Bandeau defilant","Actualisez les messages en temps reel",
    "<div class='ib ibt mb10'><span>💡</span><span>Messages visibles sur le portail. Survolez pour mettre en pause.</span></div>"
    +(rows?"<div class='tw mb12' style='max-height:200px;overflow-y:auto'><table style='width:100%'><thead><tr style='background:var(--bg2)'><th style='padding:5px 8px;text-align:left'>Message</th><th></th></tr></thead><tbody>"+rows+"</tbody></table></div>"
          :"<div class='empty mb10'><div class='empty-ico'>📢</div>Aucun message</div>")
    +"<div style='border-top:var(--br);padding-top:12px'>"
    +"<textarea class='fi mb8' id='tkNew' rows='2' placeholder='📅 BEPC 2025 le 12 juin... ou 💡 Saviez-vous ? ...'></textarea>"
    +"<div class='fl2 g8'>"
    +"<button class='btn bi sm' onclick='_tkAdd()'>➕ Ajouter</button>"
    +"<button class='btn' style='background:#F0F4FF;color:#142554;border-radius:10px;font-size:12px;padding:7px 14px;font-weight:700' onclick='_tkReset()'>↺ Defaut</button>"
    +"</div></div>",
    "<button class='btn bo' onclick='cm()'>Fermer</button>"
    +"<button class='btn bi' onclick='initTicker();cm();toast(\"Bandeau actualise\")'>▶ Appliquer</button>",true);
}
function _tkAdd(){
  var t=(document.getElementById("tkNew")?.value||"").trim();
  if(!t){toast("Message requis","warn");return;}
  if(!DB.tickerItems)DB.tickerItems=[];
  DB.tickerItems.unshift({t:t});save();initTicker();
  cm();setTimeout(mManageTickerAdmin,80);toast("Message ajoute");
}
function _tkDel(btn){var i=parseInt(btn.dataset.ti);if(isNaN(i)||!DB.tickerItems)return;DB.tickerItems.splice(i,1);save();initTicker();cm();setTimeout(mManageTickerAdmin,80);}
function _tkUp(btn){var i=parseInt(btn.dataset.ti);if(isNaN(i)||i<=0||!DB.tickerItems)return;var t=DB.tickerItems[i-1];DB.tickerItems[i-1]=DB.tickerItems[i];DB.tickerItems[i]=t;save();initTicker();cm();setTimeout(mManageTickerAdmin,80);}
function _tkReset(){DB.tickerItems=(_DEFAULT_TICKER||[]).slice();save();initTicker();cm();setTimeout(mManageTickerAdmin,80);toast("Reinitialise");}

// ── PACKS ADMIN CRUD ───────────────────────────────────────────────
function mManagePacksAdmin(){
  if(!iA())return;
  var plans=(DB.elearning&&DB.elearning.plans)||[];
  var cards=plans.map(function(p,i){
    var durL={mensuel:"Mensuel",trimestriel:"Trimestriel",semestriel:"Semestriel",annuel:"Annuel",vacances:"Vacances",conges:"Conges"};
    return "<div style='border:2px solid var(--bg3);border-radius:14px;padding:14px;position:relative'>"
      +(p.populaire?"<div style='position:absolute;top:8px;right:8px;background:#FFC93C;color:#142554;font-size:9px;font-weight:800;padding:2px 8px;border-radius:10px'>POPULAIRE</div>":"")
      +"<div style='font-size:9px;color:var(--ink4);margin-bottom:4px'>"+(durL[p.duree]||"Annuel")+"</div>"
      +"<div style='font-family:Montserrat,sans-serif;font-size:14px;font-weight:800;color:#142554;margin-bottom:4px'>"+p.nom+"</div>"
      +"<div style='font-family:Georgia,serif;font-size:20px;font-weight:700;color:var(--gold2)'>"+fmtN(p.prix)+" FCFA</div>"
      +"<div style='font-size:11px;color:var(--ink4);margin:4px 0 8px'>"+(p.cible||"")+"</div>"
      +"<div class='fl2 g6'>"
      +"<button class='btn bo sm' onclick='_editPkI("+i+")'>✏️</button>"
      +"<button class='btn br2 sm' onclick='_delPkI("+i+")'>🗑</button>"
      +"</div></div>";
  }).join("");
  M("📦 Packs abonnement","Creez et gerez vos offres",
    "<div class='ib ibt mb12'><span>💡</span><span>Les packs definissent les acces aux ressources premium et le quota IA quotidien.</span></div>"
    +"<div style='display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:12px;margin-bottom:14px'>"
    +(cards||"<div class='empty'><div class='empty-ico'>📦</div>Aucun pack</div>")
    +"</div><button class='btn bi sm' onclick='_pkNewUI()'>➕ Creer un pack</button>",
    "<button class='btn bo' onclick='cm()'>Fermer</button>",true);
}
function _editPkI(i){window._editPkIdx=i;_pkFormUI((DB.elearning&&DB.elearning.plans||[])[i]||null);}
function _delPkI(i){if(!confirm("Supprimer ce pack ?"))return;if(DB.elearning&&DB.elearning.plans)DB.elearning.plans.splice(i,1);save();cm();toast("Pack supprime");setTimeout(mManagePacksAdmin,80);}
function _pkNewUI(){window._editPkIdx=-1;_pkFormUI(null);}
function _pkFormUI(p){
  var avStr=p?(p.avantages||[]).join("|"):"";
  var duree=p&&p.duree?p.duree:"annuel";
  M(p?"✏️ Modifier le pack":"➕ Nouveau pack","",
    "<div class='fg2'>"
    +"<div class='fg'><span class='fl'>Nom *</span><input class='fi' id='pkfNom' value='"+(p?p.nom:"")+"' placeholder='Pack EXAMEN BEPC'></div>"
    +"<div class='fg'><span class='fl'>Duree</span><select class='fi' id='pkfDuree'>"
    +"<option value='mensuel'"+(duree=="mensuel"?" selected":"")+" >Mensuel (1 mois)</option>"
    +"<option value='trimestriel'"+(duree=="trimestriel"?" selected":"")+" >Trimestriel (3 mois)</option>"
    +"<option value='semestriel'"+(duree=="semestriel"?" selected":"")+" >Semestriel (6 mois)</option>"
    +"<option value='annuel'"+(duree=="annuel"?" selected":"")+" >Annuel (12 mois)</option>"
    +"<option value='vacances'"+(duree=="vacances"?" selected":"")+" >Vacances scolaires</option>"
    +"<option value='conges'"+(duree=="conges"?" selected":"")+" >Conges speciaux</option>"
    +"</select></div>"
    +"<div class='fg'><span class='fl'>Identifiant</span><input class='fi' id='pkfId' value='"+(p?p.id:"pk"+Date.now())+"' "+(p?"readonly":"")+" placeholder='pk_examen'></div>"
    +"<div class='fg'><span class='fl'>Cible</span><input class='fi' id='pkfCible' value='"+(p?p.cible||"":"")+"' placeholder='Eleves 3eme et Terminale'></div>"
    +"<div class='fg'><span class='fl'>Prix FCFA *</span><input class='fi' id='pkfPrix' type='number' value='"+(p?p.prix:"")+"' placeholder='15000'></div>"
    +"<div class='fg'><span class='fl'>Ancien prix barre</span><input class='fi' id='pkfAnc' type='number' value='"+(p&&p.ancien?p.ancien:"")+"' placeholder='25000'></div>"
    +"<div class='fg full'><span class='fl'>Avantages (separes par |)</span>"
    +"<textarea class='fi' id='pkfAv' rows='4' placeholder='Acces epreuves BEPC|Cours videos|IA illimitee|Support WhatsApp'>"+avStr+"</textarea></div>"
    +"<div class='fg'><span class='fl'>Quota IA/jour (vide=illimite)</span><input class='fi' id='pkfIa' type='number' value='"+(p&&p.iaLimit?p.iaLimit:"")+"' placeholder='25'></div>"
    +"<div class='fg full'><label style='display:flex;align-items:center;gap:8px;cursor:pointer'>"
    +"<input type='checkbox' id='pkfPop'"+(p&&p.populaire?" checked":"")+">"
    +"<span class='fl'>Marquer comme populaire</span></label></div>"
    +"</div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn bi' onclick='_savePkForm()'>"+(p?"Modifier":"Creer le pack")+"</button>",true);
}
function _savePkForm(){
  var nom=(document.getElementById("pkfNom")?.value||"").trim();
  var prix=parseInt(document.getElementById("pkfPrix")?.value)||0;
  if(!nom||!prix){toast("Nom et prix requis","warn");return;}
  if(!DB.elearning)DB.elearning=defaultDB().elearning;
  if(!DB.elearning.plans)DB.elearning.plans=[];
  var av=(document.getElementById("pkfAv")?.value||"").split("|").map(function(a){return a.trim();}).filter(Boolean);
  var ia=parseInt(document.getElementById("pkfIa")?.value)||0;
  var duree=document.getElementById("pkfDuree")?.value||"annuel";
  var isEdit=window._editPkIdx>=0;
  if(isEdit){
    var pp=DB.elearning.plans[window._editPkIdx];
    if(!pp){toast("Pack introuvable","warn");return;}
    pp.nom=nom;pp.cible=document.getElementById("pkfCible")?.value||"";
    pp.prix=prix;pp.ancien=parseInt(document.getElementById("pkfAnc")?.value)||0;
    pp.avantages=av;pp.iaLimit=ia||undefined;pp.duree=duree;
    pp.populaire=document.getElementById("pkfPop")?.checked||false;
    toast("Pack mis a jour");
  }else{
    var id=(document.getElementById("pkfId")?.value||"pk"+Date.now()).replace(/[^a-z0-9_]/gi,"_");
    if((DB.elearning.plans||[]).find(function(x){return x.id===id;})){toast("ID deja utilise","warn");return;}
    DB.elearning.plans.push({id:id,nom:nom,duree:duree,cible:document.getElementById("pkfCible")?.value||"",
      prix:prix,ancien:parseInt(document.getElementById("pkfAnc")?.value)||0,
      avantages:av,populaire:document.getElementById("pkfPop")?.checked||false,iaLimit:ia||undefined});
    toast("Pack cree");
  }
  save();cm();re();
}

// ── VIDÉO D'ACCUEIL ────────────────────────────────────────────────
function mSetIntroVideo(){
  if(!iA())return;
  var v=DB.introVideo||{};
  // Réinitialiser l'état de sélection
  window._pVidFile=null;
  window._pVidMime=v.mime||"video/mp4";
  var previewHtml;
  if(v.src&&!v.src.startsWith('data:')){
    // URL serveur ou YouTube : aperçu lecture directe
    previewHtml="<video src='"+v.src+"' controls style='width:100%;max-height:140px;border-radius:8px'></video>"
      +"<div style='font-size:11px;color:#6B7A99;margin-top:4px'>"+v.src+"</div>";
  }else if(v.src&&v.src.indexOf('data:video')===0){
    previewHtml="<div style='background:#FFF7ED;border:2px solid #FED7AA;border-radius:10px;padding:14px;font-size:12px;color:#92400E'>⚠️ Vidéo stockée localement (ancien format). Réenregistrez pour l'héberger sur le serveur.</div>";
  }else if(v.idbKey){
    previewHtml="<div style='background:#FFF7ED;border:2px solid #FED7AA;border-radius:10px;padding:14px;font-size:12px;color:#92400E'>⚠️ Vidéo en stockage local (IndexedDB). Sélectionnez-la à nouveau pour l'héberger sur le serveur.</div>";
  }else{
    previewHtml="<div style='background:#F8FAFF;border:2px dashed #C7D2FE;border-radius:10px;padding:20px;text-align:center;color:#6B7A99;font-size:13px'>Aucune vidéo configurée</div>";
  }
  M("🎬 Vidéo de présentation","Lecture automatique muette sur la page d'accueil",
    "<div class='ib ibt mb12'><span>💡</span><span>La vidéo sera envoyée sur votre serveur — max 100 Mo, MP4/WebM recommandé.</span></div>"
    +"<div class='fg mb12'><span class='fl'>Choisir un fichier vidéo (MP4/WebM)</span>"
    +"<input type='file' id='ivFile' accept='video/*' class='fi' style='padding:8px' onchange='_ivLoad(this)'></div>"
    +"<div id='ivPreview' style='margin-bottom:12px'>"+previewHtml+"</div>"
    +"<div class='fg mb10'><span class='fl'>Ou coller une URL vidéo directe (MP4/YouTube)</span>"
    +"<input class='fi' id='ivUrl' value='"+(v.src&&!v.src.startsWith("data:")?_esc(v.src):"")+"' placeholder='https://veritas-school.com/... ou YouTube'></div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn br2' onclick='_ivClear()'>🗑 Supprimer</button>"
    +"<button class='btn bi' onclick='_ivSave()'>⬆️ Enregistrer</button>",true);
}
function _ivLoad(inp){
  if(!inp.files[0])return;
  if(inp.files[0].size>104857600){toast("Max 100 Mo","warn");return;}
  window._pVidFile=inp.files[0];
  window._pVidMime=inp.files[0].type||"video/mp4";
  // Aperçu immédiat via ObjectURL (sans lire tout le fichier en base64)
  var objUrl=URL.createObjectURL(inp.files[0]);
  var prev=document.getElementById("ivPreview");
  if(prev)prev.innerHTML="<video src='"+objUrl+"' controls style='width:100%;max-height:140px;border-radius:8px'></video>"
    +"<div style='font-size:11px;color:#6B7A99;margin-top:6px;text-align:center'>"+Math.round(inp.files[0].size/1048576*10)/10+" Mo — sera envoyé sur le serveur à l'enregistrement</div>";
  toast("Vidéo prête");
}
function _ivSave(){
  var urlVal=(document.getElementById("ivUrl")?.value||"").trim();
  var mime=window._pVidMime||"video/mp4";

  // Cas 1 : URL directe saisie (YouTube ou HTTP) — pas d'upload
  if(!window._pVidFile && urlVal){
    DB.introVideo={src:urlVal,mime:mime};
    save();window._vidHtml=buildIntroVideoHtml();
    cm();toast("Vidéo enregistrée ✓");
    return;
  }

  // Cas 2 : Fichier local → upload vers le serveur
  if(window._pVidFile){
    var cfg=DB.cloudConfig||{};
    var base=(cfg.url||'https://veritas-school.com/api').replace(/\/+$/,'');
    var secret=cfg.secret; // FIX sécurité : pas de fallback hardcodé
    if(!secret){toast('⚠ Clé API cloud manquante — configurez Paramètres → Cloud','warn');return;}

    var fd=new FormData();
    fd.append('video',window._pVidFile,window._pVidFile.name);

    var xhr=new XMLHttpRequest();
    // FIX WAF LWS 2026 : Authorization header (le WAF bloque _secret= en URL)
    xhr.open('POST',base+'/upload_video.php');
    xhr.setRequestHeader('Authorization','Bearer '+secret);

    // Barre de progression dans le toast
    xhr.upload.onprogress=function(e){
      if(e.lengthComputable){
        var pct=Math.round(e.loaded/e.total*100);
        toast('⬆️ Envoi : '+pct+'%','info');
      }
    };

    xhr.onload=function(){
      try{
        var r=JSON.parse(xhr.responseText);
        if(r.url){
          DB.introVideo={src:r.url,mime:r.mime||mime};
          window._pVidFile=null;
          window._pVidMime=null;
          save();window._vidHtml=buildIntroVideoHtml();
          cm();toast('✅ Vidéo enregistrée sur le serveur ('+r.size_kb+' Ko)');
        }else{
          toast('Erreur : '+(r.error||'réponse inattendue'),'err');
        }
      }catch(ex){toast('Erreur serveur ('+xhr.status+')','err');}
    };
    xhr.onerror=function(){toast('Erreur réseau — vérifiez la connexion','err');};
    toast('⬆️ Envoi en cours...','info');
    xhr.send(fd);
    return;
  }

  toast("Choisissez une vidéo ou entrez une URL","warn");
}
function _ivClear(){DB.introVideo=null;window._pVidSrc="";save();window._vidHtml=buildIntroVideoHtml();cm();toast("Video supprimee");}

