    +"<option value='premium'>🥇 Premium</option><option value='or'>🥈 Or</option>"
    +"<option value='argent'>🥉 Argent</option><option value='autre'>🤝 Autre</option></select></div>"
    +"<div class='fg'><span class='fl'>Couleur</span><input type='color' class='fi' id='paCol' value='#3C8DFF' style='height:38px'></div>"
