function _enrichirQuizDB(){
  if(typeof DB==='undefined'||!DB)return;
  if(typeof QUIZ_DB==="undefined")return;
  Object.keys(_EXTRA_QUIZ_DB).forEach(function(k){
    if(!QUIZ_DB[k]||QUIZ_DB[k].length<3) QUIZ_DB[k]=_EXTRA_QUIZ_DB[k];
  });
  // Charger aussi depuis DB (import JSON)
  if(DB.customQuiz){
    Object.keys(DB.customQuiz).forEach(function(k){
      if(DB.customQuiz[k]&&DB.customQuiz[k].length) QUIZ_DB[k]=(QUIZ_DB[k]||[]).concat(DB.customQuiz[k]);
    });
  }
}
function _getFullQuizList(){
  var base=[
    {key:"maths_bepc",titre:"Maths BEPC",cls:"3eme",ico:"🔢",color:"#1E3A8A",free:true},
    {key:"physchim_bepc",titre:"Physique-Chimie",cls:"3eme",ico:"⚗️",color:"#059669",free:true},
    {key:"francais_bepc",titre:"Francais BEPC",cls:"3eme",ico:"📝",color:"#7C3AED",free:true},
    {key:"svt_bepc",titre:"SVT BEPC",cls:"3eme",ico:"🧬",color:"#065F46",free:true},
    {key:"anglais_bepc",titre:"Anglais BEPC",cls:"3eme",ico:"🇬🇧",color:"#1E40AF",free:true},
    {key:"philo_term",titre:"Philosophie Tle",cls:"Terminale",ico:"🧠",color:"#4C1D95",free:false,plan:"Premium"},
    {key:"litt_afric",titre:"Litterature Africaine",cls:"1ere-Tle",ico:"📚",color:"#BE185D",free:false,plan:"Premium"},
  ];
  return base.filter(function(q){
    var db=typeof QUIZ_DB!=="undefined"?QUIZ_DB:null;
    if(!db) return false;
    if(!db[q.key]||!db[q.key].length) return false;
    q.n=db[q.key].length;
    return true;
  });
}

