function _toggleJeuAcces(id){
  if(typeof JEUX_CATALOGUE==="undefined")return;
  var j=JEUX_CATALOGUE.find(function(x){return x.id===id;});
  if(!j)return;j.gratuit=!j.gratuit;toast((j.gratuit?"Gratuit":"Premium")+" : "+j.titre);cm();setTimeout(mManageJeux,80);
}
function _setAllJeuxGratuit(){if(typeof JEUX_CATALOGUE!=="undefined")JEUX_CATALOGUE.forEach(function(j){j.gratuit=true;});toast("Tous gratuits");cm();setTimeout(mManageJeux,80);}
function _setAllJeuxPremium(){if(typeof JEUX_CATALOGUE!=="undefined")JEUX_CATALOGUE.forEach(function(j){j.gratuit=false;});toast("Tous premium");cm();setTimeout(mManageJeux,80);}
function _restoreJeu(id){
  DB.deletedJeux=(DB.deletedJeux||[]).filter(function(x){return x!==id;});
  _restoreJeuInMemory(id);
  save();cm();setTimeout(mManageJeux,80);toast('Jeu restauré');
}
// ── PURGE JEU (suppression définitive) ──
function _purgeJeu(id){
  var j=typeof JEUX_CATALOGUE!=="undefined"&&JEUX_CATALOGUE.find(function(x){return x.id===id;});
  if(!j){toast('Jeu introuvable','warn');return;}
  if(!_confirmPurge('Jeu : '+j.titre+' ('+j.matiere+')'))return;
  DB.purgedJeux=DB.purgedJeux||[];
  if(DB.purgedJeux.indexOf(id)<0)DB.purgedJeux.push(id);
  // Si custom, retirer aussi de JEUX_CATALOGUE et DB.customJeux
  if(j.custom){
    var idx=JEUX_CATALOGUE.findIndex(function(x){return x.id===id;});
    if(idx>=0)JEUX_CATALOGUE.splice(idx,1);
    if(DB.customJeux)DB.customJeux=DB.customJeux.filter(function(x){return x.id!==id;});
  }
  save();cm();setTimeout(mManageJeux,80);toast('🚫 Jeu purgé définitivement');
}
function _unpurgeAllJeux(){
  if(!confirm("Annuler toutes les purges de jeux et les restaurer dans l'admin ?"))return;
  DB.purgedJeux=[];
  save();cm();setTimeout(mManageJeux,80);toast('✅ Purges annulées');
}
function _restoreAllJeux(){
  DB.deletedJeux=[];
  save();cm();setTimeout(mManageJeux,80);toast('✅ Tous les jeux restaurés');
}
function _deleteAllBuiltinJeux(){
  if(!confirm('Supprimer TOUS les jeux par défaut ?\n\nSeuls vos jeux personnalisés resteront visibles. Restauration possible depuis ce panneau.'))return;
  if(typeof JEUX_CATALOGUE==="undefined")return;
  var builtinIds=JEUX_CATALOGUE.filter(function(j){return !j.custom;}).map(function(j){return j.id;});
  DB.deletedJeux=builtinIds;
  // NE PAS splicer — DB.deletedJeux suffit comme masque, les items restent restaurables
  save();cm();setTimeout(mManageJeux,80);toast('✅ Tous les jeux par défaut supprimés');
}
function _delJeu(id){
  var j=typeof JEUX_CATALOGUE!=="undefined"&&JEUX_CATALOGUE.find(function(x){return x.id===id;});
  if(j&&j.custom){
    _delJeuCustom(id);return;
  }
  if(!confirm('Supprimer ce jeu ? Il n\'apparaîtra plus aux visiteurs.\n\nVous pourrez le restaurer depuis ce même panneau.'))return;
  DB.deletedJeux=DB.deletedJeux||[];
  if(DB.deletedJeux.indexOf(id)<0)DB.deletedJeux.push(id);
  // NE PAS splicer JEUX_CATALOGUE — le masque DB.deletedJeux suffit
  // (sinon l'admin ne peut plus voir l'élément pour le restaurer)
  save();cm();setTimeout(mManageJeux,80);toast('✅ Jeu supprimé');
}
function _restoreJeuInMemory(id){
  // Plus besoin de ré-injecter : les items restent dans JEUX_CATALOGUE,
  // seul DB.deletedJeux les masque. Cette fonction est conservée pour compatibilité.
}
function _delJeuCustom(id){
  if(!confirm("Supprimer ce jeu ?"))return;
  var idx=JEUX_CATALOGUE.findIndex(function(j){return j.id===id;});
  if(idx>=0)JEUX_CATALOGUE.splice(idx,1);
  if(DB.customJeux)DB.customJeux=DB.customJeux.filter(function(j){return j.id!==id;});
  save();cm();setTimeout(mManageJeux,80);toast("Jeu supprimé");
}
function _saveNewJeu(){
  var titre=(document.getElementById("njTitre")?.value||"").trim();
  if(!titre){toast("Titre requis","warn");return;}
  var type=document.getElementById("njType")?.value||"qcm";
  var mat=document.getElementById("njMat")?.value||"Toutes matieres";
  var niv=document.getElementById("njNiv")?.value||"3eme-Tle";
  var emoji=document.getElementById("njEmoji")?.value||"📝";
  var gratuit=document.getElementById("njAcces")?.value==="1";
  var qRaw=(document.getElementById("njQuestions")?.value||"").trim();
  var questions=[];
  if(qRaw){try{questions=JSON.parse(qRaw);}catch(e){toast("JSON invalide : "+e.message,"warn");return;}}
  var id="jcustom_"+Date.now();
  var action="lancerCustomQuiz_"+id.replace(/[^a-z0-9]/gi,"_");
  var jeu={id:id,titre:titre,emoji:emoji,matiere:mat,niveau:niv,
    desc:"Quiz "+mat+" — "+niv,gratuit:gratuit,plan:"Premium",action:action,custom:true,questions:questions,type:type};
  JEUX_CATALOGUE.push(jeu);
  if(!DB.customJeux)DB.customJeux=[];
  DB.customJeux.push(jeu);
  // Créer la fonction de lancement dynamiquement
  window[action]=function(){_lancerCustomQuiz(id);};
  save();cm();toast("✓ Jeu '"+titre+"' créé !");
}
function mImportJeuFichier(){
  if(!iA())return;
  M("📤 Importer Jeu / Quiz (fichier JSON)","",
    "<div class='ib ibt mb10'><span>📋</span><span>Importez un fichier JSON contenant un jeu complet avec ses questions.</span></div>"
    +"<div class='fg mb10'><span class='fl'>Fichier JSON *</span>"
    +"<input type='file' class='fi' id='jeuFile' accept='.json' style='padding:6px'></div>"
    +"<div class='fg'><span class='fl'>Accès</span><select class='fi' id='jeuAcces'><option value='1'>Gratuit</option><option value='0'>Premium</option></select></div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn bi' onclick='_importJeuFileDo()'>📥 Importer</button>",true);
}
function _importJeuFileDo(){
  var fileEl=document.getElementById("jeuFile");
  if(!fileEl||!fileEl.files[0]){toast("Fichier requis","warn");return;}
  var gratuit=document.getElementById("jeuAcces")?.value==="1";
  var file=fileEl.files[0];
  var ext=file.name.split('.').pop().toLowerCase();

  // ── HTML interactive game ──
  if(ext==='html'||ext==='htm'){
    var r=new FileReader();
    r.onload=function(ev){
      var id="jimport_html_"+Date.now()+"_"+Math.random().toString(36).slice(2,5);
      var htmlContent=ev.target.result;
      // Store in DB
      if(!DB.customJeuxHtml)DB.customJeuxHtml={};
      DB.customJeuxHtml[id]=htmlContent;
      var action="jeuHtml_"+id.replace(/[^a-z0-9]/gi,"_");
      var jeu={id:id,titre:file.name.replace(/.[^.]+$/,'').replace(/[_-]/g,' '),
        emoji:"&#127760;",matiere:"Interactif",niveau:"Tous",
        desc:"Jeu interactif importé",gratuit:gratuit,plan:"Premium",
        action:action,custom:true,type:"html"};
      JEUX_CATALOGUE.push(jeu);
      if(!DB.customJeux)DB.customJeux=[];
      DB.customJeux.push(jeu);
      window[action]=function(){
        var html=DB.customJeuxHtml&&DB.customJeuxHtml[id];
        if(!html){toast("Fichier introuvable","warn");return;}
        _openHtmlWithWatermark(html,jeu.titre,null);
      };
      save();cm();toast("&#9989; Jeu HTML importé — "+jeu.titre);
    };
    r.readAsText(file,'utf-8');
    return;
  }

  // ── JSON quiz ──
  if(ext==='json'){
    var r2=new FileReader();
    r2.onload=function(ev){
      try{
        var data=JSON.parse(ev.target.result);
        var jeux=Array.isArray(data)?[{titre:"Jeu importé",questions:data,emoji:"&#127918;",matiere:"Toutes matieres",niveau:"3eme-Tle",type:"qcm"}]:[data];
        jeux.forEach(function(j){
          var id="jimport_"+Date.now()+"_"+Math.random().toString(36).slice(2,6);
          var action="lancerCustomQuiz_"+id.replace(/[^a-z0-9]/gi,"_");
          var jeu={id:id,titre:j.titre||"Quiz importé",emoji:j.emoji||"&#128221;",
            matiere:j.matiere||"Toutes matieres",niveau:j.niveau||"3eme-Tle",
            desc:j.desc||"Quiz importé",gratuit:gratuit,plan:"Premium",
            action:action,custom:true,questions:j.questions||[],type:j.type||"qcm"};
          JEUX_CATALOGUE.push(jeu);
          if(!DB.customJeux)DB.customJeux=[];
          DB.customJeux.push(jeu);
          window[action]=function(){_lancerCustomQuiz(id);};
        });
        save();cm();toast("&#9989; "+jeux.length+" jeu(x) importé(s) !");
      }catch(err){toast("Erreur JSON : "+err.message,"warn");}
    };
    r2.readAsText(file);
    return;
  }

  toast("Format non supporté — utilisez .html ou .json","warn");
}

function _restoreCustomJeux(){
  if(typeof DB==='undefined'||!DB)return;
  if(!DB.customJeux||!DB.customJeux.length)return;
  DB.customJeux.forEach(function(j){
    // Corriger l'emoji manquant en mémoire
    if(!j.emoji)j.emoji='🌐';
    // Corriger l'action manquante pour les jeux HTML
    if(j.type==='html'&&!j.action)j.action='_jeuHtml_'+j.id;
    if(!JEUX_CATALOGUE.find(function(x){return x.id===j.id;})){
      JEUX_CATALOGUE.push(j);
    }
    // Enregistrer la fonction window correcte selon le type
    if(j.type==='html'||j.type==='html_interactif'){
      (function(jj){window[jj.action]=function(){_openHtmlContent(jj.id,'jeu');};})(j);
    } else {
      var action=j.action||("lancerCustomQuiz_"+j.id.replace(/[^a-z0-9]/gi,"_"));
      if(!j.action)j.action=action;
      (function(jj){window[jj.action]=function(){_lancerCustomQuiz(jj.id);};})(j);
    }
  });
  // Persister les corrections d'emoji/action en base
  save();
}
// ── Lanceur universel (utilisé dans les onclick des cartes jeux) ─────────────
// Cherche le jeu à l'heure du clic — plus besoin de window['_jeuHtml_xxx']
function vLaunchJeu(id){
  var _delJ=DB.deletedJeux||[];
  if(_delJ.indexOf(id)>=0){toast('Ce jeu n\'est plus disponible.','warn');return;}
  var j=(typeof JEUX_CATALOGUE!=='undefined')&&JEUX_CATALOGUE.find(function(x){return x.id===id;});
  if(!j){
    // Fallback : chercher dans DB.customJeux (peut arriver si JEUX_CATALOGUE pas encore peuplé)
    j=DB.customJeux&&DB.customJeux.find(function(x){return x.id===id;});
    if(j&&!JEUX_CATALOGUE.find(function(x){return x.id===id;})){JEUX_CATALOGUE.push(j);}
  }
  if(!j){toast('Jeu introuvable','warn');return;}
  // Jeu HTML → ouvrir le contenu dans un nouvel onglet avec filigrane
  if(j.type==='html'||j.type==='html_interactif'){
    if(j.externalUrl){window.open(j.externalUrl,'_blank');return;}
    var html=DB.customJeuxHtml&&DB.customJeuxHtml[id];
    if(html){_openHtmlWithWatermark(html,j.titre,null);return;}
    toast('Contenu HTML non trouvé','warn');return;
  }
  // Jeu avec questions (QCM / V-F / Pendu / Trous)
  if(!j.questions||!j.questions.length){toast('Aucune question disponible pour ce jeu','warn');return;}
  _lancerCustomQuiz(id);
}

// Lanceur générique pour quiz custom (QCM, V/F, Pendu, Texte à trous)
function _lancerCustomQuiz(id){
  var j=JEUX_CATALOGUE.find(function(x){return x.id===id;});
  if(!j||!j.questions||!j.questions.length){toast("Aucune question pour ce jeu","warn");return;}
  if(j.type==="pendu") _lancerPenduCustom(j);
  else if(j.type==="trous") _lancerTrousCustom(j);
  else _lancerQCMCustom(j); // qcm ou vf
}
function _lancerQCMCustom(j){
  var qs=j.questions.slice();var idx=0;var score=0;var isVF=j.type==="vf";
  function render(){
    if(idx>=qs.length){
      _vc("<div class='vsec'><button class='back-btn' onclick='showJeuxEdu()'>← Jeux</button>"
        +"<div class='vcard' style='text-align:center'><div style='font-size:52px;margin-bottom:16px'>🎉</div>"
        +"<div style='font-family:Montserrat,sans-serif;font-size:20px;font-weight:800;color:#142554;margin-bottom:8px'>"+j.titre+" — Terminé !</div>"
        +"<div style='font-size:16px;color:var(--ink3)'>Score : "+score+"/"+qs.length+"</div>"
        +"<button class='btn bi mt16' onclick='_lancerCustomQuiz(\""+j.id+"\")'>Rejouer</button></div></div>");
      return;
    }
    var q=qs[idx];var opts=isVF?["Vrai","Faux"]:q.opts||[];
    var h="<div class='vsec'><button class='back-btn' onclick='showJeuxEdu()'>← Jeux</button>";
    h+="<div class='vsec-title'>"+j.emoji+" "+j.titre+"</div>";
    h+="<div class='quiz-container'><div class='quiz-header'><h3>"+j.titre+"</h3>";
    h+="<p>Question "+(idx+1)+"/"+qs.length+"</p></div>";
    h+="<div class='quiz-progress'><div class='quiz-progress-fill' style='width:"+Math.round((idx/qs.length)*100)+"%'></div></div>";
    h+="<div class='quiz-q'><div class='quiz-q-text'>"+q.q+"</div>";
    h+="<div class='quiz-opts'>";
    opts.forEach(function(o,oi){
      h+="<button class='quiz-opt' onclick='_cqCheck("+oi+","+q.ans+",this,\""+encodeURIComponent(q.exp||"")+"\")'>"+String.fromCharCode(65+oi)+". "+o+"</button>";
    });
    h+="</div><div id='cqExp' style='display:none;margin-top:12px;padding:10px;background:#FEF3C7;border-left:4px solid #F59E0B;border-radius:0 8px 8px 0;font-size:12px'></div>"
    +"</div><div class='quiz-nav'><span style='font-size:13px;color:var(--ink4)'>Score : "+score+"/"+qs.length+"</span>"
    +"<button id='cqNext' class='btn bi xs' style='display:none' onclick='window._cqNext()'>Suivant →</button></div></div></div>";
    _vc(h);
    window._cqNext=function(){idx++;render();};
    window._cqCheck=function(chosen,ans,btn,exp){
      document.querySelectorAll(".quiz-opt").forEach(function(b,bi){
        b.disabled=true;
        if(bi===ans)b.classList.add("correct");
        else if(b===btn)b.classList.add("wrong");
      });
      if(chosen===ans)score++;
      var expEl=document.getElementById("cqExp");
      if(expEl&&exp){expEl.style.display="block";expEl.textContent=decodeURIComponent(exp);}
      var nxt=document.getElementById("cqNext");if(nxt)nxt.style.display="inline-flex";
    };
  }
  render();
}
function _lancerPenduCustom(j){
  var mots=j.questions.map(function(q){return{mot:(q.mot||q.q||"VERITAS").toUpperCase(),ind:q.exp||q.q||""};});
  var midx=Math.floor(Math.random()*mots.length);var item=mots[midx];
  var tries=0;var maxT=7;var found=[];var wrong=[];
  function render(){
    var display=item.mot.split("").map(function(c){return(c===" "?"&nbsp;":found.indexOf(c)>=0?c:"_");}).join(" ");
    var won=item.mot.split("").every(function(c){return c===" "||found.indexOf(c)>=0;});
    var lost=tries>=maxT;
    var ALPHA="ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    var h="<div class='vsec'><button class='back-btn' onclick='showJeuxEdu()'>← Jeux</button>";
    h+="<div class='vsec-title'>✏️ "+j.titre+"</div>";
    h+="<div class='vcard' style='max-width:560px;margin:0 auto;text-align:center'>";
    if(item.ind)h+="<div style='font-size:12px;color:var(--ink4);margin-bottom:10px;font-style:italic'>💡 "+item.ind+"</div>";
    // Bonhomme pendu SVG simplifié
    var parts=["<circle cx='100' cy='30' r='18' fill='none' stroke='#DC2626' stroke-width='3'/>",
      "<line x1='100' y1='48' x2='100' y2='110' stroke='#DC2626' stroke-width='3'/>",
      "<line x1='100' y1='65' x2='70' y2='95' stroke='#DC2626' stroke-width='3'/>",
      "<line x1='100' y1='65' x2='130' y2='95' stroke='#DC2626' stroke-width='3'/>",
      "<line x1='100' y1='110' x2='75' y2='145' stroke='#DC2626' stroke-width='3'/>",
      "<line x1='100' y1='110' x2='125' y2='145' stroke='#DC2626' stroke-width='3'/>",
      "<line x1='40' y1='0' x2='40' y2='160' stroke='#142554' stroke-width='3'/><line x1='40' y1='0' x2='100' y2='0' stroke='#142554' stroke-width='3'/><line x1='100' y1='0' x2='100' y2='12' stroke='#142554' stroke-width='3'/>"];
    h+="<svg viewBox='0 0 200 170' style='width:160px;height:130px;margin:0 auto;display:block'>"
      +parts.slice(Math.max(0,7-tries)).join("")
      +"</svg>";
    h+="<div style='font-size:26px;font-family:\"Fira Code\",monospace;letter-spacing:8px;color:#142554;margin:14px 0'>"+display+"</div>";
    if(won){h+="<div style='color:#059669;font-weight:800;font-size:16px;margin-bottom:12px'>🎉 Bravo ! Mot trouvé !</div><button class='btn bi' onclick='_lancerPenduCustom("+JSON.stringify(j).replace(/'/g,"&#39;")+")'>Rejouer</button>";}
    else if(lost){h+="<div style='color:#DC2626;font-weight:800;font-size:14px;margin-bottom:8px'>❌ Perdu ! Le mot était : <strong>"+item.mot+"</strong></div><button class='btn bi' onclick='_lancerPenduCustom("+JSON.stringify(j).replace(/'/g,"&#39;")+")'>Rejouer</button>";}
    else{
      h+="<div style='display:flex;flex-wrap:wrap;gap:5px;justify-content:center;margin-top:8px'>";
      ALPHA.split("").forEach(function(c){
        var used=found.indexOf(c)>=0||wrong.indexOf(c)>=0;
        h+="<button style='width:32px;height:32px;border-radius:6px;border:1.5px solid "+(used?"#ccc":"#142554")+";background:"+(wrong.indexOf(c)>=0?"#FEE2E2":found.indexOf(c)>=0?"#D1FAE5":"#fff")+";color:"+(used?"#999":"#142554")+";font-weight:700;font-size:13px;cursor:"+(used?"default":"pointer")+";transition:.15s'"
          +(used?"disabled":"")+(!used?" onclick='_phLetter(\""+c+"\")'":"")+" >"+c+"</button>";
      });
      h+="</div><div style='font-size:12px;color:var(--ink4);margin-top:10px'>Essais restants : "+(maxT-tries)+" / "+maxT+"</div>";
    }
    h+="</div></div>";
    _vc(h);
    window._phLetter=function(c){
      if(item.mot.indexOf(c)>=0){found.push(c);}else{wrong.push(c);tries++;}
      render();
    };
  }
  render();
}
function _lancerTrousCustom(j){
  var qs=j.questions.slice();var idx=0;var score=0;
  function render(){
    if(idx>=qs.length){
      _vc("<div class='vsec'><button class='back-btn' onclick='showJeuxEdu()'>← Jeux</button>"
        +"<div class='vcard' style='text-align:center'><div style='font-size:48px;margin-bottom:12px'>✍️</div>"
        +"<div style='font-size:20px;font-weight:800;color:#142554'>Score : "+score+"/"+qs.length+"</div>"
        +"<button class='btn bi mt14' onclick='_lancerCustomQuiz(\""+j.id+"\")'>Rejouer</button></div></div>");
      return;
    }
    var q=qs[idx];
    // Format: q contient "___" à remplacer, ans = mot attendu
    var phrase=(q.q||"").replace(/___/g,"<input id='trouInp' class='fi' style='display:inline-block;width:120px;max-width:180px;padding:4px 8px;margin:0 6px;font-size:14px;border:2px solid #142554;border-radius:6px' placeholder='...'>");
    var h="<div class='vsec'><button class='back-btn' onclick='showJeuxEdu()'>← Jeux</button>";
    h+="<div class='vsec-title'>"+j.emoji+" "+j.titre+"</div>";
    h+="<div class='vcard' style='max-width:560px;margin:0 auto'>";
    h+="<div style='font-size:12px;color:var(--ink4);margin-bottom:8px'>Question "+(idx+1)+"/"+qs.length+" · Score : "+score+"</div>";
    h+="<div style='font-size:16px;line-height:2;color:#142554;font-family:Georgia,serif;margin-bottom:16px'>"+phrase+"</div>";
    if(q.exp)h+="<div style='font-size:11px;color:var(--ink4);font-style:italic;margin-bottom:10px'>💡 Aide : "+q.exp+"</div>";
    h+="<div id='trouFb' style='min-height:20px;margin-bottom:10px'></div>";
    h+="<button class='btn bi' onclick='_trouCheck(\""+encodeURIComponent(String(q.ans))+"\")'>Valider</button>";
    h+="</div></div>";
    _vc(h);
    window._trouCheck=function(ansEnc){
      var ans=decodeURIComponent(ansEnc).trim().toLowerCase();
      var inp=document.getElementById("trouInp");
      var val=(inp?inp.value:"").trim().toLowerCase();
      var fb=document.getElementById("trouFb");
      if(val===ans||ans.split("|").some(function(a){return val===a.trim();})){
        score++;if(fb)fb.innerHTML="<span style='color:#059669;font-weight:800'>✅ Correct !</span>";
      }else{
        if(fb)fb.innerHTML="<span style='color:#DC2626;font-weight:800'>❌ Réponse : "+decodeURIComponent(ansEnc)+"</span>";
      }
      if(inp)inp.disabled=true;
      setTimeout(function(){idx++;render();},1400);
    };
  }
  render();
}

// ── IMPORT QCM ─────────────────────────────────────────────────────
function mImportQCM(){
  if(!iA())return;
  M("📥 Importer des QCM","Chargez une banque de questions au format JSON",
    "<div class='ib ibt mb12'><span>📋</span><span>Format: tableau JSON avec q, opts[4], ans(0-3), exp</span></div>"
    +"<div class='fg mb10'><span class='fl'>Matiere *</span><select class='fi' id='qcmKey'>"
    +"<option value='maths_bepc'>Maths BEPC</option><option value='francais_bepc'>Francais BEPC</option>"
    +"<option value='physchim_bepc'>Physique-Chimie</option><option value='svt_bepc'>SVT BEPC</option>"
    +"<option value='philo_term'>Philosophie Terminale</option><option value='anglais_bepc'>Anglais BEPC</option>"
    +"<option value='litt_afric'>Litterature Africaine</option>"
    +"<option value='custom'>Nouvelle matiere...</option>"
    +"</select></div>"
    +"<div class='fg mb10' id='qcmCDiv' style='display:none'><span class='fl'>Cle personnalisee</span>"
    +"<input class='fi' id='qcmCKey' placeholder='ex: maths_bac_c'></div>"
    +"<div class='fg mb10'><span class='fl'>Fichier JSON *</span>"
    +"<input type='file' class='fi' id='qcmFile' accept='.json' style='padding:6px' onchange='var s=this.value.endsWith(\".json\");if(!s)toast(\"JSON requis\",\"warn\")'></div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn bi' onclick='_importQCMDo()'>📥 Importer</button>",true);
}
function _importQCMDo(){
  var key=document.getElementById("qcmKey")?.value||"";
  if(key==="custom")key=(document.getElementById("qcmCKey")?.value||"").trim().replace(/\s+/g,"_");
  var fileEl=document.getElementById("qcmFile");
  if(!key||!fileEl||!fileEl.files[0]){toast("Matiere et fichier requis","warn");return;}
  var r=new FileReader();
  r.onload=function(e){
    try{
      var data=JSON.parse(e.target.result);
      if(!Array.isArray(data)||!data[0]||!data[0].q){toast("Format JSON invalide","warn");return;}
      if(typeof QUIZ_DB==="undefined")window.QUIZ_DB={};
      QUIZ_DB[key]=(QUIZ_DB[key]||[]).concat(data);
      if(!DB.customQuiz)DB.customQuiz={};
      DB.customQuiz[key]=(DB.customQuiz[key]||[]).concat(data);
      save();cm();toast(data.length+" questions importees pour '"+key+"'");
    }catch(err){toast("Erreur JSON: "+err.message,"warn");}
  };
  r.readAsText(fileEl.files[0]);
}

// ══════════════════════════════════════════════════════════════════
