// Polyfill roundRect (Chrome < 99 / Firefox < 112)
(function(){if(!CanvasRenderingContext2D.prototype.roundRect){CanvasRenderingContext2D.prototype.roundRect=function(x,y,w,h,r){r=Math.min(r,w/2,h/2);this.beginPath();this.moveTo(x+r,y);this.lineTo(x+w-r,y);this.quadraticCurveTo(x+w,y,x+w,y+r);this.lineTo(x+w,y+h-r);this.quadraticCurveTo(x+w,y+h,x+w-r,y+h);this.lineTo(x+r,y+h);this.quadraticCurveTo(x,y+h,x,y+h-r);this.lineTo(x,y+r);this.quadraticCurveTo(x,y,x+r,y);this.closePath();return this;};}})();

function _showLittCarte(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.carte){toast('Carte non disponible','warn');return;}
  var c=oe.carte;
  var _MMCOLORS=['#0EA5E9','#F97316','#8B5CF6','#10B981','#EF4444','#F59E0B'];
  function _mmIco(lb){
    lb=(lb||'').toLowerCase();
    if(/thème|theme/.test(lb)) return'💡 ';
    if(/personnage/.test(lb)) return'👥 ';
    if(/genre|structure|forme/.test(lb)) return'📐 ';
    if(/contexte|époque|histoire/.test(lb)) return'🌍 ';
    if(/style|procéd/.test(lb)) return'🎨 ';
    if(/symbol|image|réception/.test(lb)) return'✨ ';
    return'';
  }
  var _isMobMap=window.innerWidth<660;
  if(_isMobMap){
    // ── Layout HTML carte (mobile) : cartes colorées empilées, lisibles sur tout écran ──
    var cLines=(c.centre||(oe.titre+'\n'+oe.auteur)).split('\n').filter(Boolean);
    var ctrHtml='<div style="background:linear-gradient(135deg,#C8880A,#FFC93C);border-radius:14px;padding:14px 18px;text-align:center;box-shadow:0 4px 16px rgba(255,201,60,.35);margin-bottom:12px">'
      +'<div style="font-weight:900;font-size:16px;color:#142554;line-height:1.3">'+_esc(cLines[0]||oe.titre)+'</div>'
      +(cLines[1]?'<div style="font-size:12px;color:#5a3e00;margin-top:4px;opacity:.85">'+_esc(cLines[1])+'</div>':'')
      +'</div>';
    var brHtml='';
    (c.branches||[]).forEach(function(br,bi){
      var col=br.color||_MMCOLORS[bi%_MMCOLORS.length];
      // Branches avec gradient subtil, glow et animation d'entrée
      brHtml+='<div class="mm-branch" style="background:linear-gradient(135deg,'+col+','+col+'dd);border-radius:14px;padding:14px 18px;color:#fff;box-shadow:0 4px 14px '+col+'40,inset 0 1px 0 rgba(255,255,255,.15);position:relative;overflow:hidden;animation:mmSlideIn .55s '+(bi*0.08)+'s both cubic-bezier(.34,1.56,.64,1)" data-color="'+col+'">'
        // Bande décorative latérale
        +'<div style="position:absolute;left:0;top:0;bottom:0;width:4px;background:rgba(255,255,255,.35)"></div>'
        // Halo radial décoratif
        +'<div style="position:absolute;top:-30px;right:-30px;width:90px;height:90px;background:radial-gradient(circle,rgba(255,255,255,.18) 0%,transparent 70%);pointer-events:none"></div>'
        // Titre avec icône agrandie
        +'<div style="font-weight:900;font-size:15px;margin-bottom:10px;padding-bottom:8px;border-bottom:2px solid rgba(255,255,255,.25);display:flex;align-items:center;gap:8px;letter-spacing:.3px;text-shadow:0 1px 4px rgba(0,0,0,.2);position:relative">'
          +'<span style="font-size:24px;line-height:1;filter:drop-shadow(0 2px 4px rgba(0,0,0,.3))">'+(_mmIco(br.label)||'●')+'</span>'
          +'<span>'+_esc(br.label||'')+'</span>'
        +'</div>'
        +'<div style="font-size:13px;line-height:1.85;opacity:.96;position:relative">'
        +(br.items||[]).map(function(x,ii){
          return '<div style="display:flex;align-items:flex-start;gap:6px;padding:3px 0;animation:mmFadeRight .4s '+(bi*0.08+0.15+ii*0.04)+'s both ease-out">'
            +'<span style="color:#FFC93C;font-weight:900;flex-shrink:0;font-size:14px;line-height:1.4">▸</span>'
            +'<span>'+_esc(x)+'</span>'
            +'</div>';
        }).join('')
        +'</div></div>';
    });
    _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
      +'<div class="vsec-title" style="display:flex;align-items:center;gap:10px"><span style="font-size:32px;animation:mmPulse 2.5s ease-in-out infinite">🗺️</span><span>Carte Mentale — '+_esc(oe.titre)+'</span></div>'
      +'<div class="vsec-sub" style="font-style:italic">'+_esc(oe.auteur)+' — '+_esc(oe.classe)+'</div>'
      // Container avec fond étoilé animé
      +'<div style="background:radial-gradient(ellipse at center,#1E3A8A 0%,#07142E 70%,#020817 100%);border-radius:20px;padding:20px;margin:14px 0;position:relative;overflow:hidden;box-shadow:0 10px 40px rgba(20,37,84,.4)">'
      // Étoiles décoratives animées
      +'<div style="position:absolute;inset:0;background-image:radial-gradient(2px 2px at 20% 30%,rgba(255,201,60,.5),transparent),radial-gradient(1px 1px at 60% 70%,rgba(255,255,255,.6),transparent),radial-gradient(1px 1px at 85% 40%,rgba(255,201,60,.4),transparent),radial-gradient(2px 2px at 30% 80%,rgba(255,255,255,.5),transparent);pointer-events:none;opacity:.6;animation:mmStars 8s ease-in-out infinite"></div>'
      +'<div style="position:relative;z-index:2">'+ctrHtml
      +'<div style="display:flex;flex-direction:column;gap:12px">'+brHtml+'</div>'
      +'</div></div>'
      // Card "Comment utiliser" plus moderne
      +'<div class="vcard mt14" style="background:linear-gradient(135deg,#FFF8E1,#FFEDB5);border:2px solid #FFC93C;border-radius:16px;animation:mmSlideIn .55s '+((c.branches||[]).length*0.08+0.3)+'s both ease-out">'
        +'<div class="bold s mb8" style="color:#7C2D12;font-size:15px;display:flex;align-items:center;gap:8px"><span style="font-size:22px">📌</span><span>Comment utiliser cette carte ?</span></div>'
        +'<div style="font-size:13px;color:#78350F;line-height:1.8">Visualisez les <strong>'+(c.branches||[]).length+' axes</strong> thématiques. Chaque carte regroupe un aspect essentiel de l\'œuvre. Téléchargez en HD pour imprimer ou réviser.</div>'
        +'<div style="margin-top:14px;display:flex;gap:10px;flex-wrap:wrap">'
        +'<button class="btn sm" style="background:linear-gradient(135deg,#142554,#1E3A8A);color:#FFC93C;font-weight:700;border:none;box-shadow:0 3px 10px rgba(20,37,84,.3);transition:transform .15s" onmouseover="this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.transform=\'\'" onclick="_mmDownload(\''+oeuvreKey+'\')"><span style="margin-right:6px">⬇️</span>Télécharger HD</button>'
        +'<button class="btn sm" style="background:linear-gradient(135deg,#FFC93C,#F59E0B);color:#142554;font-weight:700;border:none;box-shadow:0 3px 10px rgba(255,201,60,.4);transition:transform .15s" onmouseover="this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.transform=\'\'" onclick="window.print()"><span style="margin-right:6px">🖨️</span>Imprimer</button>'
        +'</div></div></div>');
    return;
  }
  // ── Layout Canvas (desktop) ──
  // ── Légende couleur sous la carte ──
  var legHtml='<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;margin-top:14px">';
  (c.branches||[]).forEach(function(br){
    legHtml+='<div style="background:'+br.color+';color:#fff;padding:10px 12px;border-radius:10px;box-shadow:0 3px 10px rgba(0,0,0,.15)">'
      +'<div style="font-weight:800;font-size:13px;margin-bottom:5px">'+_esc(br.label||'')+'</div>'
      +'<div style="font-size:11px;opacity:.92;line-height:1.6">'
      +(br.items||[]).map(function(x){return'• '+_esc(x);}).join('<br>')+'</div></div>';
  });
  legHtml+='</div>';
  _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
    +'<div class="vsec-title">🗺️ Carte Mentale — '+_esc(oe.titre)+'</div>'
    +'<div class="vsec-sub" style="font-style:italic">'+_esc(oe.auteur)+' — '+_esc(oe.classe)+'</div>'
    +'<div style="background:#07142E;border-radius:18px;overflow:hidden;box-shadow:0 10px 40px rgba(0,0,0,.45);margin:12px 0">'
    +'<canvas id="mmCanvas" style="width:100%;height:auto;display:block"></canvas>'
    +'</div>'
    +legHtml
    +'<div class="vcard mt14"><div class="bold s mb8">📌 Comment utiliser cette carte ?</div>'
    +'<div style="font-size:13px;color:var(--ink3);line-height:1.8">Visualisez les <strong>'+(c.branches||[]).length+' axes</strong> autour du centre (titre + auteur). Chaque branche regroupe un aspect essentiel de l\'œuvre. Téléchargez en HD pour révision ou impression A4.</div>'
    +'<div style="margin-top:12px;display:flex;gap:8px;flex-wrap:wrap">'
    +'<button class="btn sm bi" onclick="_mmDownload(\''+oeuvreKey+'\')">⬇️ Télécharger HD (PNG)</button>'
    +'<button class="btn sm bo" onclick="window.print()">🖨️ Imprimer</button>'
    +'</div></div></div>');
  setTimeout(function(){
    var cv=document.getElementById('mmCanvas');
    if(!cv) return;
    _mmDrawCv(cv,c,oe,1,false);
  },80);
}

// ── Moteur canvas unifié (screen @ sc=1, download @ sc=2, mobile=mob) ──
function _mmDrawCv(cv,c,oe,sc,mob){
  // mob=true → layout carré 720×720 optimisé portrait mobile
  var W=mob?720*sc:1200*sc, H=mob?720*sc:760*sc;
  cv.width=W; cv.height=H;
  // Multiplicateur de lisibilité : fonts plus grosses sur mobile
  var fm=mob?1.4:1.0;
  var ctx=cv.getContext('2d');
  var cx=W/2, cy=H/2;
  var branches=c.branches||[];
  var nBr=branches.length;
  var COLORS=['#0EA5E9','#F97316','#8B5CF6','#10B981','#EF4444','#F59E0B'];

  // ── Fond dégradé radial ──
  var bg=ctx.createRadialGradient(cx,cy,0,cx,cy,Math.max(W,H)*.65);
  bg.addColorStop(0,'#1E3A7A'); bg.addColorStop(.55,'#0F2252'); bg.addColorStop(1,'#071428');
  ctx.fillStyle=bg; ctx.fillRect(0,0,W,H);

  // Étoiles déterministes (pas aléatoires = même résultat à chaque rendu)
  for(var si=0;si<65;si++){
    var sx=((Math.sin(si*47.3)*.5+.5)*W)|0;
    var sy=((Math.cos(si*31.7)*.5+.5)*H)|0;
    var sr=(si%6===0?1.7:.85)*sc;
    ctx.globalAlpha=Math.sin(si*13.1)*.3+.15;
    ctx.fillStyle='#fff'; ctx.beginPath(); ctx.arc(sx,sy,sr,0,Math.PI*2); ctx.fill();
  }
  ctx.globalAlpha=1;

  // ── Angles selon nb de branches ──
  var angles;
  if(nBr===4) angles=[-135,-45,45,135];
  else if(nBr===3) angles=[-120,0,120];
  else if(nBr===2) angles=[-90,90];
  else{ angles=[]; for(var ai=0;ai<nBr;ai++) angles.push(-180+ai*(360/nBr)); }

  // Géométrie adaptée mobile vs desktop
  var brDist=mob?155*sc:230*sc;
  var brW=mob?128*sc:152*sc, brH=mob?40*sc:46*sc, brR=mob?12*sc:14*sc;
  var itW=mob?140*sc:172*sc, itH=mob?30*sc:34*sc, itR=mob?8*sc:9*sc, itGap=mob?7*sc:10*sc;

  // ── Branches ──
  branches.forEach(function(br,bi){
    var ang=angles[bi]*Math.PI/180;
    var bx=cx+Math.cos(ang)*brDist;
    var by=cy+Math.sin(ang)*brDist;
    var col=br.color||COLORS[bi%COLORS.length];
    var isLeft=Math.cos(ang)<-0.12;
    var isRight=Math.cos(ang)>0.12;

    // Ligne centre → branche (Bezier)
    var cpx=cx+(bx-cx)*.5+Math.sin(ang)*28*sc;
    var cpy=cy+(by-cy)*.5-Math.cos(ang)*28*sc;
    ctx.save();
    ctx.beginPath(); ctx.moveTo(cx,cy); ctx.quadraticCurveTo(cpx,cpy,bx,by);
    ctx.strokeStyle=col; ctx.lineWidth=4.5*sc; ctx.globalAlpha=.75; ctx.lineCap='round'; ctx.stroke();
    ctx.restore();

    // Halo + boîte branche
    ctx.save(); ctx.shadowColor=col; ctx.shadowBlur=18*sc;
    _mmRR(ctx,bx-brW/2,by-brH/2,brW,brH,brR,col,null,0);
    ctx.restore();
    _mmRR(ctx,bx-brW/2,by-brH/2,brW,brH,brR,null,'rgba(255,255,255,.55)',1.8*sc);

    // Icône automatique
    var ico=''; var lb=(br.label||'').toLowerCase();
    if(/thème|theme/.test(lb)) ico='💡 ';
    else if(/personnage/.test(lb)) ico='👥 ';
    else if(/genre|structure|forme/.test(lb)) ico='📐 ';
    else if(/contexte|époque|histoire/.test(lb)) ico='🌍 ';
    else if(/style|procéd/.test(lb)) ico='🎨 ';
    else if(/symbol|image|réception/.test(lb)) ico='✨ ';
    ctx.save();
    ctx.fillStyle='#fff'; ctx.textAlign='center'; ctx.textBaseline='middle';
    ctx.font='bold '+(13.5*sc*fm)+'px Arial,sans-serif';
    ctx.shadowColor='rgba(0,0,0,.5)'; ctx.shadowBlur=3*sc;
    ctx.fillText(ico+_mmClip(br.label||'',mob?14:19),bx,by);
    ctx.restore();

    // ── Items : colonne à côté du nœud branche ──
    var items=br.items||[];
    var nIt=items.length; if(!nIt) return;
    var totalH=nIt*itH+(nIt-1)*itGap;

    var itemCX;
    if(isLeft){
      itemCX=bx-brW/2-16*sc-itW/2;
    } else if(isRight){
      itemCX=bx+brW/2+16*sc+itW/2;
    } else {
      // branche verticale (top/bottom) : alterner gauche/droite par index
      var vOff=mob?90*sc:130*sc;
      itemCX=(bi%2===0)?(cx+vOff+16*sc+itW/2):(cx-vOff-16*sc-itW/2);
    }

    var itemStartY=by-totalH/2;
    // Clamp dans le canvas
    var my=8*sc, mx=6*sc;
    if(itemStartY<my) itemStartY=my;
    if(itemStartY+totalH>H-my) itemStartY=H-my-totalH;
    if(itemCX-itW/2<mx) itemCX=mx+itW/2;
    if(itemCX+itW/2>W-mx) itemCX=W-mx-itW/2;

    items.forEach(function(it,ii){
      var iy=itemStartY+ii*(itH+itGap);
      var anchorX=isLeft?(bx-brW/2):(bx+brW/2);
      var anchorXitem=isLeft?(itemCX+itW/2):(itemCX-itW/2);

      // Pointillés branche → item
      ctx.save();
      ctx.beginPath(); ctx.moveTo(anchorX,by); ctx.lineTo(anchorXitem,iy+itH/2);
      ctx.strokeStyle=col; ctx.lineWidth=1.5*sc; ctx.globalAlpha=.38;
      ctx.setLineDash([5*sc,4*sc]); ctx.stroke();
      ctx.restore();

      // Boîte item — fond coloré solide opaque pour lisibilité maximale
      ctx.save();
      // Fond : couleur de branche à 0.85 opacité
      ctx.globalAlpha=0.85;
      _mmRR(ctx,itemCX-itW/2,iy,itW,itH,itR,col,null,0);
      ctx.globalAlpha=1;
      // Bordure blanche légère
      _mmRR(ctx,itemCX-itW/2,iy,itW,itH,itR,null,'rgba(255,255,255,0.5)',1.2*sc);
      ctx.restore();

      // Texte item avec wrapping 2 lignes — blanc gras sur fond coloré
      ctx.save();
      ctx.fillStyle='#ffffff'; ctx.textAlign='center'; ctx.textBaseline='middle';
      ctx.shadowColor='rgba(0,0,0,0.45)'; ctx.shadowBlur=2*sc;
      var maxTW=itW-14*sc;
      var fs1=12.5*sc*fm, fs2=11*sc*fm;
      var wds=String(it||'').split(' ');
      var l1='',l2='',on2=false;
      wds.forEach(function(w){
        ctx.font='600 '+fs1+'px Arial,sans-serif';
        if(on2){ l2+=(l2?' ':'')+w; return; }
        var t=(l1?l1+' ':'')+w;
        if(ctx.measureText(t).width<=maxTW) l1=t;
        else{ on2=true; l2=w; }
      });
      if(l2){
        ctx.font='600 '+fs2+'px Arial,sans-serif';
        ctx.fillText(_mmClip(l1,32),itemCX,iy+itH/2-6.5*sc);
        ctx.fillText(_mmClip(l2,32),itemCX,iy+itH/2+6.5*sc);
      } else {
        ctx.font='600 '+fs1+'px Arial,sans-serif';
        ctx.fillText(_mmClip(l1,34),itemCX,iy+itH/2);
      }
      ctx.restore();
    });
  });

  // ── Nœud central (ellipse dorée) ──
  var crx=(mob?100:132)*sc, cry=(mob?44:56)*sc;
  ctx.save();
  ctx.shadowColor='#FFC93C'; ctx.shadowBlur=38*sc;
  var cg=ctx.createRadialGradient(cx,cy-10*sc,0,cx,cy,crx);
  cg.addColorStop(0,'#FFE88A'); cg.addColorStop(.6,'#FFC93C'); cg.addColorStop(1,'#C8880A');
  ctx.fillStyle=cg;
  ctx.beginPath(); ctx.ellipse(cx,cy,crx,cry,0,0,Math.PI*2); ctx.fill();
  ctx.strokeStyle='rgba(255,255,255,.88)'; ctx.lineWidth=2.8*sc;
  ctx.beginPath(); ctx.ellipse(cx,cy,crx,cry,0,0,Math.PI*2); ctx.stroke();
  ctx.restore();

  // Texte central multi-lignes
  var cLines=(c.centre||oe.titre+'\n'+oe.auteur).split('\n').filter(Boolean);
  var lh=17*sc*fm;
  ctx.save(); ctx.textAlign='center'; ctx.fillStyle='#142554';
  cLines.forEach(function(l,li){
    var fs=li===0?15*sc*fm:11.5*sc*fm;
    ctx.font=(li===0?'bold ':'')+fs+'px Arial,sans-serif';
    ctx.fillText(_mmClip(l,mob?18:26),cx,cy-((cLines.length-1)*lh/2)+li*lh+4*sc);
  });
  ctx.restore();

  // Signature screen — bandeau bas discret (sans date, sans téléchargement)
  ctx.save();
  var sigH=22*sc;
  var sigGrad=ctx.createLinearGradient(0,H-sigH,0,H);
  sigGrad.addColorStop(0,'rgba(7,20,40,0)');
  sigGrad.addColorStop(1,'rgba(7,20,40,0.72)');
  ctx.fillStyle=sigGrad;
  ctx.fillRect(0,H-sigH,W,sigH);
  ctx.fillStyle='rgba(255,201,60,0.7)';
  ctx.font=(9*sc*fm)+'px Inter,Arial,sans-serif';
  ctx.textAlign='end'; ctx.textBaseline='bottom';
  ctx.fillText('© VÉRITAS Academy',W-10*sc,H-5*sc);
  ctx.restore();
}
// Rounded rect helper
function _mmRR(ctx,x,y,w,h,r,fill,stroke,sw){
  ctx.beginPath(); ctx.roundRect(x,y,w,h,r);
  if(fill){ctx.fillStyle=fill;ctx.fill();}
  if(stroke){ctx.strokeStyle=stroke;ctx.lineWidth=sw||1;ctx.stroke();}
}
// Clip texte
function _mmClip(s,max){s=String(s||'');return s.length>max?s.slice(0,max-1)+'…':s;}

// ── NE PAS SUPPRIMER — ancienne fonction préservée pour compatibilité
function _showLittCarte_svg_unused(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.carte){toast("Carte non disponible","warn");return;}
  var c=oe.carte;
  // ── v1.0 : rendu amélioré, items espacés sans chevauchement ──
  var W=960, H=640, cx=W/2, cy=H/2;
  var svg='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 '+W+' '+H+'" style="width:100%;height:auto;max-height:560px;border-radius:18px;background:radial-gradient(ellipse at center, #1A3878 0%, #0D1B3E 70%, #081024 100%);box-shadow:0 12px 40px rgba(0,0,0,.35)">';
  // Defs : filtre ombre portée, gradients
  svg+='<defs>';
  svg+='<filter id="mmShadow" x="-50%" y="-50%" width="200%" height="200%"><feGaussianBlur in="SourceAlpha" stdDeviation="3"/><feOffset dx="0" dy="2" result="offsetblur"/><feComponentTransfer><feFuncA type="linear" slope="0.5"/></feComponentTransfer><feMerge><feMergeNode/><feMergeNode in="SourceGraphic"/></feMerge></filter>';
  svg+='<radialGradient id="mmCentre" cx="50%" cy="50%" r="50%"><stop offset="0%" stop-color="#FFE28A"/><stop offset="60%" stop-color="#FFC93C"/><stop offset="100%" stop-color="#E6A817"/></radialGradient>';
  // Animation CSS-in-SVG
  svg+='<style>';
  svg+='.mmNode{opacity:0;animation:mmFadeIn .6s forwards}';
  svg+='.mmBranch{opacity:0;animation:mmFadeIn .5s forwards}';
  svg+='.mmItem{opacity:0;animation:mmFadeIn .45s forwards}';
  svg+='.mmLine{stroke-dasharray:1000;stroke-dashoffset:1000;animation:mmDraw 1s forwards}';
  svg+='@keyframes mmFadeIn{to{opacity:1}}';
  svg+='@keyframes mmDraw{to{stroke-dashoffset:0}}';
  svg+='.mmTitle{font-family:Montserrat,sans-serif;font-weight:800;fill:#142554}';
  svg+='.mmBranchLabel{font-family:Montserrat,sans-serif;font-weight:700;fill:#fff}';
  svg+='.mmItemLabel{font-family:Inter,Arial,sans-serif;fill:#fff}';
  svg+='</style>';
  svg+='</defs>';

  // Fond étoilé
  for(var s=0;s<60;s++){
    var sx=Math.floor(Math.random()*W),sy=Math.floor(Math.random()*H);
    var sr=(Math.random()<0.85)?1:1.8;
    var sop=(Math.random()*0.5+0.15).toFixed(2);
    svg+='<circle cx="'+sx+'" cy="'+sy+'" r="'+sr+'" fill="rgba(255,255,255,'+sop+')"/>';
  }

  // ── NŒUD CENTRAL ──
  // Halo diffus
  svg+='<ellipse cx="'+cx+'" cy="'+cy+'" rx="160" ry="70" fill="url(#mmCentre)" opacity="0.15"/>';
  svg+='<ellipse cx="'+cx+'" cy="'+cy+'" rx="135" ry="58" fill="url(#mmCentre)" opacity="0.3"/>';
  // Ellipse principale
  svg+='<ellipse class="mmNode" cx="'+cx+'" cy="'+cy+'" rx="118" ry="50" fill="url(#mmCentre)" stroke="#fff" stroke-width="2.5" filter="url(#mmShadow)" style="animation-delay:0s"/>';
  // Texte central (multi-lignes)
  var cLines=(c.centre||'').split('\n');
  var lineH=16;
  var startY=cy - ((cLines.length-1)*lineH/2) + 5;
  cLines.forEach(function(l,li){
    var fs = (li===0)?14:12;
    svg+='<text class="mmNode mmTitle" x="'+cx+'" y="'+(startY+li*lineH)+'" text-anchor="middle" font-size="'+fs+'" style="animation-delay:.1s">'+_esc(l)+'</text>';
  });

  // ── BRANCHES ──
  // Angles fixes pour 4 branches : NO, NE, SE, SO (distribution équilibrée)
  var branches = c.branches||[];
  var nBr = branches.length;
  // Angles en degrés — ajustés pour éviter le chevauchement des labels
  var presetAngles;
  if(nBr===4) presetAngles = [-140, -40, 40, 140]; // haut-gauche, haut-droit, bas-droit, bas-gauche
  else if(nBr===3) presetAngles = [-120, 0, 120];
  else if(nBr===2) presetAngles = [-90, 90];
  else { presetAngles = []; for(var a=0;a<nBr;a++) presetAngles.push(-180 + a*(360/nBr)); }

  var branchDist = 240;
  var itemDist   = 170;      // distance entre nœud branche et items
  var itemSpread = 95;       // largeur de l'arc d'items autour d'une branche
  var itemBoxW   = 140;
  var itemBoxH   = 30;

  branches.forEach(function(br,bi){
    var ang=(presetAngles[bi]||0)*Math.PI/180;
    var bx=cx+Math.cos(ang)*branchDist;
    var by=cy+Math.sin(ang)*branchDist;
    var delayBr = (0.3 + bi*0.15).toFixed(2);

    // Ligne centre → branche (courbe Bezier)
    var mpx = cx + Math.cos(ang)*(branchDist*0.55);
    var mpy = cy + Math.sin(ang)*(branchDist*0.55);
    // Perpendiculaire pour courber légèrement
    var perpAng = ang + Math.PI/2;
    mpx += Math.cos(perpAng)*18;
    mpy += Math.sin(perpAng)*18;
    svg+='<path class="mmLine" d="M'+cx+','+cy+' Q'+mpx+','+mpy+' '+bx+','+by+'" stroke="'+br.color+'" stroke-width="3.5" fill="none" opacity="0.8" stroke-linecap="round" style="animation-delay:'+delayBr+'s"/>';

    // Nœud branche (rectangle arrondi)
    var brBoxW = 160, brBoxH = 42;
    svg+='<rect class="mmBranch" x="'+(bx-brBoxW/2)+'" y="'+(by-brBoxH/2)+'" width="'+brBoxW+'" height="'+brBoxH+'" rx="14" fill="'+br.color+'" stroke="#fff" stroke-width="2" filter="url(#mmShadow)" style="animation-delay:'+delayBr+'s"/>';
    // Icône selon le label
    var brIco = '';
    var lbLow = (br.label||'').toLowerCase();
    if(/thème|theme/.test(lbLow)) brIco='💡 ';
    else if(/personnage/.test(lbLow)) brIco='👥 ';
    else if(/structure|genre|forme/.test(lbLow)) brIco='📐 ';
    else if(/contexte|époque|epoque|histoire/.test(lbLow)) brIco='🌍 ';
    else if(/style|procéd|procede/.test(lbLow)) brIco='🎨 ';
    svg+='<text class="mmBranch mmBranchLabel" x="'+bx+'" y="'+(by+5)+'" text-anchor="middle" font-size="13" style="animation-delay:'+delayBr+'s">'+brIco+_esc(br.label||'')+'</text>';

    // ── ITEMS : répartis sur un arc perpendiculaire à la branche ──
    var items = br.items||[];
    var nIt = items.length;
    // Direction "sortante" depuis le centre (continuation du rayon)
    // Les items sont placés sur un arc centré sur la branche, orienté vers l'extérieur
    items.forEach(function(it,ii){
      // Décalage angulaire : -spread/2 à +spread/2 réparti sur nIt
      var offsetDeg;
      if(nIt===1) offsetDeg=0;
      else offsetDeg = -itemSpread/2 + (ii*(itemSpread/(nIt-1)));
      var itAng = ang + (offsetDeg * Math.PI/180);
      // Position radiale depuis le centre (pas depuis la branche)
      var totalDist = branchDist + itemDist;
      var ix = cx + Math.cos(itAng)*totalDist;
      var iy = cy + Math.sin(itAng)*totalDist;

      // Clamp pour rester dans le viewBox avec marge
      var marginX=80, marginY=30;
      if(ix < itemBoxW/2+marginX) ix = itemBoxW/2+marginX;
      if(ix > W-itemBoxW/2-marginX) ix = W-itemBoxW/2-marginX;
      if(iy < itemBoxH/2+marginY) iy = itemBoxH/2+marginY;
      if(iy > H-itemBoxH/2-marginY) iy = H-itemBoxH/2-marginY;

      var delayIt = (parseFloat(delayBr) + 0.15 + ii*0.08).toFixed(2);
      // Ligne branche → item
      svg+='<line class="mmLine" x1="'+bx+'" y1="'+by+'" x2="'+ix+'" y2="'+iy+'" stroke="'+br.color+'" stroke-width="1.5" opacity="0.55" stroke-dasharray="5,4" style="animation-delay:'+delayIt+'s"/>';
      // Rectangle item
      svg+='<rect class="mmItem" x="'+(ix-itemBoxW/2)+'" y="'+(iy-itemBoxH/2)+'" width="'+itemBoxW+'" height="'+itemBoxH+'" rx="9" fill="rgba(255,255,255,0.08)" stroke="'+br.color+'" stroke-width="1.2" stroke-opacity="0.5" style="animation-delay:'+delayIt+'s"/>';
      // Texte item (tronqué si trop long)
      var txt = _esc(it);
      if(txt.length>22) txt = txt.substring(0,20)+'…';
      svg+='<text class="mmItem mmItemLabel" x="'+ix+'" y="'+(iy+4)+'" text-anchor="middle" font-size="11" style="animation-delay:'+delayIt+'s">'+txt+'</text>';
    });
  });

  // Signature discrète en bas
  svg+='<text x="'+(W-14)+'" y="'+(H-12)+'" text-anchor="end" font-family="Inter,sans-serif" font-size="10" fill="rgba(255,255,255,0.3)" font-style="italic">VÉRITAS · Mythe Errant 2026</text>';

  svg+='</svg>';

  // Légende des branches (cartes interactives sous le SVG)
  var legende = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px;margin-top:14px">';
  (c.branches||[]).forEach(function(br){
    legende += '<div style="background:'+br.color+';color:#fff;padding:10px 12px;border-radius:10px;box-shadow:0 3px 10px rgba(0,0,0,.15)">'
      +'<div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:13px;margin-bottom:6px">'+_esc(br.label||'')+'</div>'
      +'<div style="font-size:11px;opacity:.92;line-height:1.5">'
        +(br.items||[]).map(function(x){return '• '+_esc(x);}).join('<br>')
      +'</div>'
    +'</div>';
  });
  legende += '</div>';

  _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
    +'<div class="vsec-title">🗺️ Carte Mentale — '+_esc(oe.titre)+'</div>'
    +'<div class="vsec-sub" style="font-style:italic">'+_esc(oe.auteur)+' — '+_esc(oe.classe)+'</div>'
    +'<div class="vcard" style="padding:14px;background:var(--bg2)">'+svg+'</div>'
    +legende
    +'<div class="vcard mt14">'
    +'<div class="bold s mb8">📌 Comment utiliser cette carte ?</div>'
    +'<div style="font-size:13px;color:var(--ink3);line-height:1.8">'
    +'Visualisez les <strong>'+(c.branches||[]).length+' axes</strong> autour du centre (titre + auteur). '
    +'Chaque branche regroupe un aspect essentiel de l\'œuvre. '
    +'Reproduisez cette carte sur papier pour mieux mémoriser, ou téléchargez-la en image.'
    +'</div>'
    +'<div style="margin-top:12px;display:flex;gap:8px;flex-wrap:wrap">'
      +'<button class="btn sm bi" onclick="_mmDownload(\''+oeuvreKey+'\')">⬇️ Télécharger (PNG)</button>'
      +'<button class="btn sm bo" onclick="document.body.setAttribute(\'data-print-date\',new Date().toLocaleDateString(\'fr-FR\')+\' \'+new Date().toLocaleTimeString(\'fr-FR\',{hour:\'2-digit\',minute:\'2-digit\'}));window.print()">🖨️ Imprimer</button>'
    +'</div>'
    +'</div></div>');
}

// Helper d'échappement XML/HTML (si non défini ailleurs)
if(typeof _esc !== 'function'){
  window._esc = function(s){
    if(s==null) return '';
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
  };
}

// Télécharger la carte mentale en PNG — canvas HD 2x
function _mmDownload(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.carte){toast('Carte non disponible','warn');return;}
  toast('🎨 Génération HD…');
  setTimeout(function(){
    try{
      var cv=document.createElement('canvas');
      _mmDrawCv(cv,oe.carte,oe,2); // 2400×1520 px
      applyWatermark(cv,cv.getContext('2d'));
      var a=document.createElement('a');
      a.download='CarteMentale_'+(oe.titre||'oeuvre').replace(/[^\wÀ-ɏ]+/g,'_')+'.png';
      a.href=cv.toDataURL('image/png');
      a.click();
      toast('✓ Carte HD téléchargée (2400×1520 px)');
    }catch(e){toast('Erreur export: '+e.message,'err');}
  },50);
}

// ── MENU PRINCIPAL PAR ŒUVRE ────────────────────────────────────────
// ── CORRIGÉS MODÈLES (commentaire composé + dissertation) ───────────────
// v1.2.2 : charge le .md de /evaluations/ et l'affiche dans la fiche de l'œuvre.
function _showLittCorriges(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe){toast("Œuvre introuvable","warn");return;}
  var file=(typeof _oeuvreCorrige==='function')?_oeuvreCorrige(oeuvreKey):'';
  if(!file){toast("Aucun corrigé disponible pour cette œuvre","warn");return;}
  _vc('<div class="vsec">'
    +'<button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
    +'<div class="vsec-title">🏆 Corrigés modèles — '+_esc(oe.titre)+'</div>'
    +'<div class="vsec-sub" style="font-style:italic;color:var(--ink3)">Commentaire composé &amp; dissertation entièrement rédigés · '+_esc(oe.classe)+'</div>'
    +'<div id="littCorrigeBox" class="vcard ai-md" style="margin-top:16px;line-height:1.7">'
      +'<div style="text-align:center;color:var(--ink4);padding:24px"><span style="animation:pulse 1.2s infinite;font-size:28px">📖</span><br>Chargement du corrigé…</div>'
    +'</div></div>');
  var base=(typeof location!=='undefined'&&location.origin&&location.origin.indexOf('http')===0)?'':'';
  fetch(base+'evaluations/'+file+'?t='+Date.now())
    .then(function(r){ if(!r.ok) throw new Error('HTTP '+r.status); return r.text(); })
    .then(function(md){
      var box=document.getElementById('littCorrigeBox');
      if(box) box.innerHTML=(typeof _aiMarkdown==='function')?_aiMarkdown(md):('<pre style="white-space:pre-wrap">'+_esc(md)+'</pre>');
    })
    .catch(function(e){
      var box=document.getElementById('littCorrigeBox');
      if(box) box.innerHTML='<div class="ib ibt"><span>⚠️</span><span>Corrigé momentanément indisponible. Réessayez plus tard.<br><small>'+_esc(e.message||'')+'</small></span></div>';
    });
}

function _showLittMenu(jid,oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe){toast("Œuvre introuvable","warn");return;}
  var fi=oe.fiche||{};
  var ficheDesc=fi.genre?fi.genre:(oe.classe||'');
  // v2.4 FIX : tracker les œuvres visitées (badge litt_explorer)
  try {
    DB._oeuvresVisited = DB._oeuvresVisited || [];
    if(DB._oeuvresVisited.indexOf(oeuvreKey) < 0){
      DB._oeuvresVisited.push(oeuvreKey);
      save();
      if(typeof _checkBadges==='function') setTimeout(_checkBadges, 200);
    }
  } catch(e){}
  _vc('<div class="vsec">'
    +'<button class="back-btn" onclick="showJeuxEdu()">← Jeux</button>'
    +'<div class="vsec-title">📖 '+_esc(oe.titre)+'</div>'
    +'<div class="vsec-sub" style="font-style:italic;color:var(--ink3)">'+_esc(oe.auteur)+' — '+_esc(oe.classe)+'</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(155px,1fr));gap:14px;margin-top:18px">'
    // v2.1 : helper inline pour générer une carte avec icône Lucide + halo coloré
    + (function(){
        // ic = nom Lucide, c = couleur, bg = fond halo, t = titre, st = sous-titre, click = onclick
        function _lcard(ic, c, bg, t, st, click, isNew){
          return '<div class="vcard" style="cursor:pointer;text-align:center;position:relative;transition:all .25s var(--ease-out, ease-out);padding:16px 12px" onmouseover="this.style.transform=\'translateY(-3px)\';this.style.boxShadow=\'0 8px 24px rgba(20,37,84,.12)\'" onmouseout="this.style.transform=\'\';this.style.boxShadow=\'\'" onclick="'+click+'">'
            +(isNew?'<div style="position:absolute;top:8px;right:8px;background:linear-gradient(135deg,#7C3AED,#A855F7);color:#fff;font-size:8px;font-weight:900;padding:2px 7px;border-radius:8px;letter-spacing:.5px;z-index:2">✨ NEW</div>':'')
            // Halo circulaire coloré avec icône Lucide au centre
            +'<div style="width:56px;height:56px;border-radius:50%;background:'+bg+';display:flex;align-items:center;justify-content:center;margin:0 auto 12px;box-shadow:0 4px 12px '+bg.replace('0.12','0.25')+'">'
              +'<svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="'+c+'" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><use href="#lc-'+ic+'"/></svg>'
            +'</div>'
            +'<div style="font-family:\'Plus Jakarta Sans\',Montserrat,sans-serif;font-size:13px;font-weight:800;color:'+c+';line-height:1.2">'+t+'</div>'
            +'<div style="font-size:11px;color:var(--ink4);margin-top:5px;line-height:1.3">'+st+'</div>'
          +'</div>';
        }
        // v2.9.4 — Menu simplifié en 3 sections selon demande utilisateur :
        //   1. ANALYSE LITTÉRAIRE  → angle, contenu, extraits phares
        //   2. FICHE D'IDENTITÉ    → infos biblio + carte mentale + thèmes + axes
        //   3. CONTRÔLE DE LECTURE → citations + figures + techniques + QCM + questions ouvertes
        var nbControle = ((oe.citations||[]).length) + ((oe.techniques||[]).length) + ((oe.qcm||[]).length) + ((oe.controle||[]).length);
        var _hasCorrige = (typeof _oeuvreCorrige==='function') && _oeuvreCorrige(oeuvreKey);
        return (oe.analyse ? _lcard('bookopen','#7C3AED', 'rgba(124,58,237,0.12)','Analyse littéraire',   'Style accessible &amp; extraits phares', '_showLittAnalyse(\''+oeuvreKey+'\')', true) : '')
             + _lcard('clipboard', '#142554', 'rgba(16,185,129,0.12)',  'Fiche d\'identité',      _esc(ficheDesc)+' · Carte mentale',          '_showLittFiche(\''+oeuvreKey+'\')', false)
             + _lcard('pencil',    '#DC2626', 'rgba(220,38,38,0.12)',   'Contrôle de lecture',    nbControle+' éléments à maîtriser',          '_showLittControleComplet(\''+oeuvreKey+'\')', false)
             + (_hasCorrige ? _lcard('award','#F59E0B', 'rgba(245,158,11,0.14)', 'Corrigés modèles', 'Commentaire composé &amp; dissertation rédigés', '_showLittCorriges(\''+oeuvreKey+'\')', true) : '');
      })()
    +'</div>'
    // Bandeau auteur/classe
    +'<div class="vcard mt16" style="background:var(--bg2);display:flex;flex-wrap:wrap;gap:12px;align-items:center">'
      +'<div style="font-size:13px;color:var(--ink3);line-height:1.8;flex:1">'
        +'<strong>Auteur :</strong> '+_esc(oe.auteur)
        +(fi.edition?' &nbsp;·&nbsp; <strong>Édition :</strong> '+_esc(fi.edition):'')
        +(fi.epoque?' &nbsp;·&nbsp; <strong>Époque :</strong> '+_esc(fi.epoque):'')
        +' &nbsp;·&nbsp; <strong>Classe :</strong> '+_esc(oe.classe)
      +'</div>'
    +'</div>'
    +'</div>');
}

// ── FICHE D\'IDENTITÉ ─────────────────────────────────────────────────
function _showLittFiche(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe){toast("Œuvre introuvable","warn");return;}
  var fi=oe.fiche||{};
  var COL='#142554';
  var h='<div class="vsec">'
    +'<button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
    +'<div class="vsec-title">📋 Fiche d\'identité — '+_esc(oe.titre)+'</div>'
    +'<div class="vcard" style="max-width:640px;margin:0 auto">'
    +'<table style="width:100%;border-collapse:collapse;font-size:14px">';
  var rows=[
    ['📖 Titre',oe.titre],
    ['✍️ Auteur',oe.auteur],
    ['📅 Époque / Date',fi.epoque||'—'],
    ['🏛️ Mouvement',fi.mouvement||'—'],
    ['📚 Genre',fi.genre||'—'],
    ['🎭 Forme',fi.forme||'—'],
    ['🌍 Lieu / Contexte',fi.lieu||'—'],
    ['📕 Édition de référence',fi.edition||'—'],
    ['🎓 Classe',oe.classe]
  ];
  rows.forEach(function(r,i){
    h+='<tr style="background:'+(i%2===0?'#f8f9ff':'#fff')+'">'
      +'<td style="padding:9px 12px;font-weight:700;color:'+COL+';width:38%;border-bottom:1px solid #e5e7f0">'+r[0]+'</td>'
      +'<td style="padding:9px 12px;color:var(--ink);border-bottom:1px solid #e5e7f0">'+_esc(r[1])+'</td>'
      +'</tr>';
  });
  h+='</table>';
  // Thèmes principaux
  if(fi.themes&&fi.themes.length){
    h+='<div style="margin-top:16px"><div style="font-weight:800;color:'+COL+';font-size:13px;margin-bottom:8px">🔑 THÈMES PRINCIPAUX</div>'
      +'<div style="display:flex;flex-wrap:wrap;gap:8px">';
    fi.themes.forEach(function(t){
      h+='<span style="background:#EEF2FF;color:'+COL+';border-radius:20px;padding:4px 12px;font-size:12px;font-weight:600">'+_esc(t)+'</span>';
    });
    h+='</div></div>';
  }
  // Axes d'étude
  if(fi.axes&&fi.axes.length){
    h+='<div style="margin-top:16px"><div style="font-weight:800;color:'+COL+';font-size:13px;margin-bottom:8px">📐 AXES D\'ÉTUDE</div><ol style="margin:0;padding-left:18px;line-height:2">';
    fi.axes.forEach(function(a){
      h+='<li style="font-size:13px;color:var(--ink)">'+_esc(a)+'</li>';
    });
    h+='</ol></div>';
  }
  // Résumé / argument
  if(fi.resume){
    h+='<div style="margin-top:16px;padding:12px 16px;background:#FFF8E7;border-left:4px solid #FFC93C;border-radius:0 8px 8px 0">'
      +'<div style="font-weight:800;color:#92400E;font-size:12px;margin-bottom:6px;text-transform:uppercase">📝 Argument / Résumé</div>'
      +'<div style="font-size:13px;line-height:1.7;color:var(--ink)">'+_esc(fi.resume)+'</div></div>';
  }
  h+='</div>';
  // v2.9.4 — Carte mentale intégrée à la fiche d'identité (bouton dédié)
  if(oe.carte){
    h+='<div class="vcard mt16" style="max-width:640px;margin:16px auto 0;text-align:center;background:linear-gradient(135deg,#EFF6FF,#FAF5FF);border:1px dashed rgba(60,141,255,.3)">'
      +'<div style="font-size:13px;font-weight:800;color:#142554;margin-bottom:8px">🧠 Carte mentale interactive</div>'
      +'<div style="font-size:12px;color:#475569;margin-bottom:12px">Visualise les axes de lecture, thèmes, personnages et figures en un coup d\'œil.</div>'
      +'<button class="btn bi" onclick="_showLittCarte(\''+oeuvreKey+'\')" style="background:#3C8DFF;color:#fff;padding:10px 22px;border-radius:24px;font-weight:700;border:none;cursor:pointer">🗺️ Voir la carte mentale</button>'
    +'</div>';
  }
  h+='</div>';
  _vc(h);
}

// ══════════════════════════════════════════════════════════════════
// ── CONTRÔLE DE LECTURE COMPLET (v2.9.4) ────────────────────────
// Agrège citations + figures + techniques + QCM + questions ouvertes
// Format évaluation pour vérifier la compréhension de l'œuvre
// ══════════════════════════════════════════════════════════════════
function _showLittControleComplet(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe){toast("Œuvre introuvable","warn");return;}
  var COL='#DC2626';
  var nbCit = (oe.citations||[]).length;
  var nbTech = (oe.techniques||[]).length;
  var nbQcm = (oe.qcm||[]).length;
  var nbCtrl = (oe.controle||[]).length;
  var h='<div class="vsec">'
    +'<button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
    +'<div class="vsec-title">📝 Contrôle de lecture — '+_esc(oe.titre)+'</div>'
    +'<div class="vsec-sub" style="font-style:italic;color:var(--ink3)">Vérifie ta compréhension de l\'œuvre · '+_esc(oe.auteur)+'</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:14px;margin-top:18px;max-width:780px;margin-left:auto;margin-right:auto">';
  // Carte 1 — Citations & Figures de style
  if(nbCit > 0){
    h+='<div class="vcard" style="cursor:pointer;text-align:center;padding:18px 14px;border:1px solid rgba(245,158,11,.25);background:linear-gradient(135deg,#FFFBEB,#FEF3C7)" onclick="_showLittCitations(\''+oeuvreKey+'\')">'
      +'<div style="width:48px;height:48px;border-radius:50%;background:rgba(245,158,11,.18);display:flex;align-items:center;justify-content:center;margin:0 auto 10px"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#D97706" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><use href="#lc-message"/></svg></div>'
      +'<div style="font-weight:800;color:#92400E;font-size:13px">Citations &amp; Figures</div>'
      +'<div style="font-size:11px;color:#A16207;margin-top:4px">'+nbCit+' extraits + analyses</div>'
    +'</div>';
  }
  // Carte 2 — Techniques d'écriture
  if(nbTech > 0){
    h+='<div class="vcard" style="cursor:pointer;text-align:center;padding:18px 14px;border:1px solid rgba(124,58,237,.25);background:linear-gradient(135deg,#FAF5FF,#F3E8FF)" onclick="_showLittTechniques(\''+oeuvreKey+'\')">'
      +'<div style="width:48px;height:48px;border-radius:50%;background:rgba(124,58,237,.18);display:flex;align-items:center;justify-content:center;margin:0 auto 10px"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#7C3AED" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><use href="#lc-tool"/></svg></div>'
      +'<div style="font-weight:800;color:#6D28D9;font-size:13px">Techniques d\'écriture</div>'
      +'<div style="font-size:11px;color:#7C3AED;margin-top:4px">'+nbTech+' procédés identifiés</div>'
    +'</div>';
  }
  // Carte 3 — QCM (évaluation interactive)
  if(nbQcm > 0){
    h+='<div class="vcard" style="cursor:pointer;text-align:center;padding:18px 14px;border:1px solid rgba(60,141,255,.25);background:linear-gradient(135deg,#EFF6FF,#DBEAFE)" onclick="_lancerLittQCM(\''+oeuvreKey+'\')">'
      +'<div style="width:48px;height:48px;border-radius:50%;background:rgba(60,141,255,.18);display:flex;align-items:center;justify-content:center;margin:0 auto 10px"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#2563EB" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><use href="#lc-edit"/></svg></div>'
      +'<div style="font-weight:800;color:#1E40AF;font-size:13px">QCM noté</div>'
      +'<div style="font-size:11px;color:#2563EB;margin-top:4px">'+nbQcm+' questions · auto-correction</div>'
    +'</div>';
  }
  // Carte 4 — Questions ouvertes (contrôle écrit traditionnel)
  if(nbCtrl > 0){
    h+='<div class="vcard" style="cursor:pointer;text-align:center;padding:18px 14px;border:1px solid rgba(220,38,38,.25);background:linear-gradient(135deg,#FEF2F2,#FEE2E2)" onclick="_showLittControle(\''+oeuvreKey+'\')">'
      +'<div style="width:48px;height:48px;border-radius:50%;background:rgba(220,38,38,.18);display:flex;align-items:center;justify-content:center;margin:0 auto 10px"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#DC2626" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><use href="#lc-book"/></svg></div>'
      +'<div style="font-weight:800;color:#991B1B;font-size:13px">Questions ouvertes</div>'
      +'<div style="font-size:11px;color:#DC2626;margin-top:4px">'+nbCtrl+' questions de rédaction</div>'
    +'</div>';
  }
  h+='</div>';
  // Message si aucun contenu disponible
  if(nbCit + nbTech + nbQcm + nbCtrl === 0){
    h+='<div class="vcard mt16" style="max-width:480px;margin:24px auto 0;text-align:center;color:var(--ink3);font-style:italic">Aucun exercice de contrôle disponible pour cette œuvre pour le moment.</div>';
  } else {
    h+='<div class="vcard mt16" style="max-width:640px;margin:24px auto 0;background:#FEF2F2;border-left:4px solid #DC2626;padding:14px 18px">'
      +'<div style="font-weight:700;color:#991B1B;font-size:12px;margin-bottom:6px;text-transform:uppercase;letter-spacing:1px">💡 Conseil méthode</div>'
      +'<div style="font-size:13px;color:#7F1D1D;line-height:1.6">Pour valider ta lecture : 1) Commence par les <strong>Citations &amp; Figures</strong> (repérage). 2) Étudie les <strong>Techniques d\'écriture</strong>. 3) Teste-toi avec le <strong>QCM</strong> (auto-correction). 4) Termine par les <strong>Questions ouvertes</strong> (rédaction type examen).</div>'
    +'</div>';
  }
  h+='</div>';
  _vc(h);
}
window._showLittControleComplet = _showLittControleComplet;

// ══════════════════════════════════════════════════════════════════
// ── ANALYSE LITTÉRAIRE (style Çameditlivre) — v1.2 ───────────────
// Affiche le champ `analyse` d'une œuvre en plein écran
// ══════════════════════════════════════════════════════════════════
function _showLittAnalyse(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.analyse){toast("Aucune analyse disponible pour cette œuvre","warn");return;}
  var a=oe.analyse;
  var paragraphes=(a.contenu||'').split(/\n\n+/).filter(function(p){return p.trim().length>0;});
  var paragraphesHtml=paragraphes.map(function(p){
    var t=p.trim();
    // ── Passage / extrait d'œuvre (préfixé par 📖 EXTRAIT — ou 📖 SCÈNE —) ──
    if(/^📖\s*(EXTRAIT|SCÈNE|POÈME)/i.test(t)){
      // Séparer le label de l'extrait : "📖 EXTRAIT — Titre\n\nTexte..."
      var firstNl = t.indexOf('\n');
      var label = (firstNl>0) ? t.substring(0,firstNl).trim() : '📖 Extrait';
      var corps = (firstNl>0) ? t.substring(firstNl+1).trim() : t;
      return '<aside style="background:linear-gradient(135deg,#FAF5FF,#FDF4FF);border-left:4px solid #7C3AED;border-radius:0 14px 14px 0;padding:18px 22px;margin:22px 0;box-shadow:0 4px 14px rgba(124,58,237,.08);position:relative">'
        +'<div style="position:absolute;top:-10px;left:18px;background:#fff;padding:2px 10px;border:1px solid #E9D5FF;border-radius:20px;font-family:Montserrat,sans-serif;font-size:10px;font-weight:800;color:#7C3AED;letter-spacing:1.2px;text-transform:uppercase">'+_esc(label.replace(/^📖\s*/,''))+'</div>'
        +'<div style="font-family:Georgia,serif;font-size:14.5px;line-height:1.75;color:#4A5568;font-style:italic;white-space:pre-line">'+_esc(corps)+'</div>'
      +'</aside>';
    }
    // ── Paragraphe d'analyse normal ──
    return '<p style="font-family:Georgia,serif;font-size:15.5px;line-height:1.85;color:#2D3748;margin:0 0 18px;text-align:justify;hyphens:auto">'+_esc(t)+'</p>';
  }).join('');

  _vc('<div class="vsec">'
    +'<button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
    +'<article style="max-width:740px;margin:0 auto;background:#fff;border-radius:24px;overflow:hidden;box-shadow:0 12px 40px rgba(20,37,84,.08)">'
    // En-tête avec image et titre
    +'<header style="background:linear-gradient(135deg,#7C3AED 0%,#A855F7 50%,#EC4899 100%);padding:32px 28px 28px;color:#fff;position:relative;overflow:hidden">'
      +'<div style="position:absolute;top:-30px;right:-30px;width:160px;height:160px;background:radial-gradient(circle,rgba(255,255,255,.18) 0%,transparent 70%);border-radius:50%"></div>'
      +'<div style="position:absolute;bottom:-40px;left:-40px;width:140px;height:140px;background:radial-gradient(circle,rgba(255,201,60,.2) 0%,transparent 70%);border-radius:50%"></div>'
      +'<div style="position:relative;z-index:1">'
        +'<div style="display:inline-flex;align-items:center;gap:6px;background:rgba(255,255,255,.2);backdrop-filter:blur(8px);color:#fff;padding:5px 14px;border-radius:18px;font-size:10.5px;font-weight:900;letter-spacing:1.5px;text-transform:uppercase;margin-bottom:14px;border:1px solid rgba(255,255,255,.25)">'
          +'📖 Analyse littéraire'
        +'</div>'
        +'<h1 style="font-family:\'Libre Baskerville\',Georgia,serif;font-size:30px;font-weight:700;margin:0 0 8px;line-height:1.2;letter-spacing:.3px;text-shadow:0 2px 6px rgba(0,0,0,.15)">'+_esc(oe.titre)+'</h1>'
        +'<div style="font-style:italic;opacity:.95;font-size:14px;margin-bottom:14px">'+_esc(oe.auteur||'')+(oe.classe?' · <span style="background:rgba(255,255,255,.18);padding:2px 10px;border-radius:10px;font-size:11px;font-style:normal;font-weight:700;margin-left:6px">'+_esc(oe.classe)+'</span>':'')+'</div>'
        // Angle de lecture
        +'<div style="background:rgba(0,0,0,.12);backdrop-filter:blur(6px);border-left:4px solid #FFC93C;padding:14px 18px;border-radius:6px;margin-top:18px">'
          +'<div style="font-size:10px;font-weight:900;letter-spacing:1.5px;color:#FFC93C;text-transform:uppercase;margin-bottom:4px">🎯 Angle de lecture</div>'
          +'<div style="font-family:Georgia,serif;font-size:17px;font-style:italic;color:#fff;line-height:1.4">'+_esc(a.angle||'')+'</div>'
        +'</div>'
      +'</div>'
    +'</header>'
    // Citation phare
    +(a.citation?
      '<div style="padding:24px 32px;background:linear-gradient(180deg,#FAFBFF,#fff);border-bottom:1px solid rgba(124,58,237,.1)">'
      +'<blockquote style="font-family:\'Libre Baskerville\',Georgia,serif;font-size:18px;font-style:italic;color:#1E293B;line-height:1.6;padding:0 16px;margin:0;border-left:4px solid #7C3AED;position:relative">'
        +'<span style="position:absolute;top:-12px;left:-8px;font-size:48px;color:rgba(124,58,237,.2);font-family:Georgia,serif;line-height:1">"</span>'
        +'<span style="position:relative;z-index:1">'+_esc(a.citation)+'</span>'
      +'</blockquote>'
      +'</div>'
    :'')
    // Corps de l'analyse
    +'<div style="padding:32px 36px">'
      +paragraphesHtml
    +'</div>'
    // Footer retiré — l'analyse parle d'elle-même, plus besoin de mention de style
    // Actions
    +'<div style="padding:18px 32px 26px;display:flex;gap:10px;flex-wrap:wrap;justify-content:center">'
      +'<button class="btn bi" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')" style="padding:10px 22px;border-radius:14px;font-weight:700">← Menu de l\'œuvre</button>'
      +(oe.citations&&oe.citations.length?'<button class="btn bo" onclick="_showLittCitations(\''+oeuvreKey+'\')" style="padding:10px 22px;border-radius:14px;font-weight:700">💬 Citations détaillées →</button>':'')
    +'</div>'
    +'</article>'
    +'</div>');
}

// ── CITATIONS & FIGURES DE STYLE ──────────────────────────────────────
function _showLittCitations(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.citations||!oe.citations.length){toast("Aucune citation disponible","warn");return;}
  var idx=0;
  function renderCit(){
    var c=oe.citations[idx];
    var h='<div class="vsec">'
      +'<button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
      +'<div class="vsec-title">💬 Citations & Figures — '+_esc(oe.titre)+'</div>'
      +'<div style="font-size:12px;color:var(--ink4);text-align:center;margin-bottom:12px">Extrait '+(idx+1)+' / '+oe.citations.length+'</div>'
      // Citation principale
      +'<div class="vcard" style="max-width:660px;margin:0 auto">'
      +'<div style="background:#1a1a2e;border-radius:10px;padding:18px 20px;margin-bottom:16px">'
        +'<div style="font-family:Georgia,serif;font-size:16px;font-style:italic;color:#FFC93C;line-height:1.8">'
          +'« '+_esc(c.texte)+' »'
        +'</div>'
        +'<div style="font-size:11px;color:#aaa;margin-top:8px;text-align:right">'+_esc(c.source)+'</div>'
      +'</div>'
      // Figures de style
      +(c.figures&&c.figures.length?
        '<div style="margin-bottom:14px"><div style="font-weight:800;color:#142554;font-size:12px;text-transform:uppercase;margin-bottom:8px">🎨 Figures de style identifiées</div>'
        +'<div style="display:flex;flex-wrap:wrap;gap:8px">'
        +c.figures.map(function(f){
          return '<span style="background:#DBEAFE;color:#1E40AF;border-radius:20px;padding:5px 14px;font-size:12px;font-weight:700">'+_esc(f)+'</span>';
        }).join('')
        +'</div></div>'
      :'')
      // Analyse
      +'<div style="background:#F0F4FF;border-radius:10px;padding:14px 16px">'
        +'<div style="font-weight:800;color:#142554;font-size:12px;text-transform:uppercase;margin-bottom:8px">🔍 Analyse littéraire</div>'
        +'<div style="font-size:13px;line-height:1.8;color:var(--ink)">'+_esc(c.analyse)+'</div>'
      +'</div>'
      // Effet
      +(c.effet?
        '<div style="margin-top:12px;padding:10px 14px;background:#F0FDF4;border-left:3px solid #059669;border-radius:0 8px 8px 0">'
          +'<div style="font-weight:700;color:#065F46;font-size:12px;text-transform:uppercase;margin-bottom:4px">💡 Effet produit</div>'
          +'<div style="font-size:13px;line-height:1.7;color:var(--ink)">'+_esc(c.effet)+'</div>'
        +'</div>'
      :'')
      // Navigation
      +'<div style="display:flex;gap:10px;margin-top:18px;justify-content:space-between">'
        +'<button class="btn bo" onclick="void(0)" id="citPrev" style="'+(idx===0?'opacity:.35;pointer-events:none':'')+'">← Précédent</button>'
        +'<button class="btn bi" onclick="void(0)" id="citNext" style="'+(idx>=oe.citations.length-1?'opacity:.35;pointer-events:none':'')+'">Suivant →</button>'
      +'</div>'
      +'</div></div>';
    _vc(h);
    var prev=document.getElementById('citPrev');
    var next=document.getElementById('citNext');
    if(prev&&idx>0)prev.onclick=function(){idx--;renderCit();};
    if(next&&idx<oe.citations.length-1)next.onclick=function(){idx++;renderCit();};
  }
  renderCit();
}

// ── TECHNIQUES D\'ÉCRITURE ────────────────────────────────────────────
function _showLittTechniques(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.techniques||!oe.techniques.length){toast("Aucune technique disponible","warn");return;}
  var h='<div class="vsec">'
    +'<button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
    +'<div class="vsec-title">🔧 Techniques d\'écriture — '+_esc(oe.titre)+'</div>'
    +'<div style="max-width:660px;margin:0 auto;display:flex;flex-direction:column;gap:14px">';
  oe.techniques.forEach(function(t,i){
    var cols=['#142554','#059669','#D97706','#7C3AED','#DC2626','#0891B2'];
    var col=cols[i%cols.length];
    // Normaliser : si t est une simple chaîne, la convertir en objet {nom}
    if(typeof t === 'string'){ t = {nom: t}; }
    if(!t || (!t.nom && !t.def && !t.exemple && !t.effet)) return;
    h+='<div class="vcard" style="border-left:5px solid '+col+'">'
      +'<div style="display:flex;align-items:center;gap:10px;margin-bottom:'+(t.def||t.exemple||t.effet?'10px':'0')+'">'
        +'<span style="background:'+col+';color:#fff;border-radius:50%;width:26px;height:26px;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:800;flex-shrink:0">'+(i+1)+'</span>'
        +'<div style="font-weight:800;color:'+col+';font-size:15px">'+_esc(t.nom||'Procédé '+(i+1))+'</div>'
      +'</div>'
      +(t.def?'<div style="font-size:13px;color:var(--ink4);margin-bottom:8px;font-style:italic">'+_esc(t.def)+'</div>':'')
      +(t.exemple?
        '<div style="background:#1a1a2e;border-radius:8px;padding:10px 14px;margin-bottom:8px">'
          +'<div style="font-size:11px;color:#aaa;margin-bottom:4px;text-transform:uppercase;font-weight:600">Exemple dans l\'œuvre</div>'
          +'<div style="font-family:Georgia,serif;font-size:14px;color:#FFC93C;font-style:italic;line-height:1.7">'+_esc(t.exemple)+'</div>'
        +'</div>'
      :'')
      +(t.effet?
        '<div style="background:#F0FDF4;border-radius:8px;padding:10px 14px">'
          +'<div style="font-size:11px;color:#065F46;margin-bottom:4px;font-weight:700;text-transform:uppercase">💡 Effet littéraire</div>'
          +'<div style="font-size:13px;color:var(--ink);line-height:1.7">'+_esc(t.effet)+'</div>'
        +'</div>'
      :'')
    +'</div>';
  });
  h+='</div></div>';
  _vc(h);
}

// ── CONTRÔLE DE LECTURE ───────────────────────────────────────────────
function _showLittControle(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.controle||!oe.controle.length){toast("Aucun contrôle disponible","warn");return;}
  var idx=0; var score=0; var revealed=false;
  function renderCtrl(){
    if(idx>=oe.controle.length){
      _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
        +'<div class="vcard" style="text-align:center;max-width:480px;margin:0 auto">'
        +'<div style="font-size:52px;margin-bottom:12px">📚</div>'
        +'<div class="vsec-title">Contrôle terminé !</div>'
        +'<div style="font-size:28px;font-weight:700;color:#142554">'+score+' / '+oe.controle.length+'</div>'
        +'<div style="font-size:13px;color:var(--ink4);margin:10px 0">Questions maîtrisées</div>'
        +'<button class="btn bi mt12" onclick="_showLittControle(\''+oeuvreKey+'\')">🔄 Recommencer</button>'
        +'<button class="btn bo mt8" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Menu</button>'
        +'</div></div>');
      return;
    }
    var q=oe.controle[idx];
    revealed=false;
    var h='<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
      +'<div class="vsec-title">📚 Contrôle de lecture — '+_esc(oe.titre)+'</div>'
      +'<div class="vcard" style="max-width:620px;margin:0 auto">'
      +'<div class="quiz-progress"><div class="quiz-progress-fill" style="width:'+Math.round(idx/oe.controle.length*100)+'%"></div></div>'
      +'<div style="font-size:11px;font-weight:700;color:var(--ink4);text-transform:uppercase;margin:8px 0">Question '+(idx+1)+' / '+oe.controle.length+' — Points : '+score+'</div>'
      +'<div style="font-family:Georgia,serif;font-size:16px;color:var(--ink);line-height:1.65;margin-bottom:18px;font-weight:600;padding:14px;background:#F0F4FF;border-radius:10px">'+_esc(q.q)+'</div>'
      +'<button class="btn bo" id="ctrlReveal" style="width:100%;margin-bottom:12px">👁 Voir la réponse attendue</button>'
      +'<div id="ctrlAns" style="display:none;background:#1a1a2e;border-radius:10px;padding:16px 18px;margin-bottom:16px">'
        +'<div style="font-size:11px;color:#aaa;text-transform:uppercase;margin-bottom:8px;font-weight:600">Réponse attendue</div>'
        +'<div style="font-family:Georgia,serif;font-size:14px;color:#FFC93C;line-height:1.8;font-style:italic">'+_esc(q.r)+'</div>'
      +'</div>'
      +'<div id="ctrlRate" style="display:none">'
        +'<div style="font-size:13px;font-weight:700;color:var(--ink3);margin-bottom:10px;text-align:center">Avez-vous bien répondu ?</div>'
        +'<div style="display:flex;gap:12px">'
          +'<button class="btn" style="flex:1;background:#D1FAE5;color:#065F46;border:2px solid #059669;font-weight:700" id="ctrlOui">✅ Oui</button>'
          +'<button class="btn" style="flex:1;background:#FEE2E2;color:#991B1B;border:2px solid #DC2626;font-weight:700" id="ctrlNon">❌ Non</button>'
        +'</div>'
      +'</div>'
      +'</div></div>';
    _vc(h);
    var revBtn=document.getElementById('ctrlReveal');
    var ansDiv=document.getElementById('ctrlAns');
    var rateDiv=document.getElementById('ctrlRate');
    if(revBtn)revBtn.onclick=function(){
      if(ansDiv)ansDiv.style.display='block';
      if(rateDiv)rateDiv.style.display='block';
      revBtn.style.display='none';
    };
    var ouiBtn=document.getElementById('ctrlOui');
    var nonBtn=document.getElementById('ctrlNon');
    if(ouiBtn)ouiBtn.onclick=function(){score++;idx++;renderCtrl();};
    if(nonBtn)nonBtn.onclick=function(){idx++;renderCtrl();};
  }
  renderCtrl();
}

// ── QCM LITTÉRAIRE ─────────────────────────────────────────────────
function _lancerLittQCM(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.qcm||!oe.qcm.length){toast("Aucune question QCM","warn");return;}
  var qs=oe.qcm.slice().sort(function(){return Math.random()-.5;});
  var idx=0;var score=0;
  function renderQ(){
    if(idx>=qs.length){
      var pct=Math.round(score/qs.length*100);
      var msg=pct>=70?"✅ Excellent !":pct>=50?"👍 Bien !":"📚 Révisez l'œuvre";
      _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
        +'<div class="vcard" style="text-align:center"><div style="font-size:52px;margin-bottom:12px">🎉</div>'
        +'<div class="vsec-title">Quiz terminé !</div>'
        +'<div style="font-size:28px;font-weight:700;color:'+(pct>=70?"#059669":"#D97706")+'">'+score+' / '+qs.length+'</div>'
        +'<div style="font-size:13px;color:var(--ink4);margin:10px 0">'+msg+'</div>'
        +'<button class="btn bi mt12" onclick="_lancerLittQCM(\''+oeuvreKey+'\')">🔄 Rejouer</button>'
        +'<button class="btn bo mt8" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Menu</button>'
        +'</div></div>');
      return;
    }
    var q=qs[idx];
    var html='<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
      +'<div class="vsec-title">📝 '+oe.titre+'</div>'
      +'<div class="vcard">'
      +'<div class="quiz-progress"><div class="quiz-progress-fill" style="width:'+Math.round(idx/qs.length*100)+'%"></div></div>'
      +'<div style="font-size:11px;font-weight:700;color:var(--ink4);text-transform:uppercase;margin:8px 0">Question '+(idx+1)+'/'+qs.length+' — Score : '+score+'</div>'
      +'<div style="font-family:Georgia,serif;font-size:16px;color:var(--ink);line-height:1.6;margin-bottom:18px;font-weight:600">'+q.q+'</div>'
      +'<div class="quiz-opts">';
    var safeExp=(q.exp||'').replace(/\\/g,'\\\\').replace(/'/g,"\\'").replace(/"/g,'&quot;');
    q.opts.forEach(function(o,i){
      html+='<button class="quiz-opt" id="qo'+i+'" onclick="_lqAns('+i+','+q.ans+',\''+safeExp+'\')">'
        +'<span style="display:inline-block;width:22px;height:22px;border-radius:50%;background:#E8EEFF;color:#142554;font-size:11px;font-weight:800;line-height:22px;text-align:center;margin-right:8px">'+'ABCD'[i]+'</span>'+o+'</button>';
    });
    html+='</div><div id="lqfb" style="margin-top:14px;min-height:20px"></div></div></div>';
    _vc(html);
    window._lqAns=function(chosen,correct,exp){
      document.querySelectorAll('.quiz-opt').forEach(function(b){b.disabled=true;});
      var fb=document.getElementById('lqfb');
      if(chosen===correct){
        score++;
        var btn=document.getElementById('qo'+correct);
        if(btn)btn.classList.add('correct');
        if(fb)fb.innerHTML='<div style="color:#059669;font-weight:700;padding:10px 14px;background:#D1FAE5;border-radius:10px">✅ Correct ! '+exp+'</div>';
      }else{
        var wb=document.getElementById('qo'+chosen);
        var cb=document.getElementById('qo'+correct);
        if(wb)wb.classList.add('wrong');
        if(cb)cb.classList.add('correct');
        if(fb)fb.innerHTML='<div style="color:#DC2626;font-weight:700;padding:10px 14px;background:#FEE2E2;border-radius:10px">❌ Incorrect. '+exp+'</div>';
      }
      idx++;
      setTimeout(renderQ,1800);
    };
  }
  renderQ();
}

// ── VRAI / FAUX — conservé pour rétrocompatibilité (non affiché) ──
function _lancerLittVF(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.vf||!oe.vf.length){toast("Aucune question V/F","warn");return;}
  var qs=oe.vf.slice().sort(function(){return Math.random()-.5;});
  var idx=0;var score=0;
  function renderVF(){
    if(idx>=qs.length){
      _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
        +'<div class="vcard" style="text-align:center"><div style="font-size:52px;margin-bottom:12px">🎉</div>'
        +'<div class="vsec-title">Vrai/Faux terminé !</div>'
        +'<div style="font-size:28px;font-weight:700;color:#059669">'+score+' / '+qs.length+'</div>'
        +'<button class="btn bi mt12" onclick="_lancerLittVF(\''+oeuvreKey+'\')">🔄 Rejouer</button></div></div>');
      return;
    }
    var q=qs[idx];
    var safeExpVF=(q.exp||'').replace(/\\/g,'\\\\').replace(/'/g,"\\'").replace(/"/g,'&quot;');
    _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
      +'<div class="vsec-title">✅ Vrai/Faux — '+oe.titre+'</div>'
      +'<div class="vcard" style="max-width:560px;margin:0 auto">'
      +'<div style="font-size:11px;font-weight:700;color:var(--ink4);text-transform:uppercase;margin-bottom:8px">Proposition '+(idx+1)+'/'+qs.length+'</div>'
      +'<div style="font-family:Georgia,serif;font-size:17px;line-height:1.65;color:var(--ink);margin-bottom:24px;font-weight:600;border-left:4px solid #FFC93C;padding-left:14px">'+q.q+'</div>'
      +'<div style="display:flex;gap:14px;justify-content:center">'
      +'<button id="vfV" style="flex:1;padding:16px;border-radius:14px;border:2.5px solid #059669;background:#D1FAE5;color:#065F46;font-size:16px;font-weight:800;cursor:pointer" onclick="_vfLittAns(true,'+q.rep+',\''+safeExpVF+'\')">✅ VRAI</button>'
      +'<button id="vfF" style="flex:1;padding:16px;border-radius:14px;border:2.5px solid #DC2626;background:#FEE2E2;color:#991B1B;font-size:16px;font-weight:800;cursor:pointer" onclick="_vfLittAns(false,'+q.rep+',\''+safeExpVF+'\')">❌ FAUX</button>'
      +'</div>'
      +'<div id="vffb" style="margin-top:14px;min-height:20px"></div>'
      +'</div></div>');
    window._vfLittAns=function(chosen,correct,exp){
      var bv=document.getElementById('vfV');var bf=document.getElementById('vfF');
      if(bv)bv.disabled=true;if(bf)bf.disabled=true;
      var fb=document.getElementById('vffb');
      var ok=(chosen===correct);
      if(ok)score++;
      var col=ok?'#059669':'#DC2626';var bg=ok?'#D1FAE5':'#FEE2E2';
      if(fb)fb.innerHTML='<div style="color:'+col+';font-weight:700;padding:10px 14px;background:'+bg+';border-radius:10px">'+(ok?'✅ Exact !':'❌ Incorrect.')+' '+exp+'</div>';
      idx++;
      setTimeout(renderVF,1800);
    };
  }
  renderVF();
}

// ── PENDU LITTÉRAIRE ───────────────────────────────────────────────
function _lancerLittPendu(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.pendu||!oe.pendu.length){toast("Aucun mot pour le pendu","warn");return;}
  var mots=oe.pendu.slice().sort(function(){return Math.random()-.5;});
  var midx=0;var score=0;
  var VIES_MAX=6;
  var vies,trouves,essayes,motCourant;
  var PHEAD=['😊','🙂','😐','😟','😨','😰','😵'];
  function startMot(){
    if(midx>=mots.length){
      _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
        +'<div class="vcard" style="text-align:center"><div style="font-size:52px;margin-bottom:12px">🎯</div>'
        +'<div class="vsec-title">Pendu terminé !</div>'
        +'<div style="font-size:28px;font-weight:700;color:#142554">'+score+' / '+mots.length+' mots</div>'
        +'<button class="btn bi mt12" onclick="_lancerLittPendu(\''+oeuvreKey+'\')">🔄 Rejouer</button></div></div>');
      return;
    }
    motCourant=mots[midx].toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"");
    vies=VIES_MAX;trouves=[];essayes=[];
    renderPendu();
  }
  function renderPendu(){
    var alpha='ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
    var affiche=motCourant.split('').map(function(c,i){
      if(!/[A-Z]/.test(c))return c;
      return trouves.indexOf(i)>=0?c:'_';
    }).join(' ');
    var letMot=motCourant.replace(/[^A-Z]/g,'');
    var found=(trouves.length===letMot.length);
    var lost=(vies<=0);
    var html='<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
      +'<div class="vsec-title">🎯 Pendu — '+oe.titre+'</div>'
      +'<div class="vcard" style="text-align:center;max-width:520px;margin:0 auto">'
      +'<div style="font-size:36px;margin-bottom:4px">'+PHEAD[Math.min(vies,6)]+'</div>'
      +'<div style="font-size:11px;color:var(--ink4);margin-bottom:10px">Mot '+(midx+1)+'/'+mots.length+' — Vies : '+vies+' — Score : '+score+'</div>'
      +'<div style="font-family:\'Fira Code\',monospace;font-size:26px;font-weight:700;color:#142554;letter-spacing:6px;margin:14px 0">'+affiche+'</div>';
    if(found||lost){
      if(found){score++;html+='<div style="color:#059669;font-weight:700;font-size:14px;margin:8px 0">✅ Bravo ! '+mots[midx]+'</div>';}
      else{html+='<div style="color:#DC2626;font-weight:700;font-size:14px;margin:8px 0">❌ Perdu ! Le mot : '+mots[midx]+'</div>';}
      html+='<button class="btn bi mt10" id="nextMot">Suivant →</button>';
    }else{
      html+='<div style="display:flex;flex-wrap:wrap;gap:5px;justify-content:center;margin-top:12px">';
      alpha.forEach(function(l){
        var used=essayes.indexOf(l)>=0;
        var hit=used&&motCourant.indexOf(l)>=0;
        html+='<button onclick="_penduLett(\''+l+'\')" '+(used?'disabled':'')+' style="width:34px;height:34px;border-radius:8px;border:2px solid '+(hit?'#059669':used?'#DC2626':'#C7D2FE')+';background:'+(hit?'#D1FAE5':used?'#FEE2E2':'#F0F4FF')+';color:'+(hit?'#065F46':used?'#991B1B':'#142554')+';font-weight:800;font-size:13px;cursor:'+(used?'default':'pointer')+'">'+l+'</button>';
      });
      html+='</div>';
    }
    html+='</div></div>';
    _vc(html);
    if(found||lost){
      var nb=document.getElementById('nextMot');
      if(nb)nb.onclick=function(){midx++;startMot();};
    }
    window._penduLett=function(l){
      if(essayes.indexOf(l)>=0)return;
      essayes.push(l);
      if(motCourant.indexOf(l)>=0){
        motCourant.split('').forEach(function(c,i){if(c===l&&trouves.indexOf(i)<0)trouves.push(i);});
      }else{vies--;}
      renderPendu();
    };
  }
  startMot();
}

// ── TEXTE À TROUS LITTÉRAIRE ───────────────────────────────────────
function _lancerLittTrous(oeuvreKey){
  var oe=LITT_OEUVRES[oeuvreKey];
  if(!oe||!oe.trous||!oe.trous.length){toast("Aucun texte à trous","warn");return;}
  var qs=oe.trous.slice().sort(function(){return Math.random()-.5;});
  var idx=0;var score=0;
  function renderTrous(){
    if(idx>=qs.length){
      _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
        +'<div class="vcard" style="text-align:center"><div style="font-size:52px;margin-bottom:12px">✍️</div>'
        +'<div class="vsec-title">Texte à trous terminé !</div>'
        +'<div style="font-size:28px;font-weight:700;color:#059669">'+score+' / '+qs.length+'</div>'
        +'<button class="btn bi mt12" onclick="_lancerLittTrous(\''+oeuvreKey+'\')">🔄 Rejouer</button></div></div>');
      return;
    }
    var q=qs[idx];
    var affPhrase=q.phrase.replace('___','<span style="display:inline-block;border-bottom:2px solid #FFC93C;min-width:80px">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span>');
    _vc('<div class="vsec"><button class="back-btn" onclick="_showLittMenu(\''+oeuvreKey+'\',\''+oeuvreKey+'\')">← Retour</button>'
      +'<div class="vsec-title">✍️ Texte à trous — '+oe.titre+'</div>'
      +'<div class="vcard" style="max-width:560px;margin:0 auto">'
      +'<div style="font-size:11px;font-weight:700;color:var(--ink4);text-transform:uppercase;margin-bottom:10px">Phrase '+(idx+1)+'/'+qs.length+' — Score : '+score+'</div>'
      +'<div style="font-family:Georgia,serif;font-size:17px;line-height:2;color:var(--ink);margin-bottom:12px;font-weight:600">'+affPhrase+'</div>'
      +'<div class="ib ibt mb12"><span>💡</span><span>Indice : <span style="font-family:monospace;font-size:13px;letter-spacing:3px">'+q.indice+'</span></span></div>'
      +'<input class="fi" id="trInp" placeholder="Votre réponse..." style="font-size:15px;text-align:center">'
      +'<div style="display:flex;gap:10px;margin-top:12px">'
      +'<button class="btn bi" onclick="_trLittCheck()" style="flex:1">✓ Valider</button>'
      +'</div>'
      +'<div id="trFb" style="margin-top:12px;min-height:20px"></div>'
      +'</div></div>');
    setTimeout(function(){
      var el=document.getElementById('trInp');
      if(el){
        el.focus();
        el.onkeydown=function(e){if(e.key==='Enter')_trLittCheck();};
      }
    },100);
    var rep=q.rep;
    window._trLittCheck=function(){
      var inp=document.getElementById('trInp');
      var val=((inp&&inp.value)||'').trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,'');
      var cor=rep.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,'');
      var fb=document.getElementById('trFb');
      var ok=(val===cor||cor.includes(val)&&val.length>2||val.includes(cor)&&cor.length>2);
      if(ok)score++;
      var col=ok?'#059669':'#DC2626';var bg=ok?'#D1FAE5':'#FEE2E2';
      if(fb)fb.innerHTML='<div style="color:'+col+';font-weight:700;padding:10px 14px;background:'+bg+';border-radius:10px">'+(ok?'✅ Correct !':'❌ Incorrect. Réponse : <strong>'+rep+'</strong>')+'</div>';
      idx++;
      setTimeout(renderTrous,1800);
    };
  }
  renderTrous();
}


// ── UPLOAD IMAGE ───────────────────────────────────────────────────
function _uploadImage(inputId,onDone,maxKo){
  var inp=document.getElementById(inputId);
  if(!inp||!inp.files||!inp.files[0]){toast("Aucun fichier selectionne","warn");return;}
  var f=inp.files[0];
  if(f.size>(maxKo||500)*1024){toast("Image trop lourde (max "+(maxKo||500)+" Ko)","warn");return;}
  if(!f.type.startsWith("image/")){toast("Format image requis","warn");return;}
  var r=new FileReader();
  r.onload=function(e){onDone(e.target.result,f.type);};
  r.readAsDataURL(f);
}

// ── RELEVÉ SIMPLIFIÉ ───────────────────────────────────────────────
function pgReleve(){
  var s=SES;
  if(!s)return "<div class='empty'><div class='empty-ico'>📊</div>Non connecte</div>";
  var gr=DB.grades||[];
  var sGr=gr.filter(function(g){return g.eid===s.id;});
  function moyTri(tri){
    var gT=sGr.filter(function(g){return g.tri===tri;});
    if(!gT.length)return null;
    var tc=gT.reduce(function(a,g){return a+g.coef;},0)||1;
    return gT.reduce(function(a,g){return a+((g.n1+g.n2)/2)*g.coef;},0)/tc;
  }
  var moyTris=TRS.map(function(tri){return{tri:tri,moy:moyTri(tri)};});
  var valid=moyTris.filter(function(m){return m.moy!==null;});
  var moyAnn=valid.length?valid.reduce(function(a,m){return a+m.moy;},0)/valid.length:null;
  var ap=moyAnn!==null?getAppr(moyAnn):null;
  var rangAnn="—";
  if(moyAnn!==null){
    var cls=DB.students.filter(function(st){return st.cls===s.cls;});
    var allM=cls.map(function(st){
      var stG=gr.filter(function(g){return g.eid===st.id;});
      var v2=TRS.map(function(tri){var tg=stG.filter(function(g){return g.tri===tri;});if(!tg.length)return null;var tc=tg.reduce(function(a,g){return a+g.coef;},0)||1;return tg.reduce(function(a,g){return a+((g.n1+g.n2)/2)*g.coef;},0)/tc;}).filter(function(m){return m!==null;});
      return v2.length?v2.reduce(function(a,m){return a+m;},0)/v2.length:null;
    }).filter(function(m){return m!==null;}).sort(function(a,b){return b-a;});
    rangAnn=allM.findIndex(function(m){return Math.abs(m-moyAnn)<0.001;})+1;
  }
  var h="<div class='card mb16' style='background:linear-gradient(135deg,#142554,#1a3a8a);color:#fff;border:none;padding:22px'>";
  h+="<div class='fl2 fic fsb fw g12'><div>";
  h+="<div style='font-family:Montserrat,sans-serif;font-size:18px;color:#FFC93C;font-weight:800'>"+s.pre+" "+s.nom+"</div>";
  h+="<div style='font-size:12px;color:rgba(255,255,255,.55);margin-top:3px'>Matricule: "+s.mat+" · Classe: "+s.cls+"</div></div>";
  if(moyAnn!==null){
    h+="<div class='fl2 g16 fw'>";
    h+="<div style='text-align:center'><div style='font-size:9px;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:1px'>Moy. annuelle</div>";
    h+="<div style='font-family:Georgia,serif;font-size:28px;font-weight:700;color:"+(ap?ap.col:"#fff")+"'>"+moyAnn.toFixed(2)+"</div>";
    h+="<div style='font-size:11px;color:"+(ap?ap.col:"rgba(255,255,255,.5)")+"'>"+(ap?ap.lbl:"—")+"</div></div>";
    h+="<div style='text-align:center'><div style='font-size:9px;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:1px'>Rang</div>";
    h+="<div style='font-family:Georgia,serif;font-size:28px;font-weight:700;color:#A5F3FC'>"+rangAnn+"</div>";
    h+="<div style='font-size:11px;color:rgba(255,255,255,.5)'>sur "+DB.students.filter(function(st){return st.cls===s.cls;}).length+"</div></div>";
    h+="</div>";
  }
  h+="</div></div>";
  TRS.forEach(function(tri){
    var gT=sGr.filter(function(g){return g.tri===tri;});
    var moy=moyTri(tri);var ap2=moy!==null?getAppr(moy):null;
    h+="<div class='card mb14'>";
    h+="<div class='fl2 fic fsb mb10'>";
    h+="<div style='font-family:Montserrat,sans-serif;font-size:14px;font-weight:800;color:#142554'>"+tri+"</div>";
    if(moy!==null)h+="<div style='font-family:Georgia,serif;font-size:16px;font-weight:700;color:"+(ap2?ap2.col:"#142554")+"'>"+moy.toFixed(2)+"/20</div>";
    else h+="<span style='font-size:12px;color:#9CA3AF'>Pas de notes</span>";
    h+="</div>";
    if(gT.length){
      h+="<div class='tw'><table style='width:100%'><thead><tr>";
      h+="<th style='text-align:left;padding:6px 8px;font-size:11px;color:#6B7A99'>Matiere</th>";
      h+="<th style='text-align:center;padding:6px 8px;font-size:11px;color:#6B7A99'>Coef</th>";
      h+="<th style='text-align:center;padding:6px 8px;font-size:11px;color:#6B7A99'>Devoir 1</th>";
      h+="<th style='text-align:center;padding:6px 8px;font-size:11px;color:#6B7A99'>Devoir 2</th>";
      h+="<th style='text-align:center;padding:6px 8px;font-size:11px;color:#6B7A99;font-weight:700'>Moy.</th>";
      h+="</tr></thead><tbody>";
      gT.sort(function(a,b){return b.coef-a.coef;}).forEach(function(g){
        var mg=(g.n1+g.n2)/2;var col=mg>=10?"#059669":mg>=7?"#D97706":"#DC2626";
        h+="<tr style='border-bottom:1px solid #F0F4FF'>";
        h+="<td style='padding:7px 8px;font-size:12px;font-weight:600'>"+g.sub+"</td>";
        h+="<td style='text-align:center;padding:7px 8px;font-size:11px;color:#6B7A99'>"+g.coef+"</td>";
        h+="<td style='text-align:center;padding:7px 8px;font-size:13px'>"+g.n1.toFixed(1)+"</td>";
        h+="<td style='text-align:center;padding:7px 8px;font-size:13px'>"+g.n2.toFixed(1)+"</td>";
        h+="<td style='text-align:center;padding:7px 8px;font-family:Georgia,serif;font-size:14px;font-weight:700;color:"+col+"'>"+mg.toFixed(2)+"</td>";
        h+="</tr>";
      });
      h+="</tbody></table></div>";
    }else{h+="<div style='font-size:12px;color:#9CA3AF;text-align:center;padding:14px'>Aucune note pour ce trimestre</div>";}
    h+="</div>";
  });
  h+="<button class='btn bi' onclick=\"printBulletin('"+s.id+"','"+TRS[0]+"')\">🖨️ Imprimer bulletin</button>";
  return h;
}

// ── SOUMISSION RESSOURCES ──────────────────────────────────────────
function pgSubmitResource(){
  if(!SES)return "<div class='empty'><div class='empty-ico'>🔒</div>Connectez-vous pour soumettre</div>";
  var mats=["Mathematiques","Francais","Anglais","Physique-Chimie","SVT","Histoire-Geographie","Philosophie","Informatique","EPS","Arts"];
  var types=["Cours","Epreuve","Correction","Video","Fiche de revision","Exercices","Manuel"];
  var h="<div class='card'>";
  h+="<div class='ct mb14'>📤 Soumettre une ressource pedagogique</div>";
  h+="<div class='ib ibt mb14'><span>💡</span><span>Partagez vos cours, epreuves et corrections. Un administrateur les validera avant publication.</span></div>";
  h+="<div class='fg2'>";
  h+="<div class='fg'><span class='fl'>Titre *</span><input class='fi' id='srTitre' placeholder='Ex: Epreuve BEPC Maths 2024'></div>";
  h+="<div class='fg'><span class='fl'>Type *</span><select class='fi' id='srType'>";
  types.forEach(function(t){h+="<option>"+t+"</option>";});
  h+="</select></div>";
  h+="<div class='fg'><span class='fl'>Matiere *</span><select class='fi' id='srMat'>";
  mats.forEach(function(m){h+="<option>"+m+"</option>";});
  h+="</select></div>";
  h+="<div class='fg'><span class='fl'>Classe(s) *</span><select class='fi' id='srCls' multiple style='height:80px'>";
  CLS.forEach(function(cl){h+="<option>"+cl+"</option>";});
  h+="</select></div>";
  h+="<div class='fg full'><span class='fl'>Description</span><textarea class='fi' id='srDesc' rows='2'></textarea></div>";
  h+="<div class='fg'><span class='fl'>Prix FCFA (0=gratuit)</span><input class='fi' type='number' id='srPrix' value='0' min='0'></div>";
  h+="<div class='fg'><span class='fl'>Image de couverture (max 400Ko)</span>"
    +"<input type='file' class='fi' id='srCoverFile' accept='image/*' style='padding:6px' onchange=\"_uploadImage('srCoverFile',function(s){window._srCover=s;toast('Couverture chargee');},400)\"></div>";
  h+="<div class='fg full'><span class='fl'>Fichier principal (PDF, Word, PowerPoint, vidéo, image — max 20Mo)</span>"
    +"<input type='file' class='fi' id='srFile' accept='.pdf,.doc,.docx,.ppt,.pptx,video/*,image/*' style='padding:6px' onchange='_srLoadFile(this)'></div>";
  h+="<div id='srPreview' style='margin-top:8px'></div>";
  h+="<div class='fg full'><span class='fl'>Extrait gratuit (PDF ou texte, incite a l'achat)</span>"
    +"<textarea class='fi' id='srExtrait' rows='3' placeholder='Collez ici un extrait que les visiteurs peuvent lire gratuitement...'></textarea></div>";
  h+="</div><button class='btn bi mt14' onclick='_srSubmit()'>📤 Soumettre</button></div>";
  return h;
}
function _srLoadFile(inp){
  if(!inp.files[0])return;
  if(inp.files[0].size>20*1024*1024){toast("Max 20 Mo","warn");return;}
  toast("Chargement...");
  var r=new FileReader();
  r.onload=function(e){
    window._srFileSrc=e.target.result;window._srFileMime=inp.files[0].type;
    var prev=document.getElementById("srPreview");
    if(prev){
      if(inp.files[0].type.startsWith("image/")) _si('srPreview',"<img src='"+e.target.result+"' style='max-height:100px;border-radius:8px;margin-top:6px'>");
      else _si('srPreview',"<div style='background:#F0F4FF;border-radius:8px;padding:8px 12px;font-size:12px;margin-top:6px'>📄 "+inp.files[0].name+"</div>");
    }
    toast("Fichier charge");
  };
  r.readAsDataURL(inp.files[0]);
}
function _srSubmit(){
  var titre=(document.getElementById("srTitre")?.value||"").trim();
  var mat=document.getElementById("srMat")?.value||"";
  if(!titre||!mat){toast("Titre et matiere requis","warn");return;}
  if(!DB.elearning)DB.elearning=defaultDB().elearning;
  if(!DB.elearning.soumissions)DB.elearning.soumissions=[];
  var selCls=Array.from(document.querySelectorAll("#srCls option:checked")).map(function(o){return o.value;}).join(", ");
  DB.elearning.soumissions.push({
    id:"sub_"+Date.now(),
    titre:titre,type:document.getElementById("srType")?.value||"Cours",
    matiere:mat,classe:selCls||"Toutes classes",
    desc:document.getElementById("srDesc")?.value||"",
    prix:parseInt(document.getElementById("srPrix")?.value)||0,
    extrait:document.getElementById("srExtrait")?.value||"",
    src:window._srFileSrc||"",mime:window._srFileMime||"",
    cover:window._srCover||"",
    auteur:SES.pre+" "+SES.nom,
    date:new Date().toLocaleDateString("fr-FR"),statut:"En attente"
  });
  window._srFileSrc="";window._srFileMime="";window._srCover="";
  save();toast("Ressource soumise ! En attente de validation.");re();
}
function validerSoumission(id){
  try{
    if(!DB.elearning)DB.elearning=defaultDB().elearning;
    if(!DB.elearning.soumissions)DB.elearning.soumissions=[];
    if(!DB.elearning.contenus)DB.elearning.contenus=[];
    var sub=DB.elearning.soumissions.find(function(s){return s.id===id;});
    if(!sub){toast("Soumission '"+id+"' introuvable","warn");return;}
    sub.statut="Publie";
    var already=DB.elearning.contenus.find(function(c){return c.subId===id;});
    if(!already){
      DB.elearning.contenus.push({
        id:"el_"+Date.now()+"_"+Math.random().toString(36).slice(2),
        subId:id,titre:sub.titre,desc:sub.desc||"",
        type:sub.type,matiere:sub.matiere,classe:sub.classe,cat:"cat1",
        prix:sub.prix||0,gratuit:!sub.prix,auteur:sub.auteur||"",
        src:sub.src||"",mime:sub.mime||"",cover:sub.cover||"",extrait:sub.extrait||"",
        date:new Date().toLocaleDateString("fr-FR"),ico:"📄"
      });
    }
    save();re();toast("Ressource publiee avec succes");
  }catch(e){toast("Erreur: "+e.message,"warn");}
}
function pgSoumissions(){
  if(!iA())return "<div class='empty'><div class='empty-ico'>📥</div>Non admin</div>";
  var subs=(DB.elearning&&DB.elearning.soumissions)||[];
  var pending=subs.filter(function(s){return s.statut==="En attente";});
  var h="<div class='g2'><div class='card'>";
  h+="<div class='ct mb12'>📥 Soumissions de ressources ("+pending.length+" en attente)</div>";
  if(!subs.length){h+="<div class='empty'><div class='empty-ico'>📥</div>Aucune soumission</div>";}
  else{
    if(pending.length){
      h+="<div class='semi mb8' style='color:var(--wa)'>En attente de validation</div>";
      h+=pending.map(function(s){
        return "<div class='vcard mb8' style='border-left:4px solid var(--wa)'>"
          +"<div class='fl2 fsb fic'>"
          +"<div><div class='bold s'>"+s.titre+"</div>"
          +"<div class='xs2 mut'>"+s.type+" · "+s.matiere+" · "+s.date+"</div></div>"
          +"<div class='fl2 g6'>"
          +"<button class='btn bgr2 sm' onclick='validerSoumission(\""+s.id+"\")'>Publier</button>"
          +"<button class='btn br2 sm' onclick='_refuserSub(\""+s.id+"\")'>Refuser</button>"
          +"</div></div></div>";
      }).join("");
    }
  }
  h+="</div></div>";return h;
}
function _refuserSub(id){
  var sub=(DB.elearning&&DB.elearning.soumissions||[]).find(function(s){return s.id===id;});
  if(sub){sub.statut="Refuse";save();re();toast("Soumission refusee");}
}

