function toggleResGratuit(itemId){
  var el=DB.elearning||(DB.elearning=defaultDB().elearning);
  var item=(el.contenus||[]).find(function(c){return c.id===itemId;});
  if(!item) return;
  item.gratuit=!item.gratuit;
  if(item.gratuit){item.prix=0;}
  else if(!item.prix){item.prix=500;}
  save();re();
  toast(item.gratuit?'✅ Ressource rendue gratuite':'🔒 Ressource rendue payante');
}

function editResPlans(itemId){
  var el=DB.elearning||(DB.elearning=defaultDB().elearning);
  var item=(el.contenus||[]).find(function(c){return c.id===itemId;});
  if(!item) return;
  var plans=item.plans||[];
  var allPlans=[{id:'plan1',nom:'Examen'},{id:'plan2',nom:'Intermédiaire'},{id:'plan3',nom:'Enseignant'},{id:'plan4',nom:'Famille'}];
  var body='<div style="font-size:13px;margin-bottom:12px">Cochez les abonnements qui donnent accès à cette ressource :</div>';
  allPlans.forEach(function(p){
    var checked=plans.includes(p.id)?'checked':'';
    body+='<label style="display:block;padding:8px;margin:4px 0;background:#f8f8f8;border-radius:8px;cursor:pointer;font-size:14px"><input type="checkbox" id="rp_'+p.id+'" '+checked+' style="margin-right:8px">'+p.nom+'</label>';
  });
  body+='<div style="margin-top:12px"><label style="font-size:13px">Prix unitaire (FCFA) : <input type="number" id="rp_prix" value="'+(item.prix||0)+'" style="width:100px;padding:4px 8px;border:1px solid #ccc;border-radius:6px;margin-left:6px"></label></div>';
  M('⚙️ Plans d\u2019accès — '+_esc(item.titre),'',body,
    '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="saveResPlans(\''+itemId+'\')">✓ Enregistrer</button>');
}

function saveResPlans(itemId){
  var el=DB.elearning||(DB.elearning=defaultDB().elearning);
  var item=(el.contenus||[]).find(function(c){return c.id===itemId;});
  if(!item) return;
  var allPlans=['plan1','plan2','plan3','plan4'];
  item.plans=allPlans.filter(function(p){var cb=document.getElementById('rp_'+p);return cb&&cb.checked;});
  var px=parseInt(document.getElementById('rp_prix')?.value||'0');
  item.prix=Math.max(0,px);
  item.gratuit=(item.prix===0);
  save();cm();re();
  toast('✅ Plans et prix mis à jour');
}

// ═══ GESTION DES CITATIONS MOTIVANTES (admin) ═══
function mManageCitations(){
  if(!iA())return;
  if(!DB.citations)DB.citations=defaultDB().citations||[];
  var rows=DB.citations.map(function(c,i){
    return '<tr><td style="font-family:Georgia,serif;font-style:italic;font-size:13px;max-width:300px">\u00ab '+_esc(c.texte)+' \u00bb</td>'
      +'<td style="font-weight:600;font-size:13px;color:var(--gold2)">'+_esc(c.auteur)+'</td>'
      +'<td style="white-space:nowrap"><button class="btn br2 xs" data-ci="'+i+'" onclick="_citDel(this)">🗑</button></td></tr>';
  }).join('');
  M('💬 Citations Motivantes','Gérez les citations affichées sur le portail visiteur',
    '<table class="tbl"><thead><tr><th>Citation</th><th>Auteur</th><th></th></tr></thead><tbody>'+rows+'</tbody></table>'
    +'<div style="margin-top:16px;padding:16px;background:var(--bg2);border-radius:var(--r2)">'
    +'<div class="semi xs2 mb8">➕ Ajouter une citation</div>'
    +'<div class="fg mb8"><span class="fl">Citation</span><textarea class="fi" id="citTexte" rows="2" placeholder="Le texte de la citation..."></textarea></div>'
    +'<div class="fg mb8"><span class="fl">Auteur</span><input class="fi" id="citAuteur" placeholder="Nom de l\'auteur"></div>'
    +'<button class="btn bi sm" onclick="_citAdd()">➕ Ajouter</button>'
    +'</div>',
    '<button class="btn bo" onclick="cm()">Fermer</button>');
}
function _citAdd(){
  var t=(_ge('citTexte')?.value||'').trim();
  var a=(_ge('citAuteur')?.value||'').trim();
  if(!t||!a){toast('Citation et auteur requis','warn');return;}
  if(!DB.citations)DB.citations=[];
  DB.citations.push({texte:t,auteur:a});
  save();cm();setTimeout(mManageCitations,80);
  toast('✅ Citation ajoutée');
  _refreshCitation();
}
function _citDel(btn){
  var i=parseInt(btn.dataset.ci);
  if(isNaN(i)||!DB.citations)return;
  DB.citations.splice(i,1);save();cm();
  setTimeout(mManageCitations,80);
  toast('Citation supprimée');
  _refreshCitation();
}

