function lancerMotsCaches(){
  var mots=["MITOSE","NOYAU","ADN","CHLOROPHYLLE","ENZYME","RIBOSOME","CELLULOSE","OSMOSE"];
  var taille=8;
  function genGrille(){
    var g=[];for(var i=0;i<taille;i++){g.push([]);for(var j=0;j<taille;j++)g[i].push(String.fromCharCode(65+Math.floor(Math.random()*26)));}
    // Placer les mots horizontalement
    mots.forEach(function(m){
      if(m.length<=taille){
        var r=Math.floor(Math.random()*taille);var c=Math.floor(Math.random()*(taille-m.length+1));
        for(var k=0;k<m.length;k++)g[r][c+k]=m[k];
      }
    });
    return g;
  }
  var grille=genGrille();var trouves=[];
  function render(){
    var gHtml="<div style='display:inline-grid;grid-template-columns:repeat(8,36px);gap:2px;margin:0 auto 16px'>";
    grille.forEach(function(row){row.forEach(function(cell){gHtml+="<div style='width:36px;height:36px;background:#F0F4FF;border-radius:6px;display:flex;align-items:center;justify-content:center;font-family:monospace;font-size:14px;font-weight:700;color:#142554'>"+cell+"</div>";});});
    gHtml+="</div>";
    var motsList=mots.map(function(m){return "<span style='display:inline-block;padding:3px 10px;border-radius:20px;font-size:12px;font-weight:700;margin:3px;background:"+(trouves.includes(m)?"#D1FAE5;color:#059669;text-decoration:line-through":"#E8EEFF;color:#142554")+";'>"+m+"</span>";}).join("");
    _vc("<div class='vsec'><button class='back-btn' onclick='showJeuxEdu()'>← Jeux</button>"
      +"<div class='vsec-title'>🔬 Mots Caches Scientifiques</div>"
      +"<div class='vcard' style='text-align:center'>"
      +"<div style='overflow-x:auto;margin-bottom:14px'>"+gHtml+"</div>"
      +"<div style='margin-bottom:16px'>"+motsList+"</div>"
      +"<input id='motsAns' class='fi' style='max-width:240px;text-align:center;margin:0 auto 10px;text-transform:uppercase' placeholder='Tapez un mot trouve...'>"
      +"<div><button class='btn bi' onclick='_motsCheck()'>Valider</button></div>"
      +"<div id='motsFb' style='margin-top:10px;font-size:13px;min-height:20px'></div>"
      +"</div></div>");
  }
  window._motsCheck=function(){
    var ans=(document.getElementById("motsAns")?.value||"").trim().toUpperCase();
    var fb=document.getElementById("motsFb");
    if(mots.includes(ans)&&!trouves.includes(ans)){
      trouves.push(ans);if(fb)fb.innerHTML="<span style='color:#059669;font-weight:700'>✅ "+ans+" trouve !</span>";
      if(trouves.length===mots.length&&fb)fb.innerHTML="<span style='color:#059669;font-weight:800'>🎉 Tous les mots trouves !</span>";
    }else if(trouves.includes(ans)){if(fb)fb.innerHTML="<span style='color:#D97706'>Deja trouve !</span>";}
    else{if(fb)fb.innerHTML="<span style='color:#DC2626'>Ce mot n'est pas dans la liste.</span>";}
    document.getElementById("motsAns").value="";
    render();
  };
  render();
}

// ── QUIZ UNLOCK ────────────────────────────────────────────────────
function _quizIsUnlocked(key){
  if(typeof QUIZ_DB==="undefined"||!QUIZ_DB[key]||!QUIZ_DB[key].length)return false;
  var ql=typeof _getFullQuizList==="function"?_getFullQuizList():[];
  var q=ql.find(function(x){return x.key===key;});
  if(!q)return false;
  if(q.free)return true;
  if(!SES)return false;
  if(SES.type==="admin"||SES.type==="superadmin")return true;
  return typeof _hasPlan==="function"&&_hasPlan(q.plan||"premium");
}

function showEpreuves(){
  var mat=window._epMat||"";
  var classe=window._epClasse||"";
  var seq=window._epSeq||"";

  // Récupérer TOUTES les épreuves : EPREUVES_DB + librairie elearning (cat1,cat4,cat6) + épreuves admin
  var _hiddenEp=DB.hiddenEpreuves||[];
  var _purgedEp=DB.purgedEpreuves||[];
  function _isVisibleEp(id){return _hiddenEp.indexOf(id)<0&&_purgedEp.indexOf(id)<0;}
  // 1. EPREUVES_DB (épreuves intégrées, gérées via mManageEpreuves)
  var builtinEp=(typeof EPREUVES_DB!=="undefined"?EPREUVES_DB:[]).filter(function(e){
    return _isVisibleEp(e.id);
  });
  // 2. Librairie e-learning (cat1=épreuves, cat4=corpus, cat6=annales)
  var libEpreuves=(DB.elearningLibrary||[]).filter(function(e){
    return (e.cat==="cat1"||e.cat==="cat4"||e.cat==="cat6")&&_isVisibleEp(e.id);
  });
  // 3. Épreuves créées par l'admin (filtrées des purgées)
  var customEpreuves=(DB.customEpreuves||[]).filter(function(e){return _isVisibleEp(e.id);});
  // Fusionner sans doublons (priorité lib > builtin)
  var seenIds={};
  var allEpreuves=[];
  libEpreuves.forEach(function(e){if(!seenIds[e.id]){seenIds[e.id]=1;allEpreuves.push(e);}});
  builtinEp.forEach(function(e){if(!seenIds[e.id]){seenIds[e.id]=1;allEpreuves.push(e);}});
  customEpreuves.forEach(function(e){if(!seenIds[e.id]){seenIds[e.id]=1;allEpreuves.push(e);}});

  // Filtres
  var list=allEpreuves.filter(function(e){
    return (!mat||e.matiere===mat)&&(!classe||e.classe===classe)&&(!seq||e.seq===seq);
  });

  var mats=[...new Set(allEpreuves.map(function(e){return e.matiere||"";}).filter(Boolean))];
  var classes=[...new Set(allEpreuves.map(function(e){return e.classe||"";}).filter(Boolean))];
  var seqs=[...new Set(allEpreuves.map(function(e){return e.seq||"";}).filter(Boolean))].sort();

  var matSel=mats.map(function(m){
    var active=window._epMat===m;
    return "<button onclick=\"window._epMat='"+(active?"":m)+"';showEpreuves()\" style='padding:5px 14px;border-radius:20px;font-size:11px;font-weight:700;cursor:pointer;border:none;transition:.2s;background:"+(active?"#142554":"#E8EEFF")+";color:"+(active?"#fff":"#142554")+"'>"+m+"</button>";
  }).join("");

  var classSel=classes.map(function(c){
    var active=window._epClasse===c;
    return "<button onclick=\"window._epClasse='"+(active?"":c)+"';showEpreuves()\" style='padding:5px 14px;border-radius:20px;font-size:11px;font-weight:700;cursor:pointer;border:none;transition:.2s;background:"+(active?"#059669":"#E8F5E9")+";color:"+(active?"#fff":"#059669")+"'>"+c+"</button>";
  }).join("");

  var seqSel=seqs.map(function(s){
    var active=window._epSeq===s;
    return "<button onclick=\"window._epSeq='"+(active?"":s)+"';showEpreuves()\" style='padding:5px 14px;border-radius:20px;font-size:11px;font-weight:700;cursor:pointer;border:none;transition:.2s;background:"+(active?"#D97706":"#FFF8E1")+";color:"+(active?"#fff":"#D97706")+"'>"+s+"</button>";
  }).join("");

  var h="<div class='vsec'>";
  h+="<div class='vsec-title vsec-title-hero'>📝 Épreuves & Annales</div><div class='vsec-sub'>BEPC, Probatoire, BAC — sujets corrigés et fascicules officiels</div>";
  h+="<div class='vsec-sub'>Épreuves séquentielles, corpus, anciens sujets BEPC/Probatoire/BAC — tous niveaux</div>";

  // Bouton réinitialiser les filtres si au moins un filtre actif
  if(mat||classe||seq){
    h+="<div style='margin-bottom:12px'><button onclick=\"window._epMat='';window._epClasse='';window._epSeq='';showEpreuves()\" style='padding:5px 14px;border-radius:20px;font-size:11px;font-weight:700;cursor:pointer;border:1.5px solid #DC2626;background:#FEE2E2;color:#DC2626'>✕ Réinitialiser les filtres</button></div>";
  }

  // Filtres matières
  if(matSel){
    h+="<div style='margin-bottom:8px;font-size:12px;font-weight:700;color:#6B7A99;text-transform:uppercase;letter-spacing:.8px'>Matière</div>";
    h+="<div class='fl2 g6 mb10' style='flex-wrap:wrap'>"+matSel+"</div>";
  }

  // Filtres classes
  if(classSel){
    h+="<div style='margin-bottom:8px;font-size:12px;font-weight:700;color:#6B7A99;text-transform:uppercase;letter-spacing:.8px'>Classe / Série</div>";
    h+="<div class='fl2 g6 mb10' style='flex-wrap:wrap'>"+classSel+"</div>";
  }

  // Filtres séquences
  if(seqSel){
    h+="<div style='margin-bottom:8px;font-size:12px;font-weight:700;color:#6B7A99;text-transform:uppercase;letter-spacing:.8px'>Séquence</div>";
    h+="<div class='fl2 g6 mb14' style='flex-wrap:wrap'>"+seqSel+"</div>";
  }

  if(!list.length){
    h+="<div class='empty'><div class='empty-ico'>📝</div>Aucune épreuve pour ces critères</div>";
  } else {
    h+="<div style='font-size:12px;color:#6B7A99;margin-bottom:10px'>"+list.length+" épreuve"+(list.length>1?"s":"")+" trouvée"+(list.length>1?"s":"")+"</div>";
    h+="<div style='display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:14px'>";
    list.forEach(function(ep){
      var locked=!ep.gratuit&&!SES;
      var apercu=ep.apercu||ep.extrait||ep.desc||"";
      var badge=ep.gratuit?"GRATUIT":"PREMIUM";
      var badgeBg=ep.gratuit?"#D1FAE5":"#EDE9FE";
      var badgeColor=ep.gratuit?"#059669":"#7C3AED";
      h+="<div class='vcard' style='cursor:pointer;border-left:4px solid #142554' onclick='showEpreuveDetail(\""+ep.id+"\")'>";
      h+="<div class='fl2 fic fsb mb8'>";
      h+="<div><div style='font-family:Montserrat,sans-serif;font-size:13px;font-weight:800;color:#142554'>"+ep.titre+"</div>";
      h+="<div style='font-size:11px;color:#6B7A99;margin-top:2px'>"+(ep.classe?"🎓 "+ep.classe:"")+""+(ep.seq?" · <span style='color:#D97706;font-weight:700'>"+ep.seq+"</span>":"")+"</div></div>";
      h+="<span style='background:"+badgeBg+";color:"+badgeColor+";font-size:9px;font-weight:800;padding:3px 9px;border-radius:10px'>"+badge+"</span>";
      h+="</div>";
      if(apercu){
        h+="<div style='font-size:12px;color:#6B7A99;line-height:1.6;font-style:italic;margin-bottom:10px'>"+apercu.substring(0,100)+(apercu.length>100?"...":"")+"</div>";
      }
      h+="<button class='btn "+(ep.gratuit?"bi":"")+" sm' style='"+(ep.gratuit?"":"background:#EDE9FE;color:#7C3AED;")+";border-radius:10px;font-size:12px;font-weight:700' onclick='event.stopPropagation();showEpreuveDetail(\""+ep.id+"\")'>"+(locked?"🔒 Voir l'extrait":"📄 Lire l'épreuve")+"</button>";
      h+="</div>";
    });
    h+="</div>";
  }
  h+="</div>";
  _vc(h);
}

