// Formate le texte d'une épreuve en HTML structuré (détecte exercices, parties, sauts de ligne)
function _formatEpreuveContent(text){
  if(!text)return '<div style="text-align:center;padding:30px;color:#94A3B8;font-style:italic">Aucun contenu détaillé disponible pour cette épreuve.</div>';
  var t=String(text);
  // Échapper le HTML d'abord
  t=t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  // Détecter les titres de section (Exercice X, Partie X, EXERCICE, etc.)
  t=t.replace(/^(EXERCICE [IVX0-9]+|Exercice [0-9]+|PARTIE [IVX]+|Partie [IVX]+|Section [A-Z]|SECTION [A-Z]|Sujet [0-9]+|SUJET [0-9]+|DOSSIER [A-Z0-9]+|Dossier [A-Z0-9]+|Question [0-9]+|PRÉPARATION|DICTÉE|QUESTIONS|Texte ?:)([^\n]*)/gm,
    '<div style="background:#142554;color:#FFC93C;padding:8px 14px;border-radius:8px 8px 0 0;font-family:Montserrat,sans-serif;font-size:13px;font-weight:800;margin:18px 0 0">$1$2</div>');
  // Sauts de ligne en paragraphes
  var lines=t.split(/\n/);
  var html='';
  var inSection=false;
  lines.forEach(function(line){
    line=line.trim();
    if(!line){html+='<div style="height:6px"></div>';return;}
    if(line.indexOf('<div style="background:#142554')>=0){
      // Titre de section déjà formaté
      html+=line;
      inSection=true;
    } else {
      html+='<div style="font-family:Georgia,serif;font-size:13.5px;line-height:1.85;color:#1F2937;padding:6px 14px'+(inSection?';background:#FAFBFF;border-left:3px solid #142554':'')+'">'+line+'</div>';
    }
  });
  return '<div style="margin:14px 0">'+html+'</div>';
}

// Générateur de QR code (Promise → data URL PNG)
function _generateQRDataUrl(text, size){
  size = size || 120;
  return new Promise(function(resolve){
    if(typeof QRCode==='undefined'){resolve(null);return;}
    try{
      var div=document.createElement('div');
      div.style.cssText='position:absolute;left:-9999px;top:0';
      document.body.appendChild(div);
      new QRCode(div,{text:text,width:size,height:size,colorDark:'#142554',colorLight:'#FFFFFF',correctLevel:QRCode.CorrectLevel.M});
      setTimeout(function(){
        var canvas=div.querySelector('canvas');
        var img=div.querySelector('img');
        var url=null;
        if(canvas){try{url=canvas.toDataURL('image/png');}catch(e){}}
        if(!url && img){url=img.src;}
        document.body.removeChild(div);
        resolve(url);
      },150);
    }catch(e){resolve(null);}
  });
}

// Téléchargement de l'épreuve courante en PDF avec filigrane subtil + date + QR
async function _downloadEpreuvePDF(){
  var ep=window._currentEpreuve;
  if(!ep){toast('Épreuve non chargée','warn');return;}
  var jsPDFCls=(typeof jspdf!=='undefined'&&jspdf.jsPDF)?jspdf.jsPDF:(typeof jsPDF!=='undefined'?jsPDF:null);
  if(!jsPDFCls){toast('jsPDF non disponible — réessayez dans quelques secondes','warn');return;}
  toast('📥 Génération du PDF en cours…','info');
  try{
    var doc=new jsPDFCls({orientation:'portrait',unit:'mm',format:'a4'});
    var pw=210,ph=297,margin=18;
    var y=margin;
    var school=DB.school||{};
    var schoolNom=school.nom||'VÉRITAS Academy';
    // Pré-générer le QR code pour le pied de page de la dernière page
    var qrText='https://veritas-school.com/?ref='+(ep.id||'ep')+'&t='+Date.now();
    var qrDataUrl=null;
    try{qrDataUrl=await _generateQRDataUrl(qrText,150);}catch(eq){qrDataUrl=null;}
    var downloadDate=new Date().toLocaleString('fr-FR',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'});
    // En-tête couleur
    doc.setFillColor(20,37,84);doc.rect(0,0,pw,28,'F');
    doc.setTextColor(255,201,60);doc.setFont(undefined,'bold');doc.setFontSize(15);
    doc.text(schoolNom,pw/2,12,{align:'center'});
    doc.setFontSize(9);doc.setFont(undefined,'normal');doc.setTextColor(255,255,255);
    doc.text(school.slogan||'Centre d\'Excellence Scolaire',pw/2,18,{align:'center'});
    doc.text((school.ville||'Yaoundé, Cameroun')+' · MINESEC '+new Date().getFullYear(),pw/2,23,{align:'center'});
    y=36;
    // Métadonnées
    doc.setTextColor(20,37,84);doc.setFont(undefined,'bold');doc.setFontSize(11);
    var metaLine=[];
    if(ep.classe)metaLine.push('Classe : '+ep.classe);
    if(ep.matiere)metaLine.push('Matière : '+ep.matiere);
    if(ep.seq)metaLine.push('Séquence : '+ep.seq);
    if(ep.duree)metaLine.push('Durée : '+ep.duree+' min');
    doc.text(metaLine.join('  ·  '),pw/2,y,{align:'center'});
    y+=10;
    // Titre épreuve
    doc.setFont(undefined,'bold');doc.setFontSize(16);doc.setTextColor(20,37,84);
    var titleLines=doc.splitTextToSize(ep.titre||'Épreuve',pw-2*margin);
    titleLines.forEach(function(l){doc.text(l,pw/2,y,{align:'center'});y+=7;});
    y+=2;
    // Description italique
    if(ep.desc){
      doc.setFont(undefined,'italic');doc.setFontSize(10);doc.setTextColor(107,122,153);
      var descLines=doc.splitTextToSize(ep.desc,pw-2*margin);
      descLines.forEach(function(l){doc.text(l,pw/2,y,{align:'center'});y+=5;});
    }
    // Séparateur élégant
    y+=4;doc.setDrawColor(20,37,84);doc.setLineWidth(0.5);doc.line(margin,y,pw-margin,y);y+=8;
    // Contenu
    doc.setFont(undefined,'normal');doc.setFontSize(11);doc.setTextColor(31,41,55);
    var contentText=ep.apercu||ep.extrait||ep.desc||'(Aucun contenu détaillé)';
    var contentLines=doc.splitTextToSize(contentText,pw-2*margin);
    contentLines.forEach(function(line){
      if(y>ph-margin-15){doc.addPage();y=margin;}
      if(/^(EXERCICE|Exercice |PARTIE|Partie |Section|SUJET|Sujet|DOSSIER|Dossier|QUESTIONS|DICTÉE|PRÉPARATION)/.test(line)){
        doc.setFillColor(20,37,84);
        doc.rect(margin-2,y-4,pw-2*margin+4,7,'F');
        doc.setTextColor(255,201,60);doc.setFont(undefined,'bold');
        doc.text(line,margin,y+1);
        doc.setTextColor(31,41,55);doc.setFont(undefined,'normal');
        y+=8;
      } else {
        doc.text(line,margin,y);
        y+=5.5;
      }
    });
    var totalPages=doc.internal.getNumberOfPages();
    // ── FILIGRANE SUBTIL sur chaque page (diagonale, très léger) ──
    for(var p=1;p<=totalPages;p++){
      doc.setPage(p);
      // Filigrane diagonal "VÉRITAS" repeated grid — très transparent
      doc.saveGraphicsState&&doc.saveGraphicsState();
      doc.setFont(undefined,'bold');doc.setFontSize(56);
      // Couleur grise très claire (R,G,B proche du blanc)
      doc.setTextColor(230,234,242);
      // 3 positions diagonales pour couvrir la page
      [[35,120],[105,170],[170,220]].forEach(function(pos){
        doc.text('VÉRITAS',pos[0],pos[1],{angle:30});
      });
      doc.restoreGraphicsState&&doc.restoreGraphicsState();

      // Re-définir couleurs/font pour les éléments de pied de page
      doc.setFont(undefined,'italic');doc.setFontSize(7);doc.setTextColor(150,160,180);
      // Pied de page : copyright + pagination
      doc.text('© '+new Date().getFullYear()+' '+schoolNom+' — Usage pédagogique uniquement',pw/2,ph-6,{align:'center'});
      doc.text('Page '+p+'/'+totalPages,pw-margin,ph-6,{align:'right'});
      doc.text(downloadDate,margin,ph-6);
    }
    // ── QR CODE + DATE sur la DERNIÈRE page (subtil, en bas à droite) ──
    if(qrDataUrl){
      try{
        doc.setPage(totalPages);
        var qrSize=22;
        var qrX=pw-margin-qrSize;
        var qrY=ph-margin-qrSize-5;
        // Encadré léger autour du QR
        doc.setDrawColor(220,225,235);doc.setLineWidth(0.2);
        doc.rect(qrX-1,qrY-1,qrSize+2,qrSize+2);
        // Insérer le QR
        doc.addImage(qrDataUrl,'PNG',qrX,qrY,qrSize,qrSize);
        // Légende sous le QR (très petite)
        doc.setFontSize(6);doc.setTextColor(120,135,160);doc.setFont(undefined,'normal');
        doc.text('Scanner pour',qrX+qrSize/2,qrY+qrSize+2.5,{align:'center'});
        doc.text('veritas-school.com',qrX+qrSize/2,qrY+qrSize+5,{align:'center'});
        // Date détaillée à gauche du QR
        doc.setFontSize(7);doc.setTextColor(150,160,180);doc.setFont(undefined,'italic');
        doc.text('Téléchargé le '+downloadDate,margin,ph-margin-8);
        doc.text('Document authentique '+schoolNom,margin,ph-margin-4);
      }catch(eQR){console.warn('[PDF] QR injection failed:',eQR);}
    }
    var safeName=(ep.titre||'epreuve').replace(/[^a-zA-Z0-9_-]+/g,'_').substring(0,60);
    doc.save(safeName+'_VERITAS.pdf');
    toast('✅ PDF téléchargé : '+safeName+'.pdf');
  }catch(e){
    console.error('[PDF] erreur:',e);
    toast('❌ Erreur génération PDF : '+e.message,'err');
  }
}

// ── SIMULATEUR D'EXAMEN ───────────────────────────────────────────
function _simulerExamen(epId){
  var libEpreuves=(DB.elearningLibrary||[]).filter(function(e){return e.cat==="cat1"||e.cat==="cat4"||e.cat==="cat6";});
  var ep=libEpreuves.concat(DB.customEpreuves||[]).find(function(e){return e.id===epId;});
  if(!ep)return;
  var duree=ep.duree||60;
  cm();
  var totalSec=ep.duree*60;
  var elapsed=0;
  var timer=null;
  
  function renderTimer(){
    var remaining=totalSec-elapsed;
    var mn=Math.floor(remaining/60);
    var sc=remaining%60;
    var pct=Math.round((elapsed/totalSec)*100);
    var col=remaining<600?"#DC2626":remaining<1800?"#D97706":"#059669";
    
    _vc(
      "<div class='vsec'>"
      +"<div style='background:linear-gradient(135deg,#0F172A,#1E3A8A);border-radius:18px;padding:24px;color:#fff;margin-bottom:20px'>"
      +"<div class='fl2 fic fsb mb12'>"
      +"<div style='font-family:Montserrat,sans-serif;font-size:15px;font-weight:800'>⏱️ "+ep.titre+"</div>"
      +"<button onclick='_stopTimer()' style='background:rgba(220,38,38,.2);color:#FCA5A5;border:none;border-radius:10px;padding:6px 14px;font-size:12px;font-weight:700;cursor:pointer'>■ Arrêter</button>"
      +"</div>"
      +"<div style='text-align:center;padding:20px 0'>"
      +"<div style='font-family:monospace;font-size:56px;font-weight:900;color:"+col+";letter-spacing:4px'>"+String(mn).padStart(2,'0')+":"+String(sc).padStart(2,'0')+"</div>"
      +"<div style='font-size:12px;color:rgba(255,255,255,.5);margin-top:6px'>"+mn+" min "+sc+" sec restantes</div>"
      +"</div>"
      +"<div style='background:rgba(255,255,255,.1);border-radius:20px;height:8px;overflow:hidden'>"
      +"<div style='background:"+col+";height:100%;width:"+pct+"%;border-radius:20px;transition:width .5s'></div>"
      +"</div>"
      +"<div style='font-size:11px;color:rgba(255,255,255,.4);text-align:right;margin-top:4px'>"+pct+"% écoulé</div>"
      +"</div>"
      +"<div class='card'>"
      +"<div class='ct mb12'>📝 Composition en cours</div>"
      +"<div class='ib ibt mb10'><span>💡</span><span>Traitez l'épreuve sur papier. Ce chronomètre reproduit les conditions réelles de l'examen.</span></div>"
      +"<textarea id='simNotes' class='fi' rows='8' placeholder='Notez ici vos brouillons, formules importantes, plan de rédaction...' style='font-family:Georgia,serif;font-size:13px'></textarea>"
      +"</div>"
      +"</div>");
    
    if(remaining<=0){
      clearInterval(timer);
      _vc(
        "<div class='vsec'><div class='vcard' style='text-align:center;padding:40px'>"
        +"<div style='font-size:56px;margin-bottom:16px'>⏰</div>"
        +"<div style='font-family:Montserrat,sans-serif;font-size:22px;font-weight:800;color:#DC2626;margin-bottom:8px'>Temps écoulé !</div>"
        +"<div style='font-size:14px;color:#6B7A99;margin-bottom:20px'>La session de "+ep.duree+" minutes est terminée.</div>"
        +"<button class='btn bi' onclick='showEpreuves()'>← Retour aux épreuves</button>"
        +"</div></div>");
    }
  }
  
  window._stopTimer=function(){clearInterval(timer);showEpreuves();};
  timer=setInterval(function(){elapsed++;renderTimer();},1000);
  renderTimer();
}

