// (fonctions showLabosVirtuels/lancerLabo/saveLaboNote v1 supprimées — remplacées par versions enrichies ci-dessous)
// ── SECTION ELEARNING AMÉLIORÉE — ONGLET ÉPREUVES + LABOS ────────
// Patcher vShowSec pour exposer les épreuves et labos dans elearning
var _origVShowSecEl=window.vShowSec;
(function(){
  var _ov=window.vShowSec;
  window.vShowSec=function(sec,btn){
    if(sec!=="epreuves"){
      // Réinitialiser les filtres épreuves quand on navigue ailleurs
      window._epMat='';window._epClasse='';window._epSeq='';
    }
    if(sec==="epreuves"){
      document.querySelectorAll(".vnav-btn").forEach(function(b){b.classList.remove("on");});
      if(btn)btn.classList.add("on");
      showEpreuves();return;
    }
    if(sec==="labos"){
      document.querySelectorAll(".vnav-btn").forEach(function(b){b.classList.remove("on");});
      if(btn)btn.classList.add("on");
      showLabosVirtuels();return;
    }
    if(_ov) _ov.call(this,sec,btn);
  };
})();
