    // Onglets
    h+="<div class='fl2 g8 mb16'>";
    [{k:"theorie",l:"📖 Théorie"},{k:"experience",l:"🔬 Expérience"},{k:"quiz",l:"🧠 Quiz"},{k:"notes",l:"📓 Notes"}].forEach(function(tab){
      var active=window._laboTab===tab.k||((!window._laboTab)&&tab.k==="theorie");
      h+="<button onclick=\"window._laboTab='"+tab.k+"';window._laboQIdx=0;window._laboScore=0;_lancerLaboComplet(window._laboDBItem)\" style='padding:9px 18px;border-radius:20px;font-size:12px;font-weight:700;cursor:pointer;border:none;transition:.2s;background:"+(active?"#142554":"#F0F4FF")+";color:"+(active?"#fff":"#142554")+"'>"+tab.l+"</button>";
    });
