      h+="<button id='simPlayBtn' onclick='_simToggle()' style='background:rgba(255,255,255,.12);border:none;color:#FFC93C;border-radius:8px;padding:5px 12px;font-size:11px;font-weight:700;cursor:pointer'>⏸ Pause</button>";
      h+="<button onclick='_simReset()' style='background:rgba(255,255,255,.08);border:none;color:#fff;border-radius:8px;padding:5px 12px;font-size:11px;font-weight:700;cursor:pointer'>🔄 Reset</button>";
