// ── GESTIONNAIRE COACHING ──────────────────────────────────────────
function mManageCoaching(){
  if(!iA())return;
  // Charger les offres depuis DB ou défaut
  if(!DB.coachingPacks) DB.coachingPacks=_DEFAULT_COACHING_PACKS();
  var packs=DB.coachingPacks;
  var rows=packs.map(function(p,i){
    return "<tr>"
      +"<td style='padding:6px 8px;font-size:22px'>"+p.ico+"</td>"
      +"<td style='padding:6px 8px'><strong style='font-size:13px'>"+p.nom+"</strong><br><span style='font-size:11px;color:var(--ink4)'>"+p.desc.substring(0,60)+"...</span></td>"
      +"<td style='padding:6px 8px;font-size:13px;font-weight:700;color:var(--gold2)'>"+p.prix+" FCFA</td>"
      +"<td style='padding:6px 8px;font-size:11px'>"+p.duree+"</td>"
      +"<td style='padding:6px 8px;white-space:nowrap'>"
      +"<button class='btn bo xs' onclick='_editCoach("+i+")'>✏️</button> "
      +"<button class='btn br2 xs' onclick='_delCoach("+i+")'>🗑</button>"
      +"</td></tr>";
  }).join("");
  M("🎯 Gérer le Coaching","Ajoutez, modifiez et supprimez les offres d'accompagnement",
    "<div class='ib ibt mb12'><span>💡</span><span>Ces offres apparaissent dans la section Orientation → Coaching & Accompagnement.</span></div>"
    +(rows?"<div class='tw mb12' style='max-height:220px;overflow-y:auto'><table style='width:100%'><thead><tr style='background:var(--bg2)'><th></th><th style='text-align:left;padding:6px 8px'>Offre</th><th style='padding:6px 8px'>Prix</th><th style='padding:6px 8px'>Durée</th><th></th></tr></thead><tbody>"+rows+"</tbody></table></div>"
          :"<div class='empty mb12'><div class='empty-ico'>🎯</div>Aucune offre</div>")
    +"<button class='btn bi sm' onclick='_newCoach()'>➕ Nouvelle offre</button>",
    "<button class='btn bo' onclick='cm()'>Fermer</button>",true);
}
function _DEFAULT_COACHING_PACKS(){
  return[
    {ico:"🎯",nom:"Coaching Scolaire",desc:"Suivi personnalisé hebdomadaire, bilan de compétences, plan de progression adapté",prix:"25 000",duree:"Mensuel",color:"#1E3A8A"},
    {ico:"🧠",nom:"Développement Personnel",desc:"Confiance en soi, gestion du stress, techniques de mémorisation efficaces",prix:"20 000",duree:"Mensuel",color:"#7C3AED"},
    {ico:"📅",nom:"Emploi du Temps",desc:"Élaboration d'un planning optimisé et gestion des priorités scolaires",prix:"10 000",duree:"Session",color:"#059669"},
    {ico:"😰",nom:"Gestion du Stress",desc:"Accompagnement psychologique, relaxation et préparation mentale aux examens",prix:"15 000",duree:"Mensuel",color:"#DC2626"},
    {ico:"📚",nom:"Remédiation Scolaire",desc:"Soutien intensif dans les matières en difficulté, exercices corrigés",prix:"30 000",duree:"Mensuel",color:"#D97706"},
    {ico:"🏆",nom:"Préparation Examens",desc:"Pack intensif BEPC/BAC: épreuves blanches, corrections, stratégies de réussite",prix:"35 000",duree:"Trimestriel",color:"#0891B2"},
    {ico:"👨‍👩‍👧",nom:"Accompagnement Parents",desc:"Guide pratique pour suivre la scolarité et motiver votre enfant",prix:"12 000",duree:"Mensuel",color:"#BE185D"},
    {ico:"💻",nom:"Tutorat en Ligne",desc:"Séances individuelles en visioconférence avec un enseignant spécialisé",prix:"18 000",duree:"Mensuel",color:"#4C1D95"},
  ];
}
function _newCoach(){window._editCoachIdx=-1;_coachFormUI(null);}
function _editCoach(i){window._editCoachIdx=i;_coachFormUI(DB.coachingPacks[i]);}
function _delCoach(i){
  if(!confirm("Supprimer cette offre ?"))return;
  DB.coachingPacks.splice(i,1);save();cm();setTimeout(mManageCoaching,80);toast("Offre supprimée");
}
function _coachFormUI(p){
  M(p?"✏️ Modifier l'offre":"➕ Nouvelle offre de coaching","",
    "<div class='fg2'>"
    +"<div class='fg'><span class='fl'>Icône / Emoji *</span><input class='fi' id='cfIco' value='"+(p?p.ico:"🎯")+"'></div>"
    +"<div class='fg'><span class='fl'>Nom *</span><input class='fi' id='cfNom' value='"+(p?p.nom:"")+"' placeholder='Coaching Scolaire'></div>"
    +"<div class='fg full'><span class='fl'>Description *</span><textarea class='fi' id='cfDesc' rows='3' placeholder='Description de l&#39;offre...'>"+( p?p.desc:"")+"</textarea></div>"
    +"<div class='fg'><span class='fl'>Prix FCFA *</span><input class='fi' id='cfPrix' value='"+(p?p.prix:"")+"' placeholder='25 000'></div>"
    +"<div class='fg'><span class='fl'>Durée</span><select class='fi' id='cfDuree'>"
    +"<option value='Mensuel'"+(p&&p.duree==="Mensuel"?" selected":"")+" >Mensuel</option>"
    +"<option value='Trimestriel'"+(p&&p.duree==="Trimestriel"?" selected":"")+" >Trimestriel</option>"
    +"<option value='Semestriel'"+(p&&p.duree==="Semestriel"?" selected":"")+" >Semestriel</option>"
    +"<option value='Session'"+(p&&p.duree==="Session"?" selected":"")+" >Session unique</option>"
    +"<option value='Annuel'"+(p&&p.duree==="Annuel"?" selected":"")+" >Annuel</option>"
    +"</select></div>"
    +"<div class='fg'><span class='fl'>Couleur</span><input type='color' class='fi' id='cfColor' value='"+(p?p.color:"#142554")+"' style='height:38px'></div>"
    +"</div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn bi' onclick='_saveCoach()'>"+( p?"Modifier":"Créer")+"</button>",true);
}
function _saveCoach(){
  var ico=document.getElementById("cfIco")?.value.trim()||"🎯";
  var nom=document.getElementById("cfNom")?.value.trim()||"";
  var desc=document.getElementById("cfDesc")?.value.trim()||"";
  var prix=document.getElementById("cfPrix")?.value.trim()||"";
  if(!nom||!prix){toast("Nom et prix requis","warn");return;}
  if(!DB.coachingPacks)DB.coachingPacks=[];
  var pack={ico:ico,nom:nom,desc:desc,prix:prix,
    duree:document.getElementById("cfDuree")?.value||"Mensuel",
    color:document.getElementById("cfColor")?.value||"#142554"};
  if(window._editCoachIdx>=0) DB.coachingPacks[window._editCoachIdx]=pack;
  else DB.coachingPacks.push(pack);
  save();cm();toast(window._editCoachIdx>=0?"✅ Offre modifiée":"✅ Offre créée");
  setTimeout(mManageCoaching,80);
}

// ── GESTIONNAIRE ÉPREUVES ──────────────────────────────────────────
function mManageEpreuves(){
  if(!iA())return;
  if(!DB.customEpreuves)DB.customEpreuves=[];
  // Fusionner épreuves par défaut + épreuves admin (en filtrant les purgées)
  var _purgedE=DB.purgedEpreuves||[];
  var _builtinFiltered=(typeof EPREUVES_DB!=="undefined"?EPREUVES_DB.filter(function(e){return _purgedE.indexOf(e.id)<0;}):[]);
  var _customFiltered=(DB.customEpreuves||[]).filter(function(e){return _purgedE.indexOf(e.id)<0;});
  var all=_builtinFiltered.concat(_customFiltered);
  var _builtinFilteredLen=_builtinFiltered.length;
  var fmtColors={html:'#059669',pdf:'#DC2626',word:'#2563EB',url:'#7C3AED'};
  var rows=all.map(function(ep,i){
    var isCustom=i>=_builtinFilteredLen;
    var fmt=ep.format||((ep.externalUrl||ep.htmlLocal||ep.idbKey)?'html':'');
    var fmtBadge=fmt?"<span style='background:"+(fmtColors[fmt]||'#6b7280')+";color:#fff;font-size:8px;font-weight:800;padding:1px 5px;border-radius:4px;margin-left:4px'>"+fmt.toUpperCase()+"</span>":"";
    var hasFile=ep.externalUrl||ep.htmlLocal||ep.idbKey;
    return "<tr style='border-bottom:1px solid var(--bg3)'>"
      +"<td style='padding:6px 8px;font-size:12px'>"
        +"<div style='display:flex;align-items:center;gap:4px'><strong>"+_esc(ep.titre)+"</strong>"+fmtBadge+"</div>"
        +"<div style='font-size:10px;color:var(--ink4)'>"+_esc(ep.exam||'')+(ep.serie?" "+_esc(ep.serie):"")+(ep.annee?" · "+ep.annee:"")+"</div>"
      +"</td>"
      +"<td style='padding:6px 8px;font-size:11px'>"+_esc(ep.matiere||'')+"</td>"
      +"<td style='padding:6px 8px;font-size:11px'>"+(ep.gratuit?"<span style='color:#059669;font-weight:700'>Gratuit</span>":"<span style='color:#7C3AED'>Premium</span>")+"</td>"
      +(hasFile?"<td style='padding:6px 8px'><button class='btn bi xs' onclick='_openRessource(\""+ep.id+"\")' style='padding:3px 7px;font-size:10px'>👁</button></td>":"<td></td>")
      +"<td style='padding:6px 8px;white-space:nowrap'>"
        +(isCustom
          ?"<button class='btn bo xs' onclick='_editEpById(\""+ep.id+"\")' style='margin-right:3px'>✏️</button>"
            +"<button class='btn br2 xs' onclick='_delEpById(\""+ep.id+"\")' style='margin-right:3px'>🗑</button>"
            +"<button class='btn xs' style='background:#7F1D1D;color:#fff;font-size:10px' onclick='_purgeEpreuve(\""+ep.id+"\",true)'>🚫 Purger</button>"
          :((DB.hiddenEpreuves||[]).indexOf(ep.id)>=0
            ?"<button class='btn bgr2 xs' onclick='_restoreEpreuve(\""+ep.id+"\")' style='font-size:10px;margin-right:3px'>↩ Restaurer</button>"
              +"<button class='btn xs' style='background:#7F1D1D;color:#fff;font-size:10px' onclick='_purgeEpreuve(\""+ep.id+"\")'>🚫 Purger</button>"
            :"<button class='btn br2 xs' onclick='_hideBuiltinEp(\""+ep.id+"\")' style='font-size:10px;margin-right:3px'>🗑 Supprimer</button>"
              +"<button class='btn xs' style='background:#7F1D1D;color:#fff;font-size:10px' onclick='_purgeEpreuve(\""+ep.id+"\")'>🚫 Purger</button>"
          )
        )
      +"</td></tr>";
  }).join("");
  M("📝 Gérer les Épreuves","Ajoutez et gérez les épreuves officielles",
    "<div class='ib ibt mb12'><span>📝</span><span>🗑 Supprimer = masquer (restaurable). 🚫 Purger = suppression définitive (irréversible).</span></div>"
    +(_purgedE.length?"<div class='ib' style='background:#FEE2E2;color:#7F1D1D;border-radius:8px;padding:8px 12px;font-size:11px;margin-bottom:10px'>🚫 "+_purgedE.length+" épreuve(s) purgée(s) définitivement</div>":"")
    +"<div class='tw mb12' style='max-height:240px;overflow-y:auto'><table style='width:100%'><thead><tr style='background:var(--bg2)'><th style='text-align:left;padding:6px 8px'>Titre</th><th>Matière</th><th>Accès</th><th></th><th></th></tr></thead><tbody>"+rows+"</tbody></table></div>"
    +"<div class='fl2 g8 fw mt10'>"
    +"<button class='btn bi sm' onclick='_newEp()'>➕ Saisir une épreuve</button>"
    +"<button class='btn sm' style='background:#7C3AED;color:#fff' onclick='_importRessourceMulti()'>📥 Importer (HTML · PDF · Word)</button>"
    +"<button class='btn sm' style='background:#DC2626;color:#fff' onclick='_deleteAllBuiltinEp()'>🗑 Supprimer toutes les épreuves par défaut</button>"
    +"<button class='btn sm' style='background:#059669;color:#fff' onclick='_restoreAllEpreuves()'>↩ Tout restaurer</button>"
    +(_purgedE.length?"<button class='btn sm' style='background:#7F1D1D;color:#fff' onclick='_unpurgeAllEpreuves()'>↩ Annuler les purges ("+_purgedE.length+")</button>":"")
    +"</div>",
    "<button class='btn bo' onclick='cm()'>Fermer</button>",true);
}
// ── Épreuves : helpers par ID (robustes au filtrage) ─────────────
function _editEpById(id){
  var idx=(DB.customEpreuves||[]).findIndex(function(e){return e.id===id;});
  if(idx<0){toast("Épreuve par défaut non modifiable","warn");return;}
  window._editEpIdx=idx;
  _epFormUI(DB.customEpreuves[idx]);
}
function _delEpById(id){
  if(!confirm("Supprimer cette épreuve ?"))return;
  if(DB.customEpreuves)DB.customEpreuves=DB.customEpreuves.filter(function(e){return e.id!==id;});
  save();cm();setTimeout(mManageEpreuves,80);toast("Épreuve supprimée");
}
// ── PURGE ÉPREUVE (suppression définitive) ──
function _purgeEpreuve(id,isCustom){
  var ep=(typeof EPREUVES_DB!=="undefined"?EPREUVES_DB.find(function(x){return x.id===id;}):null)
    ||(DB.customEpreuves||[]).find(function(x){return x.id===id;});
  if(!ep){toast('Épreuve introuvable','warn');return;}
  if(!_confirmPurge('Épreuve : '+ep.titre+(ep.matiere?' ('+ep.matiere+')':'')))return;
  DB.purgedEpreuves=DB.purgedEpreuves||[];
  if(DB.purgedEpreuves.indexOf(id)<0)DB.purgedEpreuves.push(id);
  if(isCustom&&DB.customEpreuves){
    DB.customEpreuves=DB.customEpreuves.filter(function(x){return x.id!==id;});
  }
  save();cm();setTimeout(mManageEpreuves,80);toast('🚫 Épreuve purgée définitivement');
}
function _unpurgeAllEpreuves(){
  if(!confirm("Annuler toutes les purges d'épreuves et les restaurer dans l'admin ?"))return;
  DB.purgedEpreuves=[];
  save();cm();setTimeout(mManageEpreuves,80);toast('✅ Purges annulées');
}
function _hideBuiltinEp(id){
  if(!confirm('Supprimer cette épreuve ? Elle n\'apparaîtra plus aux visiteurs.\n\nVous pourrez la restaurer depuis ce même panneau.'))return;
  DB.hiddenEpreuves=DB.hiddenEpreuves||[];
  if(DB.hiddenEpreuves.indexOf(id)<0)DB.hiddenEpreuves.push(id);
  save();cm();setTimeout(mManageEpreuves,80);toast('✅ Épreuve supprimée');
}
function _restoreEpreuve(id){
  DB.hiddenEpreuves=(DB.hiddenEpreuves||[]).filter(function(x){return x!==id;});
  save();cm();setTimeout(mManageEpreuves,80);toast('✅ Épreuve restaurée');
}
function _deleteAllBuiltinEp(){
  if(!confirm('Supprimer TOUTES les épreuves par défaut ?\n\nElles seront masquées et ne s\'afficheront plus. Restauration possible depuis ce panneau.'))return;
  var all=(typeof EPREUVES_DB!=="undefined"?EPREUVES_DB:[]);
  DB.hiddenEpreuves=all.map(function(e){return e.id;});
  save();cm();setTimeout(mManageEpreuves,80);toast('✅ Toutes les épreuves par défaut supprimées');
}
function _restoreAllEpreuves(){
  DB.hiddenEpreuves=[];
  save();cm();setTimeout(mManageEpreuves,80);toast('✅ Toutes les épreuves restaurées');
}
function _newEp(){window._editEpIdx=-1;_epFormUI(null);}
function _editEp(globalIdx){
  var base=(typeof EPREUVES_DB!=="undefined"?EPREUVES_DB.length:0);
  var localIdx=globalIdx-base;
  if(localIdx<0){toast("Épreuve par défaut non modifiable","warn");return;}
  window._editEpIdx=localIdx;
  _epFormUI((DB.customEpreuves||[])[localIdx]);
}
function _delEp(localIdx){
  if(!confirm("Supprimer cette épreuve ?"))return;
  if(DB.customEpreuves)DB.customEpreuves.splice(localIdx,1);
  save();cm();setTimeout(mManageEpreuves,80);toast("Épreuve supprimée");
}
function _epFormUI(ep){
  M(ep?"✏️ Modifier l'épreuve":"➕ Nouvelle épreuve","",
    "<div class='fg2'>"
    +"<div class='fg full'><span class='fl'>Titre *</span><input class='fi' id='epTitre' value='"+(ep?ep.titre:"")+"' placeholder='BEPC 2025 — Mathématiques'></div>"
    +"<div class='fg'><span class='fl'>Examen *</span><select class='fi' id='epExam'>"
    +"<option value='BEPC'"+(ep&&ep.exam==="BEPC"?" selected":"")+" >BEPC</option>"
    +"<option value='Probatoire'"+(ep&&ep.exam==="Probatoire"?" selected":"")+" >Probatoire</option>"
    +"<option value='BAC'"+(ep&&ep.exam==="BAC"?" selected":"")+" >BAC</option>"
    +"</select></div>"
    +"<div class='fg'><span class='fl'>Série (facultatif)</span><input class='fi' id='epSerie' value='"+(ep?ep.serie||"":"")+"' placeholder='A, C, D...'></div>"
    +"<div class='fg'><span class='fl'>Matière *</span><input class='fi' id='epMat' value='"+(ep?ep.matiere:"")+"' placeholder='Mathématiques'></div>"
    +"<div class='fg'><span class='fl'>Année</span><input class='fi' id='epAnnee' type='number' value='"+(ep?ep.annee:new Date().getFullYear())+"'></div>"
    +"<div class='fg'><span class='fl'>Durée (min)</span><input class='fi' id='epDuree' type='number' value='"+(ep?ep.duree:120)+"'></div>"
    +"<div class='fg'><span class='fl'>Coefficient</span><input class='fi' id='epCoef' type='number' value='"+(ep?ep.coef:1)+"'></div>"
    +"<div class='fg full'><span class='fl'>Extrait / Énoncé (affiché aux visiteurs)</span><textarea class='fi' id='epExtrait' rows='4' placeholder='Collez ici l&#39;extrait de l&#39;épreuve...'>"+( ep?ep.extrait||"":"")+"</textarea></div>"
    +"<div class='fg full'><label style='display:flex;align-items:center;gap:8px;cursor:pointer'><input type='checkbox' id='epGratuit'"+(ep&&ep.gratuit?" checked":"")+" ><span>Accès gratuit (visible sans connexion)</span></label></div>"
    +"</div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn bi' onclick='_saveEp()'>"+(ep?"Modifier":"Ajouter")+"</button>",true);
}
function _saveEp(){
  var titre=document.getElementById("epTitre")?.value.trim()||"";
  var mat=document.getElementById("epMat")?.value.trim()||"";
  if(!titre||!mat){toast("Titre et matière requis","warn");return;}
  if(!DB.customEpreuves)DB.customEpreuves=[];
  var ep={
    id:"ep_"+Date.now(),titre:titre,
    exam:document.getElementById("epExam")?.value||"BEPC",
    serie:document.getElementById("epSerie")?.value||"",
    matiere:mat,annee:parseInt(document.getElementById("epAnnee")?.value)||new Date().getFullYear(),
    duree:parseInt(document.getElementById("epDuree")?.value)||120,
    coef:parseInt(document.getElementById("epCoef")?.value)||1,
    extrait:document.getElementById("epExtrait")?.value||"",
    gratuit:document.getElementById("epGratuit")?.checked||false,
    type:"epreuve"
  };
  if(window._editEpIdx>=0) DB.customEpreuves[window._editEpIdx]=ep;
  else DB.customEpreuves.push(ep);
  save();cm();toast(window._editEpIdx>=0?"✅ Épreuve modifiée":"✅ Épreuve ajoutée");
  setTimeout(mManageEpreuves,80);
}

