    +'<label style="display:flex;align-items:center;gap:6px;padding:6px 10px;background:var(--bg2);border-radius:8px;font-size:12px;cursor:pointer"><input type="checkbox" id="riPlan2" checked> &#128216; Pack INTERMÉDIAIRE</label>'
    +'<label style="display:flex;align-items:center;gap:6px;padding:6px 10px;background:var(--bg2);border-radius:8px;font-size:12px;cursor:pointer"><input type="checkbox" id="riPlan3"> &#128217; Pack ENSEIGNANT</label>'
