// ── IMPORT HTML — JEUX/QUIZ ────────────────────────────────────────
function mImportJeuHTML(){
  cm();
  M('📥 Importer un Jeu/Quiz HTML','Fichier HTML interactif ou URL externe',
    '<div class="ib ibt mb12"><span>💡</span><span>Un jeu HTML interactif s\'ouvre dans un nouvel onglet. Utile pour importer des quiz tiers, des labos virtuels, ou des jeux créés dans d\'autres outils.</span></div>'
    +'<div class="fg2">'
    +'<div class="fg full"><span class="fl">Titre *</span><input class="fi" id="jhTitre" placeholder="Quiz Chimie — Équations de réaction"></div>'
    +'<div class="fg"><span class="fl">Matière</span><input class="fi" id="jhMat" placeholder="Physique-Chimie"></div>'
    +'<div class="fg"><span class="fl">Niveau</span><select class="fi" id="jhNiv"><option>3ème</option><option>2nde</option><option>1ère</option><option>Terminale</option><option>Toutes classes</option></select></div>'
    +'<div class="fg"><span class="fl">Émoji</span><input class="fi" id="jhEmoji" value="🎮" maxlength="2" style="max-width:70px"></div>'
    +'<div class="fg full"><span class="fl">Option 1 — Fichier HTML local</span>'
    +'<input type="file" class="fi" id="jhFile" accept=".html,.htm" style="padding:6px"></div>'
    +'<div class="fg full"><span class="fl">Option 2 — URL externe (recommandé)</span>'
    +'<input class="fi" id="jhUrl" placeholder="https://veritas-school.com/jeux/quiz_chimie.html"></div>'
    +'<div class="fg full"><label style="display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" id="jhGratuit" checked><span>Accès gratuit</span></label></div>'
    +'</div>',
    '<button class="btn bo" onclick="cm()">Annuler</button>'
    +'<button class="btn bi" onclick="_saveJeuHTML()">💾 Importer</button>',true);
}
function _saveJeuHTML(){
  var titre=(document.getElementById('jhTitre')?.value||'').trim();
  if(!titre){toast('Titre requis','warn');return;}
  var mat=document.getElementById('jhMat')?.value||'';
  var niv=document.getElementById('jhNiv')?.value||'Toutes classes';
  var emoji=document.getElementById('jhEmoji')?.value||'🎮';
  var url=(document.getElementById('jhUrl')?.value||'').trim();
  var file=document.getElementById('jhFile')?.files?.[0];
  var gratuit=document.getElementById('jhGratuit')?.checked!==false;
  function _finalizeJeu(htmlUrl,isLocal,content){
    if(typeof JEUX_CATALOGUE==="undefined"){toast('Module jeux non chargé','warn');return;}
    var id='jeu_html_'+Date.now();
    var action='_jeuHtml_'+id;
    var jeu={id:id,titre:titre,emoji:emoji||'🌐',matiere:mat,niveau:niv,
      desc:'Jeu/Quiz HTML interactif',gratuit:gratuit,plan:gratuit?'Gratuit':'Premium',
      custom:true,type:'html',action:action,externalUrl:htmlUrl||'',htmlLocal:isLocal||false};
    if(isLocal&&content){if(!DB.customJeuxHtml)DB.customJeuxHtml={};DB.customJeuxHtml[id]=content;}
    JEUX_CATALOGUE.push(jeu);
    if(!DB.customJeux)DB.customJeux=[];
    DB.customJeux.push(jeu);
    // Action handler
    (function(jid){window['_jeuHtml_'+jid]=function(){_openHtmlContent(jid,'jeu');};})(id);
    save();cm();toast('✅ Jeu HTML importé');setTimeout(mManageJeux,80);
  }
  if(url){_finalizeJeu(url,false,null);return;}
  if(file){
    var reader=new FileReader();
    reader.onload=function(e){_finalizeJeu('',true,e.target.result);};
    reader.readAsText(file,'utf-8');return;
  }
  toast('Choisissez un fichier ou entrez une URL','warn');
}

// ── Ouvre un contenu HTML (jeu ou épreuve) — legacy + routage multi-format ──
function _openHtmlContent(id,type){
  // Pour les épreuves, router vers le nouveau système multi-format
  if(type==='epreuve'){_openRessource(id);return;}
  // Pour les jeux HTML → comportement original
  var item=null;
  if(typeof JEUX_CATALOGUE!=="undefined") item=JEUX_CATALOGUE.find(function(j){return j.id===id;});
  if(!item){toast('Contenu introuvable','warn');return;}
  if(item.externalUrl){window.open(item.externalUrl,'_blank');return;}
  var html=DB.customJeuxHtml&&DB.customJeuxHtml[id];
  if(html){
    _openHtmlWithWatermark(html,item.titre,null);
    return;
  }
  toast('Contenu HTML non trouvé','warn');
}

