      +"<td style='padding:6px 8px'><strong style='font-size:12px'>"+ev.titre+"</strong><br><span style='font-size:10px;color:var(--ink4)'>"+ev.matiere+" · "+ev.classe+"</span></td>"
      +"<td style='padding:6px 8px;font-size:11px;text-align:center'>"+nbQ+" Q</td>"
