// ── Parseurs ────────────────────────────────────────────────────────────────

function _parseEvalJSON(text){
  var data=JSON.parse(text);
  // Format array d'évaluations ou objet unique
  var evals=Array.isArray(data)?data:[data];
  var questions=[];
  evals.forEach(function(ev){
    if(ev.questions) questions=questions.concat(ev.questions);
  });
  // Normalisation : {q, opts:[A,B,C,D], ans:index}
  questions=questions.map(function(q){
    if(q.opts&&typeof q.ans==='number') return q; // déjà normalisé
    // Moodle JSON : {question_text, answers:[{answer_text, fraction}]}
    if(q.question_text){
      var opts=(q.answers||[]).map(function(a){return (a.answer_text||'').replace(/<[^>]+>/g,'').trim();});
      var ans=0;
      (q.answers||[]).forEach(function(a,i){if(parseFloat(a.fraction||0)>0) ans=i;});
      return {q:q.question_text.replace(/<[^>]+>/g,'').trim(),opts:opts,ans:ans};
    }
    return null;
  }).filter(Boolean);
  return questions;
}

function _parseEvalCSV(text){
  // Format attendu : Question,OptionA,OptionB,OptionC,OptionD,BonneReponse
  // BonneReponse = A/B/C/D ou 0/1/2/3 ou texte exact de la bonne option
  var lines=text.split('\n').map(function(l){return l.trim();}).filter(Boolean);
  var questions=[];
  // Ignorer en-tête si la 1ère colonne ressemble à un header
  var startLine=0;
  if(lines[0]&&/question|q|enonce/i.test(lines[0].split(/[,;]/)[0])) startLine=1;
  for(var i=startLine;i<lines.length;i++){
    // Support virgule et point-virgule comme séparateur
    var sep=lines[i].indexOf(';')>=0?';':',';
    var cols=lines[i].split(sep).map(function(c){return c.replace(/^["']|["']$/g,'').trim();});
    if(cols.length<5) continue;
    var q=cols[0];
    var opts=cols.slice(1,5);
    var rep=cols[5]||cols[4]||'A';
    var ans=0;
    if(/^[0-3]$/.test(rep)) ans=parseInt(rep);
    else if(/^[A-Da-d]$/.test(rep)) ans=rep.toLowerCase().charCodeAt(0)-97;
    else { // cherche la correspondance de texte
      var idx=opts.findIndex(function(o){return o.toLowerCase()===rep.toLowerCase();});
      if(idx>=0) ans=idx;
    }
    if(q&&opts[0]) questions.push({q:q,opts:opts,ans:ans});
  }
  return questions;
}

function _parseEvalGIFT(text){
  // Format GIFT Moodle : ::Title:: Question { =Bonne ~Mauvaise ~Mauvaise }
  var questions=[];
  var blocks=text.split(/\n\s*\n+/).filter(function(b){return b.trim();});
  blocks.forEach(function(block){
    block=block.replace(/\/\/[^\n]*/g,'').trim();
    if(!block||block.startsWith('$')) return;
    var qText='', opts=[], ans=0;
    var titleMatch=block.match(/^::([^:]+)::/);
    if(titleMatch) block=block.replace(titleMatch[0],'').trim();
    var braceIdx=block.indexOf('{');
    if(braceIdx<0) return;
    qText=block.slice(0,braceIdx).trim();
    var inner=block.slice(braceIdx+1,block.lastIndexOf('}')).trim();
    var optMatches=inner.match(/[=~][^=~#{}]+/g)||[];
    optMatches.forEach(function(o,i){
      var isCorrect=o.charAt(0)==='=';
      var txt=o.slice(1).replace(/#[^#]*#/,'').trim();
      if(txt){
        if(isCorrect) ans=opts.length;
        opts.push(txt);
      }
    });
    if(qText&&opts.length>=2) questions.push({q:qText,opts:opts.slice(0,4),ans:Math.min(ans,3)});
  });
  return questions;
}

function _parseEvalHtml(html){
  // 1. Essayer de détecter un tableau ou une liste structurée dans le HTML
  //    en utilisant un DOMParser (disponible dans le navigateur) ;
  //    côté Node/test on tombe dans le fallback texte.
  try{
    var doc=(typeof DOMParser!=='undefined')
      ?new DOMParser().parseFromString(html,'text/html')
      :null;

    if(doc){
      var questions=[];

      // Cas 1 : liste ordonnée <ol> avec <li> = questions,
      //          et sous-listes <ul>/<ol> avec les options
      var ols=doc.querySelectorAll('ol');
      ols.forEach(function(ol){
        ol.querySelectorAll('li').forEach(function(li){
          var qText='';
          var opts=[];
          var ans=0;
          // Texte direct du <li> (avant la sous-liste)
          li.childNodes.forEach(function(n){
            if(n.nodeType===3) qText+=n.textContent;
            if(n.nodeName==='P'||n.nodeName==='SPAN'||n.nodeName==='B'||n.nodeName==='STRONG') qText+=n.textContent;
          });
          qText=qText.trim();
          // Sous-liste = options
          var subList=li.querySelector('ul,ol');
          if(subList){
            subList.querySelectorAll('li').forEach(function(opt,i){
              var t=opt.textContent.trim();
              // Marque de bonne réponse : [x] ou (x) ou * en début
              if(/^[\[\(\*]/.test(t)||/correct|bonne|answer/i.test(opt.className||'')){ans=i;}
              t=t.replace(/^[\[\(\*xX\]\)\s]+/,'').trim();
              opts.push(t);
            });
          }
          if(qText&&opts.length>=2) questions.push({q:qText,opts:opts.slice(0,4),ans:Math.min(ans,3)});
        });
      });
      if(questions.length) return questions;

      // Cas 2 : paragraphes ou divs avec class quiz/question
      var qEls=doc.querySelectorAll('.question,.quiz-question,[data-question]');
      if(qEls.length){
        qEls.forEach(function(el){
          var qText=(el.querySelector('.question-text,.stem,p')||el).textContent.trim();
          var opts=[];
          var ans=0;
          el.querySelectorAll('.answer,.choice,.option,li').forEach(function(opt,i){
            if(/correct|right|bonne/i.test(opt.className)) ans=i;
            opts.push(opt.textContent.replace(/^[a-dA-D][.\)\-\s]/,'').trim());
          });
          if(qText&&opts.length>=2) questions.push({q:qText,opts:opts.slice(0,4),ans:Math.min(ans,3)});
        });
        if(questions.length) return questions;
      }

      // Cas 3 : fallback — extraire le texte brut du body et passer au parseur TXT
      var bodyText=(doc.body||doc.documentElement).textContent||'';
      return _parseEvalTxt(bodyText);
    }
  }catch(e){ /* ignore, fallback below */ }

  // Fallback : strip les balises manuellement et passer au parseur TXT
  var plain=html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi,'')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi,'')
    .replace(/<br\s*\/?>/gi,'\n')
    .replace(/<\/p>/gi,'\n')
    .replace(/<\/li>/gi,'\n')
    .replace(/<\/div>/gi,'\n')
    .replace(/<[^>]+>/g,'')
    .replace(/&nbsp;/g,' ')
    .replace(/&amp;/g,'&')
    .replace(/&lt;/g,'<')
    .replace(/&gt;/g,'>')
    .replace(/&quot;/g,'"');
  return _parseEvalTxt(plain);
}

function _parseEvalTxt(text){
  var questions=[];
  var blocks=text.split(/\n(?=\d+[.\)]\s)/).filter(function(b){return b.trim();});
  blocks.forEach(function(block){
    var lines=block.split('\n').map(function(l){return l.trim();}).filter(Boolean);
    if(!lines.length) return;
    var qLine=lines[0].replace(/^\d+[.\)]\s*/,'').trim();
    var opts=[], ans=0;
    var repLine='';
    lines.slice(1).forEach(function(l){
      var optM=l.match(/^([a-dA-D])[.\)\-\s]\s*(.+)/);
      var repM=l.match(/^(?:r[e\u00e9]ponse|bonne\s+r[e\u00e9]ponse)\s*:?\s*([a-dA-D0-3])/i);
      if(optM) opts.push(optM[2].trim());
      else if(repM) repLine=repM[1];
    });
    if(repLine){
      if(/^[0-3]$/.test(repLine)) ans=parseInt(repLine);
      else ans=repLine.toLowerCase().charCodeAt(0)-97;
    }
    if(qLine&&opts.length>=2) questions.push({q:qLine,opts:opts.slice(0,4),ans:Math.max(0,Math.min(ans,opts.length-1))});
  });
  return questions;
}

function _doImportEval(){
  var fmt=document.getElementById('impEvFmt')?.value||'json';
  var titre=(document.getElementById('impEvTitre')?.value||'').trim()||'Évaluation importée';
  var mat=document.getElementById('impEvMat')?.value||'';
  var cls=(document.getElementById('impEvCls')?.value||'').trim();
  var duree=parseInt(document.getElementById('impEvDuree')?.value)||30;

  function _finalize(questions){
    if(!questions||!questions.length){toast('Aucune question trouvée dans le fichier','warn');return;}
    _initEvals();
    var ev={id:'eval_'+Date.now(),titre:titre,matiere:mat,classe:cls,
      duree:duree,questions:questions,reponses:[],actif:true,
      date:new Date().toLocaleDateString('fr-FR')};
    DB.evaluations.push(ev);
    save();cm();
    toast('&#9989; '+questions.length+' question(s) import&eacute;e(s) — '+titre);
    setTimeout(mManageEvaluations,80);
  }

  function _parse(text){
    try{
      var q=[];
      if(fmt==='json') q=_parseEvalJSON(text);
      else if(fmt==='csv') q=_parseEvalCSV(text);
      else if(fmt==='gift') q=_parseEvalGIFT(text);
      else if(fmt==='html') q=_parseEvalHtml(text);
      else q=_parseEvalTxt(text);
      // Aperçu dans le modal
      var prev=document.getElementById('impEvPreview');
      if(prev){
        prev.style.display='block';
        prev.innerHTML='<strong>&#128202; '+q.length+' question(s) d&eacute;tect&eacute;e(s)</strong>'
          +(q.length?'<ul style="margin:6px 0 0 14px;max-height:100px;overflow-y:auto">'
            +q.slice(0,5).map(function(x,i){return '<li>Q'+(i+1)+': '+_esc(x.q).slice(0,60)+(x.q.length>60?'…':'')+'</li>';}).join('')
            +(q.length>5?'<li style="color:#6B7A99">… et '+(q.length-5)+' autre(s)</li>':'')+'</ul>':'');
      }
      _finalize(q);
    }catch(err){toast('Erreur de lecture : '+err.message,'warn');}
  }

  // Lire depuis le textarea collé ou depuis le fichier
  var textArea=document.getElementById('impEvText');
  var pastedText=(textArea?.value||'').trim();
  if(pastedText){_parse(pastedText);return;}

  var fileEl=document.getElementById('impEvFile');
  if(!fileEl||!fileEl.files[0]){toast('Choisissez un fichier ou collez le texte','warn');return;}
  var reader=new FileReader();
  reader.onload=function(ev){_parse(ev.target.result);};
  reader.readAsText(fileEl.files[0],'utf-8');
}

// ── Export évaluations ───────────────────────────────────────────────────────

function _exportEvalJSON(idx){
  _initEvals();
  var ev=DB.evaluations[idx];
  if(!ev) return;
  var blob=new Blob([JSON.stringify(ev,null,2)],{type:'application/json'});
  var a=document.createElement('a');
  a.href=URL.createObjectURL(blob);
  a.download=ev.titre.replace(/[^a-z0-9]/gi,'_').toLowerCase()+'_VERITAS.json';
  document.body.appendChild(a);a.click();document.body.removeChild(a);
  toast('&#8659; Export JSON : '+ev.titre);
}

function _exportEvalCSV(idx){
  _initEvals();
  var ev=DB.evaluations[idx];
  if(!ev) return;
  var rows=['Question,Option A,Option B,Option C,Option D,Bonne réponse'];
  (ev.questions||[]).forEach(function(q){
    var opts=q.opts||[];
    var ans=(q.ans||0);
    var ansLetter=String.fromCharCode(65+ans); // A/B/C/D
    rows.push([q.q,opts[0]||'',opts[1]||'',opts[2]||'',opts[3]||'',ansLetter]
      .map(function(c){return '"'+String(c).replace(/"/g,'""')+'"';}).join(','));
  });
  var blob=new Blob([rows.join('\n')],{type:'text/csv;charset=utf-8'});
  var a=document.createElement('a');
  a.href=URL.createObjectURL(blob);
  a.download=ev.titre.replace(/[^a-z0-9]/gi,'_').toLowerCase()+'_VERITAS.csv';
  document.body.appendChild(a);a.click();document.body.removeChild(a);
  toast('&#8659; Export CSV : '+ev.questions.length+' questions');
}

