function _addEvalQ(){
  var q=document.getElementById("evQ")?.value.trim()||"";
  var a0=document.getElementById("evA0")?.value.trim()||"";
  var a1=document.getElementById("evA1")?.value.trim()||"";
  var a2=document.getElementById("evA2")?.value.trim()||"";
  var a3=document.getElementById("evA3")?.value.trim()||"";
  if(!q||!a0||!a1){toast("Question et options A/B requis","warn");return;}
  var ans=parseInt(document.getElementById("evAns")?.value||"0");
  var exp=document.getElementById("evExp")?.value||"";
  var opts=[a0,a1,a2||"",a3||""].filter(Boolean);
  window._evalFormQuestions.push({q:q,opts:opts,ans:Math.min(ans,opts.length-1),exp:exp});
  var qList=document.getElementById("evQList");
  if(qList){
    var qi=window._evalFormQuestions.length-1;
    var div=document.createElement("div");
    div.style.cssText="background:#F8FAFF;border-radius:8px;padding:10px;margin-bottom:8px;border-left:3px solid #059669";
    div.innerHTML="<div style='font-size:12px;font-weight:700;margin-bottom:4px'>Q"+(qi+1)+": "+q+"</div>"
      +"<div style='font-size:11px;color:#6B7A99'>"+opts.join(" / ")+" | ✓ "+opts[Math.min(ans,opts.length-1)]+"</div>";
    qList.appendChild(div);
    qList.scrollTop=qList.scrollHeight;
  }
  ["evQ","evA0","evA1","evA2","evA3","evExp"].forEach(function(id){var el=document.getElementById(id);if(el)el.value="";});
  toast("Question "+(window._evalFormQuestions.length)+" ajoutée");
}
function _delEvalQ(qi){
  window._evalFormQuestions.splice(qi,1);
  toast("Question supprimée");
  // Refresh
  var ev=window._editEvalIdx>=0?DB.evaluations[window._editEvalIdx]:null;
  if(ev)ev.questions=window._evalFormQuestions.slice();
  _evalFormUI(ev);
}
function _saveEval(){
  var titre=document.getElementById("evTitre")?.value.trim()||"";
  if(!titre){toast("Titre requis","warn");return;}
  if(!window._evalFormQuestions||!window._evalFormQuestions.length){toast("Ajoutez au moins une question","warn");return;}
  _initEvals();
  var ev={
    id:"eval_"+Date.now(),titre:titre,
    matiere:document.getElementById("evMat")?.value||"",
    classe:document.getElementById("evCls")?.value||"",
    duree:parseInt(document.getElementById("evDuree")?.value)||30,
    questions:window._evalFormQuestions.slice(),
    reponses:[],actif:true,
    date:new Date().toLocaleDateString("fr-FR")
  };
  if(window._editEvalIdx>=0) DB.evaluations[window._editEvalIdx]=ev;
  else DB.evaluations.push(ev);
  save();cm();
  toast(window._editEvalIdx>=0?"✅ Évaluation modifiée":"✅ Évaluation créée ("+ev.questions.length+" questions)");
  setTimeout(mManageEvaluations,80);
}

// ── ÉVALUATION CÔTÉ ÉLÈVE (passer une évaluation) ─────────────────
function showMesEvaluations(){
  _initEvals();
  var actives=DB.evaluations.filter(function(ev){return ev.actif;});
  var h="<div class='vsec'>";
  h+="<div class='vsec-title'>📊 Évaluations en ligne</div>";
  h+="<div class='vsec-sub'>Passez des évaluations créées par votre établissement — résultats instantanés</div>";
  if(!actives.length){
    h+="<div class='vcard' style='text-align:center;padding:40px'><div style='font-size:48px;margin-bottom:16px'>📭</div><div style='font-size:15px;color:#6B7A99'>Aucune évaluation disponible pour le moment.<br>Revenez plus tard.</div></div>";
  }else{
    h+="<div style='display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:16px'>";
    actives.forEach(function(ev){
      var maDeja=(ev.reponses||[]).find(function(r){return SES&&r.eid===SES.id;});
      h+="<div class='vcard' style='border-top:4px solid #142554'>";
      h+="<div style='font-family:Montserrat,sans-serif;font-size:15px;font-weight:800;color:#142554;margin-bottom:6px'>"+ev.titre+"</div>";
      h+="<div style='font-size:12px;color:#6B7A99;margin-bottom:12px'>"+ev.matiere+(ev.classe?" · "+ev.classe:"")+" · "+(ev.questions||[]).length+" questions · "+ev.duree+" min</div>";
      if(maDeja){
        var pct=Math.round((maDeja.score/(ev.questions||[]).length)*100);
        h+="<div style='background:"+(pct>=60?"#D1FAE5":"#FEE2E2")+";border-radius:10px;padding:10px;font-size:13px;font-weight:700;color:"+(pct>=60?"#059669":"#DC2626")+";text-align:center;margin-bottom:10px'>Score: "+maDeja.score+"/"+(ev.questions||[]).length+" ("+pct+"%)</div>";
        h+="<button class='btn sm' style='background:#F0F4FF;color:#142554;border-radius:10px;font-weight:700;border:none;cursor:pointer' onclick='_passerEval(\""+ev.id+"\",true)'>🔄 Recommencer</button>";
      }else{
        h+="<button class='btn bi' onclick='_passerEval(\""+ev.id+"\",false)'>▶ Commencer l'évaluation</button>";
      }
      h+="</div>";
    });
    h+="</div>";
  }
  h+="</div>";
  _vc(h);
}

// v1.2.2 : "X élèves composent" — présence simulée crédible (varie avec l'heure
// + petite marche aléatoire), pour la mise en situation réelle. Sans backend.
window._evalLiveBase = null;
function _evalLiveCount(){
  if(_evalLiveBase===null){
    var h=new Date().getHours();
    // plus d'activité 7h-21h, creux la nuit
    var peak=(h>=7&&h<=21)?1:0.3;
    _evalLiveBase=Math.round((8+Math.random()*30)*peak)+3;
  } else {
    _evalLiveBase += Math.round((Math.random()-0.45)*3); // marche aléatoire douce
    if(_evalLiveBase<4)_evalLiveBase=4; if(_evalLiveBase>60)_evalLiveBase=60;
  }
  return _evalLiveBase;
}
function _passerEval(evalId,force){
  _evalLiveBase=null; // réinitialiser la présence pour cette session d'éval
  _initEvals();
  var ev=DB.evaluations.find(function(e){return e.id===evalId;});
  if(!ev)return;
  if(!SES&&!force){toast("Connectez-vous pour passer l'évaluation","warn");return;}
  var qi=0; var score=0; var timer=null; var elapsed=0;
  var totalSec=ev.duree*60;
  var userAnswers=[];

  function renderQ(){
    if(qi>=ev.questions.length){
      clearInterval(timer);
      // Sauvegarder le résultat
      if(SES){
        if(!ev.reponses)ev.reponses=[];
        ev.reponses=ev.reponses.filter(function(r){return r.eid!==SES.id;});
        ev.reponses.push({eid:SES.id,nom:SES.pre+" "+SES.nom,score:score,total:ev.questions.length,date:new Date().toLocaleDateString("fr-FR"),answers:userAnswers});
        save();
      }
      var pct=Math.round((score/ev.questions.length)*100);
      var _tm=Math.floor(elapsed/60),_ts=elapsed%60;
      var _tmps=String(_tm).padStart(2,'0')+":"+String(_ts).padStart(2,'0');
      _vc("<div class='vsec'><div class='vcard' style='text-align:center;padding:40px'>"
        +"<div style='font-size:56px;margin-bottom:14px'>"+(pct>=80?"🏆":pct>=60?"✅":"📚")+"</div>"
        +"<div style='font-family:Montserrat,sans-serif;font-size:24px;font-weight:800;color:#142554;margin-bottom:8px'>Évaluation terminée !</div>"
        +"<div style='font-family:Georgia,serif;font-size:18px;color:"+(pct>=60?"#059669":"#DC2626")+";font-weight:700;margin-bottom:10px'>"+score+"/"+ev.questions.length+" ("+pct+"%)</div>"
        +"<div style='display:flex;gap:10px;justify-content:center;margin-bottom:18px;flex-wrap:wrap'>"
          +"<div style='background:#F0F4FF;border-radius:10px;padding:8px 14px'><div style='font-size:10px;color:#6B7A99;text-transform:uppercase;letter-spacing:.5px'>⏱️ Temps</div><div style='font-family:monospace;font-weight:800;color:#142554'>"+_tmps+"</div></div>"
          +"<div style='background:#F0F4FF;border-radius:10px;padding:8px 14px'><div style='font-size:10px;color:#6B7A99;text-transform:uppercase;letter-spacing:.5px'>✅ Réussite</div><div style='font-weight:800;color:"+(pct>=60?"#059669":"#DC2626")+"'>"+pct+"%</div></div>"
        +"</div>"
        +"<div style='font-size:13px;color:#6B7A99;margin-bottom:24px'>"+(pct>=80?"Excellent travail ! Tu maîtrises ce chapitre.":pct>=60?"Bon résultat, continue sur ta lancée !":"Révise ce chapitre puis retente l'évaluation.")+"</div>"
        +"<button class='btn bi' onclick='showMesEvaluations()'>← Retour aux évaluations</button>"
        +"</div></div>");
      return;
    }
    var q=ev.questions[qi];
    var remaining=totalSec-elapsed;
    var mn=Math.floor(remaining/60);var sc=remaining%60;
    var pctT=Math.round((elapsed/totalSec)*100);
    var col=remaining<120?"#DC2626":remaining<600?"#D97706":"#059669";
    _vc("<div class='vsec'>"
      +"<div style='background:linear-gradient(135deg,#142554,#1E3A8A);border-radius:16px;padding:16px 20px;color:#fff;margin-bottom:16px'>"
        +"<div class='fl2 fic fsb'>"
          +"<div style='font-size:13px;opacity:.7'>"+ev.titre+"</div>"
          +"<div style='font-family:monospace;font-size:18px;font-weight:700;color:"+col+"'>"+String(mn).padStart(2,'0')+":"+String(sc).padStart(2,'0')+"</div>"
        +"</div>"
        +"<div style='background:rgba(255,255,255,.1);border-radius:20px;height:6px;margin-top:10px'><div style='background:"+col+";height:100%;width:"+pctT+"%;border-radius:20px;transition:width .5s'></div></div>"
        +"<div class='fl2 fic fsb' style='margin-top:6px'>"
          +"<div style='font-size:11px;opacity:.6'>Question "+(qi+1)+"/"+ev.questions.length+"</div>"
          +"<div style='font-size:11px;font-weight:700;color:#86EFAC;display:flex;align-items:center;gap:5px'><span style='width:7px;height:7px;border-radius:50%;background:#10B981;display:inline-block;box-shadow:0 0 0 0 rgba(16,185,129,.7);animation:vgzPing 1.6s infinite'></span><span id='evalLiveCount'>"+_evalLiveCount()+"</span> élèves composent</div>"
        +"</div>"
      +"</div>"
      +"<div class='vcard'>"
        +"<div style='font-family:Montserrat,sans-serif;font-size:15px;font-weight:700;color:#142554;margin-bottom:20px;line-height:1.6'>"+q.q+"</div>"
        +"<div style='display:grid;grid-template-columns:1fr 1fr;gap:10px'>"
          +q.opts.map(function(opt,i){
            return "<button onclick='_answerEval("+i+")' style='background:#F0F4FF;color:#142554;border:2px solid #E8EEFF;border-radius:12px;padding:12px 16px;font-size:13px;font-weight:600;cursor:pointer;text-align:left;transition:.2s' onmouseover=\"this.style.background='#E0EAFF'\" onmouseout=\"this.style.background='#F0F4FF'\">"+opt+"</button>";
          }).join("")
        +"</div>"
        +"<div id='evalFb' style='margin-top:14px;min-height:24px'></div>"
      +"</div>"
      +"</div>");
  }

  window._answerEval=function(i){
    var q=ev.questions[qi];
    var fb=document.getElementById("evalFb");
    var btns=document.querySelectorAll("[onclick^='_answerEval']");
    btns.forEach(function(b,idx){
      b.style.background=idx===q.ans?"#D1FAE5":idx===i&&i!==q.ans?"#FEE2E2":"#F0F4FF";
      b.style.borderColor=idx===q.ans?"#059669":idx===i&&i!==q.ans?"#DC2626":"#E8EEFF";
      b.onclick=null;b.onmouseover=null;b.onmouseout=null;
    });
    if(i===q.ans)score++;
    userAnswers.push({qi:qi,ans:i,correct:i===q.ans});
    // v1.2.2 : question ratée → file de révision espacée (J+1/J+3/J+7)
    if(i!==q.ans && typeof _srsAdd==='function'){ try{ _srsAdd(q, ev.matiere||ev.titre||''); }catch(e){} }
    if(fb)fb.innerHTML="<div style='padding:10px;background:"+(i===q.ans?"#D1FAE5":"#FEE2E2")+";border-radius:10px;font-size:13px;color:"+(i===q.ans?"#059669":"#DC2626")+"'>"+(i===q.ans?"✅ ":"❌ ")+(q.exp||"")+"</div>";
    setTimeout(function(){qi++;renderQ();},2000);
  };

  timer=setInterval(function(){
    elapsed++;
    if(elapsed>=totalSec){clearInterval(timer);qi=ev.questions.length;renderQ();}
    else {
      var remaining2=totalSec-elapsed;var mn2=Math.floor(remaining2/60);var sc2=remaining2%60;
      var col2=remaining2<120?"#DC2626":remaining2<600?"#D97706":"#059669";
      var el=document.querySelector("[style*='monospace']");
      if(el){el.style.color=col2;el.textContent=String(mn2).padStart(2,'0')+":"+String(sc2).padStart(2,'0');}
      var bar=document.querySelector("[style*='transition:width']");
      if(bar)bar.style.width=Math.round((elapsed/totalSec)*100)+"%";
      // rafraîchir la présence "élèves qui composent" toutes les 5 s
      if(elapsed%5===0){ var lc=document.getElementById('evalLiveCount'); if(lc)lc.textContent=_evalLiveCount(); }
    }
  },1000);
  renderQ();
}

// ── RÉSULTATS DES ÉVALUATIONS (admin) ────────────────────────────
function mVoirResultatsEval(evalId){
  _initEvals();
  var ev=DB.evaluations.find(function(e){return e.id===evalId;});
  if(!ev){toast("Évaluation introuvable","warn");return;}
  var reps=ev.reponses||[];
  var rows=reps.map(function(r){
    var pct=Math.round((r.score/ev.questions.length)*100);
    return "<tr><td style='padding:6px 8px;font-size:13px'>"+r.nom+"</td>"
      +"<td style='padding:6px 8px;text-align:center;font-weight:700;color:"+(pct>=60?"#059669":"#DC2626")+"'>"+r.score+"/"+ev.questions.length+"</td>"
      +"<td style='padding:6px 8px;text-align:center'>"+pct+"%</td>"
      +"<td style='padding:6px 8px;font-size:11px;color:var(--ink4)'>"+r.date+"</td></tr>";
  }).join("");
  M("📊 Résultats — "+ev.titre,"",
    (rows?"<div class='tw'><table style='width:100%'><thead><tr style='background:var(--bg2)'><th style='text-align:left;padding:6px 8px'>Élève</th><th>Score</th><th>%</th><th>Date</th></tr></thead><tbody>"+rows+"</tbody></table></div>"
         :"<div class='empty'><div class='empty-ico'>📊</div>Aucune réponse reçue</div>"),
    "<button class='btn bo' onclick='cm()'>Fermer</button>",true);
}

