// ── CONTRÔLE D'ACCÈS PAR PLAN ─────────────────────────────────────
function _hasPlan(planId){
  if(!SES)return false;
  if(SES.type==="admin"||SES.type==="superadmin")return true;
  var plans=SES.plans||[];
  if(plans.indexOf("complet")>=0)return true;
  if(planId!=="complet"&&plans.indexOf("premium")>=0)return true;
  return plans.indexOf(planId)>=0;
}

