function _mgrPlans(id){
  var acc=(DB.visitorAccounts||[]).find(function(a){return a.id===id;});
  if(!acc){toast("Compte introuvable","warn");return;}
  var stdPlans=[
    {id:"gratuit",l:"🔓 Gratuit (ressources de base)"},
    {id:"premium",l:"⭐ Premium (épreuves + labos avancés)"},
    {id:"complet",l:"💎 Complet (tout débloquer)"},
    {id:"science",l:"🔬 Sciences (labos sciences)"},
    {id:"bepc",l:"📝 Pack BEPC"},
    {id:"bac",l:"🏆 Pack BAC"},
  ];
  var customPlans=(DB.elearning&&DB.elearning.plans||[]).map(function(p){return{id:p.id,l:"📦 "+p.nom};});
  var allPlans=stdPlans.concat(customPlans);
  M("⭐ Plans de "+acc.pre+" "+acc.nom,"Abonnements actifs pour cet utilisateur",
    "<div class='ib ibt mb14'><span>💡</span><span>Cochez les abonnements auxquels cet utilisateur a souscrit. L'accès aux contenus premium sera débloqué immédiatement.</span></div>"
    +"<div style='display:grid;grid-template-columns:1fr;gap:8px'>"
    +allPlans.map(function(p){
      var ck=(acc.plans||[]).indexOf(p.id)>=0;
      return "<label style='display:flex;align-items:center;gap:10px;background:"+(ck?"linear-gradient(135deg,#EDE9FE,#E0E7FF)":"#F8FAFF")+";border:2px solid "+(ck?"#C4B5FD":"#E8EEFF")+";border-radius:12px;padding:12px 16px;cursor:pointer;transition:.15s'>"
        +"<input type='checkbox' name='planCk' value='"+p.id+"'"+(ck?" checked":"")+" style='width:16px;height:16px;accent-color:#7C3AED'>"
        +"<span style='font-size:13px;font-weight:"+(ck?"700":"600")+";color:"+(ck?"#5B21B6":"#374151")+"'>"+p.l+"</span>"
        +"</label>";
    }).join("")+"</div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn bi' onclick='_savePlans(\""+id+"\")'>💾 Enregistrer les plans</button>",true);
}

function _savePlans(id){
  var acc=(DB.visitorAccounts||[]).find(function(a){return a.id===id;});
  if(!acc){toast("Compte introuvable","warn");return;}
  acc.plans=Array.from(document.querySelectorAll("input[name='planCk']:checked")).map(function(c){return c.value;});
  save();cm();toast("Plans mis à jour pour "+acc.pre+" ✅");
  if(SES&&(SES.accountId===id||SES.id===id)){SES.plans=acc.plans;_updateVisitorHeader();}
}

function _mgrToggle(id){
  var acc=(DB.visitorAccounts||[]).find(function(a){return a.id===id;});
  if(!acc)return;
  acc.statut=acc.statut==="actif"?"suspendu":"actif";
  save();re();toast(acc.statut==="actif"?"Compte activé":"Compte suspendu");
}

function _mgrDelAcc(id){
  if(!confirm("Supprimer définitivement ce compte ?"))return;
  DB.visitorAccounts=(DB.visitorAccounts||[]).filter(function(a){return a.id!==id;});
  save();re();toast("Compte supprimé");
}

function _mgrNewAccount(){
  M("➕ Créer un compte visiteur","Créer manuellement un accès pour un utilisateur",
    "<div class='fg2'>"
    +"<div class='fg'><span class='fl'>Prénom *</span><input class='fi' id='maP' placeholder='Jean-Pierre'></div>"
    +"<div class='fg'><span class='fl'>Nom *</span><input class='fi' id='maN' placeholder='MBALLA'></div>"
    +"<div class='fg'><span class='fl'>WhatsApp *</span><input class='fi' id='maT' placeholder='+237 6 00 00 00 00'></div>"
    +"<div class='fg'><span class='fl'>Email</span><input class='fi' type='email' id='maE'></div>"
    +"<div class='fg'><span class='fl'>Classe</span><select class='fi' id='maC'>"
    +CLS.map(function(cl){return "<option>"+cl+"</option>";}).join("")+"</select></div>"
    +"<div class='fg'><span class='fl'>Identifiant *</span><input class='fi' id='maU' placeholder='ex: prenom.nom'></div>"
    +"<div class='fg'><span class='fl'>Mot de passe *</span><input class='fi' type='password' id='maPwd' placeholder='Min 6 caractères'></div>"
    +"</div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn bi' onclick='_mgrCreate()'>Créer le compte</button>",true);
}

function _mgrCreate(){
  var pre=(document.getElementById("maP")?.value||"").trim();
  var nom=(document.getElementById("maN")?.value||"").trim();
  var tel=(document.getElementById("maT")?.value||"").trim();
  var user=(document.getElementById("maU")?.value||"").trim().replace(/\s+/g,"");
  var pwd=document.getElementById("maPwd")?.value||"";
  if(!pre||!nom||!tel||!user||!pwd){toast("Tous les champs * sont requis","warn");return;}
  if(pwd.length<6){toast("Mot de passe trop court","warn");return;}
  if(!DB.visitorAccounts)DB.visitorAccounts=[];
  if(DB.visitorAccounts.find(function(a){return a.user.toLowerCase()===user.toLowerCase();})){toast("Identifiant déjà pris","warn");return;}
  var _newId = "va_"+Date.now();
  DB.visitorAccounts.push({id:_newId,user:user,pwd:pwd,nom:nom,pre:pre,tel:tel,
    email:document.getElementById("maE")?.value||"",
    cls:document.getElementById("maC")?.value||CLS[0],
    plans:[],statut:"actif",
    dateInscription:new Date().toLocaleDateString("fr-FR"),lastLogin:null});
  save();
  try { if(typeof _processReferralOnSignup==='function') _processReferralOnSignup(_newId); } catch(e){}
  cm();re();toast("Compte créé pour "+pre+" ✅");
}

// ── ÉVALUATIONS EN LIGNE ─────────────────────────────────────────
function showEvaluations(){
  var evals=(DB.evaluations||[]).filter(function(ev){
    return ev.actif!==false&&ev.questions&&ev.questions.length;
  });
  var h="<div class='vsec'><div class='vsec-title'>📊 Évaluations en ligne</div>"
    +"<div class='vsec-sub'>Tests chronométrés avec correction instantanée</div>";
  if(!evals.length){
    h+="<div class='empty'><div class='empty-ico'>📊</div><div>Aucune évaluation disponible en ce moment.</div></div></div>";
    _vc(h);return;
  }
  h+="<div class='grid-pc-3'>";
  evals.forEach(function(ev){
    var uid=SES&&(SES.accountId||SES.id);
    var myR=uid&&(ev.resultats||[]).find(function(r){return r.uid===uid;});
    var col=myR?(myR.score>=80?"#059669":myR.score>=60?"#D97706":"#DC2626"):"#142554";
    h+="<div class='vcard' style='border-top:4px solid #142554'>"
      +"<div style='font-family:Montserrat,sans-serif;font-size:15px;font-weight:800;color:#142554;margin-bottom:6px'>"+ev.titre+"</div>"
      +"<div style='font-size:11px;color:#6B7A99;margin-bottom:3px'>"+ev.matiere+(ev.classe?" · "+ev.classe:"")+"</div>"
      +"<div style='font-size:11px;color:#9CA3AF;margin-bottom:14px'>"+ev.questions.length+" questions · "+ev.duree+" min</div>";
    if(myR){
      h+="<div style='background:#F8FAFF;border-radius:10px;padding:10px;text-align:center;margin-bottom:12px'>"
        +"<div style='font-family:Georgia,serif;font-size:22px;font-weight:700;color:"+col+"'>"+myR.score+"%</div>"
        +"<div style='font-size:10px;color:#9CA3AF'>Passé le "+myR.date+" · "+myR.correct+"/"+myR.total+"</div></div>";
    }
    h+="<button class='btn bi' style='width:100%' onclick='lancerEvaluation(\""+ev.id+"\")'>"
      +(SES?(myR?"🔄 Repasser":"▶ Commencer"):"🔒 Connexion requise")+"</button></div>";
  });
  h+="</div></div>";
  _vc(h);
}

function lancerEvaluation(evId){
  if(!SES){toast("Connectez-vous pour passer une évaluation","warn");return;}
  var ev=(DB.evaluations||[]).find(function(e){return e.id===evId;});
  if(!ev||!ev.questions||!ev.questions.length){toast("Évaluation introuvable","warn");return;}
  var qIdx=0,answers=[],elapsed=0,total=ev.duree*60,timer=null;
  function renderQ(){
    if(qIdx>=ev.questions.length){
      clearInterval(timer);
      var correct=answers.filter(function(a,i){return ev.questions[i]&&a===ev.questions[i].ans;}).length;
      var pct=Math.round((correct/ev.questions.length)*100);
      var uid=SES.accountId||SES.id;
      if(!ev.resultats)ev.resultats=[];
      ev.resultats=ev.resultats.filter(function(r){return r.uid!==uid;});
      ev.resultats.push({uid:uid,nom:(SES.pre||"")+" "+(SES.nom||""),score:pct,
        correct:correct,total:ev.questions.length,
        date:new Date().toLocaleDateString("fr-FR"),temps:Math.round(elapsed/60)+"min"});
      save();
      var col=pct>=80?"#059669":pct>=60?"#D97706":"#DC2626";
      _vc(
        "<div class='vsec'><div class='vcard' style='text-align:center;padding:40px'>"
        +"<div style='font-size:60px;margin-bottom:16px'>"+(pct>=80?"🏆":pct>=60?"✅":"📚")+"</div>"
        +"<div style='font-family:Montserrat,sans-serif;font-size:22px;font-weight:800;color:#142554;margin-bottom:8px'>Évaluation terminée !</div>"
        +"<div style='font-family:Georgia,serif;font-size:36px;font-weight:700;color:"+col+";margin-bottom:8px'>"+pct+" %</div>"
        +"<div style='font-size:15px;color:#6B7A99;margin-bottom:20px'>"+correct+" / "+ev.questions.length+" réponses correctes</div>"
        +"<div style='text-align:left;background:#F8FAFF;border-radius:14px;padding:20px;margin-bottom:24px;max-height:320px;overflow-y:auto'>"
        +ev.questions.map(function(q,i){
          var ok=answers[i]===q.ans;
          return "<div style='margin-bottom:12px;padding-bottom:12px;border-bottom:1px solid #F0F4FF'>"
            +"<div style='font-size:13px;font-weight:700;color:#142554;margin-bottom:4px'>"+(i+1)+". "+q.q+"</div>"
            +"<div style='font-size:12px;color:"+(ok?"#059669":"#DC2626")+";margin-bottom:3px'>"+(ok?"✅":"❌")+" "+(ok?"Correct : ":"Bonne réponse : ")+(q.opts[q.ans]||"")+"</div>"
            +(q.exp?"<div style='font-size:11px;color:#6B7A99;font-style:italic'>"+q.exp+"</div>":"")
            +"</div>";
        }).join("")+"</div>"
        +"<button class='btn bi' onclick='showEvaluations()'>← Retour aux évaluations</button>"
        +"</div></div>");
      return;
    }
    var q=ev.questions[qIdx],rem=total-elapsed;
    var mn=String(Math.floor(rem/60)).padStart(2,"0"),sc2=String(rem%60).padStart(2,"0");
    _vc(
      "<div class='vsec'>"
      +"<div style='background:linear-gradient(135deg,#142554,#1E3A8A);border-radius:16px;padding:18px 24px;color:#fff;margin-bottom:18px;display:flex;justify-content:space-between;align-items:center'>"
      +"<div><div style='font-family:Montserrat,sans-serif;font-size:14px;font-weight:800'>"+ev.titre+"</div>"
      +"<div style='font-size:12px;opacity:.65'>Question "+(qIdx+1)+" / "+ev.questions.length+"</div></div>"
      +"<div id='evTimer' style='font-family:monospace;font-size:26px;font-weight:900;color:"+(rem<120?"#FCA5A5":"#A5F3FC")+"'>"+mn+":"+sc2+"</div>"
      +"</div>"
      +"<div class='vcard'>"
      +"<div style='background:#F0F4FF;border-radius:8px;padding:3px 12px;font-size:11px;color:#3C8DFF;font-weight:700;display:inline-block;margin-bottom:14px'>"+(qIdx+1)+"/"+ev.questions.length+"</div>"
      +"<div style='font-family:Montserrat,sans-serif;font-size:16px;font-weight:700;color:#142554;margin-bottom:22px;line-height:1.5'>"+q.q+"</div>"
      +"<div style='display:grid;grid-template-columns:1fr 1fr;gap:12px'>"
      +q.opts.map(function(opt,i){
        return "<button data-oi='"+i+"' style='background:#F8FAFF;color:#142554;border:2px solid #E8EEFF;border-radius:14px;padding:14px;font-size:13px;font-weight:600;cursor:pointer;text-align:left;line-height:1.4;transition:.15s'"
          +" onmouseover=\"this.style.background='#E0EAFF';this.style.borderColor='#A5B4FC'\""
          +" onmouseout=\"this.style.background='#F8FAFF';this.style.borderColor='#E8EEFF'\""
          +" onclick='_evAns("+i+")'>"+opt+"</button>";
      }).join("")+"</div>"
      +"<div id='evFb' style='margin-top:14px;min-height:20px'></div></div></div>");
    window._evAns=function(i){
      answers[qIdx]=i;
      document.querySelectorAll("[data-oi]").forEach(function(b,idx){
        b.style.background=idx===q.ans?"#D1FAE5":idx===i&&i!==q.ans?"#FEE2E2":"#F8FAFF";
        b.style.borderColor=idx===q.ans?"#059669":idx===i&&i!==q.ans?"#DC2626":"#E8EEFF";
        b.onclick=null;
      });
      var fb=document.getElementById("evFb");
      if(fb)fb.innerHTML="<div style='padding:10px 14px;background:"+(i===q.ans?"#D1FAE5":"#FEE2E2")+";border-radius:10px;font-size:12px;color:"+(i===q.ans?"#059669":"#DC2626")+"'>"+(i===q.ans?"✅ ":"❌ ")+(q.exp||"")+"</div>";
      setTimeout(function(){qIdx++;renderQ();},1600);
    };
  }
  timer=setInterval(function(){
    elapsed++;
    var rem=total-elapsed;
    if(rem<=0){clearInterval(timer);qIdx=ev.questions.length;renderQ();return;}
    var t=document.getElementById("evTimer");
    if(t){t.textContent=String(Math.floor(rem/60)).padStart(2,"0")+":"+String(rem%60).padStart(2,"0");t.style.color=rem<120?"#FCA5A5":"#A5F3FC";}
  },1000);
  renderQ();
}

// ── ADMIN: GESTION ÉVALUATIONS ────────────────────────────────────
function mManageEvals(){
  if(!iA())return;
  if(!DB.evaluations)DB.evaluations=[];
  var rows=DB.evaluations.map(function(ev,i){
    var actif=ev.actif!==false;
    var nb=ev.resultats?ev.resultats.length:0;
    var moy=nb?Math.round(ev.resultats.reduce(function(a,r){return a+r.score;},0)/nb):null;
    return "<div class='mgr-card' style='margin-bottom:10px'>"
      +"<div class='fl2 fic fsb mb6'>"
      +"<div><div style='font-family:Montserrat,sans-serif;font-size:13px;font-weight:800;color:#142554'>"+ev.titre+"</div>"
      +"<div style='font-size:11px;color:#6B7A99'>"+ev.matiere+" · "+ev.classe+" · "+ev.questions.length+" Q · "+ev.duree+"min</div>"
      +(nb?"<div style='font-size:11px;color:#059669;margin-top:2px'>"+nb+" passage"+(nb>1?"s":""+(moy!==null?" · Moy: "+moy+"%":""))+"</div>":"")
      +"</div>"
      +"<div class='fl2 g4'>"
      +"<span style='background:"+(actif?"#D1FAE5":"#FEE2E2")+";color:"+(actif?"#059669":"#DC2626")+";font-size:9px;font-weight:800;padding:2px 8px;border-radius:8px'>"+(actif?"ACTIF":"INACTIF")+"</span>"
      +"<button class='btn bo xs' onclick='_evalToggle("+i+")' title='Activer/Désactiver'>⇄</button>"
      +"<button class='btn bo xs' onclick='_evalEdit("+i+")' title='Modifier'>✏️</button>"
      +"<button class='btn br2 xs' onclick='_evalDel("+i+")' title='Supprimer'>🗑</button>"
      +"</div></div></div>";
  }).join("");
  M("📊 Évaluations","Gérez les tests chronométrés avec correction instantanée",
    "<div class='ib ibt mb12'><span>📊</span><span>"+DB.evaluations.length+" évaluation(s). Les élèves et visiteurs connectés les passent depuis leur espace.</span></div>"
    +(rows||"<div class='mgr-empty'>Aucune évaluation créée. Commencez par en créer une.</div>")
    +"<div style='border-top:var(--br);padding-top:12px;margin-top:10px'><button class='btn bi' onclick='_evalNew()'>➕ Créer une évaluation</button></div>",
    "<button class='btn bo' onclick='cm()'>Fermer</button>",true);
}
function _evalToggle(i){var ev=DB.evaluations[i];if(!ev)return;ev.actif=!ev.actif;save();cm();toast(ev.actif?"Activée":"Désactivée");setTimeout(mManageEvals,80);}
function _evalDel(i){if(!confirm("Supprimer cette évaluation et ses résultats ?"))return;DB.evaluations.splice(i,1);save();cm();toast("Supprimée");setTimeout(mManageEvals,80);}
function _evalNew(){window._editEvalIdx=-1;_evalForm(null);}
function _evalEdit(i){window._editEvalIdx=i;_evalForm(DB.evaluations[i]);}
function _evalForm(ev){
  M(ev?"✏️ Modifier l'évaluation":"➕ Nouvelle évaluation","",
    "<div class='fg2'>"
    +"<div class='fg'><span class='fl'>Titre *</span><input class='fi' id='evT' value='"+(ev?ev.titre:"")+"' placeholder='Ex: Contrôle Maths S1'></div>"
    +"<div class='fg'><span class='fl'>Matière</span><input class='fi' id='evM' value='"+(ev?ev.matiere||"":"")+"' placeholder='Mathématiques'></div>"
    +"<div class='fg'><span class='fl'>Classe</span><select class='fi' id='evC'>"
    +CLS.map(function(cl){return "<option"+(ev&&ev.classe===cl?" selected":"")+" >"+cl+"</option>";}).join("")
    +"</select></div>"
    +"<div class='fg'><span class='fl'>Durée (min)</span><input class='fi' type='number' id='evD' value='"+(ev?ev.duree:30)+"' min='5'></div>"
    +"<div class='fg full'><span class='fl'>Questions JSON *</span>"
    +"<textarea class='fi' id='evQ' rows='12' style='font-family:monospace;font-size:11px;line-height:1.6' placeholder='[\n  {\n    \"q\": \"Texte de la question ?\",\n    \"opts\": [\"Réponse A\",\"Réponse B\",\"Réponse C\",\"Réponse D\"],\n    \"ans\": 0,\n    \"exp\": \"Explication de la bonne réponse\"\n  }\n]'>"+(ev?JSON.stringify(ev.questions,null,2):"")+"</textarea>"
    +"<div style='font-size:11px;color:var(--ink4);margin-top:4px;line-height:1.6'>"
    +"<strong>Format requis :</strong> tableau JSON · <code>q</code>=question · <code>opts</code>=[4 options] · <code>ans</code>=index correct(0-3) · <code>exp</code>=explication</div></div>"
    +"</div>",
    "<button class='btn bo' onclick='cm()'>Annuler</button>"
    +"<button class='btn bi' onclick='_evalSave()'>"+(ev?"Modifier":"Créer l'évaluation")+"</button>",true);
}
function _evalSave(){
  var titre=(document.getElementById("evT")?.value||"").trim();
  var raw=(document.getElementById("evQ")?.value||"").trim();
  if(!titre){toast("Titre requis","warn");return;}
  var questions=[];
  try{questions=JSON.parse(raw||"[]");}
  catch(e){toast("JSON invalide: "+e.message,"warn");return;}
  if(!questions.length){toast("Ajoutez au moins une question","warn");return;}
  if(!DB.evaluations)DB.evaluations=[];
  var ei=typeof window._editEvalIdx!=="undefined"?window._editEvalIdx:-1;
  var obj={
    id:ei>=0?DB.evaluations[ei].id:"eval_"+Date.now(),
    titre:titre,matiere:document.getElementById("evM")?.value||"",
    classe:document.getElementById("evC")?.value||"",
    duree:parseInt(document.getElementById("evD")?.value)||30,
    questions:questions,actif:true,
    resultats:ei>=0?(DB.evaluations[ei].resultats||[]):[],
    dateCreation:new Date().toLocaleDateString("fr-FR")
  };
  if(ei>=0&&ei<DB.evaluations.length)DB.evaluations[ei]=obj;
  else DB.evaluations.push(obj);
  save();cm();toast(ei>=0?"Évaluation modifiée ✅":"Évaluation créée ✅");setTimeout(mManageEvals,80);
}

