// ════════════════════════════════════════════════════════════════════════════
// VERITAS — MODULE NAVIGATION HISTORIQUE (touche Retour = page précédente)
// ════════════════════════════════════════════════════════════════════════════
(function _initNavHistory(){
  // Pile interne des états de navigation
  window._navStack = [];
  // Drapeau pour éviter les boucles lors de la restauration
  window._navRestoring = false;

  // Entrée initiale dans l'historique navigateur (empêche la fermeture immédiate)
  history.replaceState({_v:0}, '');

  // ── Fonction de restauration d'un état sauvegardé ──
  window._navRestore = function(fn){
    window._navRestoring = true;
    try{ fn(); } catch(e){ console.warn('[nav]',e); }
    window._navRestoring = false;
  };

  // ── Intercepteur générique : wraps une fonction de navigation ──
  function _wrapNav(name, snapshotFn){
    var orig = window[name];
    if(typeof orig !== 'function') return;
    window[name] = function(){
      if(!window._navRestoring){
        var snap = snapshotFn ? snapshotFn.apply(this, arguments) : null;
        if(snap){
          window._navStack.push(snap);
          history.pushState({_v: window._navStack.length}, '');
        }
      }
      return orig.apply(this, arguments);
    };
  }

  // ── Wrappers par fonction ──

  // Visiteur : sections principales
  _wrapNav('vShowSec', function(sec){
    var prev = window._vCurrentSec;
    if(!prev || prev === sec) return null;
    return function(){ window._navRestoring=true; vShowSec(prev); window._navRestoring=false; };
  });

  // Admin : pages du tableau de bord
  _wrapNav('goTo', function(p){
    var prev = typeof pg !== 'undefined' ? pg : null;
    if(!prev || prev === p) return null;
    return function(){ window._navRestoring=true; goTo(prev); window._navRestoring=false; };
  });

  // Littérature : menu d'une œuvre
  _wrapNav('_showLittMenu', function(jid, key){
    var prevSec = window._vCurrentSec;
    return function(){ window._navRestoring=true; vShowSec(prevSec||'litterature'); window._navRestoring=false; };
  });

  // Littérature : sous-pages (carte, fiche, citations, techniques, contrôle, QCM)
  ['_showLittCarte','_showLittFiche','_showLittCitations',
   '_showLittTechniques','_showLittControle','_showLittQCM'].forEach(function(name){
    _wrapNav(name, function(key){
      var k = key;
      return function(){ window._navRestoring=true; _showLittMenu(k,k); window._navRestoring=false; };
    });
  });

  // Jeux éducatifs
  _wrapNav('showJeuxEdu', function(){
    var prev = window._vCurrentSec;
    if(!prev || prev === 'jeux') return null;
    return function(){ window._navRestoring=true; vShowSec(prev); window._navRestoring=false; };
  });

  // Laboratoires virtuels
  _wrapNav('showLabosVirtuels', function(){
    var prev = window._vCurrentSec;
    if(!prev || prev === 'labos') return null;
    return function(){ window._navRestoring=true; vShowSec(prev); window._navRestoring=false; };
  });

  // ── Gestionnaire de l'événement popstate (bouton Retour du navigateur) ──
  window.addEventListener('popstate', function(e){
    if(window._navStack.length > 0){
      // On a un état précédent dans notre pile → restaurer
      var fn = window._navStack.pop();
      window._navRestore(fn);
      // Maintenir l'entrée navigateur courante pour ne pas fermer l'app
      if(window._navStack.length === 0){
        history.replaceState({_v:0}, '');
      }
    } else {
      // Pile vide : on repousse un état pour ne pas quitter l'app
      history.pushState({_v:0}, '');
      toast('Utilisez le menu pour naviguer','info');
    }
  });
})();



