(function(){
  if(!DB.elearningLibrary) DB.elearningLibrary=[];
  EPREUVES_DB.forEach(function(ep){
    if(!DB.elearningLibrary.find(function(x){return x.id===ep.id;})){
      DB.elearningLibrary.push(ep);
    }
  });
})();

