// ── CHARGEUR DE FICHIER POUR SUJETS (enseignant) ─────────────────
window._sjFileData=''; window._sjFileName=''; window._sjFileMime='';
function _sjLoadFile(inp){
  if(!inp||!inp.files||!inp.files[0])return;
  var f=inp.files[0];
  if(f.size>20*1024*1024){toast('Fichier trop lourd (max 20 Mo)','warn');inp.value='';return;}
  var prev=document.getElementById('sjFilePreview');
  if(prev)prev.innerHTML='⏳ Chargement…';
  var r=new FileReader();
  r.onload=function(e){
    window._sjFileData=e.target.result;
    window._sjFileName=f.name;
    window._sjFileMime=f.type||'application/octet-stream';
    var ext=f.name.split('.').pop().toLowerCase();
    var ico=ext==='pdf'?'📄':ext==='docx'||ext==='doc'?'📝':'📎';
    if(prev)prev.innerHTML='<span style="color:var(--gr);font-weight:600">'+ico+' '+f.name+' ('+Math.round(f.size/1024)+' Ko) — Prêt</span>';
    toast('✓ Fichier chargé : '+f.name);
  };
  r.onerror=function(){toast('Erreur de lecture du fichier','warn');};
  r.readAsDataURL(f);
}

