// ── FILIGRANE VERITAS — WATERMARK AUTO SUR TÉLÉCHARGEMENT ────────
// Applique un filigrane logo + "VÉRITAS" sur les épreuves/évaluations
// avant téléchargement. Fonctionne sur les fichiers image (converti en canvas).
// Pour les PDF natifs, un overlay HTML est imprimé avec le filigrane.

// ═══ [SECTION] Mission 3.A — Filigrane universel canvas ═══
// [WATERMARK v1.2] Applique logo + filigrane daté sur un canvas (html2canvas ou dessin direct)
function applyWatermark(canvas, ctx){
  var now=new Date();
  var dateStr=now.toLocaleDateString('fr-FR')+' '+now.toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'});
  var W=canvas.width, H=canvas.height;

  // 1. Filigrane diagonal très discret — une seule passe légère, couleur claire
  ctx.save();
  ctx.globalAlpha=0.035;
  ctx.fillStyle='#4A6FA5';
  ctx.font='bold 22px Montserrat,Arial,sans-serif';
  ctx.translate(W/2,H/2);
  ctx.rotate(-Math.PI/7);
  var step=220;
  for(var fy=-H*1.2;fy<H*1.2;fy+=step){
    for(var fx=-W*1.2;fx<W*1.2;fx+=step){
      ctx.fillText('VÉRITAS',fx,fy);
    }
  }
  ctx.restore();

  // 2. Bandeau bas propre — fond bleu nuit semi-transparent
  var bH=32;
  ctx.save();
  ctx.globalAlpha=0.92;
  // Fond dégradé horizontal
  var grad=ctx.createLinearGradient(0,H-bH,0,H);
  grad.addColorStop(0,'rgba(20,37,84,0.92)');
  grad.addColorStop(1,'rgba(7,20,40,0.97)');
  ctx.fillStyle=grad;
  ctx.fillRect(0,H-bH,W,bH);
  ctx.globalAlpha=1;

  // Texte gauche : nom établissement
  ctx.fillStyle='#FFC93C';
  ctx.font='bold 12px Inter,Arial,sans-serif';
  ctx.textBaseline='middle';
  ctx.textAlign='left';
  ctx.fillText('© VÉRITAS Academy',14,H-bH/2);

  // Séparateur
  ctx.fillStyle='rgba(255,201,60,0.4)';
  ctx.fillRect(W/2-1,H-bH+6,1,bH-12);

  // Texte droite : date de téléchargement
  ctx.fillStyle='rgba(255,255,255,0.75)';
  ctx.font='11px Inter,Arial,sans-serif';
  ctx.textAlign='right';
  ctx.fillText('Téléchargé le '+dateStr,W-14,H-bH/2);
  ctx.restore();

  // 3. Logo en haut à droite (si disponible)
  var logoImg=document.getElementById('_logoData');
  if(logoImg&&logoImg.complete&&logoImg.naturalWidth>0){
    var sz=40;
    ctx.save();
    ctx.globalAlpha=0.88;
    ctx.drawImage(logoImg,W-sz-12,8,sz,sz);
    ctx.restore();
  }
}

function _applyWatermarkAndDownload(dataUrl, fileName, fileType){
  var ext=(fileName||'').split('.').pop().toLowerCase();
  var isImage=['jpg','jpeg','png','gif','webp'].indexOf(ext)>=0;
  var isPdf=ext==='pdf';

  if(isImage){
    // Watermark via canvas
    var img=new Image();
    img.onload=function(){
      var canvas=document.createElement('canvas');
      canvas.width=img.width; canvas.height=img.height;
      var ctx=canvas.getContext('2d');
      // Draw original image
      ctx.drawImage(img,0,0);
      // Semi-transparent diagonal watermarks
      ctx.save();
      ctx.globalAlpha=0.13;
      ctx.font='bold '+Math.round(img.width/12)+'px "Montserrat",Arial,sans-serif';
      ctx.fillStyle='#142554';
      ctx.translate(img.width/2,img.height/2);
      ctx.rotate(-Math.PI/5);
      for(var dy=-img.height;dy<img.height*1.5;dy+=Math.round(img.height/4)){
        ctx.fillText('VÉRITAS',-(img.width*0.45),dy);
      }
      ctx.restore();
      // Logo watermark (small, bottom-right)
      var logo=DB.school&&DB.school.logo;
      function _finalizeWm(){
        // Bottom bar with school name
        ctx.save();
        ctx.fillStyle='rgba(20,37,84,0.82)';
        var barH=Math.round(img.height*0.045);
        ctx.fillRect(0,img.height-barH,img.width,barH);
        ctx.fillStyle='#FFC93C';
        ctx.font='bold '+Math.round(barH*0.55)+'px "Montserrat",Arial,sans-serif';
        ctx.textAlign='center';
        ctx.fillText('© VÉRITAS — '+(DB.school&&DB.school.nom||'Centre VÉRITAS')+' — Reproduction interdite',img.width/2,img.height-Math.round(barH*0.25));
        ctx.restore();
        // Download
        var a=document.createElement('a');
        a.href=canvas.toDataURL('image/png');
        a.download=fileName.replace(/\.[^.]+$/,'')+'_VERITAS.png';
        a.click();
        toast('✓ Téléchargement avec filigrane VÉRITAS');
      }
      if(logo){
        var lImg=new Image();
        lImg.onload=function(){
          var lw=Math.round(img.width*0.12),lh=Math.round(lw*(lImg.height/lImg.width)||lw);
          ctx.save();ctx.globalAlpha=0.18;
          ctx.drawImage(lImg,img.width-lw-14,14,lw,lh);
          ctx.restore();
          _finalizeWm();
        };
        lImg.onerror=_finalizeWm;
        lImg.src=logo;
      } else { _finalizeWm(); }
    };
    img.onerror=function(){_directDownload(dataUrl,fileName);};
    img.src=dataUrl;
  } else if(isPdf){
    // Pour les PDF : ouvrir dans une fenêtre d'impression avec overlay filigrane
    _downloadPdfWithWatermark(dataUrl, fileName);
  } else {
    // Autres formats : télécharger directement
    _directDownload(dataUrl, fileName);
  }
}

function _directDownload(dataUrl, fileName){
  var a=document.createElement('a');a.href=dataUrl;a.download=fileName;a.click();
}

function _downloadPdfWithWatermark(dataUrl, fileName){
  var schoolNom=(DB.school&&DB.school.nom)||'Centre VÉRITAS';
  var logo=DB.school&&DB.school.logo;
  var logoHtml=logo?'<img src="'+logo+'" style="width:70px;height:70px;object-fit:contain;opacity:.10;position:fixed;top:18px;right:18px;z-index:9999;border-radius:50%">':'';
  // SVG filigrane : V stylisé + VÉRITAS
  var wmSvg='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 340 120" style="width:340px;height:120px;opacity:.08">'
    +'<text x="10" y="90" font-family="Georgia,serif" font-size="88" font-weight="900" fill="#142554" letter-spacing="-4">V</text>'
    +'<text x="72" y="88" font-family="Montserrat,Arial,sans-serif" font-size="56" font-weight="800" fill="#142554" letter-spacing="6">ÉRITAS</text>'
    +'</svg>';
  var wmWin=window.open('','_blank','width=900,height=700');
  if(!wmWin){_directDownload(dataUrl,fileName);return;}
  wmWin.document.write(
    '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>'+fileName+'</title>'+
    '<style>'+
    'body{margin:0;padding:0;font-family:sans-serif}'+
    '.wm-overlay{position:fixed;inset:0;z-index:9998;pointer-events:none;'+
    'display:grid;place-items:center;overflow:hidden}'+
    '.wm-tile{position:absolute;inset:-40%;display:grid;'+
    'grid-template-columns:repeat(3,1fr);grid-template-rows:repeat(4,1fr);'+
    'gap:0;transform:rotate(-28deg);opacity:1}'+
    '.wm-bar{position:fixed;bottom:0;left:0;right:0;z-index:9999;background:rgba(20,37,84,.90);'+
    'color:#FFC93C;padding:7px 16px;font-size:12px;font-weight:700;text-align:center;'+
    'font-family:"Montserrat",sans-serif;letter-spacing:.5px}'+
    'iframe{width:100%;height:calc(100vh - 36px);border:none}'+
    '.dl-btn{position:fixed;top:10px;right:10px;z-index:10000;background:#FFC93C;color:#142554;'+
    'border:none;border-radius:10px;padding:9px 18px;font-size:13px;font-weight:800;cursor:pointer;font-family:sans-serif}'+
    '</style></head><body>'+
    logoHtml+
    '<div class="wm-overlay"><div class="wm-tile">'+
    Array(12).fill(wmSvg).join('')+
    '</div></div>'+
    '<button class="dl-btn" onclick="document.querySelector(\'iframe\').contentWindow.print()">🖨️ Imprimer / PDF</button>'+
    '<iframe src="'+dataUrl+'"></iframe>'+
    '<div class="wm-bar">© Mythe Errant 2026 · VÉRITAS — '+schoolNom+' — Document officiel · Reproduction interdite sans autorisation</div>'+
    '</body></html>'
  );
  wmWin.document.close();
  toast('✓ Document ouvert avec filigrane VÉRITAS');
}

