// ── PATCH: Téléchargement d'épreuves avec filigrane ──────────────
// Override _dlFile pour ajouter filigrane automatiquement sur les épreuves
var _orig_dlFile=window._dlFile;
window._dlFile=function(btn){
  var url=decodeURIComponent(btn.dataset.durl||'');
  var name=decodeURIComponent(btn.dataset.dfname||'file');
  if(!url){toast('Fichier non disponible','warn');return;}
  // Si c'est dans le contexte d'une épreuve ou évaluation, ajouter filigrane
  var isEpreuve=(name.toLowerCase().indexOf('epreuve')>=0||
                 name.toLowerCase().indexOf('evaluation')>=0||
                 name.toLowerCase().indexOf('examen')>=0||
                 name.toLowerCase().indexOf('controle')>=0||
                 name.toLowerCase().indexOf('devoir')>=0||
                 (btn.closest&&btn.closest('[data-wm]'))!==null);
  if(isEpreuve){
    _applyWatermarkAndDownload(url, name, '');
  } else {
    var a=document.createElement('a');a.href=url;a.download=name;a.click();
  }
};

// ── PATCH: Téléchargement sujet classe virtuelle avec filigrane ───
// Ajouter un bouton de téléchargement avec filigrane pour les sujets
function dlSujetWithWatermark(cvId, sjId){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId;});
  if(!cv)return;
  var sj=(cv.sujets||[]).find(function(s){return s.id===sjId;});
  if(!sj){toast('Sujet introuvable','warn');return;}
  if(!sj.fichierData){
    toast('Aucun fichier attaché à ce sujet','warn');
    return;
  }
  _applyWatermarkAndDownload(sj.fichierData, sj.fichier||sj.titre+'.pdf', sj.fichierType||'');
}

