function mEditExamResults(){
  if(!iA())return;
  var ers=DB.examResults||[];
  var h='<div class="ib ibt mb12"><span>💡</span><span>Modifiez les taux, candidats et admis pour chaque année, ou supprimez des années.</span></div>';
  ers.forEach(function(er,ei){
    h+='<div style="background:var(--bg2);border-radius:12px;padding:14px;margin-bottom:12px">';
    h+='<div class="fl2 fic fsb mb10"><div class="semi s" style="color:var(--bl)">📅 '+er.annee+'</div>';
    h+='<div class="fl2 g6"><button class="btn bo xs" onclick="_delExamYear('+ei+')">🗑</button></div></div>';
    er.niveaux.forEach(function(n,ni){
      h+='<div class="fl2 fic g6 mb6" style="flex-wrap:wrap">';
      h+='<span class="bg bgd" style="min-width:64px;text-align:center">'+n.cls+'</span>';
      h+='<div style="flex:1;min-width:100px"><label style="font-size:11px;display:block;margin-bottom:2px">Taux %</label>';
      h+='<input class="fi" type="number" id="er_t_'+ei+'_'+ni+'" value="'+n.taux+'" min="0" max="100" style="padding:5px 8px"></div>';
      h+='<div style="flex:1;min-width:90px"><label style="font-size:11px;display:block;margin-bottom:2px">Candidats</label>';
      h+='<input class="fi" type="number" id="er_c_'+ei+'_'+ni+'" value="'+n.candidats+'" min="0" style="padding:5px 8px"></div>';
      h+='<div style="flex:1;min-width:80px"><label style="font-size:11px;display:block;margin-bottom:2px">Admis</label>';
      h+='<input class="fi" type="number" id="er_a_'+ei+'_'+ni+'" value="'+n.admis+'" min="0" style="padding:5px 8px"></div>';
      h+='</div>';
    });
    h+='</div>';
  });
  M('✏️ Modifier les Statistiques','Résultats aux examens nationaux',h,
    '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="_saveExamResults()">💾 Enregistrer tout</button>',true);
}

function _saveExamResults(){
  (DB.examResults||[]).forEach(function(er,ei){
    er.niveaux.forEach(function(n,ni){
      var t=document.getElementById('er_t_'+ei+'_'+ni);
      var c=document.getElementById('er_c_'+ei+'_'+ni);
      var a=document.getElementById('er_a_'+ei+'_'+ni);
      if(t)n.taux=Math.min(100,Math.max(0,parseInt(t.value)||0));
      if(c)n.candidats=parseInt(c.value)||0;
      if(a)n.admis=parseInt(a.value)||0;
    });
  });
  save();cm();
  toast('✅ Statistiques mises à jour');
  if(typeof vShowSec==='function') setTimeout(function(){vShowSec('resultats',null);},100);
}

function _delExamYear(ei){
  if(!confirm('Supprimer cette année scolaire ?'))return;
  DB.examResults.splice(ei,1);
  save();cm();toast('Année supprimée');
  setTimeout(mEditExamResults,80);
}

function mEditExamYear(ei){
  var er=DB.examResults[ei];if(!er)return;
  var h='<div class="fg mb10"><span class="fl">Libellé de l\'année *</span><input class="fi" id="ey_lbl" value="'+er.annee+'"></div>';
  h+='<div style="font-weight:700;font-size:13px;color:var(--ink3);margin-bottom:8px">Niveaux examinés</div>';
  h+='<div id="eyRows">';
  er.niveaux.forEach(function(n,ni){
    h+='<div class="fl2 fic g6 mb6" style="flex-wrap:wrap">'+
      '<input class="fi" id="ey_cls_'+ni+'" value="'+n.cls+'" style="width:80px;padding:5px 8px">'+
      '<div style="flex:1"><label style="font-size:11px">%</label><input class="fi" type="number" id="ey_t_'+ni+'" value="'+n.taux+'" min="0" max="100" style="padding:5px 8px"></div>'+
      '<div style="flex:1"><label style="font-size:11px">Cand.</label><input class="fi" type="number" id="ey_c_'+ni+'" value="'+n.candidats+'" style="padding:5px 8px"></div>'+
      '<div style="flex:1"><label style="font-size:11px">Admis</label><input class="fi" type="number" id="ey_a_'+ni+'" value="'+n.admis+'" style="padding:5px 8px"></div>'+
      '</div>';
  });
  h+='</div>';
  window._eyNi=er.niveaux.length;
  h+='<button class="btn bo sm mt6" onclick="_addNiveauRow()">➕ Ajouter un niveau</button><div id="ey_extra"></div>';
  M('✏️ '+er.annee,'Modifier cette année',h,
    '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="_saveExamYear('+ei+')">💾 Enregistrer</button>',true);
}

function _addNiveauRow(){
  var ni=window._eyNi||0;
  var ex=document.getElementById('ey_extra');if(!ex)return;
  ex.innerHTML+='<div class="fl2 fic g6 mb6" style="flex-wrap:wrap">'+
    '<input class="fi" id="ey_cls_'+ni+'" placeholder="Classe" style="width:80px;padding:5px 8px">'+
    '<div style="flex:1"><label style="font-size:11px">%</label><input class="fi" type="number" id="ey_t_'+ni+'" value="80" min="0" max="100" style="padding:5px 8px"></div>'+
    '<div style="flex:1"><label style="font-size:11px">Cand.</label><input class="fi" type="number" id="ey_c_'+ni+'" value="20" style="padding:5px 8px"></div>'+
    '<div style="flex:1"><label style="font-size:11px">Admis</label><input class="fi" type="number" id="ey_a_'+ni+'" value="16" style="padding:5px 8px"></div>'+
    '</div>';
  window._eyNi=ni+1;
}

function _saveExamYear(ei){
  var er=DB.examResults[ei];if(!er)return;
  var lbl=document.getElementById('ey_lbl');
  if(lbl)er.annee=lbl.value.trim()||er.annee;
  var newNiveaux=[];
  for(var ni=0;ni<(window._eyNi||er.niveaux.length);ni++){
    var cls=(document.getElementById('ey_cls_'+ni)?.value||'').trim();
    var t=parseInt(document.getElementById('ey_t_'+ni)?.value)||0;
    var ca=parseInt(document.getElementById('ey_c_'+ni)?.value)||0;
    var ad=parseInt(document.getElementById('ey_a_'+ni)?.value)||0;
    if(cls) newNiveaux.push({cls:cls,taux:Math.min(100,t),candidats:ca,admis:ad});
  }
  if(newNiveaux.length) er.niveaux=newNiveaux;
  save();cm();toast('✅ Année mise à jour');
  setTimeout(function(){if(typeof vShowSec==='function')vShowSec('resultats',null);},100);
}

function mAddExamYear(){
  if(!iA())return;
  var h='<div class="fg mb10"><span class="fl">Libellé de l\'année *</span><input class="fi" id="neyLbl" placeholder="Ex: 2024–2025"></div>';
  h+='<div style="font-weight:700;font-size:13px;color:var(--ink3);margin-bottom:8px">Niveaux examinés</div>';
  h+='<div id="neyRows">';
  [['3ème',85,40,34],['Tle A',78,25,20],['Tle C',90,18,16],['Tle D',82,14,12]].forEach(function(r,i){
    h+='<div class="fl2 fic g6 mb6" style="flex-wrap:wrap">'+
      '<input class="fi" id="ney_cls_'+i+'" value="'+r[0]+'" style="width:80px;padding:5px 8px">'+
      '<div style="flex:1"><label style="font-size:11px">%</label><input class="fi" type="number" id="ney_t_'+i+'" value="'+r[1]+'" style="padding:5px 8px"></div>'+
      '<div style="flex:1"><label style="font-size:11px">Cand.</label><input class="fi" type="number" id="ney_c_'+i+'" value="'+r[2]+'" style="padding:5px 8px"></div>'+
      '<div style="flex:1"><label style="font-size:11px">Admis</label><input class="fi" type="number" id="ney_a_'+i+'" value="'+r[3]+'" style="padding:5px 8px"></div>'+
      '</div>';
  });
  h+='</div>';
  window._neyCount=4;
  h+='<button class="btn bo sm mt6" onclick="(function(){var i=window._neyCount++;document.getElementById(\'neyRows\').innerHTML+=\'<div class=\\\"fl2 fic g6 mb6\\\"><input class=\\\"fi\\\" id=\\\"ney_cls_\'+i+\'\\\" placeholder=\\\"Classe\\\" style=\\\"width:80px;padding:5px 8px\\\"><div style=\\\"flex:1\\\"><label style=\\\"font-size:11px\\\">%</label><input class=\\\"fi\\\" type=\\\"number\\\" id=\\\"ney_t_\'+i+\'\\\" value=\\\"80\\\" style=\\\"padding:5px 8px\\\"></div><div style=\\\"flex:1\\\"><label style=\\\"font-size:11px\\\">Cand.</label><input class=\\\"fi\\\" type=\\\"number\\\" id=\\\"ney_c_\'+i+\'\\\" value=\\\"20\\\" style=\\\"padding:5px 8px\\\"></div><div style=\\\"flex:1\\\"><label style=\\\"font-size:11px\\\">Admis</label><input class=\\\"fi\\\" type=\\\"number\\\" id=\\\"ney_a_\'+i+\'\\\" value=\\\"16\\\" style=\\\"padding:5px 8px\\\"></div></div>\';})()">➕ Ajouter niveau</button>';
  M('➕ Nouvelle Année Scolaire','Ajouter des statistiques',h,
    '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="_saveNewExamYear()">💾 Ajouter</button>',true);
}

function _saveNewExamYear(){
  var lbl=(document.getElementById('neyLbl')?.value||'').trim();
  if(!lbl){toast('Libellé requis','warn');return;}
  var niveaux=[];
  for(var i=0;i<(window._neyCount||4);i++){
    var cls=(document.getElementById('ney_cls_'+i)?.value||'').trim();
    var t=parseInt(document.getElementById('ney_t_'+i)?.value)||0;
    var ca=parseInt(document.getElementById('ney_c_'+i)?.value)||0;
    var ad=parseInt(document.getElementById('ney_a_'+i)?.value)||0;
    if(cls) niveaux.push({cls:cls,taux:Math.min(100,t),candidats:ca,admis:ad});
  }
  if(!niveaux.length){toast('Ajoutez au moins un niveau','warn');return;}
  if(!DB.examResults)DB.examResults=[];
  DB.examResults.unshift({annee:lbl,niveaux:niveaux});
  save();cm();toast('✅ Année ajoutée : '+lbl);
  setTimeout(function(){if(typeof vShowSec==='function')vShowSec('resultats',null);},100);
}

