var _CV_DAYS=['Lundi','Mardi','Mercredi','Jeudi','Vendredi'];
var _CV_SLOTS=['07h30–09h10','09h10–10h50','11h10–12h50','14h00–15h40','15h40–17h20'];
var _chatPoll=null;
var _chatLastCount=0;

function _cvColor2(matiere){
  var m={'Mathématiques':'#3C8DFF','Français':'#DC2626','Anglais':'#059669','SVT':'#16a34a','Physique-Chimie':'#7C3AED','Histoire-Géographie':'#d97706','Philosophie':'#0891b2','Économie':'#db2777','Informatique':'#6366f1','Éducation Physique':'#f59e0b'};
  return m[matiere]||'#142554';
}
function _cvLight(hex){return hex+'1A';}
function _cvNow(){return new Date().toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'});}
function _cvInitDB2(){
  if(!DB.classesVirtuelles)DB.classesVirtuelles=[];
  if(!DB.cvMessages)DB.cvMessages=[];
  if(!DB.cvSoumissions)DB.cvSoumissions=[];
  if(!DB.cvPolls)DB.cvPolls=[];
  if(!DB.cvReactions)DB.cvReactions={};
  if(!DB.cvAnnonces)DB.cvAnnonces=[];
}
function _cvSenderName2(sid,role){
  if(role==='admin') return '🏫 Administration';
  var t=(DB.teachers||[]).find(function(x){return x.id===sid;});
  if(t) return '👨‍🏫 '+t.pre+' '+t.nom;
  var s=(DB.students||[]).find(function(x){return x.id===sid;});
  if(s) return s.pre+' '+s.nom;
  var va=(DB.visitorAccounts||[]).find(function(x){return x.id===sid;});
  if(va) return va.pre+' '+(va.nom||'');
  return 'Utilisateur';
}
function _cvSenderCol(sid){
  var cols=['#3C8DFF','#059669','#DC2626','#7C3AED','#D97706','#0891B2','#DB2777','#f59e0b'];
  var h=0;for(var i=0;i<sid.length;i++)h=(h<<5)-h+sid.charCodeAt(i);
  return cols[Math.abs(h)%cols.length];
}
function _cvGetMsgs2(cvId_){
  return (DB.cvMessages||[]).filter(function(m){return m.cvId===cvId_;});
}
function _cvGetReact(msgId){
  return (DB.cvReactions||{})[msgId]||{};
}

// ── CRÉER CLASSE V2 ────────────────────────────────────────────────
var _origCvAdminCreate=window.cvAdminCreate;
window.cvAdminCreate=function(){
  _cvInitDB2();
  var ensOpts='<option value="">-- Coordinateur --</option>'+(DB.teachers||[]).map(function(t){return '<option value="'+t.id+'">'+t.pre+' '+t.nom+' ('+t.mat2+')</option>';}).join('');
  var planOpts='<option value="gratuit">Gratuit</option>'+((DB.elearning&&DB.elearning.plans)||[]).map(function(p){return '<option value="'+p.id+'">'+p.nom+'</option>';}).join('');
  M('📚 Nouvelle Classe Virtuelle','Multi-matières · Emploi du temps · Chat en direct',
    '<div class="ib ibt mb12"><span>✨</span><span>Nouvelle classe enrichie : plusieurs matières, emploi du temps interactif et espace de discussion entre apprenants.</span></div>'+
    '<div class="fg2">'+
    '<div class="fg full"><span class="fl">Nom *</span><input class="fi" id="cvNom" placeholder="Ex: 3ème A — Révisions BEPC"></div>'+
    '<div class="fg"><span class="fl">Classe *</span><select class="fi" id="cvCls">'+CLS.map(function(c){return '<option>'+c+'</option>';}).join('')+'</select></div>'+
    '<div class="fg"><span class="fl">Coordinateur</span><select class="fi" id="cvEns">'+ensOpts+'</select></div>'+
    '<div class="fg"><span class="fl">Plan requis</span><select class="fi" id="cvPlan">'+planOpts+'</select></div>'+
    '<div class="fg"><span class="fl">Capacité max</span><input class="fi" id="cvCap" type="number" value="35" min="1" max="300"></div>'+
    '<div class="fg full"><span class="fl">Description</span><textarea class="fi" id="cvDesc" rows="2" placeholder="Objectifs pédagogiques..."></textarea></div>'+
    '</div>'+
    '<div style="background:var(--blb);border-radius:12px;padding:12px;margin-top:8px;border:1px solid var(--bld)">'+
    '<div class="semi s mb8" style="color:var(--bl)">📚 Matières (Ctrl/Cmd + clic pour plusieurs)</div>'+
    '<select class="fi" id="cvMatieres" multiple style="height:110px">'+SUBS.map(function(s){return '<option>'+s+'</option>';}).join('')+'</select></div>',
    '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="_cvSaveV2()">💾 Créer</button>'
  );
};

function _cvSaveV2(){
  var nom=(document.getElementById('cvNom')?.value||'').trim();
  if(!nom){toast('Nom requis','warn');return;}
  _cvInitDB2();
  var selMats=Array.from(document.querySelectorAll('#cvMatieres option:checked')).map(function(o){return o.value;});
  if(!selMats.length) selMats=[SUBS[0]];
  var cv={
    id:cvId(),nom:nom,
    classe:document.getElementById('cvCls')?.value||'',
    matieres:selMats,matiere:selMats[0],
    enseignantId:document.getElementById('cvEns')?.value||'',
    enseignants:{},
    planRequis:document.getElementById('cvPlan')?.value||'gratuit',
    desc:document.getElementById('cvDesc')?.value||'',
    capacite:parseInt(document.getElementById('cvCap')?.value)||35,
    eleves:[],sujets:[],emploiDuTemps:[],
    dateCreation:today(),statut:'active',version:2
  };
  if(cv.enseignantId&&selMats.length) cv.enseignants[selMats[0]]=cv.enseignantId;
  var plan=cv.planRequis;
  (DB.students||[]).filter(function(s){return s.cls===cv.classe;}).forEach(function(s){
    if(plan==='gratuit'||studentHasPlan(s.id,plan)) if(!cv.eleves.includes(s.id)) cv.eleves.push(s.id);
  });
  DB.classesVirtuelles.push(cv);save();cm();re();
  toast('✅ Classe créée · '+selMats.length+' matière(s) · '+cv.eleves.length+' élève(s)');
}

// ── GESTION MATIÈRES + PROFS ───────────────────────────────────────
window.cvAdminManageMatieres=function(cvId_){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});if(!cv)return;
  if(!cv.matieres)cv.matieres=[cv.matiere||SUBS[0]];
  if(!cv.enseignants)cv.enseignants={};
  var rows=cv.matieres.map(function(m){
    var tid=cv.enseignants[m]||'';
    var col=_cvColor2(m);
    var ensOpts='<option value="">-- Non assigné --</option>'+(DB.teachers||[]).map(function(t){return '<option value="'+t.id+'"'+(t.id===tid?' selected':'')+'>'+t.pre+' '+t.nom+'</option>';}).join('');
    return '<div class="fl2 fic g8 mb8" style="flex-wrap:wrap">'+
      '<span style="background:'+_cvLight(col)+';color:'+col+';border:1.5px solid '+col+'44;border-radius:20px;padding:4px 12px;font-size:12px;font-weight:700">'+m+'</span>'+
      '<select class="fi" id="matens_'+m.replace(/[^a-z]/gi,'_')+'" style="flex:1;min-width:140px;padding:7px 10px">'+ensOpts+'</select>'+
      '<button class="btn br2 xs" onclick="_cvDelMat(\''+cvId_+'\',\''+m+'\')">✕</button>'+
      '</div>';
  }).join('');
  var addOpts=SUBS.filter(function(s){return !(cv.matieres||[]).includes(s);}).map(function(s){return '<option>'+s+'</option>';}).join('');
  M('📚 Matières & Enseignants — '+cv.nom,'',
    '<div class="ib ibt mb12"><span>👨‍🏫</span><span>Chaque matière peut avoir son propre enseignant. Les apprenants voient toutes les matières.</span></div>'+
    (rows||'<div class="empty">Aucune matière</div>')+
    '<div class="fl2 fic g8 mt12" style="flex-wrap:wrap">'+
    '<select class="fi" id="addMatSel" style="flex:1;min-width:130px">'+addOpts+'</select>'+
    '<button class="btn bi sm" onclick="_cvAddMat(\''+cvId_+'\')">➕ Ajouter</button></div>',
    '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="_cvSaveMats(\''+cvId_+'\')">💾 Enregistrer</button>',true
  );
};

function _cvAddMat(cvId_){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});if(!cv)return;
  var m=document.getElementById('addMatSel')?.value;
  if(!m){toast('Sélectionnez','warn');return;}
  if(!cv.matieres)cv.matieres=[];
  if(cv.matieres.includes(m)){toast('Déjà présente','warn');return;}
  cv.matieres.push(m);save();cm();setTimeout(function(){window.cvAdminManageMatieres(cvId_);},80);toast('✓ '+m+' ajoutée');
}
function _cvDelMat(cvId_,m){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});if(!cv)return;
  cv.matieres=(cv.matieres||[]).filter(function(x){return x!==m;});
  if(cv.enseignants)delete cv.enseignants[m];
  save();cm();setTimeout(function(){window.cvAdminManageMatieres(cvId_);},80);
}
function _cvSaveMats(cvId_){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});if(!cv)return;
  if(!cv.enseignants)cv.enseignants={};
  (cv.matieres||[]).forEach(function(m){
    var sel=document.getElementById('matens_'+m.replace(/[^a-z]/gi,'_'));
    if(sel) cv.enseignants[m]=sel.value||'';
  });
  save();cm();re();toast('✅ Enseignants enregistrés');
}

// ── EMPLOI DU TEMPS ────────────────────────────────────────────────
window.cvAdminEmploiDuTemps=function(cvId_){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});if(!cv)return;
  if(!cv.emploiDuTemps)cv.emploiDuTemps=[];
  _renderEdtAdmin(cv);
};

function _renderEdtAdmin(cv){
  var g='<div class="cv-edt-grid" style="grid-template-columns:90px repeat(5,1fr)">';
  g+='<div class="cv-edt-head">⏰ Horaire</div>';
  _CV_DAYS.forEach(function(d){g+='<div class="cv-edt-head">'+d+'</div>';});
  _CV_SLOTS.forEach(function(slot){
    g+='<div class="cv-edt-slot">'+slot.replace('–','<br>')+'</div>';
    _CV_DAYS.forEach(function(day){
      var item=(cv.emploiDuTemps||[]).find(function(e){return e.day===day&&e.slot===slot;});
      if(item){
        var col=_cvColor2(item.matiere);
        var t=(DB.teachers||[]).find(function(x){return x.id===item.tid;})||{};
        g+='<div class="cv-edt-cell" onclick="_cvEdtEdit2(\''+cv.id+'\',\''+day+'\',\''+slot+'\')">'+
          '<div class="cv-edt-item" style="background:'+_cvLight(col)+';border-left:3px solid '+col+';color:'+col+'">'+
          '<div style="font-weight:800;font-size:11px">'+item.matiere+'</div>'+
          (t.nom?'<div style="font-size:10px;opacity:.75">'+t.pre[0]+'. '+t.nom+'</div>':'')+
          (item.salle?'<div style="font-size:9px;opacity:.6">'+item.salle+'</div>':'')+
          '</div></div>';
      } else {
        g+='<div class="cv-edt-cell" style="opacity:.35" onclick="_cvEdtEdit2(\''+cv.id+'\',\''+day+'\',\''+slot+'\')">'+
          '<div style="text-align:center;padding-top:14px;font-size:16px">＋</div></div>';
      }
    });
  });
  g+='</div>';
  M('📅 Emploi du Temps — '+cv.nom,'Cliquez pour ajouter/modifier un cours',
    '<div style="overflow-x:auto">'+g+'</div>',
    '<button class="btn bo" onclick="cm()">Fermer</button>',true);
}

function _cvEdtEdit2(cvId_,day,slot){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});if(!cv)return;
  var ex=(cv.emploiDuTemps||[]).find(function(e){return e.day===day&&e.slot===slot;});
  var mats=cv.matieres||[cv.matiere||SUBS[0]];
  var matOpts=mats.map(function(m){return '<option'+(ex&&ex.matiere===m?' selected':'')+'>'+m+'</option>';}).join('');
  var ensOpts='<option value="">-- Enseignant --</option>'+(DB.teachers||[]).map(function(t){return '<option value="'+t.id+'"'+(ex&&ex.tid===t.id?' selected':'')+'>'+t.pre+' '+t.nom+'</option>';}).join('');
  M((ex?'✏️ Modifier':'➕ Ajouter')+' un cours',day+' · '+slot,
    '<div class="fg2">'+
    '<div class="fg full"><span class="fl">Matière</span><select class="fi" id="edtMat2">'+matOpts+'</select></div>'+
    '<div class="fg full"><span class="fl">Enseignant</span><select class="fi" id="edtEns2">'+ensOpts+'</select></div>'+
    '<div class="fg full"><span class="fl">Salle / Lien visio</span><input class="fi" id="edtSalle2" value="'+(ex&&ex.salle||'')+'" placeholder="Salle A ou https://meet.google.com/..."></div>'+
    '</div>'+
    (ex?'<button class="btn br2 sm mt6" onclick="_cvEdtDel2(\''+cvId_+'\',\''+day+'\',\''+slot+'\')">🗑 Supprimer ce créneau</button>':''),
    '<button class="btn bo" onclick="cm();setTimeout(function(){window.cvAdminEmploiDuTemps(\''+cvId_+'\')},80)">← Retour</button>'+
    '<button class="btn bi" onclick="_cvEdtSave2(\''+cvId_+'\',\''+day+'\',\''+slot+'\')">💾 Enregistrer</button>'
  );
}

function _cvEdtSave2(cvId_,day,slot){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});if(!cv)return;
  if(!cv.emploiDuTemps)cv.emploiDuTemps=[];
  var mat=document.getElementById('edtMat2')?.value||'';
  if(!mat){toast('Matière requise','warn');return;}
  cv.emploiDuTemps=cv.emploiDuTemps.filter(function(e){return!(e.day===day&&e.slot===slot);});
  cv.emploiDuTemps.push({day:day,slot:slot,matiere:mat,tid:document.getElementById('edtEns2')?.value||'',salle:document.getElementById('edtSalle2')?.value||''});
  save();cm();toast('✅ Cours enregistré');
  setTimeout(function(){window.cvAdminEmploiDuTemps(cvId_);},80);
}

function _cvEdtDel2(cvId_,day,slot){
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});if(!cv)return;
  cv.emploiDuTemps=(cv.emploiDuTemps||[]).filter(function(e){return!(e.day===day&&e.slot===slot);});
  save();cm();toast('Créneau supprimé');
  setTimeout(function(){window.cvAdminEmploiDuTemps(cvId_);},80);
}

// ── CHAT + ESPACE INTERACTIF ────────────────────────────────────────
// Override _cvChatOpen pour utiliser le nouveau système enrichi
var _origCvChatOpen=typeof _cvChatOpen==='function'?_cvChatOpen:null;
window._cvChatOpen=function(cvId_,cv,uid,role){
  clearInterval(_chatPoll);
  _chatLastCount=-1;
  _renderCvSpace(cvId_,cv,uid,role);
  _chatPoll=setInterval(function(){
    var el=document.getElementById('cvChatMsgs');
    if(!el){clearInterval(_chatPoll);return;}
    var msgs=_cvGetMsgs2(cvId_);
    if(msgs.length!==_chatLastCount){_chatLastCount=msgs.length;_refreshMsgs(cvId_,uid,role);}
  },1800);
};

function _renderCvSpace(cvId_,cv,uid,role){
  _cvInitDB2();
  if(!cv.matieres)cv.matieres=[cv.matiere||SUBS[0]];
  var mats=cv.matieres;
  var isAdmin=iA&&iA();
  var isTeach=isEnseignant&&isEnseignant();
  var canPost=!!uid;
  var annonces=(DB.cvAnnonces||[]).filter(function(a){return a.cvId===cvId_;});
  var polls=(DB.cvPolls||[]).filter(function(p){return p.cvId===cvId_;});

  // Build emploi du temps view
  var edtHtml='';
  if((cv.emploiDuTemps||[]).length){
    edtHtml='<div style="overflow-x:auto"><div class="cv-edt-grid" style="grid-template-columns:90px repeat(5,1fr)">';
    edtHtml+='<div class="cv-edt-head">⏰</div>';
    _CV_DAYS.forEach(function(d){edtHtml+='<div class="cv-edt-head">'+d.substring(0,3)+'</div>';});
    _CV_SLOTS.forEach(function(slot){
      edtHtml+='<div class="cv-edt-slot" style="font-size:10px">'+slot.replace('–','<br>')+'</div>';
      _CV_DAYS.forEach(function(day){
        var item=(cv.emploiDuTemps||[]).find(function(e){return e.day===day&&e.slot===slot;});
        if(item){
          var col=_cvColor2(item.matiere);
          var t=(DB.teachers||[]).find(function(x){return x.id===item.tid;})||{};
          var lien=item.salle&&item.salle.startsWith('http')?'<a href="'+item.salle+'" target="_blank" style="font-size:9px;color:'+col+';display:block">🔗 Rejoindre</a>':'';
          edtHtml+='<div class="cv-edt-cell"><div class="cv-edt-item" style="background:'+_cvLight(col)+';border-left:3px solid '+col+';color:'+col+'">'+
            '<div style="font-weight:800;font-size:10px">'+item.matiere.substring(0,8)+'</div>'+
            (t.nom?'<div style="font-size:9px;opacity:.7">'+t.nom+'</div>':'')+lien+'</div></div>';
        } else {
          edtHtml+='<div class="cv-edt-cell"></div>';
        }
      });
    });
    edtHtml+='</div></div>';
  } else {
    edtHtml='<div class="empty"><div class="empty-ico">📅</div>Emploi du temps non encore configuré</div>';
  }

  // Matières grid
  var matHtml='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px">';
  mats.forEach(function(m){
    var tid=cv.enseignants&&cv.enseignants[m];
    var t=tid&&(DB.teachers||[]).find(function(x){return x.id===tid;});
    var col=_cvColor2(m);
    matHtml+='<div class="cv-mat-card" style="background:'+_cvLight(col)+';border:1.5px solid '+col+'33">'+
      '<div style="font-size:28px;margin-bottom:6px">📚</div>'+
      '<div style="font-weight:800;font-size:13px;color:'+col+'">'+m+'</div>'+
      (t?'<div style="font-size:11px;color:var(--ink3);margin-top:4px">'+t.pre+' '+t.nom+'</div>':
         '<div style="font-size:11px;color:var(--ink4);margin-top:4px">Non assigné</div>')+
      '<button class="btn sm mt8" style="background:'+col+';color:#fff;font-size:11px;padding:5px 10px;width:100%;justify-content:center" onclick="cvTeacherAddSujet(\''+cv.id+'\')">+ Sujet</button>'+
      '</div>';
  });
  matHtml+='</div>';

  // Polls html
  var pollsHtml=polls.map(function(p){
    var total=Math.max(1,(p.votes||[]).reduce(function(a,v){return a+(v.count||0);},0));
    var voted=(p.voters||[]).includes(uid);
    return '<div style="background:linear-gradient(135deg,#EFF6FF,#EDE9FE);border-radius:14px;padding:14px;margin-bottom:10px">'+
      '<div style="font-weight:700;font-size:14px;color:#142554;margin-bottom:10px">📊 '+p.question+'</div>'+
      (p.options||[]).map(function(opt,oi){
        var vc=(p.votes&&p.votes[oi]&&p.votes[oi].count)||0;
        var pct=Math.round((vc/total)*100);
        return '<div class="cv-poll-opt'+(voted?' voted':'')+'" onclick="_cvVote2(\''+p.id+'\','+oi+',\''+cvId_+'\',\''+uid+'\',\''+role+'\')">'+
          '<div style="flex:1"><div style="font-size:13px;font-weight:600;margin-bottom:4px">'+opt+'</div>'+
          '<div class="cv-poll-bar"><div class="cv-poll-fill" style="width:'+pct+'%"></div></div></div>'+
          '<span style="font-size:13px;font-weight:700;color:var(--gr);min-width:36px;text-align:right">'+pct+'%</span></div>';
      }).join('')+
      '<div style="font-size:11px;color:var(--ink4);margin-top:6px">'+(p.voters||[]).length+' vote(s)</div>'+
      ((isAdmin||isTeach)?'<button class="btn br2 xs mt6" onclick="_cvDelPoll2(\''+p.id+'\',\''+cvId_+'\')">🗑</button>':'')+
      '</div>';
  }).join('');

  // Annonces html
  var annHtml=annonces.slice().reverse().slice(0,5).map(function(a){
    return '<div style="background:linear-gradient(135deg,#FFF8E1,#FFF3C4);border-left:4px solid var(--gold);border-radius:0 12px 12px 0;padding:10px 12px;margin-bottom:8px">'+
      '<div style="font-size:10px;font-weight:700;color:var(--gold2);text-transform:uppercase;letter-spacing:.5px;margin-bottom:3px">📢 '+a.date+'</div>'+
      '<div style="font-size:13px;color:var(--ink2);line-height:1.6">'+a.text+'</div>'+
      ((isAdmin||isTeach)?'<button class="btn br2 xs mt4" onclick="_cvDelAnn(\''+a.id+'\',\''+cvId_+'\')">🗑</button>':'')+
      '</div>';
  }).join('');

  var tabs='<div class="cv-tabs">'+
    '<button class="cv-tab on" id="cvtC" onclick="_cvTab(this,\'cvPC\')">💬 Discussion</button>'+
    '<button class="cv-tab" id="cvtA" onclick="_cvTab(this,\'cvPA\')">📢 Annonces</button>'+
    '<button class="cv-tab" id="cvtP" onclick="_cvTab(this,\'cvPP\')">📊 Sondages</button>'+
    '<button class="cv-tab" id="cvtE" onclick="_cvTab(this,\'cvPE\')">📅 Emploi du temps</button>'+
    (mats.length>1?'<button class="cv-tab" id="cvtM" onclick="_cvTab(this,\'cvPM\')">📚 Matières ('+mats.length+')</button>':'')+
    '</div>';

  var body=tabs+
    // Chat panel
    '<div id="cvPC">'+
    (annonces.length?'<div style="margin-bottom:10px">'+annHtml+'</div>':'')+
    '<div class="cv-chat-wrap">'+
    '<div class="cv-chat-head">'+
    '<div class="fl2 fic fsb"><div><div style="font-weight:800;font-size:14px">💬 '+cv.nom+'</div>'+
    '<div style="font-size:11px;opacity:.6;margin-top:1px">'+cv.eleves.length+' apprenants · actualisation auto toutes les 2s</div></div>'+
    (isAdmin?'<span style="font-size:10px;opacity:.5">'+mats.join(' · ')+'</span>':'')+
    '</div></div>'+
    '<div class="cv-chat-msgs" id="cvChatMsgs"><div style="text-align:center;padding:20px;color:var(--ink4);font-size:13px">Chargement…</div></div>'+
    (canPost?
      '<div class="cv-chat-foot">'+
      '<input class="cv-chat-inp" id="cvChatInp" placeholder="Écrire un message (Entrée pour envoyer)…" onkeydown="if(event.key===\'Enter\'&&!event.shiftKey){event.preventDefault();_cvSend2(\''+cvId_+'\',\''+uid+'\',\''+role+'\');}">'+
      '<button class="cv-send-btn" onclick="_cvSend2(\''+cvId_+'\',\''+uid+'\',\''+role+'\')" title="Envoyer">➤</button>'+
      '</div>':
      '<div style="padding:10px;text-align:center;font-size:12px;color:var(--ink4)">Connectez-vous pour participer</div>')+
    '</div></div>'+
    // Annonces panel
    '<div id="cvPA" style="display:none">'+
    (annHtml||'<div class="empty"><div class="empty-ico">📢</div>Aucune annonce pour l\'instant</div>')+
    ((isAdmin||isTeach)?
      '<div style="margin-top:12px;background:var(--bg2);border-radius:12px;padding:14px">'+
      '<div class="semi s mb8">📢 Nouvelle annonce</div>'+
      '<textarea class="fi" id="cvAnnInp" rows="2" placeholder="Message pour tous les apprenants…"></textarea>'+
      '<button class="btn bi sm mt8" onclick="_cvPostAnn2(\''+cvId_+'\',\''+uid+'\',\''+role+'\')">📢 Publier</button></div>':'')
    +'</div>'+
    // Sondages panel
    '<div id="cvPP" style="display:none">'+
    (pollsHtml||'<div class="empty"><div class="empty-ico">📊</div>Aucun sondage actif</div>')+
    ((isAdmin||isTeach)?
      '<div style="margin-top:12px;background:var(--bg2);border-radius:12px;padding:14px">'+
      '<div class="semi s mb8">📊 Créer un sondage</div>'+
      '<input class="fi mb6" id="cvPollQ2" placeholder="Votre question…">'+
      ['Option 1 *','Option 2 *','Option 3','Option 4'].map(function(p,i){return '<input class="fi mb5" id="cvPollO'+(i+1)+'" placeholder="'+p+'">';}).join('')+
      '<button class="btn bi sm mt8" onclick="_cvCreatePoll2(\''+cvId_+'\',\''+uid+'\')">📊 Lancer le sondage</button></div>':'')
    +'</div>'+
    // Emploi du temps
    '<div id="cvPE" style="display:none">'+edtHtml+'</div>'+
    // Matières
    '<div id="cvPM" style="display:none">'+matHtml+'</div>';

  window._cvSpaceCvId=cvId_;
  window._cvSpaceUid=uid;
  window._cvSpaceRole=role;
  M('📚 '+cv.nom,'Classe virtuelle — '+cv.classe,body,'<button class="btn bo" onclick="clearInterval(_chatPoll);cm()">✕ Fermer</button>',true);
  setTimeout(function(){_refreshMsgs(cvId_,uid,role);},100);
}

function _cvTab(btn,panelId){
  document.querySelectorAll('.cv-tab').forEach(function(b){b.classList.remove('on');});
  btn.classList.add('on');
  ['cvPC','cvPA','cvPP','cvPE','cvPM'].forEach(function(id){
    var el=document.getElementById(id);if(el)el.style.display=id===panelId?'block':'none';
  });
}

function _buildMsgHtml(m,uid){
  var isMe=(m.senderId===uid);
  var name=_cvSenderName2(m.senderId,m.senderRole);
  var col=_cvSenderCol(m.senderId);
  var reactions=_cvGetReact(m.id);
  var reactHtml='';
  var cvId_=m.cvId;var role=window._cvSpaceRole||'';
  if(Object.keys(reactions).length){
    reactHtml='<div class="cv-react">';
    Object.entries(reactions).forEach(function(kv){
      var em=kv[0];var list=kv[1]||[];
      var has=list.includes(uid);
      reactHtml+='<button class="cv-react-btn'+(has?' active':'')+'" onclick="_cvReact2(\''+m.id+'\',\''+em+'\',\''+uid+'\',\''+cvId_+'\',\''+role+'\')">'+em+' '+list.length+'</button>';
    });
    reactHtml+='</div>';
  }
  var emBar='<div style="display:flex;gap:2px;margin-top:3px">'+
    ['👍','❤️','😂','🎉','💡'].map(function(em){
      return '<button class="cv-react-btn" style="font-size:11px;padding:1px 4px" onclick="_cvReact2(\''+m.id+'\',\''+em+'\',\''+uid+'\',\''+cvId_+'\',\''+role+'\')">'+em+'</button>';
    }).join('')+'</div>';
  return '<div class="cv-chat-msg '+(isMe?'me':'other')+'">'+
    (isMe?'':('<div class="cv-chat-av" style="background:'+col+'22;color:'+col+'">'+name[0].toUpperCase()+'</div>'))+
    '<div>'+
    (isMe?'':('<div style="font-size:10px;font-weight:700;color:'+col+';margin-bottom:2px">'+name+'</div>'))+
    '<div class="cv-chat-bubble">'+(m.text||'')+'</div>'+
    (m.fichier?'<div style="font-size:11px;margin-top:3px"><a href="'+m.fichier+'" target="_blank" style="color:'+(isMe?'#adf':'var(--bl)')+'">📎 '+m.fichierNom+'</a></div>':'')+
    reactHtml+emBar+
    '<div class="cv-chat-time">'+(isMe?'Vous · ':'')+m.time+'</div>'+
    '</div>'+
    (isMe?('<div class="cv-chat-av" style="background:'+col+'22;color:'+col+'">Moi</div>'):'')+
    '</div>';
}

function _refreshMsgs(cvId_,uid,role){
  var el=document.getElementById('cvChatMsgs');if(!el)return;
  var msgs=_cvGetMsgs2(cvId_);
  if(!msgs.length){el.innerHTML='<div style="text-align:center;padding:24px;color:var(--ink4);font-size:13px">Soyez le premier à écrire 👋</div>';return;}
  var atBot=(el.scrollHeight-el.scrollTop-el.clientHeight)<60;
  el.innerHTML=msgs.map(function(m){return _buildMsgHtml(m,uid);}).join('');
  if(atBot||msgs[msgs.length-1].senderId===uid) el.scrollTop=el.scrollHeight;
}

function _cvSend2(cvId_,uid,role){
  var inp=document.getElementById('cvChatInp');
  var txt=(inp?.value||'').trim();if(!txt)return;
  if(!DB.cvMessages)DB.cvMessages=[];
  DB.cvMessages.push({id:'msg_'+gid(),cvId:cvId_,senderId:uid,senderRole:role,text:txt,time:_cvNow(),date:today(),fichier:'',fichierNom:''});
  if(DB.cvMessages.length>600) DB.cvMessages=DB.cvMessages.slice(-600);
  save();inp.value='';
  _chatLastCount=DB.cvMessages.filter(function(m){return m.cvId===cvId_;}).length;
  _refreshMsgs(cvId_,uid,role);
}

function _cvReact2(msgId,emoji,uid,cvId_,role){
  if(!DB.cvReactions)DB.cvReactions={};
  if(!DB.cvReactions[msgId])DB.cvReactions[msgId]={};
  if(!DB.cvReactions[msgId][emoji])DB.cvReactions[msgId][emoji]=[];
  var list=DB.cvReactions[msgId][emoji];
  var idx=list.indexOf(uid);
  if(idx>=0) list.splice(idx,1); else list.push(uid);
  if(!list.length)delete DB.cvReactions[msgId][emoji];
  save();_refreshMsgs(cvId_,uid,role);
}

function _cvPostAnn2(cvId_,uid,role){
  var txt=(document.getElementById('cvAnnInp')?.value||'').trim();
  if(!txt){toast('Rédigez l\'annonce','warn');return;}
  if(!DB.cvAnnonces)DB.cvAnnonces=[];
  DB.cvAnnonces.push({id:'ann_'+gid(),cvId:cvId_,text:txt,date:today(),uid:uid});
  var inp=document.getElementById('cvAnnInp');if(inp)inp.value='';
  save();toast('📢 Annonce publiée !');
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});
  if(cv){cm();setTimeout(function(){window._cvChatOpen(cvId_,cv,uid,role);},80);}
}

function _cvDelAnn(annId,cvId_){
  DB.cvAnnonces=(DB.cvAnnonces||[]).filter(function(a){return a.id!==annId;});
  save();re();toast('Annonce supprimée');
}

function _cvCreatePoll2(cvId_,uid){
  var q=(document.getElementById('cvPollQ2')?.value||'').trim();
  if(!q){toast('Question requise','warn');return;}
  var opts=[];
  for(var i=1;i<=4;i++){var o=(document.getElementById('cvPollO'+i)?.value||'').trim();if(o)opts.push(o);}
  if(opts.length<2){toast('Minimum 2 options','warn');return;}
  if(!DB.cvPolls)DB.cvPolls=[];
  DB.cvPolls.push({id:'poll_'+gid(),cvId:cvId_,question:q,options:opts,votes:opts.map(function(){return{count:0};}),voters:[],uid:uid,date:today()});
  save();toast('📊 Sondage créé !');
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});
  if(cv){cm();setTimeout(function(){window._cvChatOpen(cvId_,cv,uid,window._cvSpaceRole||'admin');},80);}
}

function _cvVote2(pollId,oi,cvId_,uid,role){
  var p=(DB.cvPolls||[]).find(function(x){return x.id===pollId;});if(!p)return;
  if(!p.voters)p.voters=[];
  if(p.voters.includes(uid)){toast('Vous avez déjà voté','warn');return;}
  p.voters.push(uid);
  if(!p.votes)p.votes=p.options.map(function(){return{count:0};});
  if(!p.votes[oi])p.votes[oi]={count:0};
  p.votes[oi].count++;
  save();toast('✅ Vote enregistré');
  var cv=(DB.classesVirtuelles||[]).find(function(c){return c.id===cvId_;});
  if(cv){cm();setTimeout(function(){window._cvChatOpen(cvId_,cv,uid,role);},80);}
}

function _cvDelPoll2(pollId,cvId_){
  DB.cvPolls=(DB.cvPolls||[]).filter(function(p){return p.id!==pollId;});
  save();re();toast('Sondage supprimé');
}

// Patch: ajouter boutons EDT + Matières dans la liste admin des classes
var _origPgCVAdmin=typeof pgClassesVirtuellesAdmin==='function'?pgClassesVirtuellesAdmin:null;
if(_origPgCVAdmin){
  pgClassesVirtuellesAdmin=function(){
    var h=_origPgCVAdmin();
    // Injecter boutons EDT et Matières dans les actions du tableau
    h=h.replace(/(<button class="btn bo xs" onclick="cvAdminViewSujets\('([^']+)'\)">📝 Sujets<\/button>)/g,
      function(match,btn,id){
        return '<button class="btn bo xs" onclick="window.cvAdminManageMatieres(\''+id+'\')">📚 Matières</button>'+
               '<button class="btn bo xs" onclick="window.cvAdminEmploiDuTemps(\''+id+'\')">📅 EDT</button>'+btn;
      });
    return h;
  };
}

