function _saveWAGroupe(){
  var niv = (_ge('wgNiveau')?.value||'').trim();
  var nom = (_ge('wgNom')?.value||'').trim();
  var lien= (_ge('wgLien')?.value||'').trim();
  if(!niv||!nom||!lien){ toast('Remplissez tous les champs','warn'); return; }
  if(!lien.startsWith('https://chat.whatsapp.com/') && !lien.startsWith('https://wa.me/')){
    toast('Le lien doit commencer par https://chat.whatsapp.com/ ou https://wa.me/','warn'); return;
  }
  if(!DB.whatsappGroupes) DB.whatsappGroupes=[];
  DB.whatsappGroupes.push({ id:gid(), niveau:niv, nom:nom, lien:lien, accessMode:(_ge('wgMode')?.value||'libre'), plansRequis:[], actif: _ge('wgActif').value==='1' });
  save(); cm(); mWAGroupes(); toast('âœ… Groupe enregistré');
}

function _delWAGroupe(id){
  if(!confirm('Supprimer ce groupe ?')) return;
  DB.whatsappGroupes=(DB.whatsappGroupes||[]).filter(function(g){ return g.id!==id; });
  save(); cm(); mWAGroupes(); toast('Groupe supprimé');
}

function mEditWAGroupe(id){
  var g = (DB.whatsappGroupes||[]).find(function(x){ return x.id===id; });
  if(!g) return;
  var _eModes=['libre','paiement','abonnement','manuel'];
  var _eLbls={libre:'Libre',paiement:'Paiement',abonnement:'Abonnement',manuel:'Manuel'};
  var _eModeOpts=_eModes.map(function(m){return '<option value="'+m+'"'+((g.accessMode||'libre')===m?' selected':'')+'>'+_eLbls[m]+'</option>';}).join('');
  M('âœ️ Modifier le groupe','',
    '<div class="fg"><span class="fl">Niveau</span>'
    +'<input class="fi" id="egNiv" value="'+_esc(g.niveau)+'"></div>'
    +'<div class="fg"><span class="fl">Nom</span>'
    +'<input class="fi" id="egNom" value="'+_esc(g.nom)+'"></div>'
    +'<div class="fg"><span class="fl">Lien</span>'
    +'<input class="fi" id="egLien" value="'+_esc(g.lien)+'"></div>'
    +'<div class="fg"><span class="fl">Mode d\'acces</span>'
    +'<select class="fi" id="egMode">'+_eModeOpts+'</select></div>'
    +'<div class="fg"><span class="fl">Actif</span>'
    +'<select class="fi" id="egActif">'
    +'<option value="1"'+(g.actif?' selected':'')+'>Oui</option>'
    +'<option value="0"'+(!g.actif?' selected':'')+'>Non</option>'
    +'</select></div>',
    '<button class="btn bo" onclick="cm()">Annuler</button>'
    +'<button class="btn bi" onclick="_updateWAGroupe(\''+id+'\')">💾 Mettre à jour</button>'
  );
}

function _updateWAGroupe(id){
  var idx = (DB.whatsappGroupes||[]).findIndex(function(g){ return g.id===id; });
  if(idx<0) return;
  DB.whatsappGroupes[idx].niveau = (_ge('egNiv')?.value||'').trim();
  DB.whatsappGroupes[idx].nom    = (_ge('egNom')?.value||'').trim();
  DB.whatsappGroupes[idx].lien   = (_ge('egLien')?.value||'').trim();
  DB.whatsappGroupes[idx].accessMode = (_ge('egMode')?.value||'libre');
  DB.whatsappGroupes[idx].actif  = _ge('egActif')?.value==='1';
  save(); cm(); mWAGroupes(); toast('âœ… Groupe mis à jour');
}

// ── CONTRÔLE D'ACCÈS AUX GROUPES WHATSAPP ───────────────────────────────────

// Vérifie si un compte (visiteur ou élève) est éligible pour un groupe WA
function _waGroupAccess(grp, acc, stu){
  if(!grp||!grp.actif) return{eligible:false,reason:'Groupe inactif'};
  var mode=grp.accessMode||'libre';
  if(mode==='libre') return{eligible:true,reason:'Accès libre'};
  if(mode==='manuel') return{eligible:false,reason:'Validation manuelle requise',canManuel:true};
  if(mode==='paiement'){
    if(stu) return{eligible:stu.stat==='Payé',reason:stu.stat==='Payé'?'Scolarité réglée':'Scolarité non réglée ('+stu.stat+')'};
    if(acc){
      var paid=(DB.payments||[]).find(function(p){return p.eid===acc.id&&p.stat==='Payé';});
      var cPaid=(DB.payAttempts||[]).find(function(p){return p.status==='confirmed'&&(p.label||'').indexOf(acc.id)>=0;});
      return{eligible:!!(paid||cPaid),reason:(paid||cPaid)?'Paiement confirmé':'Aucun paiement confirmé'};
    }
    return{eligible:false,reason:'Paiement requis'};
  }
  if(mode==='abonnement'){
    var plansReq=grp.plansRequis||[];
    if(!plansReq.length) return{eligible:true,reason:'Abonnement (aucun plan requis)'};
    var hasP=function(list){return plansReq.some(function(p){return(list||[]).indexOf(p)>=0;});};
    if(acc){
      if(hasP(acc.plans)) return{eligible:true,reason:'Abonnement actif'};
      // FIX BUG typo : 'Activé' (avec accent) est le statut écrit par activerAbonnement()
      // On accepte aussi 'Actif' pour compatibilité avec d'éventuels anciens enregistrements
      var _aboActif=function(a){return a.statut==='Activé'||a.statut==='Actif';};
      var aboE=(DB.elearning&&DB.elearning.abonnements||[]).find(function(a){
        return _aboActif(a)&&(a.accountId===acc.id||hasP([a.plan]));
      });
      return{eligible:!!aboE,reason:aboE?'Abonnement e-learning actif':'Abonnement requis ('+plansReq.join(', ')+')'};
    }
    if(stu){
      var _aboActif2=function(a){return a.statut==='Activé'||a.statut==='Actif';};
      var stuA=(DB.elearning&&DB.elearning.abonnements||[]).find(function(a){
        return _aboActif2(a)&&a.classe===stu.cls&&hasP([a.plan]);
      });
      return{eligible:!!stuA,reason:stuA?'Abonnement actif':'Abonnement requis'};
    }
    return{eligible:false,reason:'Abonnement requis'};
  }
  return{eligible:false,reason:'Conditions non remplies'};
}

// Infobulles par mode
function _wacModeInfo(mode){
  var info={libre:'Tous les utilisateurs peuvent être invités sans condition.',abonnement:'Seuls les utilisateurs ayant souscrit à un des plans sélectionnés peuvent être invités.',paiement:'Seuls les élèves/visiteurs ayant réglé leur scolarité peuvent être invités.',manuel:'Aucune invitation automatique — l\'admin invite manuellement chaque personne.'};
  return info[mode]||'';
}

// Toggle champ plans dans la modale de config
function _wacModeToggle(){
  var mode=(_ge('wacMode')?.value)||'libre';
  var wrap=_ge('wacPlansWrap');
  if(wrap) wrap.style.display=mode==='abonnement'?'':'none';
  var infEl=_ge('wacInfoTxt');
  if(infEl) infEl.textContent=_wacModeInfo(mode);
}

// Modale de configuration du mode d'accès d'un groupe
function _waConfigAccess(grpId){
  var grp=(DB.whatsappGroupes||[]).find(function(g){return g.id===grpId;});
  if(!grp) return;
  var plans=(DB.elearning&&DB.elearning.plans)||[];
  var modeLabels={libre:'🟢 Libre — tout le monde',abonnement:'🔵 Abonnement — plans e-learning requis',paiement:'💛 Paiement — scolarité réglée requise',manuel:'⚙️ Manuel — validation admin uniquement'};
  var modeOpts=['libre','abonnement','paiement','manuel'].map(function(m){
    return '<option value="'+m+'"'+((grp.accessMode||'libre')===m?' selected':'')+'>'+modeLabels[m]+'</option>';
  }).join('');
  var planOpts=plans.map(function(p){
    return '<option value="'+p.id+'"'+((grp.plansRequis||[]).indexOf(p.id)>=0?' selected':'')+'>'+_esc(p.nom)+'</option>';
  }).join('');
  var curMode=grp.accessMode||'libre';
  M('🔧 Accès — '+_esc(grp.nom),'Conditions requises pour rejoindre ce groupe WhatsApp',
    '<div class="ib ibi mb12"><span>💡</span><span id="wacInfoTxt">'+_wacModeInfo(curMode)+'</span></div>'
    +'<div class="fg"><span class="fl">Mode d\'accès</span>'
    +'<select class="fi" id="wacMode" onchange="_wacModeToggle()">'+modeOpts+'</select></div>'
    +'<div class="fg" id="wacPlansWrap" style="display:'+(curMode==='abonnement'?'':'none')+'">'
    +'<span class="fl">Plans e-learning requis</span>'
    +(planOpts
      ?'<select class="fi" id="wacPlans" multiple size="4" style="height:90px">'+planOpts+'</select><div style="font-size:11px;color:var(--ink4);margin-top:4px">Ctrl+clic pour sélectionner plusieurs plans</div>'
      :'<div class="ib ibt xs2"><span>⚠️</span><span>Aucun plan e-learning configuré. Créez d\'abord des plans dans E-Learning → Plans.</span></div>')
    +'</div>',
    '<button class="btn bo" onclick="cm()">Annuler</button>'
    +'<button class="btn bi" onclick="_saveWAConfig(\''+grpId+'\')">💾 Enregistrer</button>'
  );
}

// Enregistre la config d'accès
function _saveWAConfig(grpId){
  var idx=(DB.whatsappGroupes||[]).findIndex(function(g){return g.id===grpId;});
  if(idx<0) return;
  var mode=_ge('wacMode')?.value||'libre';
  var plansEl=_ge('wacPlans');
  var plans=plansEl?Array.from(plansEl.selectedOptions).map(function(o){return o.value;}):[];
  DB.whatsappGroupes[idx].accessMode=mode;
  DB.whatsappGroupes[idx].plansRequis=plans;
  save(); cm(); re(); toast('✅ Accès configuré — '+DB.whatsappGroupes[idx].nom);
}

// Inviter en masse les comptes éligibles d'un groupe
function _waInviteEligibles(grpId){
  var grp=(DB.whatsappGroupes||[]).find(function(g){return g.id===grpId;});
  if(!grp) return;
  var eligible=(DB.visitorAccounts||[]).filter(function(a){
    return a.cls===grp.niveau&&a.groupeStatut!=='invite'&&_waGroupAccess(grp,a,null).eligible;
  });
  if(!eligible.length){toast('Aucun visiteur éligible non encore invité','warn');return;}
  eligible.forEach(function(a){_sendWAGroupInvite(a.id);});
  toast('📲 '+eligible.length+' invitation(s) envoyée(s)');
}

// Accorder l'accès manuellement à un visiteur
function _waManuelInvite(accId){
  var idx=(DB.visitorAccounts||[]).findIndex(function(a){return a.id===accId;});
  if(idx<0) return;
  DB.visitorAccounts[idx].groupeStatut='invite';
  DB.visitorAccounts[idx].dateInvitGroupe=today();
  save(); re();
  _sendWAGroupInvite(accId);
  toast('✅ Accès accordé manuellement');
}

// ── PAGE ADMIN : GESTION ACCÈS GROUPES WA ───────────────────────────────────
function pgWAAccess(){
  if(!iA()) return na();
  if(!DB.whatsappGroupes) DB.whatsappGroupes=[];
  var plans=(DB.elearning&&DB.elearning.plans)||[];
  var planLabel=function(pid){var p=plans.find(function(x){return x.id===pid;});return p?_esc(p.nom):pid;};

  var totalActifs=(DB.whatsappGroupes||[]).filter(function(g){return g.actif;}).length;
  var allAccs=DB.visitorAccounts||[];
  var nInvited=allAccs.filter(function(a){return a.groupeStatut==='invite';}).length;
  var nPending=allAccs.filter(function(a){return !a.groupeStatut||a.groupeStatut==='en_attente';}).length;
  var nEligible=0;
  (DB.whatsappGroupes||[]).filter(function(g){return g.actif;}).forEach(function(grp){
    allAccs.filter(function(a){return a.cls===grp.niveau&&a.groupeStatut!=='invite'&&_waGroupAccess(grp,a,null).eligible;}).forEach(function(){nEligible++;});
  });

  var modeCol={libre:'#059669',abonnement:'#3C8DFF',paiement:'#D97706',manuel:'#7C3AED'};
  var modeTxt={libre:'🟢 Libre',abonnement:'🔵 Abonnement',paiement:'💛 Paiement',manuel:'⚙️ Manuel'};

  var h='<div class="fl2 fic fsb mb16 fw g8">';
  h+='<div style="font-family:Montserrat,sans-serif;font-size:20px;font-weight:800;color:#142554">📱 Accès Groupes WhatsApp</div>';
  h+='<div class="fl2 g8"><button class="btn bi" onclick="mWAGroupes()">⚙️ Configurer les groupes</button>';
  h+='<button class="btn" style="background:#25D366;color:#fff" onclick="mWAPendingMembers()">⏳ Inscriptions en attente</button></div></div>';

  h+='<div class="sg" style="grid-template-columns:repeat(4,1fr);margin-bottom:20px">';
  h+='<div class="sc scb"><div class="sci">📱</div><div class="scl">Groupes actifs</div><div class="scv vb">'+totalActifs+'</div></div>';
  h+='<div class="sc scgr"><div class="sci">✅</div><div class="scl">Déjà invités</div><div class="scv vgr">'+nInvited+'</div></div>';
  h+='<div class="sc" style="background:#FFF3CD"><div class="sci">🎯</div><div class="scl">Éligibles non invités</div><div class="scv" style="color:#D97706">'+nEligible+'</div></div>';
  h+='<div class="sc scr"><div class="sci">⏳</div><div class="scl">En attente</div><div class="scv vr">'+nPending+'</div></div>';
  h+='</div>';

  var activeGrps=(DB.whatsappGroupes||[]).filter(function(g){return g.actif;});
  if(!activeGrps.length){
    h+='<div class="card"><div class="empty"><div class="empty-ico">📱</div>Aucun groupe WhatsApp actif</div></div>';
    return h;
  }

  activeGrps.forEach(function(grp){
    var mode=grp.accessMode||'libre';
    var mc=modeCol[mode]||'#142554';
    var mt=modeTxt[mode]||mode;
    var plansReq=grp.plansRequis||[];
    var students=(DB.students||[]).filter(function(s){return s.cls===grp.niveau;});
    var visitors=allAccs.filter(function(a){return a.cls===grp.niveau;});
    var eligibleNotInvited=visitors.filter(function(a){return a.groupeStatut!=='invite'&&_waGroupAccess(grp,a,null).eligible;}).length;

    h+='<div class="card mb16">';
    h+='<div class="fl2 fic fsb mb14 fw g8">';
    h+='<div class="fl2 fic g10"><span style="font-size:22px">📱</span><div>';
    h+='<div style="font-family:Montserrat,sans-serif;font-size:16px;font-weight:800;color:#142554">'+_esc(grp.nom)+'</div>';
    h+='<div style="font-size:12px;color:var(--ink3);margin-top:2px">Niveau : <strong>'+_esc(grp.niveau)+'</strong>';
    if(grp.lien) h+=' · <a href="'+_esc(grp.lien)+'" target="_blank" style="color:#25D366;font-weight:700">Lien groupe ↗</a>';
    h+='</div></div></div>';
    h+='<div class="fl2 fic g8 fw">';
    h+='<span style="background:'+mc+'22;color:'+mc+';border:1px solid '+mc+'44;padding:5px 12px;border-radius:20px;font-size:12px;font-weight:700">'+mt+'</span>';
    if(mode==='abonnement'&&plansReq.length) h+='<span style="font-size:11px;color:var(--ink3)">Plans : '+plansReq.map(planLabel).join(', ')+'</span>';
    h+='<button class="btn bo xs" onclick="_waConfigAccess(\''+grp.id+'\')">🔧 Modifier accès</button>';
    if(eligibleNotInvited>0) h+='<button class="btn xs" style="background:#25D366;color:#fff" onclick="_waInviteEligibles(\''+grp.id+'\')">📲 Inviter '+eligibleNotInvited+' éligible(s)</button>';
    h+='</div></div>';

    // Table élèves
    if(students.length){
      h+='<div style="margin-bottom:14px">';
      h+='<div style="font-size:11px;font-weight:700;color:#142554;text-transform:uppercase;letter-spacing:.8px;margin-bottom:8px">👨‍🎓 Élèves ('+students.length+')</div>';
      h+='<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">';
      h+='<thead><tr style="background:#F8FAFF"><th style="padding:6px 10px;text-align:left">Élève</th><th style="padding:6px 8px">Scolarité</th><th style="padding:6px 8px">Éligibilité</th><th style="padding:6px 8px">Invitation</th></tr></thead><tbody>';
      students.forEach(function(s){
        var a2=_waGroupAccess(grp,null,s);
        var ec=a2.eligible?'#059669':'#DC2626';
        var vAcc=(DB.visitorAccounts||[]).find(function(a){return a.cls===s.cls&&(a.nom.toLowerCase()===s.nom.toLowerCase()||a.pre.toLowerCase()===s.pre.toLowerCase());});
        var wasInvited=vAcc&&vAcc.groupeStatut==='invite';
        h+='<tr style="border-bottom:1px solid var(--bg2)">';
        h+='<td style="padding:6px 10px"><div style="font-weight:600">'+_esc(s.nom)+' '+_esc(s.pre)+'</div><div style="font-size:10px;color:var(--ink4)">'+_esc(s.mat)+'</div></td>';
        h+='<td style="padding:6px 8px;text-align:center"><span class="bg '+(s.stat==='Payé'?'bgg':'bgr')+' xs">'+_esc(s.stat)+'</span></td>';
        h+='<td style="padding:6px 8px;text-align:center"><span style="color:'+ec+';font-size:11px;font-weight:600">'+(a2.eligible?'✅':'❌')+' '+_esc(a2.reason)+'</span></td>';
        h+='<td style="padding:6px 8px;text-align:center">';
        if(wasInvited){h+='<span style="color:#059669;font-size:11px;font-weight:600">✅ Invité</span>';}
        else if(a2.eligible&&vAcc){h+='<button class="btn xs" style="background:#25D366;color:#fff" onclick="_sendWAGroupInvite(\''+vAcc.id+'\')">📲 Inviter</button>';}
        else if(a2.eligible){h+='<span style="color:#059669;font-size:11px">✅ Éligible</span>';}
        else if(a2.canManuel&&vAcc){h+='<button class="btn xs bo" onclick="_waManuelInvite(\''+vAcc.id+'\')">⚙️ Accorder</button>';}
        else{h+='<span style="color:#9CA3AF;font-size:10px">—</span>';}
        h+='</td></tr>';
      });
      h+='</tbody></table></div></div>';
    }

    // Table visiteurs
    if(visitors.length){
      h+='<div>';
      h+='<div style="font-size:11px;font-weight:700;color:#142554;text-transform:uppercase;letter-spacing:.8px;margin-bottom:8px">🌐 Comptes visiteurs ('+visitors.length+')</div>';
      h+='<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">';
      h+='<thead><tr style="background:#F8FAFF"><th style="padding:6px 10px;text-align:left">Visiteur</th><th style="padding:6px 8px">Statut</th><th style="padding:6px 8px">Abonnements</th><th style="padding:6px 8px">Éligibilité</th><th style="padding:6px 8px">Invitation</th></tr></thead><tbody>';
      visitors.forEach(function(a){
        var a2=_waGroupAccess(grp,a,null);
        var ec=a2.eligible?'#059669':'#DC2626';
        h+='<tr style="border-bottom:1px solid var(--bg2)">';
        h+='<td style="padding:6px 10px"><div style="font-weight:600">'+_esc(a.pre)+' '+_esc(a.nom)+'</div><div style="font-size:10px;color:var(--ink4)">'+_esc(a.tel||a.email||'—')+'</div></td>';
        h+='<td style="padding:6px 8px;text-align:center"><span class="bg '+(a.statut==='actif'?'bgg':'bgr')+' xs">'+_esc(a.statut||'—')+'</span></td>';
        h+='<td style="padding:6px 8px;font-size:10px;color:var(--ink3)">'+((a.plans||[]).map(planLabel).join(', ')||'—')+'</td>';
        h+='<td style="padding:6px 8px;text-align:center"><span style="color:'+ec+';font-size:11px;font-weight:600">'+(a2.eligible?'✅':'❌')+' '+_esc(a2.reason)+'</span></td>';
        h+='<td style="padding:6px 8px;text-align:center">';
        if(a.groupeStatut==='invite'){
          h+='<div style="font-size:10px;color:#059669;font-weight:700">✅ Invité '+_esc(a.dateInvitGroupe||'')+'</div>';
          h+='<button class="btn xs bo mt2" onclick="_sendWAGroupInvite(\''+a.id+'\')">🔄 Renvoyer</button>';
        } else if(a2.eligible){
          h+='<button class="btn xs" style="background:#25D366;color:#fff" onclick="_validerEtInviter(\''+a.id+'\')">📲 Inviter</button>';
        } else if(a2.canManuel){
          h+='<button class="btn xs bo" onclick="_waManuelInvite(\''+a.id+'\')">⚙️ Accorder</button>';
        } else {
          h+='<span style="color:#9CA3AF;font-size:10px">Non éligible</span>';
        }
        h+='</td></tr>';
      });
      h+='</tbody></table></div></div>';
    }

    if(!students.length&&!visitors.length){
      h+='<div class="empty xs2">Aucun élève ou visiteur inscrit dans cette classe</div>';
    }
    h+='</div>'; // card
  });

  return h;
}

// Dashboard inscriptions en attente d'invitation groupe
function mWAPendingMembers(){
  if(!iA()) return;

  var vPending=(DB.visitorAccounts||[])
    .filter(function(a){return a.groupeStatut==='en_attente'||!a.groupeStatut;})
    .map(function(a){return Object.assign({},a,{_src:'visitor'});});
  var vInvited=(DB.visitorAccounts||[])
    .filter(function(a){return a.groupeStatut==='invite';})
    .map(function(a){return Object.assign({},a,{_src:'visitor'});});
  var ePending=(DB.students||[])
    .filter(function(s){return !s.waInvited;})
    .map(function(s){return Object.assign({},s,{_src:'eleve',pre:s.pre||s.prenom||'',nom:s.nom||'',tel:s.tel||s.phone||'',cls:s.cls||s.classe||'',dateInscription:s.dateInscription||s.created||''});});
  var eInvited=(DB.students||[])
    .filter(function(s){return s.waInvited;})
    .map(function(s){return Object.assign({},s,{_src:'eleve',pre:s.pre||s.prenom||'',nom:s.nom||'',tel:s.tel||s.phone||'',cls:s.cls||s.classe||'',dateInvitGroupe:s.dateInvitGroupe||''});});

  var pending=vPending.concat(ePending);
  var invited=vInvited.concat(eInvited);

  // Helper bouton : utilise data-id + data-action pour éviter tout problème de quoting
  function mkBtn(action,id,style,label){
    return '<button class="btn sm" style="'+style+'" data-waid="'+_esc(id)+'" data-waaction="'+action+'" onclick="_waBtnDispatch(this)">'+label+'</button>';
  }

  function badge(src){
    return src==='eleve'
      ? '<span style="font-size:.68rem;background:#EDE9FE;color:#5B21B6;padding:1px 5px;border-radius:4px;margin-left:4px">&#127979; El&egrave;ve</span>'
      : '<span style="font-size:.68rem;background:#E0F2FE;color:#0369A1;padding:1px 5px;border-radius:4px;margin-left:4px">&#127760; Visiteur</span>';
  }

  function rowPending(a){
    var btn1=a._src==='eleve'
      ? mkBtn('inviterEleve',a.id,'background:#25D366;color:#fff;margin:2px','&#9989; Valider + Inviter')
      : mkBtn('validerVisiteur',a.id,'background:#25D366;color:#fff;margin:2px','&#9989; Valider + Inviter');
    var btn2=a._src==='eleve'
      ? mkBtn('envoyerEleve',a.id,'background:#142554;color:#fff;margin:2px','&#128242; Invitation seule')
      : mkBtn('invitationVisiteur',a.id,'background:#142554;color:#fff;margin:2px','&#128242; Invitation seule');
    return '<tr>'
      +'<td style="padding:8px 10px"><strong>'+_esc(a.pre)+' '+_esc(a.nom)+'</strong>'+badge(a._src)+'<br>'
      +'<span style="font-size:.75rem;color:#555">'+_esc(a.cls||'&mdash;')+'</span></td>'
      +'<td style="padding:8px 10px;font-size:.85rem">'+_esc(a.tel||'&mdash;')+'</td>'
      +'<td style="padding:8px 10px;font-size:.8rem;color:#555">'+_esc(a.dateInscription||'&mdash;')+'</td>'
      +'<td style="padding:8px 6px;text-align:center">'+btn1+btn2+'</td>'
      +'</tr>';
  }

  function rowInvited(a){
    var btn=a._src==='eleve'
      ? mkBtn('envoyerEleve',a.id,'background:#142554;color:#fff','&#128257; Renvoyer')
      : mkBtn('invitationVisiteur',a.id,'background:#142554;color:#fff','&#128257; Renvoyer');
    return '<tr style="opacity:.75">'
      +'<td style="padding:6px 10px">'+_esc(a.pre)+' '+_esc(a.nom)+badge(a._src)+'</td>'
      +'<td style="padding:6px 10px;font-size:.85rem">'+_esc(a.tel||'&mdash;')+'</td>'
      +'<td style="padding:6px 10px;font-size:.8rem;color:#1a5c2e">&#9989; Invit&eacute; le '+_esc(a.dateInvitGroupe||'&mdash;')+'</td>'
      +'<td style="padding:6px 10px;text-align:center">'+btn+'</td>'
      +'</tr>';
  }

  var body='<h4 style="color:#8b1a1a;margin-bottom:6px">&#9203; En attente d\'invitation ('+pending.length+')</h4>'
    +(pending.length
      ? '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:.83rem">'
        +'<thead><tr style="background:#fff3f3"><th style="padding:6px 10px;text-align:left">Apprenant</th>'
        +'<th style="padding:6px 10px">WhatsApp</th><th style="padding:6px 10px">Inscrit le</th><th style="padding:6px 10px">Actions</th></tr></thead>'
        +'<tbody>'+pending.map(rowPending).join('')+'</tbody></table></div>'
      : '<p style="color:#999;font-size:.85rem;padding:10px">Aucune inscription en attente &#127881;</p>')
    +'<hr style="margin:14px 0">'
    +'<h4 style="color:#1a5c2e;margin-bottom:6px">&#9989; D&eacute;j&agrave; invit&eacute;s ('+invited.length+')</h4>'
    +(invited.length
      ? '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:.83rem">'
        +'<thead><tr style="background:#f0fdf4"><th style="padding:6px 10px;text-align:left">Apprenant</th>'
        +'<th style="padding:6px 10px">WhatsApp</th><th style="padding:6px 10px">Date invitation</th><th style="padding:6px 10px">Action</th></tr></thead>'
        +'<tbody>'+invited.map(rowInvited).join('')+'</tbody></table></div>'
      : '<p style="color:#999;font-size:.85rem;padding:10px">Aucun apprenant invit&eacute; pour l\'instant.</p>');

  M('&#128242; Int&eacute;gration Groupes WhatsApp',
    pending.length+' en attente &middot; '+invited.length+' invit&eacute;s',
    body,
    '<button class="btn bo" onclick="cm()">Fermer</button>'
    +'<button class="btn bi" onclick="mWAGroupes()">&#9881;&#65039; G&eacute;rer les groupes</button>',
    true);
}

