// v1.2.2 : une méthode optionnelle n'est affichée que si réellement configurée
// (évite un lien Stripe de test cassé ou un IBAN « À configurer » visibles par le client).
function _payOK(v){ return !!v && !/replace_me|test_replace|À configurer|REMPLACER|Votre[A-Z]|exemple|example|XXXX/i.test(String(v)); }

function _payRef(prefix){
  var d = new Date();
  var y = d.getFullYear().toString().slice(2);
  var m = ('0'+(d.getMonth()+1)).slice(-2);
  var dd = ('0'+d.getDate()).slice(-2);
  var rnd = Math.random().toString(36).toUpperCase().slice(2,6);
  return (prefix||'VT')+y+m+dd+'-'+rnd;
}

// Ouvrir le modal de paiement — point d'entrée principal
// payInfo: {montant: 5000, label: 'Pack Premium', ref?: 'VT250407-XXXX', onConfirm?: fn}
function openPaymentModal(payInfo){
  payInfo = payInfo || {};
  var montant = payInfo.montant || 0;
  var label = payInfo.label || 'Paiement VÉRITAS';
  var ref = payInfo.ref || _payRef(payInfo.refPrefix || 'VT');
  var P = window.VERITAS_PAYMENTS;

  // Formatage du montant
  var montantFmt = new Intl.NumberFormat('fr-FR').format(montant) + ' FCFA';
  // Conversion approximative en EUR/USD pour PayPal/Stripe (655 FCFA ≈ 1 EUR fixe zone XAF)
  var montantEUR = (montant / 655).toFixed(2);

  // Message WhatsApp de confirmation (le client clique → envoie au centre)
  var waMsg = encodeURIComponent(
    "Bonjour,\n\nJe viens d'effectuer un paiement pour " + label + ".\n"
    + "Montant : " + montantFmt + "\n"
    + "Référence : " + ref + "\n"
    + "Moyen de paiement : [à préciser : MoMo / Orange Money / PayPal / Carte / Virement]\n"
    + "Nom de l'expéditeur : [votre nom]\n\n"
    + "Merci de valider mon inscription / ma commande."
  );
  var waNum = (P.whatsapp||'').replace(/[^0-9+]/g,'').replace(/^\+/,'');
  var waUrl = 'https://wa.me/' + waNum + '?text=' + waMsg;

  // Construction du corps du modal
  var body = ''
    + '<div style="background:linear-gradient(135deg,#142554,#1E3A8A);color:#fff;padding:20px;border-radius:14px;margin-bottom:16px">'
      + '<div style="font-family:Montserrat,sans-serif;font-size:12px;letter-spacing:2px;opacity:.75;text-transform:uppercase">Paiement pour</div>'
      + '<div style="font-family:Montserrat,sans-serif;font-size:20px;font-weight:800;margin-top:4px">'+_esc(label)+'</div>'
      + '<div style="font-size:32px;font-weight:900;color:#FFC93C;margin-top:10px">'+montantFmt+'</div>'
      + '<div style="font-size:11px;opacity:.75;margin-top:4px">≈ '+montantEUR+' € / USD (taux indicatif)</div>'
      + '<div style="margin-top:12px;padding:8px 12px;background:rgba(255,255,255,.1);border-radius:8px;font-family:monospace;font-size:12px">'
        + '<span style="opacity:.7">Référence :</span> <strong style="color:#FFC93C">'+ref+'</strong>'
      + '</div>'
    + '</div>'

    + '<div class="ib ibt mb12" style="background:rgba(220,38,38,.08);border-left:4px solid #dc2626">'
      + '<span>⚠️</span>'
      + '<span><strong>Important :</strong> Après votre paiement, <strong>cliquez sur le bouton WhatsApp en bas</strong> pour nous envoyer votre confirmation avec la référence '+ref+'. Votre accès sera activé sous 24h.</span>'
    + '</div>'

    + '<div class="bold s mb10" style="color:var(--ink2)">💰 Choisissez votre moyen de paiement :</div>'

    + '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:12px;margin-bottom:16px">'

      // MoMo — avec API automatique si activée
      + '<div class="paymethod" style="background:#fff;border:2px solid '+P.momo.couleur+';border-radius:12px;padding:14px;position:relative">'
        + '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">'
          + '<div style="font-size:28px">'+P.momo.ico+'</div>'
          + '<div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:14px;color:#142554">'+P.momo.label+'</div>'
          + (DB.payApiConfig&&DB.payApiConfig.mtnEnabled?'<span style="margin-left:auto;background:linear-gradient(135deg,#059669,#10B981);color:#fff;font-size:9px;font-weight:800;padding:2px 8px;border-radius:8px">⚡ AUTO</span>':'')
        + '</div>'
        + '<div style="font-family:monospace;font-size:15px;font-weight:800;color:'+P.momo.couleur+';margin-bottom:4px;cursor:pointer" onclick="_payCopy(\''+P.momo.numero.replace(/[^0-9+]/g,'')+'\',\'Numéro MoMo\')">'+P.momo.numero+'</div>'
        + '<div style="font-size:11px;color:var(--ink4);line-height:1.5">Nom : <strong>'+P.momo.nomCompte+'</strong><br>Code USSD : <strong>'+P.momo.code+'</strong></div>'
        + (DB.payApiConfig&&DB.payApiConfig.mtnEnabled
            ? '<div style="margin-top:10px;border-top:1px solid var(--bg3);padding-top:10px">'
              +'<input class="fi" id="mtnPhoneInput_'+ref+'" placeholder="Votre n° MTN (ex: 6XX XX XX XX)" value="'+(payInfo.customerTel||'').replace(/[^0-9+]/g,'')+'" style="font-size:12px;padding:6px 10px;width:100%;margin-bottom:6px">'
              +'<button class="btn" style="width:100%;background:linear-gradient(135deg,'+P.momo.couleur+',#FFA500);color:#142554;border:none;border-radius:8px;padding:10px;font-weight:800;font-size:13px;cursor:pointer" onclick="_payInitMtn(\''+ref+'\','+montant+',\''+_esc(label).replace(/\x27/g,"")+'\',\''+(payInfo.intent||"generic")+'\',\''+(payInfo.targetId||"")+'\',\''+(payInfo.customerAccountId||"")+'\',\''+(payInfo.customerNom||"").replace(/\x27/g,"")+'\')">⚡ Payer avec mon MTN MoMo</button>'
              +'</div>'
            : '<div style="font-size:10px;color:var(--ink4);margin-top:6px;font-style:italic">👆 Cliquez pour copier le numéro</div>'
          )
      + '</div>'

      // Orange Money — avec API automatique si activée
      + '<div class="paymethod" style="background:#fff;border:2px solid '+P.orange.couleur+';border-radius:12px;padding:14px;position:relative">'
        + '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">'
          + '<div style="font-size:28px">'+P.orange.ico+'</div>'
          + '<div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:14px;color:#142554">'+P.orange.label+'</div>'
          + (DB.payApiConfig&&DB.payApiConfig.orangeEnabled?'<span style="margin-left:auto;background:linear-gradient(135deg,#059669,#10B981);color:#fff;font-size:9px;font-weight:800;padding:2px 8px;border-radius:8px">⚡ AUTO</span>':'')
        + '</div>'
        + '<div style="font-family:monospace;font-size:15px;font-weight:800;color:'+P.orange.couleur+';margin-bottom:4px;cursor:pointer" onclick="_payCopy(\''+P.orange.numero.replace(/[^0-9+]/g,'')+'\',\'Numéro Orange Money\')">'+P.orange.numero+'</div>'
        + '<div style="font-size:11px;color:var(--ink4);line-height:1.5">Nom : <strong>'+P.orange.nomCompte+'</strong><br>Code USSD : <strong>'+P.orange.code+'</strong></div>'
        + (DB.payApiConfig&&DB.payApiConfig.orangeEnabled
            ? '<button class="btn" style="margin-top:8px;width:100%;background:linear-gradient(135deg,'+P.orange.couleur+',#ff8c00);color:#fff;border:none;border-radius:8px;padding:10px;font-weight:800;font-size:13px;cursor:pointer" onclick="_payInitOrange(\''+ref+'\','+montant+',\''+_esc(label).replace(/\x27/g,"")+'\',\''+(payInfo.intent||"generic")+'\',\''+(payInfo.targetId||"")+'\',\''+(payInfo.customerAccountId||"")+'\',\''+(payInfo.customerNom||"").replace(/\x27/g,"")+'\',\''+(payInfo.customerTel||"")+'\')">⚡ Payer maintenant (auto)</button>'
            : '<div style="font-size:10px;color:var(--ink4);margin-top:6px;font-style:italic">👆 Cliquez pour copier le numéro</div>'
          )
      + '</div>'

      // PayPal
      + (_payOK(P.paypal.url) ? ('<a href="'+P.paypal.url+'" target="_blank" rel="noopener" class="paymethod" style="text-decoration:none;background:#fff;border:2px solid '+P.paypal.couleur+';border-radius:12px;padding:14px;display:block">'
        + '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">'
          + '<div style="font-size:28px">'+P.paypal.ico+'</div>'
          + '<div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:14px;color:#142554">'+P.paypal.label+'</div>'
        + '</div>'
        + '<div style="font-family:monospace;font-size:12px;color:'+P.paypal.couleur+';margin-bottom:4px;word-break:break-all">'+P.paypal.url+'</div>'
        + '<div style="font-size:11px;color:var(--ink4)">Paiement international sécurisé<br>Depuis n\'importe quel pays</div>'
        + '<div style="font-size:10px;color:'+P.paypal.couleur+';margin-top:6px;font-weight:700">→ Ouvrir PayPal</div>'
      + '</a>') : '')

      // Stripe / Carte bancaire
      + (_payOK(P.stripe.url) ? ('<a href="'+P.stripe.url+'" target="_blank" rel="noopener" class="paymethod" style="text-decoration:none;background:#fff;border:2px solid '+P.stripe.couleur+';border-radius:12px;padding:14px;display:block">'
        + '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">'
          + '<div style="font-size:28px">'+P.stripe.ico+'</div>'
          + '<div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:14px;color:#142554">'+P.stripe.label+'</div>'
        + '</div>'
        + '<div style="font-size:12px;color:var(--ink3);margin-bottom:4px">Visa · Mastercard · Amex</div>'
        + '<div style="font-size:11px;color:var(--ink4)">Paiement sécurisé Stripe<br>Pas besoin de compte</div>'
        + '<div style="font-size:10px;color:'+P.stripe.couleur+';margin-top:6px;font-weight:700">→ Payer par carte</div>'
      + '</a>') : '')

      // Virement bancaire (affiché seulement si configuré)
      + (_payOK(P.bank.iban) ? ('<div class="paymethod" style="background:#fff;border:2px solid '+P.bank.couleur+';border-radius:12px;padding:14px;grid-column:1/-1">'
        + '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">'
          + '<div style="font-size:28px">'+P.bank.ico+'</div>'
          + '<div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:14px;color:#142554">'+P.bank.label+'</div>'
        + '</div>'
        + '<div style="font-size:12px;color:var(--ink3);line-height:1.7">'
          + '<strong>Titulaire :</strong> '+P.bank.titulaire+'<br>'
          + '<strong>Banque :</strong> '+P.bank.banque+'<br>'
          + '<strong>IBAN :</strong> <span style="font-family:monospace;background:var(--bg2);padding:2px 6px;border-radius:4px">'+P.bank.iban+'</span><br>'
          + '<strong>SWIFT/BIC :</strong> '+P.bank.swift
        + '</div>'
      + '</div>') : '')
    + '</div>'

    // Bouton WhatsApp de confirmation (obligatoire pour tracer)
    + '<a href="'+waUrl+'" target="_blank" rel="noopener" class="btn" style="background:#25d366;color:#fff;width:100%;display:flex;align-items:center;justify-content:center;gap:10px;padding:14px;font-family:Montserrat,sans-serif;font-weight:800;font-size:14px;text-decoration:none;border-radius:12px;box-shadow:0 4px 16px rgba(37,211,102,.4)">'
      + '📲 J\'ai payé → Envoyer ma confirmation WhatsApp'
    + '</a>'

    + '<div style="text-align:center;margin-top:12px;font-size:11px;color:var(--ink4);line-height:1.6">'
      + '💡 Besoin d\'aide ? Appelez le <strong>'+P.whatsapp+'</strong> ou écrivez à <strong>'+P.email+'</strong>'
    + '</div>';

  // Enregistrer la tentative de paiement en local pour traçabilité admin
  // ── v1.2 : ajout métadonnées intent/targetId pour activation automatique ──
  try{
    DB.payAttempts = DB.payAttempts || [];
    DB.payAttempts.push({
      ref: ref,
      label: label,
      montant: montant,
      date: new Date().toISOString(),
      status: 'pending',
      // Métadonnées pour activation automatique post-validation
      intent: payInfo.intent || 'generic',         // 'book' | 'product' | 'subscription' | 'whatsapp_group' | 'classroom' | 'generic'
      targetId: payInfo.targetId || null,          // ID du livre / plan / groupe / classe
      accountId: payInfo.customerAccountId || (typeof SES!=='undefined'&&SES?SES.accountId:null),
      customerNom: payInfo.customerNom || (typeof SES!=='undefined'&&SES?(SES.pre+' '+SES.nom):''),
      customerTel: payInfo.customerTel || (typeof SES!=='undefined'&&SES?SES.tel:''),
      customerEmail: payInfo.customerEmail || ''
    });
    if(typeof save === 'function') save();
    // Notif admin via VERITAS_NOTIFY (si dispo)
    if(window.VN){
      VN.toAdmin('💳 Nouvelle tentative de paiement',
        (payInfo.customerNom||'Client')+' — '+label+' ('+montantFmt+') — Réf: '+ref,
        'info');
    }
  }catch(e){console.warn('[payAttempt]',e);}

  M('💰 Paiement Sécurisé', label+' — '+montantFmt, body,
    '<button class="btn bo" onclick="cm()">Fermer</button>');
}

// ═══════════════════════════════════════════════════════════════════
// ── v1.2 : INITIATION PAIEMENT ORANGE MONEY (API automatique) ──
// ═══════════════════════════════════════════════════════════════════
function _payInitOrange(ref, montant, label, intent, targetId, accountId, nom, tel){
  if(!DB.payApiConfig || !DB.payApiConfig.orangeEnabled){
    toast('Orange API non activée — voir Paramètres','warn');
    return;
  }
  if(!DB.cloudConfig||!DB.cloudConfig.url||!DB.cloudConfig.secret){
    toast('Configuration cloud manquante (URL serveur + secret API)','err');
    return;
  }
  toast('⏳ Initialisation Orange Money...','info');
  var endpoint = DB.cloudConfig.url.replace(/\/+$/,'')+'/payment_orange.php?action=init';
  fetch(endpoint, {
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':'Bearer '+DB.cloudConfig.secret},
    body: JSON.stringify({ref:ref,montant:montant,label:label,intent:intent,targetId:targetId,
      accountId:accountId,clientNom:nom,clientTel:tel})
  })
  .then(function(r){return r.json();})
  .then(function(data){
    if(data.error){toast('❌ Orange API: '+data.error,'err');return;}
    if(!data.payment_url){toast('❌ URL paiement Orange manquante','err');return;}
    // Redirection vers la page de paiement Orange
    cm();
    M('⏳ Paiement Orange Money en cours','Référence : '+ref,
      '<div style="text-align:center;padding:20px">'
      +'<div style="font-size:64px;margin-bottom:14px">🟠</div>'
      +'<div style="font-size:14px;color:var(--ink2);margin-bottom:14px">Une nouvelle fenêtre va s\'ouvrir pour finaliser votre paiement sur Orange Money.</div>'
      +'<a href="'+data.payment_url+'" target="_blank" rel="noopener" class="btn bi" style="display:inline-block;text-decoration:none;font-size:14px;padding:12px 24px">📱 Ouvrir la page de paiement</a>'
      +'<div style="margin-top:14px;font-size:12px;color:var(--ink4)">Validez avec votre PIN Orange Money sur votre téléphone.<br>L\'activation sera automatique après confirmation.</div>'
      +'<div id="payOrangeStatus" style="margin-top:14px;font-size:12px;color:var(--bl);font-weight:700"></div>'
      +'</div>',
      '<button class="btn bo" onclick="cm();_payStopPolling()">Fermer</button>');
    // Ouvre automatiquement la fenêtre de paiement
    var pw = window.open(data.payment_url, '_blank');
    if(!pw) toast('Autorisez les pop-ups pour ouvrir Orange Money','warn');
    // Lancer le polling de statut
    _payStartPolling(ref);
  })
  .catch(function(err){
    console.error('[Orange init]',err);
    toast('❌ Connexion serveur impossible','err');
  });
}

// ═══════════════════════════════════════════════════════════════════
// ── v1.2 : INITIATION PAIEMENT MTN MOMO (API automatique) ──
// ═══════════════════════════════════════════════════════════════════
function _payInitMtn(ref, montant, label, intent, targetId, accountId, nom){
  if(!DB.payApiConfig || !DB.payApiConfig.mtnEnabled){
    toast('MTN API non activée — voir Paramètres','warn');
    return;
  }
  if(!DB.cloudConfig||!DB.cloudConfig.url||!DB.cloudConfig.secret){
    toast('Configuration cloud manquante','err');
    return;
  }
  // Récupérer le numéro depuis l'input
  var phoneEl = document.getElementById('mtnPhoneInput_'+ref);
  var tel = phoneEl ? phoneEl.value.replace(/[^0-9+]/g,'') : '';
  if(!tel || tel.length < 9){
    toast('⚠️ Entrez votre numéro MTN MoMo valide','warn');
    if(phoneEl) phoneEl.focus();
    return;
  }
  toast('⏳ Envoi du prompt MoMo sur '+tel+'...','info');
  var endpoint = DB.cloudConfig.url.replace(/\/+$/,'')+'/payment_mtn.php?action=init';
  fetch(endpoint, {
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':'Bearer '+DB.cloudConfig.secret},
    body: JSON.stringify({ref:ref,montant:montant,label:label,intent:intent,targetId:targetId,
      accountId:accountId,clientNom:nom,clientTel:tel})
  })
  .then(function(r){return r.json();})
  .then(function(data){
    if(data.error){toast('❌ MTN API: '+data.error,'err');return;}
    cm();
    M('⏳ Paiement MTN MoMo en cours','Référence : '+ref,
      '<div style="text-align:center;padding:20px">'
      +'<div style="font-size:64px;margin-bottom:14px">📱</div>'
      +'<div style="font-size:14px;color:var(--ink2);margin-bottom:12px"><strong>📲 Vérifiez votre téléphone '+_esc(tel)+'</strong></div>'
      +'<div style="font-size:13px;color:var(--ink3);margin-bottom:14px;background:var(--blb);padding:12px;border-radius:8px;border:1px solid var(--bld)">Un prompt USSD MoMo a été envoyé. Composez votre <strong>PIN MoMo</strong> pour valider le paiement de <strong>'+new Intl.NumberFormat("fr-FR").format(montant)+' FCFA</strong>.</div>'
      +'<div style="font-size:12px;color:var(--ink4)">⏱ Validation requise sous 60 secondes. L\'activation sera automatique.</div>'
      +'<div id="payMtnStatus" style="margin-top:14px;font-size:13px;color:var(--bl);font-weight:700;padding:10px;background:var(--bg2);border-radius:8px">⏳ En attente de votre PIN MoMo...</div>'
      +'</div>',
      '<button class="btn bo" onclick="cm();_payStopPolling()">Fermer</button>');
    // Polling
    _payStartPollingMtn(ref);
  })
  .catch(function(err){
    console.error('[MTN init]',err);
    toast('❌ Connexion serveur impossible','err');
  });
}

// Polling MTN spécifique (utilise payment_mtn.php)
function _payStartPollingMtn(ref){
  _payStopPolling();
  var url = DB.cloudConfig.url.replace(/\/+$/,'')+'/payment_mtn.php?action=status&ref='+encodeURIComponent(ref);
  var checks = 0;
  _payPollTimer = setInterval(function(){
    checks++;
    if(checks > 24){ // arrêt après 2 min (MTN expire ~60s)
      _payStopPolling();
      var sel=document.getElementById('payMtnStatus');
      if(sel){sel.innerHTML='⏰ Délai dépassé. Réessayez si le paiement n\'a pas abouti.';sel.style.color='var(--or)';}
      return;
    }
    fetch(url).then(function(r){return r.json();}).then(function(data){
      var statusEl = document.getElementById('payMtnStatus');
      if(!statusEl) return;
      if(data.status==='paid'){
        statusEl.innerHTML = '✅ Paiement confirmé ! Activation en cours...';
        statusEl.style.color = 'var(--gr)';
        _payStopPolling();
        var att = (DB.payAttempts||[]).find(function(x){return x.ref===ref;});
        if(att){
          att.status='paid';
          att.datePaid=new Date().toISOString();
          att.providerAuto='mtn_api';
          if(typeof _payAutoActivate==='function'){
            var result=_payAutoActivate(att);
            att.activationResult=result.msg;
          }
          save();
          if(window.VN) VN.toAdmin('✅ Paiement MTN auto-confirmé',
            'Réf '+ref+' validé par MTN MoMo API ('+(att.activationResult||'OK')+')','success');
        }
        setTimeout(function(){cm();toast('✅ Paiement confirmé et accès activé !','ok');},2500);
      } else if(data.status==='failed' || data.status==='cancelled'){
        statusEl.innerHTML = '❌ Paiement refusé'+(data.reason?' ('+data.reason+')':'')+'. Réessayez.';
        statusEl.style.color = 'var(--re)';
        _payStopPolling();
      } else {
        statusEl.innerHTML = '⏳ En attente de votre PIN MoMo... ('+(checks*5)+'s)';
      }
    }).catch(function(){});
  }, 5000);
}

// Polling du statut de paiement (toutes les 5s)
var _payPollTimer = null;
function _payStartPolling(ref){
  _payStopPolling();
  var url = DB.cloudConfig.url.replace(/\/+$/,'')+'/payment_orange.php?action=status&ref='+encodeURIComponent(ref);
  var checks = 0;
  _payPollTimer = setInterval(function(){
    checks++;
    if(checks > 120){_payStopPolling();return;} // arrêt après 10 min
    fetch(url).then(function(r){return r.json();}).then(function(data){
      var statusEl = document.getElementById('payOrangeStatus');
      if(statusEl){
        if(data.status==='paid'){
          statusEl.innerHTML = '✅ Paiement confirmé ! Activation en cours...';
          statusEl.style.color = 'var(--gr)';
          _payStopPolling();
          // Activer côté local
          var att = (DB.payAttempts||[]).find(function(x){return x.ref===ref;});
          if(att){
            att.status = 'paid';
            att.datePaid = new Date().toISOString();
            att.providerAuto = 'orange_api';
            if(typeof _payAutoActivate==='function'){
              var result = _payAutoActivate(att);
              att.activationResult = result.msg;
            }
            save();
            if(window.VN) VN.toAdmin('✅ Paiement Orange auto-confirmé',
              'Réf '+ref+' validé par l\'API Orange ('+(att.activationResult||'OK')+')','success');
          }
          setTimeout(function(){cm();toast('✅ Paiement confirmé et accès activé !','ok');},2500);
        } else if(data.status==='failed' || data.status==='cancelled'){
          statusEl.innerHTML = '❌ Paiement '+data.status+'. Réessayez ou choisissez un autre moyen.';
          statusEl.style.color = 'var(--re)';
          _payStopPolling();
        } else {
          statusEl.innerHTML = '⏳ En attente de votre confirmation Orange Money... ('+checks*5+'s)';
        }
      }
    }).catch(function(){});
  }, 5000);
}
function _payStopPolling(){
  if(_payPollTimer){clearInterval(_payPollTimer);_payPollTimer=null;}
}

// Helper : copier un texte dans le presse-papier
function _payCopy(txt, label){
  if(!txt) return;
  if(navigator.clipboard && navigator.clipboard.writeText){
    navigator.clipboard.writeText(txt).then(function(){
      toast('✓ '+(label||'Texte')+' copié : '+txt);
    }).catch(function(){
      _payCopyFallback(txt, label);
    });
  } else {
    _payCopyFallback(txt, label);
  }
}
function _payCopyFallback(txt, label){
  try{
    var ta = document.createElement('textarea');
    ta.value = txt; ta.style.position='fixed'; ta.style.left='-9999px';
    document.body.appendChild(ta); ta.select();
    document.execCommand('copy');
    document.body.removeChild(ta);
    toast('✓ '+(label||'Texte')+' copié');
  }catch(e){
    toast('Copiez manuellement : '+txt, 'warn');
  }
}

// Admin : afficher les tentatives de paiement enregistrées (mini-dashboard)
function mPayAttempts(){
  if(!iA()) return;
  var atts = (DB.payAttempts||[]).slice().reverse();

  // Helper : trouver l'abonnement e-learning lié à une tentative de paiement
  // Stratégie : même payRef OU label contenant ELRN OU même montant+date proches
  function _findAboForPay(pay){
    var abos=DB.elearning&&DB.elearning.abonnements||[];
    // 1. lien direct via payRef
    if(pay.ref){var r=abos.find(function(a){return a.payRef===pay.ref;});if(r)return r;}
    // 2. abonnement en attente créé dans la même minute (±2 min)
    var payTs=pay.date?new Date(pay.date).getTime():0;
    var near=abos.filter(function(a){
      if(a.statut!=='En attente')return false;
      var aTs=a.date?new Date(a.date+' 00:00').getTime():0;
      return Math.abs(payTs-aTs)<2*60*1000;
    });
    if(near.length===1)return near[0];
    return null;
  }

  // ── v1.2 : icône + libellé selon l'intent ──
  function _intentBadge(a){
    var map = {
      book:        {ico:'📚',lbl:'Livre',         col:'#0EA5E9'},
      product:     {ico:'🛒',lbl:'Produit',       col:'#D97706'},
      subscription:{ico:'🎓',lbl:'Abonnement',    col:'#7C3AED'},
      whatsapp_group:{ico:'📲',lbl:'Groupe WA',   col:'#25D366'},
      classroom:   {ico:'🎥',lbl:'Classe virt.',col:'#BE185D'},
      generic:     {ico:'💳',lbl:'Paiement',      col:'#64748B'}
    };
    var m = map[a.intent||'generic'] || map.generic;
    return '<span style="display:inline-flex;align-items:center;gap:4px;padding:2px 8px;border-radius:10px;background:'+m.col+'20;color:'+m.col+';font-size:10px;font-weight:700">'+m.ico+' '+m.lbl+'</span>';
  }

  var rows = atts.length
    ? atts.map(function(a){
        var dt = a.date ? new Date(a.date).toLocaleString('fr-FR') : '-';
        var statColor = a.status==='paid'?'var(--gr)':a.status==='pending'?'var(--gold2)':'var(--re)';
        var aboLie = _findAboForPay(a);
        // ── v1.2 : bouton consolidé "Valider et activer" ──
        var btnPaye = a.status==='paid'
          ? '<span style="font-size:11px;color:var(--gr)">✓ Validé</span>'
          : '<button class="btn xs" style="background:linear-gradient(135deg,#059669,#10B981);color:#fff;font-weight:700;border:none" onclick="_payMarkPaid(\''+a.ref+'\')" title="Valider le paiement ET activer automatiquement l\'accès">✓ Valider &amp; activer</button>';
        var btnAbo = (aboLie && aboLie.statut!=='Activé' && a.status!=='paid')
          ? ' <button class="btn xs" style="background:#6D28D9;color:#fff" onclick="cm();activerAbonnement(\''+aboLie.id+'\')">🎓 Abo (manuel)</button>'
          : (aboLie&&aboLie.statut==='Activé' ? '<span style="font-size:10px;color:var(--gr)"> ✓ Abo actif</span>' : '');
        // Infos client + résultat d'activation
        var clientInfo = (a.customerNom||a.customerTel)
          ? '<div style="font-size:10px;color:var(--ink4);margin-top:2px">👤 '+_esc(a.customerNom||'')+(a.customerTel?' · '+_esc(a.customerTel):'')+'</div>'
          : '';
        var actInfo = a.activationResult ? '<div style="font-size:10px;color:var(--gr);margin-top:2px">✓ '+_esc(a.activationResult)+'</div>' : '';
        return '<tr>'
          +'<td style="font-family:monospace;font-size:11px;vertical-align:top">'+_esc(a.ref)+'<br>'+_intentBadge(a)+'</td>'
          +'<td style="font-size:12px;max-width:220px;vertical-align:top">'+_esc(a.label)+clientInfo+actInfo+'</td>'
          +'<td style="font-size:12px;white-space:nowrap;vertical-align:top"><strong>'+new Intl.NumberFormat('fr-FR').format(a.montant)+'</strong> FCFA</td>'
          +'<td style="font-size:11px;color:var(--ink4);white-space:nowrap;vertical-align:top">'+dt+'</td>'
          +'<td style="vertical-align:top"><span style="padding:3px 8px;border-radius:10px;font-size:10px;font-weight:800;background:'+statColor+';color:#fff">'+_esc(a.status||'pending').toUpperCase()+'</span></td>'
          +'<td style="white-space:nowrap;vertical-align:top">'+btnPaye+btnAbo
            +' <button class="btn xs bo" onclick="_payDelete(\''+a.ref+'\')">🗑</button>'
          +'</td>'
        +'</tr>';
      }).join('')
    : '<tr><td colspan="6" style="text-align:center;padding:20px;color:var(--ink4)">Aucune tentative enregistrée.</td></tr>';

  // ── v1.2 : compteurs récap ──
  var pendingCount = atts.filter(function(x){return x.status==='pending';}).length;
  var paidCount = atts.filter(function(x){return x.status==='paid';}).length;
  var totalCollected = atts.filter(function(x){return x.status==='paid';}).reduce(function(s,x){return s+(x.montant||0);},0);
  var topBar = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:8px;margin-bottom:12px">'
    +'<div style="background:var(--orb);padding:8px 12px;border-radius:8px;text-align:center"><div style="font-size:18px;font-weight:800;color:var(--or)">'+pendingCount+'</div><div style="font-size:10px;color:var(--ink4)">⏳ En attente</div></div>'
    +'<div style="background:var(--grb);padding:8px 12px;border-radius:8px;text-align:center"><div style="font-size:18px;font-weight:800;color:var(--gr)">'+paidCount+'</div><div style="font-size:10px;color:var(--ink4)">✓ Validés</div></div>'
    +'<div style="background:var(--blb);padding:8px 12px;border-radius:8px;text-align:center"><div style="font-size:14px;font-weight:800;color:var(--bl)">'+new Intl.NumberFormat('fr-FR').format(totalCollected)+'</div><div style="font-size:10px;color:var(--ink4)">💰 Total FCFA</div></div>'
    +'</div>';

  M('💳 Paiements & Activations Auto', 'Validation = activation automatique',
    topBar
    +'<div class="ib ibg mb12" style="background:#F0FDF4;border:1px solid #A7F3D0"><span>✨</span><span><strong>v1.2 — Automatisation totale</strong> : cliquez sur <b>"✓ Valider &amp; activer"</b>. Le système exécute automatiquement la bonne action selon le type (📚 livre → commande payée, 🎓 abonnement → accès e-learning activé, 📲 groupe WA → adhésion validée, 🎥 classe virtuelle → élève inscrit). Le client reçoit une notification avec ses accès.</span></div>'
    +'<div class="tw" style="max-height:420px;overflow:auto"><table>'
    +'<thead><tr><th>Réf / Type</th><th>Description / Client</th><th>Montant</th><th>Date</th><th>Statut</th><th>Actions</th></tr></thead>'
    +'<tbody>'+rows+'</tbody></table></div>',
    '<button class="btn bo" onclick="cm()">Fermer</button>');
}
// Helpers appelés depuis les onclick inline de mPayAttempts
// ── v1.2 : auto-exécution de l'action liée à l'intent ──
function _payMarkPaid(ref){
  var a=(DB.payAttempts||[]).find(function(x){return x.ref===ref;});
  if(!a) return;
  a.status='paid';
  a.datePaid=new Date().toISOString();

  // ── ACTIVATION AUTOMATIQUE selon l'intent ──
  var result = _payAutoActivate(a);
  a.activationResult = result.msg;

  // ── v2.8 : CALCUL SPLITS PARTENAIRES (parrains + auteurs) ──
  try { if(typeof _computeSplits === 'function') _computeSplits(a); } catch(e){ console.warn('_computeSplits:', e); }

  save();

  // ── NOTIFICATIONS ──
  if(window.VN){
    VN.toAdmin('✅ Paiement validé','Réf. '+ref+' — '+(a.label||'Paiement')+' ('+fmtN(a.montant||0)+' FCFA)'+(result.msg?' — '+result.msg:''),'success');
    if(a.accountId) VN.send({to:a.accountId, titre:'✅ Paiement confirmé', msg:'Votre paiement '+(a.label||'')+' a été validé. '+(result.userMsg||'Merci de votre confiance !'), type:'success'});
  } else if(typeof autoNotify==='function'){
    autoNotify('✅ Paiement validé','Réf. '+ref+' — '+(a.label||'Paiement')+' ('+fmtN(a.montant||0)+' FCFA) marqué comme reçu.','admin');
    if(a.accountId)autoNotify('✅ Paiement confirmé','Votre paiement (réf. '+ref+') a été validé. Merci de votre confiance !',a.accountId);
  }

  // ── ÉVÉNEMENT pour VERITAS_AUTO ──
  if(window.VA) VA.fire('payAttempt.validated', {attempt: a});

  mPayAttempts();
  toast('✓ Paiement validé'+(result.msg?' — '+result.msg:''));
}

// ════════════════════════════════════════════════════════════════════
// v2.8 — 💰 SYSTÈME PARTAGE REVENUS PARTENAIRES (splits + versements)
// ════════════════════════════════════════════════════════════════════
// Phase 1 : tracking auto au paiement (calcul des parts dues)
// Phase 2 : versement manuel admin (1 clic → MoMo/Orange + WhatsApp confirmation)
// Phase 3 : versement auto via Disbursement API (scaffolding)

// Configuration des pourcentages (modifiable depuis admin)
window.SPLIT_CONFIG_DEFAULT = {
  parrain_abo: 10,      // 10% au parrain sur chaque abonnement filleul
  parrain_boutique: 5,  //  5% au parrain sur achat boutique du filleul
  auteur_livre: 60,     // 60% à l'auteur sur ventes de ses livres
  auteur_ressource: 60, // 60% à l'auteur sur ses ressources marketplace
  enseignant_cours: 70  // 70% à l'auteur/enseignant sur ventes cours/quiz marketplace (modèle 70/30 concurrentiel)
};

window._getSplitConfig = function(){
  return Object.assign({}, SPLIT_CONFIG_DEFAULT, (DB._splitConfig || {}));
};

// Calculer les splits dus à partir d'un paiement validé
window._computeSplits = function(payAttempt){
  if(!payAttempt || !payAttempt.montant) return;
  DB.splits = DB.splits || [];
  DB.partenairesSplit = DB.partenairesSplit || {};
  var cfg = _getSplitConfig();
  var splits = [];

  // 1. Parrainage : si le payeur a été parrainé, créditer le parrain
  try {
    var userId = payAttempt.accountId || payAttempt.userId;
    if(userId){
      var parr = (DB.parrainages || []).find(function(p){ return p.filleulId === userId && p.confirmed; });
      if(parr && parr.parrainId && parr.parrainId !== userId){
        // v1.2.2 : barème admin DB.parrainRate {forfait, pct} (forfait + %),
        // repli sur SPLIT_CONFIG si non défini. → un seul barème, éditable par le superadmin.
        var pr = DB.parrainRate || {};
        var pPct = (typeof pr.pct === 'number') ? pr.pct
                 : ((payAttempt.intent === 'subscription') ? cfg.parrain_abo : cfg.parrain_boutique);
        var pForfait = (typeof pr.forfait === 'number') ? pr.forfait : 0;
        var amount = pForfait + Math.round((payAttempt.montant * pPct) / 100);
        if(amount > 0){
          splits.push({
            id: gid(),
            paymentRef: payAttempt.ref,
            type: 'parrainage',
            partenaireId: parr.parrainId,
            description: 'Parrainage de '+(payAttempt.customerNom || 'filleul'),
            montantBase: payAttempt.montant,
            forfait: pForfait,
            pct: pPct,
            montant: amount,
            etat: 'pending',
            createdAt: Date.now()
          });
        }
      }
    }
  } catch(e){ console.warn('split parrain:', e); }

  // 2. Auteur de livre : si achat boutique d'un livre avec authorId
  try {
    if(payAttempt.intent === 'book' || payAttempt.intent === 'boutique'){
      var bid = payAttempt.targetId;
      var book = (DB.books || []).find(function(b){ return b.id === bid; });
      if(book && book.authorId){
        // v1.2.2 : part réelle du livre (book.share) sinon part globale (DB.authorShare), sinon défaut.
        var pct = (typeof book.share === 'number') ? book.share
                : (typeof DB.authorShare === 'number') ? DB.authorShare : cfg.auteur_livre;
        var amount = Math.round((payAttempt.montant * pct) / 100);
        splits.push({
          id: gid(),
          paymentRef: payAttempt.ref,
          type: 'auteur_livre',
          partenaireId: book.authorId,
          description: 'Vente livre : '+(book.titre||'?'),
          montantBase: payAttempt.montant,
          pct: pct,
          montant: amount,
          etat: 'pending',
          createdAt: Date.now()
        });
      }
    }
  } catch(e){ console.warn('split auteur livre:', e); }

  // 3. Enseignant marketplace : si achat d'un contenu marketplaceItems
  try {
    if(payAttempt.intent === 'marketplace'){
      var mid = payAttempt.targetId;
      var item = (DB.marketplaceItems || []).find(function(m){ return m.id === mid; });
      if(item && item.teacherId){
        var pct = cfg.enseignant_cours;
        var amount = Math.round((payAttempt.montant * pct) / 100);
        splits.push({
          id: gid(),
          paymentRef: payAttempt.ref,
          type: 'enseignant_cours',
          partenaireId: item.teacherId,
          description: 'Vente '+(item.type||'cours')+' : '+(item.title||'?'),
          montantBase: payAttempt.montant,
          pct: pct,
          montant: amount,
          etat: 'pending',
          createdAt: Date.now()
        });
        // Marquer la vente côté marketplace
        item.salesCount = (item.salesCount||0) + 1;
      }
    }
  } catch(e){ console.warn('split marketplace:', e); }

  // Enregistrer les splits
  splits.forEach(function(s){
    DB.splits.push(s);
    // Cumuler le solde du partenaire
    DB.partenairesSplit[s.partenaireId] = DB.partenairesSplit[s.partenaireId] || { solde: 0, totalVerse: 0, splits: [] };
    DB.partenairesSplit[s.partenaireId].solde += s.montant;
    DB.partenairesSplit[s.partenaireId].splits.push(s.id);
  });
  // v1.2.2 : ventilation lisible enregistrée sur le paiement (affichable dans mPayAttempts).
  try {
    var partTotal = splits.reduce(function(s,x){ return s + (x.montant||0); }, 0);
    payAttempt.ventilation = {
      brut: payAttempt.montant,
      parts: splits.map(function(x){ return {type:x.type, beneficiaire:x.partenaireId, forfait:x.forfait||0, pct:x.pct||0, montant:x.montant}; }),
      totalReverse: partTotal,
      netVeritas: Math.max(0, (payAttempt.montant||0) - partTotal)
    };
  } catch(e){}
  if(splits.length) try { save(); } catch(e){}
  return splits;
};

// Page admin : tableau de bord des partenaires + soldes + versements
