// ── v1.2 P2 — MODULE STATS BUSINESS DASHBOARD ADMIN ────────────────
// ════════════════════════════════════════════════════════════════════
window.mBusinessStats = function(){
  if(!iA()) return;
  try {
    var pays = (DB.payAttempts||[]).filter(function(p){return p.status==='paid';});
    var allPays = DB.payAttempts||[];
    var totalCA = pays.reduce(function(s,p){return s+(+p.montant||0);},0);
    var caMois = pays.filter(function(p){
      try{var d=new Date(p.created||p.date); var n=new Date();
        return d.getFullYear()===n.getFullYear() && d.getMonth()===n.getMonth();}
      catch(e){return false;}
    }).reduce(function(s,p){return s+(+p.montant||0);},0);
    var nbStud = (DB.students||[]).length;
    var nbVisit = (DB.visitorAccounts||[]).length;
    var nbAbo = ((DB.elearning||{}).abonnements||[]).filter(function(a){return a.statut==='actif';}).length;
    var nbBook = (DB.bookPurchases||[]).length;
    var pendingPays = allPays.filter(function(p){return p.status==='pending';}).length;
    var convRate = nbVisit>0 ? ((nbAbo/nbVisit)*100).toFixed(1) : '0';

    // Top 3 produits e-learning vendus
    var prodCount = {};
    (allPays.filter(function(p){return p.status==='paid';})).forEach(function(p){
      var k = p.label||'(inconnu)';
      prodCount[k] = (prodCount[k]||0)+1;
    });
    var topProd = Object.entries(prodCount).sort(function(a,b){return b[1]-a[1];}).slice(0,3);

    var body = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:14px;margin-bottom:18px">'
      +_statCard('💰', fmt(totalCA), 'CA total', '#10B981')
      +_statCard('📅', fmt(caMois), 'CA ce mois', '#3C8DFF')
      +_statCard('👥', nbStud, 'Élèves', '#FFC93C')
      +_statCard('🌐', nbVisit, 'Visiteurs inscrits', '#7C3AED')
      +_statCard('🎓', nbAbo, 'Abonnements actifs', '#EC4899')
      +_statCard('📚', nbBook, 'Achats livres', '#F59E0B')
      +_statCard('⏳', pendingPays, 'Paiements en attente', '#EF4444')
      +_statCard('📊', convRate+'%', 'Taux conversion', '#06B6D4')
      +'</div>';

    if(topProd.length){
      body += '<div style="background:linear-gradient(135deg,rgba(255,201,60,.08),rgba(60,141,255,.05));padding:14px;border-radius:14px;margin-top:8px">'
        +'<div style="font-weight:700;color:#142554;margin-bottom:10px;display:flex;align-items:center;gap:6px">'
        +'<span class="material-icons-round" style="color:#FFC93C">trending_up</span> Top 3 produits</div>';
      topProd.forEach(function(t,i){
        var medal = ['🥇','🥈','🥉'][i]||'•';
        body += '<div style="display:flex;justify-content:space-between;padding:8px;background:#fff;border-radius:8px;margin-bottom:6px">'
          +'<span>'+medal+' '+_esc(t[0])+'</span>'
          +'<b style="color:#10B981">'+t[1]+' vente'+(t[1]>1?'s':'')+'</b></div>';
      });
      body += '</div>';
    }

    body += '<div style="margin-top:14px;padding:10px;background:#F3F4F6;border-radius:10px;font-size:12px;color:#6B7280">'
      +'<b>📈 Suggestions :</b> '
      +(caMois<10000 ? 'Augmenter la visibilité (poster Facebook, WhatsApp).' :
        caMois<50000 ? 'Bon démarrage — pensez aux programmes de parrainage.' :
        'Excellente croissance — envisagez d\'ajouter des plans premium.')
      +'</div>';

    M('📊 Statistiques Business', 'Vue d\'ensemble VÉRITAS', body,
      '<button class="btn bo" onclick="cm()">Fermer</button>'
      +'<button class="btn bi" onclick="mBusinessStats()">🔄 Actualiser</button>', true);
  } catch(e){
    console.error('mBusinessStats error:', e);
    toast('Erreur stats : '+e.message,'err');
  }
};

function _statCard(emoji, val, lbl, color){
  return '<div style="background:#fff;border:1px solid #E5E7EB;border-radius:14px;padding:14px;text-align:center;border-top:3px solid '+color+'">'
    +'<div style="font-size:24px;margin-bottom:6px">'+emoji+'</div>'
    +'<div style="font-size:20px;font-weight:800;color:'+color+';margin-bottom:2px">'+val+'</div>'
    +'<div style="font-size:11px;color:#6B7280;text-transform:uppercase;letter-spacing:.5px">'+lbl+'</div>'
    +'</div>';
}

