window.t = function(key, fallback){
  try {
    var lang = (DB && DB._lang) || localStorage.getItem('_vrtLang') || 'fr';
    var dict = I18N_DICT[lang] || I18N_DICT.fr;
    return dict[key] || I18N_DICT.fr[key] || fallback || key;
  } catch(e){ return fallback || key; }
};

window.setLang = function(lang){
  if(lang!=='fr' && lang!=='en') return;
  try {
    DB._lang = lang;
    localStorage.setItem('_vrtLang', lang);
    if(typeof save==='function') save();
    document.documentElement.lang = lang==='en' ? 'en' : 'fr-CM';

    // Traduire éléments avec data-i18n
    document.querySelectorAll('[data-i18n]').forEach(function(el){
      var k = el.getAttribute('data-i18n');
      el.textContent = t(k);
    });

    // ── v2.2 : traduction visible immédiate de la nav visiteur ──
    var navMap = lang==='en' ? {
      'Accueil':'Home','E-Learning':'E-Learning','Boutique':'Shop','Jeux':'Games',
      'Labos':'Labs','Classes':'Classes','Orientation':'Guidance','Calendrier':'Calendar',
      'Épreuves':'Exams','Évals':'Tests','Devoir IA':'AI Tutor','Parrainage':'Referral',
      'Parcours IA':'AI Path','Forum':'Forum','Actualités':'News','Contact':'Contact',
      'IA':'AI','Pratiquer':'Practice','Communauté':'Community','Infos':'Info','Partenaires':'Partners',
      'Panier':'Cart',"S'inscrire":'Sign up','Se connecter':'Log in','Enseignant':'Teacher'
    } : {
      'Home':'Accueil','Shop':'Boutique','Games':'Jeux','Labs':'Labos','Classes':'Classes',
      'Guidance':'Orientation','Calendar':'Calendrier','Exams':'Épreuves','Tests':'Évals',
      'AI Tutor':'Devoir IA','Referral':'Parrainage','AI Path':'Parcours IA','News':'Actualités',
      'AI':'IA','Practice':'Pratiquer','Community':'Communauté','Info':'Infos','Partners':'Partenaires',
      'Cart':'Panier','Sign up':"S'inscrire",'Log in':'Se connecter','Teacher':'Enseignant'
    };
    document.querySelectorAll('.vnav-btn, .vlogin-btns .btn').forEach(function(btn){
      // Récupérer le dernier nœud texte (après SVG icône), en préservant l'espace et la flèche ▾
      btn.childNodes.forEach(function(n){
        if(n.nodeType===3 && n.textContent.trim()){
          var raw = n.textContent;
          var lead = (raw.match(/^\s*/)||[''])[0];
          var hadArrow = /▾\s*$/.test(raw.trim());
          var t0 = raw.trim().replace(/\s*▾\s*$/,'');
          if(navMap[t0]) n.textContent = lead + navMap[t0] + (hadArrow?' ▾':'');
        }
      });
    });

    toast(lang==='en'?'🌐 Language: English ✓':'🌐 Langue : Français ✓','ok');
  } catch(e){ console.warn('setLang:',e); toast('Erreur changement langue','warn'); }
};

window.mLanguageMenu = function(){
  var curr = (DB && DB._lang) || localStorage.getItem('_vrtLang') || 'fr';
  var body = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;padding:8px">'
    +'<button class="btn" style="background:'+(curr==='fr'?'#FFC93C':'#F3F4F6')+';color:'+(curr==='fr'?'#142554':'#374151')+';padding:18px;font-size:16px;font-weight:700;border-radius:14px" onclick="setLang(\'fr\');cm()">🇫🇷 Français</button>'
    +'<button class="btn" style="background:'+(curr==='en'?'#FFC93C':'#F3F4F6')+';color:'+(curr==='en'?'#142554':'#374151')+';padding:18px;font-size:16px;font-weight:700;border-radius:14px" onclick="setLang(\'en\');cm()">🇬🇧 English</button>'
    +'</div>'
    +'<div style="margin-top:14px;padding:10px;background:#FEF3C7;border-radius:8px;font-size:12px;color:#92400E">'
    +'<b>ℹ️ Note :</b> '+(curr==='fr'?'Les contenus pédagogiques (cours, œuvres, épreuves) restent en français — seule l\'interface est traduite.':'Educational content (courses, works, exams) stays in French — only the UI is translated.')
    +'</div>';
  M(t('menu.lang','Langue'),'',body,'<button class="btn bi" onclick="cm()">'+t('btn.close','Fermer')+'</button>');
};

