// ════════════════════════════════════════════════════════════════════
// ── v1.2 P3 — #13 IA ADAPTATIVE — Spaced Repetition SM-2 ───────────
// ════════════════════════════════════════════════════════════════════
// Algorithme SuperMemo-2 (Anki) : analyse perfs élève → planning révisions
// optimal. Stocke les "cartes" (notions à réviser) dans DB.smCards{}.
window.SM2 = {
  // calcule la prochaine date de révision selon la qualité de réponse (0-5)
  nextReview: function(card, quality){
    quality = Math.max(0, Math.min(5, +quality||0));
    card.easiness = card.easiness || 2.5;
    card.repetition = card.repetition || 0;
    card.interval = card.interval || 1;
    if(quality < 3){
      card.repetition = 0;
      card.interval = 1;
    } else {
      if(card.repetition === 0) card.interval = 1;
      else if(card.repetition === 1) card.interval = 6;
      else card.interval = Math.ceil(card.interval * card.easiness);
      card.repetition++;
      card.easiness = Math.max(1.3, card.easiness + (0.1 - (5-quality)*(0.08+(5-quality)*0.02)));
    }
    card.lastReview = Date.now();
    card.nextReview = Date.now() + card.interval * 24*60*60*1000;
    card.lastQuality = quality;
    return card;
  },
  // Enregistre un résultat de quiz/devoir et MAJ la carte SM-2
  recordResult: function(userId, topic, scorePct){
    if(!userId || !topic) return;
    DB.smCards = DB.smCards || {};
    DB.smCards[userId] = DB.smCards[userId] || {};
    var card = DB.smCards[userId][topic] || { topic: topic, history: [] };
    var quality = Math.round((scorePct/100) * 5); // 0-100% → 0-5
    card.history.push({ score: scorePct, quality: quality, date: Date.now() });
    if(card.history.length > 20) card.history = card.history.slice(-20);
    SM2.nextReview(card, quality);
    DB.smCards[userId][topic] = card;
    try { save(); } catch(e){}
  },
  // Retourne les topics à réviser maintenant (interval expired)
  getDueTopics: function(userId){
    if(!DB.smCards || !DB.smCards[userId]) return [];
    var now = Date.now();
    return Object.values(DB.smCards[userId]).filter(function(c){
      return c.nextReview && c.nextReview <= now;
    }).sort(function(a,b){ return (a.lastQuality||0) - (b.lastQuality||0); });
  },
  // Topics à renforcer (qualité moyenne < 3)
  getWeakTopics: function(userId){
    if(!DB.smCards || !DB.smCards[userId]) return [];
    return Object.values(DB.smCards[userId]).filter(function(c){
      var avg = c.history.reduce(function(s,h){return s+h.quality;},0) / Math.max(1,c.history.length);
      return avg < 3 && c.history.length >= 2;
    }).sort(function(a,b){
      var avgA = a.history.reduce(function(s,h){return s+h.quality;},0)/a.history.length;
      var avgB = b.history.reduce(function(s,h){return s+h.quality;},0)/b.history.length;
      return avgA - avgB;
    });
  }
};

