// ════════════════════════════════════════════════════════════════════
// v2.4 — 🛡️ SÉCURITÉ RUNTIME — Protection inputs utilisateurs
// ════════════════════════════════════════════════════════════════════

// 1. Sanitization HTML pour les contenus user-generated (forum, commentaires)
window._sanitizeHTML = function(input){
  if(typeof input !== 'string') return '';
  // v2.4 FIX : retirer DABORD les caractères de contrôle invisibles
  // (ASCII 0-31 + 127 DEL), PUIS échapper le HTML — préserve les espaces normaux
  input = input.replace(/[\u0000-\u001F\u007F]/g, '');
  // Échappe caractères HTML dangereux
  return input
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#39;')
    .replace(/\//g,'&#x2F;')
    .replace(/[\u0000-\u001F\u007F]/g, ''); // contrôle invisible
};

// 2. CSRF token simple (basé sur sessionStorage + timestamp)
window._getCSRFToken = function(){
  var tok = sessionStorage.getItem('_vrtCSRF');
  if(!tok){
    tok = 'csrf_'+Date.now()+'_'+Math.random().toString(36).slice(2,12);
    sessionStorage.setItem('_vrtCSRF', tok);
  }
  return tok;
};

// 3. Rate-limit client : bloque les actions spammées
window._RATE_LIMITS = {}; // action → [timestamps]
window._checkRateLimit = function(action, maxPerMinute){
  maxPerMinute = maxPerMinute || 10;
  var now = Date.now();
  _RATE_LIMITS[action] = (_RATE_LIMITS[action]||[]).filter(function(t){return now-t < 60000;});
  if(_RATE_LIMITS[action].length >= maxPerMinute){
    if(typeof toast === 'function') toast('⚠️ Trop d\'actions. Attendez quelques secondes.','warn');
    return false;
  }
  _RATE_LIMITS[action].push(now);
  return true;
};

// 4. Honeypot field : champ caché que seuls les bots remplissent
window._isLikelyBot = function(formEl){
  if(!formEl) return false;
  var hp = formEl.querySelector('input[name="_hp_field"]');
  return hp && hp.value.length > 0;
};

// 5. Validation entrée stricte (noms, emails, téléphones CM)
window._validate = {
  email: function(s){ return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(s||''); },
  telCM: function(s){ return /^(\+?237\s?)?6[5-9]\d{1}[\s\-]?\d{2}[\s\-]?\d{2}[\s\-]?\d{2}$/.test((s||'').replace(/\s/g,'')); },
  nom: function(s){ return s && s.length>=2 && s.length<=50 && /^[a-zA-ZÀ-ÿ\s'\-]+$/.test(s); },
  pwd: function(s){ return s && s.length>=6 && s.length<=100; },
  text: function(s, max){ max=max||500; return s && s.length<=max; }
};

// 6. Audit log local : enregistre actions sensibles
window._auditLog = function(event, details){
  try {
    var logs = JSON.parse(localStorage.getItem('_vrtAuditLog') || '[]');
    logs.push({
      ts: Date.now(),
      event: event,
      details: details || {},
      ua: navigator.userAgent.substring(0,100),
      url: location.pathname
    });
    if(logs.length > 200) logs = logs.slice(-200);
    localStorage.setItem('_vrtAuditLog', JSON.stringify(logs));
  } catch(e){}
};

// 7. Détection clickjacking — si on est dans une iframe non-autorisée
try {
  if(window.top !== window.self && location.hostname !== 'veritas-school.com'){
    document.body.innerHTML = '<div style="padding:30px;text-align:center;background:#142554;color:#FFC93C;font-family:sans-serif">⚠️ Cette page ne peut être affichée dans un cadre tiers pour des raisons de sécurité.<br><a href="https://veritas-school.com" style="color:#fff">Accéder à VÉRITAS</a></div>';
  }
} catch(e){
  // Browser SOP empêche d'accéder à window.top — c'est le signe qu'on est dans un iframe cross-origin
}

