window.VERITAS_XP = {
  perActivity: { quiz:10, devoir:30, lecture:5, login:2, battle_win:50, sujet_jour:15 },
  levels: [
    {min:0,    title:'🌱 Apprenti',    color:'#94A3B8'},
    {min:100,  title:'📘 Étudiant',     color:'#3C8DFF'},
    {min:300,  title:'⭐ Bachelier',    color:'#10B981'},
    {min:600,  title:'🎓 Diplômé',     color:'#7C3AED'},
    {min:1000, title:'🏆 Champion',    color:'#FFC93C'},
    {min:2000, title:'👑 Légende',     color:'#DC2626'}
  ]
};

// Helper : récupère ou crée la fiche streak de l'utilisateur courant
window._getUserStreak = function(){
  var ses = (typeof SES!=='undefined' && SES) ? SES : null;
  if(!ses || !ses.id) return null;
  DB.userStreaks = DB.userStreaks || {};
  if(!DB.userStreaks[ses.id]){
    DB.userStreaks[ses.id] = { current:0, best:0, lastDate:null, xp:0, totalActivities:0 };
  }
  return DB.userStreaks[ses.id];
};

// Helper : ajoute XP + met à jour streak quotidien
window._addXP = function(activity){
  var s = _getUserStreak();
  if(!s) return null;
  var pts = (VERITAS_XP.perActivity[activity] || 1);
  s.xp = (s.xp||0) + pts;
  s.totalActivities = (s.totalActivities||0) + 1;
  // Streak quotidien
  var today = new Date().toISOString().slice(0,10);
  if(s.lastDate !== today){
    var y = new Date(); y.setDate(y.getDate()-1);
    var yesterday = y.toISOString().slice(0,10);
    if(s.lastDate === yesterday){
      s.current = (s.current||0) + 1;
    } else if(s.lastDate){
      // Streak cassé
      s.current = 1;
    } else {
      s.current = 1;
    }
    if(s.current > (s.best||0)) s.best = s.current;
    s.lastDate = today;
  }
  try { save(); } catch(e){}
  // Toast léger
  if(typeof toast==='function'){
    toast('+'+pts+' XP'+(s.current>1?' 🔥 '+s.current+'j':''),'ok');
  }
  return s;
};

window._currentLevel = function(xp){
  xp = xp || 0;
  var L = VERITAS_XP.levels;
  for(var i=L.length-1; i>=0; i--){
    if(xp >= L[i].min){
      var next = L[i+1];
      return {
        current: L[i],
        next: next || null,
        progress: next ? (xp - L[i].min) / (next.min - L[i].min) * 100 : 100
      };
    }
  }
  return { current: L[0], next: L[1], progress: 0 };
};

// Badge streak visible (à appeler depuis un widget)
window._streakBadgeHtml = function(){
  var s = _getUserStreak();
  if(!s) return '';
  var lvl = _currentLevel(s.xp);
  var col = lvl.current.color;
  return '<div onclick="mMonParcours()" style="display:inline-flex;align-items:center;gap:6px;padding:6px 10px;background:linear-gradient(135deg,'+col+'18,'+col+'08);border:1px solid '+col+'40;border-radius:99px;cursor:pointer;font-size:11px;font-weight:700;color:'+col+'" title="Mon parcours · '+lvl.current.title+'">'
    +(s.current>0?'<span>🔥 '+s.current+'j</span>':'')
    +'<span>'+lvl.current.title.split(' ')[0]+' '+s.xp+' XP</span>'
    +'</div>';
};

