// ─── 2. BATTLES HEBDOMADAIRES + LEADERBOARD ─────────────────────────
window._currentWeekKey = function(){
  var d = new Date();
  var year = d.getFullYear();
  var firstJan = new Date(year,0,1);
  var days = Math.floor((d - firstJan) / (1000*60*60*24));
  var week = Math.ceil((days + firstJan.getDay() + 1) / 7);
  return year+'-W'+String(week).padStart(2,'0');
};

// v1.2.2 : cycle MINESEC d'un élève (programmes & difficulté différents)
//   I  = 6e-5e · II = 4e-3e · III = 2nde-1ère-Tle
window._battleCycle = function(cls){
  var c = String(cls||'').toLowerCase().replace(/\s/g,'');
  if(/(^|[^0-9])6e|sixi|6[eè]me|^5e|cinqu|5[eè]me|form1|form2/.test(c)) {
    if(/6|sixi|form1/.test(c)) return 'I';
    if(/5|cinqu|form2/.test(c)) return 'I';
  }
  if(/4e|quatri|4[eè]me|3e|troisi|3[eè]me|form3|form4|bepc/.test(c)) return 'II';
  if(/2nde|2de|seconde|1[eè]re|premiere|première|tle|terminale|form5|lower|upper|bac|probat/.test(c)) return 'III';
  if(/^4|^3/.test(c)) return 'II';
  if(/^2|^1|^t/.test(c)) return 'III';
  return 'II'; // défaut prudent (collège supérieur)
};
window._battleCycleLabel = function(cy){
  return ({I:'Cycle I · 6ᵉ–5ᵉ', II:'Cycle II · 4ᵉ–3ᵉ', III:'Cycle III · 2nde–Tle'})[cy] || ('Cycle '+cy);
};
// Clé de battle = semaine + cycle (un défi et un classement par cycle)
window._battleKey = function(cls){
  return _currentWeekKey() + '-C' + _battleCycle(cls || (typeof SES!=='undefined'&&SES?SES.cls:'') );
};

window._generateBattleQuestions = function(){
  // Tirer 10 QCM aléatoires depuis toutes les sources disponibles
  // FIX v1.2 : conversion format {opts:[], ans:N} → {a,b,c,ok} attendu par le moteur de battle
  var KEYS = ['a','b','c','d'];
  function convertQ(q, src){
    if(!q || !q.q) return null;
    // Format natif {a,b,c,ok} déjà prêt
    if(q.ok && q.a) return {q:q.q, a:q.a, b:q.b, c:q.c, ok:q.ok, src:src};
    // Format {opts:[], ans:N} → conversion
    if(Array.isArray(q.opts) && q.opts.length >= 2 && typeof q.ans === 'number'){
      var entry = {q:q.q, src:src};
      q.opts.forEach(function(opt, i){ if(i < 4) entry[KEYS[i]] = opt; });
      entry.ok = KEYS[q.ans] || 'a';
      return entry;
    }
    return null;
  }
  var pool = [];
  // LITT_OEUVRES — FIX : utilisent {opts, ans}, pas {a,b,c,ok}
  if(typeof LITT_OEUVRES !== 'undefined'){
    Object.values(LITT_OEUVRES).forEach(function(oe){
      if(oe.qcm) oe.qcm.forEach(function(q){
        var c = convertQ(q, oe.titre || '?');
        if(c) pool.push(c);
      });
    });
  }
  // JEUX_CATALOGUE QCM — FIX : utilisent j.questions (pas j.data) + format {opts, ans}
  if(typeof JEUX_CATALOGUE !== 'undefined'){
    JEUX_CATALOGUE.filter(function(j){return j.type==='qcm' && (j.questions||j.data);}).forEach(function(j){
      var qs = j.questions || j.data || [];
      qs.slice(0,3).forEach(function(q){
        var c = convertQ(q, j.titre || '?');
        if(c) pool.push(c);
      });
    });
  }
  if(pool.length < 5) return [];
  // Shuffle + 10
  pool.sort(function(){return Math.random()-0.5;});
  return pool.slice(0,10);
};

window.mBattles = function(){
  var ses = (typeof SES!=='undefined' && SES) ? SES : null;
  if(!ses){
    M('⚔️ Battles hebdo','Connectez-vous pour participer aux défis',
      '<div style="text-align:center;padding:18px"><p>Affrontez les autres élèves dans 10 QCM hebdomadaires. Top 3 = prix mensuel (manuel offert) !</p></div>',
      '<button class="btn bo" onclick="cm()">Fermer</button><button class="btn bi" onclick="cm();showRegisterForm()">✨ S\'inscrire</button>');
    return;
  }
  DB.battles = DB.battles || {};
  var wk = _battleKey(ses.cls);               // v1.2.2 : clé par cycle
  var _cy = _battleCycle(ses.cls);
  DB.battles[wk] = DB.battles[wk] || { participants: {}, questions: null, cycle: _cy };
  var battle = DB.battles[wk];
  // Génère les questions si pas encore (ou si vide — FIX v1.2 : [] est truthy)
  if(!battle.questions || !battle.questions.length){
    battle.questions = _generateBattleQuestions();
    try { save(); } catch(e){}
  }
  var hasPlayed = !!battle.participants[ses.id];
  var leaderboard = Object.entries(battle.participants)
    .sort(function(a,b){
      if(b[1].score !== a[1].score) return b[1].score - a[1].score;
      return a[1].timeMs - b[1].timeMs;
    });
  var myRank = leaderboard.findIndex(function(e){return e[0]===ses.id;}) + 1;

  var body = '<div style="padding:8px">'
    +'<div style="background:linear-gradient(135deg,#FEF3C7,#FBBF24);color:#92400E;padding:14px;border-radius:12px;margin-bottom:14px;text-align:center">'
      +'<div style="font-size:11px;text-transform:uppercase;letter-spacing:1.5px;font-weight:800">Défi de la semaine · '+_esc(_battleCycleLabel(_cy))+'</div>'
      +'<div style="font-size:18px;font-weight:900;margin-top:4px">🏆 '+leaderboard.length+' participant'+(leaderboard.length>1?'s':'')+' de ton niveau</div>'
      +'<div style="font-size:10.5px;margin-top:3px;opacity:.85">Tu affrontes uniquement les élèves de ton cycle (programmes équivalents)</div>'
    +'</div>'
    +(hasPlayed
      ? '<div style="background:#D1FAE5;border:1px solid #6EE7B7;padding:12px;border-radius:10px;margin-bottom:14px;text-align:center"><div style="font-weight:700;color:#065F46">✓ Vous avez déjà joué cette semaine</div><div style="font-size:13px;color:#047857;margin-top:4px">Votre score : '+battle.participants[ses.id].score+'/10 · Position : #'+myRank+'</div></div>'
      : '<div style="text-align:center;margin-bottom:14px"><button class="btn bi" style="background:linear-gradient(135deg,#DC2626,#F59E0B);color:#fff;padding:14px 28px;font-size:15px;font-weight:800" onclick="cm();_lancerBattle()">⚡ Lancer le défi (10 QCM)</button><div style="font-size:11px;color:#6B7280;margin-top:8px">Un seul essai par semaine</div></div>'
    )
    +'<div style="font-size:13px;font-weight:700;color:#142554;margin-bottom:8px">🏆 Classement de la semaine</div>';
  if(!leaderboard.length){
    body += '<div style="text-align:center;padding:20px;color:#9CA3AF">Soyez le premier à participer !</div>';
  } else {
    leaderboard.slice(0,10).forEach(function(e,idx){
      var p = e[1];
      var isMe = e[0] === ses.id;
      var medal = ['🥇','🥈','🥉'][idx] || '#'+(idx+1);
      body += '<div style="display:flex;align-items:center;gap:10px;padding:8px 10px;background:'+(isMe?'#FEF3C7':'#fff')+';border:1px solid '+(isMe?'#FCD34D':'#E5E7EB')+';border-radius:8px;margin-bottom:4px">'
        +'<div style="font-size:18px;min-width:30px;font-weight:800">'+medal+'</div>'
        +'<div style="flex:1;font-weight:600;color:#142554">'+_esc(p.nom||'Anonyme')+(isMe?' <span style="font-size:10px;background:#FFC93C;padding:1px 5px;border-radius:4px;color:#142554">vous</span>':'')+'</div>'
        +'<div style="font-weight:800;color:#10B981">'+p.score+'/10</div>'
      +'</div>';
    });
  }
  body += '</div>';
  M('⚔️ Battle hebdomadaire','Affrontez les autres élèves',body,
    '<button class="btn bi" onclick="cm()">Fermer</button>', true);
};

window._lancerBattle = function(){
  var ses = (typeof SES!=='undefined' && SES) ? SES : null;
  if(!ses) return;
  DB.battles = DB.battles || {};
  var wk = _battleKey(ses.cls);               // v1.2.2 : même clé par cycle
  var battle = DB.battles[wk];
  if(!battle || !battle.questions || !battle.questions.length){
    toast('Battle indisponible cette semaine','warn'); return;
  }
  var qs = battle.questions;
  var idx = 0, score = 0, startMs = Date.now();
  function _renderQ(){
    if(idx >= qs.length){
      // Fin
      var timeMs = Date.now() - startMs;
      battle.participants[ses.id] = {
        nom: (ses.pre||'')+' '+(ses.nom||''),
        score: score,
        timeMs: timeMs,
        date: Date.now()
      };
      try { save(); } catch(e){}
      _addXP('battle_win');
      // Bonus XP selon score
      var s = _getUserStreak();
      if(s){ s.xp = (s.xp||0) + score*5; try{save();}catch(e){} }
      M('🎉 Battle terminé !','Bravo pour votre participation',
        '<div style="text-align:center;padding:20px">'
        +'<div style="font-size:60px;margin-bottom:10px">'+(score>=8?'🏆':score>=5?'⭐':'💪')+'</div>'
        +'<div style="font-size:32px;font-weight:900;color:#10B981">'+score+'/10</div>'
        +'<div style="font-size:13px;color:#6B7280;margin-top:8px">Temps : '+Math.round(timeMs/1000)+'s</div>'
        +'<div style="margin-top:14px;padding:12px;background:#FEF3C7;border-radius:10px;font-size:13px;color:#92400E"><b>+'+(50+score*5)+' XP gagnés !</b><br>Battle bonus + '+score+' bonnes réponses × 5 XP</div>'
        +'</div>',
        '<button class="btn bo" onclick="cm()">Fermer</button>'
        +'<button class="btn bi" onclick="cm();mBattles()">🏆 Voir le classement</button>', true);
      return;
    }
    var q = qs[idx];
    var body = '<div style="padding:8px">'
      +'<div style="background:#142554;color:#fff;padding:10px 14px;border-radius:10px;margin-bottom:14px;display:flex;justify-content:space-between;align-items:center">'
        +'<div style="font-weight:700">Question '+(idx+1)+'/10</div>'
        +'<div style="font-size:11px;opacity:.85">Score : '+score+'/'+idx+'</div>'
      +'</div>'
      +'<div style="font-size:15px;color:#142554;font-weight:700;margin-bottom:14px;line-height:1.5">'+_esc(q.q)+'</div>'
      +['a','b','c'].map(function(L){
        if(!q[L]) return '';
        return '<button class="btn" style="display:block;width:100%;text-align:left;padding:12px 14px;margin-bottom:8px;background:#fff;border:2px solid #E5E7EB;border-radius:10px;color:#142554;font-size:14px;font-weight:600" onclick="window._answerBattle(\''+L+'\')">'+L.toUpperCase()+'. '+_esc(q[L])+'</button>';
      }).join('')
      +'</div>';
    M('⚔️ Battle en cours','Q '+(idx+1)+'/10',body,'', true);
    window._answerBattle = function(ans){
      if(ans === q.ok) score++;
      idx++;
      setTimeout(_renderQ, 150);
    };
  }
  _renderQ();
};

