window._getSujetDuJour = function(){
  DB._sujetJour = DB._sujetJour || {};
  var today = new Date().toISOString().slice(0,10);
  if(DB._sujetJour.date === today && DB._sujetJour.q && DB._sujetJour.mat) return DB._sujetJour;
  // Sélection déterministe basée sur la date (toujours le même sujet par jour)
  var dayOfYear = Math.floor((new Date() - new Date(new Date().getFullYear(),0,1)) / 86400000);
  var sj = SUJETS_FALLBACK[dayOfYear % SUJETS_FALLBACK.length];
  DB._sujetJour = { date:today, q:sj.q, a:sj.a, lvl:sj.lvl, mat:sj.mat||'', revealed:false };
  try { save(); } catch(e){}
  return DB._sujetJour;
};

window.mSujetDuJour = function(){
  var sj = _getSujetDuJour();
  var now = new Date();
  var canReveal = now.getHours() >= 18 || sj.revealed;
  var body = '<div style="padding:8px">'
    +'<div style="background:linear-gradient(135deg,#7C3AED,#A855F7);color:#fff;padding:14px;border-radius:12px;margin-bottom:14px;text-align:center">'
      +'<div style="font-size:11px;text-transform:uppercase;letter-spacing:1.5px;font-weight:800;opacity:.9">☀️ Sujet du '+new Date(sj.date).toLocaleDateString('fr-FR',{weekday:'long',day:'numeric',month:'long'})+'</div>'
      +'<div style="font-size:11px;margin-top:6px;background:rgba(0,0,0,.2);padding:2px 10px;border-radius:99px;display:inline-block">'+(sj.mat?'📚 '+_esc(sj.mat)+' · ':'')+'Niveau : '+_esc(sj.lvl)+'</div>'
    +'</div>'
    +'<div style="background:#fff;border:2px solid #E5E7EB;border-radius:12px;padding:18px;margin-bottom:14px">'
      +'<div style="font-size:11px;color:#6B7280;font-weight:700;text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">❓ Question</div>'
      +'<div style="font-size:15px;color:#142554;font-weight:600;line-height:1.6">'+_esc(sj.q)+'</div>'
    +'</div>'
    +(canReveal
      ? '<div style="background:#F0FDF4;border:2px solid #6EE7B7;border-radius:12px;padding:18px">'
        +'<div style="font-size:11px;color:#059669;font-weight:700;text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">✅ Correction</div>'
        +'<div style="font-size:14px;color:#065F46;line-height:1.7">'+_esc(sj.a)+'</div>'
      +'</div>'
      : '<div style="background:#FEF3C7;border:1px solid #FCD34D;border-radius:12px;padding:14px;text-align:center">'
        +'<div style="font-size:13px;color:#92400E;font-weight:700">🔒 Correction disponible à 18h</div>'
        +'<div style="font-size:11px;color:#92400E;opacity:.8;margin-top:4px">Essayez de répondre par vous-même avant !</div>'
      +'</div>'
    )
    +'</div>';
  M('☀️ Sujet du jour','Une question par jour pour rester affûté',body,
    '<button class="btn bo" onclick="cm()">Fermer</button>'
    +(canReveal ? '<button class="btn bi" onclick="cm();_markSujetLu()">📖 J\'ai lu (+15 XP)</button>' : ''), true);
  // Marquer comme révélé après 18h
  if(canReveal && !sj.revealed){ sj.revealed = true; try{save();}catch(e){} }
};

