// ─── 4. BAC EN 100 JOURS ────────────────────────────────────────────
window._getDaysToBAC = function(){
  // Date BAC officielle : 1er juin par défaut, configurable via DB._bacDate
  var bacDate;
  if(DB._bacDate){
    bacDate = new Date(DB._bacDate);
  } else {
    var y = new Date().getFullYear();
    bacDate = new Date(y, 5, 1); // 1er juin année courante
    if(bacDate < new Date()){
      bacDate = new Date(y+1, 5, 1); // prochaine année
    }
  }
  var diff = bacDate - new Date();
  return Math.max(0, Math.ceil(diff / (1000*60*60*24)));
};

