// Orientation après acceptation de la mission : guide l'apprenant + entonnoir abonnement
window._bacMissionDone = function(){
  try{ if(typeof _addXP==='function') _addXP('lecture'); }catch(e){}
  cm();
  var days = _getDaysToBAC();
  var urgent = days<=30, soon = days<=60;
  var intro = urgent
    ? 'Plus que <b>'+days+' jours</b> — chaque séance compte. Voici ton plan pour les prochaines 48h :'
    : 'Bravo 👏 Mission validée. Garde le rythme — voici par quoi continuer maintenant :';
  var step = function(ic,t,d,cb){
    return '<button class="btn" style="display:flex;gap:12px;align-items:flex-start;width:100%;text-align:left;background:#fff;border:1.5px solid #E6EAF2;border-radius:12px;padding:12px 14px;margin-bottom:8px;cursor:pointer" onmouseover="this.style.borderColor=\'#3C8DFF\'" onmouseout="this.style.borderColor=\'#E6EAF2\'" onclick="cm();'+cb+'">'
      +'<span style="font-size:20px;flex-shrink:0">'+ic+'</span>'
      +'<span style="min-width:0"><span style="display:block;font-weight:800;color:#142554;font-size:14px">'+t+'</span>'
      +'<span style="display:block;font-size:12px;color:#5B6B85;margin-top:2px">'+d+'</span></span></button>';
  };
  var steps = step('📝','Faire un QCM chronométré','10 questions, classement de la semaine',"(typeof mBattles===\'function\'?mBattles():null)")
    + step('🤖','Demander une fiche au Prof. Ambassa','Correction IA + fiche de révision personnalisée',"(typeof mAgentAmbassa===\'function\'?mAgentAmbassa():null)")
    + step('☀️','Lire le sujet du jour','Une question MINESEC corrigée par jour',"(typeof mSujetDuJour===\'function\'?mSujetDuJour():null)");
  var body = '<div style="padding:6px">'
    +'<div style="background:#F0FDF4;border:1.5px solid #6EE7B7;border-radius:12px;padding:12px 14px;margin-bottom:14px;text-align:center">'
      +'<div style="font-size:13px;font-weight:800;color:#065F46">✓ Mission validée · +5 XP</div>'
      +'<div style="font-size:12px;color:#047857;margin-top:2px">Reviens demain pour ne pas casser ton streak 🔥</div>'
    +'</div>'
    +'<div style="font-size:13px;color:#374151;line-height:1.6;margin-bottom:12px">'+intro+'</div>'
    +steps
    +'<div style="margin-top:16px;background:linear-gradient(135deg,#142554,#7C3AED);border-radius:14px;padding:16px;color:#fff;position:relative;overflow:hidden">'
      +'<div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:1.2px;color:#FFC93C">'+(urgent?'⚡ Sprint final':'🎯 Aller plus loin')+'</div>'
      +'<div style="font-size:16px;font-weight:900;margin-top:4px;line-height:1.25">Révision Intensive '+(new Date().getFullYear()+(days>365?1:0))+'</div>'
      +'<div style="font-size:12.5px;opacity:.9;margin-top:6px;line-height:1.5">Épreuves corrigées, fiches IA illimitées, suivi de progression et accès prioritaire à tous les cours MINESEC.</div>'
      +'<button class="btn" style="margin-top:12px;background:#FFC93C;color:#142554;font-weight:800;border:none;padding:10px 16px;border-radius:10px;cursor:pointer" onclick="_bacGoElearning()">🚀 Découvrir les abonnements</button>'
    +'</div>'
    +'</div>';
  M('🎓 Et maintenant ?', soon?'Ton plan pour le BAC dans '+days+' jours':'Continue sur ta lancée',body,
    '<button class="btn bo" onclick="cm()">Plus tard</button>'
    +'<button class="btn bi" onclick="_bacGoElearning()">🚀 Révisions intensives</button>', true);
};

