// v2.4 — 🧬 VÉRITAS GENOME : ADN académique partageable
// ════════════════════════════════════════════════════════════════════
window.mVeritasGenome = function(){
  var ses = (typeof SES!=='undefined' && SES) ? SES : null;
  if(!ses){
    M('🧬 VÉRITAS Genome','Découvrez votre ADN académique',
      '<div style="text-align:center;padding:20px"><p style="margin-bottom:14px">Le VÉRITAS Genome analyse vos performances et révèle :</p><ul style="text-align:left;color:#374151;line-height:2;max-width:400px;margin:0 auto"><li>✓ Vos <b>forces</b> et <b>faiblesses</b> par matière</li><li>✓ Votre <b>courbe d\'évolution</b> sur 30 jours</li><li>✓ Une <b>prédiction de note BAC</b> basée IA</li><li>✓ Une <b>infographie partageable</b> sur WhatsApp</li></ul></div>',
      '<button class="btn bo" onclick="cm()">Fermer</button><button class="btn bi" onclick="cm();showRegisterForm()">✨ S\'inscrire pour mon Genome</button>');
    return;
  }
  // v2.4 FIX : tracker la consultation pour débloquer le badge genome_unlock
  try { DB._genomeViewed = true; save(); if(typeof _checkBadges==='function') setTimeout(_checkBadges, 200); } catch(e){}
  var s = _getUserStreak() || {xp:0,current:0,best:0,totalActivities:0};
  var lvl = _currentLevel(s.xp);
  // Calculs Genome (basés sur SM-2 + battles + activités)
  var cards = (DB.smCards && DB.smCards[ses.id]) ? Object.values(DB.smCards[ses.id]) : [];
  var topics = cards.length;
  var mastered = cards.filter(function(c){
    var avg = c.history.reduce(function(s,h){return s+h.quality;},0)/Math.max(1,c.history.length);
    return avg >= 4;
  }).length;
  var weak = cards.filter(function(c){
    var avg = c.history.reduce(function(s,h){return s+h.quality;},0)/Math.max(1,c.history.length);
    return avg < 3 && c.history.length>=2;
  }).length;
  // Prédiction BAC : formule simple basée sur XP, streak, % maîtrisé
  var pctMastered = topics > 0 ? (mastered/topics)*100 : 0;
  var pctStreak = Math.min(100, (s.current||0)*3);
  var pctXP = Math.min(100, (s.xp||0)/20);
  var bacScore = Math.round((pctMastered*0.5 + pctStreak*0.2 + pctXP*0.3));
  var bacNote = Math.round((bacScore/100) * 20);
  var bacMention = bacNote >= 16 ? 'Très Bien' : bacNote >= 14 ? 'Bien' : bacNote >= 12 ? 'Assez Bien' : bacNote >= 10 ? 'Passable' : '—';
  // Battles
  var battlesPlayed = 0, battlesWon = 0;
  if(DB.battles){
    Object.values(DB.battles).forEach(function(b){
      if(b.participants && b.participants[ses.id]){
        battlesPlayed++;
        if(b.participants[ses.id].score >= 8) battlesWon++;
      }
    });
  }
  // ID unique génétique (basé sur l'ID utilisateur — pour rendre chaque genome unique visuellement)
  var hash = (ses.id+'').split('').reduce(function(a,c){return a+c.charCodeAt(0);},0);
  var geneCode = ['VRT','GNM','BAC','DXA','RSL'][hash%5] + '-' + String(hash%9999).padStart(4,'0');

  var body = '<div id="genomeCard" style="background:linear-gradient(135deg,#0F1E47,#1E3A8A 50%,#7C3AED);padding:24px;border-radius:18px;color:#fff;position:relative;overflow:hidden">'
    +'<div style="position:absolute;top:-20px;right:-20px;width:140px;height:140px;border-radius:50%;background:radial-gradient(circle,#FFC93C 0%,transparent 70%);opacity:.3"></div>'
    +'<div style="position:relative;z-index:1">'
    // Header
    +'<div style="display:flex;justify-content:space-between;align-items:start;margin-bottom:18px;flex-wrap:wrap;gap:10px">'
      +'<div>'
        +'<div style="font-size:10px;text-transform:uppercase;letter-spacing:2px;color:#FFC93C;font-weight:800">🧬 VÉRITAS Genome</div>'
        +'<div style="font-size:18px;font-weight:900;margin-top:4px;font-family:Plus Jakarta Sans,sans-serif">'+_esc((ses.pre||'')+' '+(ses.nom||''))+'</div>'
        +'<div style="font-size:11px;opacity:.7;font-family:monospace;margin-top:2px">'+geneCode+'</div>'
      +'</div>'
      +'<div style="text-align:right">'
        +'<div style="font-size:48px;font-weight:900;color:#FFC93C;line-height:1;font-family:Plus Jakarta Sans">'+bacNote+'/20</div>'
        +'<div style="font-size:10px;opacity:.85;text-transform:uppercase;letter-spacing:1px">Prédiction BAC</div>'
        +'<div style="font-size:11px;color:#FFC93C;margin-top:2px">'+bacMention+'</div>'
      +'</div>'
    +'</div>'
    // ADN visuel (barres horizontales colorées)
    +'<div style="background:rgba(0,0,0,.25);border-radius:12px;padding:14px;margin-bottom:14px">'
      +'<div style="font-size:10px;color:#FFC93C;font-weight:800;text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">📊 Profil génétique</div>'
      +[
        {l:'Maîtrise notions',v:Math.round(pctMastered),c:'#10B981'},
        {l:'Régularité (streak)',v:Math.round(pctStreak),c:'#DC2626'},
        {l:'Engagement (XP)',v:Math.round(pctXP),c:'#FFC93C'}
      ].map(function(r){
        return '<div style="margin-bottom:8px">'
          +'<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:3px"><span>'+r.l+'</span><span style="font-weight:700;color:'+r.c+'">'+r.v+'%</span></div>'
          +'<div style="background:rgba(255,255,255,.1);height:6px;border-radius:99px;overflow:hidden"><div style="width:'+r.v+'%;height:100%;background:'+r.c+';border-radius:99px;transition:width 1s"></div></div>'
        +'</div>';
      }).join('')
    +'</div>'
    // Stats
    +'<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;text-align:center;font-size:11px">'
      +'<div><div style="font-size:22px;font-weight:900;color:#FFC93C">'+topics+'</div><div style="opacity:.7">Notions</div></div>'
      +'<div><div style="font-size:22px;font-weight:900;color:#10B981">'+mastered+'</div><div style="opacity:.7">Maîtrisées</div></div>'
      +'<div><div style="font-size:22px;font-weight:900;color:#3C8DFF">'+battlesPlayed+'</div><div style="opacity:.7">Battles</div></div>'
      +'<div><div style="font-size:22px;font-weight:900;color:#EC4899">'+(s.best||0)+'</div><div style="opacity:.7">Record streak</div></div>'
    +'</div>'
    +'<div style="text-align:center;font-size:9px;color:rgba(255,255,255,.4);margin-top:14px;letter-spacing:1px">VÉRITAS ACADEMY · DOUALA · '+new Date().getFullYear()+'</div>'
    +'</div></div>';

  M('🧬 Votre VÉRITAS Genome','ADN académique unique partageable',body,
    '<button class="btn bo" onclick="cm()">Fermer</button>'
    +'<button class="btn" style="background:#25D366;color:#fff" onclick="_genomeShareWA()">📱 Partager WhatsApp</button>'
    +'<button class="btn bi" onclick="_genomeDownload()">📥 Télécharger</button>', true);
};

window._genomeShareWA = function(){
  var ses = (typeof SES!=='undefined' && SES) ? SES : null;
  if(!ses) return;
  var s = _getUserStreak() || {xp:0,current:0};
  var lvl = _currentLevel(s.xp);
  var url = 'https://veritas-school.com';
  var msg = '🧬 Mon VÉRITAS Genome :\n'
    +'• Niveau : '+lvl.current.title+'\n'
    +'• XP : '+s.xp+' · Streak : '+s.current+'j 🔥\n'
    +'Découvre le tien sur '+url+' !';
  window.open('https://wa.me/?text='+encodeURIComponent(msg),'_blank');
};

window._genomeDownload = function(){
  // Utilise html2canvas pour capturer la carte
  if(typeof html2canvas === 'undefined'){
    toast('Module export indisponible — copiez la capture manuellement','warn');
    return;
  }
  var card = document.getElementById('genomeCard');
  if(!card) return;
  html2canvas(card,{backgroundColor:null,scale:2}).then(function(canvas){
    var link = document.createElement('a');
    link.download = 'veritas-genome-'+Date.now()+'.png';
    link.href = canvas.toDataURL('image/png');
    link.click();
    toast('✓ Genome téléchargé','ok');
  }).catch(function(){toast('Échec capture','err');});
};

