window._checkBadges = function(){
  var ses = (typeof SES!=='undefined' && SES) ? SES : null;
  if(!ses) return [];
  var s = _getUserStreak() || {};
  DB.userBadges = DB.userBadges || {};
  DB.userBadges[ses.id] = DB.userBadges[ses.id] || [];
  var unlocked = DB.userBadges[ses.id];
  var newly = [];
  VERITAS_BADGES.forEach(function(b){
    if(unlocked.indexOf(b.id) >= 0) return;
    try {
      if(b.cond(s, DB)){
        unlocked.push(b.id);
        newly.push(b);
      }
    } catch(e){}
  });
  if(newly.length){
    try { save(); } catch(e){}
    // Animation déblocage
    newly.forEach(function(b,i){
      setTimeout(function(){ _showBadgeUnlock(b); }, i*1500);
    });
  }
  return newly;
};

window._showBadgeUnlock = function(badge){
  var n = document.createElement('div');
  n.style.cssText = 'position:fixed;top:80px;right:20px;background:linear-gradient(135deg,#FFC93C,#F59E0B);color:#142554;padding:16px 22px;border-radius:14px;box-shadow:0 12px 40px rgba(0,0,0,.3);z-index:10000;display:flex;gap:12px;align-items:center;max-width:340px;animation:slideInRight .5s ease-out;cursor:pointer;font-family:Plus Jakarta Sans,sans-serif';
  n.innerHTML = '<div style="font-size:36px">'+badge.ic+'</div><div><div style="font-size:10px;text-transform:uppercase;letter-spacing:1.5px;font-weight:800;opacity:.8">🏆 Badge débloqué !</div><div style="font-weight:900;font-size:15px;margin-top:2px">'+badge.t+'</div><div style="font-size:11px;opacity:.85;margin-top:2px">'+badge.d+'</div></div>';
  n.onclick = function(){ mAchievements(); n.remove(); };
  document.body.appendChild(n);
  // Confettis
  _confetti();
  setTimeout(function(){ n.style.transition='all .5s'; n.style.opacity='0'; n.style.transform='translateX(50px)'; setTimeout(function(){n.remove();}, 500); }, 4500);
};

window.mAchievements = function(){
  var ses = (typeof SES!=='undefined' && SES) ? SES : null;
  if(!ses){
    M('🏆 Achievements','Connectez-vous pour débloquer les badges',
      '<div style="text-align:center;padding:18px"><p>30+ badges progressifs : Champion, Marathonien, Sans-faute, Légende…</p></div>',
      '<button class="btn bo" onclick="cm()">Fermer</button><button class="btn bi" onclick="cm();showRegisterForm()">✨ S\'inscrire</button>');
    return;
  }
  // FIX v1.2 : re-vérifier les conditions avant affichage
  if(typeof _checkBadges === 'function') _checkBadges();
  DB.userBadges = DB.userBadges || {};
  var unlocked = DB.userBadges[ses.id] || [];
  var pct = Math.round((unlocked.length / VERITAS_BADGES.length) * 100);
  var body = '<div style="padding:8px">'
    +'<div style="background:linear-gradient(135deg,#FFC93C,#F59E0B);padding:16px;border-radius:14px;text-align:center;margin-bottom:14px;color:#142554">'
      +'<div style="font-size:36px;font-weight:900">'+unlocked.length+'/'+VERITAS_BADGES.length+'</div>'
      +'<div style="font-size:12px;opacity:.85;text-transform:uppercase;letter-spacing:1px;font-weight:800">Badges débloqués · '+pct+'%</div>'
      +'<div style="background:rgba(0,0,0,.15);border-radius:99px;height:6px;margin-top:8px;overflow:hidden"><div style="width:'+pct+'%;height:100%;background:#fff"></div></div>'
    +'</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(110px,1fr));gap:10px">';
  VERITAS_BADGES.forEach(function(b){
    var owned = unlocked.indexOf(b.id) >= 0;
    body += '<div style="text-align:center;padding:12px 8px;background:'+(owned?'linear-gradient(135deg,#FEF3C7,#FFE082)':'#F3F4F6')+';border:1px solid '+(owned?'#FCD34D':'#E5E7EB')+';border-radius:12px;'+(owned?'':'opacity:.5;filter:grayscale(.7)')+'" title="'+_esc(b.d)+'">'
      +'<div style="font-size:32px;margin-bottom:4px">'+b.ic+'</div>'
      +'<div style="font-weight:800;font-size:11px;color:'+(owned?'#92400E':'#6B7280')+';line-height:1.2">'+_esc(b.t)+'</div>'
    +'</div>';
  });
  body += '</div></div>';
  M('🏆 Mes Achievements',pct+'% complétés · '+unlocked.length+'/'+VERITAS_BADGES.length+' badges',body,
    '<button class="btn bi" onclick="cm()">Continuer</button>', true);
};

