// v2.4 — 🎉 CONFETTIS sur succès importants
// ════════════════════════════════════════════════════════════════════
window._confetti = function(){
  var c = document.createElement('div');
  c.style.cssText = 'position:fixed;inset:0;pointer-events:none;z-index:9999;overflow:hidden';
  var colors = ['#FFC93C','#3C8DFF','#10B981','#EC4899','#F59E0B','#7C3AED'];
  for(var i=0;i<40;i++){
    var p = document.createElement('div');
    var col = colors[Math.floor(Math.random()*colors.length)];
    var size = 6 + Math.random()*8;
    p.style.cssText = 'position:absolute;width:'+size+'px;height:'+size+'px;background:'+col+';left:'+(Math.random()*100)+'%;top:-20px;border-radius:'+(Math.random()>0.5?'50%':'2px')+';transform:rotate('+(Math.random()*360)+'deg)';
    var dur = 2 + Math.random()*2;
    var delay = Math.random()*0.5;
    p.animate([
      {transform:'translate(0,0) rotate(0deg)', opacity:1},
      {transform:'translate('+(Math.random()*200-100)+'px,'+(window.innerHeight+50)+'px) rotate('+(Math.random()*720)+'deg)', opacity:0}
    ], {duration: dur*1000, delay: delay*1000, easing:'cubic-bezier(.5,0,.5,1)', fill:'forwards'});
    c.appendChild(p);
  }
  document.body.appendChild(c);
  setTimeout(function(){c.remove();}, 4500);
};

