window.saveForumPost = function(){
  var ses = (typeof SES!=='undefined') ? SES : null;
  if(!ses){ toast('Connexion requise','warn'); return; }
  var title = (_ge('fpTitle')?.value||'').trim();
  var body = (_ge('fpBody')?.value||'').trim();
  var cat = (_ge('fpCat')?.value||'general');
  if(!title || title.length<5){ toast('Titre trop court','warn'); return; }
  if(!body || body.length<10){ toast('Détails trop courts','warn'); return; }
  DB.forumPosts = DB.forumPosts || [];
  DB.forumPosts.push({
    id: gid(), cat: cat, title: title, body: body,
    authorId: ses.id, authorName: (ses.pre||'')+' '+(ses.nom||''),
    date: Date.now(), votes: [], banned: false, parentId: null
  });
  try { save(); } catch(e){}
  // Notif admin
  try { autoNotify && autoNotify('💬 Nouvelle question forum','['+ cat +'] '+title,'info'); } catch(e){}
  cm();
  toast('✓ Question publiée');
  showForumCat(cat);
};

window.showForumPost = function(postId){
  var post = (DB.forumPosts||[]).find(function(p){return p.id===postId;});
  if(!post){ toast('Question introuvable','warn'); return; }
  var replies = (DB.forumPosts||[]).filter(function(p){return p.parentId===postId && !p.banned;}).sort(function(a,b){return a.date-b.date;});
  var ses = (typeof SES!=='undefined') ? SES : null;
  var isLogged = ses && (ses.type==='visiteur_inscrit' || ses.type==='eleve' || ses.type==='enseignant' || iA());
  var hasVoted = ses && (post.votes||[]).indexOf(ses.id) >= 0;
  var cat = FORUM_CATEGORIES.find(function(c){return c.k===post.cat;}) || FORUM_CATEGORIES[0];

  var repliesHTML = replies.length ? replies.map(function(r){
    return '<div style="background:#F9FAFB;padding:12px;border-radius:10px;margin-top:10px;border-left:3px solid #3C8DFF">'
      +'<div style="font-size:13px;color:#374151;white-space:pre-wrap">'+_esc(r.body)+'</div>'
      +'<div style="font-size:11px;color:#9CA3AF;margin-top:8px">👤 '+_esc(r.authorName||'Anonyme')+' · '+new Date(r.date).toLocaleString('fr-FR')+'</div></div>';
  }).join('') : '<div style="text-align:center;padding:20px;color:#9CA3AF">Aucune réponse pour le moment</div>';

  var html = '<div class="vsec">'
    +'<button class="btn bo sm" onclick="showForumCat(\''+post.cat+'\')">← '+cat.l+'</button>'
    +'<div class="card mt12">'
    +'<div style="display:flex;justify-content:space-between;align-items:start;gap:12px;flex-wrap:wrap">'
    +'<h2 style="margin:0;color:#142554;flex:1">'+_esc(post.title)+'</h2>'
    +'<button class="btn '+(hasVoted?'bi':'bo')+'" onclick="voteForumPost(\''+post.id+'\')"'+(!isLogged?' disabled':'')+'>👍 '+(post.votes||[]).length+'</button></div>'
    +'<div style="margin-top:12px;color:#374151;white-space:pre-wrap;font-size:14px;line-height:1.6">'+_esc(post.body)+'</div>'
    +'<div style="font-size:11px;color:#9CA3AF;margin-top:10px">👤 '+_esc(post.authorName||'Anonyme')+' · '+new Date(post.date).toLocaleString('fr-FR')
    +(iA() ? ' · <button class="btn bo sm" onclick="adminBanForumPost(\''+post.id+'\')" style="margin-left:8px">🚫 Supprimer</button>':'')+'</div>'
    +'</div>'
    +'<h3 style="color:#142554;margin-top:18px">💬 Réponses ('+replies.length+')</h3>'
    +repliesHTML
    +(isLogged ? '<div class="card mt12"><textarea class="fi" id="fpReply" rows="3" placeholder="Votre réponse..."></textarea>'
      +'<button class="btn bi mt10" onclick="saveForumReply(\''+post.id+'\')">📤 Répondre</button></div>' : '')
    +'</div>';
  if(typeof _vc==='function') _vc(html); else _si('vContent', html);
};

window.voteForumPost = function(postId){
  var ses = (typeof SES!=='undefined') ? SES : null;
  if(!ses){ toast('Connexion requise','warn'); return; }
  var post = (DB.forumPosts||[]).find(function(p){return p.id===postId;});
  if(!post) return;
  post.votes = post.votes || [];
  var idx = post.votes.indexOf(ses.id);
  if(idx>=0) post.votes.splice(idx,1);
  else post.votes.push(ses.id);
  try { save(); } catch(e){}
  showForumPost(postId);
};

window.saveForumReply = function(parentId){
  var ses = (typeof SES!=='undefined') ? SES : null;
  if(!ses){ toast('Connexion requise','warn'); return; }
  var body = (_ge('fpReply')?.value||'').trim();
  if(!body || body.length<5){ toast('Réponse trop courte','warn'); return; }
  var parent = (DB.forumPosts||[]).find(function(p){return p.id===parentId;});
  DB.forumPosts.push({
    id: gid(), cat: parent ? parent.cat : 'general',
    title: '', body: body,
    authorId: ses.id, authorName: (ses.pre||'')+' '+(ses.nom||''),
    date: Date.now(), votes: [], banned: false, parentId: parentId
  });
  try { save(); } catch(e){}
  toast('✓ Réponse publiée');
  showForumPost(parentId);
};

window.adminBanForumPost = function(postId){
  if(!iA()) return;
  if(!confirm('Supprimer ce post ?')) return;
  var post = (DB.forumPosts||[]).find(function(p){return p.id===postId;});
  if(post){ post.banned = true; try{save();}catch(e){} toast('✓ Supprimé'); showForum(); }
};

// Page admin de modération forum
window.pgForumAdmin = function(){
  if(!iA()) return na();
  var posts = (DB.forumPosts||[]).filter(function(p){return !p.banned;}).sort(function(a,b){return b.date-a.date;});
  var bannedCount = (DB.forumPosts||[]).filter(function(p){return p.banned;}).length;
  var rows = posts.slice(0,50).map(function(p){
    var cat = FORUM_CATEGORIES.find(function(c){return c.k===p.cat;}) || FORUM_CATEGORIES[0];
    var preview = (p.title || p.body || '').slice(0,80);
    return '<tr><td>'+new Date(p.date).toLocaleDateString('fr-FR')+'</td>'
      +'<td><span style="background:'+cat.c+';color:#fff;padding:2px 6px;border-radius:6px;font-size:11px">'+cat.l+'</span></td>'
      +'<td>'+_esc(preview)+'</td>'
      +'<td>'+_esc(p.authorName||'?')+'</td>'
      +'<td>'+(p.parentId?'réponse':'question')+'</td>'
      +'<td><button class="btn sm" style="background:#DC2626;color:#fff" onclick="adminBanForumPost(\''+p.id+'\')">🚫 Suppr.</button></td></tr>';
  }).join('');
  return '<div class="pgt">💬 Modération Forum</div>'
    +'<div class="card mt12"><div class="ct">📊 Stats</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px">'
    +_statCard('💬', posts.length, 'Posts actifs', '#3C8DFF')
    +_statCard('🚫', bannedCount, 'Supprimés', '#EF4444')
    +_statCard('📂', FORUM_CATEGORIES.length, 'Catégories', '#10B981')
    +'</div></div>'
    +'<div class="card mt12"><div class="ct">📋 50 derniers posts</div>'
    +'<div style="overflow-x:auto"><table class="t" style="width:100%;border-collapse:collapse">'
    +'<thead><tr><th>Date</th><th>Cat.</th><th>Aperçu</th><th>Auteur</th><th>Type</th><th>Action</th></tr></thead>'
    +'<tbody>'+rows+'</tbody></table></div></div>';
};

