// ── v1.2 P3 — #11 MARKETPLACE ENSEIGNANTS ──────────────────────────
// ════════════════════════════════════════════════════════════════════
// Auteurs & enseignants peuvent soumettre cours/quiz/livres/épreuves. Admin valide.
// Modèle 70/30 (70% auteur, 30% VÉRITAS) — taux concurrentiel.
window.MARKETPLACE_COMMISSION = 0.30;

window.pgMarketplaceEnseignant = function(){
  var ses = (typeof SES!=='undefined') ? SES : null;
  if(!ses || (ses.type!=='enseignant' && ses.type!=='visiteur_inscrit' && !iA())) return na();
  DB.marketplaceItems = DB.marketplaceItems || [];
  var mine = DB.marketplaceItems.filter(function(m){return m.teacherId===ses.id;});
  var totalSales = mine.reduce(function(s,m){return s+(m.salesCount||0);},0);
  var totalRev = mine.reduce(function(s,m){return s+((m.salesCount||0)*(m.price||0)*(1-MARKETPLACE_COMMISSION));},0);
  var pending = mine.filter(function(m){return m.status==='pending';}).length;
  var approved = mine.filter(function(m){return m.status==='approved';}).length;

  var itemsHTML = mine.length ? mine.map(function(m){
    var statusColor = {pending:'#F59E0B', approved:'#10B981', rejected:'#EF4444'}[m.status]||'#6B7280';
    var statusLbl = {pending:'⏳ En attente', approved:'✅ Approuvé', rejected:'❌ Refusé'}[m.status]||'?';
    return '<div class="card" style="margin:8px 0">'
      +'<div style="display:flex;justify-content:space-between;align-items:start;gap:10px">'
      +'<div style="flex:1"><b>'+_esc(m.title)+'</b> <span style="background:#E5E7EB;padding:2px 6px;border-radius:4px;font-size:11px">'+_esc(m.type)+'</span>'
      +'<div style="font-size:12px;color:#6B7280;margin-top:4px">'+_esc((m.description||'').slice(0,100))+'</div></div>'
      +'<div style="text-align:right">'
      +'<span style="background:'+statusColor+';color:#fff;padding:4px 10px;border-radius:8px;font-size:11px;font-weight:700">'+statusLbl+'</span>'
      +'<div style="font-weight:800;color:#10B981;margin-top:6px">'+fmt(m.price||0)+'</div>'
      +'<div style="font-size:11px;color:#9CA3AF">'+(m.salesCount||0)+' ventes</div></div></div>'
      +(m.rejectReason ? '<div style="background:#FEE2E2;padding:8px;border-radius:6px;margin-top:8px;font-size:12px;color:#991B1B"><b>Refus :</b> '+_esc(m.rejectReason)+'</div>':'')
      +'</div>';
  }).join('') : '<div style="text-align:center;padding:30px;color:#9CA3AF">Aucun contenu soumis. Cliquez sur "Soumettre" pour commencer !</div>';

  return '<div class="pgt">🛒 Espace Auteur — Mes contenus</div>'
    +'<div class="card mt12"><div class="ct">📊 Vue d\'ensemble</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px">'
    +_statCard('📚', mine.length, 'Soumissions', '#3C8DFF')
    +_statCard('✅', approved, 'Approuvés', '#10B981')
    +_statCard('⏳', pending, 'En attente', '#F59E0B')
    +_statCard('🛒', totalSales, 'Ventes', '#EC4899')
    +_statCard('💰', fmt(totalRev), 'Revenus (70%)', '#FFC93C')
    +'</div></div>'
    +'<div class="card mt12">'
    +'<button class="btn bi" onclick="mMarketplaceSubmit()">📤 Soumettre un nouveau contenu</button>'
    +'<div class="ib ibi mt12 mb0"><span>💡</span><span>Modèle <b>70/30</b> : vous touchez 70% des ventes, VÉRITAS 30%. Versement mensuel via MoMo/Orange.</span></div></div>'
    +'<div class="card mt12"><div class="ct">📋 Mes contenus</div>'+itemsHTML+'</div>';
};

window.mMarketplaceSubmit = function(){
  M('📤 Soumettre un contenu', 'Modèle 70/30 (vous 70%, VÉRITAS 30%)',
    '<div class="fg"><span class="fl">Type *</span><select class="fi" id="mkType">'
    +'<option value="cours">📚 Cours complet</option>'
    +'<option value="quiz">❓ Quiz / Évaluation</option>'
    +'<option value="livre">📖 Livre / E-book PDF</option>'
    +'<option value="video">🎥 Vidéo pédagogique</option>'
    +'</select></div>'
    +'<div class="fg"><span class="fl">Titre *</span><input class="fi" id="mkTitle" placeholder="Ex: Cours complet de Géométrie 3ème"></div>'
    +'<div class="fg"><span class="fl">Description *</span><textarea class="fi" id="mkDesc" rows="4" placeholder="Décrivez votre contenu, son public, ses objectifs..."></textarea></div>'
    +'<div class="fg"><span class="fl">Niveau</span><select class="fi" id="mkLevel">'
    +'<option value="6e">6ème</option><option value="5e">5ème</option><option value="4e">4ème</option><option value="3e">3ème</option>'
    +'<option value="2nde">2nde</option><option value="1ere">1ère</option><option value="tle">Terminale</option></select></div>'
    +'<div class="fg"><span class="fl">Matière</span><input class="fi" id="mkSubject" placeholder="Ex: Mathématiques"></div>'
    +'<div class="fg"><span class="fl">Prix de vente (FCFA) *</span><input class="fi" id="mkPrice" type="number" min="500" step="500" value="2000"></div>'
    +'<div class="fg"><span class="fl">Lien contenu (URL ou WeTransfer)</span><input class="fi" id="mkUrl" placeholder="https://..."></div>'
    +'<div style="background:#FEF3C7;padding:10px;border-radius:8px;font-size:12px;color:#92400E"><b>ℹ️</b> Votre soumission sera validée par un admin VÉRITAS sous 48h.</div>',
    '<button class="btn bo" onclick="cm()">Annuler</button>'
    +'<button class="btn bi" onclick="saveMarketplaceItem()">📤 Soumettre</button>', true);
};

window.saveMarketplaceItem = function(){
  var ses = (typeof SES!=='undefined') ? SES : null;
  if(!ses){ toast('Connexion requise','warn'); return; }
  var title = (_ge('mkTitle')?.value||'').trim();
  var desc = (_ge('mkDesc')?.value||'').trim();
  var price = parseInt(_ge('mkPrice')?.value)||0;
  if(!title || title.length<5){ toast('Titre trop court','warn'); return; }
  if(!desc || desc.length<20){ toast('Description trop courte','warn'); return; }
  if(price<500){ toast('Prix minimum 500 FCFA','warn'); return; }
  DB.marketplaceItems = DB.marketplaceItems || [];
  DB.marketplaceItems.push({
    id: gid(),
    teacherId: ses.id,
    teacherName: (ses.pre||'')+' '+(ses.nom||''),
    type: _ge('mkType')?.value||'cours',
    title: title,
    description: desc,
    level: _ge('mkLevel')?.value||'',
    subject: _ge('mkSubject')?.value||'',
    price: price,
    url: _ge('mkUrl')?.value||'',
    status: 'pending',
    salesCount: 0,
    submittedAt: Date.now()
  });
  try { save(); } catch(e){}
  try { autoNotify && autoNotify('🛒 Nouvelle soumission marketplace', title+' par '+(ses.pre||'?'), 'info'); } catch(e){}
  cm();
  toast('✓ Soumission envoyée pour validation','ok');
  if(typeof re==='function') re();
};

// Page admin validation
window.pgMarketplaceAdmin = function(){
  if(!iA()) return na();
  DB.marketplaceItems = DB.marketplaceItems || [];
  var pending = DB.marketplaceItems.filter(function(m){return m.status==='pending';});
  var approved = DB.marketplaceItems.filter(function(m){return m.status==='approved';});
  var totalRev = approved.reduce(function(s,m){return s+((m.salesCount||0)*(m.price||0)*MARKETPLACE_COMMISSION);},0);

  var pendingHTML = pending.length ? pending.map(function(m){
    return '<div class="card" style="border-left:4px solid #F59E0B;margin:8px 0">'
      +'<div style="display:flex;justify-content:space-between;align-items:start;gap:10px">'
      +'<div style="flex:1"><b>'+_esc(m.title)+'</b> <span style="background:#E5E7EB;padding:2px 6px;border-radius:4px;font-size:11px">'+_esc(m.type)+' / '+_esc(m.level)+'</span>'
      +'<div style="font-size:12px;color:#6B7280;margin-top:4px">Par <b>'+_esc(m.teacherName)+'</b> · '+_esc(m.subject||'?')+'</div>'
      +'<div style="font-size:13px;color:#374151;margin-top:8px">'+_esc(m.description)+'</div>'
      +(m.url ? '<a href="'+_esc(m.url)+'" target="_blank" style="color:#3C8DFF;font-size:12px">🔗 '+_esc(m.url)+'</a>':'')
      +'</div>'
      +'<div style="text-align:right"><b style="color:#10B981">'+fmt(m.price)+'</b></div></div>'
      +'<div style="display:flex;gap:8px;margin-top:12px">'
      +'<button class="btn sm" style="background:#10B981;color:#fff" onclick="adminApproveMK(\''+m.id+'\')">✅ Approuver</button>'
      +'<button class="btn sm" style="background:#EF4444;color:#fff" onclick="adminRejectMK(\''+m.id+'\')">❌ Refuser</button>'
      +'</div></div>';
  }).join('') : '<div style="text-align:center;padding:20px;color:#10B981">✅ Aucune soumission en attente</div>';

  return '<div class="pgt">🛒 Marketplace — Modération</div>'
    +'<div class="card mt12"><div class="ct">📊 Stats globales</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px">'
    +_statCard('⏳', pending.length, 'En attente', '#F59E0B')
    +_statCard('✅', approved.length, 'Approuvés', '#10B981')
    +_statCard('💰', fmt(totalRev), 'Commission VÉRITAS (30%)', '#FFC93C')
    +'</div></div>'
    +'<div class="card mt12"><div class="ct">⏳ Soumissions à valider</div>'+pendingHTML+'</div>';
};

window.adminApproveMK = function(id){
  if(!iA()) return;
  var m = (DB.marketplaceItems||[]).find(function(x){return x.id===id;});
  if(!m) return;
  m.status = 'approved';
  m.approvedAt = Date.now();
  try { save(); } catch(e){}
  try { autoNotify && autoNotify('✅ Contenu approuvé', m.title+' est désormais publié sur la marketplace','ok'); } catch(e){}
  toast('✓ Approuvé');
  if(typeof re==='function') re();
};

window.adminRejectMK = function(id){
  if(!iA()) return;
  var reason = prompt('Raison du refus (visible par l\'enseignant) :');
  if(reason===null) return;
  var m = (DB.marketplaceItems||[]).find(function(x){return x.id===id;});
  if(!m) return;
  m.status = 'rejected';
  m.rejectReason = reason||'Non précisé';
  m.rejectedAt = Date.now();
  try { save(); } catch(e){}
  toast('Refusé');
  if(typeof re==='function') re();
};

