// ── v1.2 P3 — #15 MULTI-TENANT — Préparation centre_id ─────────────
// ════════════════════════════════════════════════════════════════════
// Permet d'héberger plusieurs centres sur la même instance.
// Sous-domaine → centre_id. Chaque DB.* est tagguée centreId.
window.MULTITENANT = {
  current: null,
  init: function(){
    try {
      // Résolution depuis sous-domaine (douala.veritas-school.com → 'douala')
      var host = location.hostname.split('.');
      var sub = host.length >= 3 ? host[0] : 'default';
      if(sub==='www'||sub==='veritas-school'||sub==='localhost') sub = 'default';
      MULTITENANT.current = sub;
      if(!DB._centreId) DB._centreId = sub;
      document.documentElement.setAttribute('data-centre', sub);
    } catch(e){ MULTITENANT.current = 'default'; }
  },
  registerCentre: function(centre){
    if(!iA()) return;
    DB.centres = DB.centres || [];
    DB.centres.push({
      id: centre.id || gid(),
      slug: centre.slug,
      nom: centre.nom,
      ville: centre.ville,
      email: centre.email,
      tel: centre.tel,
      plan: centre.plan||'starter', // starter / pro / enterprise
      mrrFcfa: centre.mrrFcfa||10000,
      createdAt: Date.now(),
      active: true
    });
    try { save(); } catch(e){}
  }
};
try { MULTITENANT.init(); } catch(e){}

