// v2.5 — CALENDRIER ADMIN ÉDITABLE (CRUD complet)
// ════════════════════════════════════════════════════════════════════
window.pgCalendrierAdmin = function(){
  if(!iA()) return na();
  // Charger depuis DB ou clone du statique au premier accès
  if(!DB.calendrierData || !DB.calendrierData.annee){
    try { DB.calendrierData = JSON.parse(JSON.stringify(CALENDRIER_SCOLAIRE)); save(); } catch(e){}
  }
  var cal = DB.calendrierData;

  var h = '<div class="pgt">📅 Calendrier Scolaire — Édition</div>';
  h += '<div class="ib ibi mt12 mb14"><span>ℹ️</span><span>Toutes les modifications sont sauvegardées automatiquement et visibles sur le portail visiteur dans l\'onglet <strong>Calendrier</strong>.</span></div>';

  // ─── Année scolaire ───
  h += '<div class="card mt12"><div class="ct">📆 Année scolaire</div>';
  h += '<div class="fg"><span class="fl">Année (ex: 2026-2027)</span><input class="fi" id="calAnnee" value="'+_esc(cal.annee||'')+'"></div>';
  h += '<button class="btn bi sm" onclick="_calSaveAnnee()">💾 Mettre à jour l\'année</button>';
  h += '</div>';

  // ─── Trimestres + séquences ───
  h += '<div class="card mt12"><div class="ct">🗓️ Trimestres &amp; Séquences</div>';
  (cal.trimestres||[]).forEach(function(tri, ti){
    var triLabel = tri.num===1 ? '1er Trimestre' : tri.num+'ème Trimestre';
    h += '<div style="background:#F8FAFC;border:1px solid #E2E8F0;border-radius:12px;padding:14px;margin-bottom:12px">';
    h += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><strong style="color:#1E3A8A;font-size:15px">'+triLabel+'</strong>';
    h += '<button class="btn sm" style="background:#FEE2E2;color:#DC2626;border:none;border-radius:8px;padding:4px 10px" onclick="_calDelTri('+ti+')">🗑 Supprimer trimestre</button>';
    h += '</div>';
    h += '<div class="fg2">';
    h += '<div class="fg"><span class="fl">Date début</span><input class="fi" id="calT'+ti+'Debut" value="'+_esc(tri.debut||'')+'"></div>';
    h += '<div class="fg"><span class="fl">Date fin</span><input class="fi" id="calT'+ti+'Fin" value="'+_esc(tri.fin||'')+'"></div>';
    h += '</div>';
    h += '<div style="font-weight:700;color:#475569;font-size:13px;margin:10px 0 6px">Séquences</div>';
    (tri.seqs||[]).forEach(function(s, si){
      h += '<div style="background:#fff;border:1px solid #E2E8F0;border-radius:8px;padding:10px;margin-bottom:6px;display:grid;grid-template-columns:60px 1fr 1fr 2fr 30px;gap:8px;align-items:center">';
      h += '<input class="fi" type="number" id="calT'+ti+'S'+si+'Num" value="'+(s.num||'')+'" style="text-align:center">';
      h += '<input class="fi" id="calT'+ti+'S'+si+'Debut" value="'+_esc(s.debut||'')+'" placeholder="Début">';
      h += '<input class="fi" id="calT'+ti+'S'+si+'Fin" value="'+_esc(s.fin||'')+'" placeholder="Fin">';
      h += '<input class="fi" id="calT'+ti+'S'+si+'Exa" value="'+_esc(s.examens||'')+'" placeholder="Épreuves">';
      h += '<button class="btn sm" style="background:#FEE2E2;color:#DC2626;border:none;border-radius:6px;padding:4px 8px;font-size:11px" onclick="_calDelSeq('+ti+','+si+')" title="Supprimer">×</button>';
      h += '</div>';
    });
    h += '<button class="btn sm bvi mt8" onclick="_calAddSeq('+ti+')">+ Ajouter une séquence</button>';
    h += '<button class="btn bi sm mt8" style="margin-left:8px" onclick="_calSaveTri('+ti+')">💾 Enregistrer ce trimestre</button>';
    h += '</div>';
  });
  h += '<button class="btn bi" onclick="_calAddTri()">+ Ajouter un trimestre</button>';
  h += '</div>';

  // ─── Examens nationaux ───
  h += '<div class="card mt12"><div class="ct">🎓 Examens Nationaux</div>';
  h += '<div style="overflow-x:auto"><table class="t" style="width:100%;border-collapse:collapse;font-size:13px"><thead><tr>';
  h += '<th style="padding:8px;text-align:left">Nom</th><th>Date</th><th>Niveaux</th><th>Matières</th><th>Action</th></tr></thead><tbody>';
  (cal.examens_nationaux||[]).forEach(function(ex, i){
    h += '<tr>';
    h += '<td style="padding:6px"><input class="fi" id="calEx'+i+'Nom" value="'+_esc(ex.nom||'')+'"></td>';
    h += '<td style="padding:6px"><input class="fi" id="calEx'+i+'Date" value="'+_esc(ex.date||'')+'"></td>';
    h += '<td style="padding:6px"><input class="fi" id="calEx'+i+'Niv" value="'+_esc(ex.niveaux||'')+'"></td>';
    h += '<td style="padding:6px"><input class="fi" id="calEx'+i+'Mat" value="'+_esc(ex.matières||'')+'"></td>';
    h += '<td style="padding:6px"><button class="btn sm" style="background:#FEE2E2;color:#DC2626;border:none;border-radius:6px;padding:4px 10px" onclick="_calDelExam('+i+')">🗑</button></td>';
    h += '</tr>';
  });
  h += '</tbody></table></div>';
  h += '<div class="mt12"><button class="btn bvi sm" onclick="_calAddExam()">+ Ajouter un examen</button>';
  h += '<button class="btn bi sm" style="margin-left:8px" onclick="_calSaveAllExams()">💾 Enregistrer tous les examens</button></div>';
  h += '</div>';

  // ─── Vacances ───
  h += '<div class="card mt12"><div class="ct">🏖️ Vacances scolaires</div>';
  (cal.vacances||[]).forEach(function(v, i){
    h += '<div style="display:grid;grid-template-columns:2fr 1fr 1fr 40px;gap:10px;align-items:center;margin-bottom:8px">';
    h += '<input class="fi" id="calVac'+i+'Lab" value="'+_esc(v.label||'')+'" placeholder="Label (ex: Toussaint)">';
    h += '<input class="fi" id="calVac'+i+'Deb" value="'+_esc(v.debut||'')+'" placeholder="Début">';
    h += '<input class="fi" id="calVac'+i+'Fin" value="'+_esc(v.fin||'')+'" placeholder="Fin">';
    h += '<button class="btn sm" style="background:#FEE2E2;color:#DC2626;border:none;border-radius:6px;padding:4px 8px;font-size:11px" onclick="_calDelVac('+i+')">×</button>';
    h += '</div>';
  });
  h += '<div class="mt12"><button class="btn bvi sm" onclick="_calAddVac()">+ Ajouter des vacances</button>';
  h += '<button class="btn bi sm" style="margin-left:8px" onclick="_calSaveAllVac()">💾 Enregistrer toutes les vacances</button></div>';
  h += '</div>';

  // ─── Actions globales ───
  h += '<div class="card mt12" style="background:#FEF3C7;border:1px solid #FCD34D"><div class="ct">⚙️ Actions globales</div>';
  h += '<button class="btn" style="background:#1E3A8A;color:#fff" onclick="_calSaveAll()">💾 Enregistrer TOUT le calendrier</button> ';
  h += '<button class="btn bo sm" style="margin-left:8px" onclick="_calReset()">↻ Réinitialiser au calendrier officiel</button> ';
  h += '<button class="btn sm" style="background:#10B981;color:#fff;margin-left:8px" onclick="window.open(\'/?cal=preview\',\'_blank\')">👁️ Aperçu portail visiteur</button>';
  h += '<div class="ib ibg mt12 mb0"><span>✅</span><span>Pensez à cliquer <strong>Enregistrer TOUT</strong> après vos modifications pour les rendre visibles sur le portail.</span></div>';
  h += '</div>';
  return h;
};

// Helpers CRUD
window._calSaveAnnee = function(){
  var v = (_ge('calAnnee')||{}).value||'';
  DB.calendrierData.annee = v.trim();
  save(); toast('✓ Année enregistrée');
};

window._calSaveTri = function(ti){
  var tri = DB.calendrierData.trimestres[ti];
  if(!tri) return;
  tri.debut = (_ge('calT'+ti+'Debut')||{}).value || tri.debut;
  tri.fin = (_ge('calT'+ti+'Fin')||{}).value || tri.fin;
  (tri.seqs||[]).forEach(function(s, si){
    s.num = parseInt((_ge('calT'+ti+'S'+si+'Num')||{}).value) || s.num;
    s.debut = (_ge('calT'+ti+'S'+si+'Debut')||{}).value || s.debut;
    s.fin = (_ge('calT'+ti+'S'+si+'Fin')||{}).value || s.fin;
    s.examens = (_ge('calT'+ti+'S'+si+'Exa')||{}).value || s.examens;
  });
  save(); toast('✓ Trimestre '+(ti+1)+' enregistré'); re();
};

window._calAddSeq = function(ti){
  var tri = DB.calendrierData.trimestres[ti];
  if(!tri) return;
  tri.seqs = tri.seqs || [];
  var nextNum = (tri.seqs.length>0 ? tri.seqs[tri.seqs.length-1].num+1 : 1);
  tri.seqs.push({num:nextNum, debut:'', fin:'', examens:''});
  save(); re();
};

window._calDelSeq = function(ti, si){
  if(!confirm('Supprimer cette séquence ?')) return;
  DB.calendrierData.trimestres[ti].seqs.splice(si, 1);
  save(); re();
};

window._calAddTri = function(){
  var trs = DB.calendrierData.trimestres;
  trs.push({num: trs.length+1, debut:'', fin:'', seqs:[]});
  save(); re();
};

window._calDelTri = function(ti){
  if(!confirm('Supprimer ce trimestre et toutes ses séquences ?')) return;
  DB.calendrierData.trimestres.splice(ti, 1);
  save(); re();
};

window._calAddExam = function(){
  DB.calendrierData.examens_nationaux = DB.calendrierData.examens_nationaux || [];
  DB.calendrierData.examens_nationaux.push({nom:'Nouvel examen', date:'', niveaux:'', matières:''});
  save(); re();
};

window._calDelExam = function(i){
  if(!confirm('Supprimer cet examen ?')) return;
  DB.calendrierData.examens_nationaux.splice(i, 1);
  save(); re();
};

window._calSaveAllExams = function(){
  (DB.calendrierData.examens_nationaux||[]).forEach(function(ex, i){
    ex.nom = (_ge('calEx'+i+'Nom')||{}).value || ex.nom;
    ex.date = (_ge('calEx'+i+'Date')||{}).value || ex.date;
    ex.niveaux = (_ge('calEx'+i+'Niv')||{}).value || ex.niveaux;
    ex.matières = (_ge('calEx'+i+'Mat')||{}).value || ex.matières;
  });
  save(); toast('✓ Examens enregistrés');
};

window._calAddVac = function(){
  DB.calendrierData.vacances = DB.calendrierData.vacances || [];
  DB.calendrierData.vacances.push({label:'Nouvelles vacances', debut:'', fin:''});
  save(); re();
};

window._calDelVac = function(i){
  if(!confirm('Supprimer ces vacances ?')) return;
  DB.calendrierData.vacances.splice(i, 1);
  save(); re();
};

window._calSaveAllVac = function(){
  (DB.calendrierData.vacances||[]).forEach(function(v, i){
    v.label = (_ge('calVac'+i+'Lab')||{}).value || v.label;
    v.debut = (_ge('calVac'+i+'Deb')||{}).value || v.debut;
    v.fin = (_ge('calVac'+i+'Fin')||{}).value || v.fin;
  });
  save(); toast('✓ Vacances enregistrées');
};

window._calSaveAll = function(){
  _calSaveAnnee();
  (DB.calendrierData.trimestres||[]).forEach(function(_, ti){ _calSaveTri(ti); });
  _calSaveAllExams();
  _calSaveAllVac();
  toast('✓ Calendrier complet enregistré','ok');
};

window._calReset = function(){
  if(!confirm('Réinitialiser au calendrier officiel ? Toutes vos modifications seront perdues.')) return;
  try { DB.calendrierData = JSON.parse(JSON.stringify(CALENDRIER_SCOLAIRE)); save(); re(); toast('✓ Calendrier réinitialisé','ok'); } catch(e){ toast('Erreur reset','err'); }
};

window.pgCentresAdmin = function(){
  if(!iA() || !isSA()) return na();
  DB.centres = DB.centres || [];
  var totalMRR = DB.centres.filter(function(c){return c.active;}).reduce(function(s,c){return s+(+c.mrrFcfa||0);},0);
  var rows = DB.centres.map(function(c){
    return '<tr>'
      +'<td><b>'+_esc(c.nom||'?')+'</b><br><span style="font-size:11px;color:#6B7280">'+_esc(c.slug||'?')+'.veritas-school.com</span></td>'
      +'<td>'+_esc(c.ville||'?')+'</td>'
      +'<td><span style="background:#3C8DFF;color:#fff;padding:2px 8px;border-radius:6px;font-size:11px">'+_esc(c.plan)+'</span></td>'
      +'<td><b style="color:#10B981">'+fmt(c.mrrFcfa||0)+'</b>/mois</td>'
      +'<td>'+new Date(c.createdAt).toLocaleDateString('fr-FR')+'</td>'
      +'<td>'+(c.active?'✅':'⏸️')+'</td></tr>';
  }).join('') || '<tr><td colspan="6" style="text-align:center;padding:20px;color:#9CA3AF">Aucun centre client (mode mono-tenant)</td></tr>';
  return '<div class="pgt">🏢 Centres clients (multi-tenant)</div>'
    +'<div class="card mt12"><div class="ct">📊 SaaS Overview</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:12px">'
    +_statCard('🏢', DB.centres.length, 'Centres clients', '#3C8DFF')
    +_statCard('✅', DB.centres.filter(function(c){return c.active;}).length, 'Actifs', '#10B981')
    +_statCard('💰', fmt(totalMRR), 'MRR mensuel récurrent', '#FFC93C')
    +_statCard('📅', fmt(totalMRR*12), 'ARR annualisé', '#7C3AED')
    +'</div></div>'
    +'<div class="card mt12"><div class="ct">🏢 Liste des centres</div>'
    +'<button class="btn bi sm" onclick="mAddCentre()">➕ Ajouter un centre client</button>'
    +'<div style="overflow-x:auto;margin-top:12px"><table class="t" style="width:100%;border-collapse:collapse">'
    +'<thead><tr><th>Centre</th><th>Ville</th><th>Plan</th><th>MRR</th><th>Inscrit</th><th>Statut</th></tr></thead>'
    +'<tbody>'+rows+'</tbody></table></div></div>'
    +'<div class="card mt12"><div class="ct">💡 Notice multi-tenant</div>'
    +'<div class="ib ibi mb0"><span>ℹ️</span><span>L\'isolation complète des données par centre nécessite un backend dédié (cf. ROADMAP_LONG_TERME.md #15). Le frontend est prêt — il manque les Row-Level Security côté SQL et la résolution serveur des sous-domaines.</span></div></div>';
};

window.mAddCentre = function(){
  M('🏢 Ajouter un centre client', 'Plan SaaS multi-tenant',
    '<div class="fg"><span class="fl">Nom du centre *</span><input class="fi" id="cNom" placeholder="Centre VÉRITAS Yaoundé"></div>'
    +'<div class="fg"><span class="fl">Sous-domaine (slug) *</span><input class="fi" id="cSlug" placeholder="yaounde" style="text-transform:lowercase"></div>'
    +'<div class="fg"><span class="fl">Ville</span><input class="fi" id="cVille" placeholder="Yaoundé"></div>'
    +'<div class="fg"><span class="fl">Email contact</span><input class="fi" id="cEmail" type="email"></div>'
    +'<div class="fg"><span class="fl">Téléphone WhatsApp</span><input class="fi" id="cTel" placeholder="+237 6XX XX XX XX"></div>'
    +'<div class="fg"><span class="fl">Plan</span><select class="fi" id="cPlan">'
    +'<option value="starter">Starter — 10 000 FCFA/mois (≤100 élèves)</option>'
    +'<option value="pro">Pro — 25 000 FCFA/mois (≤500 élèves)</option>'
    +'<option value="enterprise">Enterprise — 50 000 FCFA/mois (illimité)</option>'
    +'</select></div>',
    '<button class="btn bo" onclick="cm()">Annuler</button>'
    +'<button class="btn bi" onclick="saveCentre()">💾 Créer le centre</button>');
};

window.saveCentre = function(){
  var nom = (_ge('cNom')?.value||'').trim();
  var slug = (_ge('cSlug')?.value||'').trim().toLowerCase().replace(/[^a-z0-9-]/g,'');
  var plan = _ge('cPlan')?.value||'starter';
  var mrr = {starter:10000, pro:25000, enterprise:50000}[plan]||10000;
  if(!nom || !slug){ toast('Nom et slug requis','warn'); return; }
  MULTITENANT.registerCentre({
    slug: slug, nom: nom,
    ville: _ge('cVille')?.value||'',
    email: _ge('cEmail')?.value||'',
    tel: _ge('cTel')?.value||'',
    plan: plan, mrrFcfa: mrr
  });
  cm();
  toast('✓ Centre '+nom+' créé');
  if(typeof re==='function') re();
};

