function openProductPage(itemId, type){
  var item = null;
  var el = DB.elearning || {};
  if(type === 'contenu'){
    item = (el.contenus||[]).find(function(c){return c.id===itemId;});
  } else if(type === 'abonnement'){
    item = (el.plans||[]).find(function(p){return p.id===itemId;});
  } else if(type === 'article'){
    item = (DB.books||[]).find(function(b){return b.id===itemId;});
  }
  if(!item) { toast('Produit introuvable','warn'); return; }

  var titre = item.titre || item.nom || 'Produit';
  var prix = item.prix || 0;
  var desc = item.desc || item.description || '';
  var apercu = item.apercu || item.resume || '';
  var classe = item.classe || item.cls || '';
  var matiere = item.matiere || '';
  var seq = item.seq || '';
  var ico = item.ico || (type==='contenu'?'📄':type==='abonnement'?'🎓':'📚');
  var chaps = item.chaps || item.chapitres || [];
  var prixAncien = item.prixAncien || item.oldPrix || 0;
  var prixFmt = new Intl.NumberFormat('fr-FR').format(prix) + ' FCFA';

  var badges = '';
  if(classe) badges += '<span style="display:inline-block;background:var(--blb);color:var(--bl);padding:4px 10px;border-radius:20px;font-size:11px;font-weight:700;margin-right:6px">'+_esc(classe)+'</span>';
  if(matiere) badges += '<span style="display:inline-block;background:var(--pub);color:var(--pu);padding:4px 10px;border-radius:20px;font-size:11px;font-weight:700;margin-right:6px">'+_esc(matiere)+'</span>';
  if(seq) badges += '<span style="display:inline-block;background:var(--orb);color:var(--or);padding:4px 10px;border-radius:20px;font-size:11px;font-weight:700">'+_esc(seq)+'</span>';

  var chapHtml = '';
  if(chaps.length){
    chapHtml = '<div style="margin-top:16px"><div style="font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;color:var(--ink);margin-bottom:10px">📋 Contenu inclus</div>';
    chapHtml += chaps.map(function(ch){ return '<div style="padding:6px 0;border-bottom:1px solid var(--bg2);font-size:13px;color:var(--ink2)"><span style="color:var(--gr);margin-right:8px">✅</span>'+_esc(ch)+'</div>'; }).join('');
    chapHtml += '</div>';
  }

  var waNum = (window.VERITAS_PAYMENTS?.whatsapp||'').replace(/[^0-9+]/g,'').replace(/^\+/,'');
  var waMsg = encodeURIComponent('Bonjour, je souhaite commander :\n\n📦 '+titre+'\n💰 '+prixFmt+'\n\nMerci de me confirmer la disponibilité.');
  var waUrl = 'https://wa.me/'+waNum+'?text='+waMsg;

  var html = ''
    +'<div id="productPageOverlay" style="position:fixed;inset:0;z-index:9500;background:#fff;overflow-y:auto;animation:su .25s">'
    +'<div style="max-width:680px;margin:0 auto;padding:24px 20px 40px">'

    // Close button
    +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px">'
    +'<button onclick="document.getElementById(\'productPageOverlay\').remove()" style="background:var(--bg2);border:none;border-radius:50%;width:40px;height:40px;font-size:20px;cursor:pointer;display:flex;align-items:center;justify-content:center">←</button>'
    +'<span style="font-size:11px;color:var(--ink4);font-weight:600;letter-spacing:1px;text-transform:uppercase">VÉRITAS Boutique</span>'
    +'</div>'

    // SECTION A — Hero produit
    +'<div style="text-align:center;margin-bottom:28px">'
    +'<div style="font-size:64px;margin-bottom:12px">'+ico+'</div>'
    +'<div style="font-family:Montserrat,sans-serif;font-size:22px;font-weight:800;color:var(--ink);margin-bottom:8px">'+_esc(titre)+'</div>'
    +(badges?'<div style="margin-bottom:12px">'+badges+'</div>':'')
    +(prixAncien?'<div style="font-size:14px;color:var(--ink4);text-decoration:line-through">'+new Intl.NumberFormat('fr-FR').format(prixAncien)+' FCFA</div>':'')
    +'<div style="font-family:Montserrat,sans-serif;font-size:32px;font-weight:900;color:var(--gold)">'+prixFmt+'</div>'
    +'<div style="margin-top:10px;display:inline-block;background:var(--grb);color:var(--gr);padding:6px 14px;border-radius:20px;font-size:12px;font-weight:700">✅ Accès immédiat après paiement</div>'
    +'</div>'

    // CTA principal
    +'<div style="display:flex;gap:10px;margin-bottom:28px;flex-wrap:wrap">'
    +'<button onclick="document.getElementById(\'productPageOverlay\').remove();openPaymentModal({montant:'+prix+',label:\''+_esc(titre).replace(/'/g,"\\'")+'\',refPrefix:\''+( type==='contenu'?'ELRN':type==='abonnement'?'ELRN':'SHOP')+'\'})" style="flex:1;min-width:200px;background:var(--gold);color:var(--ink);border:none;border-radius:14px;padding:16px 24px;font-family:Montserrat,sans-serif;font-size:15px;font-weight:800;cursor:pointer;box-shadow:0 4px 16px rgba(255,201,60,.3)">💳 Payer maintenant — '+prixFmt+'</button>'
    +'<button onclick="addToCart(\''+itemId+'\',\''+type+'\')" style="min-width:140px;background:var(--sur);color:var(--ink);border:2px solid var(--bg3);border-radius:14px;padding:16px 20px;font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;cursor:pointer">🛒 Ajouter au panier</button>'
    +'</div>'

    // SECTION B — Aperçu
    +(apercu?'<div style="margin-bottom:24px"><div style="font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;color:var(--ink);margin-bottom:10px">📖 Aperçu du contenu</div><div style="background:var(--bg2);border-left:4px solid var(--gold);padding:16px;border-radius:0 12px 12px 0;font-size:13px;color:var(--ink2);line-height:1.7">'+_esc(apercu)+'</div></div>':'')

    // SECTION C — Description + chapitres
    +(desc?'<div style="margin-bottom:24px"><div style="font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;color:var(--ink);margin-bottom:10px">📝 Description</div><div style="font-size:13px;color:var(--ink2);line-height:1.7">'+_esc(desc)+'</div></div>':'')
    +chapHtml

    // SECTION D — Informations livraison
    +'<div style="margin:28px 0;background:var(--sur2);border:1px solid var(--bg2);border-radius:14px;padding:20px">'
    +'<div style="font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;color:var(--ink);margin-bottom:12px">📦 Informations de livraison</div>'
    +'<div style="font-size:13px;color:var(--ink2);line-height:2">'
    +'📩 Livraison par WhatsApp sous 24h<br>'
    +'📱 Compatible smartphone, tablette, ordinateur<br>'
    +'🔒 Paiement sécurisé — MoMo · Orange Money · PayPal · Carte'
    +'</div></div>'

    // SECTION E — CTA final
    +'<div style="display:flex;flex-direction:column;gap:10px;margin-top:24px">'
    +'<button onclick="document.getElementById(\'productPageOverlay\').remove();openPaymentModal({montant:'+prix+',label:\''+_esc(titre).replace(/'/g,"\\'")+'\',refPrefix:\''+( type==='contenu'?'ELRN':type==='abonnement'?'ELRN':'SHOP')+'\'})" style="background:var(--gold);color:var(--ink);border:none;border-radius:14px;padding:16px;font-family:Montserrat,sans-serif;font-size:15px;font-weight:800;cursor:pointer;box-shadow:0 4px 16px rgba(255,201,60,.3)">💳 Payer — '+prixFmt+'</button>'
    +'<a href="'+waUrl+'" target="_blank" rel="noopener" style="text-align:center;background:#25d366;color:#fff;border:none;border-radius:14px;padding:14px;font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;cursor:pointer;text-decoration:none">📲 Commander par WhatsApp</a>'
    +'<button onclick="document.getElementById(\'productPageOverlay\').remove()" style="background:var(--bg2);color:var(--ink3);border:none;border-radius:14px;padding:12px;font-size:13px;font-weight:600;cursor:pointer">← Retour à la boutique</button>'
    +'</div>'

    +'</div></div>';

  var wrap = document.createElement('div');
  wrap.innerHTML = html;
  document.body.appendChild(wrap.firstChild);
}
window.openProductPage = openProductPage;

