// ── v1.1 — MODULE 2 : PANIER DE COMMANDE ────────────────────────
// ═══════════════════════════════════════════════��══════════════════

function _getCart(){ DB.cart = DB.cart || []; return DB.cart; }

function addToCart(itemId, type){
  var cart = _getCart();
  var existing = cart.find(function(c){return c.id===itemId;});
  if(existing){ existing.qty = (existing.qty||1)+1; save(); renderCartBadge(); toast('✓ Quantité mise à jour'); return; }

  var item = null, titre = '', prix = 0;
  var el = DB.elearning || {};
  if(type === 'contenu'){
    item = (el.contenus||[]).find(function(c){return c.id===itemId;});
    if(item){ titre = item.titre; prix = item.prix||0; }
  } else if(type === 'abonnement'){
    item = (el.plans||[]).find(function(p){return p.id===itemId;});
    if(item){ titre = item.nom; prix = item.prix||0; }
  } else if(type === 'article'){
    item = (DB.books||[]).find(function(b){return b.id===itemId;});
    if(item){ titre = item.titre; prix = item.prix||0; }
  }
  if(!item){ toast('Produit introuvable','warn'); return; }

  cart.push({id:itemId, titre:titre, prix:prix, type:type, qty:1});
  save();
  renderCartBadge();
  toast('✓ '+titre+' ajouté au panier');
}

function removeFromCart(itemId){
  DB.cart = (DB.cart||[]).filter(function(c){return c.id!==itemId;});
  save();
  renderCartBadge();
  openCart();
}

function renderCartBadge(){
  var cart = _getCart();
  var badge = document.getElementById('cartBadge');
  if(!badge) return;
  var total = cart.reduce(function(s,c){return s+(c.qty||1);},0);
  if(total > 0){
    badge.style.display = 'flex';
    badge.textContent = total > 99 ? '99+' : total;
  } else {
    badge.style.display = 'none';
  }
}

function openCart(){
  var cart = _getCart();
  if(!cart.length){
    M('🛒 Votre panier','Aucun article',
      '<div style="text-align:center;padding:30px"><div style="font-size:48px;margin-bottom:12px">🛒</div><div style="font-size:14px;color:var(--ink4)">Votre panier est vide.<br>Parcourez notre boutique pour ajouter des articles.</div></div>',
      '<button class="btn bo" onclick="cm()">Fermer</button>');
    return;
  }
  var total = cart.reduce(function(s,c){return s + (c.prix||0)*(c.qty||1);},0);
  var totalFmt = new Intl.NumberFormat('fr-FR').format(total) + ' FCFA';
  var rows = cart.map(function(c){
    var sub = new Intl.NumberFormat('fr-FR').format((c.prix||0)*(c.qty||1));
    return '<div style="display:flex;align-items:center;gap:12px;padding:12px 0;border-bottom:1px solid var(--bg2)">'
      +'<div style="flex:1;min-width:0"><div style="font-size:13px;font-weight:600;color:var(--ink)">'+_esc(c.titre)+'</div>'
      +'<div style="font-size:11px;color:var(--ink4);margin-top:2px">'+_esc(c.type)+' · Qté: '+(c.qty||1)+'</div></div>'
      +'<div style="font-family:Montserrat,sans-serif;font-size:13px;font-weight:700;color:var(--gold);white-space:nowrap">'+sub+' F</div>'
      +'<button onclick="removeFromCart(\''+c.id+'\')" style="background:var(--reb);color:var(--re);border:none;border-radius:8px;width:28px;height:28px;font-size:14px;cursor:pointer">×</button>'
      +'</div>';
  }).join('');

  var labels = cart.map(function(c){return c.titre;}).join(' + ');
  if(labels.length > 60) labels = labels.substring(0,57)+'...';

  M('🛒 Votre panier', cart.length+' article'+(cart.length>1?'s':''),
    rows
    +'<div style="display:flex;justify-content:space-between;align-items:center;padding:16px 0;margin-top:8px">'
    +'<span style="font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;color:var(--ink)">Total</span>'
    +'<span style="font-family:Montserrat,sans-serif;font-size:20px;font-weight:900;color:var(--gold)">'+totalFmt+'</span>'
    +'</div>',
    '<button class="btn bo" onclick="cm()">Continuer les achats</button>'
    +'<button class="btn bi" onclick="cm();openPaymentModal({montant:'+total+',label:\'🛒 '+_esc(labels).replace(/'/g,"\\'")+'\',refPrefix:\'CART\'})">💳 Payer tout — '+totalFmt+'</button>',
    true);
}

window.addToCart = addToCart;
window.removeFromCart = removeFromCart;
window.openCart = openCart;
window.renderCartBadge = renderCartBadge;
setTimeout(renderCartBadge, 500);

