// ═══════════════════════════════��══════════════════════���═══════════

var _origOpenPaymentModal = openPaymentModal;

openPaymentModal = function(payInfo){
  payInfo = payInfo || {};
  var montant = payInfo.montant || 0;
  var label = payInfo.label || 'Paiement VÉRITAS';
  var ref = payInfo.ref || _payRef(payInfo.refPrefix || 'VT');
  var P = window.VERITAS_PAYMENTS;
  if(!P) return;

  _promoApplied = null;
  _promoDiscount = 0;

  var montantFmt = new Intl.NumberFormat('fr-FR').format(montant) + ' FCFA';
  var montantEUR = (montant / 655).toFixed(2);

  var waNum = (P.whatsapp||'').replace(/[^0-9+]/g,'').replace(/^\+/,'');

  // Stepper HTML
  var stepper = '<div style="display:flex;align-items:center;justify-content:center;gap:8px;margin-bottom:20px">'
    +'<div id="payStep1Ind" style="width:28px;height:28px;border-radius:50%;background:var(--gold);color:var(--ink);display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:800">①</div>'
    +'<div style="width:30px;height:2px;background:var(--bg3)"></div>'
    +'<div id="payStep2Ind" style="width:28px;height:28px;border-radius:50%;background:var(--bg3);color:var(--ink4);display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:800">②</div>'
    +'<div style="width:30px;height:2px;background:var(--bg3)"></div>'
    +'<div id="payStep3Ind" style="width:28px;height:28px;border-radius:50%;background:var(--bg3);color:var(--ink4);display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:800">③</div>'
    +'</div>'
    +'<div style="display:flex;justify-content:center;gap:24px;font-size:10px;color:var(--ink4);margin-bottom:16px;text-align:center">'
    +'<span style="width:70px">Coordonnées</span><span style="width:70px">Paiement</span><span style="width:70px">Confirmer</span></div>';

  // Step 1 : Client form
  var step1 = '<div id="payStep1">'
    +'<div style="background:linear-gradient(135deg,#142554,#1E3A8A);color:#fff;padding:16px;border-radius:14px;margin-bottom:16px">'
    +'<div style="font-size:11px;letter-spacing:2px;opacity:.7;text-transform:uppercase">Paiement pour</div>'
    +'<div style="font-family:Montserrat,sans-serif;font-size:18px;font-weight:800;margin-top:4px">'+_esc(label)+'</div>'
    +'<div style="font-size:28px;font-weight:900;color:#FFC93C;margin-top:8px" id="payStepTotal">'+montantFmt+'</div>'
    +'<div style="font-size:11px;opacity:.7;margin-top:2px">≈ '+montantEUR+' € / USD</div>'
    +'</div>'
    +'<div style="font-family:Montserrat,sans-serif;font-size:13px;font-weight:700;margin-bottom:10px;color:var(--ink)">👤 Vos coordonnées</div>'
    +'<div class="fg2">'
    +'<div class="fg"><span class="fl">Nom complet *</span><input class="fi" id="payNom" placeholder="Ex: MBALLA Jean-Pierre"></div>'
    +'<div class="fg"><span class="fl">Numéro WhatsApp *</span><input class="fi" id="payTel" type="tel" placeholder="+237 6XX XX XX XX"></div>'
    +'<div class="fg"><span class="fl">Email (pour PDF)</span><input class="fi" id="payEmail" type="email" placeholder="votre@email.com"></div>'
    +'</div>'
    +'<div style="margin-top:12px"><span class="fl">Code promo</span><div style="display:flex;gap:8px"><input class="fi" id="promoInput" placeholder="Ex: ELEVE10" style="flex:1;text-transform:uppercase"><button class="btn bi sm" onclick="appliquerPromo('+montant+')" style="white-space:nowrap">Appliquer</button></div><div id="promoFeedback" style="margin-top:6px"></div></div>'
    +'<div style="margin-top:16px;text-align:right"><button class="btn bi" onclick="_payGoStep(2)">Suivant →</button></div>'
    +'</div>';

  // Step 2 : Payment methods
  var step2 = '<div id="payStep2" style="display:none">'
    +'<div class="bold s mb10" style="color:var(--ink2)">💰 Choisissez votre moyen de paiement :</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:10px;margin-bottom:16px">'
    // MoMo
    +'<div style="background:#fff;border:2px solid '+P.momo.couleur+';border-radius:12px;padding:12px;cursor:pointer" onclick="_payCopy(\''+P.momo.numero.replace(/[^0-9+]/g,'')+'\',\'Numéro MoMo\')">'
    +'<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px"><div style="font-size:24px">'+P.momo.ico+'</div><div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:13px;color:#142554">'+P.momo.label+'</div></div>'
    +'<div style="font-family:monospace;font-size:14px;font-weight:800;color:'+P.momo.couleur+'">'+P.momo.numero+'</div>'
    +'<div style="font-size:10px;color:var(--ink4);margin-top:4px">Nom: '+P.momo.nomCompte+' · USSD: '+P.momo.code+'</div>'
    +'<div style="font-size:9px;color:var(--ink4);margin-top:4px;font-style:italic">👆 Cliquez pour copier</div></div>'
    // Orange
    +'<div style="background:#fff;border:2px solid '+P.orange.couleur+';border-radius:12px;padding:12px;cursor:pointer" onclick="_payCopy(\''+P.orange.numero.replace(/[^0-9+]/g,'')+'\',\'Numéro Orange Money\')">'
    +'<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px"><div style="font-size:24px">'+P.orange.ico+'</div><div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:13px;color:#142554">'+P.orange.label+'</div></div>'
    +'<div style="font-family:monospace;font-size:14px;font-weight:800;color:'+P.orange.couleur+'">'+P.orange.numero+'</div>'
    +'<div style="font-size:10px;color:var(--ink4);margin-top:4px">Nom: '+P.orange.nomCompte+' · USSD: '+P.orange.code+'</div>'
    +'<div style="font-size:9px;color:var(--ink4);margin-top:4px;font-style:italic">👆 Cliquez pour copier</div></div>'
    // PayPal
    +'<a href="'+P.paypal.url+'" target="_blank" rel="noopener" style="text-decoration:none;background:#fff;border:2px solid '+P.paypal.couleur+';border-radius:12px;padding:12px;display:block">'
    +'<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px"><div style="font-size:24px">'+P.paypal.ico+'</div><div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:13px;color:#142554">'+P.paypal.label+'</div></div>'
    +'<div style="font-size:11px;color:var(--ink4)">Paiement international sécurisé</div>'
    +'<div style="font-size:10px;color:'+P.paypal.couleur+';margin-top:4px;font-weight:700">→ Ouvrir PayPal</div></a>'
    // Stripe (affiché seulement si configuré)
    + (_payOK(P.stripe.url) ? ('<a href="'+P.stripe.url+'" target="_blank" rel="noopener" style="text-decoration:none;background:#fff;border:2px solid '+P.stripe.couleur+';border-radius:12px;padding:12px;display:block">'
    +'<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px"><div style="font-size:24px">'+P.stripe.ico+'</div><div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:13px;color:#142554">'+P.stripe.label+'</div></div>'
    +'<div style="font-size:11px;color:var(--ink4)">Visa · Mastercard · Amex</div>'
    +'<div style="font-size:10px;color:'+P.stripe.couleur+';margin-top:4px;font-weight:700">→ Payer par carte</div></a>') : '')
    // Bank (affiché seulement si configuré)
    + (_payOK(P.bank.iban) ? ('<div style="background:#fff;border:2px solid '+P.bank.couleur+';border-radius:12px;padding:12px;grid-column:1/-1">'
    +'<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px"><div style="font-size:24px">'+P.bank.ico+'</div><div style="font-family:Montserrat,sans-serif;font-weight:800;font-size:13px;color:#142554">'+P.bank.label+'</div></div>'
    +'<div style="font-size:11px;color:var(--ink3);line-height:1.6"><strong>Titulaire:</strong> '+P.bank.titulaire+' · <strong>Banque:</strong> '+P.bank.banque+'<br><strong>IBAN:</strong> <span style="font-family:monospace;background:var(--bg2);padding:2px 4px;border-radius:4px;font-size:10px">'+P.bank.iban+'</span> · <strong>SWIFT:</strong> '+P.bank.swift+'</div></div>') : '')
    +'</div>'
    +'<div style="display:flex;justify-content:space-between;margin-top:12px"><button class="btn bo" onclick="_payGoStep(1)">← Précédent</button><button class="btn bi" onclick="_payGoStep(3)">J\'ai payé → Confirmer</button></div>'
    +'</div>';

  // Step 3 : Confirmation
  var step3 = '<div id="payStep3" style="display:none">'
    +'<div style="text-align:center;padding:16px">'
    +'<div style="font-size:48px;margin-bottom:12px">✅</div>'
    +'<div style="font-family:Montserrat,sans-serif;font-size:18px;font-weight:800;color:var(--ink);margin-bottom:8px">Confirmation de paiement</div>'
    +'<div style="background:var(--bg2);border-radius:12px;padding:16px;margin:16px 0;text-align:left">'
    +'<div style="font-size:12px;color:var(--ink4);margin-bottom:4px">Référence de transaction</div>'
    +'<div style="font-family:monospace;font-size:18px;font-weight:800;color:var(--gold)">'+ref+'</div>'
    +'<div style="font-size:12px;color:var(--ink4);margin-top:8px">Montant : <strong>'+montantFmt+'</strong></div>'
    +'</div>'
    +'<div style="font-size:13px;color:var(--ink2);line-height:1.7;margin-bottom:16px">Notre équipe activera votre accès sous <strong>24h</strong> après vérification.<br>Conservez cette référence.</div>'
    +'<button class="btn bo sm" onclick="_payCopy(\''+ref+'\',\'Référence\')" style="margin-bottom:12px">📋 Copier la référence</button>'
    +'</div>'
    +'<div id="payStep3WA"></div>'
    +'<div style="display:flex;justify-content:space-between;margin-top:12px"><button class="btn bo" onclick="_payGoStep(2)">← Précédent</button><button class="btn bi" onclick="cm()">Fermer</button></div>'
    +'</div>';

  var body = stepper + step1 + step2 + step3;

  // Save attempt
  try{
    DB.payAttempts = DB.payAttempts || [];
    DB.payAttempts.push({
      ref: ref, label: label, montant: montant,
      date: new Date().toISOString(),
      status: 'pending'
    });
    if(typeof save === 'function') save();
  }catch(e){}

  M('💰 Paiement Sécurisé', label+' — '+montantFmt, body,
    '<button class="btn bo" onclick="cm()">Fermer</button>', true);
};
window.openPaymentModal = openPaymentModal;

function _payGoStep(step){
  var s1=document.getElementById('payStep1'), s2=document.getElementById('payStep2'), s3=document.getElementById('payStep3');
  var i1=document.getElementById('payStep1Ind'), i2=document.getElementById('payStep2Ind'), i3=document.getElementById('payStep3Ind');
  if(!s1||!s2||!s3) return;

  if(step===2){
    var nom=(document.getElementById('payNom')?.value||'').trim();
    var tel=(document.getElementById('payTel')?.value||'').trim();
    if(!nom||!tel){toast('Nom et WhatsApp requis','warn');return;}
    // Save client info to latest payAttempt
    var latest = (DB.payAttempts||[])[(DB.payAttempts||[]).length-1];
    if(latest){latest.clientNom=nom;latest.clientTel=tel;latest.clientEmail=(document.getElementById('payEmail')?.value||'').trim();if(_promoApplied){latest.promo=_promoApplied;latest.discount=_promoDiscount;latest.montantFinal=Math.round(latest.montant*(100-_promoDiscount)/100);}save();}
  }

  if(step===3){
    // Build WhatsApp confirmation
    var latest2=(DB.payAttempts||[])[(DB.payAttempts||[]).length-1]||{};
    var cNom=latest2.clientNom||'';
    var cTel=latest2.clientTel||'';
    var mFinal=latest2.montantFinal||latest2.montant||0;
    var mFinalFmt=new Intl.NumberFormat('fr-FR').format(mFinal)+' FCFA';
    var P2=window.VERITAS_PAYMENTS;
    var waNum2=(P2.whatsapp||'').replace(/[^0-9+]/g,'').replace(/^\+/,'');
    var waMsg2=encodeURIComponent('Bonjour,\n\nJe viens d\'effectuer un paiement.\n\n👤 Nom: '+cNom+'\n📱 Tél: '+cTel+'\n📦 Article: '+(latest2.label||'')+'\n💰 Montant: '+mFinalFmt+'\n🔖 Réf: '+(latest2.ref||'')+'\n💳 Moyen: [MoMo / Orange / PayPal / Carte / Virement]\n\nMerci de confirmer.');
    var waUrl2='https://wa.me/'+waNum2+'?text='+waMsg2;
    var s3wa=document.getElementById('payStep3WA');
    if(s3wa) s3wa.innerHTML='<a href="'+waUrl2+'" target="_blank" rel="noopener" style="display:flex;align-items:center;justify-content:center;gap:10px;background:#25d366;color:#fff;border-radius:12px;padding:14px;font-family:Montserrat,sans-serif;font-weight:800;font-size:14px;text-decoration:none;box-shadow:0 4px 16px rgba(37,211,102,.4)">📲 Envoyer ma confirmation WhatsApp</a>';
  }

  s1.style.display=step===1?'block':'none';
  s2.style.display=step===2?'block':'none';
  s3.style.display=step===3?'block':'none';
  if(i1){i1.style.background=step>=1?'var(--gold)':'var(--bg3)';i1.style.color=step>=1?'var(--ink)':'var(--ink4)';}
  if(i2){i2.style.background=step>=2?'var(--gold)':'var(--bg3)';i2.style.color=step>=2?'var(--ink)':'var(--ink4)';}
  if(i3){i3.style.background=step>=3?'var(--gold)':'var(--bg3)';i3.style.color=step>=3?'var(--ink)':'var(--ink4)';}
}
window._payGoStep = _payGoStep;

