// ── v1.1 — MODULE 5 : TABLEAU DE BORD PAIEMENTS (admin) ─────────
// ══════════════════════════════════════════════════════════════════

function pgPaiementsAdmin(){
  if(!iA()) return na();
  var atts = (DB.payAttempts||[]).slice().reverse();
  var paid = atts.filter(function(a){return a.status==='paid';});
  var pending = atts.filter(function(a){return a.status==='pending';});
  var totalCollected = paid.reduce(function(s,a){return s+(a.montantFinal||a.montant||0);},0);
  var avgRevenue = paid.length ? Math.round(totalCollected/paid.length) : 0;

  // KPIs
  var h = '<div class="fl2 fic fsb mb16 fw g8"><div class="bold" style="font-size:18px">💳 Tableau de bord Paiements</div></div>';
  h += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:12px;margin-bottom:24px">';
  h += '<div style="background:linear-gradient(135deg,var(--grb),var(--grd));border-radius:14px;padding:16px;text-align:center"><div style="font-size:11px;color:var(--gr);font-weight:700;text-transform:uppercase;letter-spacing:1px">Total collecté</div><div style="font-family:Montserrat,sans-serif;font-size:20px;font-weight:900;color:var(--gr);margin-top:6px">'+new Intl.NumberFormat('fr-FR').format(totalCollected)+'</div><div style="font-size:10px;color:var(--ink4)">FCFA</div></div>';
  h += '<div style="background:linear-gradient(135deg,var(--orb),var(--ord));border-radius:14px;padding:16px;text-align:center"><div style="font-size:11px;color:var(--or);font-weight:700;text-transform:uppercase;letter-spacing:1px">En attente</div><div style="font-family:Montserrat,sans-serif;font-size:20px;font-weight:900;color:var(--or);margin-top:6px">'+pending.length+'</div><div style="font-size:10px;color:var(--ink4)">transactions</div></div>';
  h += '<div style="background:linear-gradient(135deg,var(--blb),var(--bld));border-radius:14px;padding:16px;text-align:center"><div style="font-size:11px;color:var(--bl);font-weight:700;text-transform:uppercase;letter-spacing:1px">Validées</div><div style="font-family:Montserrat,sans-serif;font-size:20px;font-weight:900;color:var(--bl);margin-top:6px">'+paid.length+'</div><div style="font-size:10px;color:var(--ink4)">transactions</div></div>';
  h += '<div style="background:linear-gradient(135deg,var(--pub),var(--pud));border-radius:14px;padding:16px;text-align:center"><div style="font-size:11px;color:var(--pu);font-weight:700;text-transform:uppercase;letter-spacing:1px">Revenu moyen</div><div style="font-family:Montserrat,sans-serif;font-size:20px;font-weight:900;color:var(--pu);margin-top:6px">'+new Intl.NumberFormat('fr-FR').format(avgRevenue)+'</div><div style="font-size:10px;color:var(--ink4)">FCFA / transaction</div></div>';
  h += '</div>';

  // Filter
  h += '<div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap">';
  h += '<button class="btn bo sm" onclick="window._payFilter=\'\';re();" style="'+((!window._payFilter)?'background:var(--ink);color:#fff':'')+'">Tous ('+atts.length+')</button>';
  h += '<button class="btn bo sm" onclick="window._payFilter=\'pending\';re();" style="'+((window._payFilter==='pending')?'background:var(--or);color:#fff':'')+'">En attente ('+pending.length+')</button>';
  h += '<button class="btn bo sm" onclick="window._payFilter=\'paid\';re();" style="'+((window._payFilter==='paid')?'background:var(--gr);color:#fff':'')+'">Payés ('+paid.length+')</button>';
  h += '</div>';

  // Filtered list
  var filtered = atts;
  if(window._payFilter==='pending') filtered = pending;
  else if(window._payFilter==='paid') filtered = paid;

  // Table
  if(filtered.length){
    h += '<div class="tw" style="max-height:400px;overflow:auto"><table><thead><tr><th>Réf</th><th>Nom</th><th>Tél</th><th>Article</th><th>Montant</th><th>Date</th><th>Statut</th><th>Actions</th></tr></thead><tbody>';
    filtered.forEach(function(a){
      var dt = a.date ? new Date(a.date).toLocaleString('fr-FR') : '';
      var statColor = a.status==='paid' ? 'var(--gr)' : 'var(--or)';
      var mnt = a.montantFinal || a.montant || 0;
      var clientWA = (a.clientTel||'').replace(/[^0-9]/g,'');
      if(clientWA && !clientWA.startsWith('237')) clientWA = '237'+clientWA;
      h += '<tr>'
        +'<td style="font-family:monospace;font-size:10px">'+_esc(a.ref||'')+'</td>'
        +'<td style="font-size:11px">'+_esc(a.clientNom||'-')+'</td>'
        +'<td style="font-size:11px">'+_esc(a.clientTel||'-')+'</td>'
        +'<td style="font-size:11px;max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+_esc(a.label||'')+'</td>'
        +'<td style="font-size:11px;white-space:nowrap;font-weight:700">'+new Intl.NumberFormat('fr-FR').format(mnt)+' F</td>'
        +'<td style="font-size:10px;color:var(--ink4);white-space:nowrap">'+dt+'</td>'
        +'<td><span style="padding:2px 8px;border-radius:10px;font-size:9px;font-weight:800;background:'+statColor+';color:#fff">'+_esc(a.status||'pending').toUpperCase()+'</span></td>'
        +'<td style="white-space:nowrap">'
        +'<button class="btn xs bi" onclick="(function(){var a=DB.payAttempts.find(function(x){return x.ref===\''+a.ref+'\'});if(a){a.status=\'paid\';save();re();toast(\'✓ Marqué payé\');}})()">✓</button> '
        +(clientWA?'<a href="https://wa.me/'+clientWA+'" target="_blank" class="btn xs bo" style="text-decoration:none">📲</a> ':'')
        +'<button class="btn xs bo" style="color:var(--re)" onclick="(function(){if(!confirm(\'Supprimer ?\'))return;DB.payAttempts=DB.payAttempts.filter(function(x){return x.ref!==\''+a.ref+'\'});save();re();})()">🗑</button>'
        +'</td></tr>';
    });
    h += '</tbody></table></div>';
  } else {
    h += '<div style="text-align:center;padding:30px;color:var(--ink4)">Aucune transaction trouvée.</div>';
  }

  // Monthly chart (CSS bars)
  h += '<div style="margin-top:28px"><div style="font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;margin-bottom:16px;color:var(--ink)">📊 Revenus mensuels (6 derniers mois)</div>';
  var months = [];
  var now = new Date();
  for(var mi=5;mi>=0;mi--){
    var d = new Date(now.getFullYear(), now.getMonth()-mi, 1);
    var mKey = d.getFullYear()+'-'+('0'+(d.getMonth()+1)).slice(-2);
    var mLabel = ['Jan','Fév','Mar','Avr','Mai','Jun','Jul','Aoû','Sep','Oct','Nov','Déc'][d.getMonth()];
    var mTotal = paid.filter(function(a){return(a.date||'').startsWith(mKey);}).reduce(function(s,a){return s+(a.montantFinal||a.montant||0);},0);
    months.push({label:mLabel, total:mTotal});
  }
  var maxM = Math.max.apply(null, months.map(function(m){return m.total;}))||1;
  h += '<div style="display:flex;align-items:flex-end;gap:8px;height:120px;padding:8px 0;border-bottom:2px solid var(--bg2)">';
  months.forEach(function(m){
    var pct = Math.round(m.total/maxM*100);
    h += '<div style="flex:1;display:flex;flex-direction:column;align-items:center;justify-content:flex-end;height:100%">'
      +'<div style="font-size:9px;color:var(--ink4);margin-bottom:4px">'+(m.total?new Intl.NumberFormat('fr-FR').format(m.total):'0')+'</div>'
      +'<div style="width:100%;max-width:40px;height:'+Math.max(pct,4)+'%;background:var(--gold);border-radius:6px 6px 0 0;transition:height .3s"></div>'
      +'</div>';
  });
  h += '</div><div style="display:flex;gap:8px;margin-top:6px">';
  months.forEach(function(m){ h+='<div style="flex:1;text-align:center;font-size:10px;color:var(--ink4);font-weight:600">'+m.label+'</div>'; });
  h += '</div></div>';

  // Promo codes section
  h += '<div style="margin-top:28px"><div style="font-family:Montserrat,sans-serif;font-size:14px;font-weight:700;margin-bottom:12px;color:var(--ink)">🏷️ Codes Promo actifs</div>';
  var promos = window.VERITAS_PROMOS || {};
  var promoKeys = Object.keys(promos);
  if(promoKeys.length){
    h += '<div class="tw"><table><thead><tr><th>Code</th><th>Réduction</th><th>Utilisations</th><th>Max</th><th>Statut</th></tr></thead><tbody>';
    promoKeys.forEach(function(k){
      var p=promos[k];
      var full = p.usage>=p.max;
      h += '<tr><td style="font-family:monospace;font-weight:700">'+k+'</td><td>'+p.pct+'%</td><td>'+p.usage+'</td><td>'+p.max+'</td>'
        +'<td><span style="padding:2px 8px;border-radius:10px;font-size:10px;font-weight:700;background:'+(full?'var(--re)':'var(--gr)')+';color:#fff">'+(full?'ÉPUISÉ':'ACTIF')+'</span></td></tr>';
    });
    h += '</tbody></table></div>';
  }
  h += '<button class="btn bo sm mt14" onclick="_mAddPromo()">+ Ajouter un code promo</button>';
  h += '</div>';

  return h;
}

function _mAddPromo(){
  M('🏷️ Nouveau code promo','',
    '<div class="fg2">'
    +'<div class="fg"><span class="fl">Code *</span><input class="fi" id="npCode" placeholder="MONCODE" style="text-transform:uppercase"></div>'
    +'<div class="fg"><span class="fl">Réduction (%) *</span><input class="fi" id="npPct" type="number" min="1" max="100" placeholder="10"></div>'
    +'<div class="fg"><span class="fl">Label</span><input class="fi" id="npLabel" placeholder="Description courte"></div>'
    +'<div class="fg"><span class="fl">Utilisations max *</span><input class="fi" id="npMax" type="number" min="1" placeholder="100"></div>'
    +'</div>',
    '<button class="btn bo" onclick="cm()">Annuler</button><button class="btn bi" onclick="_saveNewPromo()">✓ Créer</button>');
}

function _saveNewPromo(){
  var code=(document.getElementById('npCode')?.value||'').trim().toUpperCase();
  var pct=parseInt(document.getElementById('npPct')?.value)||0;
  var label=(document.getElementById('npLabel')?.value||'').trim();
  var max=parseInt(document.getElementById('npMax')?.value)||100;
  if(!code||!pct){toast('Code et % requis','warn');return;}
  if(!window.VERITAS_PROMOS) window.VERITAS_PROMOS={};
  window.VERITAS_PROMOS[code]={pct:pct,label:label||code,usage:0,max:max};
  cm();re();
  toast('✓ Code '+code+' créé ('+pct+'%)');
}

window.pgPaiementsAdmin = pgPaiementsAdmin;
window._mAddPromo = _mAddPromo;
window._saveNewPromo = _saveNewPromo;

// ══════════════════════════════════════════════════════════════════
// ── DIAGNOSTIC SYNTAX ERROR AMÉLIORÉ v1.0 ───────────────────────
// ══════════════════════════════════════════════════════════════════
// Améliore la capture d'erreur pour localiser précisément les SyntaxError runtime
(function(){
  var oldHandler = window.onerror;
  window.onerror = function(msg, src, line, col, err){
    if(typeof oldHandler==='function') try{oldHandler.apply(this, arguments);}catch(e){}
    // Logger dans localStorage pour debug post-mortem
    try{
      var logs = JSON.parse(localStorage.getItem('_veritasErrors')||'[]');
      logs.push({
        msg: String(msg).substring(0,500),
        src: String(src).substring(0,200),
        line: line, col: col,
        stack: err && err.stack ? String(err.stack).substring(0,1000) : '',
        when: new Date().toISOString()
      });
      if(logs.length>50) logs = logs.slice(-50);
      localStorage.setItem('_veritasErrors', JSON.stringify(logs));
    }catch(e){}
    return false;
  };
})();
// Accessible depuis la console : window.showVeritasErrors()
window.showVeritasErrors = function(){
  try{
    var logs = JSON.parse(localStorage.getItem('_veritasErrors')||'[]');
    console.table(logs);
    return logs;
  }catch(e){return [];}
};
window.clearVeritasErrors = function(){
  localStorage.removeItem('_veritasErrors');
  console.log('✓ Logs d\'erreurs effacés');
};

// ── VÉRIFICATION ET PATCH TICKER FIXED SPEED ─────────────────────
// (initTickerFixed défini plus haut — on relance après chargement complet)
setTimeout(function(){initTickerFixed();},1200);
setTimeout(function(){initTickerFixed();},3000);

// ═══════════════════════════════════════════════════════════════
// VÉRITAS v1.1.2 — DESIGN PREMIUM : Scroll Reveal, Ripple, Progress
// ═══════════════════════════════════════════════════════════════

(function(){
  'use strict';

  // ── 1. SCROLL REVEAL via IntersectionObserver ──
  // Uses multiple observers: one per scrollable root (#vContent, .cnt, viewport)
  function initScrollReveal(){
    if(!('IntersectionObserver' in window)) return;
    var targets = '.vcard, .card, .sc, .rc, .nc, .jeu-card, .pk, .ai-card, .bc, .partner-card, .el-cat-panel, .review-card, .dv-card, .vsec-title, .vstats, .quiz-container, .mgr-card, .photo-card, .hours-card, .note-card, .book-viewer, .featured-card';

    function makeObserver(root){
      return new IntersectionObserver(function(entries){
        entries.forEach(function(e){
          if(e.isIntersecting){
            e.target.classList.add('v-reveal','visible');
            try { observerMap.get(e.target).unobserve(e.target); } catch(x){}
          }
        });
      }, { threshold: 0.06, root: root || null, rootMargin: '0px 0px -30px 0px' });
    }

    var observerMap = new Map();
    var vcObs = null, cntObs = null, vpObs = makeObserver(null);

    function getObserverForEl(el){
      // Find which scrollable container this element lives in
      var vc = document.getElementById('vContent');
      var cnt = document.querySelector('.cnt');
      if(vc && vc.contains(el)){
        if(!vcObs) vcObs = makeObserver(vc);
        return vcObs;
      }
      if(cnt && cnt.contains(el)){
        if(!cntObs) cntObs = makeObserver(cnt);
        return cntObs;
      }
      return vpObs;
    }

    function scan(){
      document.querySelectorAll(targets).forEach(function(el){
        if(!el.classList.contains('visible') && !el.dataset.vScanned){
          el.dataset.vScanned = '1';
          var parent = el.parentElement;
          if(parent){
            var siblings = Array.prototype.filter.call(parent.children, function(c){ return c.matches && c.matches(targets); });
            var idx = siblings.indexOf(el);
            if(idx > 0 && idx <= 6) el.dataset.delay = String(idx);
          }
          el.classList.add('v-reveal');
          var obs = getObserverForEl(el);
          observerMap.set(el, obs);
          obs.observe(el);
        }
      });
    }

    // Reveal elements already visible (no scroll needed)
    function revealVisible(){
      document.querySelectorAll('.v-reveal:not(.visible)').forEach(function(el){
        var root = null;
        var vc = document.getElementById('vContent');
        var cnt = document.querySelector('.cnt');
        if(vc && vc.contains(el)) root = vc;
        else if(cnt && cnt.contains(el)) root = cnt;
        var rootRect = root ? root.getBoundingClientRect() : { top: 0, bottom: window.innerHeight };
        var elRect = el.getBoundingClientRect();
        // Element is visible if its top is above root bottom
        if(elRect.top < rootRect.bottom && elRect.bottom > rootRect.top){
          el.classList.add('visible');
          try { observerMap.get(el).unobserve(el); } catch(x){}
        }
      });
    }

    scan();
    setInterval(scan, 1500);
    // Check initially visible elements after a short delay
    setTimeout(revealVisible, 500);
    setTimeout(revealVisible, 2000);

    var origRe = window.re;
    if(typeof origRe === 'function'){
      window.re = function(){
        vcObs = null; cntObs = null;
        var r = origRe.apply(this, arguments);
        setTimeout(scan, 100);
        setTimeout(revealVisible, 300);
        return r;
      };
    }
  }

  // ── 2. RIPPLE CLICK EFFECT ──
  function initRipple(){
    document.addEventListener('click', function(e){
      var btn = e.target.closest('.btn, .sc-btn, .pk-btn, .book-order-btn, .vnav-btn, .lbtn, .back-btn');
      if(!btn) return;
      var rect = btn.getBoundingClientRect();
      var ripple = document.createElement('span');
      ripple.className = 'v-ripple';
      ripple.style.left = (e.clientX - rect.left - 20) + 'px';
      ripple.style.top  = (e.clientY - rect.top - 20) + 'px';
      btn.style.position = btn.style.position || 'relative';
      btn.appendChild(ripple);
      setTimeout(function(){ ripple.remove(); }, 600);
    });
  }

  // ── 3. SCROLL PROGRESS BAR ──
  function initScrollProgress(){
    var bar = document.createElement('div');
    bar.className = 'v-scroll-progress';
    document.body.appendChild(bar);

    function update(){
      // Find the active scrollable container
      var vc = document.getElementById('vContent');
      var cnt = document.querySelector('.cnt');
      var scroller = null;
      if(vc && vc.offsetParent !== null && vc.scrollHeight > vc.clientHeight){
        scroller = vc;
      } else if(cnt && cnt.offsetParent !== null && cnt.scrollHeight > cnt.clientHeight){
        scroller = cnt;
      }
      if(scroller){
        var pct = scroller.scrollTop / (scroller.scrollHeight - scroller.clientHeight) * 100;
        bar.style.width = Math.min(pct, 100) + '%';
      } else {
        bar.style.width = '0%';
      }
    }
    // Listen on both containers
    var vc = document.getElementById('vContent');
    var cnt = document.querySelector('.cnt');
    if(vc) vc.addEventListener('scroll', update, {passive:true});
    if(cnt) cnt.addEventListener('scroll', update, {passive:true});
    // Re-attach after DOM changes
    setInterval(function(){
      var vc2 = document.getElementById('vContent');
      var cnt2 = document.querySelector('.cnt');
      if(vc2 && !vc2._vsp){ vc2.addEventListener('scroll', update, {passive:true}); vc2._vsp = true; }
      if(cnt2 && !cnt2._vsp){ cnt2.addEventListener('scroll', update, {passive:true}); cnt2._vsp = true; }
    }, 2000);
  }

  // ── 4. COUNTER ANIMATION (animate numbers on stat cards) ──
  function initCounterAnim(){
    if(!('IntersectionObserver' in window)) return;
    var io = new IntersectionObserver(function(entries){
      entries.forEach(function(e){
        if(!e.isIntersecting) return;
        var el = e.target;
        io.unobserve(el);
        var text = el.textContent.trim();
        var num = parseInt(text.replace(/[^\d]/g, ''), 10);
        if(isNaN(num) || num < 2 || num > 99999) return;
        var suffix = text.replace(/[\d\s]/g, '');
        var dur = 1200;
        var start = performance.now();
        function step(now){
          var t = Math.min((now - start) / dur, 1);
          // ease-out expo
          var val = Math.round(num * (1 - Math.pow(1 - t, 3)));
          el.textContent = val.toLocaleString('fr-FR') + suffix;
          if(t < 1) requestAnimationFrame(step);
        }
        requestAnimationFrame(step);
      });
    }, { threshold: 0.5 });

    function scan(){
      document.querySelectorAll('.scv, .vstats-n, .vstat-n, .lsn, .hours-value, .avg-num').forEach(function(el){
        if(!el.dataset.vCounted){ el.dataset.vCounted = '1'; io.observe(el); }
      });
    }
    scan();
    setInterval(scan, 2000);
  }

  // ── 5. SMOOTH PAGE TRANSITION ──
  var origGoTo = window.goTo;
  if(typeof origGoTo === 'function'){
    window.goTo = function(page){
      var cnt = document.querySelector('.cnt');
      if(cnt){
        cnt.style.opacity = '0';
        cnt.style.transform = 'translateY(8px)';
        cnt.style.transition = 'opacity .15s ease, transform .15s ease';
        setTimeout(function(){
          origGoTo(page);
          cnt.style.opacity = '1';
          cnt.style.transform = 'translateY(0)';
        }, 150);
      } else {
        origGoTo(page);
      }
    };
  }

  // ── 6. EMOJI → MATERIAL ICONS REPLACEMENT ENGINE ──
  // Comprehensive mapping of emojis to Material Symbols Rounded icon names
  var EMOJI_ICON_MAP = {
    // Education & Academic
    '🎓':'school','📚':'menu_book','📖':'auto_stories','📝':'edit_note','📋':'assignment',
    '✏️':'edit','✍️':'draw','📐':'architecture','📄':'description','📜':'history_edu',
    '📊':'bar_chart','📈':'trending_up','📉':'trending_down',
    // People & Roles
    '👨‍🏫':'person','🧑‍🏫':'person','👤':'person','👥':'group','👨‍👩‍👧':'family_restroom',
    '👋':'waving_hand','👑':'verified','👔':'checkroom',
    // Science & Research
    '🔬':'biotech','⚗️':'science','🧬':'genetics','🔭':'explore',
    // Buildings & Places
    '🏫':'apartment','🏛️':'account_balance','🏥':'local_hospital','🏢':'business',
    '🏦':'account_balance','🏪':'storefront','🏆':'emoji_events','🏅':'military_tech',
    // Shopping & Finance
    '🛍️':'shopping_bag','🛒':'shopping_cart','💰':'payments','💳':'credit_card',
    '💸':'currency_exchange','🧾':'receipt_long','💵':'paid',
    // Communication
    '💬':'chat_bubble','📞':'call','✉️':'mail','📧':'email','📢':'campaign',
    '📲':'smartphone','📱':'phone_iphone','🔔':'notifications',
    // Media & Content
    '🎬':'movie','🎭':'theater_comedy','🎵':'music_note','🎶':'library_music',
    '📺':'live_tv','📻':'radio','🎨':'palette','📸':'photo_camera',
    // Navigation & Actions
    '🧭':'explore','🔍':'search','🔗':'link','📍':'location_on','📌':'push_pin',
    '🗺️':'map','🌍':'public','🌐':'language',
    // Status & Indicators
    '✅':'check_circle','❌':'cancel','⚠️':'warning','ℹ️':'info',
    '🔐':'admin_panel_settings','🔒':'lock','🔓':'lock_open',
    '⭐':'star','🔥':'local_fire_department',
    // Time & Calendar
    '📅':'event','🕐':'schedule','⏸':'pause_circle','▶':'play_circle',
    // Games & Fun
    '🎮':'sports_esports','🧩':'extension','🎯':'gps_fixed',
    '🎁':'redeem','🎉':'celebration','🎊':'celebration',
    // Sports & Medals
    '🥇':'emoji_events','🥈':'workspace_premium','🥉':'military_tech','⚽':'sports_soccer',
    // Tools & Settings
    '⚙️':'settings','🛠️':'build','🔧':'handyman','🗑':'delete',
    '📥':'download','📤':'upload','📎':'attach_file','🔄':'refresh',
    '🖨️':'print','➕':'add_circle','＋':'add_circle',
    // Nature & Science
    '🌿':'eco','🌱':'park','☀️':'light_mode','🌙':'dark_mode',
    // Symbols used in admin menus
    '⊕':'add_circle','◇':'diamond','◈':'dashboard','◉':'radio_button_checked',
    '▦':'grid_view','▤':'view_list','▣':'calendar_view_month','◆':'announcement',
    '◐':'visibility','◌':'radio_button_unchecked','⊡':'select_check_box','⊙':'settings',
    '△':'account_balance_wallet','⨡':'manage_accounts',
    // Misc
    '🚀':'rocket_launch','🤝':'handshake','💡':'lightbulb','🧠':'psychology',
    '😰':'sentiment_stressed','💻':'laptop','🎒':'backpack','📡':'cell_tower',
    '🟠':'fiber_manual_record','⚖️':'balance','💼':'work','🎖️':'military_tech',
    '✨':'auto_awesome','📦':'package_2','✕':'close','✓':'check',
    '🏠':'home','👆':'touch_app','🎮':'sports_esports','🦁':'pets',
    '🏙️':'location_city','🌆':'apartment','🔢':'tag','📰':'newspaper',
    '🫕':'soup_kitchen','⚡':'bolt','🇬🇧':'translate','🔊':'volume_up',
    '🔇':'volume_off','⏯':'play_pause',
    '📘':'book','📗':'book','📕':'book','📙':'book',
    '👨‍👩‍📘':'family_restroom','👩':'person'
  };

  // Icon size classes: detect context and pick appropriate size
  function _icoSize(el){
    if(!el) return '18px';
    var fs = parseFloat(getComputedStyle(el).fontSize || 16);
    if(fs >= 36) return '36px';
    if(fs >= 24) return '24px';
    if(fs >= 18) return '20px';
    return '18px';
  }

  // Replace emoji text nodes with Material Icons spans
  // v1.2.2 : un nœud est "protégé" si lui ou un ancêtre veut garder l'emoji natif.
  function _emojiProtected(el){
    for(var p=el; p && p.nodeType===1; p=p.parentNode){
      if(p.getAttribute && p.getAttribute('role')==='img') return true;
      if(p.hasAttribute && p.hasAttribute('data-keep-emoji')) return true;
      if(p.classList && p.classList.contains('vgz-role-ico')) return true;
    }
    return false;
  }
  function replaceEmojisInNode(node){
    if(node.nodeType === 3){ // Text node
      if(node.parentNode && _emojiProtected(node.parentNode)) return; // garder l'emoji natif
      var text = node.textContent;
      var found = false;
      var keys = Object.keys(EMOJI_ICON_MAP);
      for(var i=0; i<keys.length; i++){
        if(text.indexOf(keys[i]) !== -1){ found = true; break; }
      }
      if(!found) return;

      var frag = document.createDocumentFragment();
      var remaining = text;
      while(remaining.length > 0){
        var earliest = -1, earliestKey = null, earliestPos = remaining.length;
        for(var j=0; j<keys.length; j++){
          var pos = remaining.indexOf(keys[j]);
          if(pos !== -1 && pos < earliestPos){
            earliestPos = pos;
            earliestKey = keys[j];
          }
        }
        if(earliestKey === null){
          frag.appendChild(document.createTextNode(remaining));
          break;
        }
        if(earliestPos > 0){
          frag.appendChild(document.createTextNode(remaining.substring(0, earliestPos)));
        }
        var ico = document.createElement('span');
        ico.className = 'material-symbols-rounded v-ico';
        ico.textContent = EMOJI_ICON_MAP[earliestKey];
        frag.appendChild(ico);
        remaining = remaining.substring(earliestPos + earliestKey.length);
      }
      node.parentNode.replaceChild(frag, node);
    } else if(node.nodeType === 1 && node.tagName !== 'SCRIPT' && node.tagName !== 'STYLE'
              && !node.classList.contains('material-icons-round')
              && !node.classList.contains('material-symbols-rounded')
              && !node.classList.contains('v-ico')
              // v1.2.2 : NE PAS transformer les pictos volontairement en emoji natif
              // (cartes rôles, bento, icônes labellisées) — la police Material ne
              // s'applique pas partout → on verrait le mot « school » au lieu de 🎓.
              && node.getAttribute && node.getAttribute('role') !== 'img'
              && !node.hasAttribute('data-keep-emoji')
              && !node.classList.contains('vgz-role-ico')
              && node.tagName !== 'OPTION'){
      // Iterate children in reverse (replacing may change length)
      var children = Array.prototype.slice.call(node.childNodes);
      for(var k=0; k<children.length; k++){
        replaceEmojisInNode(children[k]);
      }
    }
  }

  // Post-process: fix icon colors based on actual background luminosity
  function _fixIconColors(){
    var icons = document.querySelectorAll('.v-ico, .material-symbols-rounded, .material-icons-round');
    for(var i=0; i<icons.length; i++){
      var el = icons[i];
      if(el.getAttribute('data-color-fixed')) continue;
      // Walk up ancestors to find effective background color
      var node = el.parentNode;
      var bg = 'rgba(0, 0, 0, 0)';
      while(node && node.nodeType === 1){
        try {
          var cs = window.getComputedStyle(node);
          var cbg = cs.backgroundColor;
          if(cbg && cbg !== 'rgba(0, 0, 0, 0)' && cbg !== 'transparent'){
            bg = cbg;
            break;
          }
        }catch(e){ break; }
        node = node.parentNode;
      }
      // Parse RGB from bg
      var m = bg.match(/(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/);
      if(m){
        var r=parseInt(m[1]),g=parseInt(m[2]),b=parseInt(m[3]);
        // Relative luminance (simplified)
        var lum = (0.299*r + 0.587*g + 0.114*b);
        if(lum < 80){
          // Dark background → white icon
          el.style.color = '#fff';
          el.setAttribute('data-color-fixed','1');
        }
      }
    }
  }

  // v1.2.2 FIX : ne convertir les emojis en Material Symbols QUE si la police
  // est réellement chargée. Sinon (cas fréquent au Cameroun : police CDN bloquée/
  // lente) on afficherait le MOT « school » au lieu de l'icône → on garde l'emoji natif.
  function _materialFontReady(){
    try{
      if(!document.fonts || !document.fonts.check) return false;
      return document.fonts.check('24px "Material Symbols Rounded"');
    }catch(e){ return false; }
  }
  function runEmojiReplace(){
    if(!_materialFontReady()) return; // police absente → emojis natifs conservés
    replaceEmojisInNode(document.body);
    requestAnimationFrame(_fixIconColors);
  }

  // MutationObserver to catch dynamically rendered content
  function initEmojiReplacer(){
    // Attendre que les polices soient prêtes avant la 1re passe
    var started=false;
    function start(){
      if(started) return; started=true;
      runEmojiReplace();
      if('MutationObserver' in window){
        var debounceTimer = null;
        var mo = new MutationObserver(function(){
          clearTimeout(debounceTimer);
          debounceTimer = setTimeout(runEmojiReplace, 150);
        });
        mo.observe(document.body, { childList: true, subtree: true });
      }
      // v1.2.2 : scan périodique BORNÉ (10 passes max) au lieu d'un setInterval
      // permanent → évite le coût batterie/CPU continu sur mobile.
      var passes=0;
      var iv=setInterval(function(){ runEmojiReplace(); if(++passes>=10) clearInterval(iv); }, 3000);
    }
    if(document.fonts && document.fonts.ready && document.fonts.ready.then){
      document.fonts.ready.then(start);
      setTimeout(start, 1500); // filet de sécurité si fonts.ready ne résout pas
    } else {
      start();
    }
  }

  // ── INIT ──
  function bootDesign(){
    initScrollReveal();
    initRipple();
    initScrollProgress();
    initCounterAnim();
    initEmojiReplacer();
  }

  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', bootDesign);
  } else {
    setTimeout(bootDesign, 200);
  }

})();


/* ════════════════════════════════════════════════════════════════
   v1.2.2 — FALLBACK GLOBAL des emojis 3D (CDN em-content.zobj.net)
   Ce CDN est lent/inaccessible depuis le Cameroun → images cassées.
   Quand une <img> de ce CDN échoue, on dérive l'emoji NATIF depuis le
   nom de fichier (ex. graduation-cap_1f393.png → 🎓) et on le substitue.
   Répare TOUT le site d'un coup, sans dépendance réseau. (capture=true
   pour intercepter les erreurs d'images injectées dynamiquement.)
   ════════════════════════════════════════════════════════════════ */
(function(){
  function emojiFromUrl(url){
    try{
      var file=url.split('/').pop().split('?')[0].replace(/\.(png|webp|svg|gif)$/i,'');
      var tail=file.split('_').pop();                 // ex: 1f468-1f3fd-200d-1f3eb
      var parts=tail.split('-').filter(function(h){return /^[0-9a-f]{2,6}$/i.test(h);});
      if(!parts.length) return '';
      return parts.map(function(h){return String.fromCodePoint(parseInt(h,16));}).join('');
    }catch(e){ return ''; }
  }
  function _replaceCdnImg(img){
    if(!img || img.tagName!=='IMG') return;
    if(img.dataset && img.dataset._emojiFixed) return;
    var src=img.getAttribute('src')||img.currentSrc||img.src||'';
    if(src.indexOf('zobj.net')<0) return;
    var emo=emojiFromUrl(src) || '🎓';
    if(img.dataset) img.dataset._emojiFixed='1';
    var span=document.createElement('span');
    span.setAttribute('role','img');
    span.setAttribute('aria-hidden','true');
    if(img.alt) span.setAttribute('aria-label', img.alt);
    var sz=Math.max(img.width||0, parseInt(getComputedStyle(img).width)||0, 40);
    span.style.cssText='display:inline-flex;align-items:center;justify-content:center;'
      +'font-size:'+Math.round(sz*0.82)+'px;line-height:1;width:100%;height:100%';
    span.textContent=emo;
    if(img.parentNode) img.parentNode.replaceChild(span, img);
  }
  // 1) Réactif : si une image CDN échoue (capture car 'error' ne bulle pas)
  document.addEventListener('error', function(ev){ _replaceCdnImg(ev.target); }, true);
  // 2) PROACTIF : convertir SANS attendre l'échec réseau (le CDN zobj est lent au
  //    Cameroun → on évite le timeout/clignotement). Au chargement + contenu dynamique.
  function _sweepCdnImgs(root){
    try{ (root||document).querySelectorAll('img[src*="zobj.net"]').forEach(_replaceCdnImg); }catch(e){}
  }
  function _bootCdn(){
    _sweepCdnImgs(document);
    if('MutationObserver' in window){
      var t=null;
      new MutationObserver(function(){ clearTimeout(t); t=setTimeout(function(){_sweepCdnImgs(document);},120); })
        .observe(document.body, {childList:true, subtree:true});
    }
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', _bootCdn);
  else _bootCdn();
})();

/* ════════════════════════════════════════════════════════════════════════════
   PROGRAMME DE PARTENARIAT VÉRITAS v1.0 — module autonome
   © 2024-2026 Jacques Miterand TAKOU (Mythe Errant). Tous droits réservés.

   Architecture :
     - pgPartnerships()         landing publique des 9 programmes
     - pgPartnerProgram(type)   fiche détaillée d'un programme
     - mPartnerSignup(type)     modale de candidature
     - submitPartnerApplication candidature → DB.partnerApplications
     - pgPartnersAdmin()        dashboard admin (validation + stats + commissions)
     - mApprovePartner(id)      valider une candidature → bascule en active
     - applyPartnerCode(...)    appelée à chaque vente avec code parrainage
     - calculatePartnerLevel    recalcule Bronze/Argent/Or/Diamant (mix tous types)
     - _genPartnerCode(name)    génère un code parrainage unique
     - pgPartnerPortal()        espace privé d'un partenaire connecté
═════════════════════════════════════════════════════════════════════════════ */

// ── helpers internes ──────────────────────────────────────────────────────
function _prtL(){ return (typeof DB!=='undefined' && DB.partnerLevels) ? DB.partnerLevels
  : {bronze:{min:0,commission:0.05,label:'Bronze',badge:'🥉',bonusFixe:0,color:'#CD7F32'},
     argent:{min:20,commission:0.08,label:'Argent',badge:'🥈',bonusFixe:0,color:'#C0C0C0'},
     or:{min:50,commission:0.10,label:'Or',badge:'🥇',bonusFixe:10000,color:'#FFD700'},
     diamant:{min:100,commission:0.12,label:'Diamant',badge:'💎',bonusFixe:50000,color:'#B9F2FF'}}; }
function _prtT(){ return (typeof DB!=='undefined' && DB.partnerTypes) ? DB.partnerTypes : {}; }
function _prtSafe(s){ return (typeof _esc==='function')?_esc(s):String(s==null?'':s); }
function _prtFmt(n){ return (typeof fmt==='function')?fmt(n):(n+' FCFA'); }
function _prtFmtN(n){ return (typeof fmtN==='function')?fmtN(n):String(n); }
function _prtToast(m,t){ if(typeof toast==='function') toast(m,t||'ok'); }
function _prtSave(){ if(typeof save==='function') save(); }
function _prtRe(){ if(typeof re==='function') re(); }
function _prtCm(){ if(typeof cm==='function') cm(); }

// Routing intelligent : si on est en visiteur → vShowSec, sinon → goTo
function _prtGo(target){
  var visiteur = false;
  try {
    var vis = document.getElementById('VISITOR');
    visiteur = vis && getComputedStyle(vis).display !== 'none';
  } catch(e){}
  if(visiteur && typeof vShowSec==='function'){
    vShowSec(target, null);
  } else if(typeof goTo==='function'){
    goTo(target);
  }
}

// Génère un code parrainage à partir du nom — unique dans DB.partners + DB.promoCodes
function _genPartnerCode(name){
  var base = String(name||'PARRAIN').toUpperCase().replace(/[^A-Z0-9]/g,'').substring(0,8) || 'PARRAIN';
  var i = 10;
  while(true){
    var candidate = base + i;
    var clash = (DB.partners||[]).some(function(p){return p.code===candidate;})
             || (DB.promoCodes||[]).some(function(p){return p.code===candidate;});
    if(!clash) return candidate;
    i++;
    if(i>9999){ candidate = base + Math.floor(Math.random()*100000); return candidate; }
  }
}

